/* characters q14 (185 mục) — R2.6 bồi tiểu sử Xích Hồn Tử */
window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q14"]=window.__LIBQ["tien-nghich"]["q14"]||{};window.__LIBQ["tien-nghich"]["q14"]["characters"]={"updatedAt":"2026-07-17","count":185,"chars":[{"id":"vuong-lam","name":"Vương Lâm","cn":"王林","aliases":["Phong Tôn","Mã Lương","Thiết Trụ","Hứa Mộc","đại nho Vương Lâm","Thanh niên tóc bạc"],"gioiTinh":"nam","canhGioiCaoNhat":"Bước thứ ba Không Linh trung kỳ (@c1531)","trangThai":"song","tabs":{"kinhLich":[{"mucCt":"ky","text":"Cùng người điên trở về Liên Minh Tinh Vực, cảm thụ khí tức quen thuộc, lòng tràn ngập bi thương nhớ về nhà ở Côn Hư và Chu Tước, người nhà đã mất từ lâu. Nhận người điên có ân tái tạo, ân oán phân minh quyết bảo vệ. Phát hiện một tu chân tinh cấp thấp vô cùng to lớn, nhìn thấu bốn lão quái bế quan bên trong. Triệu hồi Hứa Lập Quốc và Lưu Kim Bưu từ trữ vật, giao nhiệm vụ trông coi người điên trên tu chân tinh này. Một mình biến mất trong tinh không, đi thẳng tới tổng bộ Tu Chân Liên Minh gặp Thanh Thủy sư huynh.","anchor":"Thanh Thủy sư huynh, Vương Lâm tới rồi!","bridge":true,"khoang":"@c1451"},{"mucCt":"ky","text":"Một mình xuyên tinh không chỉ ba bước tới Côn Hư tinh vực, thân thể mạnh tới mức khe không gian va vào liền sụp đổ. Bước đầu thoáng thấy Lỗ Phu Tử đang bố trí trận pháp nhưng không dừng. Bước hai tới vùng cấm thức gần trung tâm Côn Hư, nhận ra dấu tích đại chiến kịch liệt, suy đoán bản thân đã ở trong U Minh thú nhiều ngày và chiến cục đã diễn ra nhiều lần. Phát hiện Viêm Lôi Tử bị hai tu sĩ Toái Niết giới ngoại truy sát, ra tay cứu: một tay túm Viêm Lôi Tử kéo lại dập tắt ngọn lửa sinh mạng, hiện hình bạch y phóng kim quang vạn trượng chiếu rọi tinh không, quát một tiếng khiến hai kẻ tê dại kinh hồn. Tuyên bố trở về.","anchor":"Phong Tôn Vương Lâm!","bridge":true,"khoang":"@c1452"},{"mucCt":"ky","text":"Kim quang từ mắt tràn ra bao phủ tinh không, giết hai tu sĩ Toái Niết giới ngoại (Hỏa Tước tộc và Phụng Thiên Lang tộc) dễ như bóp kiến. Nghe Viêm Lôi Tử tường thuật toàn cảnh ba trận đại chiến giới nội-giới ngoại trong vài thập niên vắng mặt: Hồng Sam Tử bị phong ấn, Nam Vân Tử trọng thương bế quan, tiên đế Thanh Lâm trọng thương sau đại chiến thứ ba, giới nội nguy cấp. Dùng kim quang chữa trị cải tạo cơ thể Viêm Lôi Tử khiến hắn thoát thai hoán cốt. Quyết định hướng tới tổng bộ Tu Chân Liên Minh để hủy diệt Thất Thải Giới, tuyên bố “Theo ta một chuyến, hủy diệt giới này!” dù bên trong có Thiên Triệu Thượng Sư (Không Linh sơ kỳ) và Trọng Huyền Tử phản bội.","anchor":"kim quang từ trong mắt Vương Lâm tràn ra, bao phủ cả tinh không","bridge":true,"khoang":"@c1453"},{"mucCt":"ky","text":"Bước một bước xuyên tinh không đưa Viêm Lôi Tử tới bên ngoài tổng bộ Tu Chân Liên Minh, hồi tưởng thời còn là tu sĩ Chu Tước Tinh khi nơi đây là đỉnh cao không thể tiến vào. Thì thầm mong Thanh Thủy sư huynh còn sống. Điểm một ngón tay khiến dòng xoáy phong ấn truyền thừa từ thượng cổ dừng hẳn, rồi xé nát dòng xoáy bằng tay không. Đạp chân khiến tinh không sụp đổ, vung tay tạo cơn lốc vàng diệt mấy ngàn tu sĩ giới ngoại, phá bức màn tinh không lộ ra tu chân tinh tổng bộ. Chỉ bằng sự xuất hiện đã khiến mấy ngàn rồi hơn vạn tu sĩ giới ngoại kinh hoàng sụp đổ tâm thần. Đối diện Thiên Triệu Thượng Sư xuất hiện nghênh chiến.","anchor":"chỉ tùy ý điểm một cái liền khiến cho dòng xoáy mênh mông này không thể thừa nhận nổi","bridge":true,"khoang":"@c1454"},{"mucCt":"ky","text":"Vương Lâm quyết định dùng toàn lực bất chấp rút ngắn thời gian áp chế lực bài xích, vì muốn cứu Thanh Thủy và lấy đạo quả. Kim quang (tiên lực chính tông) từ mắt hắn tràn ngập tinh không, mang khí tức khiến thiên địa kinh hãi. Ba hương hỏa hắc long nhận ra tiên lực trong truyền thừa linh hồn, sợ hãi phun máu đen đồng loạt bái lạy. Hơn vạn tu sĩ giới ngoại bị uy áp linh hồn phun máu quỳ xuống. Vương Lâm bước tới, lần lượt dùng nắm tay màu vàng đánh nát thân thể Thiên Triệu Thượng Sư, tiên lôi đánh tan vô tận hồn phách hương hỏa, ngọn lửa màu vàng (Thiên Hoàng Lô) thiêu hủy nguyên thần — Thiên Triệu Thượng Sư tiêu tán. Từ đầu tới cuối Vương Lâm không nói một lời. Sau khi dùng toàn lực, cơ thể bắt đầu đau đớn mơ hồ do lực bài xích dần muốn bộc phát.","anchor":"Vạn tu quỳ, hắc long bái! Hỏi thiên hạ, ai nắm quyền sinh sát!","bridge":true,"khoang":"@c1455"},{"mucCt":"ky","text":"Đứng giữa tinh không trước gần vạn tu sĩ giới ngoại đang quỳ run rẩy, quan sát tu chân tinh tổng bộ Tu Chân Liên Minh và nhận ra cấm chế trận pháp thứ hai. Chụp lấy ba con hắc long hương hỏa: con thứ nhất bức ra hồn phách tu sĩ giới nội rồi phong ấn tặng Viêm Lôi Tử, nói hương hỏa tuy có độc nhưng lợi nhiều hơn hại, có cơ duyên đạt bước thứ ba. Con thứ hai xử lý tương tự rồi gửi cho Thân Công Hổ qua Viêm Lôi Tử, đáp lại hai chữ tôn chủ năm xưa. Con thứ ba sai nuốt gần vạn tu sĩ giới ngoại rồi lao vào tu chân tinh phá trận, gây nứt vỡ. Đoán ra Long Bàn Tử đã dung hợp nguyên thần với tu chân tinh để trở thành tinh hồn vạn cổ bất diệt, trong lòng nổi lên kính nể trước trí tuệ và sự táo bạo của đối phương. Cuối chương nghe tiếng gào thét chứa sát lục bổn nguyên từ bên trong tu chân tinh, nhận ra cực kỳ quen thuộc, sắc mặt lần đầu biến đổi dữ dội, thốt lên Thanh Thủy sư huynh.","anchor":"sắc mặt Vương Lâm lần đầu tiên biến đổi. một sự dao động dũng mãnh hiện lên!","bridge":true,"khoang":"@c1456"},{"mucCt":"ky","text":"Xác nhận Thanh Thủy còn sống bên trong tu chân tinh Tu Chân Liên Minh, vui mừng quyết tâm cứu sư huynh. Phóng thích hắc long hương hỏa cho tự do, đặt điều kiện cấm giết tu sĩ giới nội. Dùng thuần lực phá nát hai cánh tay tu chân tinh, không gì ngăn nổi bước chân. Đối mặt chí bảo Sơn Hà Đồ do lão già Tu Chân Liên Minh triệu hoán, nhờ tiên huyết mạch thi triển Dịch Linh Ấn chính tông bậc nhất, chưởng ấn kim quang vạn trượng, tiên lực tinh thuần chưa từng có lan khắp Côn Hư Tinh Vực gây chấn động toàn giới nội.","anchor":"Vương Lâm nhờ vào tiên huyết mạch, mà thi triển ra Dịch Linh Ấn chính tông bậc nhất!","bridge":true,"khoang":"@c1457"},{"mucCt":"ky","text":"Thi triển Dịch Linh Ấn bất chấp lực bài xích tàn phá cơ thể, bộc phát toàn bộ tiên lực huyết mạch biến Dịch Linh Ấn thành tiên thuật thực sự, xé rách một góc Sơn Hà Đồ. Bị Sơn Hà Đồ tự khôi phục và phản kích, khóe miệng tràn máu, lực bài xích giữa nguyên tiên và Đạo cổ giằng co dữ dội. Lấy ra một cây cung từ trong thân thể, công khai tự xưng đương kim Phong Tôn, vạch trần Liên Minh bị giới ngoại chiếm cứ, Trọng Huyền Tử là tay sai, mục đích hủy Thất Thải Giới, cứu Thanh Thủy, giết tu sĩ giới ngoại. Long Bàn Tử sửng sốt dừng lại.","anchor":"Ta là đương kim Phong Tôn, tới đây để hủy Thất Thải Giới, cứu Thanh Thủy sư huynh của ta, giết tu sĩ giới ngoại","bridge":true,"khoang":"@c1458"},{"mucCt":"ky","text":"Cầm Côn Cực Tiên tự xưng Phong Tôn trước Long Bàn Tử, bất chấp dây cung dung hợp huyết mạch khiến gân cốt bị lôi kéo kịch liệt. Lạnh lùng chứng kiến Long Bàn Tử giết hai đại trưởng lão Tu Chân Liên Minh, nghe Trọng Huyền Tử đổ lỗi cho Thanh Thủy. Long Bàn Tử tự thiêu nguyên thần gánh tội thay đệ tử, mở lối vào Thất Thải Giới. Vương Lâm hỏi Thanh Thủy đang ở đâu.","anchor":"Hắn muốn cứu Thanh Thủy, thì sẽ bất chấp hết thảy!","bridge":true,"khoang":"@c1459"},{"mucCt":"ky","text":"Khuyên Viêm Lôi Tử hấp thụ hương hỏa hắc long làm cơ duyên, cảnh báo Thất Thải Giới nguy hiểm rồi từ biệt. Một mình kiên định bước vào Thất Thải Giới lần thứ hai, không quay đầu, không do dự. Bên trong phát hiện gần mười vạn ngọn núi tạo thành trận pháp khổng lồ, trên mỗi đỉnh núi có tu sĩ bị đá nhọn xuyên thân giam cầm, máu chảy không ngừng bốc thành khói hồng bay về ngọn núi trung tâm. Nửa là tu sĩ giới ngoại có ấn ký mi tâm, nửa là tu sĩ Liên Minh. Khi bước vào, cấm chế kích hoạt, mười vạn tu sĩ đồng loạt dồn ánh mắt oán khí rít gào rồi phun máu tạo sương máu tràn ngập. Dùng tốc độ cực nhanh lao thẳng tới ngọn núi cao nhất. Phát hiện mười vạn ngọn núi thực chất là gai trên lưng một con Huyền Vũ khổng lồ đã hóa đá chiếm cứ toàn bộ Thất Thải Giới. Trên đầu Huyền Vũ có một trung niên khí tức vạn cổ khoanh chân ngồi, không có sức sống, thân thể nối liền Huyền Vũ, thiên linh bị gai dài ba tấc đâm xuyên từ dưới lên.","anchor":"trong đời hắn đây là lần thứ hai hắn bước vào Thất Thải Giới","bridge":true,"khoang":"@c1460"},{"mucCt":"ky","text":"Tiến vào đỉnh núi cao nhất, tìm thấy Thanh Thủy bị mười cái cọc phong ấn trên vách núi, thần trí điên cuồng, hồn phách bị Huyền Vũ trấn áp, mi tâm bị ngón tay trỏ bảy màu hấp thụ sát lục bổn nguyên. Bị Thanh Thủy phóng Cực Cảnh chứa sát lục bổn nguyên tấn công, dùng kim lôi mắt phải và kim hỏa mắt trái đối kháng, khóe miệng tràn máu phải lùi lại. Gào to gọi tên Thanh Thủy khiến hắn thoáng tỉnh lộ vẻ thống khổ, nói được vài lời rồi lại bị khí xám từ Huyền Vũ xâm nhập rơi vào điên cuồng. Phát hiện cọc thứ mười ẩn dưới tóc Thanh Thủy đâm vào thiên linh, giải mã toàn bộ trận pháp: mười vạn ngọn núi hóa mười cọc phong ấn, mười vạn tu sĩ nuôi Huyền Vũ bằng máu và kích thích sát ý Thanh Thủy, Huyền Vũ chưa chết dùng thân xác trấn áp hồn phách Thanh Thủy, Thanh Thủy là lò luyện sát lục bổn nguyên, ngón tay trỏ bảy màu thu sát lục bổn nguyên. Suy luận Huyền Vũ Thánh Hoàng phản bội Tứ Thánh Tông vì Tu Chân Liên Minh tìm được chân thân Huyền Vũ — rất có thể là tứ đại chiến tướng dưới trướng Tiên Tôn — hắn muốn sức mạnh tổ tiên nên cam tâm phản bội. Nhìn cảnh tượng quá khứ Thanh Thủy hiện trong sương máu: thái tử nước nhỏ phàm trần, nước bị tàn phá, bỏ trốn bái nhập sơn môn bị lăng nhục, từ đó sinh ra Cực Cảnh, suốt quá trình có ánh sáng bảy màu với hư ảnh bí ẩn quan sát. Nảy ra phán đoán cực kỳ đáng sợ về kẻ đứng sau thao túng cuộc đời Thanh Thủy.","anchor":"Hắn mơ hồ có một sự phán đoán cực kỳ đáng sợ!","bridge":true,"khoang":"@c1461"},{"mucCt":"ky","text":"Nhìn thấy toàn bộ quá khứ bi thảm của Thanh Thủy qua sương máu trong Thất Thải Giới, cảm nhận ánh mắt bảy màu cổ quái trên bầu trời như nhìn vào gương, người kia giống chính mình. Thề liều mạng cứu Thanh Thủy ra. Nhận ra Huyền Vũ hóa đá là mấu chốt trận pháp trấn áp hồn phách Thanh Thủy, dùng Đạo Cổ lực và mười quyền thất tinh Cổ Thần tấn công nhưng Huyền Vũ không nứt, cánh tay phải bị lực phản chấn rắc rắc. Thi triển kim hỏa tiên hóa màu vàng và tiên lôi càn quét mười vạn tu sĩ tử thi nhưng hư hỏa không hiệu quả với xác chết. Mười vạn tu sĩ tự nổ tung, máu thịt ngưng tụ thành cây đao khổng lồ cao tận trời chém xuống. Vỗ mi tâm kích hoạt bảy tinh điểm vàng, hóa Cổ Thần ngàn trượng đỡ đao bằng tay phải. Bất chấp lực bài xích, bộc phát toàn bộ sức mạnh dung hợp tiên-thần, mượn lực cây đao dung hợp vào thân, lao xuống lần đầu tiên thi triển sức mạnh Cổ Thần đồng thời cả hai tay đập vào lưng Huyền Vũ, khiến mai Huyền Vũ phát ra tiếng rắc rắc.","anchor":"cái mai cứng như đá của Huyền Vũ kia phát ra những tiếng rắc rắc!","bridge":true,"khoang":"@c1462"},{"mucCt":"ky","text":"Đánh nứt mai Huyền Vũ khiến khí xám phun ra, phát hiện thi thể Huyền Vũ Thánh Hoàng sắp sống lại, lập tức vung huyết kiếm chém đứt đầu y và chém đứt cọc trên đầu, xóa tan nguy hiểm. Xoay người tung quyền liên tục phá nát cây đao máu thịt, hàng ngàn hồn phách bên trong tan vỡ. Chịu lực bài xích cực lớn, toàn thân rỉ máu từ lỗ chân lông, hóa đau thành quyết tâm cứu Thanh Thủy. Đánh mấy trăm quyền xen kim quang, lửa, lôi đình vào mai Huyền Vũ, thi triển Dịch Linh Ấn — chưởng ấn màu vàng khổng lồ giáng xuống kết hợp hữu chưởng đập nát hoàn toàn mai Huyền Vũ. Hồn phách từ thân Huyền Vũ bay ra lao tới Thanh Thủy. Mười vạn gai trên lưng Huyền Vũ sụp đổ, gần mười vạn gai xuyên khắp toàn thân kể cả mắt, biến hắn thành quả cầu gai khổng lồ. Nửa nén nhang sau đấm phá quả cầu thoát ra, tự rút gai khỏi mắt, huyết lệ tuôn chảy, kéo tách toàn bộ quả cầu — nhiều gai gãy gắn liền xương thịt không lấy ra được. Toàn thân đẫm máu từng bước đi tới Thanh Thủy trong đám mây bảy màu, rút cái cọc thứ nhất khỏi ngực Thanh Thủy.","anchor":"Thanh Thủy sư huynh, ta tới cứu ngươi đây","bridge":true,"khoang":"@c1463"},{"mucCt":"ky","text":"Rút lần lượt bốn cây cọc phong ấn trên người Thanh Thủy: cọc thứ nhất (ngực) phong ấn trái tim khiến tim đau nhức dữ dội, cọc thứ hai (cổ họng) phong ấn gân cốt kéo căng gân cốt, cọc thứ ba và thứ tư (hai cánh tay) phong ấn thần thức gây trọng thương thần thức, phun máu hai lần. Lực bài xích giữa tiên lực và Đạo cổ lực phá vỡ gai bên ngoài thân thể nhưng gai bên trong da thịt vẫn mọc rễ không loại bỏ được. Ngón tay bảy màu đã tiêu tan ngưng tụ thành thân ảnh bảy màu hư ảo, chỉ Vương Lâm nhìn thấy. Thân ảnh bảy màu cho cơ hội cứu Thanh Thủy, tỏ ra bình thản không quan tâm bí mật trên người Vương Lâm, nhắc đến một tiểu tu sĩ thờ phụng Chiến Nguyên từng khiến hắn kinh ngạc. Thân ảnh tiết lộ Đạo cổ Diệp Mịch trước khi chết phun tam thiên tiên huyết, một thiên hóa cổ Thần, một thiên hóa cổ Ma, một thiên hóa cổ Yêu, tạo nên nguồn gốc ba bộ tộc cổ đại. Vương Lâm liên kết với lời Bối La năm xưa về cổ Tộc là thế hệ nghịch tu thứ nhất, sau đánh với trời phân tán thành ba tộc, suy luận tam thiên tiên huyết dung hợp phần nhiều chính là vương tộc nhưng không chắc thật giả.","anchor":"Tâm thần Vương Lâm chấn động, hắn không hoàn toàn tin vào lời nói của đối phương","bridge":true,"khoang":"@c1464"},{"mucCt":"ky","text":"Rút cọc phong ấn thứ năm ở đan điền Thanh Thủy (phong ấn nguyên thần), vận tiên lực và Đạo cổ lực dung hợp, máu bắn tung tóe. Rút đồng thời cọc thứ sáu và thứ bảy ở hai chân, lực bài xích trong cơ thể lên đỉnh điểm, đau đớn cực độ. Rút cọc thứ tám gần thiên linh Thanh Thủy — cọc này không phải phong ấn mà để mở ra luân hồi; khi rút, vô số ký ức vặn vẹo tràn vào đầu. Thanh Thủy tách khỏi ngọn núi, ngã vào vai Vương Lâm nói \"Đa tạ\" rồi hôn mê, Vương Lâm rơi nước mắt gọi \"Sư huynh\". Nhận đạo quả màu vàng từ thân ảnh bảy màu nhưng nghi ngờ ẩn ý, cảm nhận đối phương cho cảm giác giống Thiên Vận Tử. Hỏi thân ảnh bảy màu có phải Tiên Tôn không, được đáp \"Phải, mà cũng không phải\". Bị đẩy ra khỏi Thất Thải Giới, khe Thất Thải Giới co lại biến mất. Liên hệ \"tiểu tử Chiến Nguyên\" với Chiến lão quỷ, nhận ra chuyện Thanh Thủy chỉ là trò chơi của thân ảnh bảy màu, nổi hàn quang. Đưa Thanh Thủy tới tu chân tinh hoang dã ngoài tổng bộ Tu Chân Liên Minh, ngồi khoanh chân cố đè nén lực bài xích nhưng chỉ giảm đau chút ít.","anchor":"cái khe Thất Thải Giới kia chậm rãi co lại, cuối cùng biến mất hoàn toàn","bridge":true,"khoang":"@c1465"},{"mucCt":"ky","text":"Dùng song chỉ rút cây cọc thứ chín (đen, mềm, đã dung hợp phân nửa xương sống) ra khỏi xương sống Thanh Thủy, máu đen phun ra, xương sống hồi phục. Tiếp tục rút cây cọc thứ mười (cuối cùng, màu tím) từ huyết quản Thanh Thủy — chặt đứt mạch máu, dùng ấn quyết cầm máu, rút ra hơn phân nửa trước khi Thanh Thủy tự đứng lên bẻ gãy và hoàn thành. Lấy bầu viêm long huyết mà lão Chu Tước từng cho để Thanh Thủy uống thay rượu mạnh. Cùng sư huynh uống rượu sảng khoái, Thanh Thủy cảm khái sư đệ đã trưởng thành. Chứng kiến Thanh Thủy khôi phục hình dáng năm xưa và sát lục bổn nguyên bộc phát kinh thiên, Không Đại Môn xuất hiện ở chân trời.","anchor":"Sắc mặt Vương Lâm tái nhợt, sau khi ném cây cọc kia đi cũng ngồi xuống","bridge":true,"khoang":"@c1466"},{"mucCt":"ky","text":"Phân tích mục đích thật sự của đạo nhân bảy màu, suy luận hắn không phải muốn sát lục bổn nguyên mà có thể là hạ luân hồi vào trong sát lục bổn nguyên của Thanh Thủy. Hồi tưởng chuỗi sự kiện xuyên suốt từ gặp Tham Lang ở Điện Lạc, đoạt pho tượng bảy màu, Chiến lão quỷ nói với Chưởng Tôn ở Vân Hải, tinh thạch lưng Huyền Vũ từ Thất Thải Giới — tất cả là bộ phận của bí ẩn cực lớn liên quan giới nội. Tự nhận ba đạo bổn nguyên sinh tử, nhân quả, thật giả phải đại thành, hiện đã có hai đạo quả, cần thêm một đạo nữa. Dùng hơn mười lá Cổ Tức Diệp bắt trăm vạn cấm chế kết hợp máu tiên nhân (máu vàng nhạt, huyết mạch tiên nhân) tạo phong ấn thiên địa ngưng kết tàn hồn Hàm Yên cho Thanh Thủy. Nhận được hắc kiếm bổn nguyên do Thanh Thủy tặng — pháp bảo bổn nguyên bước thứ ba, chứa sát lục bổn nguyên đầy đủ, nếu luyện hóa cảm ngộ sẽ có sát lục bổn nguyên.","anchor":"Hôm nay có hai đạo quả, chỉ cần một đạo quả nữa là ta có thể nắm chắc khả năng thành công","bridge":true,"khoang":"@c1467"},{"mucCt":"ky","text":"Nhận thanh sát lục kiếm từ Thanh Thủy, bổn nguyên đạt sáu đạo. Quyết định chưa luyện hóa sát lục bổn nguyên ngay, đợi ba bổn nguyên nhân quả, sinh tử, thật giả đại thành mới phá không môn. Cùng Thanh Thủy uống long huyết tửu trên tu chân tinh hoang dã, lập lời hứa mai táng cho nhau — nếu mình chết trước xin đưa về Chu Tước Tinh, Triệu Quốc, Vương gia. Tiết lộ có một con trai, ánh mắt bi ai. Thanh Thủy nhờ nếu gặp nữ tử có hồng ấn vai trái thì chiếu cố. Hai người hóa sóng gợn quét sạch tu sĩ giới ngoại khắp Côn Hư ba đại tinh vực, tiến vào Triệu Hà Thất Thải Giới. Nhìn thấy đạo quả cực lớn trong đám mây bảy sắc phía trên Long Bàn Tử và điện chủ Thiên Phạt Điện.","anchor":"khiến cho bản then trở thành người có sáu đạo bổn nguyên cực kỳ hiếm gặp từ xưa đến nay!","bridge":true,"khoang":"@c1468"},{"mucCt":"ky","text":"Thân thể tiến tới bên đạo quả dưới tầng mây ngũ sắc, vỗ vào bị phản chấn đẩy lùi. Sau khi Thanh Thủy và Long Bàn Tử liên thủ đánh trọng thương Điện chủ Thiên Phạt Điện, Vương Lâm từ chối đề nghị đổi chác của Điện chủ. Tay phải phát ánh sáng nhu hòa xuyên thẳng vào đạo quả không hề bị phản chấn, nắm Hồng Sam Tử kéo ra, sợi tơ tan vỡ, Hồng Sam Tử tỉnh lại. Tuyên bố không ai hiểu rõ đạo quả bằng hắn, kể cả chưởng tôn giới ngoại. Dùng huyết kiếm chặt đứt cành cây, đạo quả rơi vào tay, tuyên bố sẽ nuốt đạo quả này và có thể hấp thu toàn bộ, khiến Điện chủ kinh hãi lùi lại.","anchor":"Ta nuốt đạo quả này, có thể hấp thu toàn bộ","bridge":true,"khoang":"@c1469"},{"mucCt":"vua","text":"Dùng kim quang hợp lực cùng Hồng Sam Tử, Long Bàn Tử, Thanh Thủy đánh bại Tần Cửu Duyên. Không lấy ba đạo quả, quyết tâm trước khi lực bài xích bộc phát phải làm ba đạo bổn nguyên đại thành, mở không môn chứng đạo. Được Hồng Sam Tử giao nhiệm vụ lấy danh nghĩa Phong Tôn tới chiến trường Vân Hải chủ huy cuộc phản kích cuối cùng. Cuối chương xuất hiện ở khách sạn Côn Hư Nhất Linh dưới hình dáng nam tử áo trắng.","anchor":"hắn giơ tay phải lên, hai mắt loé lên kim quang, liền có một luồng kim quang dũng mãnh nhập vào ngón tay trỏ","bridge":true,"khoang":"@c1470"},{"mucCt":"ky","text":"Trên đường về Chu Tước Tinh bái tế cha mẹ, cảm nhận khí tức Thập Tam và phân thân Cổ Yêu nên ghé vào khách sạn trên tu chân tinh buôn bán. Gặp lại Thập Tam, nhận xét hắn càng ngày càng giống mình năm đó. Ngồi nghe Chu Tử Hồng kể chuyện cũ của chính mình, uống rượu, lòng bi ai nhớ cha mẹ, nhớ lại ánh mắt bất lực cầu cứu của Lý Mộ Uyển năm xưa. Quay đầu mỉm cười với Chu Tử Hồng rồi rời đi. Trên đỉnh núi từ chối cho Thập Tam theo hầu, dạy bảo phải tự đối mặt gió mưa, có ý chí nghịch thiên, tuyên bố từ nay Thập Tam lấy danh nghĩa đồ đệ hắn bắt đầu con đường tu đạo riêng. Vỗ đỉnh đầu Thập Tam. Tiết lộ dự định ở Chu Tước Tinh luyện hoá ba bổn nguyên nhân quả, sinh tử, chân giả.","anchor":"Đệ tử của Vương Lâm ta phải có một ý chí nghịch thiên, phải có một sự kiên định và quyết tâm đội trời đạp đất!","bridge":true,"khoang":"@c1471"},{"mucCt":"ky","text":"Dùng một chưởng hóa cảm ngộ đại thành về lôi hỏa bổn nguyên thành hạt giống màu vàng chứa tiên lực huyết mạch, gieo sâu vào hồn phách Thập Tam. Lấy lại pho tượng Cổ Yêu từ Thập Tam, đặt trong không gian trữ vật chờ thời điểm mấu chốt mới hấp thụ vào mắt trái, muốn chờ pho tượng lớn thêm. Dặn dò Thập Tam sống theo lương tâm, tìm nữ tử mình yêu thích, nói dù gây đại họa đã có sư phụ che. Nhớ lại Cổ Yêu bắt ở La Thiên vẫn bị phong ấn, không quên lời hứa cho hắn một con đường sống. Đi ngang cửa lớn Vũ Tiên Giới nhưng không đủ thời gian nên không vào, quay đầu nhìn rồi rời đi, hướng tới tu chân tinh cấp bảy tìm người điên. Bước ra từ gợn sóng tinh không bên ngoài tu chân tinh, nhìn lướt qua phát hiện tình trạng đệ tử lừa người điên, nhướn mày lóe hàn quang nói một chữ “Hồ đồ!”.","anchor":"Hắn đến một mình, và đi cũng một mình","bridge":true,"khoang":"@c1472"},{"importance":"bridge","mucCt":"gon","chuong":"@c1473","tieuDe":"Bắt quả tang Hứa Lập Quốc và Lưu Kim Bưu lừa đảo","text":"Xuất hiện dưới dạng thân ảnh áo trắng phía sau đám người đang diễn kịch, ánh mắt hàn quang, quát đích danh Hứa Lập Quốc và Lưu Kim Bưu.","anchor":"Hứa Lập Quốc, Lưu Kim Bưu, hai ngươi thật là to gan lớn mật! Được, được lắm!"},{"mucCt":"ky","text":"Xuất hiện trong động phủ, uy áp chấn nhiếp toàn bộ tu sĩ khiến họ phun máu. Chỉ một ngón tay phế ba thành tu vi Hứa Lập Quốc vì dám đem người điên ra cho bọn họ chơi đùa, nói rõ nếu không có công lao trước đó sẽ hủy hồn phách. Đánh bắn Lưu Kim Bưu, tước cơ duyên tự do, bắt làm nô bộc một ngàn năm vì bản tính khó sửa. Vung tay áo cuốn cả hai thu vào không gian trữ vật, lấy lại hơn phân nửa giọt máu màu vàng. Mang người điên rời đi hướng về Chu Tước Tinh. Nhìn bộ dạng nói liến thoắng của người điên, mơ hồ cảm thấy giống một người từng gặp một lần ở giới ngoại Thái Cổ Tinh Thần, gần như đã quên.","anchor":"cảm thấy cái bộ dạng của đối phương hiện giờ, nhất là cái miệng nói liến thoắng kia dường như rất giống một người","bridge":true,"khoang":"@c1474"},{"mucCt":"ky","text":"Mang theo người điên đi qua tinh không trở về quê hương Chu Tước Tinh, thân thể khẽ run khi nhìn thấy quê nhà. Nhiều khuôn mặt người thân hiện lên trước mắt, cảm thán cảnh còn người mất. Phát hiện bên ngoài Chu Tước Tinh có trận pháp mênh mông mới được bố trí vài thập niên gần đây, lúc hắn ra đi chưa có. Vạch trần trò lừa của người điên: máu hắn hứa cho Hứa Lập Quốc và Lưu Kim Bưu chỉ là thứ vất đi, chẳng bằng nửa giọt máu chính thức. Chọn đi từ cửa chính qua trận pháp vào quê hương, hai hư ảnh canh trận pháp thấy quen mặt nhưng không nhận ra hắn. Chu Tước Tinh nay được tu sĩ giới nội tôn sùng là thánh địa, cố hương của Phong Tôn.","anchor":"Hắn dù nhắm mắt cũng có thể tìm được Chu Tước Tinh","bridge":true,"khoang":"@c1475"},{"mucCt":"ky","text":"Trở lại Chu Tước Tinh cùng người điên, đứng trên thang trời nhìn pho tượng khổng lồ khắc hình chính mình (Phong Tôn) tay cầm Khai Thiên Phủ trên ngọn núi cao nhất. Lang thang tìm lại những nơi cũ: Luyện Hồn Tông đã biến mất thành hồ nước, Cự Ma tộc thành thảo nguyên du mục, Tuyết Vực quốc không còn tuyết, thành trì phàm nhân nơi hắn ở gần trăm năm thành phế tích, Tu Ma Hải sương tan sơn động với Lý Mộ Uyển không còn, sơn cốc nơi Lý Mộ Uyển già đi và Chu Như lớn lên bị san bằng thành biển. Cả Chu Tước Tinh trở thành một quốc gia duy nhất với cửu đại tông môn, không còn chút quen thuộc, cô độc tột cùng. Phá trận pháp hào quang bảo vệ Triệu Quốc bằng lực vô hình, kinh động toàn bộ tu sĩ đại thần thông và cửu đại tông môn. Dùng Súc Địa Thành Thốn tới Hằng Nhạc Sơn, tìm thấy ngôi nhà năm xưa ở Hoàng Tổ Hảo không hề thay đổi. Quỳ trước mộ cha mẹ được hậu nhân đời đời tu bổ, khóc, vuốt bia mộ, tự xưng Thiết Trụ, nói chỉ cần cha mẹ còn sống, cả nhà (mình, Uyển Nhi, Bình Nhi) đoàn tụ, không cần gì khác.","anchor":"Cha, mẹ……Thiết Trụ quay về thăm cha mẹ đây……","bridge":true,"khoang":"@c1476"},{"mucCt":"ky","text":"Vương Lâm quỳ trước ngôi mộ cha mẹ tại Triệu Quốc, vuốt ve bia mộ, nước mắt rơi thấm ướt mộ. Từ cơ thể phát ra ánh sáng nhẹ nhàng bao phủ ngôi mộ, bên cạnh xuất hiện ba hư ảnh — nữ tử quỳ bên trái, thanh niên tướng mạo giống hắn cùng một nữ tử bên phải — cả bốn người quỳ trước mộ như gia đình đoàn tụ. Chu Vũ Thái xuất hiện, hai người cùng uống rượu Tằng gia cất từ ngàn năm trước, ôn chuyện cũ suốt đêm. Vương Lâm cảm ơn Chu Vũ Thái đã thủ hộ nơi này. Nghe tin Vân Tước Tử đã chết, Chu Tử Hồng rời đi, Tằng Ngưu thành đệ tử Chu Vũ Thái. Cuối cùng Chu Vũ Thái trong trạng thái hồn say nói ra: Hồng Điệp có thể vẫn chưa chết.","anchor":"Người có thể có tư cách quỳ trước ngôi mộ này, có thể có tư cách ở trước ngôi mộ này mà rơi lệ, có tư cách nói ra hai chữ cha mẹ, trong thiên địa này chỉ có một, đó chính là Phong Tôn!","bridge":true,"khoang":"@c1477"},{"text":"Nghe Chu Vũ Thái kể về trận pháp chứa tóc Hồng Điệp, phân tích đây là Hồn Truyền Tống Trận cần tu vi Tịnh Niết hậu kỳ đại viên mãn mới bố trí được, kết luận Hồng Điệp có thể chưa chết — phần hồn phách đã được truyền tống đi. Nghe tin Tuyết Vực Quốc và Cự Ma tộc đều từ bên ngoài tới Chu Tước Tinh. Thông báo cho Chu Vũ Thái rằng Liễu Mi đã chết. Giữ đạo hiếu bảy ngày trước mộ phụ mẫu tại Triệu Quốc, ngày thứ tám dập đầu rồi trở lại con đường tu chân. Quyết định khám phá tầng thứ 19 hố sâu Phù Văn tộc, mang theo người điên bay đi.","anchor":"Một bước này hắn từ một phàm nhân du đãng hồi hương lại trở lại làm tu sĩ lần thứ hai!","mucCt":"ky","bridge":true,"khoang":"@c1478"},{"mucCt":"ky","text":"Một mình đi vào hố sâu Phù Văn tộc, xuyên qua các tầng không gặp trở ngại, phong ấn tầng 16 tự sụp trước uy áp vô hình trên người. Tới tầng 18 nắm ngọn lửa bổn nguyên vuốt tan nát, lộ ra cánh cửa hình tròn dẫn vào tầng 19 với phong ấn dày đặc phù văn tích luỹ vô số năm, lực phong ấn tổng hợp ngang Thiên Nhân đệ ngũ suy. Dùng kim quang phá toàn bộ phong ấn chỉ còn ký hiệu cuối cùng — một vòng tròn đơn giản chứa cả uy áp huyết mạch tiên nhân lẫn khí tức Đạo Cổ. Cảm nhận khí tức quen thuộc của Đạo Cổ Diệp Mịch, suy đoán vật bị phong ấn chính là mắt trái Đạo Cổ Diệp Mịch bị Lý Quảng bắn rơi năm xưa, mũi tên dính máu Lý Quảng khiến mắt trái mang cả hai khí tức bài xích, Phù Văn tộc lợi dụng lực bài xích đó biến thành phong ấn.","anchor":"mắt trái của Đạo Cổ Diệp Mịch không ngờ ở nơi này","bridge":true,"khoang":"@c1479"},{"mucCt":"ky","text":"Nhận ra phong ấn tầng 19 là sự dung hợp tiên lực và Đạo Cổ khí tức, chỉ người đồng thời mang cả hai mới mở được — trong thiên địa chỉ mình hắn đủ điều kiện. Hồi tưởng chuỗi nhân duyên từ khi rời Chu Tước Tinh qua vùng Yêu Linh, La Thiên tinh vực, gặp U Minh thú, gặp người điên nhận huyết mạch tiên nhân — thiếu một mắt xích nào cũng không thể mở phong ấn. Dồn lực bài xích ra ngón trỏ, chịu đau đớn cực hạn vẽ lại ký hiệu vòng tròn trên cánh cửa đá trong khoảng một nén nhang rưỡi. Khi hoàn thành, phản lực bùng nổ phá vỡ Quang ảnh thuẫn, đẩy bật Thiên Hoàng Lô trở về mi tâm, đánh hắn lùi hơn mười trượng va vào vách tường nứt nẻ. Cánh cửa đá mở ra sau vạn năm phong ấn. Bước vào tầng 19 qua thông đạo kỳ dị do vòng tròn tiên lực–Đạo Cổ dung hợp tạo thành, bên trong tràn ngập khí tức tang thương và hơi thở ác liệt. Tiến tới vòng tròn cuối cùng rộng mấy ngàn trượng và bước vào trung tâm. Phát hiện phong ấn này cho hắn thấy một con đường khác khiến lực bài xích trong cơ thể tiêu tán.","anchor":"Trong thiên địa này cũng chỉ có mình hắn mới có thể là người mở ra được phong ấn này","bridge":true,"khoang":"@c1480"},{"mucCt":"ky","text":"Tiến vào thiên địa bên trong phong ấn, thấy mũi tên dài mấy vạn trượng xuyên thấu bầu trời bị mắc kẹt một nửa. Hàn khí từ mũi tên kích hoạt ký ức truyền thừa Đạo cổ ở mắt trái, mắt trái chảy máu, phun máu rồi thổ nạp hồi phục. Phân tích và ghép nối toàn bộ lai lịch mũi tên Lý Quảng: Lý Quảng bắn rơi mắt trái Đạo cổ trong vùng đất cổ mộ, mũi tên bay xuyên tinh không phá mấy tu chân tinh, mắt trái tách rơi vào tinh hải, mũi tên phá vào thiên địa ẩn giấu rồi mắc kẹt, sát khí và máu mắt trái dung hợp tiên-cổ hủy diệt toàn bộ thiên địa. Suy luận ra Phù Văn Tộc tìm được mũi tên nhưng không điều khiển được, phong ấn lại chờ Chưởng Tôn. Cuối cùng ngồi lên mũi tên, dùng tinh điểm Cổ Thần hấp thụ vết máu mắt trái Đạo cổ chứa yêu khí cực đậm, đồng thời lấy pho tượng Cổ Yêu ra ấn tay trái vào.","anchor":"Tinh điểm cổ Thần trên mi tâm hắn nhanh chóng chuyển động, bắt đầu hấp thụ","bridge":true,"khoang":"@c1481"},{"mucCt":"ky","text":"Dùng mười ngày luyện hóa huyết dịch mắt trái Đạo cổ trên đầu mũi tên, chuyển cổ Yêu lực vào pho tượng, ngưng tụ tinh điểm thứ sáu. Phá phong ấn cổ Yêu lấy từ Huyết Thần Tử, đập tan yêu tinh dồn yêu lực, tinh điểm thứ bảy thành hình. Giữ lời hứa năm xưa, lưu hồn phách cổ Yêu Huyết Thần Tử phong ấn cất giữ. Vận chuyển huyết mạch tiên lực hiện cung Lý Quảng trong cơ thể, cảm ứng linh hồn mũi tên khổng lồ, ra lệnh thu nhỏ nhiều lần từ vạn trượng thành kích thước bình thường. Triệu Thiên Hoàng Lô, lôi hồn Nam Chiếu Thượng Nhân và Thiên Triệu Thượng Sư gia tăng vào hai trong bốn ký hiệu trên mũi tên. Lấy lầu các địa phủ Diệp Mịch cân nhắc dùng ba thần hồn bên trong nhưng quyết không thả vì thực lực chưa đủ. Thu mũi tên hóa bảy đạo kim quang nhập thất khiếu. Quay về tầng 18 Phù Văn Tộc, phong ấn cửa đá, phát hiện khe nứt vách tường thông tới chiến trường vực ngoại.","anchor":"Từ nay về sau, đây sẽ là bảo vật của Vương Lâm ta","bridge":true,"khoang":"@c1482"},{"mucCt":"ky","text":"Bị tách khỏi Chu Tước Tinh thật vào vùng thiên địa lam quang do toàn bộ cao thủ Không Huyền Thái Cổ Tinh Thần liên thủ cùng Viễn Cổ Tiên Phi bố trí, không ai trong giới nội phát hiện, thời hạn ba canh giờ. Lam Mộng Đạo Tôn hiện thân niệm tình cũ cảnh báo, khẳng định không tham gia giết Phong Tôn đời trước. Ba cao thủ tu vi Không Huyền bị áp chế còn Không Linh Trung Kỳ (lão già áo xám, bà lão áo đen, nam tử áo trắng) liên thủ tấn công. Thi triển Hô Phong Thuật cực hạn (13 hắc long, gió kim quang màu vàng) đối kháng rồng xám, Quang Ảnh Thuẫn bị hàn kiếm đóng băng xuyên thấu, Dịch Linh Ấn bị cắt đứt lần đầu. Rút huyết kiếm đánh vỡ hàn kiếm đối phương. Phun máu hai lần bị thương nặng nhưng chiến ý điên cuồng, tuyên bố không ai quyết định được vận mệnh của hắn. Tái thi triển Dịch Linh Ấn chưởng ấn kim quang vạn trượng, kim quang bí ẩn khiến lão già áo xám mơ hồ sợ hãi.","anchor":"Không ai có thể quyết định vận mệnh của ta, sinh tử kiếp cũng không thể!","bridge":true,"khoang":"@c1484"},{"mucCt":"ky","text":"Bị ba cường giả giới ngoại (lão già áo xám, bà lão áo đen, nam tử bạch y) phối hợp phá hủy Dịch Linh Ấn, trọng thương nghiêm trọng — thân thể bị hóa đất và hàn khí xâm nhập, phun máu vàng nhiều lần. Liên tiếp dùng Thiên Hoàng Lô rồi Quang Ảnh Thuẫn phòng thủ nhưng đều bị hủy trong nháy mắt. Triệu Cổ Thần hộ tí — hư ảnh Cổ Thần khổng lồ hiện ra hứng ba sát chiêu, tinh điểm trên mi tâm nổ tung đánh lui ba người, cánh tay cuối cùng ôm Vương Lâm ném xuống nước rồi tiêu tán hoàn toàn, hộ tí tan nát chia lìa. Từ đáy nước phản công liều mạng: dùng một quyền cùng đầu lâu đạo cổ bức lui nam tử bạch y, dùng lôi đình truyền tiên lực thành tiên lôi đánh lão già áo xám, dùng lửa tiên lực đánh bà lão áo đen — cả ba phun máu lùi lại, hoảng sợ nhận ra hắn sở hữu tiên lực. Tranh thủ cơ hội điểm chỉ lên trời thi triển Phần Giới Cổ Tán, bầu trời hóa cây ô khổng lồ màu lam rồi biển lửa bao phủ.","anchor":"Nguy cơ lúc này là kiếp nạn lớn nhất trong đời Vương Lâm! Đây là tử kiếp!","bridge":true,"khoang":"@c1485"},{"mucCt":"ky","text":"Hiến tế sinh cơ toàn thân kích hoạt Phần Giới Cổ Tán, tạo biển lửa diệt thế bao phủ thiên địa. Điều khiển lửa giết hình chiếu bà lão hắc y, đánh trọng thương lão già áo xám, phong ấn nam tử bạch y. Khuôn mặt nhanh chóng già đi, sinh cơ cạn kiệt, lực bài xích hành hạ toàn thân. Khi tiến tới định giết nam tử bạch y thì bị nữ tử bí ẩn xuất hiện thi triển Ngũ Tạng Tiên Đạo — hai quả thận héo rũ hóa máu tiêu tan, lực khôi phục Cổ thân cũng không phục hồi nổi, tiếp đến phế và tỳ bị nhắm tới. Phun máu lui ba bước nhưng sát khí trong mắt càng đậm, tuyên bố chán ghét tu đạo, chỉ muốn trước khi chết giết thêm vài người.","anchor":"Lão tử vốn chán ghét tu đạo, có thể trước khi chết giết thêm vài người vậy là đủ rồi","bridge":true,"khoang":"@c1486"},{"mucCt":"ky","text":"Bị nữ tử tiên phi hoàn tất Ngũ tạng kỳ thuật — can tạng vỡ nát, tâm tạng hóa đá, ngũ tạng mất bốn, sinh cơ chặt đứt, Giới Cổ Tán tiêu tán. Thử ngọc giản truyền tống và triệu hoán U Minh thú đều thất bại do phong ấn. Cương quyết không quỳ, thề báo thù gấp trăm lần. Dung nhập tiên lực kim quang thi triển Hô Phong Hoán Vũ + Sơn Băng Địa Liệt dưới dạng tiên thuật để câu thời gian. Lần đầu thi triển Âm Nguyệt Hữu Tình — vầng trăng sáng xuất hiện trên mặt nữ tử tiên phi, khe nứt lan từ mặt xuống cổ, hủy dung hoàn toàn. Dùng Cổ lực đấm thẳng vào nữ tử, lực phản chấn ngưng tụ bạo tăng, đánh lùi tiên phi hơn mười trượng khóe miệng chảy máu, nhưng cánh tay phải vỡ nát từ đốt ngón tay, thất khiếu chảy máu. Bị tiếng đàn Táng Hoàng Tuyền oanh kích tâm thần, lùi trăm trượng thất khiếu chảy máu. Phóng huyết kiếm phát hiện nữ tử tử y phía sau nhưng huyết kiếm xuyên qua thân hư ảo không hiệu quả. Bị nữ tử tử y dự ngữ ba nhịp thở tử vong.","anchor":"Vương Lâm không quỳ trước thiên địa, sao có thể quỳ gối trước ngươi","bridge":true,"khoang":"@c1487"},{"mucCt":"ky","text":"Bị thuật bói toán của Tiên Phi tấn công ba nhịp (thịt nát, tan xương, hồn phách tan), gần chết nhưng vẫn giữ cây cung chờ Chưởng Tôn. Bị dồn đường cùng, vỗ tay phải vào mi tâm chuyển đổi từ thân Cổ Thần sang tiên thể, bộc lộ tiên nhân bất diệt thể chưa hoàn chỉnh. Kim quang vạn trượng bao phủ thiên địa, thân Cổ Thần ẩn vào bảy tinh điểm trên mi tâm. Hệ quả nghiêm trọng: lực bài xích hoàn toàn bộc phát không thể khống chế, thân thể liên tục tan vỡ rồi tự ngưng tụ. Trong trạng thái đó thi triển Tàn Dạ và Lưu Nguyệt dung hợp tiên lực phản công, phá phần lớn phi đao và khiến nữ tử bói toán phun máu. Ngay sau đó bị Hư Thần Thiên Tôn đánh một chưởng vào hậu tâm, phun máu vàng bắn thẳng xuống Chu Tước Tinh.","anchor":"tiên thể do huyết mạch tiên lực ngưng tụ thành cũng ẩn chứa một sức mạnh bất diệt","bridge":true,"khoang":"@c1488"},{"mucCt":"ky","text":"Thân thể bất diệt rơi xuống Chu Tước Tinh, xuyên tới tầng 18 Phù Văn Tộc, không ngừng tan vỡ rồi ngưng tụ. Hư Thần Thiên Tôn hóa sương mù dung nhập đoạt xá tiên thể, chiếm gần hết thân thể và ký ức, chỉ còn tay trái mơ hồ điều khiển được. Dùng tay trái bấm ấn ký triệu hồi vô số du hồn từ chiến trường vực ngoại, chúng coi hắn như vua, hình thành cơn lốc đen khổng lồ đẩy Hư Thần Thiên Tôn ra khỏi thân xác, đoạt xá thất bại. Sau khi thân thể ngưng tụ lại, rút cung Lý Quảng giương mũi tên chứa hồn phách Nam Chiếu và Thiên Triệu, uy lực kinh hoàng khiến Hư Thần Thiên Tôn hoảng sợ lui lại tuyên bố không tham gia nữa, hai Tiên Phi run rẩy lùi lại, cả ba bóp ngọc giản muốn rời đi nhưng không có phản ứng.","anchor":"Hai mắt hắn mở bừng ra, lộ kim quang vạn trượng, nhìn chằm chằm Hư Thần Thiên Tôn đang lao tới","bridge":true,"khoang":"@c1489"},{"text":"Quyết định dùng mũi tên vốn dành cho Chưởng Tôn để đối phó bốn kẻ thù. Dồn toàn bộ linh hồn, nguyên thần, sức mạnh Đạo Cổ, tiên huyết mạch vào một tiễn duy nhất. Phản lực khiến thân thể chấn động, máu tràn, rơi xuống mặt nước. Mũi tên giết chết nam tử áo trắng, Tiên Phi Âm Nguyệt, Hư Thần Thiên Tôn; xuyên qua Tiên Phi bói toán nhưng bị viên đá đen bảo hộ cản. Dư lực mũi tên lao về phía phong ấn bầu trời nhưng bị Chưởng Tôn xuất hiện chụp lấy. Sau tiễn này không còn sức sống để hiến tế kéo cung lần nữa.","anchor":"linh hồn, nguyên thần cùng với toàn bộ sức mạnh trong cơ thể của Vương Lâm, sức mạnh Đạo Cổ, sức mạnh của tiên huyết mạch, tất cả những sức mạnh mà hắn có được","mucCt":"ky","bridge":true,"khoang":"@c1490"},{"mucCt":"ky","text":"Chưởng Tôn hiện thân sau khi mũi tên bắn xong, xóa tan mũi tên bằng tay nhưng mũi tên theo phương thức kỳ dị quay về trong hồn Vương Lâm. Chưởng Tôn triệu mặt trời dùng bổn nguyên thái sơ quy tắc phóng cột sáng bao phủ, thiêu hủy toàn bộ du hồn, tách hoàn toàn huyết mạch tiên nhân khỏi cơ thể. Toàn bộ tiên huyết và tủy sống ngưng tụ thành giọt máu tỏa kim quang vạn trượng chứa nửa ký hiệu tiên nhân bất diệt thể. Tinh điểm Cổ Thần trên mi tâm và tinh điểm Cổ Ma ở mắt phải không còn kim quang, cơ thể trở về thân Cổ Thần thuần túy. Chịu đau cực hạn nhưng không kêu, vẫn giấu chiêu sát thủ chờ thời cơ. Khi Chưởng Tôn giơ tay định cầm giọt máu, cắn lưỡi phun máu Đạo Cổ mở một cửa sổ Hắc Tháp giải phong ấn Xích Hồn Tử. Xích Hồn Tử được giải phóng nhưng không đánh Chưởng Tôn mà lao nuốt Tiên Phi rồi phá bầu trời bay đi.","anchor":"hắn vẫn còn đang chờ đợi, chờ tới thời điểm mấu chốt, chờ cho đối phương tới gần thêm chút nữa mới xuất ra chiêu sát thủ có thể thay đổi hết thảy này","bridge":true,"khoang":"@c1491"},{"mucCt":"ky","text":"Xích Hồn Tử phá tan phong ấn Tĩnh Trung Lao Nguyệt, Vương Lâm thoát khỏi trạng thái giam cầm. Nắm lấy huyết dịch tiên nhân bất diệt thể màu vàng trên đỉnh đầu trước Chưởng Tôn. Thái sơ lực và Tĩnh Trung Lao Nguyệt của Chưởng Tôn vô tình tách cổ lực và tiên lực trong cơ thể, hóa giải hoàn toàn lực bài xích chí mạng. Thân thể trở về thuần Cổ Thần, ngũ tạng tái sinh, thương thế hồi phục nhanh chóng. Quyết định luyện hóa huyết dịch tiên thể thành pháp bảo tiên thể dung nhập cơ thể theo phương thức tránh bài xích. Lao về phía lỗ thủng định thoát nhưng bị Lam Mộng dùng lam quang chặn lỗ thủng bắn ngược lại. Đối mặt cây trường thương bảy màu mang khí tức hủy thiên diệt địa do Chưởng Tôn ném tới.","anchor":"Mất đi tiên thể, mất đi huyết mạch tiên nhân nhưng thân thể Vương Lâm lại một lần nữa trở về thân thể của cổ Thần, không còn lực bài xích nữa","bridge":true,"khoang":"@c1492"},{"mucCt":"ky","text":"Thất Thải Thương lao tới với sức hủy thiên diệt địa, Vương Lâm biết không thể tránh, nhắm mắt buông xuôi chấp nhận cái chết. Lồng ngực vỡ tung, huyết nhục bị xé, thân thể tan vỡ. Trong khoảnh khắc cuối hồi tưởng ba cảnh ấm áp: cha mẹ ở quê nhà, Lý Mộ Uyển đánh đàn trong sơn cốc, Bình Nhi trên đỉnh núi hứa ở cùng cha mãi mãi. Nói lời từ biệt cha mẹ, xin lỗi Uyển Nhi vì không có sức mạnh khiến nàng thức tỉnh, xin lỗi Bình Nhi. Người điên đột ngột xuất hiện từ lam quang, phát tiếng rống kinh thiên lao vào ánh sáng bảy màu ôm lấy Vương Lâm đang hôn mê. Cả hai bị hắc động hút vào biến mất.","anchor":"Cha, mẹ. Thiết Trụ mệt quá rồi. Con đến với cha mẹ nhé.","bridge":true,"khoang":"@c1493"},{"chuong":"@c1494","importance":"major","mucCt":"ky","tieuDe":"Thi triển Mộng Đạo, rơi vào giấc mộng ngàn năm","text":"Trong hư vô sau sát kiếp, thân thể tan nát được giọt máu vàng bao phủ bảo hộ cùng người điên. Gắng tỉnh dậy chốc lát, mở khe trữ vật lấy ba Thăng Tiên Quả thu nhỏ nuốt vào để lấy đạo niệm. Nắm tay người điên liên kết, rồi dùng tia lực lượng cuối cùng thi triển thần thông thứ ba Mộng Đạo trên bản thân, mộng về ngàn năm trước nhằm khiến sinh tử, nhân quả, thật giả — ba đạo bổn nguyên hoàn toàn đại thành. Sau đó rơi vào giấc mộng, hóa thành thanh niên thư sinh say rượu trong nhà trọ bên đường, ngâm thơ rồi nói vừa mơ thấy bản thân thành tiên.","anchor":"Lấy thuật Mộng Đạo dùng trên bản thân, mộng về ngàn năm trước"},{"mucCt":"ky","text":"Toàn bộ chương diễn ra trong một thực tại mà Vương Lâm là thư sinh phàm nhân mười tám mười chín tuổi, quê ở sơn thôn vùng rừng núi thuộc Triệu quốc, lần đầu rời nhà vào kinh ứng thí. Tại nhà trọ bên quan đạo, hắn tỉnh dậy sau cơn say rượu chỉ hai chén, tiểu nhị kể đêm qua hắn nói mộng thành tiên. Hắn nhớ rõ giấc mộng tu tiên: ba năm trước tứ thúc đến, hắn gia nhập Hằng Nhạc phái, nhưng chỉ nhớ tới đoạn gia nhập, phần sau hoàn toàn trống. Hắn thử thi triển Dẫn Lực Thuật theo ấn quyết trong trí nhớ mộng nhưng chén trà không nhúc nhích, xác nhận hoàn toàn là phàm nhân. Hắn tự nhủ không tin quỷ thần, sửa soạn hành trang lên đường vào kinh ứng thí, mang chí nguyện đỗ đạt bảng vàng rồi đón cha mẹ rời sơn thôn. Trên đường gặp mưa, hắn đứng dưới gốc cây ngắm cảnh ngâm thơ, bị một cô gái xinh xắn trên đầu thuyền gần bờ mắng là thư sinh ngốc, hắn sửng sốt gãi đầu.","anchor":"Giấc mộng đó thật chân thật, hầu như khiến người ta không phân biệt được","bridge":true,"khoang":"@c1495"},{"mucCt":"ky","text":"Trong thân phận thư sinh phàm nhân, lần đầu ra khỏi thôn, Vương Lâm trú mưa bên bờ sông và gặp Từ Phi cùng Chu Nhị trên thuyền. Mặt đỏ bừng ngượng ngùng vì lần đầu thấy thiếu nữ đẹp. Được Chu Nhị dùng thân pháp đỡ lên thuyền khi trượt chân. Nhận ra Chu Nhị có bản lĩnh phi phàm, bắt đầu hoảng hốt. Bị Chu Nhị thi triển pháp thuật khiến dần buồn ngủ rồi ngủ say. Trước khi mất ý thức, lờ mờ nghe được các từ khóa về tu tiên và Hằng Nhạc Phái.","anchor":"Ta đang nằm mơ sao… Vương Lâm nhắm hai mắt, ngủ say.","bridge":true,"khoang":"@c1496"},{"text":"Vương Lâm ngủ trên thuyền, mơ gọi tên Từ Phi, Chu sư tỷ, Vương Trác, Vương Hạo, Trương Hổ, mộng thấy cảnh Hằng Nhạc Phái. Tỉnh dậy trải qua cô độc tịch mịch cực mãnh liệt, nước mắt tự rơi, mơ hồ nhìn thấy ảo ảnh kiếp tu tiên: vực sâu vạn trượng, thân ảnh cô độc trong khe đá, thanh niên áo trắng tóc trắng đi trong tinh không. Vô thức giơ tay chỉ ngọn đèn khiến nó tự bốc cháy mà không hay biết. Con chim bi ai bay lướt qua, nỗi bi ai tiêu tan, ngọn đèn tắt. Hai tu sĩ cầu vồng xuất hiện, nữ tử áo lam cảm thấy quen hắn nhưng sư huynh nhận định hắn chỉ là phàm nhân. Thu hành trang, cất áo khoác nữ tử áo tím, xuống thuyền lên đường.","mucCt":"ky","anchor":"Sự bi ai này như đến từ trong linh hồn, như đến từ trong thiên địa, dường như thiên địa chính là linh hồn của hắn","bridge":true,"khoang":"@c1497"},{"mucCt":"ky","text":"Sau khi chứng kiến nữ tử bay qua trời, Vương Lâm dâng trào nỗi đau đớn khó hiểu, cảm thấy thân ảnh nữ tử đã tồn tại trong hắn vô số năm tháng, sắc mặt trắng bệch, thân thể lảo đảo. Hắn thốt lên rằng thật sự có tiên nhân tồn tại rồi tự hỏi mình mơ thành tiên nhân hay tiên nhân mơ thành mình, lần đầu thân phận phàm nhân ý thức rõ ràng về sự tồn tại của tiên nhân. Suốt bảy ngày hành trình cô độc trên quan đạo tới kinh thành, thân thể phàm nhân từ yếu ớt dần rắn chắc, ban đêm ngủ dưới gốc cây trong bóng tối không hề sợ hãi mà trái tim bình lặng như nước. Ngày thứ tám gặp mưa bão lớn, trú trong miếu thổ địa bỏ hoang có mấy bộ xương trắng trong sân, gặp nam tử trung niên điên quần áo tả tơi chạy vào miếu vừa khóc vừa cười lẩm bẩm hỏi mình là ai. Vương Lâm nổi lòng thương xót, thì thào suy tư triết lý về mộng tựa nhân sinh, mộng là sinh tỉnh lại là tử, nhân sinh có lẽ là luân hồi hay nhân quả và khi nào mới tỉnh, đánh dấu bước tiến quan trọng trong quá trình ngộ đạo Toái Niết dưới thân phận phàm nhân.","anchor":"Nhân sinh có lẽ là một sự luân hồi, có lẽ cũng là một hồi nhân quả.chỉ là khi nào mới tỉnh","bridge":true,"khoang":"@c1498"},{"mucCt":"ky","text":"Trong miếu hoang đêm mưa, Vương Lâm chia lương khô cho người điên rồi trò chuyện suốt đêm, thổ lộ lý tưởng vào kinh ứng thí vì cha mẹ và nỗi hoang mang không phân biệt nổi mộng-thực. Nhờ lời người điên, hắn dần minh bạch: dù nhân sinh là giấc mộng thì hắn cũng muốn sống vui vẻ, kiên định bước tiếp, coi đây là một cuộc đời khác của mình. Trong đêm tối khi lửa tắt, hắn phát hiện cổ tay phải người điên phát kim quang mơ hồ hiện hình một dấu tay, cảm giác vô cùng quen thuộc nhưng không nhận ra. Sáng hôm sau, hắn không nỡ bỏ lại người điên, quay đầu nói thiếu một thư đồng và nhận người điên đi cùng — hành vi này chính là luân hồi lặp lại chuyện cũ ở Nhân phương giới vùng đất Điên Lạc.","anchor":"Cho dù là mộng thì Vương Lâm ta cũng là một cuộc đời khác!","bridge":true,"khoang":"@c1499"},{"mucCt":"ky","text":"Trong kiếp luân hồi thân phận thư sinh, Vương Lâm cùng thư đồng Đại Phúc đi tới huyện thành ứng thí, gặp bão lớn tại nhà trọ. Trong bão, nhìn thấy cánh chim trắng từng thấy trong mộng bay tới đậu trước cửa sổ, trong đầu vang tiếng nói mê mang về nhân quả. Sấm sét quấy rầy, theo tiềm thức điểm một chỉ ra ngoài cửa sổ, mắt phải lóe ấn ký hình tia chớp. Ý chí như quân vương lôi điện hiệu lệnh toàn bộ sấm sét, mây mưa Triệu quốc ngừng hẳn trong nháy mắt. Tu vi chân thực bộc phát xuyên qua kiếp luân hồi phàm nhân, chấn động mọi tu sĩ trong Triệu quốc.","anchor":"Một chỉ này điểm tới, trong mắt phải của hắn đột nhiên có một đạo ấn ký hình tia chớp lóe lên","bridge":true,"khoang":"@c1500"},{"mucCt":"ky","text":"Suốt đêm trầm tư vì tiếng nói về nhân quả vang vọng trong đầu, mi tâm mơ hồ đau nhức. Năm ngày chuẩn bị kỳ thi, hầu như không rời nhà trọ, lo lắng vì không muốn cha mẹ chịu ánh mắt cười nhạo của họ hàng. Vào trường thi, ngồi cả ngày không hạ bút trong khi mọi thí sinh đã viết xong theo đề đống lương chi tài. Gần hết giờ mới bừng tỉnh, hạ bút viết bài luận riêng biệt về nhân quả. Giám quan già đánh giá hắn sẽ thành đại nho một đời, khoanh tròn tên. Rời trường thi thì bị sư huynh Độn Thiên dùng hắc phong bao phủ.","anchor":"Suy tư với nhân quả tới mức này không ngờ lại xuất hiện ở một thiếu niên","bridge":true,"khoang":"@c1501"},{"mucCt":"ky","text":"Được Niệm Thiên (tông chủ Luyện Hồn tông, Anh Biến) tìm tới sau chín lần tính toán, hoàn toàn bình tĩnh trước uy áp tiên nhân, được đánh giá có khí tức đại nho ngang hàng đại nho mấy trăm năm mới xuất hiện. Yêu cầu được đưa tới Luyện Hồn tông, đi khắp sơn môn với cảm giác quen thuộc mãnh liệt như đã từng ở đây, thậm chí biết trước chỗ nguy hiểm. Khi nhìn thấy Độn Thiên, trong đầu ầm ầm nổ vang, mơ hồ nhớ ra điều gì đó, hai hàng nước mắt chảy xuống. Thì thào nói ra lời tiên tri: mấy trăm năm sau ngày Độn Thiên tọa hóa tử vong sẽ có người tới, đó chính là thông thiên lộ của Luyện Hồn tông.","anchor":"Luyện Hồn tông, mấy trăm năm sau ngày ngươi tọa hóa tử vong thì sẽ có một người tới nơi này. Hắn chính là thông thiên lộ của Luyện Hồn tông!","bridge":true,"khoang":"@c1502"},{"mucCt":"ky","text":"Bị đưa trở về huyện thành Triệu quốc, đứng bên cây đại thụ ngoài trường thi, cảm thán đã hơi hiểu rõ nhân quả. Nhìn thấy cánh chim trắng biến mất trong tầng mây. Đậu tú tài nhưng hoàn toàn bình thản, lấy bằng chứng công danh và ngân lượng thưởng rồi rời đi. Tâm tính thay đổi sâu sắc: không còn ý niệm được mất, khí tức đại nho bừng lên, tâm như nước lặng trong giếng cổ. Tự nhủ nhân sinh như mộng, giấc mộng này không muốn tỉnh lại. Rời huyện thành, hai tháng đi đường uống rượu ngắm cảnh, tửu lượng tiến bộ, khí chất từ thư sinh chuyển sang hào hiệp. Tới Tô thành, đứng trên đầu cầu nghe tiếng đàn, nói đang chờ một người trong mộng sẽ đến tặng bầu rượu, nếu xuất hiện sẽ ấn chứng suy đoán về nhân quả. Thì thào chờ đợi.","anchor":"Nhân sinh như mộng. Giấc mộng này ta không muốn tỉnh lại.","bridge":true,"khoang":"@c1503"},{"mucCt":"ky","text":"Vương Lâm giả dạng công tử bạch y thuê họa thuyền trôi trên sông Tô thành hơn một tháng, cùng thư đồng Đại Phúc và ba nữ tử, uống rượu ngâm thơ chờ cảnh tượng trong mộng. Hắn tự tay gảy khúc đàn bi ai mà năm xưa Lý Mộ Uyển đàn, nước mắt chảy ra rơi lên dây đàn, hé lộ nỗi bi ai sâu kín từ giấc mộng ban đêm luôn tìm tới. Trên cầu đá, thay vì gặp “một con người khác của mình” trong mộng, hắn lại gặp đại văn hào Tô Đạo. Hắn mê mang không giải thích được sự khác biệt, tự nhủ biết chuyện Luyện Hồn tông và mơ hồ đoán được người mấy trăm năm sau xuất hiện ở đó nhưng ở đây lại không đúng. Khi Tô Đạo hỏi nhân quả, Vương Lâm đáp “ta là nhân, ta chính là quả”.","anchor":"Nhân quả.ta là nhân, ta chính là quả.","bridge":true,"khoang":"@c1504"},{"mucCt":"ky","text":"Được đại nho Tô Đạo mời vào phủ, nhận ra lão già từng hỏi mình trên cầu chính là Tô Đạo. Một già một trẻ uống Quế Hoa tửu đàm luận tới trăng sáng, Vương Lâm vái lạy nhận sư khi 19 tuổi. Từ bỏ khoa cử, ở lại phủ Tô Đạo mười năm truy tìm nhân quả, khí tức đại nho ngày càng nồng đậm, danh tiếng vang dội Triệu quốc vượt qua các Tô cử. Thay mặt sư phụ tiếp đủ hạng người từ phàm nhân, hoàng tộc đến tu sĩ. Mười năm sau nghe Tô Đạo luận tơ liễu là nhân sinh nhân quả, được Tô Đạo nói là nhân quả cuối cùng trong đời ông. Ngẩng đầu hình như nhìn thấy hai đám tơ liễu cuốn lấy nhau, bên tai vọng tới tiếng đàn mất mát giống nữ tử cô độc chờ đợi.","anchor":"Ngươi chính là nhân quả cuối cùng trong đời này của ta","bridge":true,"khoang":"@c1505"},{"mucCt":"ky","text":"Mười năm trôi qua, Vương Lâm gần bốn mươi tuổi. Ba năm trước, Tô Đạo hết thọ qua đời vào mùa đông, Vương Lâm đẩy xe đưa ông lên đỉnh Tô sơn, chứng kiến ông áp mặt vào bia mộ vợ mỉm cười nhắm mắt tắt thở, rồi chôn cất ông bên cạnh. Tô Đạo dặn dò cả đời không có con nối dõi, chỉ Vương Lâm mới có tư tưởng tương đương, tặng phủ đệ cho hắn. Ba năm sau khi Tô Đạo mất, tiếng dèm pha VL không xứng đại nho lan khắp Triệu quốc, hai trong ba môn sinh cũ của Tô Đạo cũng lên tiếng nghi ngờ. Hoàng đế Triệu quốc gửi chín đạo thánh chỉ mời VL làm đế sư nhưng hắn đều không đáp ứng. Tiếng đồn lan tới sơn thôn khiến phụ thân VL lâm bệnh, mẹ hắn nhờ người viết thư, tứ thúc phái người mang tới. Đọc thư, VL lần đầu nổi giận vì cha mẹ là điểm dừng mấu chốt của hắn. Hắn tuyên bố giảng học mười năm, đón người khắp thiên hạ tới Tô thành luận học, ai thắng được thì lấy phủ đệ.","anchor":"Đại Phúc, sắp xếp truyền tin nói ta muốn giảng học mười năm","bridge":true,"khoang":"@c1506"},{"mucCt":"ky","text":"Bốn tháng sau tuyên bố giảng học mười năm tại Tô phủ, hơn ngàn văn sinh đổ về, hoàng đế Triệu quốc âm thầm thôi động người tới chất vấn. Vương Lâm bình thản ngồi uống Quế Hoa tửu, lần lượt đối đáp sắc bén về sinh lão bệnh tử, ý nghĩa mưa, tiên nhân đối phàm nhân, nhân quả. Câu đáp về mưa khiến nhiều danh sĩ cảm phục vái lạy rồi rời đi. Tô Nhất (đệ nhất môn sinh Tô Đạo, nay là văn thần đương triều) chất vấn Vương Lâm có thực sự coi tiên nhân như kiến hôi được không. Vương Lâm cười đáp có gì không thể, lập tức thanh niên đạo bào (tu sĩ hầu cận nam tử hoa phục) hóa cầu vồng cầm kiếm lao tới phán tội chết. Vương Lâm không chút sợ hãi, ngửa mặt gầm một tiếng, bộc phát luồng khí mênh mông kèm vô số lôi đình gào thét, phong vân biến sắc, uy áp bao phủ thiên địa, khiến nam tử hoa phục tái nhợt kinh hãi và tu sĩ còn lại sợ hãi khôn cùng.","anchor":"một luồng khí mênh mông ầm ầm tràn ra từ cơ thể hắn, hình thành một luồng uy áp vô hình, trực tiếp bao phủ thiên địa","bridge":true,"khoang":"@c1507"},{"mucCt":"ky","text":"Một tiếng quát phát ra uy áp chính khí mênh mông khiến hai tu sĩ Trúc Cơ phun máu kinh hồn, phi kiếm rơi xuống đất, cả hai cung kính xin rời đi thề không vào Tô thành. Được toàn bộ văn sinh và lão giả tôn làm đại nho Triệu quốc, hoàn toàn thay thế sư tôn Tô Đạo, trở thành đại nho khiến tiên nhân khiếp sợ chưa từng có trong lịch sử. Tám năm nữa trôi qua, tổng cộng hai mươi tám năm ở Tô thành, từ bốn mươi thành năm mươi tuổi, tóc gần nửa bạc. Mỗi tháng vài ngày ngồi họa thuyền uống Quế Hoa tửu chờ người hẹn ước nhưng không ai tới. Gặp lại Chu Nhị và Từ Phi trên sông, nhận ra nữ tử họ Chu là người duy nhất cả đời khiến mình động tâm, vẫn giữ tấm áo khoác nàng tặng trong hòm trúc chưa hề lấy ra. Hai thuyền lướt qua nhau rồi xa dần, không bắt chuyện. Cuối cùng quyết định không đợi nữa, cùng Đại Phúc lên xe ngựa rời Tô thành về nhà dưới chân Hằng Nhạc Sơn.","anchor":"Ta đang chờ chính ta. Chờ người hẹn ước với ta lần trước.","bridge":true,"khoang":"@c1508"},{"mucCt":"ky","text":"Rời Tô thành cùng Đại Phúc bằng xe ngựa, sau bốn tháng về tới sơn thôn Hằng Nhạc Sơn, đã hai mươi tám năm xa quê. Quỳ trước cha mẹ tự xưng Thiết Trụ, hứa ở lại hầu hạ tới hết đời. Thân thích Vương gia, quan viên, học tử tới bái kiến vị đại nho Triệu quốc. Phụ thân đắc ý tổ chức tiệc rượu lớn, nhắc hắn chưa cưới thê tử. Lờ mờ thấy cảnh tượng bái kiến này trong mộng đã từng gặp nhưng chênh lệch quá lớn. Ở lại năm năm, mái tóc bạc quá nửa. Phụ thân lâm chung, nhắc đã nhờ người chỉnh sửa lời con thành sách, nhớ câu thiên địa luân hồi sinh lão bệnh tử. Vương Lâm ôm cha an ủi đừng sợ, nhắc lại con ngựa gỗ nhỏ cha tặng lúc bé. Phụ thân dần hết sợ hãi, nhắm mắt ra đi trong lòng con trai.","anchor":"Cha, có con đây rồi, đừng sợ, có con ở đây rồi","bridge":true,"khoang":"@c1509"},{"mucCt":"ky","text":"Mẫu thân qua đời trong giấc ngủ với nụ cười hạnh phúc sau khi phụ thân mất, Vương Lâm giữ mộ ba năm, tóc bạc trắng, lưng còng, gần sáu mươi tuổi (năm thứ 38 trong mộng). Hắn nhận ra còn thiếu một tia cảm ngộ đối với thiên địa, từ biệt Đại Phúc, mùa xuân năm thứ 38 một mình rời sơn thôn, uống rượu trên xe ngựa rời xa Hằng Nhạc sơn. Mấy tháng sau tới biên giới Triệu quốc, lần đầu tiên trong kiếp mộng rời khỏi Triệu quốc. Ngay lúc bước qua biên giới, một đạo cầu vồng bay qua, hắn không ngẩng đầu, bình tĩnh bước tiếp. Liễu Mi từ trong cầu vồng bay xuống gặp hắn, nói đã gặp mấy chục năm trước, nay lần thứ hai vẫn cảm thấy quen thuộc đau lòng bí ẩn, không hiểu vì sao. Vương Lâm xưng danh đại nho Triệu quốc. Liễu Mi tặng viên đan dược bảo trì tinh lực rồi cưỡi mây bay đi. Khi nàng đã xa, Vương Lâm dùng hết khí lực hét vọng theo: dù kiếp sau, luân hồi hay mộng, đừng quen biết tu sĩ tên Vương Lâm. Bản ngã tu sĩ xuyên qua lớp mộng phàm nhân, hắn ý thức rõ nỗi đau mình sẽ gây ra cho nàng.","anchor":"Liễu Mi, ngươi nhớ lấy. Cho dù là lúc nào, có lẽ là kiếp tiếp theo, có lẽ là một lần luân hồi nữa, có lẽ là trong một giấc mộng, không nên quen biết một tu sĩ tên là Vương Lâm!","bridge":true,"khoang":"@c1510"},{"mucCt":"ky","text":"Nuốt viên đan dược nhận vô tận tinh lực, một mình chu du Chu Tước Tinh suốt mười lăm năm dưới thân phận phàm nhân. Đi qua vô số quốc gia phàm nhân, gặp hoàng đế các nước, giáo hóa dân chúng, tư tưởng thoát thai hoán cốt. Bước vào các tông phái tu chân, đàm luận với tu sĩ, giúp người có cơ hội Hóa Thần, khiến cả tu sĩ đã Hóa Thần cũng tâm thần chấn động. Danh tiếng đại nho Vương Lâm truyền khắp Chu Tước Tinh cả phàm lẫn tu chân giới, khí chất vượt cả sư phụ Tô Đạo năm xưa. Năm bảy mươi tuổi, đến đô thành từng thấy trong mộng, gặp gia đình thợ rèn, nhìn bé trai giống Đại Ngưu trong mộng nhưng không phải, uống rượu không phân biệt được mộng hay thực. Cuối cùng đứng trong mái đình nhìn mưa, muốn vượt biển sang nơi có nữ tử trong mộng, thì gặp nữ tử Tuyết Vực quốc tìm tới hỏi chuyện.","anchor":"bốn chữ đại nho Vương Lâm ở trên Chu Tước Tinh đã gây nên một hồi sóng gió","bridge":true,"khoang":"@c1511"},{"mucCt":"ky","text":"Tiếp nữ tử Tuyết Vực đem đứa bé gái tới nhờ chỉ điểm hóa giải kiếp nạn. Ôm đứa bé, cảm nhận luồng khí tức quen thuộc, nhìn con bướm trú mưa dưới lá mà minh ngộ, đặt tên nó là Hồng Điệp. Dùng nước mưa vẽ trận pháp thâm áo từ ký ức trong mộng lên bàn đá, dặn nữ tử đặt tóc bé vào trong để hóa giải đại kiếp sinh tử. Suy tư về nhân quả thật giả, kiếp trước kiếp này liệu có phải tự tạo thành viên mãn. Năm thứ mười lăm rời Triệu quốc, lên thương thuyền vượt đại dương năm tháng. Chứng kiến hải thị thận lâu — huyễn cảnh ngọn núi lửa bộc phát trên mặt biển, nhận ra đây là hiện tượng Thận trong sách cổ. Trong huyễn cảnh nhìn thấy nữ tử bạch y — nhận ra là Lý Mộ Uyển, toàn thân ngây dại, bi thương tràn dâng, hai hàng nước mắt trào ra, thốt lên Là nàng.","anchor":"Hai hàng nước mắt trào ra từ khóe mắt hắn","bridge":true,"khoang":"@c1512"},{"mucCt":"ky","text":"Chín tháng sau khi hình ảnh hư ảo biến mất, thương thuyền gặp bão biển nộ hải giữa đêm. Vương Lâm đứng trên thuyền giữa sóng gió, cảm nhận lực lượng thiên địa, ngộ ra vạn tượng vô tình là đạo lý chân chính, trái tim mở rộng vô hạn đủ dung nạp thiên địa. Nghe bài ca nghịch hành bất khuất của thuyền viên, hắn minh ngộ ba cảnh giới sinh tử: thuận sinh thuận tử, nghịch ý khinh miệt sinh tử, và cảnh giới thứ ba — một câu nói đã tràn ngập trong đầu nhưng có tấm màng ngăn khiến chưa nói ra được. Thuyền sống sót, tháng thứ mười một tới đại lục xa lạ. Ba năm chu du đại lục (tổng mười chín năm từ rời Triệu quốc), hắn trở thành đại nho thời nay danh tiếng khắp bốn phương, đôi mắt ẩn chứa thiên địa chỉ nhìn đã khiến người mê mang. Mùa thu năm thứ mười chín, tại vùng núi lửa bộc phát, hắn gặp nữ tử áo trắng tóc dài đang cầm bình ngọc thu thập vật phẩm — chỉ một ánh mắt khiến hắn run lên, như đã đợi mấy ngàn năm.","anchor":"Chỉ nhìn một cái đã khiến Vương Lâm khó quên nổi, khiến thân thể hắn run lên, giống như hắn đã đợi cái nhìn này mấy ngàn năm","bridge":true,"khoang":"@c1513"},{"mucCt":"ky","text":"Vương Lâm trong thân phận đại nho già nua giác ngộ hoàn toàn bản chất thế giới Mộng Đạo: toàn bộ do bản thể tu sĩ dùng ba đạo quả kết hợp Mộng Đạo thuật tạo ra, mọi thứ đều là tưởng tượng. Hắn vạch trần từng nhân quả giả tạo được sắp đặt: Tô Đạo được tạo ra để đại nho ngộ thiên địa, Liễu Mi xuất hiện hai lần và tặng đan dược để cắt nhân quả, chuyện Hồng Điệp được đưa vào mộng luân hồi, chuyện Niệm Thiên Luyện Hồn Tông cũng được sắp đặt. Hắn tiết lộ đã biết sự thật từ hơn 55 năm trước khi nhìn thấy dấu tay trên cánh tay phải người điên lúc đống lửa bị dập tắt, nhưng tự lừa gạt bản thân suốt thời gian đó. Hắn kịch liệt phản đối việc cắt đứt nhân quả với Lý Mộ Uyển, tuyên bố mọi chuyện khác có thể bỏ qua nhưng riêng chuyện này không thể tiếp nhận. Hắn ngửa mặt gầm thét khiến thiên địa chấn động, sấm sét tràn bầu trời, dòng xoáy khổng lồ xuất hiện trên trời lộ ra thế giới đen tối chứa luồng sáng đỏ với hai thi thể nhắm mắt — một thi thể tóc bạc trắng có dấu hiệu dãy dụa muốn thức tỉnh. Hắn dùng tay phải điểm chỉ lên dòng xoáy, phát luồng khí mênh mông, vung tay áo khiến sấm sét ầm vang, dòng xoáy nhỏ dần rồi biến mất hóa thành con chim trắng bay đi. Hắn khẳng định không ai trong thiên địa hiểu rõ hơn hắn về nhân quả, sinh tử, thật giả, tuyên bố đạo quả, ký ức, thế giới giả dối đừng động tới hắn.","anchor":"Ngươi nuốt ba đạo quả vào, ngươi dùng Mộng Đạo thuật để trở lại hai ngàn năm trước","bridge":true,"khoang":"@c1514"},{"mucCt":"ky","text":"Vương Lâm hồi tưởng cảnh chứng kiến Lý Mộ Uyển từ hồng nhan tới khô cốt, tự nhận trái tim đã chết từ ngày đó, không hồng nhan nào thay thế được nàng. Năm thứ 31 sau rời Triệu quốc, hắn cùng Lý Mộ Uyển ngồi trên tảng đá giữa vô số tu sĩ, cảm ngộ thiên địa. Năm thứ 32, cảm nhận phàm thân sắp chết, được Lý Mộ Uyển dìu bay đi. Hai người về sơn cốc sống bình dị, hắn chấp nhận nàng dùng thần thông biến thành bà lão để cùng già đi. Năm thứ 35, cảm nhận tử vong sắp tới, hắn cầm lá vàng nói lá rụng về cội, yêu cầu nàng đưa về Triệu quốc mang theo Đại Phúc tới Tô thành hoàn thành ước hẹn cuối cùng. Bên ngoài mộng, tin Phong Tôn tử vong lan rộng, phòng tuyến ánh sáng viễn cổ Thanh Lâm sụp đổ, giới nội bỏ ba tinh vực tử thủ La Thiên trước Chu Tước Tinh.","anchor":"Trái tim hắn trong ngày đó, vào lúc ôm Lý Mộ Uyển bi thống ngửa mặt lên trời gầm thét đã chết rồi","bridge":true,"khoang":"@c1516"},{"mucCt":"ky","text":"Sau 35 năm rời Triệu quốc, Vương Lâm đi xe ngựa cùng Lý Mộ Uyển trở về quê, ngang qua nhà trọ đổ nát nơi hắn từng tỉnh lại năm xưa. Về sơn thôn dưới Hằng Nhạc Sơn gặp lại Đại Phúc đã già nua chờ đợi suốt 35 năm theo lời hẹn. Viếng mộ cha mẹ phía sau thôn, giới thiệu Lý Mộ Uyển là con dâu, hai người quỳ trước mộ trầm mặc rồi cùng vái. Rời quê về Tô thành, nhấc rèm nhìn lại quê hương chìm trong tuyết, nhớ lại 73 năm trước lần đầu rời nhà với hòm trúc sách vở. Tại Tô thành thuê họa thuyền uống Quế Hoa tửu chờ đợi cuộc hẹn. Tháng sáu năm thứ 75, cười vang ngâm bài thơ về tâm nghịch hành, đời người như giấc mộng. Cánh chim trắng đã rất lâu không xuất hiện bay tới, lao xuống cầu đá hóa dòng xoáy trắng, thanh niên tóc bạc thần sắc lạnh lùng mê man bước ra — chính là bản thể tu sĩ của Vương Lâm xâm nhập mộng cảnh. Ánh mắt hai bản thân giao nhau, thời gian mộng cảnh hoàn toàn dừng lại, vạn vật bất động. Vương Lâm lão niên mỉm cười mời uống rượu. Thanh niên tóc bạc bước lên mũi thuyền ngồi xuống cầm bầu rượu, không nhìn bản thân lão niên mà nhìn Lý Mộ Uyển đã thành bà lão rất lâu.","anchor":"Chỉ có người thanh niên trên cây cầu đá, chỉ có Vương Lâm ở trên họa thuyền là vẫn như cũ.","bridge":true,"khoang":"@c1517"},{"mucCt":"ky","text":"Đối ẩm cùng thanh niên tóc bạc (phân thân tạp niệm của chính mình) trên họa thuyền, xác nhận giấc mộng do tạp niệm trong ba đạo quả tự thôi diễn. Gảy khúc mộng cầm cuối cùng bên Lý Mộ Uyển, hồi tưởng toàn bộ cuộc tình từ Hỏa Phần quốc qua nhiều lần luân hồi. Uống cạn bầu rượu rồi thốt lời phá hủy đại địa mộng cảnh, mọi quốc gia và địa danh trên Chu Tước Tinh tiêu tan. Thốt lời sinh tử khiến mọi sinh linh trong mộng — Lý Mộ Uyển, Liễu Mi, Từ Phi, Vương Trác, Hoàng Long chân nhân, Chu Vũ Thái, Vân Tước Tử, Độn Thiên, Chu Tước Tử — đều hóa tro bụi. Rơi nước mắt khi Lý Mộ Uyển tiêu tan, hứa sẽ đánh thức nàng. Cầm tay Đại Phúc, nắm dấu ấn trên cánh tay hắn, nhắm mắt tỉnh mộng — giấc mộng phàm trần Hóa Phàm chính thức kết thúc.","anchor":"Thứ gì là nhân quả.ta nắm nhân, cũng nắm giữ quả.","bridge":true,"khoang":"@c1518"},{"chuong":"@c1519","importance":"major","mucCt":"ky","tieuDe":"Thức tỉnh mộng đạo, ngưng tụ ba bổn nguyên","text":"Thức tỉnh sau hơn bảy mươi năm mộng đạo trong hư vô đen tối, bên cạnh thi thể người điên có dấu tay màu vàng trên cổ tay. Giấc mộng là hắn bắt chước thuật lừa đảo của Lưu Kim Bưu để lừa gạt chính bản thân, sống trọn một cuộc đời khác. Ngưng tụ Lôi bổn nguyên đại thành — chín tia sét dung hợp thành lôi ấn ký bất diệt hình thái hỗn độn. Ngưng tụ Hỏa bổn nguyên đại thành — chín màu hợp nhất vượt hư hỏa thành đạo hóa, ký hiệu hình ngọn lửa hư ảo bất định. Hai đạo bổn nguyên đủ giết tu sĩ Không Niết hậu kỳ đại viên mãn trở xuống. Dùng khí tức đại nho từ cảm ngộ thiên địa trong mộng ngưng tụ Nhân Quả bổn nguyên vô hình vô ảnh trên tay phải — mở tay là nhân, nắm tay là quả — sáng tạo thần thông thứ tư: Nhân Quả ấn. Tuyên bố tu đạo hơn hai ngàn năm, muốn phá tan không môn trở thành tu sĩ bước thứ ba, nhắc kẻ thù: Chưởng Tôn, Hư Thần Thiên Tôn, mấy tiên phi.","anchor":"mở tay là nhân, nắm tay là quả"},{"mucCt":"ky","text":"Vương Lâm ngộ ra Nhân Quả ấn — mở bàn tay là nhân, nắm bàn tay là quả diệt thế, quá trình nắm tay là duyên — thức thần thông thứ tư do hắn tự sáng tạo, đánh dấu nhân quả bổn nguyên đại thành. Ba đạo bổn nguyên (lôi đình, hỏa, nhân quả) đều đại thành, khí tức bước thứ ba tăng mạnh gấp bội, uy lực toàn kích vượt Không Niết đại viên mãn. Khi ba bổn nguyên biến ảo vang vọng tinh không, Không Đại Môn khổng lồ xuất hiện giữa chiến trường Chu Tước Tinh, khiến toàn bộ hai phe kinh hoàng.","anchor":"Ba đạo bổn nguyên đại thành, giờ phút này dù là tu sĩ Không Niết đại viên mãn có ở đây cũng không thể chống nổi một kích toàn lực của Vương Lâm","bridge":true,"khoang":"@c1520"},{"mucCt":"ky","text":"Trong hư vô mênh mông, Vương Lâm triệu xuất đạo bổn nguyên thứ tư — Sinh Tử: tay trái Sinh (bạch khí, sinh cơ vô tận, ý chí thiên không), tay phải Tử (hắc khí, tử khí, lực lượng đại địa). Hai tay hợp nhất hóa thành Sinh Tử Ấn — thức thần thông thứ năm do hắn tự sáng tạo, dung hợp cùng ba đạo bổn nguyên Lôi, Hỏa, Nhân Quả. Bên ngoài không môn còn hiện ra đạo bổn nguyên thứ năm — Thật Giả, khiến không môn mơ hồ, phía sau xuất hiện thêm một không môn hư ảo khó phân biệt thật giả. Tổng cộng năm đạo bổn nguyên dẫn động không môn, chấn kinh toàn bộ tu sĩ giới nội lẫn giới ngoại, sự kiện chưa từng có từ cổ chí kim.","anchor":"Đây chính là thức thần thông thứ năm Vương Lâm tự sáng tạo ra, Sinh Tử Ấn!","bridge":true,"khoang":"@c1521"},{"mucCt":"ky","text":"Bổn nguyên thứ năm Thật Giả đại thành, ngưng tụ thần thông thứ sáu Chân Giả Ấn. Nắn vỡ Sát Lục Kiếm, hấp thu toàn bộ sát lục bổn nguyên thành đạo bổn nguyên thứ sáu. Tuyên bố dùng sáu đạo bổn nguyên đánh tan không môn, thành tựu bước thứ ba toàn năng. Thu hồi giọt máu bất diệt thể tiên nhân bị Chưởng Tôn tách năm xưa, đặt lên mi tâm làm pháp bảo tương lai. Thu người điên đang hôn mê mang theo. Phá vỡ hư vô tạo dòng xoáy phân hai: một về Chu Tước Tinh, một tới Tiên Cương đại lục. Dùng thần thức thăm dò Tiên Cương, thấy đại lục chín mặt trời tiên khí cực đậm, gặp nữ đồng Oa Oa truyền âm. Liên hệ hàng loạt bí mật kinh thiên xuyên suốt giới nội giới ngoại: Tiên Cương, đạo nhân bảy màu, Thanh Thủy, người điên, Chưởng Tôn, Chiến lão quỷ, hạt châu Thiên Nghịch, viễn cổ tiên vực. Chọn đường về Chu Tước Tinh, phá không môn xuất hiện đúng lúc Hư Thần Thiên Tôn vừa phá nát trận pháp.","anchor":"Vương Lâm ta hôm nay lợi dụng sáu đạo bổn nguyên đánh tan không môn, thành tựu bước thứ ba toàn năng!","bridge":true,"khoang":"@c1522"},{"mucCt":"ky","text":"Vương Lâm áo trắng tóc bạc bước ra từ vòng xoáy cạnh Không Môn bên ngoài Chu Tước Tinh, tuyên bố trở về. Khí tức khiến mấy vạn tu sĩ giới ngoại run rẩy lùi lại, Chu Cẩn đổ mồ hôi tuyệt vọng, nam tử áo xanh đạo tâm bất ổn. Hư Thần Thiên Tôn phân thân lao tới định đoạt xá, Vương Lâm nhắm rồi mở mắt phóng chính khí đại nho, chỉ một câu quát khiến phân thân Thái cổ ngũ tôn khựng lại lùi mấy trượng hoảng sợ. Sau đó xướng chú triệu sáu đạo bổn nguyên ngưng tụ Không Môn mạnh nhất lịch sử, bóp nát quang cầu dung nhập thân thể, lao thẳng tới cửa để hướng bậc toàn năng bước thứ ba.","anchor":"một nam tử mặc áo trắng, tóc bạc, thần sắc mang theo vẻ lạnh lùng, thân ảnh hắn từng bước một, từ trong vòng xoáy đi ra","bridge":true,"khoang":"@c1523"},{"mucCt":"ky","text":"Vương Lâm hô hiệu lệnh lôi đình, một quyền đánh lên Không Môn sáu đạo bổn nguyên, chấn động khiến mấy vạn tu sĩ phun máu, Không Môn chậm rãi hé ra một chút. Sau đó kêu một tiếng dài, dẫn động toàn bộ lôi đình tứ đại tinh vực Côn Hư, Vân Hải, Triệu Hà, La Thiên hướng về Chu Tước Tinh. Lôi đình bất diệt tồn tại vạn năm ở cửa Lôi Tiên Giới cũng bị phá nát thoát ra, lần đầu bay ra sau vô số vạn năm. Vương Lâm như vua của lôi đình triệu tập, toàn thân áo trắng ngửa mặt lên trời kêu gọi, thanh thế chưa từng có. Sáu đạo bổn nguyên đã đại thành nhưng vẫn chưa dung hợp lại với nhau.","anchor":"Nhân danh Vương Lâm ta, hiệu lệnh lôi đình trong thiên địa!","bridge":true,"khoang":"@c1524"},{"mucCt":"ky","text":"Dùng tiếng kêu dài dẫn động lôi đình từ cả giới nội lẫn giới ngoại qua lỗ hổng Phong Giới Đại Trận tại Vân Hải, hội tụ về Chu Tước Tinh. Lấy lôi đình bổn nguyên phá vỡ hoàn toàn Không Môn thứ nhất, khí thế đạt Không Niết sơ kỳ. Từ chối hấp thu sức mạnh Không Môn vì chỉ đạt sơ kỳ nhờ một đạo bổn nguyên là chưa đủ, mục tiêu là sáu đạo bổn nguyên dung hợp để một bước thành danh. Ép sức mạnh Không Môn quay lại, triệu Không Môn thứ hai. Gọi hỏa bổn nguyên nhân danh mình, dẫn lửa từ Côn Hư, Vân Hải, La Thiên, Triệu Hà và Thái cổ Tinh Thần hội tụ thành biển lửa thiêu hủy Không Môn thứ hai. Khí thế sau hai lần phá cửa bạo tăng từ Không Niết sơ kỳ lên Không Niết trung kỳ, nhưng vẫn chưa phải tu vi thực chất. Một cái liếc khiến Chu Cẩn tâm thần chấn động phun máu.","anchor":"Thứ hắn muốn, chính là một bước thành danh","bridge":true,"khoang":"@c1525"},{"mucCt":"ky","text":"Không hấp thụ mà ép Không Môn tiếp tục sụp đổ, Lô Vân Tử chỉ tay khiến vòng xoáy tinh không dẫn ra đồng thời Không Môn thứ ba đến thứ năm. Dùng Nhân Quả Ấn phá Không Môn thứ ba, tu vi vọt lên Không Niết Hậu Kỳ. Dùng Sinh Tử Ấn xé toạc Không Môn thứ tư, đạt Không Niết Đại Viên Mãn, mi tâm hiện khe tối đen chứa thiên địa của bản thân (không phải hương hỏa giới, chưa mở hoàn toàn). Dùng Chân Giả Đạo quét vỡ Không Môn thứ năm, khe mi tâm hiện hoàn toàn, khí thế Không Linh Sơ Kỳ khuếch tán. Hấp thụ sát lục bổn nguyên (Thanh Thủy tặng) đại thành tức thì, dẫn ra Không Môn thứ sáu — Vạn Không Cốt Môn bằng bạch cốt hình đầu lâu khổng lồ. Gợn sóng từ cửa lan ra làm gần một vạn tu sĩ già đi mà chết thành tro bụi. Hư Thần Thiên Tôn và Nam Vân Tử nhận ra Vạn Không Cốt Môn, dẫn lời rằng người dẫn động được cửa này nếu không gặp tai họa ắt thành Đại Tôn.","anchor":"là thức thần thông thứ năm của hắn","bridge":true,"khoang":"@c1526"},{"mucCt":"ky","text":"Vương Lâm dùng sát lục bổn nguyên hóa huyết chưởng đánh Vạn Không Cốt Môn, chưởng ấn chứa giết chóc cả đời hắn và sát lục của Thanh Thủy, khiến cánh cửa nứt nhưng chưa sụp. Hắn lần lượt vận lôi, hỏa, Nhân Quả Ấn, Sinh Tử Ấn, Chân Giả Đạo, dung hợp khí thế đại nho và Không Linh sơ kỳ, dồn sáu đạo bổn nguyên vào một quyền đánh sập Vạn Không Cốt Môn. Sức mạnh Không Môn từ vòng xoáy tinh không nhập thể, sáu bổn nguyên dung hợp, tu vi vượt cực hạn bước thứ hai, chính thức trở thành bước thứ ba toàn năng. Quá trình dung hợp đẩy tu vi qua Không Niết trung kỳ, hậu kỳ, đại viên mãn rồi đạt Không Linh sơ kỳ trong Không Tứ Cảnh. Trong lúc vẫn hấp thụ sức mạnh Không Môn, hắn điểm một chỉ chứa đạo niệm bỏ đi từ ba đạo quả, kiềm chế Chu Cẩn và nam tử áo xanh không thể tiến, làm Hư Thần Thiên Tôn chậm lại. Hắn áp sát nam tử áo xanh, dùng Định Thân Thuật khiến y mê man rồi thi triển Nhân Quả Ấn rút ra bổn nguyên của y dưới dạng sương mù hư ảo.","anchor":"Một quyền này là một đòn tấn công toàn lực kết hợp sáu đạo bổn nguyên đại thành của hắn","bridge":true,"khoang":"@c1527"},{"mucCt":"ky","text":"Thi triển Nhân Quả Ấn rút hơn phân nửa bổn nguyên nam tử áo xanh (tu vi Không Huyền), tuyên bố chỉ lấy bổn nguyên, phong ấn ngàn năm chứ không giết, bức lui hắn mấy ngàn trượng. Quay sang Hư Thần Thiên Tôn, nói chuyện năm đó hôm nay kết thúc. Thân hóa hư ảo cho hàng vạn pho tượng của Vạn Hà Hư Thần Đạo xuyên qua mà không cản được. Tung liên hoàn Sinh Tử Ấn, Định, Lôi, Hỏa, Nhân Quả, Sinh Tử, Chân Giả Đạo rồi Sát lục chém đôi Thiên Tôn hóa hai đám sương tím. Nhờ Chân Giả Đạo cảm nhận được lớp sương chỉ là áo, phát hiện bản thể phân thân là đám khí vô hình hư ảo.","anchor":"Dựa vào Định Thân Thuật, Vương Lâm lúc này giống như là thiên đạo!","bridge":true,"khoang":"@c1528"},{"mucCt":"ky","text":"Điểm mi tâm lấy giọt máu vàng, dựa cảm ứng triệu Cung Lý Quảng cùng mũi tên đã dung hợp bên trong. Kéo cung nhắm Hư Thần Thiên Tôn đang bỏ chạy, tuyên bố giành lại Côn Hư. Mũi tên thực chất hóa, phá sụp tinh không, xuyên diệt nam tử áo xanh — tu sĩ Không Huyền đầu tiên tử vong trong cuộc chiến. Gợn sóng từ mũi tên lan khắp đông nam tây bắc Côn Hư, bỏ qua tu sĩ giới nội nhưng quét sạch lượng lớn tu sĩ giới ngoại. Mũi tên truy tới biên giới Côn Hư – Vân Hải, xuyên diệt phân thân Hư Thần Thiên Tôn, khiến bản thể ở Thái cổ Tinh Thần phun máu trọng thương. Thu cung tên về giọt máu vàng, đặt lại mi tâm, nhìn Không Môn chưa tan và tự biết quá trình ngưng tụ bước thứ ba còn thiếu một phần, Thiên Kiếp bước thứ ba sắp tới.","anchor":"Một tiễn này, ta muốn giành lại Côn Hư","bridge":true,"khoang":"@c1529"},{"mucCt":"ky","text":"Trong vòng xoáy Không Môn, Vương Lâm hoàn tất dung hợp đạo sát lục bổn nguyên thứ sáu, tu vi tăng từ Không Linh sơ kỳ lên Không Linh trung kỳ. Hắn dùng sức mạnh Không Môn ngưng tụ sáu thanh bổn nguyên kiếm: lôi đình, hỏa diễm, nhân quả, sinh tử, chân giả và sát lục. Khí tức Thiên Kiếp mạnh nhất đời hắn từ tận cùng tinh không truyền tới. Hắn thi triển Định Thân Thuật cưỡng ép giữ vòng xoáy Không Môn đang tiêu tán, dùng bản tính thôn hồn hút thêm lượng lớn sức mạnh Không Môn không thuộc về mình. Hắn lấy Xạ Thần Xa đã hủy ra cho hấp thụ Không Môn lực, Thanh Quang Thuẫn và giáp cổ tay Cổ Thần đều được khôi phục hoàn chỉnh. Khi vòng xoáy sụp đổ, một ý chí cực mạnh khuếch tán ra, Vương Lâm không khuất phục, nói sẽ báo đáp việc mượn sức mạnh Không Môn. Thiên Nghịch Châu trong tâm thần hắn đột nhiên chuyển động.","anchor":"Ngay khi hoàn thành quá trình dung hợp này, tu vi của Vương Lâm từ Không Linh Sơ Kỳ đã tăng lên tới Không Linh Trung Kỳ","bridge":true,"khoang":"@c1530"},{"mucCt":"ky","text":"Ý chí từ vòng xoáy Không Môn sụp đổ lao tới mang sức trấn áp, Vương Lâm dùng khí thế đại nho chống lại, Thiên Nghịch Châu trong tâm thần xoay tròn như thức tỉnh và tham lam hấp thụ ý chí ấy. Sức mạnh Không Môn trào ra chữa lành mảnh giáp bảo vệ cánh tay Cổ Thần và khôi phục Thập Ức Tôn Hồn Phiên tàn phá, khiến cây phiên bộc phát khí tức cực mạnh. Vòng xoáy Không Môn tiêu tan, sát lục bổn nguyên dung nhập vào hồn, Vương Lâm chính thức tiến vào bước thứ ba Không Linh trung kỳ. Đồ hình Vạn Không Cốt Môn — cánh cửa thứ sáu hắn đã phá — hiện trên lòng bàn tay phải rồi ngưng tụ khắc sâu trong tim. Sương mù thiên kiếp cuồn cuộn tới đẩy lui mấy ngàn tu sĩ giới nội và cả Chu Tước Tinh khỏi quỹ đạo, chỉ còn một mình hắn trong phạm vi trăm vạn trượng. Vương Lâm ngẩng đầu nhìn vòng xoáy lôi đình, tuyên bố trời không có tư cách giáng kiếp xuống mình và chủ động gọi lôi kiếp nhân danh Vương Lâm nổi lên.","anchor":"Bước thứ ba! Lúc này hắn đã chính thức tiến vào bước thứ ba Không Linh trung kỳ","bridge":true,"khoang":"@c1531"},{"mucCt":"ky","text":"Vương Lâm chủ động nghênh đón thiên kiếp bước thứ ba, hóa ra lôi kiếp màu đỏ như máu từ ấn ký mắt phải để đối kháng lôi kiếp xanh giáng từ vòng xoáy thiên kiếp. Thiên lôi xanh tăng lên chín đạo hợp nhất áp chế lôi kiếp đỏ khiến nó tiêu tan. Vương Lâm trực tiếp bước tới chạm vào thiên lôi xanh hợp nhất, dùng thân phận chủ lôi bổn nguyên ép thiên lôi xanh tan rã thành tinh quang. Tiếp đó triệu hàng vạn đạo xích lôi từ quanh thân lao vào vòng xoáy thiên kiếp đánh tan nó hoàn toàn. Vòng xoáy tan rã lộ ra khe nứt vạn trượng, bên trong có tế đàn bốn góc với thân ảnh mơ hồ ngồi giữa và bốn thanh kiếm cắm xung quanh. Vương Lâm chuyển sang dùng đồ hình ngọn lửa ở mắt trái phát động hỏa kiếp, biển lửa lan rộng mấy vạn dặm nuốt lấy khe nứt và tế đàn. Cuối cùng áp sát thân ảnh mơ hồ trên tế đàn, cách không nhấn xuống rồi nắm quyền thi triển Nhân Quả Ấn.","anchor":"Hôm nay Vương mỗ muốn lấy thiên kiếp để chống lại thiên kiếp, kiếp thứ nhất gọi là lôi kiếp của riêng ta.","bridge":true,"khoang":"@c1532"},{"mucCt":"ky","text":"Vương Lâm dùng Nhân Quả Ấn rút khí tức bốn kiếm và tế đàn thiên kiếp, phá nát tế đàn trong biển lửa. Sứ giả thiên kiếp lao ra tấn công nhưng bị hắn dùng Sinh Tử đại ấn đánh tan chỉ bằng một đòn. Hắn chính diện chất vấn thiên kiếp và trời, hỏi vì sao có tư cách cướp đi Lý Mộ Uyển và giáng nạn xuống mình, lời truyền ra tới Tư Đồ Nam cùng mấy ngàn tu sĩ giới nội. Trời giáng Huyễn Chân Kiếp, sương mù hóa thành cha mẹ, tứ thúc, Vương Trác, Trương Hổ, Liễu Mi ôm đứa trẻ bị hắc khí bao quanh, Lý Mộ Uyển lệ đẫm mỉm cười bước tới — dùng thật giả khó phân để công phá tâm thần. Nhờ đã minh ngộ chân giả bổn nguyên, hắn nhắm mắt vung tay đưa mọi thân ảnh trở về hư vô. Sau đó dùng Chân Giả Đạo biến ra Chu Như, Bạch Phàm, Thanh Thủy, Thác Sâm, dân chúng Thiểm Lôi Tộc, Tán Linh thượng nhân cùng vô số người oán trời, tạo thành thiên kiếp đáp trả thiên kiếp. Cuối cùng khuếch tán thần thức phủ khắp Côn Hư tinh vực, dung nhập linh hồn và ký ức của người chết, lấy Chân Giả Đạo chuyển thành sức mạnh đánh vào cái khe thiên kiếp, khiến cái khe lần đầu run lên và tiếng rít gào ngừng lại.","anchor":"Thiên kiếp, ngươi có tư cách gì mà giáng kiếp nạn xuống ta","bridge":true,"khoang":"@c1533"},{"mucCt":"ky","text":"Vương Lâm không sợ thiên kiếp, chủ động tiến về khe vạn trượng để truy xét nguồn gốc kiếp nạn. Tam Thiên phất trần bay ra từ khe, ba nghìn sợi tơ bạc diễn hóa thành ba nghìn thần thông mà hắn từng biết hoặc chứng kiến, mang tiên lực tinh thuần công kích hắn. Nhờ từng gặp người điên và có giọt máu vàng tiên nhân bất diệt thể trên mi tâm, hắn nhận ra tiên khí này không phải tiên ngọc Tứ Đại Tiên Giới mà là khí của tiên nhân đích thực, từ đó củng cố suy đoán Viễn cổ Tiên Vực sau khe có liên hệ lớn với Tiên Cương đại lục. Trấn Tiên bảo tháp chín tầng màu vàng từ khe bay ra trấn áp hắn, bên trong tháp ba nghìn sợi tơ quấn chặt như phong ấn, hào quang vàng định luyện hóa hắn bằng tiên lực. Vương Lâm hiện tinh điểm Cổ Thần, thân thể bành trướng thành Cổ Thần, kéo đứt gần hết sợi tơ rồi tung quyền đánh lên đỉnh tháp.","anchor":"Không chịu nổi một đòn Vương Lâm lại lắc đầu, thân thể hướng lên phía trên bước tới","bridge":true,"khoang":"@c1534"},{"mucCt":"ky","text":"Vương Lâm hiển hóa đầu lâu Đạo Cổ sau lưng, dung hợp uy thế vào quyền kình, đánh ba quyền phá sập bảo tháp thiên kiếp. Phong Mệnh Hoàn xuất hiện là pháp bảo thứ ba, uy áp vượt xa hai pháp bảo trước, Vương Lâm cố ý không né để nó phong ấn thân thể, Nguyên Thần và hồn phách, nhằm tự thân cảm thụ kết cấu bảo vật. Hắn phát hiện Phong Mệnh Hoàn do hơn mười triệu ký hiệu cấu thành, là bán thành phẩm bị kẻ nào đó dung nhập vào thiên kiếp để hoàn thiện. Trong thời gian cực ngắn hắn đã điều khiển được ba phần ký hiệu khiến kim quang ảm đạm. Mười hai Cổ Tộc bát tinh gồm bốn Cổ Thần, bốn Cổ Ma, bốn Cổ Yêu từ cái khe hiện ra vây sát bốn phía khi hắn vẫn nhắm mắt tính toán.","anchor":"Hắn đã động tâm với bảo vật này","bridge":true,"khoang":"@c1535"},{"mucCt":"ky","text":"Trong thiên kiếp, Vương Lâm đối đầu bốn bát tinh Cổ Thần, hiện thất tinh vương tộc áp chế và đánh lui cả bốn mà nương tay. Sau đó hắn ra tay tàn nhẫn diệt bốn Cổ Ma, phá chiến phủ và hấp thu ma khí vào mắt trái. Quầng sáng màu vàng trên trán bị giọt máu tiên nhân bất diệt thể bao phủ, kim quang chuyển thành thuộc về hắn, hoàn tất thu phục bảo vật. Mộng Đạo thức tỉnh, hắn thi triển Dịch Linh Ấn uy lực vượt xa trước kia, một chưởng ấn vàng diệt bốn Cổ Yêu rồi đổi hướng diệt bốn Cổ Thần bị xóa trí nhớ để giải thoát đồng tộc. Hắn tuyên bố thiên kiếp nên kết thúc, bước vào khe vạn trượng và phát hiện thế giới vô tận đầy tượng đá Cổ Thần, Cổ Ma, Cổ Yêu cùng tiên khí chân chính của Tiên Cương đại lục. Trên một pho tượng Cổ Yêu, hắn thấy một thanh niên tóc bạc áo trắng giống hệt mình về hình dáng, thần sắc và khí tức.","anchor":"Thiên kiếp, đáng phải kết thúc rồi!","bridge":true,"khoang":"@c1536"},{"mucCt":"ky","text":"Bị thanh niên tóc bạc giống hệt mình chặn trước đại lục, tự xưng là chính hắn và gọi đây là Bổn Ngã kiếp. Thử lao về phía đại lục nhưng bị màn ngăn chứa tiên khí phản chấn. Giao thủ bằng bổn nguyên, cả hai cùng rút bổn nguyên đối phương rồi dùng Nhân Quả ấn bù hao tổn. Đối kháng Sinh Tử Ấn, Chân Giả Đạo và Định thần thuật nhưng đối phương đều thi triển y hệt, kết quả ngang bằng. Trong lúc bất động rơi xuống, hắn xác nhận mọi hành động trước đó đều có dụng tâm kín đáo nhằm thăm dò đối thủ, vì phân tích rằng đối phương có thể cảm ứng suy nghĩ của mình.","anchor":"Vương Lâm làm tất cả những chuyện trước đó trên thực tế là đã dụng tâm kín đáo với thanh niên tóc bạc kia","bridge":true,"khoang":"@c1537"},{"mucCt":"ky","text":"Dùng Định Thần thuật khóa thần thức và suy nghĩ của cả hai bên để giấu tính toán trước bản ngã kiếp. Trong khoảnh khắc Định Thần thuật, âm thầm thi triển Mộng Đạo hóa thành Đạo lừa gạt, tự lừa bản thân rơi vào trạng thái điên cuồng chiến đấu nhưng vẫn giữ một phần tỉnh táo chờ thời cơ. Giao chiến với thanh niên tóc bạc bằng hơn mười loại thần thông giống nhau, bao gồm tiên thuật của Bạch Phàm, tiên thuật của Thanh Thủy, hỏa bổn nguyên và lôi đình bổn nguyên, kết quả lưỡng bại câu thương. Khi thanh niên tóc bạc nhắm mắt theo Chân Giả Đạo, bất ngờ mở mắt khiến đối phương lần đầu có động tác khác mình, dùng Nhân Quả Ấn rút bổn nguyên rồi Sinh Tử Ấn đánh vào mi tâm khiến đối phương trọng thương. Tự đánh nát đùi phải lợi dụng liên hệ song trùng khiến thanh niên tóc bạc chịu thương thế giống hệt và chậm lại. Lao tới va chạm trực tiếp khiến thân thể thanh niên tóc bạc tứ phân ngũ liệt, tấm màn ngăn cản tan rã. Sau trận vận chuyển tu vi và Cổ Thần lực chữa chân phải, bước vào sau tấm màn vừa tan rã thì sững lại vì nhìn thấy điều gì đó.","anchor":"Vương Lâm không dám xác định là nếu thời gian suy nghĩ quá dài, đối phương có thể thấy được hay không","bridge":true,"khoang":"@c1538"},{"mucCt":"ky","text":"Đặt chân vào Viễn cổ tiên vực, phát hiện chín mặt trời giống Tiên Cương đại lục, phán đoán nơi đây là một bộ phận của Tiên Cương. Bay tới mặt trời thứ nhất, phất tay cuốn sương mù rồi vung tay nhiều lần khiến mặt trời sụp đổ hoàn toàn. Phát hiện bên trong phong ấn tia lôi đình chín màu — căn nguyên dẫn dắt thiên kiếp thứ nhất. Nắm tia sét, đưa thần thức vào bên trong nghịch chuyển thời gian, chứng kiến nam tử trung niên đạo bào bảy màu tự xưng bổn tôn tuyên bố động phủ bốn tôn tự thành một giới, vạn vật do hắn tạo ra, sẽ cướp thiên đạo và chế tạo sấm sét thiên kiếp trừng phạt nghịch tu. Nhận ra nam tử bảy màu giống hệt pho tượng trong khe trữ vật, có chút tương tự người hóa thân bảy màu ở Thất Thải giới nhưng mạnh hơn gấp bội. Ấn chứng bí mật chấn động: giới nội giới ngoại chỉ là một động phủ của đại tôn trên Tiên Cương đại lục biến thành, nhớ lại lời Chiến lão quỷ từng nói giới nội là nội phủ. Cười điên cuồng chỉ vào bầu trời.","anchor":"Hóa ra giới nội giới ngoại chẳng qua chỉ là do một động phủ của đại tôn trên Tiên Cương đại lục biến thành!","bridge":true,"khoang":"@c1539"},{"mucCt":"ky","text":"Minh ngộ hoàn toàn chân tướng thiên đạo: thiên địa chỉ là động phủ do nam tử bảy màu sáng tạo, tu sĩ bên trong không phải người Tiên Cương đại lục. Cười điên cuồng tuyên bố sẽ bước ra khỏi động phủ, tiến vào Tiên Cương đại lục khiến các đại tôn khuất phục. Lần lượt đánh tan tám mặt trời, phá giải bản chất tám thiên kiếp: chân tướng, hóa kiếp, thiên uy, bốn thanh kiếm, huyễn chân kiếp, ba pháp bảo, hồn lực tam tộc, Bổn Ngã kiếp. Thâm nhập mặt trời thứ chín — bổn nguyên thiên kiếp chứa vận mệnh hết thảy chúng sinh — tìm thấy khí tức vận mệnh bản thân, thôn phệ dung nhập, chính thức trở thành chúa tể vận mệnh của mình, siêu thoát khỏi mọi ràng buộc. Tiếp tục thu hồi vận mệnh cho cha mẹ, Thập Tam, Đồng tử đầu to, Chu Dật, Thanh Sương, Thanh Lâm, Nam Vân Tử, Hồng Sam Tử, Vương Trác, lão Thánh Hoàng, Độn Thiên, Vương Bình, Chu Như, Hồng Điệp, Mộc Băng Mi, Tây Tử Phượng, Lý Thiến Mai. Không tìm thấy vận mệnh Thanh Thủy, Tư Đồ Nam, Thiên Vận Tử. Phát hiện vận mệnh Lý Mộ Uyển có dấu hiệu tồn tại nhưng đã bị kẻ nào đó sớm một bước đem đi.","anchor":"dường như giờ phút này Vương Lâm hắn mới chính thức viên mãn, nắm lấy vận mệnh của mình từ trong thiên địa, siêu thoát khỏi nó!","bridge":true,"khoang":"@c1540"},{"mucCt":"ky","text":"Dùng thần thức tìm kiếm trong mặt trời thứ chín nhưng không tìm thấy vận mệnh của Tư Đồ Nam và Thanh Thủy. Phát hiện khí tức vận mệnh của Uyển Nhi vốn có dấu vết nhưng đã bị ai đó lấy đi. Nổi sát khí phát lời thề tại viễn cổ tiên vực nhất định sẽ thu hồi vận mệnh nàng, dù phải huyết tẩy Tiên Cương đại lục. Suy luận vận mệnh Tư Đồ Nam và Thanh Thủy có thể không thuộc mặt trời thứ chín, liên hệ ánh mắt kỳ dị của đạo nhân bảy màu nhìn Thanh Thủy và thiên tư bạo tăng bất thường của Tư Đồ Nam. Dù tu vi đạt Không Linh trung kỳ vẫn kiêng kỵ Thiên Vận Tử, cho rằng bí mật của người này rất nhiều, ẩn giấu rất sâu. Phá hủy vô số pho tượng tam tộc cổ trên mặt đất, giải thoát hồn linh; hư ảnh tam tộc hiện ra ôm quyền vái như được siêu thoát, khí tức Cổ Thần, Cổ Ma, Cổ Yêu dung nhập vào tinh điểm mi tâm và hai mắt. Phá hủy pho tượng Cổ Thần sát cửu tinh cao mấy ngàn trượng, phát hiện sinh vật bí ẩn ẩn bên trong dùng pho tượng làm phôi thể chữa thương. Túm cánh tay khô héo giật mạnh lôi ra ném xuống đất, tuyên bố muốn lấy trí nhớ của sinh vật này.","anchor":"Mặc kệ ngươi là tiên hay tu sĩ, Vương Lâm ta muốn trí nhớ của ngươi","bridge":true,"khoang":"@c1541"},{"mucCt":"ky","text":"Lao xuống hố sâu, dùng một trảo vặn xoắn quy tắc thiên địa khóa chặt lão già tiên nhân gầy gò. Đánh một chưởng xuyên thân thể, đánh nát tay trái lão già. Lão già cắn lưỡi phun máu thi triển thủ đoạn bảo mạng nhưng Vương Lâm điểm một ngón tay niệm Định, thi triển Định Không Thuật đình chỉ toàn bộ chuyển động kể cả năm tháng trong thiên địa. Tự nhận không phải tiên nhân mà chỉ là một con kiến hôi sinh ra trong thế giới phàm tục. Cuối cùng đặt tay lên thiên linh lão già chuẩn bị đọc ký ức tìm hiểu trận đại chiến năm xưa.","anchor":"Tu vi hắn đánh tan không môn, đạp tan thiên kiếp, lúc này đã là cảnh giới Không Linh trung kỳ","bridge":true,"khoang":"@c1542"},{"mucCt":"ky","text":"Dùng thần thức tràn vào thiên linh lão già sĩ tiên để thu lấy toàn bộ trí nhớ, khiến lão ta thất khiếu chảy máu. Trong thức hải lão già gặp sương mù nồng đậm phong toả, giống phong ấn từng thấy khi soát hồn Ngân Y Luyện Thi năm xưa. Tiến sâu vào sương mù, phát hiện nam tử trung niên bảy màu ngồi khoanh chân — chính là chân thân pho tượng bảy màu trong khe trữ vật, lần thứ hai nhìn thấy. Lần lượt thử phá phong ấn bằng chưởng ấn, dòng suối thần thức, song chỉ dung hợp Cổ Thần lực — tất cả đều bị tiêu tán ở giới hạn ba tấc bên ngoài thân nam tử bảy màu. Song chỉ mất gần nửa, dùng Cổ Thần lực hồi phục huyết nhục. Động lực hành động: hiểu rõ giới nội giới ngoại chỉ là động phủ tiên tôn, cộng thêm khí tức Lý Mộ Uyển biến mất khiến thống hận đỉnh điểm. Nhận định phá phong ấn rất gian nan nhưng không phải không có khả năng.","anchor":"khí tức của Lý Mộ Uyển biến mất lại càng khiến Vương Lâm hận","bridge":true,"khoang":"@c1543"},{"mucCt":"ky","text":"Quyết tâm phá phong ấn ký ức lão già gầy gò để biết chân tướng thiên địa. Lần đầu tiên đồng thời kích phát lực lượng Cổ Thần, Cổ Ma, Cổ Yêu cùng đầu lâu Đạo Cổ, tam tộc cổ đồng thời hiện ra phía sau. Thi triển thần thông tự sáng tạo trong mộng đạo — Cổ Tộc Bất Diệt Chỉ — ngưng tụ toàn bộ lực lượng tam tộc cổ vào ngón trỏ, ngón tay tan rã-khôi phục nghìn vạn lần xuyên qua giới hạn ba tấc phong ấn của tiên tôn, điểm vào mi tâm nam tử trung niên bảy màu phá vỡ phong ấn. Dùng Định Thần Thuật kịp giữ tinh thể ký ức sắp tự huỷ, nguyên thần bao phủ tinh thể đoạt về. Rút tay khỏi thiên linh lão già, lùi lại tránh lực trùng kích từ thân thể lão già nổ tung. Bình tĩnh cười lạnh trước sự chấn kinh của Tứ Thánh Hoàng.","anchor":"thân thể lập tức lui lại phía sau, thần sắc bình tĩnh, ngẩng đầu nhìn về phương xa, khoé miệng nở nụ cười lạnh","bridge":true,"khoang":"@c1544"},{"mucCt":"ky","text":"Dùng Cổ Tộc Bất Diệt Chỉ liên tục điểm phá lực trùng kích, tạo lỗ hổng bước ra, chu vi mấy trăm ngàn dặm biến thành đống đổ nát. Lấy tinh thể ký ức màu vàng nhạt của lão già gầy gò, dùng giọt máu tiên nhân bất diệt thể ở mi tâm kích hoạt để đọc toàn bộ ký ức. Ký ức tiết lộ Tiên Cương đại lục có chín mặt trời đại biểu chín đại thiên tôn, Thất Đạo Tông do đôi đạo lữ khai tông, tông chủ Thất Thải Thiên Tôn chính là viễn cổ tiên hoàng pho tượng bảy màu. Chứng kiến cảnh đêm hai mặt trời xuất hiện, Thất Thải Thiên Tôn cùng đạo lữ bay đi rồi chỉ một mình trở về. Đạo Cổ Diệp Mịch tìm đến chỉ trích Thất Thải vứt bỏ đạo lữ đoạt bảo vật, sau đó đại chiến nổ ra trong động phủ với ba kẻ phát kim quang, một trong ba tự xưng Bổn vương bảo Thất Thải ra quỳ lạy rồi tiến tới cánh cửa đá. Ký ức kết thúc, tinh thể tan nát. Nhận ra giọng nói Bổn vương chính là giọng người điên đang ngủ say trong không gian trữ vật. Xác nhận nữ tử mặc quần áo bạc trong ký ức là ngân y nữ tử trong khe trữ vật, thân phận nữ tử của tiên tôn. Liên hệ cánh cửa đá mà người điên bước tới chính là cánh cửa ngân y nữ tử nói không phải do nàng mở. Suy luận kết quả đại chiến: người điên mất thần trí, viễn cổ tiên vực thành đổ nát, Thất Thải Thiên Tôn trọng thương, Thất Đạo Tông gần diệt. Đặt nghi vấn bọn họ tranh đoạt thiên đạo hay Thiên Nghịch, Thiên Nghịch là pháp khí giống la bàn nhưng uy lực không lớn vậy nó thực sự là gì. Nhớ lại sau đại chiến có nhóm tu sĩ bên ngoài xuất hiện ở giới ngoại mang theo Côn Cực Tiên, danh tính chưa rõ. Cảm thấy đang mở ra một tầng bí mật, ngày càng gần đáp án cuối cùng.","anchor":"Giọng nói của người điên!","bridge":true,"khoang":"@c1545"},{"mucCt":"ky","text":"Tiến sâu vào Viễn cổ Tiên Vực, phá hủy thêm pho tượng Tam tộc cổ, bỏ qua ý định sưu hồn vì lục soát ký ức quá khó khăn. Phát hiện bốn pho tượng khổng lồ chọc trời, nhận ra một đạo khí tức là Chu Tước, giống Chu Tước đời thứ nhất ở Điên Lạc, xác định có một đạo là phân thân. Gọi Chu Tước chiến tướng ra gặp để giao dịch. Bạch Hổ chiến tướng (Không Huyền Sơ Kỳ) xông ra tấn công nhưng bị Vương Lâm một quyền đẩy lùi, thân mình không hề lùi. Dùng ánh mắt uy áp khiến Bạch Hổ theo bản năng lùi lại. Tuyên bố thẳng Viễn cổ Tiên Vực chỉ là đám tu sĩ tàn phế đại lục Tiên Cương tự xưng tiên nhân. Ra tối hậu thư cho Chu Tước: nếu không ra gặp sẽ giết người sưu hồn, uy áp vô hình lan ra bao phủ bốn phía.","anchor":"chỉ là một đám tu sĩ tàn phế của đại lục Tiên Cương ở trong động phủ này tự xưng là tiên nhân","bridge":true,"khoang":"@c1546"},{"mucCt":"ky","text":"Đối đầu Bạch Hổ lão giả trong viễn cổ tiên vực, dùng Chân Giả bổn nguyên nhắm mắt hóa giải toàn bộ thức Hổ Khiếu Sơn Hà và hàng ngàn nhát khai thiên đao mà thân thể không hề hấn gì — đao xuyên qua như hư ảnh. Phản kích bằng Nhân Quả bổn nguyên, vỗ chưởng vào ngực Bạch Hổ lão giả rồi lôi luồng bạch quang từ cơ thể hắn ra bóp nát, khiến lão phun máu hai lần. Triệu hoán đầu lâu Đạo cổ cùng hư ảnh tam tộc cổ đồng thời gầm thét, sóng âm áp đảo hoàn toàn tiếng hổ gầm, buộc Bạch Hổ lão giả phải dung hợp với hư ảnh Bạch Hổ hóa thành Bạch Hổ khổng lồ vừa gào vừa lùi. Thân thể Cổ Thần là yếu tố then chốt — nếu không có thì dù Không Linh trung kỳ cũng bị đánh tan.","anchor":"Nếu hắn không có thân thể cổ Thần thì lúc này trong tiếng hổ rống kinh thiên, hắn dù có tu vi Không Linh trung kỳ cũng sẽ bị đánh tan thân thể","bridge":true,"khoang":"@c1547"},{"mucCt":"ky","text":"Điểm một chỉ khiến đầu lâu Đạo cổ lao về phía Bạch Hổ khổng lồ, va chạm tạo lực trùng kích phá hủy mặt đất viễn cổ tiên vực, đánh tan hư ảnh Bạch Hổ, khiến Bạch Hổ lão giả phun máu bị găm vào pho tượng. Bị Bạch Hổ lão giả thi triển đại thuật Kỵ Hổ Nan Hạ trói trên lưng Bạch Hổ, phong ấn thiên địa xung quanh, hổ linh quấn quanh thân mưu nuốt thiên linh. Nhắm mắt bùng phát khí thế bậc đại nho, tay trái đè lên hổ khẩu quát trấn áp, lực trấn áp ẩn chứa minh ngộ cả đời và hư bổn nguyên bước thứ ba. Hổ linh run rẩy cúi đầu quy phục. Xác nhận tu vi Không Linh trung kỳ, thân thể Cổ Thần cùng thần thông đủ đánh Không Huyền sơ kỳ, cố ý không dùng cung Lý Quảng.","anchor":"Tu vi của Vương Lâm là Không Linh trung kỳ nhưng thân thể cổ Thần và thần thông của hắn đủ để đánh với tu sĩ Không Huyền sơ kỳ","bridge":true,"khoang":"@c1548"},{"mucCt":"ky","text":"Hổ linh cúi vái Vương Lâm rồi dung hợp lại thành Bạch Hổ, Bạch Hổ bỏ đi tiêu tán vào viễn cổ tiên vực không thèm để ý Bạch Hổ chiến tướng. Ba chiến tướng Thanh Long, Huyền Vũ, Bạch Hổ nhân lúc bạch quang chói mắt liên thủ đánh lén. Vương Lâm dùng Cổ Tộc Bất Diệt chỉ bức lùi Thanh Long chiến tướng khiến hắn phun máu lùi hơn trăm trượng. Kích hoạt giọt máu tiên nhân bất diệt thể trên mi tâm xuyên thấu nắm tay Huyền Vũ chiến tướng, phá tan hư ảnh Huyền Vũ. Thi triển sáu chưởng ấn liên hoàn phá tan khai thiên đao và trọng thương Bạch Hổ chiến tướng. Bạch Hổ chiến tướng điên cuồng đòi mở phong ấn tu vi ở mi tâm. Vương Lâm rút cung Lý Quảng kéo căng dây cung, cả bốn chiến tướng đều kinh hoàng im bặt. Chu Tước chiến tướng cuối cùng bước ra, vẻ xấu hổ, ôm quyền xưng Vương Lâm là tiên hữu và cầu hòa.","anchor":"Thậm chí càng có cảm giác nguy cơ, hắn lại càng tỉnh táo!","bridge":true,"khoang":"@c1549"},{"mucCt":"ky","text":"Thu cung Lý Quảng sau khi thị uy, gặp mặt Chu Tước đời thứ nhất (phân thân). Dùng uy hiếp cung Lý Quảng (3 mũi tên đủ hủy Viễn Cổ Tiên Vực), đề xuất giao dịch với tứ đại chiến tướng: cam kết hủy Viễn Cổ Tiên Vực giới ngoại và bảo vệ bọn họ 3 năm trị thương, đổi lại bốn yêu cầu — giết hết người giới ngoại, bảo toàn sinh mạng tu sĩ giới nội, giải phóng sinh linh khỏi động phủ, được tới đại lục Tiên Cương nhận tài nguyên. Phân một tia thần thức ngưng tụ thành hình cành liễu làm thệ ước. Khẳng định Viễn Cổ Tiên Vực giới ngoại không thể ra được, khiến tứ đại chiến tướng sững sờ. Nội tâm tiết lộ mục đích thật: lợi dụng môn nhân Thất Đạo Tông ra ngoài tìm Viễn Cổ Tiên Tôn, nghi Thất Thải Đạo Nhân và chiến lão quỷ cùng các phe phái đều tìm kiếm một thứ — có thể là Thiên Đạo — muốn trong sự hỗn loạn đạt mục đích riêng.","anchor":"Ta muốn tu sĩ giới nội từ lúc các ngươi đi ra, không còn một người nào tử vong nữa!","bridge":true,"khoang":"@c1550"},{"mucCt":"ky","text":"Rời viễn cổ tiên vực cùng tứ đại chiến tướng qua cái khe thiên kiếp, lần đầu cảm thấy thiên địa hoàn toàn hư ảo. Nhận rõ Thiên Nghịch châu là vật mấu chốt ra vào viễn cổ tiên vực. Hiểu rằng Phong Tôn đời trước chỉ là thủ hạ của tiên tôn, đến từ Tiên Cương đại lục, tới giới nội để sắp đặt cho chủ nhân, không phải người giới nội. Trước mấy ngàn tu sĩ hoan hô hô vang Phong Tôn, hắn trầm mặc mê man, muốn nói ra sự thật nhưng không thể mở miệng. Ngồi uống rượu suốt đêm cùng Tư Đồ Nam trên đỉnh núi vô danh trên Chu Tước Tinh, tự sự toàn bộ hành trình tu đạo: vì cha mẹ mà tu, việc tu đạo thành căn nguyên cha mẹ chết, báo thù diệt Đẳng gia máu chảy thành sông, vì Uyển nhi tử vong mà tu đạo để cứu nàng sống lại, trở thành Phong Tôn danh chấn thiên địa nhưng vẫn ghét tu đạo. Cuối cùng tiết lộ cho Tư Đồ Nam toàn bộ bí mật: đã giết một tiên nhân trong viễn cổ tiên vực và lục soát trí nhớ, phát hiện giới nội giới ngoại chỉ là một tòa động phủ của viễn cổ tiên tôn, một giới tạo ra để thu thập hương hỏa.","anchor":"Ta lục soát trí nhớ của tiên nhân này, biết một chuyện có liên quan tới giới nội, giới ngoại, biết bí mật quan trong nhất của thiên địa này.","bridge":true,"khoang":"@c1551"},{"mucCt":"ky","text":"Kể cho Tư Đồ Nam bí mật thiên địa: giới nội giới ngoại chỉ là động phủ của Thất Thải Tiên Tôn, Thiên Đạo do Tiên Tôn cướp được rồi nuôi dưỡng, Thiên Kiếp do hắn tạo ra để diệt nghịch tu. Tổng kết ba quá trình tu đạo của bản thân: vì người khác, chán nản mê man, nay bước vào quá trình thứ ba với sự kiên định chưa từng có, tuyên bố từ nay không còn chán nản tu đạo. Ngộ ra ý nghĩa thực sự của danh hiệu Phong Tôn — đảm đương: không chỉ chống ngoại xâm mà phải dẫn tu sĩ giới nội thoát khỏi động phủ, phá tan mọi trở ngại. Tuyên bố muốn giết Thất Thải Tiên Tôn để giành vận mệnh và tự do, nhưng trước đó phải bảo vệ biên cương ba năm. Lần đầu nhìn pho tượng Phong Tôn của chính mình trên Chu Tước Tinh, cảm nhận khí thế quyết không quay đầu, liên tưởng tới sự quyết tâm từng thấy trên người Tán Linh Thượng Nhân. Đứng trên đỉnh đầu pho tượng phát lời kêu gọi tu sĩ Chu Tước Tinh cùng tới La Thiên đánh giới ngoại, vô số tu sĩ đáp lời hóa cầu vồng bay lên tụ lại.","anchor":"Cả đời ta tu đạo chưa bao giờ trong lòng có một sự kiên định","bridge":true,"khoang":"@c1552"},{"mucCt":"ky","text":"Dẫn đầu mấy ngàn tu sĩ giới nội xuất chinh từ Chu Tước Tinh, hô hào cùng giành lại giang sơn giới nội, hóa cầu vồng lao vào tinh không. Sát tâm bùng phát mạnh nhất kể từ trận diệt Đằng gia hơn hai ngàn năm trước. Khuếch tán thần thức bao trùm toàn bộ Côn Hư tinh vực, đơn thân diệt sạch mọi tu sĩ giới ngoại sống sót bao gồm mấy chục người đầu tiên và cặp song sinh thiên nhân nhị suy. Thu thập mấy trăm đầu lâu bị phong ấn linh hồn và nguyên thần. Xác nhận cuộc chiến giới nội–giới ngoại chỉ là bước đầu tiên, mục tiêu tối thượng là phá vỡ động phủ ra ngoài. Quét sạch Côn Hư tinh vực rồi tiến tới biên giới Triệu Hà.","anchor":"Hắn hiểu rõ hai chữ đảm dương. Hắn hiểu rõ bản thân mình phải có trách nhiệm.","bridge":true,"khoang":"@c1553"},{"mucCt":"ky","text":"Tiến vào Triệu Hà tinh vực, lần đầu thi triển Sanh Tử Chân Giả Nhân Quả trận — trận pháp bổn nguyên do dung hợp tam đại bổn nguyên minh ngộ, dùng hư bổn nguyên vây khốn nguyên thần trong mấy trăm đầu lâu khiến chúng trải qua sinh tử chân giả nhân quả vô tận, là bước đầu gieo trồng mầm mống sát lục. Sát lục bổn nguyên bộc phát, bốn phía xuất hiện bông tuyết hư ảo đỏ đậm, tinh không đóng băng lấp lóe hồng quang. Dùng Nhân Quả ấn dạng chưởng ấn khổng lồ che phủ bầu trời, lòng bàn tay mang ấn ký Vạn Không Cốt Môn, tiêu diệt mấy ngàn tu sĩ giới ngoại trên tu chân tinh đầu tiên, rút nguyên thần phong ấn vào đầu lâu. Tuyên bố còn chưa đủ, tiếp tục tiến tới tu chân tinh khác. Thần thức bao phủ cả Triệu Hà, phát hiện đại năng bước thứ ba Không Linh hậu kỳ giới ngoại nhưng chẳng thèm quan tâm, chủ động để kẻ đó tìm mình. Phát hiện Chu Tử Hồng bị giam làm tù binh trên tu chân tinh Minh Linh tộc.","anchor":"Hắn còn giết chưa đủ, còn chưa giết sướng khoái.","bridge":true,"khoang":"@c1554"},{"mucCt":"ky","text":"Xuất hiện tại tu chân tinh nơi Minh Linh tộc ẩn náu, hừ lạnh một tiếng đánh tan song chưởng tộc trưởng thiên nhân ngũ suy, sau đó một trảo nát thân thể hắn, phong ấn nguyên thần vào đầu lâu. Dùng sấm sét từ mắt phải chia thành vô số tia giáng xuống, diệt toàn bộ tộc nhân Minh Linh tộc trên tu chân tinh, thu gần vạn đầu lâu. Vung tay áo đưa ba trăm nguyên thần nữ tu Triệu Hà (trong đó có Chu Tử Hồng) trở lại cơ thể, hút toàn bộ tử khí mặt đất ngưng tụ thành quả cầu sương mù trên tay phải, khôi phục sinh cơ cho tu chân tinh. Sau đó phóng cơn lốc tử vong bức tu sĩ giới ngoại Bước thứ ba hiện thân, dùng nhân quả phá tấm khiên mai rùa, Định Thần thuật khống chế rồi chém đầu. Tuyên bố dưới Không Huyền không ai là địch thủ.","anchor":"Dưới Không Huyền không ai là địch thủ của Vương Lâm ta","bridge":true,"khoang":"@c1555"},{"mucCt":"ky","text":"Dùng thuật sưu hồn lấy ký ức từ đầu lâu tu sĩ bước thứ ba đầu tiên bị giết, thu được kiến thức về hư bổn nguyên và phương pháp nuôi dân hương hỏa. Quét sạch toàn bộ tu sĩ giới ngoại trong Triệu Hà tinh vực, đầu lâu từ một vạn tăng lên gần năm vạn. Bước vào Vân Hải tinh vực, khuếch tán thần thức bao phủ toàn tinh vực, dùng phương thức bá đạo báo cho tất cả tu sĩ giới ngoại biết sự hiện diện. Nhận ra năm vạn đầu lâu có thể tạo thành sinh tử trận. Nhìn cảnh Vân Hải quen thuộc bị phá hủy, phẫn nộ tăng mạnh. Thần thức quét qua phế tích Phá Thiên Tông phát hiện nữ tử thanh y trong nụ hoa tím, quét qua đại lục trôi nổi phát hiện lão già hồng bào ấn ký dơi đen. Phát hiện La Thiên bị hơn mười vạn tu sĩ giới ngoại vây khốn, Mộc Băng Mi và những thân ảnh quen thuộc đều bị vây bên trong trận pháp 990 tu chân tinh.","anchor":"Năm vạn đầu lâu, có thể tạo thành sinh tử trận!","bridge":true,"khoang":"@c1556"},{"mucCt":"ky","text":"Có mặt tại Vân Hải tinh vực, quyết định không tiến thẳng La Thiên mà quét sạch tu sĩ giới ngoại ở các tinh vực khác trước để thu đầu lâu và nguyên thần tạo trận pháp. Thu đủ năm vạn đầu lâu, chia hai dòng xoáy sinh/tử rồi dung hợp, phun tâm thần huyết bước thứ ba ngưng kết thành bánh xe khổng lồ mười vạn trượng — Sinh Tử trận thành. Tiếp tục tàn sát thu thêm đầu lâu cho trận thứ hai Nhân Quả đại trận. Giao chiến với nữ tu sĩ bước thứ ba giới ngoại, triệu huyết kiếm dung nhập lực lượng hủy diệt Không Linh trung kỳ, một kiếm bổ đôi tu chân tinh lẫn bổn tôn nữ tử. Quét sạch toàn bộ tu sĩ giới ngoại tại Vân Hải tinh vực, phóng bánh xe sinh tử chặn đại lục đang chạy trốn vào Thái Cổ Tinh Thần.","anchor":"Hắn muốn trước tiên giết sạch tu sĩ giới ngoại ở các tinh vực khác","bridge":true,"khoang":"@c1557"},{"mucCt":"ky","text":"Dùng Sinh Tử đại trận triệu bánh xe sinh tử hủy diệt đại lục trong sương mù tại Vân Hải tinh vực, tu sĩ tu vi yếu bị thân thể tan nát và nguyên thần phong ấn vào đầu lâu. Lão già đối thủ dùng hắc phong hóa miệng khổng lồ nuốt bánh xe nhưng thất bại, bị đánh bật ra. Vương Lâm vung tay khiến thân thể lão già nổ tung, đầu lâu phong ấn nguyên thần bắn lên, tuyên bố kết thúc giết chóc tại Vân Hải tinh vực. Một nửa đại lục trong lỗ hổng Phong Giới Đại Trận cũng bị hủy diệt thành bụi bặm. Sau đó dùng một chưởng nén dòng xoáy đầu lâu kết chặt thành bánh xe thứ hai, trên dưới thân có hai bánh xe khổng lồ (sinh tử và nhân quả), mái tóc bạc trắng tung bay, sát khí băng hàn. Dịch chuyển tới La Thiên tinh vực.","anchor":"Vương Lâm nhắm hai mắt, tay phải vung về phía trước","bridge":true,"khoang":"@c1558"},{"mucCt":"vua","text":"Từ nơi giao nhau La Thiên Tinh Vực và Vân Hải Tinh Vực, bắn mũi tên mang phẫn nộ, sát lục và tử vong. Tiếng gầm mũi tên lấn áp cả chưởng ấn bổn tôn Chưởng Tôn, trở thành âm thanh duy nhất giữa tinh không.","anchor":"Tiếng gầm thét của nó ầm ầm vang lên, không ngờ lấn áp tiếng vang do chưởng ấn của Chưởng Tôn","bridge":true,"khoang":"@c1560"},{"mucCt":"ky","text":"Xuất hiện trên mũi tên Lý Quảng vạn trượng, bạch y tóc bạc, phía sau mơ hồ có hai bánh xe bất động khổng lồ, mũi tên mang sát lục tích từ Côn Hư, Triệu Hà, Vân Hải xé rách tinh không tạo khe nứt vĩnh viễn. Lần lượt phá chưởng ấn bảy màu, bảy tầng màn sáng, mặt trời huyết mạch tiên nhân, mũi tên hư ảo từ giếng hương hỏa giới, xuyên thấu thân thể Chưởng Tôn và phá hủy cung điện thánh vật. Chưởng Tôn tiết lộ Vương Lâm đã bỏ qua tiên nhân bất diệt thể mà chủ nhân ban cho, tiên lực chỉ đủ bắn thêm hai lần nữa, sau đó tuyệt đối không thể thành tiên nhân. Sau trận chiến xoay người bảo vệ Mộc Băng Mi, tuyên bố nàng là mẫu thân con trai Vương Bình, nhìn thẳng đe dọa Đạo Phi Hủ.","anchor":"Nàng mặc dù không phải là hồng nhan của ta nhưng lại là mẫu thân của con trai Vương Bình của ta","bridge":true,"khoang":"@c1561"},{"mucCt":"ky","text":"Chặn Đạo Phi Hủ trước mặt Mộc Băng Mi khi hắn định bắt nàng làm con tin, phá nát tứ chi rồi vỗ mi tâm khiến thân thể nổ tung, bóp nát nguyên thần — bậc toàn năng bước ba Không Niết hoàn toàn tử vong. Đuổi kịp đại hán phong lôi đang bỏ chạy, phá tan cơn lốc máu kết hợp lôi cầu bằng một tiếng gầm nhẹ, thể hiện lôi bổn nguyên đại thành viên mãn khiến mọi lôi đình thiên địa thuần phục. Điểm vào cổ đại hán, hút sạch máu huyết, sinh cơ, xương cốt, nguyên thần biến thành quả cầu sương mù. Dùng tu vi xua bảy luồng hắc khí độc tố khỏi thất khiếu Thanh Thủy, xóa tử khí, rồi ấn quả cầu sương mù vào cơ thể sư huynh để hồi phục thương thế. Nói rõ lý do trừng phạt: Mộc Băng Mi là mẫu thân Vương Bình, tuyệt đối không cho phép ai khinh nhờn.","anchor":"Vương Lâm chính là tổ tông của lôi đình, lôi bổn nguyên đại thành viên mãn","bridge":true,"khoang":"@c1562"},{"mucCt":"ky","text":"Tuyên chiến với tu sĩ giới ngoại, phát lệnh Sát, dẫn gần tám vạn tu sĩ giới nội xông ra từ tinh trận. Triệu xuất bánh xe Sinh Tử trận trấn áp mười vạn tu sĩ giới ngoại, khiến mấy vạn người phun máu, một số tan nát tử vong. Xông vào giữa đại quân mở con đường máu, đầu lâu kẻ địch ngưng tụ thành áo choàng đầu người phía sau. Trực tiếp giao chiến tiên phi Không Huyền trung kỳ: dùng thân thể Cổ Thần ngạnh kháng ngũ tạng thuật dù ngũ tạng vỡ vụn, tung quyền dung hợp Đạo cổ và tam tộc cổ đánh lui nàng. Rút Xạ Thần xa chấn nhiếp tiên phi bỏ chạy, dùng Định khống chế, thi triển tiên thuật Bạch Phàm rồi Âm Nguyệt Hữu Tình xé tan dung nhan nàng. Thi triển Dịch Linh Ấn đẩy lùi, hé lộ thân phận tiên phi là phi tử tông chủ Thất Đạo Tông từ Tiên Cương đại lục khiến nàng kịch chấn. Cuối chương rút huyết kiếm vung chém xuống tiên phi.","anchor":"Huyết kiếm xuất hiện trong tay, Vương Lâm vung lên hung hăng chém xuống!","bridge":true,"khoang":"@c1563"},{"mucCt":"ky","text":"Phối hợp Dịch Linh Ấn và huyết kiếm hạ sát tiên phi đầu tiên, khiến nàng hình thần câu diệt, nhưng bản thân bị thương bởi thần thông huyết mạch tiên nhân. Biến thành sương mù đen thôn phệ hơn vạn tu sĩ giới ngoại, khôi phục hơn phân nửa thương thế. Thi triển Nhân Quả trận biến kiếm khí lão già áo đen thành năm vạn đạo kiếm khí quét ngang tám hướng, giết năm vạn tu sĩ giới ngoại. Dùng Sinh Tử Ấn đánh trúng lão già áo đen, rồi dùng Nhân Quả Ấn kéo một phần bổn nguyên lão ra bóp nát, tung Thất Thải Đinh đâm ngực lão. Kích hoạt Thiên Hoàng Lô từ Cổ Thần tinh điểm, dung hợp toàn bộ tinh điểm Cổ Thần cùng giọt máu vàng tiên nhân bất diệt thể, kết hợp thần thông Lưu Nguyệt tạo cánh cửa đá đặt lên lò, trấn áp tiên phi áo lam và lão già áo đen vạn vạn năm. Hô Thanh Lâm, Hồng Sam Tử, Triệu Hà liên thủ chặn hai Không Huyền cuối cùng, chuẩn bị bố trí Sinh Tử Nhân Quả Chân Giả đại trận, quyết giết hết tu sĩ giới ngoại.","anchor":"xem rốt cục hai kẻ kia muốn tìm thứ gì!","bridge":true,"khoang":"@c1564"},{"mucCt":"ky","text":"Ngồi trên Thiên Hoàng Lô triển khai trận pháp tam đại bổn nguyên, chồng ba bánh xe Sinh Tử, Chân Giả, Nhân Quả thành một trận pháp duy nhất — thần thông mạnh nhất hắn tự sáng tạo, cả đời chỉ ngưng tụ được một lần. Kêu gọi một vạn tu sĩ giới nội tự nguyện hiến nguyên thần làm trận linh. Bánh xe bành trướng sánh ngang bầu trời, quay bốn vòng: vòng một phá tan tinh trận do tu chân tinh tạo thành và giết ba phần tu sĩ giới ngoại, vòng hai lại giết thêm ba phần, vòng ba được Thanh Lâm cùng Hồng Sam Tử, nữ tử Triệu Hà, Thanh Thủy xuất nguyên thần đẩy khiến tinh không thực sự sụp đổ, vòng bốn Vương Lâm đích thân xuất nguyên thần nhấn hoàn thành, quét ngang toàn bộ La Thiên diệt sạch hơn mười vạn tu sĩ giới ngoại. Bà lão áo lục Không Huyền hình thần câu diệt, chỉ tiên phi Không Huyền dùng thần thông tổn mệnh Tiên Cương đại lục mở khe thoát thân. Sau trận phun máu trọng thương, tuyên bố ba năm cuối cùng và hứa bảo vệ mọi người ba năm tu dưỡng.","anchor":"Đây là thần thông mạnh nhất trong số những thần thông Vương Lâm tự nghĩ ra","bridge":true,"khoang":"@c1565"},{"mucCt":"ky","text":"Bị thương nặng từ ba nguồn: tiên phi phản kích trước khi chết, dùng Thiên Hoàng Lô trấn áp, và đặc biệt nặng nhất là dung hợp tam đại bổn nguyên tạo bánh xe vận mệnh — lần đẩy thứ tư khiến kiệt sức hoàn toàn. Dù tu vi đã đạt Không Linh trung kỳ vẫn sắc mặt tái nhợt, nhưng ánh mắt kiên định tuyên bố bảo vệ nơi này ba năm. Hiểu rằng Trường hạo kiếp sẽ bộc phát trong hoặc sau ba năm, có thể hủy diệt giới nội giới ngoại, mang kế hoạch riêng và ý niệm điên cuồng, cuốn bánh xe tam đại bổn nguyên lao về Vân Hải tinh vực. Dùng khí tức bổn nguyên từ bánh xe tạo cuồng phong quét sạch sương mù trước lỗ hổng Phong Giới Đại Trận, lộ ra khe hở ngàn trượng — vết sẹo gần ngàn năm không khép lại. Nhận ra trận pháp đã không còn cứu được, chọn lấy lực một người trấn giữ.","anchor":"Hắn không lùi bước, không ngã xuống mà nói lên lời nói sẽ bảo vệ nơi này ba năm","bridge":true,"khoang":"@c1566"},{"mucCt":"ky","text":"Đối mặt Tử Hà (tiên phi thứ tám) trước lỗ hổng Phong Giới Đại Trận, cự tuyệt mọi yêu cầu giao tiên phi và dụ dỗ gia nhập Thất Đạo Tông. Phát sát khí đuổi Tử Hà, nể công lao nàng cho giới nội nên không ra tay. Hồi tưởng tổng kết tám tiên phi: thứ hai đã chết, thứ ba được thả, thứ tư bị nhốt trong cổ mộ, thứ năm bị trấn áp trong Thiên Hoàng Lô, thứ sáu chạy thoát, thứ tám là Tử Hà, suy đoán nữ tử có ước định ở Vân Hải tinh vực là tiên phi thứ nhất hoặc thứ bảy. Khinh bỉ nói Thất Thải Tiên Tôn chỉ là tiểu chư hầu, Thất Đạo Tông chỉ tiểu tông phái. Trong tâm lập chí sẽ giết tiên tôn lấy thiên đạo, giải phóng dân chúng trong động phủ ra Tiên Cương đại lục. Hấp thu thiên địa nguyên lực Vân Hải tinh vực, dùng Nhân Quả ấn rút bổn nguyên khôi phục sáu đạo bổn nguyên và thân thể Cổ Thần. Quyết tâm khi Phong Giới Đại Trận chết sẽ phá hủy nơi này và dùng tu vi bản thân tạo trận mới.","anchor":"Vương mỗ cả đời nghịch tu thiên đạo, muốn làm gì thì làm, làm gì có chuyện để người khác sai khiến, cầu xin người khác mang ta rời khỏi nơi này","bridge":true,"khoang":"@c1567"},{"mucCt":"ky","text":"Vương Lâm suy tư về con đường bước thứ ba độc nhất: không cần hương hỏa, dựa vào minh ngộ khiến tam đại hư bổn nguyên viên mãn, dựa vào thôn phệ khiến lôi hỏa bổn nguyên đại thành, cần bổn nguyên do người khác ngưng tụ để thôn phệ đề cao tu vi. Hắn nhận ra con đường bổn nguyên có thể đạt tới bảy, tám, chín, thậm chí mười đạo — bảy đạo đại thành bằng Không Linh hậu kỳ, tám đạo bằng Không Linh đỉnh phong, chín đạo bước vào Không Huyền, chín đạo dung hợp thành lực lượng gọi là Không thì đối mặt huyền kiếp, vượt chín lần huyền kiếp thành Không Kiếp đại tôn. Hắn đứng dậy đạp lên Phong Giới Đại Trận đang thoi thóp khiến nó lóe sáng huyễn hóa, mấy vạn tu sĩ trong La Thiên đều nhìn thấy. Hắn vái trận pháp một vái vì nó đã thủ hộ giới nội vô số năm, rồi tuyên bố nó cũng giam giữ giới nội khiến rất ít bậc toàn năng bước thứ ba, tu sĩ suốt đời bị nhốt. Hắn tuyên bố sẽ bố trí một đại trận mới hoàn toàn thuộc về tu sĩ giới nội. Hắn thi triển Nhân Quả ấn, dùng Nhân Quả trừu linh lần lượt rút ra và hủy diệt bảy trận linh của Phong Giới Đại Trận. Trận pháp sụp đổ hoàn toàn, ranh giới giới nội – giới ngoại bị xóa bỏ. Hắn cho bát linh — Khai Thiên Phủ, pháp khí vô thượng Cổ Thần tộc — lựa chọn trở về tay hắn hoặc bị hủy diệt.","anchor":"Ta cho ngươi một sự lựa chọn!","bridge":true,"khoang":"@c1568"},{"mucCt":"ky","text":"Hóa chân thân cổ Thần ngàn trượng, dùng nắm đấm giao chiến với khí linh Khai Thiên Phủ, tay phải bị thương tới xương rồi hồi phục. Triệu huyết kiếm trăm trượng chém liên tục đánh bại khí linh, để lại vết kiếm trên lưỡi búa. Xưng mình là vương tộc cổ Thần, triệu đầu lâu Đạo cổ uy hiếp khiến khí linh tan nát rồi ôm quyền quy phục. Cắn lưỡi phun máu tạo ấn ký thu phục Khai Thiên Phủ, dung nhập vào mi tâm, hoàn toàn dựa sức mạnh bản thân mà không cần nhờ Phong Tôn đời đầu. Sau đó thi triển Nhân Quả ấn lần cuối cùng lôi ngọc bội chữ tiên (trận linh cuối cùng) ra khỏi Phong Giới Đại Trận, ngọc bội vỡ thành năm mảnh, đại trận hoàn toàn tan rã, tứ đại tinh vực được giải phóng, giới nội giới ngoại hợp nhất. Trở thành người đầu tiên từ cổ chí kim hủy Phong Giới Đại Trận, mang danh hiệu Phong Tôn thế hệ mới, chuẩn bị dẫn tu sĩ giới nội rời động phủ ra Tiên Cương đại lục.","anchor":"hắn là Phong Tôn, không phải là Phong Tôn của Thất Đạo Tông, không phải là Phong Tôn dưới trướng Thất Thải Tiên Tôn mà là Phong Tôn chuẩn bị mang tu sĩ giới nội đi khỏi động phủ này","bridge":true,"khoang":"@c1569"},{"mucCt":"ky","text":"Sau khi Phong Giới Đại Trận sụp đổ hoàn toàn, Vương Lâm tuyên bố lập trận pháp mới tên Vô Danh, cốt lõi là bánh xe tam đại bổn nguyên khuếch trương vô tận bao phủ toàn bộ tứ đại tinh vực. Hắn dùng bổn nguyên lực kêu gọi linh hồn pháp bảo đã tan nát và tinh hồn tu chân tinh bị hủy diệt trong trăm năm chiến tranh dung hợp vào bánh xe, hứa chúng vĩnh hằng bất diệt. Hắn dùng thần thông gió lốc cuốn trên trăm vạn tàn hồn tu sĩ giới ngoại từ khắp tứ đại tinh vực phong ấn vào trận pháp, ép chúng đẩy bánh xe đời đời kiếp kiếp chuộc tội vĩnh viễn. Trận pháp ngăn cách giới nội giới ngoại nhưng không cản khí tức Thái Cổ Tinh Thần, được dự kiến tồn tại lâu hơn Phong Giới Đại Trận, mở ra thời đại mới và là bước đầu tiên trong kế hoạch giết tiên tôn. Cuối cùng hắn kính cẩn ôm quyền vái tinh không, thỉnh mời hồn phách tiên nhân giới nội nguyện làm trận linh bất diệt được đời đời cúng bái.","anchor":"Hôm nay Vương Lâm ta phá hủy Phong Giới Đại Trận, muốn lập trận pháp mới. Trận này tên Vô Danh!","bridge":true,"khoang":"@c1570"},{"mucCt":"ky","text":"Vương Lâm thực hiện nghi thức tế bái chưa từng có trong lịch sử giới nội, cúng tế toàn bộ vong hồn tử trận trong chiến tranh giới nội – giới ngoại từ viễn cổ tới nay. Tiếng nói vang vọng của hắn gọi về tàn hồn từ khắp tứ đại tinh vực. Ba lớp anh hồn xuất hiện theo thời đại: tàn hồn viễn cổ, tiên nhân thượng cổ từ tứ đại tiên giới, và tu sĩ cận đại. Hắn hỏi các anh hồn có nguyện ý trở thành trận linh bất diệt hay không. Hàng chục vạn anh hồn lần lượt dừng trước mặt hắn, ôm quyền vái rồi tự nguyện dung nhập vào bánh xe do tam đại bổn nguyên biến thành, trở thành trận linh. Trong lòng Vương Lâm, bọn họ chính là tiên. Sau khi hoàn thành, Vương Lâm vái một cái rồi không chút do dự nhảy vào bên trong trận pháp.","anchor":"Từ cổ chí kim, trong chiến tranh giữa giới nội và giới ngoại có rất nhiều tu sĩ và chúng sinh tử vong. Nhưng chưa bao giờ có ai làm cúng tế cho bọn họ","bridge":true,"khoang":"@c1571"},{"mucCt":"ky","text":"Điều khiển tam đại bổn nguyên biến thành bánh xe, anh hồn giới nội làm trận linh, khai mở Vô Danh Chuyển Luân trận ngăn tu sĩ giới ngoại xâm nhập. Tuyên bố Phong Giới Đại Trận năm đó bất công, lập lại tinh không mở lại tinh vực. Triệu tập hồn phách phàm nhân vô tội chết trong chiến tranh tu sĩ suốt vô số năm, dùng trận pháp tiễn vào thiên đạo luân hồi. Giới nội mở rộng từ hai phần lên ba phần nhờ hồn phách phàm nhân dung nhập. Tự nguyện bỏ qua hết thảy, đầu nhập trận pháp trở thành trận linh, ngồi trên Thiên Hoàng Lô trước lỗ hổng Vân Hải tinh vực nhắm mắt bảo vệ giới nội ba năm. Trận pháp khuếch trương lên bốn phần, ánh sáng vạn trượng bao phủ giới nội.","anchor":"trong ba năm này Vương Lâm ta sẽ bỏ qua hết thảy, đầu nhập vào bên trong trận này, trở thành trận linh","bridge":true,"khoang":"@c1572"},{"mucCt":"ky","text":"Khoanh chân ngồi trên Thiên Hoàng Lô trong Vô Danh Chuyển Luân trận, không ngừng trấn áp phong ấn hai bậc toàn năng Không Huyền bên trong (lão già áo đen và tiên phi thứ năm), cần bảo vệ ba năm. Nghĩ tới Lý Mộ Uyển, không biết có thể làm cho nàng sống lại hay không. Tây Tử Phượng tới xin một năm ở bên cạnh, ban đầu cự tuyệt nhưng sau thở dài đồng ý. Ba nữ tử (Tây Tử Phượng, Mộc Băng Mi, nữ tử áo hồng) đã thỏa thuận mỗi người một năm, tổng ba năm khớp thời gian bảo vệ. Ba tháng sau, đại quân giới ngoại mười vạn tu sĩ gồm năm người bước thứ ba và chiến xa ngàn trượng kéo tới tấn công lần nữa.","anchor":"Thở dài một tiếng, Vương Lâm mở hai mắt, nhìn về phía Tây Tử Phượng.","bridge":true,"khoang":"@c1573"},{"mucCt":"ky","text":"Đứng trên Thiên Hoàng Lô bình thản đối diện toàn bộ lực lượng cực hạn giới ngoại gồm mười vạn tu sĩ, năm toàn năng bước thứ ba, chiến xa và bia đá chín quan tài. Đòn đầu tiên — đại kiếm hợp nhất mười vạn nguyên thần chém xuống Vô Danh Chuyển Luân trận — bị trận pháp tự phản lực đánh bật vỡ tan mà Vương Lâm không cần cử động. Đối mặt đòn thứ hai — mười vạn tu sĩ hiến tế toàn bộ thọ nguyên triệu hồi ánh sáng viễn cổ kim quang mang khí tức Tiên Cương đại lục, suýt phá bánh xe tam đại bổn nguyên — hắn bình tĩnh thi triển Phần Giới Cổ Tán mở ô diệt giới bao phủ kim quang, đồng thời triệu xuất trường thương bảy màu (Xích, Chanh, Hồng, Lục, Lam, Thanh, Tử) phá nát ánh sáng viễn cổ. Sau khi phá giải, vung tay áo bước về bên Tây Tử Phượng uống rượu, bình thản nói rượu còn chưa đủ ấm, thể hiện phong thái áp đảo tuyệt đối.","anchor":"Rượu còn chưa đủ ấm, Tây Tử, làm ấm thêm chút nữa","bridge":true,"khoang":"@c1574"},{"mucCt":"ky","text":"Vương Lâm tuyên bố trong ba năm bất luận ai muốn vào giới nội đều phải bước qua xác hắn. Hắn thi triển trường thương bảy màu lao vào dòng xoáy mười vạn nguyên thần, đối kháng ánh sáng viễn cổ, hai bên triệt tiêu lẫn nhau. Sau đó dùng Phần Giới cổ Tán với biển lửa diệt giới che hắc động, đốt cháy dòng xoáy mười vạn nguyên thần khiến năm bậc toàn năng và mấy vạn tu sĩ phun máu trọng thương. Liên tục thi triển quá sức — khí huyết quay cuồng, nguyên thần đau đớn nhưng vẫn đứng vững thách thức đối phương. Đối mặt chiến xa viễn cổ mãnh thú tấn công Vô Danh Chuyển Luân trận khiến trận pháp chấn động, hắn tuyên bố mình cũng có viễn cổ cự thú còn sống có thân thể. Điểm lên mi tâm, dòng xoáy tỏa khí tức tang thương xuất hiện, u quang lóe lên.","anchor":"trong ba năm bất luận kẻ nào muốn đi vào giới nội cũng phải bước qua xác ta!","bridge":true,"khoang":"@c1575"},{"mucCt":"ky","text":"Triệu hoán U Minh thú xuất hiện trong Vô Danh Chuyển Luân trận, bước lên thân nó vỗ nhẹ trấn an qua tâm thần tương liên. Ra mệnh lệnh buộc U Minh thú nuốt trọn hơn mười hồn phách mãnh thú viễn cổ nhưng ngăn nó hút mấy vạn tu sĩ để tránh nó ngủ say nhiều năm — đây cũng là lý do trước đó ở chiến trường La Thiên không gọi nó ra. Chín quan tài trên tấm bia đá khổng lồ mở tung sau khi năm bậc toàn năng và mấy vạn tu sĩ giới ngoại hiến tế nguyên thần tinh huyết, bùng lên luồng khí tức Đạo cổ biến đổi giữa Cổ Thần – Cổ Ma – Cổ Yêu. Nhận ra khí tức thuộc về Đạo cổ Diệp Mịch, cực kỳ ngưng trọng. Phán đoán đây không phải mắt trái của Diệp Mịch vì khí tức chưa đủ mạnh, nhưng không rõ bản chất thực sự là gì.","anchor":"Không phải mắt trái! Nếu là mắt trái thì khí tức phải còn mạnh hơn thế này nhiều","bridge":true,"khoang":"@c1576"},{"mucCt":"ky","text":"Chín quan tài nổ tung hợp nhất thành nam tử trung niên ngàn trượng mang khí tức Đạo cổ Diệp Mịch, hai tinh điểm Cổ Thần trên mi tâm. Vương Lâm nhận diện khí tức thuộc Đạo cổ Diệp Mịch nhưng xác định không phải mắt trái Đạo cổ. Nam tử dùng Cổ tộc Chiến Ấn khiêu chiến, Vương Lâm nhận ra ấn ký từ trí nhớ truyền thừa Đạo cổ và đáp lại bằng Chiến Ấn. Vương Lâm lần đầu tiên rời khỏi Vô Danh Chuyển Luân trận, thân thể bành trướng tới ngàn trượng, lao ra tinh không Thái cổ Tinh Thần đấu quyền trực tiếp với nam tử trung niên. Va chạm chấn động cả giới nội giới ngoại. Mục đích của Vương Lâm là đoạt khí tức Đạo cổ Diệp Mịch trên người đối phương để tiến tới bát tinh Cổ Thần.","anchor":"Vương Lâm lần đầu tiên rời khỏi Vô Danh Chuyển Luân trận, đứng bên trong tinh không Thái cổ Tinh Thần","bridge":true,"khoang":"@c1577"},{"mucCt":"ky","text":"Giao tranh khốc liệt bằng thân thể cổ tộc với nam tử trung niên, trao đổi chín quyền cận chiến, dư chấn khiến mấy vạn tu sĩ giới ngoại lui hơn mười vạn trượng. Hợp song quyền xuyên phá Cổ Thần nhất chỉ (hư ảnh Cổ Thần tám tinh điểm), đánh lõm ngực đối thủ nhưng bị đá bắn lùi mấy ngàn trượng. Lần đầu gầm lớn trong trận chiến. Nếm máu đối phương phân tích ra nam tử trung niên KHÔNG phải con trai Đạo Cổ Diệp Mịch mà do đám Chưởng Tôn giới ngoại qua vô tận năm tháng giết vô số người tam tộc cổ, ngưng tụ tám giọt tâm huyết tạo thành. Bộc phát khí tức Đạo cổ, triệu hồi đầu lâu Đạo cổ (không mắt trái) quyết sinh tử. Nếu thắng sẽ thôn phệ tám giọt tinh huyết, ngưng hóa thêm tinh điểm Cổ Thần/Yêu/Ma, tương đương truyền thừa lần hai.","anchor":"Tất cả mọi chuyện chính là cơ hội để hắn có thể vào vùng đất cổ mộ lần thứ hai, đạt được truyền thừa một lần nữa!","bridge":true,"khoang":"@c1578"}],"nhanMach":[{"ten":"Thiên Triệu Thượng Sư","tag":"doi-thu","quanHe":"Đối thủ sắp đối đầu","ghiChu":"Phó hội trưởng Trường Tôn hội, Không Linh sơ kỳ, đóng tại Thất Thải Giới tổng bộ Tu Chân Liên Minh"},{"ten":"Long Bàn Tử","tag":"doi-thu","quanHe":"Địch thủ, thái thượng trưởng lão Tu Chân Liên Minh, Vương Lâm kính nể trí tuệ và sự táo bạo của hắn","gap":"@c1456"},{"ten":"Trương Tịch","tag":"khac","quanHe":"Đại trưởng lão Tu Chân Liên Minh, bị Long Bàn Tử giết trước mặt Vương Lâm","gap":"@c1459"},{"ten":"Nữ tử ôn nhu","tag":"khac","quanHe":"Người yêu của Thanh Thủy, xuất hiện trong ký ức","ghiChu":"Vương Lâm nhìn thấy qua sương máu @c1462"},{"ten":"Thập Tam","tag":"su-mon","quanHe":"Đệ tử","ghiChu":"Thanh niên áo đen gọi Sư tôn, kích động khi thấy Vương Lâm bước vào khách sạn"},{"ten":"Viêm Lôi Tử","tag":"dong-minh","quanHe":"Cứu mạng trong vùng cấm thức Côn Hư","ghiChu":"Túm lại dập lửa sinh mạng, ngăn tử chiến @c1452"},{"ten":"Lam Mộng Đạo Tôn","tag":"khac","quanHe":"Đạo Tôn Thái Cổ Tinh Thần, niệm tình cũ với Phong Tôn mà hiện thân cảnh báo Vương Lâm về sát kiếp","ghiChu":"Khẳng định không tham gia giết Phong Tôn đời trước"},{"ten":"Lão già áo xám","tag":"doi-thu","quanHe":"Cao thủ Thái Cổ Tinh Thần, một trong ba kẻ vây sát Vương Lâm trong thiên địa lam quang"},{"ten":"Bà lão áo đen","tag":"doi-thu","quanHe":"Cao thủ Thái Cổ Tinh Thần, tập kích sau lưng Vương Lâm trong trận vây sát"},{"ten":"Nam tử áo trắng","tag":"doi-thu","quanHe":"Cao thủ Thái Cổ Tinh Thần, dùng hàn kiếm phá Quang Ảnh Thuẫn và Dịch Linh Ấn của Vương Lâm"},{"ten":"Nữ tử bí ẩn (Ngũ Tạng Tiên Đạo)","tag":"doi-thu","quanHe":"Đối thủ","ghiChu":"Xuất hiện từ hư vô thi triển Ngũ Tạng Tiên Đạo phá nội tạng Vương Lâm khi hắn sắp giết nam tử bạch y"},{"ten":"Nữ tử tử y","tag":"doi-thu","quanHe":"Tiên phi thứ hai, dự ngữ Vương Lâm ba nhịp thở tử vong","ghiChu":"@c1487"},{"ten":"Hư Thần Thiên Tôn","tag":"doi-thu","quanHe":"Kẻ thù cấp Thái Cổ","ghiChu":"Đánh một chưởng vào hậu tâm Vương Lâm, hút máu tiên nhân, tuyên bố phải đoạt thân thể bất diệt"},{"ten":"Xích Hồn Tử","tag":"khac","quanHe":"Linh hồn được Vương Lâm giải phong ấn từ Hắc Tháp","ghiChu":"Vương Lâm dùng máu Đạo Cổ giải phóng, yêu cầu giúp giết địch nhưng Xích Hồn Tử không tuân lệnh mà lao nuốt Tiên Phi rồi bay đi."},{"ten":"Chu Nhị","tag":"khac","quanHe":"Nữ tu sĩ gặp trong mộng cảnh, cảm thấy quen mặt quen tên Vương Lâm","ghiChu":"@c1496"},{"ten":"Từ Phi","tag":"khac","quanHe":"Sư muội của Chu Nhị, gặp trong mộng cảnh, trêu gọi hắn là tiểu tử ngốc","ghiChu":"@c1496"},{"ten":"Đại Phúc","tag":"khac","quanHe":"Người điên gặp trong miếu hoang đêm mưa","ghiChu":"Hai người ngồi bên đống lửa trong miếu thổ địa, Vương Lâm thương xót cho người mất trí"},{"ten":"Người điên","tag":"dong-hanh","quanHe":"Nhận làm thư đồng","ghiChu":"Gặp trong miếu hoang đêm mưa, chia lương khô và trò chuyện suốt đêm, sáng sau nhận làm thư đồng đi cùng vào kinh — hành vi luân hồi lặp lại chuyện Nhân phương giới. @c1499"},{"ten":"Niệm Thiên","tag":"khac","quanHe":"Sư huynh của Độn Thiên tại Luyện Hồn tông, tìm tới Vương Lâm bằng chiêm bốc","ghiChu":"Dùng hắc phong bao phủ Vương Lâm, nói chỉ muốn hỏi một câu"},{"ten":"Tô Đạo","tag":"khac","quanHe":"Đại văn hào gặp trên cầu đá Tô thành, hỏi Vương Lâm về nhân quả rồi quan tâm hỏi tên","ghiChu":"@c1504"},{"ten":"Tô Đạo","tag":"su-mon","quanHe":"Sư phụ nho đạo, đại nho Tô thành","ghiChu":"Bái sư năm 19 tuổi, theo học mười năm"},{"ten":"Tô Nhất","tag":"doi-thu","quanHe":"Đệ nhất môn sinh của Tô Đạo, chất vấn Vương Lâm tại buổi giảng học","ghiChu":"@c1507"},{"ten":"Phụ thân Vương Lâm","tag":"cha-me","quanHe":"Phụ tử","ghiChu":"Phụ thân phàm nhân, lâm chung trong vòng tay Vương Lâm sau ba mươi ba năm xa quê"},{"ten":"Mẫu thân Vương Lâm","tag":"cha-me","quanHe":"Mẫu tử","ghiChu":"Mẫu thân phàm nhân, hiền từ đón con hồi hương"},{"ten":"Liễu Mi","tag":"khac","quanHe":"Nữ tử quen thuộc bí ẩn xuyên kiếp","ghiChu":"Trong kiếp mộng gặp hai lần, Liễu Mi cảm thấy quen thuộc đau lòng không rõ nguyên do, Vương Lâm hét cảnh cáo nàng đừng quen tu sĩ Vương Lâm"},{"ten":"Nữ tử Tuyết Vực quốc","tag":"khac","quanHe":"Nữ tử từ Tuyết Vực quốc tìm tới hỏi chuyện","ghiChu":"@c1511"},{"ten":"Đại hán thợ rèn","tag":"khac","quanHe":"Chủ tiệm rèn ở đô thành trong mộng, mời uống rượu và tặng bầu rượu","ghiChu":"@c1511"},{"ten":"Hồng Điệp","tag":"khac","quanHe":"Đặt tên cho nàng khi còn là trẻ sơ sinh, cảm nhận khí tức quen thuộc từ nàng","ghiChu":"@c1512"},{"ten":"Lý Mộ Uyển","tag":"the-thiep","quanHe":"Người yêu / nhân duyên xuyên suốt giấc mộng","ghiChu":"Vương Lâm phá phong ấn mi tâm nàng, nàng là người đầu tiên tỉnh lại trong mộng, thề chờ hắn tỉnh mộng"},{"ten":"Oa Oa","tag":"khac","quanHe":"Nữ đồng trên Tiên Cương đại lục, truyền âm xuyên hư vô tự giới thiệu với Vương Lâm khi thần thức hắn thăm dò","ghiChu":"@c1522"},{"ten":"Nam tử áo xanh","tag":"doi-thu","quanHe":"Đối thủ tu vi Không Huyền","ghiChu":"Bị Nhân Quả Ấn rút hơn phân nửa bổn nguyên, bỏ chạy rồi quay lại"},{"ten":"Thanh niên tóc bạc trong Bổn Ngã kiếp","tag":"doi-thu","quanHe":"Đối thủ Bổn Ngã kiếp, tự xưng là chính Vương Lâm, có thần thông và bổn nguyên giống hệt","ghiChu":"Vương Lâm phải đánh bại hắn mới biết bí mật thiên kiếp"},{"ten":"Lão già khô gầy (sĩ tiên)","tag":"doi-thu","quanHe":"Sinh vật bí ẩn ẩn trong pho tượng Cổ Thần sát cửu tinh, bị Vương Lâm chế phục để lấy trí nhớ","gap":"@c1541"},{"ten":"Thất Thải Thiên Tôn","tag":"khac","quanHe":"Chủ nhân viễn cổ tiên vực mà Vương Lâm khám phá ký ức","ghiChu":"Vương Lâm qua ký ức lão già gầy gò biết được lai lịch Thất Thải Thiên Tôn là tông chủ Thất Đạo Tông, viễn cổ tiên hoàng"},{"ten":"Đạo Cổ Diệp Mịch","tag":"khac","quanHe":"Nhân vật trong ký ức viễn cổ, từng tấn công Thất Đạo Tông","ghiChu":"Vương Lâm biết qua ký ức lão già gầy gò"},{"ten":"Bạch Hổ Thánh Hoàng","tag":"doi-thu","quanHe":"Bạch Hổ chiến tướng dưới trướng Thất Thải Tiên Tôn, xông ra tấn công nhưng bị Vương Lâm một quyền đẩy lùi","ghiChu":"@c1546"},{"ten":"Tộc trưởng Minh Linh tộc","tag":"doi-thu","quanHe":"Đối thủ bị diệt","ghiChu":"Giết tộc trưởng và toàn bộ tộc nhân Minh Linh tộc trên tu chân tinh (@c1555)"},{"ten":"Tử Hà","tag":"doi-thu","quanHe":"Tiên phi thứ tám đến yêu cầu giao tiên phi, bị Vương Lâm cự tuyệt và đuổi đi","ghiChu":"Coi nàng là người Thất Đạo Tông, nể công lao cho giới nội nên tha"},{"ten":"Chu Tước đời thứ nhất (phân thân)","tag":"dong-minh","quanHe":"Đối tượng đàm phán giao dịch","ghiChu":"Gặp mặt tại Viễn Cổ Tiên Vực, Vương Lâm xưng vãn bối, đề xuất giao dịch hợp tác."},{"ten":"Nam tử trung niên (chín quan tài)","tag":"doi-thu","quanHe":"Đối thủ sanh tử qua Cổ tộc Chiến Ấn","ghiChu":"Mang khí tức Đạo cổ Diệp Mịch, Vương Lâm muốn đoạt để tiến bát tinh @c1577"}],"tuViMoc":[{"chuong":"@c1488","canhGioi":"Tiên nhân bất diệt thể (chưa hoàn chỉnh)","text":"Chuyển đổi từ thân Cổ Thần sang tiên thể, bộc lộ tiên nhân bất diệt thể đã đạt một nửa nhờ người điên trước đó. Kim quang vạn trượng bao phủ cả Chu Tước Tinh. Tuy nhiên lực bài xích giữa Cổ Thần và tiên hoàn toàn mất kiểm soát.","importance":"major"},{"chuong":"@c1491","canhGioi":"Cổ Thần thuần túy (mất huyết mạch tiên nhân)","text":"Bị Chưởng Tôn dùng bổn nguyên thái sơ quy tắc tách hoàn toàn huyết mạch tiên nhân, tinh điểm Cổ Thần và Cổ Ma mất kim quang, cơ thể trở về thân Cổ Thần thuần túy. Du hồn bị thiêu hủy hết, lực bài xích tiêu tan.","importance":"major"},{"chuong":"@c1519","canhGioi":"Lôi bổn nguyên đại thành","text":"Ngưng tụ chín tia sét dung hợp thành lôi ấn ký bất diệt hình thái hỗn độn, uy áp bước thứ ba, chấn động Không Niết sơ kỳ.","importance":"major"},{"chuong":"@c1519","canhGioi":"Hỏa bổn nguyên đại thành","text":"Biển lửa chín màu hợp nhất vượt hư hỏa thành đạo hóa, ngưng tụ thành ký hiệu hình ngọn lửa hư ảo bất định, nhiệt độ đốt cháy Không Niết sơ kỳ. Cùng Lôi bổn nguyên đủ giết Không Niết hậu kỳ đại viên mãn trở xuống.","importance":"major"},{"chuong":"@c1519","canhGioi":"Nhân Quả bổn nguyên (sáng tạo)","text":"Dùng khí tức đại nho từ bảy mươi năm mộng đạo ngưng tụ Nhân Quả bổn nguyên trên tay phải — mở tay là nhân, nắm tay là quả — thần thông thứ tư do hắn tự sáng tạo.","importance":"major"},{"chuong":"@c1520","canhGioi":"Bước thứ ba — ba đạo bổn nguyên đại thành","text":"Nhân quả bổn nguyên đại thành sau khi ngộ Nhân Quả ấn, kết hợp lôi đình bổn nguyên và hỏa bổn nguyên (cũng đã đại thành), ba đạo bổn nguyên đồng thời viên mãn. Khí tức bước thứ ba tăng gấp bội, Không Môn xuất hiện.","importance":"major"},{"chuong":"@c1522","canhGioi":"Bước thứ ba (sáu đạo bổn nguyên, phá không môn)","text":"Hoàn thành sáu đạo bổn nguyên, phá không môn thành tựu bước thứ ba toàn năng. Hư Thần Thiên Tôn đánh giá nếu phá ra sẽ đạt Không Niết Sơ Kỳ nhưng đủ sức chiến Không Huyền sơ kỳ, thậm chí vượt qua không cảnh trong thời gian ngắn.","importance":"major"},{"chuong":"@c1525","canhGioi":"Không Niết Trung Kỳ (khí thế)","text":"Sau khi phá Không Môn thứ nhất bằng lôi đình bổn nguyên, khí thế đạt Không Niết sơ kỳ. Phá tiếp Không Môn thứ hai bằng hỏa bổn nguyên, khí thế bạo tăng lên Không Niết trung kỳ. Tuy nhiên đây chỉ là khí thế chứ chưa phải tu vi thực chất, vì chưa hấp thu sức mạnh Không Môn và chưa dung hợp sáu đạo bổn nguyên.","importance":"major"},{"chuong":"@c1526","canhGioi":"Không Niết Hậu Kỳ","text":"Phá Không Môn thứ ba bằng Nhân Quả Ấn, tu vi từ Không Niết Trung Kỳ vọt lên Không Niết Hậu Kỳ.","importance":"minor"},{"chuong":"@c1526","canhGioi":"Không Niết Đại Viên Mãn","text":"Phá Không Môn thứ tư bằng Sinh Tử Ấn, đạt đỉnh Không Niết Đại Viên Mãn. Mi tâm hiện khe thiên địa bản thân, chưa mở hoàn toàn.","importance":"minor"},{"chuong":"@c1526","canhGioi":"Không Linh Sơ Kỳ","text":"Phá Không Môn thứ năm bằng Chân Giả Đạo, khe mi tâm hiện hoàn toàn với lực hút vô tận, khí thế Không Linh Sơ Kỳ khuếch tán. Đột phá đại cảnh giới Không Linh.","importance":"major"},{"chuong":"@c1530","canhGioi":"Không Linh trung kỳ","text":"Đạo sát lục bổn nguyên thứ sáu dung hợp hoàn toàn với thân thể, tu vi từ Không Linh sơ kỳ tăng lên Không Linh trung kỳ ngay trong vòng xoáy Không Môn.","importance":"minor"},{"chuong":"@c1531","canhGioi":"Bước thứ ba Không Linh trung kỳ","text":"Sau khi hợp sáu đạo bổn nguyên và phá vỡ Không Môn, Vương Lâm vượt Không Niết chính thức tiến vào bước thứ ba Không Linh trung kỳ, trở thành bậc toàn năng của thiên địa.","importance":"major"}],"tuiDo":{},"diem":[{"text":"Phàm nhân tư chất kém, nhờ Nghịch Thiên Châu khai mở Mộng Cảnh, chính thức bước vào con đường tu tiên","chuong":"@c0023"},{"text":"Đoạt xá thân Mã Lương sau khi tự nổ thân thể xuyên Vực Ngoại, tái sinh từ tuyệt cảnh","chuong":"@c0103"},{"text":"Nhận truyền thừa Cổ Thần Đồ Ti, trọng tổ thân thể Cổ Thần, nền tảng cho toàn bộ con đường thể tu sau này","chuong":"@c0176"},{"text":"Dung hợp bổn tôn và phân thân thành một, đạt tam tinh Cổ Thần, xác lập hình thái chiến đấu hoàn chỉnh","chuong":"@c0365"},{"text":"Chính thức thành Đại Thiên Tôn, Đại Thiên Tôn Chi Dương ba màu thực chất hóa trọn vẹn, mười mặt trời hiện trên Tiên Cương","chuong":"@c1939"},{"text":"Diệt Thiên Vận Tử, hồi sinh Lý Mộ Uyển, thu La Bàn Định Giới, đạt cảnh giới Đạp Thiên — hoàn tất hành trình nghịch thiên","chuong":"@c1976"}]},"nguon":["@c1451","@c1452","@c1453","@c1454","@c1455","@c1456","@c1457","@c1458","@c1459","@c1460","@c1461","@c1462","@c1463","@c1464","@c1465","@c1466","@c1467","@c1468","@c1469","@c1470","@c1471","@c1472","@c1473","@c1474","@c1475","@c1476","@c1477","@c1478","@c1479","@c1480","@c1481","@c1482","@c1483","@c1484","@c1485","@c1486","@c1487","@c1488","@c1489","@c1490","@c1491","@c1492","@c1493","@c1494","@c1495","@c1496","@c1497","@c1498","@c1499","@c1500","@c1501","@c1502","@c1503","@c1504","@c1505","@c1506","@c1507","@c1508","@c1509","@c1510","@c1511","@c1512","@c1513","@c1514","@c1515","@c1516","@c1517","@c1518","@c1519","@c1520","@c1521","@c1522","@c1523","@c1524","@c1525","@c1526","@c1527","@c1528","@c1529","@c1530","@c1531","@c1532","@c1533","@c1534","@c1535","@c1536","@c1537","@c1538","@c1539","@c1540","@c1541","@c1542","@c1543","@c1544","@c1545","@c1546","@c1547","@c1548","@c1549","@c1550","@c1551","@c1552","@c1553","@c1554","@c1555","@c1556","@c1557","@c1558","@c1560","@c1561","@c1562","@c1563","@c1564","@c1565","@c1566","@c1567","@c1568","@c1569","@c1570","@c1571","@c1572","@c1573","@c1574","@c1575","@c1576","@c1577","@c1578"],"theLuc":[{"ten":"Chu Tước Tinh","trangThai":"gan-bo"}],"vaiTro":"Nhân vật chính — phàm nhân nghịch thiên, Đại Thiên Tôn tam cổ cửu tinh đệ nhất cường giả Tiên Cương","tinhCach":"Kiên nghị bất khuất, nhiều lần từ tuyệt cảnh tán công vươn lên đột phá; Thâm trầm mưu trí, giỏi ẩn nhẫn bố cục và phản kích trong thế yếu; Quyết đoán tàn nhẫn với kẻ thù nhưng nặng tình với cố nhân; Không chịu khuất phục trước hoàng quyền và trật tự áp đặt","blurb":"Vương Lâm xuất thân là thiếu niên phàm nhân tư chất kém ở Thạch Thôn, nhờ Nghịch Thiên Châu khai mở Mộng Cảnh, ý chí khổ tu và vô số lần sinh tử — từ đoạt xá thân Mã Lương, truyền thừa Cổ Thần Đồ Ti, dung hợp bổn tôn với phân thân, vượt mười bảy tầng Thiên Tôn Niết — mà từng bước vươn tới đỉnh cao tu đạo. Sau khi được sắc phong Dược Thiên Tôn, đạt Không Kiếp hậu kỳ với thân thể tam cổ cửu tinh và ngưng hình dáng ban đầu của Đại Thiên Tôn Chi Dương, hắn đối diện trực tiếp áp lực hoàng quyền Đạo Cổ mà vẫn không quỳ gối, vượt Tam Tổn Kiếp tại Tổ Miếu Thủy Cổ, chính thức thành Đại Thiên Tôn, dung "},{"id":"nam-tu-thay-kho","name":"Nam tử thây khô","cn":"","aliases":["Người điên","A Ngốc"],"gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"mucCt":"ky","text":"Hưng phấn gào thét khi ra thế giới bên ngoài sau bao năm bị giam hãm, giương nanh múa vuốt vui sướng. Bị Vương Lâm dùng kim quang kéo lại nhưng thi triển thần thông bí ẩn thoát khỏi trong nháy mắt, cho thấy sức mạnh thực sự vượt xa vẻ ngoài. Tự xưng bổn vương, nói có nhiều sư tôn mà không ai quản được. Được Vương Lâm sắp xếp ở lại tu chân tinh cấp thấp cùng Hứa Lập Quốc và Lưu Kim Bưu. Gọi Hứa Lập Quốc là tiểu nương tử, cười bò lăn rồi dần mê man nhắc Tiểu Hồng mang ô.","anchor":"Con bà nó, ngươi dám quản bổn vương sao? Ngay cả ca ca ta cũng không quản được ta.","bridge":true,"khoang":"@c1451"}],"nhanMach":[{"ten":"Hứa Lập Quốc","tag":"khac","quanHe":"Người được Vương Lâm giao trông coi người điên","ghiChu":"Bị người điên gọi là tiểu nương tử"},{"ten":"Lưu Kim Bưu","tag":"khac","quanHe":"Người được Vương Lâm giao trông coi người điên","ghiChu":""}],"tuViMoc":[],"tuiDo":{},"diem":[{"text":"Lần đầu xuất hiện từ quan tài hở góc, ngưng tụ lôi cầu tím bằng hắc quang, tuyên bố kỳ hạn trăm năm đã tới","chuong":"@c0077"},{"text":"Hiện ra từ hắc vụ, dùng cánh tay khô héo hóa bàn tay khổng lồ phong ấn không gian, đánh đuổi Đằng Hóa Nguyên Nguyên Anh tu sĩ","chuong":"@c0078"},{"text":"Dùng cổ ngữ điều khiển pho tượng, tuyên bố truy sát chủ nhân Ngô Vũ để đoạt tự do","chuong":"@c0079"},{"text":"Thoát khỏi giam hãm ra thế giới bên ngoài, hưng phấn gào thét giương nanh múa vuốt","chuong":"@c1451"}]},"nguon":["@c1451"],"vaiTro":"Thân thể cũ của lão tổ Ngô Vũ — thi khôi tự sinh thần trí, truy sát chủ nhân cũ","tinhCach":"Lạnh lùng, quyết đoán khi truy sát; kiên nhẫn chờ đợi hàng trăm năm giữa các lần hoạt động; hưng phấn cuồng nhiệt khi thoát giam hãm","blurb":"Vốn là thân xác bị lão tổ Ngô Vũ bỏ lại ba trăm năm trước khi Nguyên Anh ly thể chạy thoát, cái xác khô về sau tự nảy sinh thần trí và đắc cơ duyên đột phá tới Nguyên Anh trung kỳ, vượt qua chính Ngô Vũ. Bị ràng buộc không được rời Ngô Vũ quá trăm dặm nếu không sẽ tan rã, và mỗi lần hoạt động phải nghỉ khoảng trăm năm. Nhiều lần truy sát Ngô Vũ để đoạt tự do, đánh đuổi cả Đằng Hóa Nguyên rồi phá pho tượng tìm chủ nhân, nhưng cuối cùng Ngô Vũ cùng đồng hành kịp truyền tống đào thoát; về sau từng thoát ra thế giới bên ngoài."},{"id":"hua-lap-quoc","name":"Hứa Lập Quốc","cn":"许立国","gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1451","importance":"bridge","mucCt":"vua","text":"Bị Vương Lâm triệu ra từ trữ vật cùng Lưu Kim Bưu, phàn nàn rồi được giao trông coi người điên trên tu chân tinh cấp thấp, bị người điên gọi là tiểu nương tử.","anchor":"Lão tử nói gì thì cũng là một kiếm linh có thể lập công lao cho sát tinh cơ mà"},{"mucCt":"ky","text":"Cùng Lưu Kim Bưu hợp mưu nhiều ngày lừa người điên, dùng kế dụ hắn bằng việc hứa dẫn đi gặp nữ tử để đổi lấy máu tươi quý giá. Đóng vai a dua nịnh bợ, xưng “tiểu nhân” với người điên. Vẻ mặt hưng phấn cẩn thận hứng lấy những giọt máu tươi. Khi người điên dọa mách sư phụ thì hoảng sợ run người, vì mục đích chính mấy ngày qua cũng là làm người điên quên chuyện mách sư phụ Vương Lâm.","anchor":"Mấy ngày này, hai người bọn họ đã hợp mưu lừa người điên này, đã thu hoạch được không ít chuyện tốt","bridge":true,"khoang":"@c1472"},{"mucCt":"ky","text":"Cùng Lưu Kim Bưu dẫn Người điên qua truyền tống trận tới động phủ. Dụ Người điên vào phòng gặp Pháp Hoa Tử (nam giới đóng giả tiểu nương tử). Dùng ngọc giản kích hoạt truyền tống trận triệu hồi hơn mười tu sĩ đồng mưu diễn kịch. Giả vờ bị cắm đầy kiếm trên người, kêu thảm thiết tạo áp lực buộc Người điên cho máu tươi. Nhìn Người điên như kho báu di động, sợ sát tinh (chủ nhân) trở về phát hiện. Cuối cùng bị thân ảnh áo trắng xuất hiện quát đích danh.","anchor":"Vương gia, không cần phải để ý tới ta, người hãy chạy mau đi!","bridge":true,"khoang":"@c1473"},{"mucCt":"ky","text":"Nghe tiếng Vương Lâm xuất hiện, quỳ xuống gọi chủ nhân, sợ hãi cầu xin tha mạng. Bị Vương Lâm chỉ một ngón tay phế ba thành tu vi, linh thể gần tan vỡ, tâm thần chấn động. Kêu lên thảm thiết, kể công lao: nhắc lão tổ Cự Ma Tộc ở Chu Tước Tinh, nói lấy giọt máu vàng vì chủ nhân. Vương Lâm nói rõ nếu không có những công lao đó thì sẽ hủy diệt hồn phách chứ không chỉ phế tu vi. Bị Vương Lâm vung tay áo cuốn thu vào không gian trữ vật.","anchor":"nếu không có những chuyện đó, thì một chỉ vừa rồi sẽ không phải chỉ phế đi ba thành tu vi của ngươi, mà là sẽ hủy diệt hồn phách của ngươi","bridge":true,"khoang":"@c1474"}],"nhanMach":[{"ten":"Pháp Hoa Tử","tag":"dong-minh","quanHe":"Đồng mưu trong kế hoạch lừa Người điên"}],"tuViMoc":[],"tuiDo":{},"diem":[{"text":"Bị Vương Lâm bắt sống tại Phần Kim sơn mạch, hủy ý thức gốc, ép nguyên thần thành ma đầu Trúc Cơ hậu kỳ đỉnh giả đan","chuong":"@c0112"},{"text":"Cản đòn bảo vệ thân thể Vương Lâm trước người khổng lồ băng tuyết, chiến đấu tới kiệt sức","chuong":"@c0338"},{"text":"Phản chủ chém đứt cánh tay trái Cự Ma lão tổ rồi tự nguyện quay về theo Vương Lâm","chuong":"@c0373"},{"text":"Được Chu Dật cho lĩnh hội truyền thừa kiếm ý viễn cổ, trở thành kiếm linh đời thứ nhất của Vũ tiên kiếm","chuong":"@c0596"},{"text":"Bị giam trong lốc xoáy lửa ba năm liên tục kháng cự, thực lực tăng mạnh","chuong":"@c1018"},{"text":"Khôi phục ký ức tiền kiếp trước lúc rời Tổ Thành, nhận lại Vương Lâm làm chủ nhân","chuong":"@c1881"}]},"nguon":["@c1451","@c1472","@c1473","@c1474"],"vaiTro":"Ma đầu bị Vương Lâm khống chế — kiếm linh đời thứ nhất của Vũ tiên kiếm","tinhCach":"Kiêu ngạo, hay lải nhải đòi đảo chủ tớ nhưng luôn bị trấn áp khuất phục; si mê nữ sắc tới mức mất tự chủ; nhát gan tính toán phản bội song cuối cùng vẫn quay về theo chủ; thực dụng giỏi nịnh nọt để tự bảo toàn","blurb":"Hứa Lập Quốc vốn là tu sĩ Nguyên Anh kỳ của Thiên Cương Tông, bị Vương Lâm bắt sống tại Phần Kim sơn mạch, hủy ý thức gốc rồi ép nguyên thần thành ma đầu. Trải qua hàng loạt biến cố, hắn lần lượt làm tay sai giám sát, kiếm hồn trong tiên kiếm, được Chu Dật cho lĩnh hội truyền thừa kiếm ý viễn cổ mà trở thành kiếm linh đời thứ nhất của Vũ tiên kiếm. Về sau hắn được đưa tới Tiên Cương, trải qua đầu thai chuyển thế mất rồi khôi phục ký ức, tiếp tục nhận Vương Lâm làm chủ và đi theo tới Tiên giới."},{"id":"luu-kim-buu","name":"Lưu Kim Bưu","cn":"刘金宝","gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1451","importance":"bridge","mucCt":"vua","text":"Bị Vương Lâm triệu ra cùng Hứa Lập Quốc, cẩn thận đánh giá xung quanh rồi được giao nhiệm vụ trông coi người điên trên tu chân tinh cấp thấp.","anchor":"Lưu Kim Bưu lộ thần sắc ngưng trọng, tiến lên vài bước, ánh mắt không ngừng đánh giá người điên"},{"chuong":"@c1472","importance":"bridge","mucCt":"vua","text":"Đồng mưu với Hứa Lập Quốc lừa người điên lấy máu tươi, giả vẻ bình tĩnh nhưng hai mắt cũng sáng ngời khi thấy máu; dùng ấn quyết mở các truyền tống trận dẫn đường.","anchor":"ngay cả Lưu Kim Bưu kia hai mắt cũng sáng ngời"},{"mucCt":"ky","text":"Bóp vai cho Người điên rồi quỳ xin thưởng, kể chi tiết chi phí mười ba ngày để ép lấy tám chín giọt máu tươi. Tiết lộ trước đây từng lừa nhiều tu sĩ tu vi cao thâm nhưng dùng mẹo đơn giản nhất cho Người điên vì hắn tâm tính đơn giản. Cho biết đã dùng mấy chục truyền tống trận trước đó lấy không ít máu tươi. Giả vờ bị thương dính đầy máu trong màn kịch. Thỏa thuận chia ba bảy với Hứa Lập Quốc. Cuối cùng bị thân ảnh áo trắng quát đích danh.","anchor":"Những người mà lão phu lừa năm đó không có kẻ nào điên, đều là những hạng người tu vi cao thâm, thông minh hơn người","bridge":true,"khoang":"@c1473"},{"chuong":"@c1474","importance":"normal","mucCt":"ky","tieuDe":"Bị tước tự do, bắt làm nô bộc ngàn năm","text":"Hồn bay phách tán trước uy áp Vương Lâm, quỳ dập đầu liên tục đến trán đầm đìa máu. Bị Vương Lâm đánh bắn đi mấy trượng, tuyên bố công lao ở Hỏa Tước Tộc vẫn tính nhưng tước cơ duyên tự do, bắt ở lại làm nô bộc một ngàn năm vì bản tính khó sửa. Trong lòng cười khổ chấp nhận hình phạt. Bị thu vào không gian trữ vật.","anchor":"Ngươi đã lập công lớn, công lao này vẫn còn, nhưng cơ duyên thì phải bỏ, cũng đừng nghĩ đến tự do nữa, ngươi hãy ở lại làm nô bộc cho ta một ngàn năm"},{"chuong":"@c1514","importance":"bridge","mucCt":"gon","text":"Được nhắc: bản thể tu sĩ Vương Lâm trong Mộng Đạo đã học cả thuật lừa đảo của Lưu Kim Bưu để lừa gạt chính mình.","anchor":"ngươi trong Mộng Đạo còn học cả thuật lừa đảo của Lưu Kim Bưu, lừa gạt cả bản thân"},{"chuong":"@c1519","importance":"bridge","mucCt":"gon","text":"Được nhắc đến: Vương Lâm bắt chước thuật lừa đảo của Lưu Kim Bưu để lừa gạt chính bản thân trong bảy mươi năm mộng đạo.","anchor":"do hắn bắt chước thuật lừa đảo của Lưu Kim Bưu để lừa gạt chính bản thân mình"},{"importance":"bridge","mucCt":"vua","chuong":"@c1538","text":"Bị thanh niên tóc bạc gọi tên khi nhận ra Đạo lừa gạt mà Vương Lâm sử dụng có nguồn gốc từ hắn.","anchor":"đây là Đạo lừa gạt của Lưu Kim Bưu"}],"nhanMach":[{"ten":"Pháp Hoa Tử","tag":"dong-minh","quanHe":"Đồng mưu trong kế hoạch lừa Người điên"}],"tuViMoc":[],"tuiDo":{},"diem":[{"text":"Dùng ngọc giản phóng khí tức Toái Niết phá tan hộ sơn đại trận Thiên Cương Tông, tống tiền cả tông môn","chuong":"@c1158"},{"text":"Giả dạng Chu Tước đời thứ sáu lừa lão tổ Hỏa Tước tộc, xâm nhập thánh địa trên Hỏa Tước tinh","chuong":"@c1335"},{"text":"Bị Vương Lâm tước tự do, quỳ dập đầu đến trán đầm đìa máu, bắt đầu làm nô bộc ngàn năm","chuong":"@c1474"},{"text":"Chuyển thế tại Tiên Cương, khôi phục ký ức hai đời và thức tỉnh nhận thức mới về đạo lừa gạt — hiểu lừa mình chính là bước thứ hai","chuong":"@c1848"},{"text":"Con rắn nhỏ Hải Long trên vai khôi phục bản thể, gào rít chặn đứng Xích Hồn Tử tại Tiên giới","chuong":"@c1964"}]},"nguon":["@c1451","@c1472","@c1473","@c1474","@c1514","@c1519","@c1538"],"vaiTro":"Kẻ lừa đảo kỳ cựu — nô bộc ngàn năm của Vương Lâm, người ngộ đạo lừa gạt","tinhCach":"Xảo quyệt, chuyên giả mạo khí tức cường giả để tống tiền tông môn; Tham lợi nhưng biết sợ cường giả, quỳ gối cầu sinh không chút do dự; Dai dẳng theo đuổi đạo lừa gạt đến mức tự lừa chính bản thân, ký ức và nguyên thần cũng bị ảnh hưởng; Linh hoạt nương theo Vương Lâm để sinh tồn, dần chuyển từ kẻ b","blurb":"Lưu Kim Bưu, bí danh Kim Bưu Tử, là tu sĩ tu vi thực chỉ ở tầng Âm Hư nhưng nhờ ngọc giản chứa khí tức Toái Niết mà tung hoành lừa gạt các tông môn, từ Thiên Cương Tông tới Quy Nguyên Tông, cho đến khi bị Vương Lâm truy kích, mất bảo vật, rồi bị tước tự do làm nô bộc ngàn năm. Sau khi chuyển thế tại Tiên Cương dưới danh Kim Bưu đại tiên, lão khôi phục ký ức hai đời, thức tỉnh nhận thức mới về đạo lừa gạt — hiểu rằng lừa mình mới là cảnh giới cao nhất — rồi tiếp tục theo Vương Lâm xuyên suốt hành trình từ Đông Lâm Tông qua Tổ Thành đến Tiên giới, với con rắn nhỏ Hải Long trên vai trở thành vật "},{"id":"viem-loi-tu","name":"Viêm Lôi Tử","cn":"炎雷子","aliases":[],"gioiTinh":"nam","tabs":{"kinhLich":[{"chuong":"@c1452","importance":"normal","mucCt":"ky","tieuDe":"Bị truy sát tại vùng cấm thức, được Vương Lâm cứu","text":"Bị hai tu sĩ Toái Niết giới ngoại (Hỏa Tước tộc và Phụng Thiên Lang tộc) truy sát trong vùng cấm thức gần trung tâm Côn Hư. Phản kích bằng hơn mười mảnh đại lục biến ảo, cho nổ tung để ngăn cản nhưng bản thân trọng thương nặng. Khích bác hai kẻ địch bằng chiến tích Phong Tôn: giết lão tổ Hỏa Tước tộc trước mặt hơn mười vạn tu sĩ, lão tổ Phụng Thiên Lang tộc là nô bộc của Phong Tôn. Bị dồn vào đường cùng, quyết tâm đốt sinh mạng tử chiến. Được Vương Lâm xuất hiện cứu trong gang tấc, vui mừng nhận ra Phong Tôn trở về.","anchor":"Phong Tôn có chết hay không thì các ngươi còn rõ ràng hơn chúng ta"},{"mucCt":"ky","text":"Bị hai tu sĩ Toái Niết giới ngoại truy sát do thương thế từ đại chiến thứ ba khiến tu vi thụt lùi. Được Vương Lâm giết địch cứu mạng. Kích động hành lễ tham kiến Phong Tôn, tự xưng Chỉ huy phó chiến tuyến tây bắc La Thiên, bài danh 53 trên Phong Tôn bảng. Tường thuật chi tiết toàn cảnh ba trận đại chiến giới nội-giới ngoại và tình hình bốn đại tinh vực. Tiết lộ nhiều năm tới nơi này chờ Phong Tôn vì tin hắn chưa chết, đồng thời vâng lệnh Hồng Sam Tử quan sát Thất Thải Giới. Được Vương Lâm dùng kim quang chữa trị — thoát thai hoán cốt, tóc bạc chuyển đen, lão già hóa trung niên, khí tức có dấu hiệu đột phá. Đi theo Vương Lâm hướng tới tổng bộ Tu Chân Liên Minh.","anchor":"Phong Tôn năm đó từng nói sẽ tới nơi này","bridge":true,"khoang":"@c1453"},{"mucCt":"vua","text":"Theo Vương Lâm tới bên ngoài tổng bộ Tu Chân Liên Minh, chứng kiến Vương Lâm phá dòng xoáy phong ấn mà hoảng sợ rồi kích động. Chỉ ra tổng đàn Tu Chân Liên Minh phía trước và xác nhận Trọng Huyền Tử đang ở nơi đó. Nhận diện Thiên Triệu Thượng Sư cho Vương Lâm.","anchor":"Phong Tôn đó chính là tổng đàn của Tu Chân Liên Minh","bridge":true,"khoang":"@c1454"},{"importance":"bridge","mucCt":"gon","chuong":"@c1455","tieuDe":"Chứng kiến vạn tu quỳ phục","text":"Ở phía sau Vương Lâm, cảm nhận cuồng phong ba hắc long cực kỳ kinh khủng, chứng kiến cảnh vạn tu quỳ phục trước kim quang tiên lực, đầu óc trống rỗng ngơ ngác.","anchor":"Cảnh tượng hôm nay khiến hắn không thể tin nổi"},{"mucCt":"vua","text":"Cung kính cung cấp thông tin về tu chân tinh lớn và Long Bàn Tử cho Vương Lâm. Nhận được con hắc long hương hỏa thứ nhất đã phong ấn từ Vương Lâm, kích động vái dài, nhớ lại câu người có duyên từ lần gặp đầu tiên năm xưa. Được giao nhiệm vụ đưa con hắc long thứ hai cho Thân Công Hổ và chiếu cố Thân Công Hổ sau khi trở về La Thiên. Nhận ra Long Bàn Tử khi lão già hư ảo xuất hiện trên đỉnh tu chân tinh, thất thanh kinh hãi. Chứng kiến cảnh tàn sát gần vạn tu sĩ, sinh ra kính sợ sâu đậm hơn với Vương Lâm.","anchor":"Long Bàn Tử này năm đó ta cũng chỉ gặp một lần, vốn tưởng rằng hắn đã chết","bridge":true,"khoang":"@c1456"},{"chuong":"@c1459","importance":"bridge","mucCt":"gon","text":"Đứng phía sau Vương Lâm, ánh mắt lộ vẻ thù hận khi nghe Trọng Huyền Tử đổ lỗi cho Thanh Thủy Tiên Quân phá phong ấn.","anchor":"Viêm Lôi Tử ở phía sau hắn ánh mắt lộ ra một vẻ thù hận"},{"mucCt":"ky","text":"Nhìn theo hướng Trọng Huyền Tử rời đi với ánh mắt đầy thù hận. Hồi tưởng: vốn là đạo hữu chí cốt với Trọng Huyền Tử, ba người thường xuyên luận đạo, hắn cùng đạo lữ theo yêu cầu Trọng Huyền Tử gia nhập tu chân Liên Minh, rất đồng tình cam tâm nghe lệnh. Nhưng một sự việc bí ẩn đã khiến mọi thứ thay đổi hoàn toàn, biến thành thù hận sâu như biển, ký ức như cái gai đâm sâu vào da thịt không thể rút ra. Nói rõ với Vương Lâm rằng mối thù với Trọng Huyền Tử là việc riêng, Phong Tôn không nên để trong lòng, lấy đại cục làm trọng, nếu cả hai sống sót sau trận chiến sẽ báo thù. Gật đầu từ biệt rồi rời đi, bóng lưng trùng xuống lộ vẻ già nua, hiu quạnh, cô độc.","anchor":"Hẳn cùng với Trọng Huyền Tử vốn là đạo hữu chí cốt","bridge":true,"khoang":"@c1460"},{"chuong":"@c1559","importance":"bridge","mucCt":"vua","text":"Ở hướng tây cùng tu sĩ La Thiên, tuyên bố khi màn sáng sụp đổ sẽ tự bạo.","anchor":"Lúc màn sáng sụp đổ, đó là khoảnh khắc ta tự bạo"}],"tuViMoc":[],"nhanMach":[{"ten":"Trọng Huyền Tử","tag":"doi-thu","quanHe":"Cựu đạo hữu chí cốt, nay thù địch","ghiChu":"Vốn là bạn thân luận đạo, theo yêu cầu Trọng Huyền Tử gia nhập Liên Minh, nhưng vì một sự việc bí ẩn mà trở thành thù hận sâu như biển"},{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Được Vương Lâm cứu mạng tại vùng cấm thức Côn Hư","ghiChu":"@c1452"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Kích hoạt Lôi Tiên Đại Trận luyện hóa tiên giới, triệu hồi nguyên thần các cấp thiên tiên, tiên vương và Tiên Quân quy vị vào trận","chuong":"@c0745"},{"text":"Chủ trì nghi thức Phong Tiên: phong Hứa Mộc làm Chính phẩm Lôi tiên, hiến tinh huyết nguyên thần phá bức tường không gian mở thông đạo tới Liên Minh Tinh Vực","chuong":"@c0828"},{"text":"Bộc lộ tu vi thật vượt Toái Niết hậu kỳ trong trận chiến với Cực Hiền Thiên ở phía Bắc Liên Minh","chuong":"@c0864"},{"text":"Giao chiến một ngày với thượng cổ tu sĩ áo đỏ chưa phân thắng bại, sau đó bị dư uy Diệt Thần Mâu trọng thương nặng, được Lỗ Phu Tử cứu","chuong":"@c1066"},{"text":"Tiết lộ bản thân từng là trưởng lão Tu Chân Liên Minh trước khi gia nhập La Thiên, mang mối thù truyền kiếp với Trọng Huyền Tử vốn là đạo hữu chí cốt","chuong":"@c1408"},{"text":"Bị tu sĩ Toái Niết giới ngoại truy sát do thương thế khiến tu vi thụt lùi, được Vương Lâm cứu thoát","chuong":"@c1452"}]},"canhGioiCaoNhat":"Toái Niết đại viên mãn","nguon":["@c1452","@c1453","@c1454","@c1455","@c1456","@c1459","@c1460","@c1559"],"trangThai":"song","vaiTro":"Điện chủ Lôi Tiên Điện — chỉ huy cấp cao La Thiên, cựu trưởng lão Tu Chân Liên Minh","tinhCach":"trọng dụng nhân tài, sẵn sàng chấp nhận tổn thất để chiêu nạp cao thủ; quyết đoán trong đại cục, dám hiến tinh huyết nguyên thần mở thông đạo; bình tĩnh trước chất vấn và biến cố bất ngờ; mang mối thù truyền kiếp với Tu Chân Liên Minh, không chịu dừng tay khi chiến sự chưa ngã ngũ","blurb":"Viêm Lôi Tử là Điện chủ Lôi Tiên Điện, một trong những nhân vật chỉ huy then chốt của La Thiên trong cuộc đại chiến với Tu Chân Liên Minh. Vốn từng là trưởng lão Tu Chân Liên Minh trước khi gia nhập La Thiên, ông sở hữu tu vi vượt Toái Niết hậu kỳ, từng kích hoạt Lôi Tiên Đại Trận luyện hóa tiên giới, chủ trì nghi thức Phong Tiên phong Hứa Mộc làm Chính phẩm Lôi tiên, hiến tinh huyết nguyên thần phá bức tường không gian mở thông đạo tới Liên Minh Tinh Vực, rồi trực tiếp giao chiến với các đại tu sĩ hàng đầu như Cực Hiền Thiên, Võ Đông Thiện và thượng cổ tu sĩ áo đỏ. Trải qua đại chiến thứ ba v"},{"id":"lo-phu-tu","name":"Lỗ Phu Tử","cn":"鲁夫子","aliases":[],"gioiTinh":"nam","tabs":{"kinhLich":[{"chuong":"@c1452","importance":"bridge","mucCt":"gon","text":"Đang bố trí trận pháp thượng cổ bên ngoài Côn Hư theo lệnh Hồng Sam Tử, thoáng cảm nhận khí tức quen thuộc khi Vương Lâm lướt qua nhưng cho rằng mình hoa mắt.","anchor":"Khí tức này rất giống của hắn"},{"chuong":"@c1520","importance":"normal","mucCt":"ky","tieuDe":"Ở lại Côn Hư tử chiến, đấu Chu Cẩn","text":"La Thiên Lão tổ, không rút về La Thiên mà chọn ở lại Côn Hư tử chiến, muốn chết trong chiến trận. Đang giằng co với Chu Cẩn ở tinh không bên trái Chu Tước Tinh. Khi Không Môn hiện, tuyệt vọng.","anchor":"Lão phu muốn chết trong chiến trận"},{"chuong":"@c1521","importance":"bridge","mucCt":"gon","text":"Tham gia phản công giới ngoại, bị sương mù tím quét trúng phun máu sụp đổ, được Long Bàn Tử cuốn rút vào Chu Tước Tinh.","anchor":"Tư Đồ Nam, Long Bàn Tử, Lỗ Phu Tử đều đồng loạt lao tới, trong tiếng ầm vang tiến"},{"chuong":"@c1523","importance":"bridge","mucCt":"gon","text":"Thân thể chấn động kích động khi cảm nhận khí tức Phong Tôn trở về.","anchor":"Lỗ Phu Tử, còn có Thanh Long Thánh Hoàng thần sắc mệt mỏi kia lúc này toàn bộ đều thân thể chấn động"},{"chuong":"@c1524","importance":"bridge","mucCt":"gon","text":"Chăm chú nhìn Vương Lâm mở Không Môn, thần sắc lo lắng.","anchor":"đều chăm chú nhìn, thần sắc lộ ra vẻ lo lắng"}],"tuViMoc":[],"nhanMach":[{"ten":"Chu Cẩn","tag":"doi-thu","quanHe":"Giằng co chiến đấu ở tinh không bên trái Chu Tước Tinh"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Hoảng sợ trốn chạy khi Thác Sâm xuất hiện, rút vào tinh không không dám giao chiến","chuong":"@c1147"},{"text":"Bừng tỉnh từ nhập định khi cảm nhận khí thế Vương Lâm xuất hiện tại La Thiên, lộ diện trên Hoành Vân Sơn sau khi Vương Lâm rời đi","chuong":"@c1386"},{"text":"Đấu văn ba hiệp với Vương Lâm, luyện thành La Thiên Thụ được vạn tu sĩ tung hô, nhưng ý chí kháng cự sụp đổ hoàn toàn trước thực lực áp đảo của Vương Lâm, thừa nhận bại trận và hòa giải","chuong":"@c1401"},{"text":"Tiết lộ mối đe dọa chiến tranh giới ngoại cho Vương Lâm, nhắc lại ân nghĩa năm xưa với Chiến Tinh Dã — lý do nhận Liệt Vân Tử làm đệ tử","chuong":"@c1407"},{"text":"Dẫn đầu tu sĩ La Thiên chi viện giới nội, phối hợp giáp công hàn giới ngoại cùng Triệu Hà và Hồng Sam Tử","chuong":"@c1434"},{"text":"Chọn ở lại Côn Hư tử chiến thay vì rút về La Thiên, bị sương mù tím quét trúng trọng thương, được Long Bàn Tử cứu rút vào Chu Tước tinh","chuong":"@c1520"}]},"nguon":["@c1452","@c1520","@c1521","@c1523","@c1524"],"trangThai":"song","vaiTro":"Cường giả mạnh nhất La Thiên tinh vực — tu vi Không Niết Sơ Kỳ bước thứ ba","tinhCach":"Thận trọng, tránh đối đầu trực diện khi chưa nắm chắc phần thắng; biết tiến biết lui, chấp nhận bại trận trước kẻ mạnh hơn; trọng nhân quả và ân nghĩa cũ; sẵn sàng xả thân tử chiến khi đại cuộc lâm nguy","blurb":"Lỗ Phu Tử là cường giả được vạn tu sĩ La Thiên tôn sùng, tu vi Không Niết Sơ Kỳ bước thứ ba, lâu nay ẩn mình chữa thương trong tinh trận tây bắc La Thiên. Từng hoảng sợ trốn chạy khi Thác Sâm xuất hiện, về sau đối đầu Vương Lâm qua ba hiệp đấu văn, luyện thành La Thiên Thụ rồi thừa nhận bại trận và hòa giải, tiết lộ mối đe dọa chiến tranh giới ngoại. Sau đó dẫn đầu tu sĩ La Thiên chi viện giới nội, chọn ở lại Côn Hư tử chiến thay vì rút lui, bị trọng thương trong trận phản công và được cứu rút vào Chu Tước tinh."},{"id":"tu-si-hoa-tuoc-toc","name":"Tu sĩ Hỏa Tước tộc","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thái Cổ Tinh Thần","trangThai":"gan-bo"},{"ten":"Hỏa Tước tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Toái Niết đại viên mãn","trangThai":"song","blurb":"Tu sĩ thuộc Hỏa Tước tộc của Thái Cổ Tinh Thần, tu vi Toái Niết đại viên mãn, cùng tu sĩ Phụng Thiên Lang tộc truy sát Viêm Lôi Tử trong vùng cấm thức Côn Hư. Thi triển biển lửa từ mi tâm và hỏa linh giao chiến, nhưng sau đó bị Vương Lâm dùng kim quang tiêu diệt, thân thể hóa mây khói, nguyên thần tan nát tử vong.","vaiTro":"Tu sĩ giới ngoại thuộc Hỏa Tước tộc, truy sát Viêm Lôi Tử trong vùng cấm thức","tinhCach":"Kiêu ngạo, khinh thường giới nội; sợ hãi trước cường giả thật sự","tabs":{"diem":[{"text":"Cùng tu sĩ Phụng Thiên Lang tộc truy sát Viêm Lôi Tử, thi triển biển lửa từ mi tâm và hỏa linh giao chiến trong vùng cấm thức","chuong":"@c1452"},{"text":"Bị Vương Lâm dùng kim quang tiêu diệt, thân thể hóa mây khói, nguyên thần tan nát tử vong","chuong":"@c1453"}],"kinhLich":[{"chuong":"@c1452","importance":"normal","mucCt":"vua","tieuDe":"Truy sát Viêm Lôi Tử, đối mặt Phong Tôn","text":"Cùng tu sĩ Phụng Thiên Lang tộc truy sát Viêm Lôi Tử trong vùng cấm thức, thi triển biển lửa từ mi tâm và hỏa điểu đen. Chế giễu Phong Tôn đã chết, bị Viêm Lôi Tử khích bác về việc lão tổ Hỏa Tước tộc bị Phong Tôn giết. Cuối cùng bị kim quang vạn trượng của Vương Lâm khiến tê dại, kinh hãi gọi tên Phong Tôn.","anchor":"chém chết hắn trước mặt hơn mười vạn tu sĩ giới ngoại"},{"chuong":"@c1453","importance":"major","mucCt":"gon","tieuDe":"Bị Vương Lâm tiêu diệt","text":"Bị kim quang Vương Lâm tràn ngập, thân thể hóa mây khói, nguyên thần tan nát tử vong.","anchor":"thân thể hắn liền biến thành mây khói, nguyên thần cũng không có chút chống cự"}],"tuViMoc":[],"nhanMach":[{"ten":"Viêm Lôi Tử","tag":"doi-thu","quanHe":"Mục tiêu truy sát","ghiChu":"Cùng tu sĩ Phụng Thiên Lang tộc truy kích trong vùng cấm thức @c1452"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Bị uy áp","ghiChu":"Kinh hãi trước sự tái xuất của Phong Tôn @c1452"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1452","@c1453"]},{"id":"tu-si-phung-thien-lang-toc","name":"Tu sĩ Phụng Thiên Lang tộc","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thái Cổ Tinh Thần","trangThai":"gan-bo"},{"ten":"Phụng Thiên Lang tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Toái Niết đại viên mãn","trangThai":"song","blurb":"Tu sĩ Phụng Thiên Lang tộc thuộc Thái Cổ Tinh Thần, tu vi Toái Niết đại viên mãn, cùng tu sĩ Hỏa Tước tộc truy kích Viêm Lôi Tử. Tiết lộ ước định tạm hoãn giao chiến giữa Thiên Triệu Thượng Sư và giới nội.","vaiTro":"Tu sĩ giới ngoại truy sát Viêm Lôi Tử, tiết lộ tình hình chiến cục","tinhCach":"Kiêu ngạo; hay chế nhạo; khinh thường Phong Tôn trước khi gặp mặt","tabs":{"diem":[{"text":"Tiết lộ ước định tạm hoãn giao chiến giữa phó hội trưởng Trường Tôn hội Thiên Triệu Thượng Sư và giới nội","chuong":"@c1452"},{"text":"Thi triển huyễn hóa cánh tay mọc lông xanh hóa thành cự lang tấn công","chuong":"@c1452"},{"text":"Từng sống sót qua búa Phong Tôn tại lỗ hổng Phong Giới Đại Trận, ám ảnh nỗi sợ suốt vài thập niên","chuong":"@c1453"},{"text":"Toái Niết đại viên mãn thuộc Thái Cổ Tinh Thần, huyễn hóa cánh tay mọc lông xanh thành cự lang tấn công","chuong":"@c1452"}],"kinhLich":[{"chuong":"@c1452","importance":"normal","mucCt":"vua","tieuDe":"Truy sát Viêm Lôi Tử, bị Phong Tôn uy áp","text":"Cùng tu sĩ Hỏa Tước tộc truy kích Viêm Lôi Tử, thi triển huyễn hóa cánh tay mọc lông xanh hóa thành cự lang tấn công. Tiết lộ ước định tạm hoãn giao chiến giữa Thiên Triệu Thượng Sư và giới nội, chế nhạo Phong Tôn đã chết. Bị kim quang Vương Lâm khiến kinh hãi.","anchor":"Lão phu thấy hắn chẳng qua chỉ là một thằng nhãi ranh"},{"chuong":"@c1453","importance":"normal","mucCt":"vua","tieuDe":"Phát điên tiêu tan trước Vương Lâm","text":"Nhìn thấy lại thân ảnh Vương Lâm, nhớ lại hình ảnh năm xưa Phong Tôn cầm búa đứng ở lỗ hổng Phong Giới Đại Trận cản mấy vạn tu sĩ. Nỗi sợ vài thập niên bùng phát khiến hắn phát điên hoàn toàn, da thịt bị hòa tan, tiêu tan trong kim quang.","anchor":"hắn quên cả lùi lại phía sau, da thịt trên thân thể lập tức bị hòa tan"}],"tuViMoc":[],"nhanMach":[{"ten":"Viêm Lôi Tử","tag":"doi-thu","quanHe":"Mục tiêu truy sát","ghiChu":"Cùng tu sĩ Hỏa Tước tộc truy kích @c1452"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Bị uy áp","ghiChu":"Kinh hãi trước Phong Tôn tái xuất @c1452"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1452","@c1453"]},{"id":"hong-sam-tu","name":"Hồng Sam Tử","cn":"洪三子","aliases":[],"gioiTinh":"nam","tabs":{"kinhLich":[{"chuong":"@c1453","importance":"normal","mucCt":"vua","tieuDe":"Bị phong ấn vây trong Thất Thải Giới","text":"Trong đại chiến thứ hai bị hàn y đồng tử và tu sĩ bước thứ ba giới ngoại liên thủ phong ấn, vây trong Thất Thải Giới ở Triệu Hà, bị ba vạn tu sĩ trấn áp. Hiện chỉ còn phân thân chiến đấu trên đài phong giới. Nhiều lần cố hủy hai Thất Thải Giới còn lại nhưng thất bại.","anchor":"Hồng Sam Tử tiền bối trong trận đại chiến lần thứ hai bị hàn y đồng tử và tu sĩ bước thứ ba giới ngoại liên thủ phong ấn"},{"chuong":"@c1468","importance":"normal","mucCt":"gon","tieuDe":"Bổn tôn bị phong ấn tại Thất Thải Giới Triệu Hà","text":"Bổn tôn bị phong ấn tại Thất Thải Giới cuối cùng ở Triệu Hà, Vương Lâm và Thanh Thủy lao tới nơi này.","anchor":"Nơi này chính là nơi bổn tôn của Hồng Sam Tử bị phong ấn!"},{"chuong":"@c1469","importance":"normal","mucCt":"vua","tieuDe":"Bị đạo quả luyện hóa, được Vương Lâm cứu","text":"Bổn tôn bị giam trong đạo quả, toàn thân phát hồng mang, không có Thiên Nghịch nên không thể hấp thu đạo niệm hỗn tạp, đang bị sợi tơ hấp thu dưỡng chất, kết cục chỉ có tử vong. Khi Vương Lâm công kích đạo quả, sợi tơ truyền lực khiến càng thống khổ. Cuối cùng được Vương Lâm dùng ánh sáng nhu hòa xuyên vào cứu ra, sợi tơ tan vỡ, tỉnh lại.","anchor":"Đồng tử này chính là bổn tôn của Hồng Sam Tử"},{"mucCt":"vua","text":"Hồi phục sau trận chiến, sương máu hóa áo đỏ trên người. Hóa hồng ảnh tấn công Tần Cửu Duyên, bắt sống giam cầm mang đi, tuyên bố sẽ luyện thành huyết thân phục vụ giới nội. Giúp Long Bàn Tử dập tắt linh hồn bị thiêu đốt. Tuyên bố trước tu sĩ giới nội rằng Phong Tôn đã trở lại, giao Vương Lâm chủ huy chiến trường Vân Hải.","anchor":"Tần Cửu Duyên, cho dù ngươi có thiêu đốt tu vi, hôm nay ngươi có chạy đằng trời","bridge":true,"khoang":"@c1470"},{"importance":"bridge","mucCt":"gon","chuong":"@c1492","text":"Đang luyện hóa hồn phách tu sĩ giới ngoại bắt từ Triệu Hà tại Vân Hải tinh vực, phát hiện chuyện kỳ quái, cảm ứng phong ấn bị phá liền thu hồn phách lao đi.","anchor":"Hồng Sam Tử hầu như không chút do dự, thu hồi hồn phách đang luyện hóa"},{"chuong":"@c1494","importance":"minor","mucCt":"gon","text":"Xuất hiện tại tinh không Chu Tước Tinh, mắt lộ bi ai, khẳng định Vương Lâm sẽ không chết.","anchor":"Hắn sẽ không chết đâu"},{"chuong":"@c1540","importance":"bridge","mucCt":"gon","text":"Được Vương Lâm tìm thấy và thu hồi vận mệnh trong mặt trời thứ chín.","anchor":"Hắn tìm ấy Thập Tam, tìm thấy đầu to, tìm được Chu Dật"},{"mucCt":"ky","text":"Ngồi phía sau Thanh Thủy trong tế đàn, hai tay bắt quyết trợ giúp bức bảy luồng hắc khí. Cảnh báo không giúp thì Thanh Thủy không sống nổi ba khắc. Bị Thanh Thủy hai lần quát không cần quản. Phóng một con rối hắc quang ra ngoài trận. Cuối cùng bi ai rời đi, kiên quyết ra ngoài đối mặt bà lão bước thứ ba giới ngoại.","anchor":"Ta nếu không giúp ngươi thì không tới ba khắc ngươi sẽ tử vong","bridge":true,"khoang":"@c1559"},{"importance":"bridge","mucCt":"gon","chuong":"@c1560","text":"Đang giao chiến với bậc toàn năng Không Huyền giới ngoại bên ngoài tinh trận, gặp nguy cơ sinh tử lớn nhất, đồng thời là mục tiêu chưởng ấn bổn tôn Chưởng Tôn.","anchor":"Thanh Lâm. nữ tử của Triệu Hà, Hồng Sam Tử đang giao chiến với bậc toàn năng Không Huyền của giới ngoại cũng gặp phải nguy cơ sinh tử lớn nhất trong đời"},{"chuong":"@c1561","importance":"bridge","mucCt":"gon","text":"Hoàn toàn ngẩn ra trước sự xuất hiện của Vương Lâm, không ngờ hắn còn sống và tu vi đạt tầm này.","anchor":"Hồng Sam Tử hoàn toàn ngẩn ra"},{"chuong":"@c1563","importance":"bridge","mucCt":"gon","text":"Cùng xông ra từ tinh trận tham gia quyết chiến với tu sĩ giới ngoại.","anchor":"Cùng nhau lao ra còn có Thanh Lâm, Hồng Sam Tử"},{"chuong":"@c1564","importance":"bridge","mucCt":"gon","text":"Đang gắng gượng chặn tiên phi cuối cùng, rõ ràng không phải địch thủ, sau đó nhận lệnh Vương Lâm liên thủ ba người chặn hai Không Huyền.","anchor":"Hồng Sam Tử rõ ràng không phải là địch thủ của nàng, đang gắng gượng ngăn cản đối phương"},{"chuong":"@c1565","importance":"bridge","mucCt":"gon","text":"Cùng Thanh Lâm, nữ tử Triệu Hà, Thanh Thủy xuất nguyên thần đẩy bánh xe quay vòng thứ ba.","anchor":"Cùng lúc đó Hồng Sam Tử và nữ tử của Triệu Hà kia cũng đồng thời nhắm hai mắt, nguyên thần tràn ra"},{"chuong":"@c1571","importance":"bridge","mucCt":"gon","text":"Được nhắc tên cùng Nam Vân Tử và Tư Đồ Nam khi đồng loạt đứng dậy vái lạy anh hồn tại La Thiên Tinh Vực.","anchor":"Nam Vân Tử, Tư Đồ Nam, Hồng Sam Tử, tất cả tu sĩ đều không hề có ngoại lệ"}],"tuViMoc":[],"nhanMach":[{"ten":"Thanh Thủy","tag":"dong-minh","quanHe":"Trợ giúp bức hắc khí, bị Thanh Thủy quát đuổi"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Được chủ nhân Phong Giới nhắc tên, lệnh Huyền Bỉnh đi tìm để thông báo ước định hợp nhất Tứ Đại Tiên Giới","chuong":"@c1233"},{"text":"Dẫn mấy vạn tu sĩ Vân Hải từ tinh không bất ngờ xuất hiện tiếp viện giới nội trong đại chiến","chuong":"@c1425"},{"text":"Lộ danh hiệu Huyết Sam Đồng Tử, phá sát giới mấy vạn năm, một mình đối đầu nhiều cao thủ bước thứ ba giới ngoại","chuong":"@c1427"},{"text":"Bị phong ấn tại Thất Thải Giới trong đại chiến thứ hai, sau đó được Vương Lâm giải cứu khỏi đạo quả giam cầm","chuong":"@c1469"},{"text":"Chọn chuyển thế đầu thai, sau đó được Vương Lâm dùng tinh quang điểm mi tâm khôi phục ký ức kiếp trước","chuong":"@c1959"}]},"nguon":["@c1452","@c1453","@c1468","@c1469","@c1470","@c1492","@c1494","@c1540","@c1559","@c1560","@c1561","@c1563","@c1564","@c1565","@c1571"],"trangThai":"song","vaiTro":"Cường giả Vân Hải tinh vực — người được ủy thác ước định hợp nhất Tứ Đại Tiên Giới","tinhCach":"Dũng mãnh không sợ chết, sẵn sàng xả thân vì đại cục; quyết đoán trên chiến trường, không lùi dù đối mặt cường địch áp đảo; trọng nghĩa khí, giữ sát giới mấy vạn năm nhưng phá giới khi cần; trung thành tận tụy, hết lòng phò tá Vương Lâm trong mọi trận quyết chiến","blurb":"Hồng Sam Tử, biệt hiệu Huyết Sam Đồng Tử, là cường giả Không Huyền Trung Kỳ trú tại tầng thứ nhất Vân Hải tinh vực, một trong những người được chủ nhân Phong Giới ủy thác ước định hợp nhất Tứ Đại Tiên Giới. Khi Phong Giới Đại Trận hiện hình và chiến tranh giới nội–giới ngoại bùng nổ, Hồng Sam Tử dẫn mấy vạn tu sĩ Vân Hải tiếp viện, một mình đối đầu nhiều cao thủ bước thứ ba, phá sát giới mấy vạn năm để chiến đấu, đóng vai trò then chốt trong nhiều trận quyết chiến bảo vệ giới nội. Sau đại chiến thứ hai bị phong ấn tại Thất Thải Giới, được Vương Lâm giải cứu, tiếp tục tham chiến trong các trận ","canhGioiCaoNhat":"Không rõ","theLuc":[{"ten":"La Thiên Tinh Vực","trangThai":"gan-bo"}]},{"id":"nam-van-tu","name":"Nam Vân Tử","cn":"南云子","aliases":[],"gioiTinh":"nam","tabs":{"kinhLich":[{"mucCt":"gon","text":"Bị Chưởng Tôn đánh trọng thương bế quan, cho tới nay vẫn chưa xuất quan.","anchor":"Nam Vân Tử tiền bối bị Chưởng Tôn đánh trọng thương bế quan","bridge":true,"khoang":"@c1453"},{"importance":"bridge","mucCt":"gon","chuong":"@c1492","text":"Đang tế luyện trận kỳ ở khu vực Thi Âm Tông tại Côn Hư, nhận ra khí tức Thái cổ Tinh Thần đang vây khốn Phong Tôn, lập tức lao đi.","anchor":"Nam Vân Tử đột nhiên ngẩng phắt đầu thần sắc kịch biến, đã nhận ra khí tức của Thái cổ Tinh Thần"},{"chuong":"@c1494","importance":"minor","mucCt":"gon","text":"Cùng Hồng Sam Tử và Thanh Lâm xuất hiện tại tinh không Chu Tước Tinh, quét thần thức tìm Vương Lâm nhưng không cảm nhận được khí tức.","anchor":"Bọn họ không cảm thấy khí tức của Vương Lâm. Giống như năm đó Vương Lâm mất tích, giống như đã tử vong"},{"chuong":"@c1520","importance":"normal","mucCt":"vua","tieuDe":"Cầm đầu quân giới nội tử chiến Chu Tước Tinh","text":"Cầm đầu lực lượng cuối cùng giới nội tại Côn Hư tinh vực, dẫn chưa đầy tám ngàn tu sĩ quyết tử chiến bên ngoài Chu Tước Tinh, không muốn rút về La Thiên.","anchor":"tại Côn Hư tinh vực do Nam Vân Tử cầm đầu, đang ở bên ngoài Chu Tước Tinh này quyết một trận tử chiến"},{"mucCt":"vua","text":"Nhận định giá trị ba rồi bốn đạo bổn nguyên, nắm thời cơ tu sĩ giới ngoại bị không môn làm rung động tâm thần, ra lệnh Côn Hư phản công. Đang giao chiến thì bị sương mù tím va chạm, vốn đã bị thương nay phun máu bắn về phía Chu Tước Tinh, hét tên Thái Cổ Ngũ Tôn và ra lệnh toàn bộ rút về Chu Tước Tinh dùng trận pháp đối kháng.","anchor":"Thái cổ ngũ tôn! Mau lui lại Chu Tước Tinh dùng trận pháp đối kháng!","bridge":true,"khoang":"@c1521"},{"chuong":"@c1523","importance":"bridge","mucCt":"gon","text":"Cười ha hả khi nhận ra Phong Tôn lấy sáu đạo bổn nguyên dẫn động Không Môn.","anchor":"Uy lực của Phong Tôn, sao có thể chết được!"},{"chuong":"@c1524","importance":"bridge","mucCt":"gon","text":"Quyết định tới thời điểm mấu chốt sẽ dốc hết toàn lực trợ giúp Vương Lâm mở Không Môn.","anchor":"sẽ dốc hết toàn lực để trợ giúp cho Vương Lâm"},{"mucCt":"vua","text":"Nhận ra cửa thứ sáu là Vạn Không Cốt Môn. Dẫn lời Phong Tôn đời trước rằng cửa không phải của Phong Giới mà hiện ở quê hương của Phong Tôn, mắt lộ vẻ khó tin.","anchor":"Nam Vân Tử nhìn cánh cửa quỷ dị kia, trong mắt lộ ra vẻ khó tin","bridge":true,"khoang":"@c1526"},{"chuong":"@c1527","importance":"bridge","mucCt":"gon","text":"Định lao tới ngăn ba địch thủ tấn công Vương Lâm lúc dung hợp bổn nguyên nhưng bị một câu của Vương Lâm chặn lại.","anchor":"Hành động của ba người khiến cho đám người Nam Vân Tử lập tức thân thể nhoáng lên"},{"importance":"bridge","mucCt":"vua","chuong":"@c1529","text":"Chứng kiến uy lực Vạn Không Cốt Môn và mũi tên của Vương Lâm, xúc động gọi Phong Tôn là hy vọng cho cuộc chiến của giới nội.","anchor":"Đây mới là Phong Tôn, là hi vọng cho cuộc chiến của giới nội ta"},{"mucCt":"vua","text":"Nhận ra tiếng gào là thiên kiếp, ra lệnh mấy ngàn tu sĩ giới nội lùi lại hộ pháp từ ngoài. Giải thích nghịch tu thành đạo sẽ có thiên kiếp và nhận định nếu Vương Lâm vượt qua sẽ thành người đứng đầu tu sĩ giới nội.","anchor":"Phong Tôn độ kiếp, chúng ta hãy chờ ở ngoài hộ pháp","bridge":true,"khoang":"@c1531"},{"chuong":"@c1534","importance":"bridge","mucCt":"vua","text":"Lo lắng trước sự yên tĩnh sau khi Trấn Tiên bảo tháp trấn áp Vương Lâm, nhưng ngăn Tư Đồ Nam xông vào sương mù, cho rằng can thiệp vào Phong Tôn độ kiếp chỉ khiến hắn phân tâm.","anchor":"Phong Tôn độ kiếp, chúng ta không nên xen vào"},{"chuong":"@c1535","importance":"bridge","mucCt":"vua","text":"Cảm nhận uy áp của pháp bảo thứ ba liền biến sắc lùi mấy trăm trượng, nhận ra uy áp là khí tức pháp bảo chứ không phải do tu sĩ phát ra.","anchor":"Với tu vi của hắn có thể cảm nhận được uy áp này không phải là do tu sĩ truyền ra mà là khí tức của Pháp Bảo"},{"chuong":"@c1540","importance":"normal","mucCt":"gon","text":"Được Vương Lâm tìm thấy và thu hồi vận mệnh trong mặt trời thứ chín.","anchor":"Hắn tìm ấy Thập Tam, tìm thấy đầu to, tìm được Chu Dật"},{"chuong":"@c1553","importance":"bridge","mucCt":"gon","text":"Theo sát Vương Lâm khi xuất chinh, với tư cách tiền bối trong đoàn tu sĩ giới nội.","anchor":"còn có Nam Vân Tử tiền bối"},{"chuong":"@c1571","importance":"bridge","mucCt":"gon","text":"Được nhắc tên cùng Tư Đồ Nam và Hồng Sam Tử khi đồng loạt đứng dậy vái lạy anh hồn tại La Thiên Tinh Vực.","anchor":"Nam Vân Tử, Tư Đồ Nam, Hồng Sam Tử, tất cả tu sĩ đều không hề có ngoại lệ"}],"tuViMoc":[],"nhanMach":[{"ten":"Chưởng Tôn","tag":"doi-thu","quanHe":"Bị Chưởng Tôn đánh trọng thương","ghiChu":""}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Được chủ nhân Phong Giới chọn làm một trong ba người giữ ước định hợp nhất Tứ Đại Tiên Giới","chuong":"@c1233"},{"text":"Xung trận bảo vệ Vân Hải, đồng thời đảm nhận sửa chữa Phong Giới Đại Trận trong đại chiến giới nội – giới ngoại","chuong":"@c1427"},{"text":"Ngưng tụ hư ảnh trận pháp khổng lồ phối hợp tấn công kẻ địch, thể hiện trình độ trận pháp cao thâm","chuong":"@c1438"},{"text":"Cầm đầu chưa đầy tám ngàn tu sĩ giới nội quyết tử chiến bên ngoài Chu Tước Tinh, trợ giúp Vương Lâm mở Không Môn","chuong":"@c1520"},{"text":"Chọn ở lại tân Tiên Giới trấn giữ, thân thể bị đánh tan vỡ chỉ còn nguyên thần","chuong":"@c1961"},{"text":"Được Vương Lâm dùng sức mạnh thiên địa ngưng tụ thân thể mới từ nguyên thần","chuong":"@c1964"}]},"nguon":["@c1452","@c1453","@c1492","@c1494","@c1520","@c1521","@c1523","@c1524","@c1526","@c1527","@c1529","@c1531","@c1534","@c1535","@c1540","@c1553","@c1571"],"canhGioiCaoNhat":"Không rõ","trangThai":"song","vaiTro":"Tu sĩ Thi Âm Tông (Liên Minh Tinh Vực) — người giữ ước định hợp nhất Tứ Đại Tiên Giới, tinh thông trận pháp","tinhCach":"Trọng nghĩa khí, cả đời ít nói nhưng quyết báo đáp ân tình Phong Tôn; kiên định không lùi bước trước kẻ địch mạnh; tinh thông trận pháp, hành sự cẩn trọng; có tầm nhìn đại cục, biết nắm thời cơ chỉ huy chiến trường","blurb":"Nam Vân Tử là tu sĩ thuộc Thi Âm Tông của Liên Minh Tinh Vực, một trong ba người ở ba tinh vực được chủ nhân Phong Giới giao ước định hợp nhất Tứ Đại Tiên Giới Phong Vũ Lôi Điện. Trong đại chiến giới nội – giới ngoại, ông vừa xung trận bảo vệ Vân Hải, vừa đảm nhận sửa chữa Phong Giới Đại Trận và ngưng tụ hư ảnh trận pháp khổng lồ tấn công kẻ địch; sau khi bị Chưởng Tôn đánh trọng thương bế quan rồi phục hồi, ông cầm đầu lực lượng chưa đầy tám ngàn tu sĩ giới nội quyết tử chiến tại Chu Tước Tinh, dốc toàn lực trợ giúp Vương Lâm mở Không Môn, và tiếp tục theo sát Vương Lâm xuất chinh. Về sau ông","theLuc":[{"ten":"La Thiên Tinh Vực","trangThai":"gan-bo"}]},{"id":"thien-trieu-thuong-su","name":"Thiên Triệu Thượng Sư","cn":"天召上师","aliases":["Phó hội trưởng Trường Tôn hội"],"gioiTinh":"nam","theLuc":[{"ten":"Trường Tôn hội","trangThai":"gan-bo"}],"trangThai":"khong-ro","blurb":"Thiên Triệu Thượng Sư là phó hội trưởng Trường Tôn hội, tu sĩ Không Linh sơ kỳ có hương hỏa lực, đóng trong Thất Thải Giới tại tổng bộ Tu Chân Liên Minh. Nghênh chiến Vương Lâm nhưng bị giết — nguyên thần tiêu tán, sau đó hồn bị phong ấn trong Thiên Hoàng Lô và bị Vương Lâm lôi ra dung hợp vào ký hiệu trên mũi tên.","vaiTro":"Phó hội trưởng Trường Tôn hội — tu sĩ Không Linh giới ngoại đóng tại tổng bộ Tu Chân Liên Minh","tinhCach":"Ngoài mặt ngông cuồng nhưng nội tâm khiếp nhược; hư trương thanh thế để che giấu sợ hãi","tabs":{"diem":[{"text":"Tu sĩ Không Linh sơ kỳ có hương hỏa lực, đóng trong Thất Thải Giới ở tổng bộ Tu Chân Liên Minh","chuong":"@c1453"},{"text":"Xuất hiện nghênh chiến Vương Lâm, khiến hơn vạn tu sĩ giới ngoại phấn chấn","chuong":"@c1454"},{"text":"Bị Vương Lâm giết — nguyên thần tiêu tán; nội tâm khiếp hãi nhưng cố tỏ ra ngông cuồng","chuong":"@c1455"},{"text":"Hồn bị phong ấn trong Thiên Hoàng Lô, bị Vương Lâm lôi ra dung hợp vào ký hiệu trên mũi tên","chuong":"@c1482"}],"kinhLich":[{"chuong":"@c1453","importance":"bridge","mucCt":"gon","tieuDe":"","text":"Được Viêm Lôi Tử nhắc tới: đóng trong Thất Thải Giới ở tổng bộ Tu Chân Liên Minh, Vương Lâm đang tiến tới đối đầu.","anchor":"bên trong có Thiên Triệu Thượng Sư - Phó hội trưởng Trường Tôn hội"},{"importance":"normal","mucCt":"ky","chuong":"@c1454","tieuDe":"Nghênh chiến Vương Lâm tại tổng bộ Tu Chân Liên Minh","text":"Xuất hiện từ tu chân tinh trong đám sương mù đen, khiến hơn vạn tu sĩ giới ngoại phấn chấn. Tuyên bố muốn giết Phong Tôn để đứng thứ nhất Thái Cổ Tinh Thần bảng. Thi triển đòn sát thủ nổi danh — ngưng tụ hương hỏa lực thành ba con hắc long vạn trượng, trong miệng mỗi con chứa hương hỏa giới với vô số môn đồ dâng hương hỏa lực, biến thành hương hỏa long. Ba con hắc long là long thú thật bắt từ nơi kỳ dị, tế luyện ngàn năm mới cúng bái hắn.","anchor":"Phong Tôn thì đã làm sao. Ngươi cứ đợi xem lão phu giết Phong Tôn này thế nào!"},{"importance":"normal","mucCt":"ky","chuong":"@c1455","tieuDe":"Bị Vương Lâm giết — nguyên thần tiêu tán","text":"Thiên Triệu Thượng Sư nội tâm khiếp hãi Vương Lâm nhưng cố tỏ ra ngông cuồng, tự trấn an rằng Vương Lâm không có Khai Thiên Phủ sẽ không đấu nổi hắn. Vung tay áo điều khiển ba con hương hỏa hắc long tấn công. Khi thấy kim quang tiên lực, nhớ lại năm xưa bắt năm con hắc long đã từng gặp tiên nhân có kim quang, chỉ bị nhìn một cái đã hôn mê gần mười năm. Hoảng sợ cực điểm hét “Tiên nhân! Ngươi là tiên nhân!”, bỏ mọi sự chống cự điên cuồng rút lui. Bị Vương Lâm lần lượt dùng nắm tay vàng đánh nát thân thể, tiên lôi đánh tan hồn phách hương hỏa, ngọn lửa vàng (Thiên Hoàng Lô) thiêu hủy nguyên thần — chết.","anchor":"Nguyên thần của Thiên Triệu Thượng Sư trong khoảnh khắc liền tiêu tán"},{"importance":"bridge","mucCt":"gon","chuong":"@c1462","tieuDe":"Được nhắc tên","text":"Được nhắc đến: trước đây bị Vương Lâm giết bằng sức mạnh dung hợp tiên-thần bộc phát toàn bộ mười phần.","anchor":"Thiên Triệu Thượng Sư lúc trước chính là do sức mạnh bộc phát ra toàn bộ mười phần này của Vương Lâm"},{"chuong":"@c1482","importance":"normal","mucCt":"gon","tieuDe":"Hồn bị lôi ra gia tăng mũi tên","text":"Hồn bị phong ấn trong Thiên Hoàng Lô, bị Vương Lâm lôi ra cùng Nam Chiếu dung hợp vào ký hiệu trên mũi tên.","anchor":"hồn của Nam Chiếu và Thiên Triệu trực tiếp bay ra"}],"tuViMoc":[{"chuong":"@c1453","canhGioi":"Không Linh sơ kỳ","text":"Tu vi Không Linh sơ kỳ (thông tin từ Viêm Lôi Tử)","importance":"major"},{"chuong":"@c1454","canhGioi":"Không Linh","text":"Tu sĩ Không Linh có hương hỏa lực, lần đầu xuất hiện đã ở cảnh giới này.","importance":"major"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối thủ sắp đối đầu","ghiChu":"Vương Lâm tiến tới tổng bộ Tu Chân Liên Minh hủy Thất Thải Giới"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1452","@c1453","@c1454","@c1455","@c1462","@c1482"],"canhGioiCaoNhat":"Không Linh sơ kỳ"},{"id":"chuong-ton","name":"Chưởng Tôn","cn":"掌尊","aliases":[],"gioiTinh":"nam","tabs":{"kinhLich":[{"chuong":"@c1453","importance":"bridge","mucCt":"vua","tieuDe":"Bày mưu Thất Thải Giới và đánh thương Nam Vân Tử","text":"Được nhắc: Thất Thải Giới là chỗ mai phục do Chưởng Tôn bày mưu cả vạn năm. Nam Vân Tử bị Chưởng Tôn đánh trọng thương bế quan.","anchor":"Chưởng Tôn đã bày mưu với Thất Thải Giới"},{"chuong":"@c1479","importance":"bridge","mucCt":"gon","tieuDe":"","text":"Được nhắc gián tiếp: lão tổ Phù Văn tộc là nữ nhi của Chưởng Tôn.","anchor":"lão tổ Phù Văn tộc lại là nữ nhi của chưởng tôn"},{"chuong":"@c1481","importance":"bridge","mucCt":"vua","text":"Được nhắc đến trong suy luận của Vương Lâm: từng bất chấp tiến vào giới nội để giết Phong Tôn và lấy mũi tên, nhưng tiếng rống từ giới nội khiến hoảng sợ cực điểm, bị trọng thương cuốn ra.","anchor":"Có lẽ Chưởng Tôn cũng đã từng tới đây, hắn đã bất chấp hết thảy để tiến vào trong giới nội"},{"chuong":"@c1490","importance":"major","tieuDe":"Xuất hiện chụp mũi tên, đối mặt Vương Lâm","text":"Bước ra từ tấm màn trên bầu trời trong ánh sáng lam, mặc hắc bào, cánh tay phải khô héo, uy áp không bị giới hạn Không Linh Trung Kỳ như bốn người kia. Chụp lấy mũi tên dư lực, thân thể chấn động. Tự xưng Chưởng Tôn, nhắc hai lần gặp Vương Lâm trước đó ở mộ địa Đạo Cổ và Vân Hải tinh vực.","anchor":"Một rống ở bên ngoài mộ địa Đạo Cổ, một trận đánh bại tu quân Thái Cổ Tinh Thần của ta ở Vân Hải tinh vực, Vương Lâm, chúng ta lại gặp mặt rồi","mucCt":"ky"},{"chuong":"@c1491","importance":"normal","mucCt":"ky","tieuDe":"Hiện thân tách huyết mạch tiên nhân Vương Lâm","text":"Hiện thân sau khi Vương Lâm bắn mũi tên, xóa tan mũi tên bằng tay. Tiết lộ toàn bộ nơi sát kiếp là một hồi Tĩnh Trung Lao Nguyệt, thứ mò ra là Chu Tước Tinh và Vương Lâm. Triệu mặt trời dùng bổn nguyên thái sơ quy tắc phóng cột sáng tách hoàn toàn huyết mạch tiên nhân khỏi cơ thể Vương Lâm, ngưng tụ thành giọt máu chứa nửa ký hiệu tiên nhân bất diệt thể. Kích động cuồng nhiệt khi thấy giọt máu, giơ tay định cầm nhưng bị Xích Hồn Tử giải phóng từ Hắc Tháp va vào đẩy lùi hơn mười trượng, mũ hắc bào tung lộ dung nhan.","anchor":"Từ thủa sơ khai của thiên địa đã có ánh sáng, ánh sáng này chính là một trong những bổn nguyên mà lão phu cảm ngộ được, bổn nguyên thái sơ quy tắc"},{"importance":"major","mucCt":"ky","chuong":"@c1492","tieuDe":"Bị thương — ném thương tử vong về phía Vương Lâm","text":"Phong ấn Tĩnh Trung Lao Nguyệt bị Xích Hồn Tử phá tan, bị bức lui mười trượng. Bản thể ở đại điện Thái cổ Tinh Thần phun hai ngụm máu tươi. Mất cơ hội đoạt huyết dịch tiên thể. Gọi Lam Mộng thực hiện ước định lấy lại thân thể thê tử, Lam Mộng xuất thủ chặn Vương Lâm. Chỉ lên trời ngưng tụ ánh sáng bảy màu thành cây trường thương khổng lồ mang khí tức hủy thiên diệt địa, ném về phía Vương Lâm — cây thương tử vong.","anchor":"Hắn quyết không cho phép kế hoạch lần này thất bại"},{"chuong":"@c1493","importance":"normal","mucCt":"ky","tieuDe":"Kinh hãi gọi người điên là Chủ, bị Chiến lão quỷ đánh tan vỡ biến mất","text":"Khi nghe tiếng nói từ lỗ thủng, kinh hãi tột cùng hơn cả khi gặp Xích Hồn Tử, gọi người điên là Chủ, hồn phi phách tán. Lẩm bẩm khẳng định tiên nhân bất diệt thể nhất định do người điên truyền cho Vương Lâm, tự an ủi rằng hắn sẽ không nhận ra ta. Thân thể lờ mờ dần tiêu tán, bị Chiến lão quỷ xuất hiện vô thanh điểm một chỉ đánh trúng, thân ảnh tan vỡ hoàn toàn biến mất.","anchor":"Chủ.chủ. Chưởng Tôn hầu như hồn phi phách tán nhìn người điên, sắc mặt trong nháy mắt liền tái nhợt"},{"chuong":"@c1519","importance":"bridge","mucCt":"gon","text":"Bị Vương Lâm nhắc đến là kẻ thù khi thức tỉnh sau mộng đạo, cùng Hư Thần Thiên Tôn và mấy tiên phi.","anchor":"Chưởng Tôn. Hư Thần Thiên Tôn, còn cả mấy tiên phi kia"},{"chuong":"@c1522","importance":"bridge","mucCt":"gon","text":"Được nhắc: giọt máu bất diệt thể tiên nhân là vật bị Chưởng Tôn tách khỏi thân Vương Lâm năm xưa; Hư Thần Thiên Tôn đánh giá ngay cả Chưởng Tôn cũng không thể có sáu đạo bổn nguyên.","anchor":"Loại chuyện này ngay cả Chưởng Tôn cũng không thể làm được"},{"chuong":"@c1528","importance":"bridge","mucCt":"gon","text":"Được nhắc đến khi nam tử áo xanh đánh giá Nhân Quả Ấn của Vương Lâm ngang với thần thông Tĩnh Trung Lao Nguyệt của Chưởng Tôn.","anchor":"cũng phải tương đương với Tĩnh Trung Lao Nguyệt của Chưởng Tôn."},{"importance":"bridge","mucCt":"gon","chuong":"@c1529","text":"Bị Hư Thần Thiên Tôn oán trách vì năm xưa đưa Cung Lý Quảng ra, khiến Vương Lâm có bảo vật mà giới nội lẫn giới ngoại khó ai giết được hắn.","anchor":"Chưởng Tôn, năm đó người đưa cây cung kia ra"},{"chuong":"@c1531","importance":"normal","mucCt":"ky","tieuDe":"Hoảng loạn bộc lộ bí mật về chủ nhân và Thất Thải","text":"Trong cung điện đen ở Thái Cổ Tinh Thần, đứng bên giếng tắt nến, hoảng loạn vì Vương Lâm khó giết. Nhắc lần đầu giết Vương Lâm bị Lam Mộng ngăn cản, lần hai bị chủ nhân xuất hiện cứu Vương Lâm. Suy đoán cây cung Lý Quảng và mũi tên do chủ nhân dùng huyết mạch hỗ trợ Vương Lâm thi triển mà không bị bài xích. Lo sợ chủ nhân đang điên và bị Thiên Đạo nuốt mất tích, nếu khôi phục trí nhớ sẽ trừng phạt vì mình đã khuất phục Thất Thải.","anchor":"Thân mình Chưởng Tôn ở bên dưới lớp hắc bào như đang run rẩy"},{"chuong":"@c1558","importance":"bridge","mucCt":"gon","text":"Được xác nhận không có mặt tại La Thiên, cùng với văn sĩ trung niên là những người tham gia đại kiếp sinh tử năm đó nhưng vắng mặt.","anchor":"Ngoài Chưởng Tôn và văn sĩ trung niên và Hư Thần Thiên Tôn đã chết ra thì toàn bộ đều ở đây"},{"importance":"normal","mucCt":"ky","chuong":"@c1560","tieuDe":"Bổn tôn lần đầu bước vào giới nội","text":"Lần đầu tiên dùng bổn tôn bước vào giới nội thay vì phân thân hay ý chí. Xuất hiện từ khe không gian khổng lồ mang khí tức Thái Cổ Tinh Thần, cung điện hành cung bay ra trước. Mặc hắc bào, tướng mạo không rõ, cánh tay khô héo như xương khô. Đánh chưởng ấn khổng lồ che lấp tinh không nhắm vào Hồng Sam Tử, nữ tử Triệu Hà và Thanh Lâm, tuyên bố kết thúc chiến tranh. Mười vạn tu sĩ giới ngoại mừng rỡ. Nhưng mũi tên Vương Lâm lấn áp chưởng ấn của hắn.","anchor":"Chưởng Tôn lần đầu dùng bổn tôn bước vào giới nội"},{"chuong":"@c1561","importance":"normal","mucCt":"ky","tieuDe":"Bị mũi tên xuyên thấu, dùng tam mệnh thuật bỏ trốn","text":"Dùng chưởng ấn bảy màu, bảy tầng màn sáng, cắn lưỡi phun máu huyết mạch tiên nhân hóa mặt trời thái sơ quy tắc, triệu giếng khổng lồ hương hỏa giới thứ hai do người điên ở Tiên Cương đại lục ban cho — tất cả đều bị mũi tên Vương Lâm phá tan. Thân thể bị xuyên thấu tan nát, cung điện thánh vật bị phá hủy. Tiết lộ Vương Lâm đã bỏ tiên nhân bất diệt thể, chỉ đủ tiên lực bắn thêm hai lần. Dùng phong diệt tộc tam mệnh thuật tái sinh, sắc mặt tái nhợt lập tức nhảy vào khe đóng lại bỏ trốn.","anchor":"Lão phu không tin là cây cung của Lý Quảng trên tay ngươi lại có thể có lực lượng giết ta"},{"chuong":"@c1568","importance":"bridge","mucCt":"gon","text":"Được nhắc khi so sánh huyền kiếp: chỉ vượt qua ba lần huyền kiếp, không có dũng khí đối diện lần thứ tư.","anchor":"Mạnh mẽ như Chưởng Tôn cũng chỉ vượt qua được ba lần huyền kiếp, không có dũng khí đối diện với lần thứ tư."},{"chuong":"@c1572","importance":"normal","mucCt":"ky","tieuDe":"Triệu tập tổng lực phản công, cầu kiến sư tôn","text":"Phán đoán Vương Lâm chỉ còn sức bắn hai mũi tên, tam mệnh thuật bản thân cũng chỉ còn một lần thi triển. Truyền lệnh qua ngọc giản cho Trường Tôn hội ngưng tụ toàn bộ lực lượng, bất kể giá nào trong ba năm phải hủy diệt trận pháp giới nội. Ra lệnh toàn năng Thái Cổ Tinh Thần nghe lệnh Trường Tôn hội, ép tu sĩ thiên nhân đệ ngũ suy trong bộ lạc thành con rối, mở bảo khố lấy viễn cổ bí chiếu dùng máu mười vạn tu sĩ viết. Tới Lam Sơn giao dịch với Lam Mộng Đạo Tôn: dẫn động một mũi tên của Vương Lâm đổi trợ giúp bức hồn phách tiên phi thứ năm ra. Triệu tiên phi thứ bảy ra tay. Cuối cùng tới sáu đại lục sâu trong Thái Cổ Tinh Thần cung kính cầu kiến sư tôn.","anchor":"Đệ tử cầu kiến sư tôn!"},{"chuong":"@c1573","importance":"major","mucCt":"ky","tieuDe":"Bái kiến sư tôn đạo nhân bảy màu, lộ giao kèo và chủ nhân bí ẩn","text":"Tới chín đại lục trôi nổi trong Thái Cổ Tinh Thần, bái kiến sư tôn — đạo nhân bảy màu. Bẩm báo thất bại trong trận đánh giới nội-giới ngoại, cây cung của Lý Quảng đã rơi vào tay Vương Lâm. Đạo nhân bảy màu bàn về “người thứ ba” ẩn thế luân hồi vô số lần, dự định thôn phệ người thứ ba rồi vượt Chiến lão quỷ. Trước khi rời đi, Chưởng Tôn nhắc lại giao kèo năm xưa — hắn bái sư theo yêu cầu, đổi lại đạo nhân phải giữ lời hứa. Đạo nhân bảy màu nói “chủ nhân của ngươi” không rời khỏi nơi này và sẽ trở thành “thuốc bổ” cho hắn. Lộ ra Chưởng Tôn có một chủ nhân bí ẩn khác ngoài sư tôn.","anchor":"Năm đó ngươi khiến ta bái ngươi làm thầy, ta đã tuân theo"},{"mucCt":"vua","text":"Thân ảnh biến ảo xuất hiện trong Thái Cổ Tinh Thần quan sát cuộc chiến từ xa. Nhận định thần thông hiến tế thọ nguyên mười vạn tu sĩ rất mạnh, ngay cả hắn muốn đối kháng cũng phải cố sức. Muốn xem Vương Lâm có phải dùng Xạ Thần xa hay không.","anchor":"Ta muốn xem ngươi có phải dùng cung hay không","bridge":true,"khoang":"@c1574"},{"importance":"normal","mucCt":"vua","chuong":"@c1575","tieuDe":"Oán hận sư tôn truyền thần thông cho Vương Lâm","text":"Từ Thái Cổ Tinh Thần dùng thần thức nhận ra trường thương bảy màu là thần thông tuyệt mật của sư tôn Thất Thải Tiên Tôn. Oán hận thì thào rằng từ nhỏ đã theo chủ nhân cúc cung tận tụy nhưng chưa bao giờ được truyền thụ thần thông cấp bậc này, trong khi sư tôn lại truyền cho một tu sĩ hèn kém trong động phủ. Đánh giá chủ nhân tính tình cổ quái, bạc bẽo tới cực điểm.","anchor":"Chủ nhân, ta từ nhỏ đã theo người, nhiều năm như vậy người chưa bao giờ truyền thụ thần thông cấp bậc này cho ta"},{"mucCt":"vua","text":"Dùng thần thức quan sát chiến trường từ xa. Tiết lộ nam tử trung niên trong chín quan tài là chí bảo Trường Tôn hội do hắn và đạo nhân bảy màu tạo nên qua năm tháng vô tận. Mục đích: bức Vương Lâm bắn tên Xạ Thần xa, đồng thời hy vọng hai kẻ truyền thừa Đạo cổ tự giết nhau gây thiên biến tạo vết rách trên trận pháp.","anchor":"bọn hắn đều được truyền thừa của đạo cổ, tự giết lẫn nhau sẽ dẫn tới thiên biến","bridge":true,"khoang":"@c1577"},{"chuong":"@c1578","importance":"bridge","mucCt":"gon","text":"Bị Vương Lâm vạch trần: đám Chưởng Tôn giới ngoại đã qua vô tận năm tháng giết vô số người tam tộc cổ, ngưng tụ tâm huyết tạo ra nam tử trung niên.","anchor":"bị đám người Chưởng Tôn trong giới ngoại qua vô tận năm tháng, giết vô số người của tam tộc cổ"}],"tuViMoc":[],"nhanMach":[{"ten":"Sư tôn của Chưởng Tôn","tag":"su-mon","quanHe":"Sư tôn","ghiChu":"Ở nơi sáu đại lục lơ lửng sâu trong Thái Cổ Tinh Thần, Chưởng Tôn cung kính xưng đệ tử cầu kiến @c1572"},{"ten":"Tiên phi thứ bảy","tag":"dong-minh","quanHe":"Đồng minh có ước định","ghiChu":"Triệu ra tay phá trận, đe ước định vô hiệu nếu không hợp tác @c1572"},{"ten":"Lam Mộng Đạo Tôn","tag":"dong-minh","quanHe":"Đối tác giao dịch","ghiChu":"Đề nghị dẫn động một mũi tên Vương Lâm đổi trợ giúp bức hồn phách tiên phi thứ năm @c1572"},{"ten":"Đạo nhân bảy màu","tag":"su-mon","quanHe":"Sư tôn (bái sư theo giao kèo)","ghiChu":"Chưởng Tôn bái sư đạo nhân bảy màu để đổi lấy lời hứa về chủ nhân bí ẩn"}],"tuiDo":{},"diem":[{"text":"Dùng thần thông Thiên Địa Thái Sơ giết Chiến Tinh Dã đoạt chiến hồn, tiết lộ Thiên Đạo Kế","chuong":"@c1134"},{"text":"Liên thủ cùng người Viễn Cổ Tiên Vực đánh trọng thương Chủ nhân Phong Giới gần tử vong","chuong":"@c1238"},{"text":"Phát lệnh tàn sát Phong Giới theo ý chỉ Viễn Cổ Tiên Vực, triển khai trận chiến giới ngoại","chuong":"@c1413"},{"text":"Bái kiến sư tôn đạo nhân bảy màu, lộ giao kèo và thân phận nô bộc bị thu phục","chuong":"@c1573"},{"text":"Bổn tôn lần đầu bước vào giới nội, bị mũi tên xuyên thấu phải dùng tam mệnh thuật bỏ trốn","chuong":"@c1561"},{"text":"Bị Vương Lâm lấy nửa hồn, rơi vào luân hồi nhân quả, kết cục bi thảm","chuong":"@c1680"}]},"nguon":["@c1453","@c1459","@c1479","@c1481","@c1490","@c1491","@c1492","@c1493","@c1519","@c1522","@c1528","@c1529","@c1531","@c1558","@c1560","@c1561","@c1568","@c1572","@c1573","@c1574","@c1575","@c1577","@c1578"],"canhGioiCaoNhat":"Không rõ","trangThai":"song","vaiTro":"Lão tổ tông Nguyệt Tộc bước thứ ba — kẻ thù lớn của Vương Lâm tại giới ngoại Thái Cổ Tinh Thần","tinhCach":"Mưu tính thâm sâu, bày Thiên Đạo Kế và mai phục Thất Thải Giới cả vạn năm; tàn nhẫn quyết đoán, giết Chiến Tinh Dã đoạt chiến hồn, phát lệnh tàn sát Phong Giới; giỏi dụ lợi mua chuộc, dùng lợi ích lôi kéo Diệu Âm đạo tôn và Lam Mộng đạo tôn ra tay; ngoài mạnh trong yếu, nhiều lần hoảng sợ kinh hãi t","blurb":"Chưởng Tôn là lão tổ tông Nguyệt Tộc bước thứ ba, tự xưng Chưởng Tôn Thái Cổ Tinh Thần, bị đạo nhân bảy màu thu phục làm sai vặt chiếm cứ giới ngoại. Hắn nhiều đời bố trí Thiên Đạo Kế, luyện Thất Thải Thần Không Đinh, liên thủ trọng thương Chủ nhân Phong Giới, phát lệnh tàn sát Phong Giới theo ý chỉ Viễn Cổ Tiên Vực, đồng thời tách huyết mạch tiên nhân khỏi Vương Lâm và nhiều lần trực tiếp đối đầu. Trong các cuộc giao tranh với Vương Lâm, hắn liên tiếp bị phá cục, bị mũi tên xuyên thấu, đạo tâm sụp đổ, cuối cùng bị lấy nửa hồn và rơi vào luân hồi nhân quả, kết thúc một đời kiêu hùng chỉ là nô "},{"id":"thanh-lam","name":"Thanh Lâm","cn":"青岚","aliases":["Tiên đế"],"gioiTinh":"nam","tabs":{"kinhLich":[{"chuong":"@c1453","importance":"normal","mucCt":"vua","tieuDe":"Thi triển viễn cổ tiên thuật cứu giới nội","text":"Rời Vũ giới lãnh đạo giới nội đánh trận, thi triển viễn cổ tiên thuật gọi ánh sáng viễn cổ giết tu sĩ giới ngoại và phong kín Thất Thải Giới, giúp giới nội sống sót qua đại chiến thứ hai. Trong đại chiến thứ ba bị trọng thương.","anchor":"tiên đế Thanh Lâm thi triển ra viễn cổ tiên thuật, gọi tới ánh sáng viễn cổ"},{"chuong":"@c1479","importance":"bridge","mucCt":"gon","tieuDe":"","text":"Được nhắc: năm đó phong ấn lão tổ Phù Văn tộc (nữ nhi Chưởng Tôn) ở vùng đất Yêu Linh.","anchor":"Nữ tử này năm đó bị Thanh Lâm phong ấn ở vùng đất Yêu Linh rồi"},{"chuong":"@c1481","importance":"bridge","mucCt":"gon","text":"Được nhắc đến: phong ấn con gái Chưởng Tôn ở vùng đất Yêu Linh.","anchor":"Con gái của Chưởng Tôn bị Thanh Lâm phong ấn ở vùng đất Yêu Linh"},{"importance":"bridge","mucCt":"gon","chuong":"@c1492","text":"Đang bế quan chữa thương tại Vũ Tiên Giới trong Côn Hư, mở mắt kinh hãi nhận ra khí tức Chưởng Tôn, xé khe không gian lao đi.","anchor":"hai mắt hắn mở bừng ra, lộ vẻ vô cùng khiếp sợ"},{"chuong":"@c1494","importance":"minor","mucCt":"gon","text":"Xuất hiện tại tinh không Chu Tước Tinh sau sát kiếp Vương Lâm, than thở đại chiến sắp bắt đầu.","anchor":"Đại chiến sắp bắt đầu, việc này giới ngoại chắc chắn sẽ không kiêng nể gì mà truyền ra"},{"mucCt":"vua","text":"Ánh sáng viễn cổ do Thanh Lâm tạo thành hơn 30 năm trước đã sụp đổ, phòng tuyến ngăn giới ngoại không còn, tu sĩ giới ngoại tràn vào tứ đại tinh vực.","anchor":"Ánh sáng viễn cổ do Thanh Lâm tạo thành hơn ba mươi năm trước đã sụp đổ","bridge":true,"khoang":"@c1516"},{"chuong":"@c1540","importance":"bridge","mucCt":"gon","text":"Được Vương Lâm tìm thấy và thu hồi vận mệnh trong mặt trời thứ chín.","anchor":"Hắn tìm ấy Thập Tam, tìm thấy đầu to, tìm được Chu Dật"},{"mucCt":"ky","text":"Bay ra khỏi tinh trận dưới dạng thanh quang, đánh với lão già áo đen (từng vây sát Vương Lâm). Bị lão già áo đen khen là đệ tử của lão già Phong Tôn, biết mượn lực lượng hương hỏa dù tu vi kém hơn. Trọng thương nhưng vẫn kiên trì ra đánh.","anchor":"Một tiên đế Vũ Giới Thanh Lâm giỏi lắm, không hổ là đệ tử của lão già Phong Tôn kia","bridge":true,"khoang":"@c1559"},{"importance":"bridge","mucCt":"gon","chuong":"@c1560","text":"Đang giao chiến bên ngoài tinh trận, gặp nguy cơ sinh tử lớn nhất, là mục tiêu chưởng ấn bổn tôn Chưởng Tôn.","anchor":"Thanh Lâm. nữ tử của Triệu Hà, Hồng Sam Tử đang giao chiến với bậc toàn năng Không Huyền của giới ngoại cũng gặp phải nguy cơ sinh tử lớn nhất trong đời"},{"chuong":"@c1561","importance":"bridge","mucCt":"gon","text":"Nhìn mũi tên, cảm giác quen thuộc mơ hồ nhưng không dám tưởng tượng, lộ vẻ không thể tin nổi.","anchor":"Ánh mắt Thanh Lâm lộ vẻ không thể tin nổi"},{"chuong":"@c1563","importance":"bridge","mucCt":"gon","text":"Cùng Vương Lâm đồng loạt xông ra khỏi tinh trận tham chiến quyết chiến với tu sĩ giới ngoại.","anchor":"Cùng nhau lao ra còn có Thanh Lâm, Hồng Sam Tử"},{"chuong":"@c1564","importance":"bridge","mucCt":"gon","text":"Đuổi theo sát nút tiên phi áo lam, bị Thiên Hoàng Lô đẩy ra ngoài, sau đó nhận lệnh Vương Lâm liên thủ chặn hai Không Huyền cuối cùng.","anchor":"Thanh Lâm đang đuổi theo sát nút"},{"mucCt":"vua","text":"Khi tu sĩ giới nội kiệt sức không đẩy nổi bánh xe lần ba, Thanh Lâm nhắm mắt xuất nguyên thần mênh mông nhấn vào bánh xe, thân là toàn năng bước thứ ba, tiên đế Vũ Giới. Cùng Hồng Sam Tử, nữ tử Triệu Hà, Thanh Thủy bốn nguyên thần đẩy bánh xe quay vòng thứ ba, khiến tinh không thực sự sụp đổ.","anchor":"Thân là bậc toàn năng bước thứ ba, thân là tiên đế của Vũ Giới, lực lượng nguyên thần của hắn kinh thiên động địa","bridge":true,"khoang":"@c1565"},{"mucCt":"vua","text":"Ngồi nhìn tinh không, nhắm mắt cảm thán rằng Vương Lâm có lẽ đã biết chút sự thật. Sư tôn năm đó kể chuyện này khiến Thanh Lâm không tin nổi, phải tự lừa gạt quên đi, nhưng nhận xét Vương Lâm mạnh mẽ hơn vì chọn đối mặt.","anchor":"khi năm đó sư tôn nói chuyện này với ta, ta cũng không thể tin nổi, chỉ có thể lừa gạt bản thân mình quên đi","bridge":true,"khoang":"@c1566"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Được xác nhận là Tiên Đế, cường giả đệ nhất Tiên giới và phụ thân Thanh Sương qua ngọc giản","chuong":"@c0595"},{"text":"Thức tỉnh trong trận pháp hồi sinh, khai sinh Tân Vũ Giới, ôn hòa an ủi đệ tử sau tang thương","chuong":"@c1050"},{"text":"Hiện thân từ thức hải, đánh tan Cổ Ma Tháp Già và truyền thụ Quy tắc thân thể cho Vương Lâm","chuong":"@c1047"},{"text":"Thi triển viễn cổ tiên thuật gọi ánh sáng viễn cổ, lãnh đạo giới nội đánh trận giết tu sĩ giới ngoại","chuong":"@c1453"},{"text":"Được xác nhận là phách thứ ba (cam) của Thất Thải Tiên Tôn, phách chứa chính khí và lương tri","chuong":"@c1650"},{"text":"Luân hồi thành phàm nhân thợ rèn ở thành trì Lâm Hóa Châu, có vợ, chọn quên đi quá khứ","chuong":"@c1960"}]},"nguon":["@c1453","@c1479","@c1481","@c1492","@c1494","@c1516","@c1540","@c1559","@c1560","@c1561","@c1563","@c1564","@c1565","@c1566"],"canhGioiCaoNhat":"Không rõ","trangThai":"song","vaiTro":"Tiên Đế — phách thứ ba (cam) của Thất Thải Tiên Tôn, cường giả đệ nhất Tiên giới","tinhCach":"Mưu tính sâu xa, bố cục vượt thời gian; lạnh lùng quyết đoán với kẻ địch; che chở đệ tử và giới nội, trọng ân nghĩa; mang vẻ tang thương sau biến cố, ôn hòa với người thân cận","blurb":"Thanh Lâm là Tiên Đế, được công nhận là cường giả đệ nhất Tiên giới, phụ thân Thanh Sương, phu quân Hoa Phi, ân sư của Vương Nguy và Hồ Quyên, đồng thời là phách thứ ba chứa chính khí và lương tri của Thất Thải Tiên Tôn. Sau khi thân thể bị Cổ Ma Tháp Già chiếm cứ, ông nhờ trận pháp hồi sinh mà thức tỉnh, truyền Quy tắc thân thể cho Vương Lâm và khai sinh Tân Vũ Giới, rồi bế quan chữa thương hàng trăm năm tại Vũ Tiên Giới, nhiều lần ra tay bảo vệ giới nội và tham chiến đại chiến giới ngoại. Cuối cùng ông luân hồi thành phàm nhân thợ rèn tại thành trì Lâm Hóa Châu, chọn cách quên đi quá khứ."},{"id":"trong-huyen-tu","name":"Trọng Huyền Tử","cn":"重玄子","aliases":["Tống nhi"],"gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1453","importance":"normal","mucCt":"vua","tieuDe":"Phản bội thành tay sai giới ngoại","text":"Chưa tử vong, đã trở thành tay sai của giới ngoại, hiện ở tổng bộ Tu Chân Liên Minh phục vụ giới ngoại. Vương Lâm đang tiến tới đối đầu.","anchor":"Trọng Huyền Tử cũng chưa tử vong, hôm nay đã trở thành tay sai của giới ngoại"},{"importance":"bridge","mucCt":"gon","chuong":"@c1454","tieuDe":"","text":"Viêm Lôi Tử xác nhận Trọng Huyền Tử đang ở tổng đàn Tu Chân Liên Minh, trở thành mục tiêu hành trình của Vương Lâm.","anchor":"Trọng Huyền Tử đang ở nơi này"},{"chuong":"@c1459","importance":"major","mucCt":"ky","tieuDe":"Khai ra sự thật, được sư tôn gánh tội","text":"Bị Long Bàn Tử lôi ra từ tu chân tinh, dung mạo đã biến thành lão già. Quỳ xuống cầu xin tha mạng, thú nhận bắt tay giới ngoại vì giới nội không phải đối thủ, tiết lộ sự tồn tại của Long Bàn Tử cho giới ngoại để đổi cơ duyên. Đổ lỗi cho Thanh Thủy Tiên Quân buộc hắn phá phong ấn Thất Thải Giới. Long Bàn Tử hồi tưởng hắn vốn tên Tống nhi, là đồng tử ăn mày bò lên đỉnh núi mười bảy ngày cầu tiên duyên, được sư tôn lấy thiên địa ngũ mạch tạo đạo cốt. Long Bàn Tử tự thiêu nguyên thần gánh tội thay, cuốn hắn rời đi.","anchor":"Nhưng hôm nay ngươi lại không hề có đạo tâm."},{"importance":"normal","mucCt":"vua","chuong":"@c1460","tieuDe":"Nói lời cuối với Viêm Lôi Tử rồi rời đi","text":"Trước khi rời đi nói với Viêm Lôi Tử rằng chuyện năm đó không hoàn toàn như hắn nhìn thấy, giọng mang vẻ bi thương và hối hận đối với sư tôn. Quay đầu nhìn thoảng qua Viêm Lôi Tử rồi cùng Long Bàn Tử rời đi.","anchor":"chuyện năm đó cũng không phải hoàn toàn như ngươi nhìn thấy đâu"},{"chuong":"@c1470","importance":"bridge","mucCt":"gon","text":"Theo sư phụ Long Bàn Tử rời đi sau trận chiến.","anchor":"Hắn mang theo thương thế dẫn đệ tử Trọng Huyền Tử yên lặng rời khỏi"}],"tuViMoc":[],"nhanMach":[{"ten":"Viêm Lôi Tử","tag":"doi-thu","quanHe":"Cựu đạo hữu chí cốt, nay thù địch","ghiChu":"Vốn là bạn thân, nhưng vì sự việc bí ẩn năm đó mà trở thành kẻ thù; Trọng Huyền Tử tỏ ra hối hận"},{"ten":"Long Bàn Tử","tag":"su-mon","quanHe":"Sư tôn — người thu nhận từ nhỏ, tạo đạo cốt, cuối cùng tự thiêu gánh tội thay","gap":"@c1459"}],"tuiDo":{},"diem":[{"text":"Bị lão giả tóc trắng liệt vào mục tiêu truy sát sau khi kế hoạch mấy vạn năm hoàn thành","chuong":"@c0696"},{"text":"Từng là luyện khí sĩ nổi bật của Hạ giới, cùng đồng đạo lần đầu tới Vũ Tiên Giới đạt được phần lớn truyền thừa","chuong":"@c1039"},{"text":"Không thể phân thân vì chiến sự với La Thiên đang căng thẳng","chuong":"@c0938"},{"text":"Phản bội Tu Chân Liên Minh, trở thành tay sai của giới ngoại, ẩn náu tại tổng bộ Liên Minh","chuong":"@c1453"},{"text":"Bị sư phụ Long Bàn Tử lôi ra, quỳ gối cầu xin tha mạng và thú nhận tội trạng, được sư tôn gánh tội","chuong":"@c1459"},{"text":"Nói lời bi thương với Viêm Lôi Tử rồi theo sư phụ Long Bàn Tử rời đi","chuong":"@c1460"}]},"nguon":["@c1453","@c1454","@c1459","@c1460","@c1470"],"vaiTro":"Đại Trưởng lão Tu Chân Liên Minh — phản đồ phục vụ giới ngoại, đệ tử Long Bàn Tử","tinhCach":"khuất phục trước quyền lực mạnh hơn, sẵn sàng phản bội lập trường vì sinh tồn; mang bi thương và hối tiếc khi đối diện cố nhân","blurb":"Trọng Huyền Tử là Đại Trưởng lão Tu Chân Liên Minh, sư huynh của Hư Không Tử, vốn xuất thân là luyện khí sĩ nổi bật của Hạ giới và từng cùng đồng đạo đến Vũ Tiên Giới đạt được phần lớn truyền thừa. Ông lâu năm chỉ huy chiến sự chống La Thiên nhưng sau đó phản bội, trở thành tay sai của giới ngoại và ẩn náu tại tổng bộ Liên Minh. Cuối cùng bị sư phụ Long Bàn Tử lôi ra, quỳ gối cầu xin tha mạng, thú nhận tội trạng và được sư phụ gánh tội rồi theo Long Bàn Tử rời đi."},{"id":"thanh-thuy","name":"Thanh Thủy","cn":"青水","gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1454","tieuDe":"","text":"Vương Lâm đứng trước tổng bộ Tu Chân Liên Minh thì thầm mong Thanh Thủy sư huynh còn sống.","anchor":"Thanh Thủy sư huynh, ngươi phải còn sống đó"},{"mucCt":"vua","text":"Từ bên trong tu chân tinh truyền ra tiếng gào thét điên cuồng chứa sát lục bổn nguyên. Vương Lâm nhận ra tiếng gào thét cực kỳ quen thuộc, sắc mặt lần đầu biến đổi, thốt lên Thanh Thủy sư huynh — cho thấy Thanh Thủy đang bị giam hoặc phong ấn bên trong tu chân tinh tổng bộ Tu Chân Liên Minh.","anchor":"Tiếng gào thét này Vương Lâm rất quen thuộc, cực kỳ quen thuộc","bridge":true,"khoang":"@c1456"},{"chuong":"@c1457","importance":"normal","mucCt":"ky","tieuDe":"Xác nhận còn sống trong tu chân tinh","text":"Được hồi cố toàn bộ thân thế: vốn là vua Thanh Thủy Quốc, bị truy sát, thức tỉnh Cực Cảnh rồi quay về tàn sát báo thù. Vào Lôi Tiên Giới gặp sư tôn Bạch Phàm và một nữ tử, trở thành tiên quân nhưng sau đó phát điên giết thê tử và người thân. Bị Bạch Phàm phong ấn nhưng lưu hồn phách. Hiện vẫn sống bên trong tu chân tinh Tu Chân Liên Minh, phát ra tiếng gào thét điên cuồng tràn ngập sát khí.","anchor":"từ trong miệng Thanh Thủy truyền ra một tiếng rống tuyệt vọng nhất trong đời!"},{"chuong":"@c1461","importance":"normal","mucCt":"ky","tieuDe":"Bị phong ấn trên đỉnh núi, lộ quá khứ thái tử","text":"Bị phong ấn trên đỉnh núi cao nhất bởi mười cái cọc phát ánh sáng bảy màu, chín cọc lộ rõ đóng chặt thân thể lên vách núi, cọc thứ mười ẩn dưới tóc đâm vào thiên linh. Toàn thân gầy yếu, thần sắc dữ tợn, mắt đỏ bừng, điên cuồng gào thét muốn giết sạch chúng sinh. Hồn phách bị thân thể Huyền Vũ trấn áp, mi tâm không ngừng bị ngón tay trỏ bảy màu hấp thụ sát lục bổn nguyên. Phóng Cực Cảnh chứa sát lục bổn nguyên tấn công Vương Lâm, rồi phóng huyết ảnh đầu lâu khổng lồ, đẩy lùi Vương Lâm khiến khóe miệng tràn máu. Khi nghe Vương Lâm gọi tên, thoáng tỉnh lộ vẻ thống khổ bi ai, nói được vài lời rồi bị khí xám từ Huyền Vũ xâm nhập lại rơi vào điên cuồng. Cảnh tượng quá khứ hiện ra trong sương máu: vốn là thái tử nước nhỏ phàm trần, nước bị tàn phá phải bỏ trốn, bái nhập sơn môn bị lăng nhục, đứng trên núi gào thét giận dữ hận trời đất chúng sinh — Cực Cảnh được sinh ra. Suốt quá trình có ánh sáng bảy màu với thân ảnh bí ẩn bên trong quan sát hắn từ thuở thiếu niên.","anchor":"Hồn phách của ta bị thân thể của Huyền Vũ trấn áp"},{"importance":"major","mucCt":"ky","chuong":"@c1462","tieuDe":"Quá khứ bi thảm hé lộ qua sương máu","text":"Quá khứ được hé lộ đầy đủ qua sương máu: thiếu niên lớn lên, quay về cố quốc đã bị diệt vong, bảy ngày đẫm máu. Bước vào Tiên Giới, gặp nữ tử ôn nhu và Bạch Phàm, sống hạnh phúc. Bị người bảy màu trên bầu trời chỉ xuống kích phát huyết quang và sát ý xâm chiếm thần trí, điên cuồng giết chóc vô số tu sĩ Lôi Tiên Giới. Giết cả người yêu trong cơn điên, nữ tử chết trước mặt vẫn dịu dàng nhìn hắn, nói một câu khiến hắn tỉnh lại, phát ra tiếng kêu bi thảm tuyệt vọng. Ký ức sụp đổ rồi tuần hoàn từ đầu, sức mạnh mờ ám dùng vòng lặp tàn khốc kích thích sát lục bổn nguyên trong cơ thể dần thực chất hóa. Hiện hồn phách bị Huyền Vũ hóa đá trấn áp.","anchor":"khiến cho sát lục bổn nguyên trong cơ thể hắn dần dần lớn mạnh, chậm rãi thực chất hóa"},{"chuong":"@c1463","importance":"normal","mucCt":"vua","tieuDe":"Hồn phách được giải phóng, Vương Lâm rút cọc thứ nhất","text":"Khi mai Huyền Vũ bị phá vỡ, đám hồn phách mang vẻ bi ai từ thân Huyền Vũ bay ra lao tới Thanh Thủy. Gai chỗ Thanh Thủy bay lên không trung, bị đám mây bảy màu bao phủ. Thân thể run rẩy cúi đầu, tóc rối che kín mặt. Vương Lâm đi tới rút cái cọc thứ nhất khỏi ngực y.","anchor":"Thanh Thủy thân thể run rẩy, đang cúi đầu, bị mái tóc rối che kín khuôn mặt ở phía trước"},{"mucCt":"vua","text":"Bị Vương Lâm rút lần lượt bốn cây cọc phong ấn trên ngực, cổ họng, hai cánh tay, giải phóng trái tim, gân cốt và thần thức. Chịu đựng cực khổ không kêu la, sau khi hai tay được giải phóng ngẩng đầu nhìn Vương Lâm với ánh mắt bi ai, vui mừng, kích động. Không thể nhìn thấy thân ảnh bảy màu đang đối thoại với Vương Lâm.","anchor":"Ánh mắt kia có sự bi ai, có vẻ vui mừng, còn có sự kích động","bridge":true,"khoang":"@c1464"},{"chuong":"@c1465","importance":"normal","mucCt":"ky","tieuDe":"Bị rút bốn cọc — nói Đa tạ rồi hôn mê","text":"Bị Vương Lâm rút tiếp bốn cọc phong ấn (cọc 5 ở đan điền phong ấn nguyên thần, cọc 6-7 ở hai chân, cọc 8 gần thiên linh). Chịu đau tột cùng nhưng cắn răng không hét. Cọc thứ tám được thân ảnh bảy màu tiết lộ không phải phong ấn mà để mở ra luân hồi. Sau khi cọc 8 bị rút, tách khỏi ngọn núi, ngã vào vai Vương Lâm nói \"Đa tạ\" rồi hôn mê. Còn hai đạo phong ấn cuối cùng chưa được gỡ, được nói là khó hơn rất nhiều. Được Vương Lâm mang tới tu chân tinh hoang dã ngoài tổng bộ Tu Chân Liên Minh.","anchor":"Đa tạ Nói xong một câu này, Thanh Thủy bắt đầu hôn mê"},{"importance":"normal","mucCt":"ky","chuong":"@c1466","tieuDe":"Giải trừ hoàn toàn phong ấn, khôi phục tu vi","text":"Chịu đựng thống khổ cực hạn khi Vương Lâm rút cây cọc thứ chín từ xương sống và cây cọc thứ mười từ huyết quản. Cùng sư đệ uống rượu, cảm khái Vương Lâm đã trưởng thành thành nhất đại cao thủ khiến tinh không rung chuyển. Tự mở vết thương trước ngực lôi mạch máu ra, bẻ gãy cây cọc cuối cùng làm đôi, dùng sát lục bổn nguyên giết chết phần cọc còn lại trong cơ thể. Tự xưng “bổn tiên quân”. Phun máu đen, thân thể gầy gò bành trướng khôi phục hình dáng năm xưa, sát lục bổn nguyên bộc phát kinh thiên biến thiên địa thành màu đen, tuyết đen tràn ngập, Không Đại Môn xuất hiện ở chân trời. Tiết lộ sau khi rút hết cọc sẽ khôi phục tu vi và tinh tiến không ít.","anchor":"Dám phong ấn bổn tiên quân bấy lâu nay, hôm nay ngươi cút đi cho ta!"},{"chuong":"@c1467","importance":"major","mucCt":"ky","tieuDe":"Phá không môn đột phá Không Niết Sơ Kỳ","text":"Dùng sát lục bổn nguyên ngưng tụ hắc kiếm, chém một kiếm phá vỡ non nửa không môn, ánh sáng vô sắc dung nhập thân thể, khí tức tăng tới Không Niết Sơ Kỳ — chính thức trở thành tu sĩ bước thứ ba. Khi không môn hiện, vô số hồn phách người bị giết quỳ lạy, riêng tàn hồn thê tử Hàm Yên đứng mỉm cười. Ôm lấy Hàm Yên khóc rống, sẵn sàng từ bỏ tu vi bước thứ ba để giữ nàng. Sau khi Vương Lâm dùng Cổ Tức Diệp và máu tiên nhân phong ấn tàn hồn, cài thoa cổ xưa (di vật từ diệt giới) lên đầu nàng. Thu toàn bộ hồn phách (trừ Hàm Yên) vào hắc kiếm rồi tặng kiếm cho Vương Lâm, nói nếu luyện hóa cảm ngộ sẽ có sát lục bổn nguyên.","anchor":"kiếm này là ta vì phá không môn mà ngưng tụ lại"},{"chuong":"@c1468","importance":"major","mucCt":"ky","tieuDe":"Sát lục đại thành, lời hứa mai táng, điên cuồng giết chóc tiến vào Triệu Hà","text":"Ôm hồn phách thê tử hóa ấn ký đặt tại trái tim, tặng Vương Lâm thanh sát lục kiếm. Nhắc đến phát hiện tại tổng bộ Tu Chân Liên Minh là một trò chơi với vẻ khổ sở. Yêu cầu Vương Lâm nếu hắn chết hãy đưa về quê chôn, bia mộ không ghi danh. Tiết lộ có một con gái đã thất lạc, có lẽ đã luân hồi chuyển thế, vai trái có hồng ấn nhận dạng, nhờ Vương Lâm chiếu cố. Sát lục bổn nguyên đại thành bộc phát, hàn khí đen kịt bao phủ cánh tay, cùng Vương Lâm hóa sóng gợn quét sạch tu sĩ giới ngoại khắp Côn Hư rồi tiến vào Triệu Hà Thất Thải Giới, lao vào giết mấy vạn tu sĩ đang tụng chú.","anchor":"Sát lục bổn nguyên là một đạo bổn nguyên cực kỳ đặc thù, từ cổ chí kim rất ít người có được"},{"chuong":"@c1469","importance":"normal","mucCt":"ky","tieuDe":"Lộ Bạch Phàm Thuật, liên thủ đánh trọng thương Điện chủ","text":"Dùng sát lục bổn nguyên tạo cơn lốc đen đóng băng toàn bộ sinh linh quỷ dị và phong tỏa cửa Thất Thải Giới ngăn Điện chủ rút lui. Thi triển Bạch Phàm Thuật — Âm Nguyệt điểm chỉ khiến vầng trăng hiện trên mặt Điện chủ, rồi dùng Hữu Tình khiến ánh mặt trời bùng lên phá sụp vầng trăng, gây năm vết rách sâu trên mặt Điện chủ. Bị Điện chủ nhận ra danh tính qua Bạch Phàm Thuật. Liên thủ cùng Long Bàn Tử khiến Thất Thải Giới chấn động, ba khối đại lục tan thành tro bụi. Sau đợt liên thủ bị thương, máu tràn khóe miệng.","anchor":"Bạch Phàm Thuật! Đây là tam trọng lục đạo thuật của Bạch Phàm"},{"mucCt":"vua","text":"Dùng Âm Nguyệt Hữu Tình Thuật tấn công Tần Cửu Duyên, tạo năm vết nứt trên mặt. Sau trận chiến rời đi tìm con gái, thề chỉ cần Vương Lâm nói một câu sẽ trở về. Tiết lộ trong tinh không chỉ còn quan tâm hai người, một là sư đệ Vương Lâm.","anchor":"bất luận thế nào, chỉ cần Vương Lâm nói một câu, cho dù hắn ở chân trời góc biển cũng sẽ trở về","bridge":true,"khoang":"@c1470"},{"importance":"bridge","mucCt":"gon","chuong":"@c1492","text":"Đang tìm kiếm thứ gì đó trong tinh hải ở La Thiên tinh vực, thần sắc ảm đạm, nhận ra khí tức Vương Lâm liền bỏ việc lao thẳng tới Côn Hư.","anchor":"Sau khi nhận ra luồng khí tức trong giới nội, Thanh Thủy chẳng lo tới chuyện của mình nữa"},{"chuong":"@c1494","importance":"major","mucCt":"vua","tieuDe":"Hóa thành Vương Lâm, bế quan thay trên đài chiến","text":"Xuất hiện tại tinh không Chu Tước Tinh, phóng sát khí tuyên bố thay mặt Vương Lâm bế quan trên đài chiến Vân Hải tinh vực. Biến đổi khuôn mặt thành hình dạng Vương Lâm, bỏ qua việc tìm con gái và tự do, trở thành biểu tượng cho giới nội, thề báo thù cho sư đệ.","anchor":"Hắn bỏ qua việc đi tìm nữ nhi, bỏ qua tự do mà lựa chọn hóa thành Vương Lâm"},{"chuong":"@c1516","importance":"normal","mucCt":"vua","tieuDe":"Bị Hư Thần Thiên Tôn trọng thương gần chết","text":"Thanh Thủy hóa thân thành Vương Lâm tọa trấn giới nội, nhưng trong một lần đại chiến bị Hư Thần Thiên Tôn trọng thương gần như tử vong. Tin Phong Tôn tử vong từ đó không thể ngăn cản.","anchor":"Thanh Thủy cũng bị Hư Thần Thiên Tôn khiến cho bị trọng thương, gần như tử vong"},{"chuong":"@c1522","importance":"bridge","mucCt":"gon","text":"Được nhắc: Sát Lục Kiếm là pháp bảo khi sát lục bổn nguyên của Thanh Thủy đại thành ngưng tụ thành; nằm trong chuỗi suy luận bí mật của Vương Lâm.","anchor":"chính là pháp bảo khi sát lục bổn nguyên của Thanh Thủy đại thành ngưng tụ thành"},{"chuong":"@c1523","importance":"bridge","mucCt":"gon","text":"Được hồi tưởng: năm đó lấy sát lục bổn nguyên dẫn động, một kiếm mở Không Môn và phá vỡ một góc, cực hiếm thấy.","anchor":"Thanh Thủy năm đó sau khi lấy sát lục bổn nguyên dẫn động Không Môn"},{"chuong":"@c1527","importance":"bridge","mucCt":"gon","text":"Sát lục của Thanh Thủy ẩn chứa trong huyết chưởng mà Vương Lâm dùng để đánh Vạn Không Cốt Môn.","anchor":"còn ẩn chứa cả sự giết chóc của Thanh Thủy"},{"chuong":"@c1533","importance":"bridge","mucCt":"vua","text":"Được Chân Giả Đạo biến ra trong trạng thái sau khi tỉnh lại và khôi phục trí nhớ, lặng nhìn trời sụp đổ.","anchor":"có Thanh Thủy sau khi tỉnh lại, khôi phục trí nhớ"},{"chuong":"@c1540","importance":"normal","mucCt":"vua","tieuDe":"Vận mệnh không tồn tại trong hệ thống động phủ","text":"Tương tự Tư Đồ Nam, vận mệnh Thanh Thủy không tồn tại trong mặt trời thứ chín, gợi ý nàng không thuộc hệ thống vận mệnh của động phủ.","anchor":"Vận mệnh của Thanh Thủy và Tư Đồ Nam dường như chưa từng xuất hiện bên trong mặt trời thứ chín này."},{"chuong":"@c1541","importance":"bridge","mucCt":"vua","text":"Được Vương Lâm nhắc tới khi tìm kiếm trong mặt trời thứ chín: không tìm thấy khí tức vận mệnh, Vương Lâm liên hệ ánh mắt kỳ dị của đạo nhân bảy màu nhìn nàng ở Thất Thải Giới để giải thích.","anchor":"Ánh mắt kỳ dị đó cho tới ngày nay Vương Lâm vẫn còn nhớ như in"},{"chuong":"@c1559","importance":"normal","mucCt":"ky","tieuDe":"Trọng thương thất khiếu bảy luồng hắc khí, nhận ra nữ nhi","text":"Ngồi trong tế đàn trung tâm bị trọng thương nghiêm trọng: thất khiếu có bảy luồng hắc khí như bảy con độc xà, đồng tử có vẻ tan rã và bảy điểm đen. Hồng Sam Tử cảnh báo không giúp thì ba khắc sẽ chết, nhưng Thanh Thủy hai lần quát không cần quản. Bộc phát sát lục bổn nguyên va chạm với ngón tay Hồng Sam Tử, phun máu. Sau khi Hồng Sam Tử rời đi, ngẩng đầu nhìn về phía tu chân tinh nữ tử áo hồng, ánh mắt nhu hòa, nói 'Là nó sao… hẳn là nó rồi' — đã nhận ra từ lâu nhưng không dám kiểm nghiệm.","anchor":"Ánh mắt Thanh Thủy lộ vẻ nhu hòa"},{"importance":"normal","mucCt":"ky","chuong":"@c1560","tieuDe":"Bùng phát sát lục bảo vệ nữ nhi, thân thể sụp đổ","text":"Dù chỉ còn sống ba khắc, Thanh Thủy cảm nhận khí tức hồn phách nữ nhi nơi nữ tử áo hồng — bí mật không ai biết kể cả Vương Lâm. Hắn vỗ nát mặt đất tế đàn tạo lực phản chấn bay ra khỏi sương mù. Bùng phát sát lục bổn nguyên kinh thiên động địa, dùng bông tuyết đỏ và sát lục tâm xé nát Lôi Long màu đen vạn trượng của đại hán phong lôi. Chém đại hán một nhát tạo vết thương từ mi tâm tới ngực, suýt giết chết đối thủ. Sau đó thân thể không chịu nổi, phun máu đen ngã xuống, được nữ tử áo hồng đỡ lấy.","anchor":"Quan hệ của nàng và Thanh Thủy trong thiên địa này không ai biết tới, cho dù là Vương Lâm cũng không biết"},{"chuong":"@c1561","importance":"normal","mucCt":"vua","tieuDe":"Cảm nhận khí tức Vương Lâm trở lại","text":"Đang tuyệt vọng nhắm mắt thì cảm nhận luồng khí tức quen thuộc cực điểm của huynh đệ. Mơ hồ nhìn về phía xa.","anchor":"tâm thần lại cảm nhận được một luồng khí tức quen thuộc tới cực điểm"},{"chuong":"@c1562","importance":"major","mucCt":"vua","tieuDe":"Được Vương Lâm cứu chữa khỏi cận tử","text":"Đang sắp tử vong, được Vương Lâm xua bảy luồng hắc khí độc tố khỏi thất khiếu, tử khí tiêu tán, sinh cơ bắt đầu hồi phục. Được ấn quả cầu sương mù chứa tinh hoa đại hán phong lôi vào cơ thể để nhanh chóng khôi phục thương thế.","anchor":"tử khí trên người đã tiêu tán đi nhiều, bắt đầu có sinh cơ hồi phục"},{"chuong":"@c1565","importance":"bridge","mucCt":"gon","text":"Dù thương thế chưa khôi phục, vẫn xuất nguyên thần cùng Thanh Lâm, Hồng Sam Tử, nữ tử Triệu Hà đẩy bánh xe vòng thứ ba.","anchor":"Còn có cả Thanh Thủy ở phía xa cũng không để ý tới thương thế chưa khôi phục, nguyên thần bay ra"},{"chuong":"@c1566","importance":"normal","mucCt":"ky","tieuDe":"Xác nhận nữ tử áo hồng là nữ nhi, khuyên nàng đuổi theo Vương Lâm","text":"Nguyên thần trở về thân thể, nhận ra nữ tử áo hồng đã sớm quen biết Vương Lâm. Khuyên nàng đừng do dự mà đi theo hắn — cuộc đời có việc do dự sẽ mất. Khi nữ tử hỏi vì sao cứu nàng, không nói được vì khi nhận ra đối phương là nữ nhi của mình đã không biết nói thế nào.","anchor":"Nếu có thể nói thì năm đó khi nhận ra đối phương là nữ nhi của mình hắn đã nói rồi"}],"nhanMach":[{"ten":"Nữ tử ôn nhu","tag":"the-thiep","quanHe":"Người yêu, bị Thanh Thủy giết trong cơn điên cuồng","ghiChu":"Nàng dịu dàng nhìn hắn trước khi chết, nói câu khiến hắn tỉnh @c1462"},{"ten":"Con gái Thanh Thủy","tag":"cha-me","quanHe":"Con gái, đã thất lạc","ghiChu":"Khi sinh để lại hồng ấn trên vai trái, vĩnh viễn theo qua luân hồi chuyển thế. Nhờ Vương Lâm chiếu cố nếu gặp."},{"ten":"Nữ tử áo hồng","tag":"khac","quanHe":"Nhìn về phía nàng với ánh mắt nhu hòa, gợi ý là con gái"},{"ten":"Hồng Sam Tử","tag":"dong-minh","quanHe":"Hồng Sam Tử trợ giúp bức hắc khí, bị Thanh Thủy quát đuổi"},{"ten":"Nữ tử áo hồng","tag":"cha-me","quanHe":"Nữ nhi (mang khí tức hồn phách nữ nhi của Thanh Thủy)","ghiChu":"Bí mật không ai biết kể cả Vương Lâm"}],"tuViMoc":[{"chuong":"@c1457","canhGioi":"Cực Cảnh","text":"Năm xưa trong tuyệt vọng bị truy sát đã thức tỉnh Cực Cảnh (hồi tưởng).","importance":"major"},{"chuong":"@c1467","canhGioi":"Không Niết Sơ Kỳ (bước thứ ba)","text":"Dùng sát lục bổn nguyên ngưng tụ hắc kiếm phá không môn, ánh sáng vô sắc dung nhập thân thể, đột phá thành công lên Không Niết Sơ Kỳ — tu sĩ bước thứ ba.","importance":"major"}],"diem":[{"text":"Thái tử Thanh Thủy Quốc, sau khi cố quốc bị diệt vong đã thức tỉnh Cực Cảnh, bảy ngày đẫm máu tàn sát kẻ thù rồi mang sát nghiệp cùng cực, tự phong ấn bản thân","chuong":"@c1462"},{"text":"Truyền thừa cho Vương Lâm hai tiên thuật đại tiên đế Hoán Vũ và Tát Đậu Thành Binh, công khai nhận Vương Lâm là sư đệ trước Lôi Tiên Điện","chuong":"@c0816"},{"text":"Dùng sát lục bổn nguyên ngưng tụ hắc kiếm phá Không Môn, đột phá Không Niết Sơ Kỳ — bước thứ ba tu hành","chuong":"@c1467"},{"text":"Hóa thân thành Vương Lâm bế quan trấn thủ đài chiến Vân Hải, bị Hư Thần Thiên Tôn trọng thương gần chết vì thay mặt sư đệ","chuong":"@c1516"},{"text":"Được xác nhận là phách thứ nhất của Thất Thải Tiên Tôn; cùng con gái Hồng Điệp bước vào chuyển thế đầu thai, nhờ Vương Lâm chiếu cố nữ nhi","chuong":"@c1696"},{"text":"Sau chuyển thế, ấn ký tự tiêu tan, khôi phục ký ức kiếp trước, rời tông môn tìm đến Thất Đạo Tông và thề cứu thê tử Hàm Yên","chuong":"@c1961"}]},"nguon":["@c1454","@c1456","@c1457","@c1459","@c1461","@c1462","@c1463","@c1464","@c1465","@c1466","@c1467","@c1468","@c1469","@c1470","@c1483","@c1492","@c1494","@c1516","@c1522","@c1523","@c1527","@c1533","@c1540","@c1541","@c1559","@c1560","@c1561","@c1562","@c1565","@c1566"],"aliases":["Thanh Thủy Tiên Quân","Bổn tiên quân"],"canhGioiCaoNhat":"Không Niết","vaiTro":"Phách thứ nhất Thất Thải Tiên Tôn — sư huynh đồng mạch Bạch Phàm của Vương Lâm, Tiên Quân mang sát nghiệp viễn cổ","tinhCach":"trọng nghĩa đồng môn, nhiều lần xả thân bảo hộ Vương Lâm không tính được mất; sát phạt quyết liệt, mang sát nghiệp cùng cực từ viễn cổ; thận trọng đa nghi, không dễ tin người nhưng giữ chữ tín; nặng tình thân, nguyện cùng con gái chuyển thế đầu thai","blurb":"Thanh Thủy vốn là thái tử Thanh Thủy Quốc trong thượng cổ tu chân giới; sau khi cố quốc bị diệt vong, trong tuyệt vọng bị truy sát đã thức tỉnh Cực Cảnh, quay về tàn sát kẻ thù rồi mang sát nghiệp cùng cực, tự phong ấn bản thân. Là sư huynh đồng mạch Bạch Phàm của Vương Lâm, ông nhiều lần hiện thân bảo hộ, truyền thừa tiên thuật Hoán Vũ và Tát Đậu Thành Binh, về sau dùng sát lục bổn nguyên phá Không Môn bước vào Không Niết Sơ Kỳ. Được xác nhận là phách thứ nhất của Thất Thải Tiên Tôn; cuối cùng ông cùng con gái Hồng Điệp bước vào chuyển thế, tự khôi phục ký ức kiếp trước và thề cứu thê tử Hàm "},{"id":"long-ban-tu","name":"Long Bàn Tử","cn":"龙蟠子","aliases":["Lão già bạch quang"],"gioiTinh":"nam","theLuc":[{"ten":"Tu Chân Liên Minh","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không Huyền","trangThai":"song","blurb":"Thái thượng trưởng lão Tu Chân Liên Minh, sư phụ của Trọng Huyền Tử, vốn tưởng đã tử vong khi tuổi thọ cạn kiệt. Năm đó hắn đem nguyên thần dung hợp với tu chân tinh tổng bộ Liên Minh, biến bản thân thành tinh hồn vạn cổ bất diệt; sau khi thức tỉnh đã nhiều lần thiêu đốt nguyên thần và tu vi để chiến đấu bảo vệ đồng đạo, từ việc mở Thất Thải Giới đến tàn sát tu sĩ giới ngoại tại Côn Hư và một mình tới Chu Tước Tinh tham chiến.","vaiTro":"Thái thượng trưởng lão Tu Chân Liên Minh — tinh hồn tu chân tinh tổng bộ","tinhCach":"Trí tuệ sâu xa, dám đoạt tạo hóa thiên địa; trung thành tận tụy bảo vệ Liên Minh; trọng ân nghĩa, sẵn sàng thiêu đốt bản thân vì đại nghĩa","tabs":{"diem":[{"text":"Thức tỉnh từ tu chân tinh tổng bộ, lộ thân phận thái thượng trưởng lão Liên Minh và sư phụ Trọng Huyền Tử","chuong":"@c1456"},{"text":"Dung hợp nguyên thần với tu chân tinh, tu vi bạo tăng lên Không Linh Trung Kỳ, đối đầu Vương Lâm","chuong":"@c1458"},{"text":"Tự thiêu nguyên thần bộc phát Không Huyền Sơ Kỳ, gánh tội thay đệ tử và mở phong ấn Thất Thải Giới","chuong":"@c1459"},{"text":"Cùng đệ tử tạo trận giết gần hết tu sĩ giới ngoại tại Côn Hư, giao chiến với điện chủ Thiên Phạt Điện","chuong":"@c1468"},{"text":"Thiêu đốt tu vi hòa hợp Sơn Hà Đồ, liên thủ ngăn cản Điện chủ và đánh Tần Cửu Duyên","chuong":"@c1469"},{"text":"Một mình tới Chu Tước Tinh dùng Sơn Hà Đồ chiến đấu bảo vệ đồng đạo","chuong":"@c1520"}],"kinhLich":[{"chuong":"@c1456","importance":"normal","mucCt":"ky","tieuDe":"Thức tỉnh — lộ bản chất tinh hồn tu chân tinh","text":"Là thái thượng trưởng lão Tu Chân Liên Minh, sư phụ Trọng Huyền Tử, tưởng đã tử vong. Năm đó tuổi thọ đã hết, trong lúc sắp chết đã đem nguyên thần dung hợp với tu chân tinh tổng bộ để tế luyện, biến bản thân thành tinh hồn vạn cổ bất diệt. Toàn bộ cấu trúc tinh cầu giống hình người khổng lồ không chân: tu chân tinh lớn là thân, hai hàng tinh cầu nhỏ là đôi bàn tay, lão già tóc bạc hư ảo là đầu. Khi hắc long tấn công gây nứt vỡ tu chân tinh, đạo khí tức thứ tư thức tỉnh, tu chân tinh sống lại, tuyên bố sẽ khiến kẻ xâm phạm hồn phi phách tán.","anchor":"Đem nguyên thần của bản thân dung hợp với tu chân tinh để cùng tế luyện"},{"chuong":"@c1458","importance":"normal","mucCt":"ky","tieuDe":"Dung hợp tu chân tinh, đối đầu Vương Lâm","text":"Sau khi dung hợp với tu chân tinh, tu vi bạo tăng lên Không Linh Trung Kỳ, phối hợp hương hỏa trong Sơn Hà Đồ phản kích Dịch Linh Ấn. Khi nghe Vương Lâm tuyên bố Liên Minh bị giới ngoại chiếm cứ và Trọng Huyền Tử là tay sai, sửng sốt dừng lại.","anchor":"Người xâm phạm Liên Minh ta, hồn bay phách tán, thân thể tiêu tan!"},{"chuong":"@c1459","importance":"major","mucCt":"ky","tieuDe":"Tự thiêu nguyên thần gánh tội, mở Thất Thải Giới","text":"Tỉnh lại sau giấc ngủ dài, nhận ra Vương Lâm xưng Phong Tôn thì nhớ ân tình năm xưa. Lôi Trọng Huyền Tử và hai đại trưởng lão từ tu chân tinh ra tra hỏi, giết Trương Tịch vì do dự, giết đại trưởng lão còn lại sau khi đọc ký ức. Tiết lộ mục đích thật của Tu Chân Liên Minh: nâng cao tu vi tu sĩ Côn Hư để đánh giới ngoại. Hồi tưởng Trọng Huyền Tử vốn là đồng tử ăn mày tên Tống nhi, đã tự tay điều dưỡng lấy thiên địa ngũ mạch tạo đạo cốt. Vái Vương Lâm một cái rồi vỗ ngực phun nguyên thần khí, tự thiêu đốt nguyên thần bộc phát sức mạnh Không Huyền Sơ Kỳ. Tuyên bố giết toàn bộ tu sĩ giới ngoại trong giới nội, phá hủy Thất Thải Giới bên ngoài, giành lại Triệu Hà. Cuốn Trọng Huyền Tử rời đi, phóng cuồng phong mở lối vào Thất Thải Giới cho Vương Lâm.","anchor":"Cái sai của ngươi hãy để cho vi sư thay ngươi đền tội"},{"importance":"bridge","mucCt":"gon","chuong":"@c1460","tieuDe":"Rời đi cùng Trọng Huyền Tử","text":"Cùng Trọng Huyền Tử rời đi, cơn cuồng phong do hắn gây ra phá tan hồng quang phong ấn trên Thất Thải Giới.","anchor":"mười vạn ngọn núi ở nơi này không phải là nằm trên mặt đất mà là được một con Huyền Vũ khổng lồ đã hóa đá nâng lên"},{"chuong":"@c1468","importance":"normal","mucCt":"vua","tieuDe":"Giết sạch tu sĩ giới ngoại, chiến đấu với điện chủ Thiên Phạt Điện","text":"Cùng đệ tử tạo trận giết chóc chấn động sao trời, giết gần hết tu sĩ giới ngoại tại Côn Hư. Đang chiến đấu với điện chủ Thiên Phạt Điện (Không Huyền sơ kỳ) trong Thất Thải Giới Triệu Hà.","anchor":"Trận giết chóc này là do một đôi sư đồ tạo nên, dưới tu vi tuyệt đối của Long Bàn Tử"},{"chuong":"@c1469","importance":"normal","mucCt":"ky","tieuDe":"Thiêu tu vi hòa hợp Sơn Hà Đồ, liên thủ đánh Điện chủ","text":"Ngăn cản Điện chủ đuổi giết Vương Lâm, mở Sơn Hà Đồ chắn đường khi Điện chủ muốn rút. Thiêu đốt tu vi, thân thể hòa hợp với Sơn Hà Đồ hóa thành bàn tay khổng lồ chụp xuống Điện chủ, bộc phát tu vi mạnh nhất đời. Sau đợt liên thủ bị phản lực đẩy lùi, phun nguyên thần khí, uể oải nhưng bình tĩnh.","anchor":"Sơn Hà Đồ liền ầm ầm mở ra chắn trước người hắn"},{"mucCt":"vua","text":"Triển khai Sơn Hà Đồ hợp lực đánh Tần Cửu Duyên. Linh hồn bị thiêu đốt được Hồng Sam Tử giúp dập tắt. Mang theo Trọng Huyền Tử rời đi, chờ trận chiến tiếp theo.","anchor":"Linh hồn bị thiếu đốt của Long Bàn Tử cuối cùng dưới sự trợ giúp của Hồng Sam Tử đã có dấu hiệu được dập tắt","bridge":true,"khoang":"@c1470"},{"chuong":"@c1520","importance":"normal","mucCt":"ky","tieuDe":"Tới Chu Tước Tinh dùng Sơn Hà Đồ bảo vệ","text":"Sau khi thức tỉnh, biết Phong Tôn chính là Vương Lâm, Long Bàn Tử một mình tới Chu Tước Tinh chiến đấu. Tu vi ngang Không Huyền, vung Sơn Hà Đồ bao phủ cả Chu Tước Tinh bảo vệ nó khỏi bị đánh nát. Cùng Tư Đồ Nam đấu nam tử áo thanh y nhưng bại lui. Khi Không Môn hiện, đồng tử co rút, ánh mắt sầu lo.","anchor":"lấy tu vi có thể sánh với không huyền của mình ở bên ngoài Chu Tước Tinh này, vung Sơn Hà Đồ"},{"mucCt":"vua","text":"Tham gia phản công giới ngoại nhưng bị sương mù tím quét trúng, phun máu. Thân thể tản ra rồi ngưng tụ lại gần trong suốt, vung tay áo cuốn Tư Đồ Nam và Lỗ Phu Tử rút vào Chu Tước Tinh.","anchor":"thân thể của Long Bàn Tử tản ra, sau đó ngưng tụ lại ở phía sau, cơ hồ trở nên trong suốt","bridge":true,"khoang":"@c1521"},{"chuong":"@c1523","importance":"bridge","mucCt":"gon","text":"Mỉm cười nhìn vòng xoáy như thấy lại thân ảnh phẫn nộ năm đó.","anchor":"Long Bàn Tử kia trên mặt lộ ra một nụ cười"},{"chuong":"@c1524","importance":"bridge","mucCt":"gon","text":"Chăm chú nhìn Vương Lâm mở Không Môn, thần sắc lo lắng cùng Lỗ Phu Tử và Thanh Long Thánh Hoàng.","anchor":"Đám người Lỗ Phu Tử, Long Bàn Tử, Thanh Long Thánh Hoàng đều chăm chú nhìn"}],"tuViMoc":[{"chuong":"@c1458","canhGioi":"Không Linh Trung Kỳ","text":"Sau khi dung hợp nguyên thần với tu chân tinh, tu vi bạo tăng từ Không Niết lên Không Linh Trung Kỳ.","importance":"minor"},{"chuong":"@c1459","canhGioi":"Không Huyền Sơ Kỳ (bộc phát tạm thời)","text":"Tự thiêu đốt nguyên thần, lấy sinh mạng bộc phát ra sức mạnh Không Huyền Sơ Kỳ.","importance":"major"}],"nhanMach":[{"ten":"Trọng Huyền Tử","tag":"su-mon","quanHe":"Đồ đệ","gap":"@c1456"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Kẻ tấn công tu chân tinh tổng bộ Liên Minh","gap":"@c1456"},{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Phong Tôn — ân nhân năm xưa","ghiChu":"Nhớ ân tình Phong Tôn, vái lạy xin gánh chịu tội lỗi, mở lối Thất Thải Giới cho Vương Lâm @c1459"},{"ten":"Trương Tịch","tag":"su-mon","quanHe":"Đồng tử hầu hạ / đại trưởng lão","ghiChu":"Từng ngồi hầu hạ khi Long Bàn Tử ngủ say, bị giết vì do dự không dám nói thật @c1459"},{"ten":"Vương Lâm","tag":"an-nhan","quanHe":"Biết Phong Tôn chính là Vương Lâm, vì hắn mà tới Chu Tước Tinh tử chiến"},{"ten":"Tư Đồ Nam","tag":"dong-minh","quanHe":"Cùng chiến đấu tại Chu Tước Tinh, hợp lực đấu nam tử áo thanh y"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1456","@c1458","@c1459","@c1460","@c1468","@c1469","@c1470","@c1520","@c1521","@c1523","@c1524"]},{"id":"than-cong-ho","name":"Thân Công Hổ","cn":"申公豹","aliases":[],"gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1456","importance":"bridge","mucCt":"gon","text":"Vương Lâm hỏi thăm tình trạng qua Viêm Lôi Tử, được biết vẫn còn sống ở La Thiên, dặn chiếu cố và gửi con hắc long hương hỏa thứ hai cho hắn như cơ duyên đáp lại hai chữ tôn chủ năm xưa.","anchor":"Thân Công Hổ kia với ta có chút quen biết, sau khi ngươi trở về La Thiên hãy nể mặt ta mà chiếu cố hắn một chút"},{"chuong":"@c1559","importance":"bridge","mucCt":"vua","text":"Ở cùng Tây Tử Phượng và Chiến Không Liệt hướng tây trong tinh trận.","anchor":"Bên cạnh nàng còn có chiến Không Liệt và Thân Công Hổ"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[{"ten":"Hắc long hương hỏa (con thứ hai)","trangThai":"dang-co","moTa":"Con hắc long hương hỏa phong ấn do Vương Lâm gửi qua Viêm Lôi Tử, đã bị bức ra hồn phách tu sĩ giới nội. Là cơ duyên Vương Lâm đáp lại hai chữ tôn chủ.","nguon":"@c1456"}],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Dâng đạo hồn quỳ bái Vương Lâm, tự nguyện xưng Tôn Chủ và trở thành tuỳ tùng","chuong":"@c0681"},{"text":"Kiên quyết tiến cử Hứa Mộc có tư cách tranh đệ nhất nhân La Thiên Tinh Vực","chuong":"@c0808"},{"text":"Từ chối bước vào Thăng Tiên trì, giữ con đường tu đạo bản thân thay vì đổi ý cảnh thành tiên nguyên","chuong":"@c0826"},{"text":"Quyết định chuyển thế đầu thai, tới bên cạnh Vương Lâm trước khi rời đi","chuong":"@c1694"},{"text":"Sau chuyển thế lại trở thành tông chủ một tông phái","chuong":"@c1955"}]},"nguon":["@c1456","@c1559"],"vaiTro":"Tuỳ tùng trung thành của Vương Lâm — Nhị cấp sứ giả Lôi Tiên Điện, người Thân Công tộc nam vực La Thiên","tinhCach":"biết nắm thời cơ nương tựa cường giả, dâng đạo hồn quy phục không do dự; sùng kính Vương Lâm đến mức cuồng nhiệt, lấy đó làm tín niệm tu hành; kiên định với con đường tu đạo bản thân, từ chối cơ duyên đổi ý cảnh; phản ứng nhanh nhạy khi lâm nguy","blurb":"Thân Công Hổ là tu sĩ Thân Công tộc ở nam vực La Thiên, Nhị cấp sứ giả Lôi Tiên Điện, tự xưng tu vi Dương Thật. Sau khi bị uy thế Vương Lâm áp chế tại Lôi Trì trong Lôi Ngục, hắn dâng đạo hồn xin nương tựa, từ đó trở thành tuỳ tùng trung thành theo Vương Lâm quan chiến và tham chiến qua nhiều biến cố lớn từ Lôi Tiên Giới sụp đổ đến tranh đoạt phong hào Nam vực. Hắn kiên quyết giữ con đường tu đạo bản thân khi từ chối bước vào Thăng Tiên trì, cuối cùng quyết định chuyển thế đầu thai và sau đó lại trở thành tông chủ một tông phái."},{"id":"bach-pham","name":"Bạch Phàm","cn":"百凡","gioiTinh":"nam","tabs":{"kinhLich":[{"chuong":"@c1457","importance":"bridge","mucCt":"gon","text":"Được nhắc lại: năm đó phong ấn Thanh Thủy nhưng vì thương hại nên lưu hồn phách cho hắn.","anchor":"Bạch Phàm phong ấn lại. Vì sư tôn của hắn thương hại, nên lưu lại hồn phách cho hắn"},{"importance":"bridge","mucCt":"vua","chuong":"@c1462","tieuDe":"Xuất hiện trong ký ức Thanh Thủy","text":"Xuất hiện trong ký ức Thanh Thủy tại Tiên Giới, thần sắc hiền lành nhìn Thanh Thủy và nữ tử ôn nhu trìu mến. Khi Thanh Thủy bị kích phát điên cuồng, đứng đằng xa ngơ ngác nhìn bầu trời, cảm nhận được điều bất thường.","anchor":"Bạch Phàm đang đứng. Hắn ngơ ngác nhìn bầu trời, dường như hắn cảm nhận được một điều gì đó!"},{"chuong":"@c1469","importance":"bridge","mucCt":"gon","text":"Được Điện chủ Thiên Phạt Điện nhắc tới khi nhận ra Bạch Phàm Thuật do Thanh Thủy thi triển, nói Bạch Phàm đã chết.","anchor":"Bạch Phàm đã chết, ngươi là…ngươi là Thanh Thuỷ"},{"chuong":"@c1487","importance":"normal","mucCt":"gon","tieuDe":"Lộ thân phận phản đồ Âm Nguyệt Tông","text":"Nữ tử tiên phi tiết lộ Bạch Phàm trước khi bị lão già nhận làm tùy tùng từng là phản đồ của Âm Nguyệt Tông.","anchor":"trước khi Bạch Phàm được lão già đó nhận làm tùy tùng thì từng là phản đồ của Âm Nguyệt tông"},{"chuong":"@c1533","importance":"bridge","mucCt":"vua","text":"Được Chân Giả Đạo của Vương Lâm biến ra với tư thế chỉ tay lên trời và cười điên cuồng, trở thành một phần tiếng gào phản thiên.","anchor":"có Bạch Phàm chỉ tay lên trời, điên cuồng cười lớn"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Từng ra tay đánh bại Thanh Thủy khi đồ đệ nhập ma gây sát kiếp.","chuong":"@c0746"},{"text":"Bố trí trận pháp trị thương trên chín phong ấn cho Thanh Thủy.","chuong":"@c0747"},{"text":"Dùng Hô Phong trừng phạt Long Đạo Tử vì phạm tiên điều, đánh tan thân thể và xương cốt.","chuong":"@c0768"},{"text":"Được nhắc là người để lại ba thức thần thông Hô Phong, Hoán Vũ và Vãi Đậu Thành Binh.","chuong":"@c0803"},{"text":"Khi sáng tạo mỗi tiên thuật, dùng thần thông cả đời cúng tế một pháp bảo dung nhập quy tắc thiên đạo.","chuong":"@c1047"},{"text":"Được Lam Mộng Đạo Tôn xác nhận là Tiên Đế, Chí tôn của Lôi giới, nắm Hô Phong đạo và Vũ đạo.","chuong":"@c1244"}]},"nguon":["@c1457","@c1462","@c1469","@c1487","@c1533"],"trangThai":"khong-ro","vaiTro":"Tiên Đế viễn cổ — sư tôn Thanh Thủy, Chí tôn Lôi giới","tinhCach":"nghiêm minh với tiên điều; trọng tình thầy trò; có chí giáo hóa nhân gian","blurb":"Bạch Phàm là Tiên Đế thời viễn cổ, từng là phản đồ Âm Nguyệt Tông trước khi được xác nhận là Chí tôn của Lôi giới, nắm Hô Phong đạo và Vũ đạo trong lục đạo tam trọng. Ông là sư tôn của Thanh Thủy, để lại hệ tiên thuật gồm Hô Phong, Hoán Vũ và Vãi Đậu Thành Binh; mỗi thuật ẩn chứa pháp bảo được ông dùng thần thông cả đời cúng tế, dung nhập quy tắc thiên đạo. Khi Thanh Thủy nhập ma gây sát kiếp, Bạch Phàm đánh bại và phong ấn đồ đệ, nhưng vì thương hại nên vẫn lưu hồn phách cho hắn."},{"id":"lao-nhan-tien-di-toc-toc-bac","name":"Lão nhân Tiên Di tộc tóc bạc","gioiTinh":"nam","tabs":{"kinhLich":[{"chuong":"@c1457","importance":"normal","mucCt":"vua","tieuDe":"Kích hoạt Sơn Hà Đồ bảo vệ Liên Minh","text":"Đánh ấn quyết kích hoạt Sơn Hà Đồ từ lòng đất tu chân tinh, hai dãy núi nổi lên tựa hai thanh trục mở ra cuộn tranh sơn thủy mười vạn trượng. Hô bảo vệ Liên Minh, tạo lực hút khổng lồ kèm thời gian trôi nhanh nhắm vào Vương Lâm.","anchor":"Sơn Hà Đồ, bảo vệ Liên Minh ta!"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Cùng hơn trăm tộc nhân xuất hiện, cung kính gọi Vương Lâm là Thượng tiên và nhận ra Tử Mẫu Đạo Khô","chuong":"@c0755"},{"text":"Dẫn Vương Lâm tới nơi cư trú bộ tộc, giải thích trận pháp tiên vương và kể lại tai họa Vụ thú","chuong":"@c0756"},{"text":"Chỉ huy ứng chiến khi sương đen và Vụ thú ập đến, xin Vương Lâm tha cho Tháp Sơn","chuong":"@c0757"},{"text":"Bắt quyết dùng ký hiệu để đối phó hắc khí khi Tháp Sơn dẫn Vương Lâm xuống phía dưới","chuong":"@c0759"},{"text":"Đại diện Tiên Tuyển Tộc xin Vương Lâm cho một tu chân tinh để tộc nhân dung thân tại La Thiên","chuong":"@c0770"},{"text":"Đánh ấn quyết kích hoạt Sơn Hà Đồ từ lòng đất tu chân tinh, triển khai phòng tuyến bảo vệ Liên Minh","chuong":"@c1457"}]},"nguon":["@c1457"],"trangThai":"song","vaiTro":"Tổ tiên tộc Tiên Di-Tiên Tuyển — đại diện bộ tộc tiếp đón và quy phục Vương Lâm","tinhCach":"cung kính trước cường giả; thận trọng trước hiểm nguy; tận tụy bảo hộ tộc nhân; quyết đoán khi lâm trận","blurb":"Lão nhân tóc bạc là tiên tổ của tộc Tiên Di-Tiên Tuyển, người đại diện bộ tộc tiếp xúc với Vương Lâm — cung kính gọi hắn là Thượng tiên khi nhận ra Tử Mẫu Đạo Khô. Ông dẫn dắt tộc nhân qua tai họa Vụ thú, thuật lại trận pháp tiên vương, sau đó xin cho bộ tộc dung thân tại một tu chân tinh thuộc La Thiên. Về sau, khi Liên Minh lâm nguy, lão nhân đánh ấn quyết kích hoạt Sơn Hà Đồ từ lòng đất tu chân tinh để bảo vệ thế lực này."},{"id":"tham-lang","name":"Tham Lang","gioiTinh":"nam","tabs":{"kinhLich":[{"chuong":"@c1457","importance":"bridge","mucCt":"gon","text":"Được nhắc: pháp bảo bình phong của Tham Lang có dấu ấn Sơn Hà Đồ, nay Vương Lâm mới thấy bản thể chân chính.","anchor":"chính là pháp bào giống như là một bức bình phong của Tham Lang, trên bức bình phong kia có dấu ấu Sơn Hà Đồ"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Từng đạt Âm Hư chi cảnh, vượt trên Vấn Đỉnh và chỉ kém Dương Thật.","chuong":"@c0571"},{"text":"Khống chế Văn thú đầu đàn bằng Thất Ma Châm, dùng bầy Văn thú vây khốn Đại La Kiếm Tông.","chuong":"@c0602"},{"text":"Vì tham bảo vào Vân Hà Tinh đào Kim Viêm quáng mạch, chạm tới Nguyệt Hoa nên bị Vọng Nguyệt nuốt vào và mắc kẹt.","chuong":"@c0668"},{"text":"Thoát khỏi lạc ấn sau biến cố Vọng Nguyệt, rơi xuống một tinh cầu nguyên thủy trong tình trạng thân thể vỡ nát, nguyên thần bị thương.","chuong":"@c0674"},{"text":"Ở vùng đất Điên Lạc trở thành đại cung phụng nổi danh, nhờ lai lịch thần bí và số lượng pháp bảo lớn; sau đó đạt Toái Niết trung kỳ nhờ được Điên Lạc đại đế ban đan dược.","chuong":"@c1295"},{"text":"Được xác nhận là phách thứ tư màu vàng của Thất Thải Tiên Tôn, phách đại biểu khí vận và cơ duyên cả đời.","chuong":"@c1650"}]},"nguon":["@c1457"],"trangThai":"song","vaiTro":"Lão tu sĩ lưu lạc — phách thứ tư của Thất Thải Tiên Tôn","tinhCach":"Tham bảo liều thân; tàn bạo cưỡng ép Văn thú; giỏi bỏ chạy giữ mạng; sợ hãi Vương Lâm","blurb":"Tham Lang là lão tu sĩ từng cư ngụ Chu Tước Tinh hơn vạn năm, về sau lưu lạc qua Đại La Kiếm Tông, La Thiên Tinh Vực, vùng đất Điên Lạc và Tiên Cương. Hắn nhiều lần vì tham bảo mà rơi vào hiểm địa, mất pháp bảo hoặc bị Vương Lâm truy đuổi, nhưng vẫn sống sót nhờ nhiều thủ đoạn bảo mệnh. Về sau Tham Lang được xác nhận là phách thứ tư màu vàng của Thất Thải Tiên Tôn, đại biểu khí vận và cơ duyên cả đời."},{"id":"thanh-nien-mi-tam-khong-an-ky","name":"Thanh niên mi tâm không ấn ký","gioiTinh":"nam","aliases":[],"theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Thanh niên bí ẩn ở phía bắc Triệu Hà Tinh Vực, mi tâm không có ấn ký, đang bấm độn tìm chỗ mà Mã sư bá chỉ dẫn. Cảm nhận tiên khí Vương Lâm, kinh hoàng nhận ra đó là tiên khí hoàng tộc tiên.","vaiTro":"Nhân vật bí ẩn xuất hiện cuối chương, liên quan Mã sư bá","tinhCach":"Thận trọng; kinh hoàng trước sức mạnh hoàng tộc tiên","tabs":{"diem":[{"text":"Mi tâm không có ấn ký, nhận ra tiên khí cấp hoàng tộc tiên vượt xa cả Mã sư bá","chuong":"@c1457"}],"kinhLich":[{"chuong":"@c1457","importance":"normal","mucCt":"vua","tieuDe":"Cảm ứng tiên khí hoàng tộc tại Triệu Hà","text":"Ở phía bắc Triệu Hà Tinh Vực đang bấm độn tìm nơi Mã sư bá chỉ dẫn nhưng chưa thấy lối vào. Cảm nhận tiên khí lan tỏa, nhận ra là hoàng tộc tiên, kinh ngạc tột độ.","anchor":"Đây là hoàng tộc tiên! Là ai vậy! Là ai đã giáng lâm vậy!"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1457"]},{"id":"chien-lao-quy","name":"Chiến lão quỷ","gioiTinh":"nam","tabs":{"kinhLich":[{"chuong":"@c1457","importance":"bridge","mucCt":"gon","text":"Bị tiên khí Dịch Linh Ấn của Vương Lâm lan tỏa khiến khiếp sợ.","anchor":"Cũng bị tiên khí này khiến cho khiếp sợ còn có Chiến lão quỷ thần bí kia"},{"chuong":"@c1458","importance":"normal","mucCt":"ky","tieuDe":"Cảm nhận tiên khí hoàng tộc tiên","text":"Ẩn cư trong vầng sáng ngàn trượng tại Lôi Tiên Giới hoang tàn, đang quan sát đường vân trên lá cây thì cảm nhận được tiên khí hoàng tộc tiên huyết mạch La Huyền Thiên Địa màu vàng. Tự tiết lộ năm xưa có được truyền thừa tiên nhân, tu vi hiện đạt Không Kiếp Sơ Kỳ tương đương Địa Tiên. Nảy ý muốn lấy huyết mạch của tiên nhân phát ra tiên khí.","anchor":"Năm đó ta có được cơ duyên, lấy được truyền thừa của tiên nhân, đến nay tu vi đã đạt tới Không Kiếp Sơ Kỳ, tương đương với Địa Tiên"},{"importance":"bridge","mucCt":"gon","chuong":"@c1492","text":"Từ Lôi tiên giới ở La Thiên bước ra, dùng tốc độ cực nhanh vọt tới Côn Hư, là kẻ Chưởng Tôn kiêng kỵ nhất.","anchor":"Chiến lão quỷ thần bí khó lường từ trong Lôi tiên giới cất bước đi ra"},{"chuong":"@c1493","importance":"normal","mucCt":"vua","tieuDe":"Tấn công Chưởng Tôn, quan sát hắc động tầng phủ bích rồi rời đi","text":"Xuất hiện vô thanh khi Chưởng Tôn mất cảnh giác, điểm một chỉ khiến Chưởng Tôn bị thương tan vỡ biến mất. Nhìn hắc động suy tư, tiếc nuối máu tiên thể, nghi ngờ người điên là người trong ký ức kia, nhận xét hắc động tỏa khí tức tầng phủ bích — một bước lên trời, một bước xuống đất. Trầm mặc rồi rời đi.","anchor":"Tới chậm một bước. Đáng tiếc cho máu tiên thể. Còn có người điên kia.chẳng lẽ hắn chính là người trong ký ức kia."},{"mucCt":"vua","text":"Áo tím hiện thân ở xa quan sát thiên kiếp, nhận ra tiễn khí mạnh và suy đoán Vương Lâm đã tìm được mũi tên. Nhắc sáu đạo bổn nguyên khiến Vương Lâm vượt Không Niết lên Không Linh trung kỳ, rồi thấy tay mình cũng có biểu tượng Vạn Không Cốt Môn và nghi ngờ Vương Lâm là người thứ ba.","anchor":"Chẳng lẽ hắn chính là người thứ ba hay sao Chiến lão quỷ nhíu mày","bridge":true,"khoang":"@c1531"},{"mucCt":"vua","text":"Quan sát thiên kiếp của Vương Lâm, ban đầu thất vọng cho rằng hắn không phải người thứ ba và định rời đi. Khi thấy Vương Lâm bước tới chạm trực tiếp vào thiên lôi xanh, Chiến lão quỷ lập tức quay lại, hai mắt sáng rực đến cực điểm.","anchor":"đột nhiên hắn kêu lên một tiếng, xoay mạnh người lại, vẻ thất vọng trong hai mắt lộ ra hào quang sáng ngời đến cực điểm.","bridge":true,"khoang":"@c1532"},{"mucCt":"vua","text":"Ở ngoài sương mù quan sát biểu hiện của Vương Lâm, ánh mắt lộ vẻ tham lam chưa từng có. Tự nhận định Vương Lâm có ba phần khả năng là người thứ ba.","anchor":"Có ba phần khả năng hắn chính là người thứ ba","bridge":true,"khoang":"@c1533"},{"mucCt":"vua","text":"Tỏ ra hưng phấn khi nhận ra Tam Thiên phất trần và Trấn Tiên bảo tháp, đồng thời nhắc thêm Phong Mệnh, tiết lộ năm đó có người đã đưa ba pháp bảo này vào khi bài trí thiên kiếp trong phủ.","anchor":"Năm đó khi hắn bài trí thiên kiếp trong phủ đã đem ba Pháp Bảo này đưa vào trong đó","bridge":true,"khoang":"@c1534"},{"mucCt":"ky","text":"Không bị khí tức Phong Mệnh Hoàn ảnh hưởng, nhận ra pháp bảo này từ trí nhớ, biết nó có danh tiếng tại Tiên Cương đại lục. Lão đặt kỳ vọng rằng nếu Vương Lâm thu phục được bảo vật thì khả năng trở thành 'người thứ ba' càng cao.","anchor":"Phong Mệnh Hoàn! Vật này chính là thứ trong trí nhớ của hắn","bridge":true,"khoang":"@c1535"},{"mucCt":"vua","text":"Đứng ngoài trăm vạn trượng sương mù quan sát Vương Lâm trong thiên kiếp, Chiến lão quỷ kích động khi thấy hắn nhanh chóng thu phục bảo vật. Hắn nâng khả năng Vương Lâm là người thứ ba từ ba phần lên năm phần, nhắc rằng bảy màu ở bên ngoài phủ cũng tìm vô số năm mà chưa tìm được.","anchor":"Trong thời gian ngắn như vậy, hắn.hắn không ngờ lại thu phục được bảo vật này!","bridge":true,"khoang":"@c1536"}],"tuViMoc":[{"chuong":"@c1458","canhGioi":"Không Kiếp Sơ Kỳ","text":"Tự tiết lộ tu vi đạt Không Kiếp Sơ Kỳ, tương đương Địa Tiên, nhờ truyền thừa tiên nhân năm xưa.","importance":"major"}],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Được Chưởng Tôn nhắc đến khi giết Chiến Tinh Dã, là kẻ khiến Chưởng Tôn kiêng kỵ nhất","chuong":"@c1134"},{"text":"Hé lộ tiên duyên: khi độ huyền kiếp thất bại, toàn thân thối rữa, nguyên thần tan nát, bị hồn phách thứ hai của Thất Thải Tiên Tôn ký sinh","chuong":"@c1651"},{"text":"Cưỡng ép vái lạy anh hồn đồng đạo cũ, tiết lộ bí mật tiên duyên tại Côn Hư tinh vực","chuong":"@c1571"},{"text":"Cắn nuốt đạo nhân bảy màu, tu vi gần đạt mức Thất Thải Tiên Tôn, sau đó tách hồn phách Thất Thải Tiên Tôn khỏi thân thể","chuong":"@c1681"},{"text":"Khôi phục bá đạo năm xưa, giao chiến với Vương Lâm nhưng bị Tâm Động Lôi Âm áp chế","chuong":"@c1682"},{"text":"Tử vong trong biến cố giải thoát khỏi Thất Thải tại cổ mộ, khi cảm nhận nguy cơ sinh tử từ phong ấn dung hợp khí tức Tiên Cương","chuong":"@c1690"}]},"nguon":["@c1457","@c1458","@c1492","@c1493","@c1531","@c1532","@c1533","@c1534","@c1535","@c1536"],"canhGioiCaoNhat":"Không Kiếp Sơ Kỳ (tương đương Địa Tiên)","trangThai":"song","vaiTro":"Sư phụ Chiến Tinh Dã — cường giả Không Kiếp bị hồn phách Thất Thải Tiên Tôn ký sinh","tinhCach":"Ẩn nhẫn thâm trầm, thường quan sát từ xa trước khi hành động; bá đạo quyết liệt khi ra tay; tham lam trước pháp bảo và hồn thứ ba của Thất Thải; đa nghi cẩn trọng, biết giữ cân bằng thế lực giữa các phe","blurb":"Chiến Lão Quỷ, bí danh Không Kiếp, là cường giả Không Kiếp Sơ Kỳ tương đương Địa Tiên, sư phụ của Chiến Tinh Dã và là kẻ khiến Chưởng Tôn kiêng kỵ nhất. Hắn ẩn trong Lôi Tiên Giới, nhiều lần bí mật theo dõi Vương Lâm cùng tứ đại chiến tướng trong cuộc truy tìm hồn thứ ba của Thất Thải Tiên Tôn, song bản thân cũng bị hồn phách Thất Thải ký sinh suốt từ khi độ huyền kiếp thất bại. Về sau hắn cắn nuốt đạo nhân bảy màu khiến tu vi gần đạt mức Thất Thải Tiên Tôn, tự tách hồn phách ký sinh và khôi phục bá đạo năm xưa, nhưng cuối cùng tử vong trong biến cố giải thoát khỏi Thất Thải tại cổ mộ.","cn":"战老鬼","aliases":["Chiến Không Liệt"]},{"id":"bach-ho","name":"Bạch Hổ","cn":"白虎","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Viễn cổ Tiên Tôn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"mat-tich","tabs":{"kinhLich":[{"chuong":"@c1458","importance":"normal","mucCt":"ky","tieuDe":"Bị phong ấn tại Viễn cổ Tinh Vực","text":"Bị phong ấn trong mi tâm pho tượng Cổ Thần khổng lồ tại Viễn cổ Tinh Vực cùng ba chiến tướng khác. Cảm nhận tiên lực tinh thuần, muốn vươn tay ra ngoài lấy cho chủ nhân để khôi phục trí nhớ nhưng bị phong ấn kỳ dị bắn trở lại, gào phẫn nộ.","anchor":"Tiên lực tiên lực thật là tinh thuần. Nếu chủ nhân có thể lấy được, nhất định sẽ nhanh chóng khôi phục lại được trí nhớ!"},{"chuong":"@c1550","importance":"bridge","mucCt":"gon","text":"Hỏi Vương Lâm tại sao cung Lý Quảng lại trong tay hắn, bị cự tuyệt trả lời, nghệt mặt không nói thêm.","anchor":"Cây cung của Lý Quảng tại sao lại ở trong tay ngươi!"}],"tuViMoc":[],"nhanMach":[{"ten":"Viễn cổ Tiên Tôn","tag":"su-mon","quanHe":"Chủ nhân","ghiChu":"Trung thành tuyệt đối, muốn lấy tiên lực cho chủ nhân khôi phục trí nhớ"},{"ten":"Chu Tước","tag":"dong-minh","quanHe":"Đồng liêu chiến tướng","ghiChu":"Cùng bị phong ấn"},{"ten":"Huyền Vũ","tag":"dong-minh","quanHe":"Đồng liêu chiến tướng","ghiChu":"Cùng bị phong ấn"},{"ten":"Thanh Long","tag":"dong-minh","quanHe":"Đồng liêu chiến tướng","ghiChu":"Cùng bị phong ấn"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Tử chiến chặn đại quân Liên Minh, giết nhiều trưởng lão chủ chốt trong đại chiến năm xưa","chuong":"@c0976"},{"text":"Bị phong ấn trong mi tâm pho tượng Cổ Thần tại Viễn cổ Tinh Vực cùng ba chiến tướng khác","chuong":"@c1458"},{"text":"Là người đầu tiên bước vào tàn giới, thiết lập toàn bộ quy tắc tại đó","chuong":"@c1661"},{"text":"Bại trận trước Vương Lâm trong giới cờ, bị uy áp trấn phục vàràng buộc nhận lệnh","chuong":"@c1663"},{"text":"Trọng thương vẫn cõng Chu Tước và Huyền Vũ bỏ chạy, từ chối đầu hàng khi bị truy sát tại Đan Hải","chuong":"@c1749"},{"text":"Được Vương Lâm cứu khỏi hai tu sĩ Lục Ma Châu và cùng hộ pháp phá cấm chế Đan Hải","chuong":"@c1750"}]},"nguon":["@c1458","@c1549","@c1550"],"vaiTro":"Một trong Tứ Thánh Tông — chiến tướng bị phong ấn tại Viễn cổ Tinh Vực, sau theo Vương Lâm","tinhCach":"trực tính, hay trào phúng khi chất vấn; dễ chấn động trước sự kiện bất ngờ; tự tin vào lợi thế huyết mạch tiên nhân; kiên cường, không chịu đầu hàng dù trọng thương","blurb":"Bạch Hổ là một trong bốn chiến tướng thuộc Tứ Thánh Tông, từng tử chiến chặn đại quân Liên Minh trong đại chiến năm xưa. Hắn bị phong ấn trong mi tâm pho tượng Cổ Thần khổng lồ tại Viễn cổ Tinh Vực, sau khi thoát ra đã giao chiến rồi quy phục Vương Lâm, trở thành người thiết lập toàn bộ quy tắc tại tàn giới nhưng cuối cùng bại trận trong giới cờ và bị ràng buộc nhận lệnh. Về sau hắn cùng Chu Tước và Huyền Vũ nhiều lần đồng hành, từng bị truy sát tại Đan Hải và được Vương Lâm cứu giúp."},{"id":"chu-tuoc","name":"Chu Tước","cn":"朱雀","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Viễn cổ Tiên Tôn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","tabs":{"kinhLich":[{"mucCt":"vua","text":"Trấn an Bạch Hổ rằng phong ấn sắp hết hiệu lực, tuyên bố có kế hoạch đang thực hiện và sẽ không thất bại.","anchor":"Bạch Hổ, đừng có lãng phí tiên lực. Phong ấn này đã giam giữ chúng ta bao nhiêu năm không còn dùng được bao lâu nữa","bridge":true,"khoang":"@c1458"},{"chuong":"@c1479","importance":"bridge","mucCt":"gon","tieuDe":"","text":"Được nhắc: năm đó từng nói tầng 19 có tàn hồn lão tổ Phù Văn tộc, nhưng Vương Lâm nhận ra điều này không đúng.","anchor":"Chu Tước Tử năm đó từng nói rằng tầng mười chín có một tia tàn hồn của lão tổ Phù Văn tộc"},{"chuong":"@c1546","importance":"bridge","mucCt":"gon","text":"Ẩn trong vòng xoáy pho tượng, chưa xuất hiện dù Vương Lâm gọi ra gặp để giao dịch và ra tối hậu thư lần cuối.","anchor":"Chu Tước chiến tướng dưới chướng của Thất Thải Tiên Tôn, ngươi hãy ra đây gặp ta!"},{"chuong":"@c1550","importance":"normal","mucCt":"ky","tieuDe":"Phân thân xuất hiện, tiết lộ quan hệ bổn tôn–phân thân","text":"Chu Tước đời thứ nhất cuối cùng xuất hiện tại Viễn Cổ Tiên Vực, mặc hồng bào, bộ dạng lão già cực giống Chu Tước ở Điên Lạc. Tiết lộ trong tứ đại chiến tướng chỉ mình hắn lưu bổn tôn ở bên ngoài (vùng đất Điên Lạc), bản thân đang ở đây là phân thân. Thời gian quá lâu, bổn tôn không còn thao túng phân thân, chỉ liên hệ suy nghĩ. Bổn tôn mệt mỏi muốn về quê hương, phân thân muốn đi tìm Tiên Tôn. Cảnh báo Vương Lâm rằng mở cửa bên này thì Viễn Cổ Tiên Vực giới ngoại cũng mở. Trầm mặc trước yêu cầu giao dịch.","anchor":"Ở vùng đất Điên Lạc là bổn tôn của lão phu"}],"tuViMoc":[],"nhanMach":[{"ten":"Viễn cổ Tiên Tôn","tag":"su-mon","quanHe":"Chủ nhân","ghiChu":""},{"ten":"Bạch Hổ","tag":"dong-minh","quanHe":"Đồng liêu chiến tướng","ghiChu":""},{"ten":"Huyền Vũ","tag":"dong-minh","quanHe":"Đồng liêu chiến tướng","ghiChu":""},{"ten":"Thanh Long","tag":"dong-minh","quanHe":"Đồng liêu chiến tướng","ghiChu":""},{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Đối tượng đàm phán giao dịch","ghiChu":"Vương Lâm xưng vãn bối, đề xuất giao dịch hợp tác."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1458","@c1479","@c1515","@c1546","@c1550"]},{"id":"huyen-vu","name":"Huyền Vũ","cn":"玄武","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Viễn cổ Tiên Tôn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1458","importance":"bridge","mucCt":"gon","text":"Hỏi Chu Tước về khả năng thành công của kế hoạch bằng thanh âm âm trầm.","anchor":"Chu Tước, ngươi có nhiều mưu lược, kế hoạch kia có bao nhiêu khả năng thành công!"},{"importance":"normal","mucCt":"vua","chuong":"@c1462","tieuDe":"Bị Vương Lâm đập nứt mai","text":"Là mấu chốt trận pháp trấn áp hồn phách Thanh Thủy, chưa thật sự chết mà giống đang ngủ say. Chịu mười quyền thất tinh Cổ Thần không nứt, cuối cùng bị Vương Lâm hóa Cổ Thần ngàn trượng dùng cả hai tay đập, mai phát ra tiếng rắc rắc.","anchor":"cái mai cứng như đá của Huyền Vũ kia phát ra những tiếng rắc rắc!"},{"chuong":"@c1550","importance":"bridge","mucCt":"gon","text":"Trầm mặc hồi lâu rồi hỏi Vương Lâm giao dịch gì, mở đường cho cuộc đàm phán.","anchor":"Là giao dịch gì!"}],"tuViMoc":[],"nhanMach":[{"ten":"Viễn cổ Tiên Tôn","tag":"su-mon","quanHe":"Chủ nhân","ghiChu":""},{"ten":"Chu Tước","tag":"dong-minh","quanHe":"Đồng liêu chiến tướng","ghiChu":""},{"ten":"Bạch Hổ","tag":"dong-minh","quanHe":"Đồng liêu chiến tướng","ghiChu":""},{"ten":"Thanh Long","tag":"dong-minh","quanHe":"Đồng liêu chiến tướng","ghiChu":""}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1458","@c1462","@c1550"]},{"id":"thanh-long","name":"Thanh Long","cn":"青龙","aliases":["lão già mặc thanh y"],"gioiTinh":"nam","theLuc":[{"ten":"Viễn cổ Tiên Tôn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1458","importance":"bridge","mucCt":"gon","text":"Được nhắc tên là một trong tứ đại chiến tướng bị phong ấn tại Viễn cổ Tinh Vực, không có lời thoại riêng.","anchor":"Bốn người đang bị bốn pho tượng khổng lồ này phong ấn không ngờ chính là tứ đại chiến tướng của Viễn cổ Tiên Tôn"},{"chuong":"@c1549","importance":"normal","mucCt":"vua","tieuDe":"Đánh lén Vương Lâm thất bại, bị Cổ Tộc Bất Diệt chỉ bức lùi","text":"Từ dòng xoáy mi tâm pho tượng bước ra, dung hợp hư ảnh Thanh Long dùng một chỉ đánh lén Vương Lâm. Bị Cổ Tộc Bất Diệt chỉ đánh bại, hư ảnh Thanh Long sụp đổ, phun máu lùi hơn trăm trượng. Nhận ra cung Lý Quảng, sửng sốt lùi lại theo tiềm thức.","anchor":"Cung của Lý Quảng!"},{"chuong":"@c1550","importance":"normal","mucCt":"vua","tieuDe":"Phân tích điểm yếu cung Lý Quảng và tiết lộ cơ chế phòng thủ 100 năm","text":"Chỉ ra Vương Lâm dùng giọt máu tiên nhân bất diệt thể giương cung nhưng không phải tiên nhân nên chỉ bắn được vài mũi tên. Tiết lộ trước đó tứ đại chiến tướng đã giao pháp bảo tiên nhân cho một người hạ giới dung nhập đại trận hạ giới, chống cự được 100 năm, đã qua hơn 90 năm, còn 3 năm nữa.","anchor":"Chúng ta đã đưa cho hắn một loại pháp bảo của tiên nhân dung nhập vào trong một đại trận của hạ giới"}],"tuViMoc":[],"nhanMach":[{"ten":"Viễn cổ Tiên Tôn","tag":"su-mon","quanHe":"Chủ nhân","ghiChu":""},{"ten":"Bạch Hổ","tag":"dong-minh","quanHe":"Đồng liêu chiến tướng","ghiChu":""},{"ten":"Chu Tước","tag":"dong-minh","quanHe":"Đồng liêu chiến tướng","ghiChu":""},{"ten":"Huyền Vũ","tag":"dong-minh","quanHe":"Đồng liêu chiến tướng","ghiChu":""}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Xưng Thánh Hoàng, chỉnh hợp Tứ Thánh Tông thành một tông và thu thái cổ thánh khí","chuong":"@c1054"},{"text":"Một mình tiến vào tinh vực Thi Âm Tông uy hiếp, bị Thác Sâm trọng thương","chuong":"@c147"},{"text":"Dung hợp hư ảnh Thanh Long đánh lén Vương Lâm thất bại, bị Cổ Tộc Bất Diệt chỉ bức lùi","chuong":"@c1549"},{"text":"Liên thủ cùng ba chiến tướng vẫn bị Khai Thiên Phủ chém tan, kinh hãi nhận ra thiên đạo","chuong":"@c1633"},{"text":"Tử vong trong vụ nổ hủy diệt chín mặt trời va tiễn thứ ba","chuong":"@c1670"}]},"nguon":["@c1458","@c1549","@c1550"],"vaiTro":"Tứ đại chiến tướng Viễn cổ Tinh Vực — danh vị Thanh Long trong Tứ Thánh","tinhCach":"hành sự quỷ quyệt, thiên về đánh lén; phân tích chiến cục lạnh lùng, thấu đáo; thận trọng, kiêng kị trước hiểm nguy chưa lường được","blurb":"Thanh Long là một trong Tứ Thánh, thuộc hàng tứ đại chiến tướng từng bị phong ấn tại Viễn cổ Tinh Vực, sau khi thoát phong ấn đã xưng Thánh Hoàng và chỉnh hợp Tứ Thánh Tông thành một tông phái duy nhất. Nhiều lần giao chiến với Vương Lâm — từ đánh lén bằng hư ảnh Thanh Long bất thành đến liên thủ cùng ba chiến tướng khác vẫn thất bại trước Khai Thiên Phủ — và cuối cùng tử vong trong vụ nổ hủy diệt của chín mặt trời va tiễn thứ ba."},{"id":"truong-tich","name":"Trương Tịch","cn":"张籍","aliases":[],"gioiTinh":"nam","vaiTro":"Đại trưởng lão Tu Chân Liên Minh, từng là đồng tử hầu hạ Long Bàn Tử","tinhCach":"Do dự, sợ quyền lực","blurb":"Một trong hai đại trưởng lão Tu Chân Liên Minh, vốn là đồng tử ngồi hầu hạ Long Bàn Tử khi ngủ say. Bị Long Bàn Tử giết vì do dự không dám nói thật.","theLuc":[{"ten":"Tu Chân Liên Minh","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"tu-vong","tabs":{"diem":[{"text":"Từng là đồng tử hầu hạ Long Bàn Tử khi ngủ say, sau thành đại trưởng lão Liên Minh","chuong":"@c1459"},{"text":"Từng là đồng tử hầu hạ Long Bàn Tử, sau thành đại trưởng lão Liên Minh, bị giết vì do dự khi sư tôn tra hỏi","chuong":"@c1459"}],"kinhLich":[{"chuong":"@c1459","importance":"normal","mucCt":"gon","tieuDe":"Bị Long Bàn Tử giết vì do dự","text":"Bị Long Bàn Tử hỏi lời Vương Lâm thật hay giả, do dự liếc nhìn Trọng Huyền Tử, bị mắng rồi bị giết tại chỗ.","anchor":"Đồ rác rưởi vô dụng!"}],"tuViMoc":[],"nhanMach":[{"ten":"Long Bàn Tử","tag":"su-mon","quanHe":"Sư tôn, từng hầu hạ khi Long Bàn Tử ngủ say","gap":"@c1459"},{"ten":"Trọng Huyền Tử","tag":"cap-tren","quanHe":"Liên Minh chủ, cấp trên trực tiếp","gap":"@c1459"}],"tuiDo":{}},"nguon":["@c1459"]},{"id":"trung-nien-tren-dau-huyen-vu","name":"Trung niên bí ẩn trên đầu Huyền Vũ","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"khong-ro","blurb":"Trung niên bí ẩn mang khí tức vạn cổ, ngồi khoanh chân trên đầu con Huyền Vũ hóa đá chiếm cứ toàn bộ Thất Thải Giới. Thân thể nối liền Huyền Vũ, thiên linh bị gai đâm xuyên, không còn sức sống. Được Vương Lâm phát hiện; danh tính và lai lịch chưa rõ.","vaiTro":"Nhân vật bí ẩn ngồi trên đầu Huyền Vũ hóa đá trong Thất Thải Giới","tinhCach":"Chưa rõ","tabs":{"diem":[{"text":"Được Vương Lâm phát hiện trên đầu Huyền Vũ hóa đá, mang khí tức vạn cổ, không có sức sống","chuong":"@c1460"}],"kinhLich":[{"importance":"major","mucCt":"ky","chuong":"@c1460","tieuDe":"Được Vương Lâm phát hiện trên đầu Huyền Vũ","text":"Ngồi khoanh chân trên đầu con Huyền Vũ hóa đá chiếm cứ toàn bộ Thất Thải Giới. Khí tức vạn cổ, không có sức sống, thân thể nối liền với Huyền Vũ. Trên thiên linh có một cái gai dài ba tấc đâm xuyên từ dưới thân thể lên phá vỡ xương sọ nhô ra khỏi đỉnh đầu.","anchor":"trên đầu của con Huyền Vũ này có một người đang khoanh chân ngồi"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{}},"nguon":["@c1460"]},{"id":"huyen-vu-thanh-hoang","name":"Huyền Vũ Thánh Hoàng","cn":"玄武圣皇","aliases":["Huyền Vũ chiến tướng","lão già mặc hắc y"],"gioiTinh":"nam","canhGioiCaoNhat":"Không rõ","trangThai":"song","tabs":{"kinhLich":[{"mucCt":"vua","text":"Thi thể được Vương Lâm phát hiện trên đỉnh núi, ngồi đối diện con Huyền Vũ bằng đá, vẻ mặt vừa mừng vừa sợ, đã chết trong trạng thái đang hấp thụ sức mạnh Huyền Vũ. Vương Lâm suy luận hắn phản bội Tứ Thánh Tông vì Tu Chân Liên Minh tìm được chân thân Huyền Vũ, hắn muốn sức mạnh tổ tiên nên cam tâm phản bội nhưng đã chết trong lúc hấp thụ.","anchor":"Huyền Vũ Thánh Hoàng kia năm đó phản bội chính là vì Tu Chân Liên Minh không biết ở chỗ nào đã tìm được chân thân của Huyền Vũ","bridge":true,"khoang":"@c1461"},{"chuong":"@c1463","importance":"normal","mucCt":"vua","tieuDe":"Thi thể sắp sống lại bị Vương Lâm chém đầu tiêu diệt","text":"Khí xám phun từ vết nứt mai Huyền Vũ nhập vào thi thể khiến y có dấu hiệu sống lại, bộc phát khí tức cực mạnh kèm gào thét. Bị Vương Lâm dùng huyết kiếm chém đứt đầu và chém đứt cọc thò lên ba tấc, khí xám phun thoát, thi thể héo rũ sụp đổ hoàn toàn.","anchor":"khiến cho thân thể người này động đậy, dường như là sắp sửa sống lại"},{"chuong":"@c1544","importance":"normal","mucCt":"vua","tieuDe":"Xác nhận phong ấn tiên tôn bị phá, tiết lộ Thất Đạo Tông","text":"Hiện thân từ pho tượng, dùng thần thức tự mình dò xét xác nhận phong ấn tiên tôn bị phá. Kinh ngạc cho rằng từ cổ chí kim chưa từng có. Tiết lộ phong ấn là thần thông tiên tôn sáng tạo để bảo vệ ký ức hạch tâm của Thất Đạo Tông.","anchor":"Từ cổ chí kim chưa bao giờ nghe nói phong ấn của tiên tôn bị phá vỡ"},{"chuong":"@c1549","importance":"normal","mucCt":"vua","tieuDe":"Đánh lén Vương Lâm thất bại, bị giọt máu tiên nhân xuyên thấu","text":"Từ dòng xoáy pho tượng bước ra kèm hư ảnh Huyền Vũ, dùng quyền đầy gai nhọn đánh lén Vương Lâm. Bị giọt máu tiên nhân bất diệt thể xuyên thấu nắm tay, hư ảnh Huyền Vũ tan nát, nắm tay nát bấy. Kinh hãi nhận ra huyết mạch tiên nhân bất diệt thể, thấy cung Lý Quảng thì sắc mặt trắng bệch.","anchor":"Huyết mạch của tiên nhân. Ngươi không ngờ lại có huyết mạch của tiên nhân!"}],"nhanMach":[],"tuViMoc":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Cùng ba đại đệ tử và phần lớn tộc nhân Huyền Vũ Thánh Tông phản bội Tứ Thánh Tông trong đại chiến, đánh lén Chu Tước Thánh Hoàng","chuong":"@c0976"},{"text":"Bị Côn Hư chi cảnh dùng thủ đoạn khiến phản bội, bị Chu Tước Thánh Hoàng đời 14 đánh trọng thương","chuong":"@c1027"},{"text":"Thi thể được Vương Lâm phát hiện trên đỉnh núi, ngồi đối diện con Huyền Vũ bằng đá","chuong":"@c1461"},{"text":"Thi thể có dấu hiệu sống lại do khí xám từ mai Huyền Vũ, bị Vương Lâm chém đầu tiêu diệt","chuong":"@c1463"},{"text":"Hiện thân từ pho tượng, dùng thần thức xác nhận phong ấn tiên tôn bị phá, tiết lộ Thất Đạo Tông","chuong":"@c1544"},{"text":"Đánh lén Vương Lâm thất bại, bị giọt máu tiên nhân xuyên thấu","chuong":"@c1549"}]},"nguon":["@c1461","@c1463","@c1544","@c1549","@c1550"],"theLuc":[{"ten":"Thất Đạo Tông","trangThai":"gan-bo"}],"vaiTro":"Thánh Hoàng phản bội Tứ Thánh Tông — cựu chủ Huyền Vũ Thánh Tông","tinhCach":"phản phúc, bị lợi dụng bởi thế lực bên ngoài; mưu mô nhưng thiếu thực lực áp chế đối thủ","blurb":"Thánh Hoàng đứng đầu Huyền Vũ Thánh Tông, bị Côn Hư chi cảnh dùng thủ đoạn khiến phản bội Tứ Thánh Tông trong đại chiến năm xưa, đánh lén Chu Tước Thánh Hoàng đời thứ 14 khiến chiến cuộc đảo chiều, song bản thân cũng bị đánh trọng thương. Về sau thi thể được phát hiện trên đỉnh núi cạnh pho tượng Huyền Vũ đá; trải qua các biến cố liên quan đến phong ấn tiên tôn, cuối cùng hiện thân đánh lén Vương Lâm nhưng bị giọt máu tiên nhân xuyên thấu."},{"id":"nu-tu-on-nhu","name":"Nữ tử ôn nhu","cn":"","aliases":["người yêu Thanh Thủy"],"gioiTinh":"nữ","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"tu-vong","blurb":"Người yêu của Thanh Thủy, tướng mạo không tuyệt mỹ nhưng tính tình ôn nhu, nhu hòa. Trong cơn điên cuồng của Thanh Thủy, nàng bị hắn giết chết, song đến giây phút cuối vẫn dịu dàng nhìn hắn và giơ tay muốn chạm vào hắn, trở thành mấu chốt khiến Thanh Thủy tỉnh lại.","vaiTro":"Người yêu của Thanh Thủy, xuất hiện trong ký ức quá khứ","tinhCach":"Ôn nhu, dịu dàng; yêu thương Thanh Thủy vô điều kiện","tabs":{"diem":[{"text":"Bị Thanh Thủy giết trong cơn điên cuồng, nhưng vẫn dịu dàng nhìn hắn và giơ tay muốn chạm vào hắn trước khi chết","chuong":"@c1462"}],"kinhLich":[{"importance":"major","mucCt":"vua","chuong":"@c1462","tieuDe":"Bị Thanh Thủy giết trong cơn điên","text":"Xuất hiện trước mặt Thanh Thủy đang điên cuồng, bị hắn giết chết nhưng vẫn dịu dàng nhìn hắn, giơ tay muốn chạm mặt người yêu rồi buông xuống bất lực, nói một câu cuối khiến Thanh Thủy tỉnh lại.","anchor":"giấu đi sự đau khổ mà dịu dàng nhìn Thanh Thủy, giơ tay lên như muốn chạm vào mặt người yêu"}],"tuViMoc":[],"nhanMach":[{"ten":"Thanh Thủy","tag":"the-thiep","quanHe":"Người yêu, bị hắn giết trong cơn điên cuồng","ghiChu":"@c1462"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1462"]},{"id":"than-anh-bay-mau","name":"Thân ảnh bảy màu","cn":"","aliases":["Người bảy màu","Thất thải đạo nhân"],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"khong-ro","blurb":"Hư ảnh bí ẩn ngưng tụ từ ngón tay bảy màu đã tiêu tan tại Thất Thải Giới, chỉ Vương Lâm nhìn thấy. Tiết lộ nguồn gốc cổ tam tộc từ tam thiên tiên huyết Đạo cổ Diệp Mịch, từng quen biết một tiểu tu sĩ thờ phụng Chiến Nguyên.","vaiTro":"Nhân vật bí ẩn cổ đại, nắm giữ bí mật về cổ tam tộc và Đạo cổ","tinhCach":"Bình thản, cao ngạo; không thèm để ý đến bí mật trên người Vương Lâm; thái độ ban phát cơ hội","tabs":{"diem":[{"text":"Hư ảnh bí ẩn chỉ Vương Lâm nhìn thấy, ngưng tụ từ ngón tay bảy màu đã tiêu tan","chuong":"@c1464"},{"text":"Tiết lộ tam thiên tiên huyết Đạo cổ Diệp Mịch là nguồn gốc cổ Thần, cổ Ma, cổ Yêu","chuong":"@c1464"},{"text":"Nhắc đến tiểu tu sĩ thờ phụng Chiến Nguyên từng khiến hắn kinh ngạc, khẳng định không có quan hệ với Vương Lâm","chuong":"@c1464"}],"kinhLich":[{"chuong":"@c1464","importance":"normal","mucCt":"ky","tieuDe":"Xuất hiện tại Thất Thải Giới, tiết lộ nguồn gốc cổ tam tộc","text":"Ngón tay bảy màu đã tiêu tan tái hiện rồi tan vỡ thành tinh quang bảy màu, ngưng tụ thành thân ảnh hư ảo. Cho Vương Lâm cơ hội cứu Thanh Thủy và mang đi, hướng dẫn tác dụng của từng cây cọc phong ấn. Nhận ra Vương Lâm mang truyền thừa Đạo cổ thân thể bất diệt tiên tộc và năm đạo bổn nguyên nhưng tuyên bố tạm thời không có tác dụng. So sánh Vương Lâm với tiểu tu sĩ thờ phụng Chiến Nguyên từng khiến hắn kinh ngạc, khẳng định giữa hắn và Vương Lâm không có quan hệ. Tiết lộ Đạo cổ Diệp Mịch tới nơi này trước khi chết phun tam thiên tiên huyết, một thiên hóa cổ Thần, một thiên hóa cổ Ma, một thiên hóa cổ Yêu, tạo nên nguồn gốc ba bộ tộc cổ đại. Chỉ Vương Lâm mới nhìn thấy hắn, Thanh Thủy không thể thấy.","anchor":"Ngươi là một tu sĩ rất thú vị, cũng giống như tiểu tu sĩ thờ phụng Chiến Nguyên năm đó đã khiến ta rất kinh ngạc"},{"chuong":"@c1465","importance":"normal","mucCt":"ky","tieuDe":"Tiết lộ mục đích — đẩy Vương Lâm khỏi Thất Thải Giới","text":"Hướng dẫn Vương Lâm rút cọc, giải thích cọc 5 phong ấn nguyên thần, cọc 8 mở ra luân hồi chứ không phải phong ấn. Tặng đạo quả màu vàng cho Vương Lâm làm lễ vật. Gọi Thanh Thủy là \"đồ chơi\", tiết lộ mục đích: muốn xem linh tu có biến hóa tuyệt diệu như \"tiểu tử của Chiến Nguyên\" để nhờ đó tìm được thứ hắn cần tìm. Khi Vương Lâm hỏi có phải Tiên Tôn không, đáp \"Phải, mà cũng không phải\". Vung tay đẩy Vương Lâm ra khỏi Thất Thải Giới, khe Thất Thải Giới co lại biến mất.","anchor":"Phải, mà cũng không phải Thanh âm thần bí vang lên"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Cho Vương Lâm cơ hội cứu Thanh Thủy, tiết lộ bí mật cổ tam tộc","ghiChu":"@c1464"},{"ten":"Đạo Cổ Diệp Mịch","tag":"khac","quanHe":"Biết rõ về Diệp Mịch và tam thiên tiên huyết của hắn","ghiChu":"@c1464"}],"tuiDo":{}},"nguon":["@c1464","@c1465"]},{"id":"lao-to-cam-dia-chu-tuoc","name":"Lão Tổ Cấm Địa Chu Tước","gioiTinh":"nam","tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1466","tieuDe":"","text":"Được nhắc gián tiếp khi Vương Lâm lấy bầu viêm long huyết mà lão Chu Tước đã cho để Thanh Thủy uống thay rượu mạnh.","anchor":"viêm long huyết mà lão Chu Tước đã cho hắn"},{"chuong":"@c1544","importance":"bridge","mucCt":"gon","text":"Im lặng đứng bên trong dòng chảy quan sát Vương Lâm phá phong ấn, thần sắc biến hoá không ngừng, không nói gì.","anchor":"Chu Tước không nói gì. Hắn ở bên trong dòng chảy nhìn về phía trước, thần sắc biến hoá không ngừng"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Ra lệnh Kiền Phong nuốt Hồng Điệp làm mồi luyện, sai Liễu Mi truy tìm Vương Lâm để đoạt Thiên Nghịch Châu và Tinh La Bàn","chuong":"@c0340"},{"text":"Triệu tám Tiên vệ và Tiên đế nghênh chiến Vương Lâm nhưng Tiên vệ áo đen bị hắn một chỉ Tịch Diệt diệt sát","chuong":"@c0577"},{"text":"Giảng giải bản chất Phá Không Ngũ Chỉ và con đường Niết Không bước thứ ba cho Vương Lâm","chuong":"@c1327"},{"text":"Ngầm lưu hư hỏa trên người Tư Mặc Tử qua ba cái tát, bố cục giúp Vương Lâm lập uy danh khi khiêu chiến","chuong":"@c1330"},{"text":"Truyền thụ Phần Giới Cổ Tán — thuật mạnh nhất Chu Tước tộc — với gần hai trăm vạn ấn ký qua bốn lần ấn quyết","chuong":"@c1336"},{"text":"Được Vương Lâm giải phong ấn tại vùng đất Điên Lạc, không còn bị nhốt vĩnh viễn, có thể tùy ý đi ra","chuong":"@c1966"}]},"nguon":["@c1466","@c1483","@c1544"],"trangThai":"song","theLuc":[{"ten":"Thất Đạo Tông","trangThai":"gan-bo"}],"aliases":["Chu Tước Thánh Hoàng","Chu Tước"],"vaiTro":"Lão tổ đời thứ hai của Chu Tước tộc — thế lực bí ẩn trong cấm địa Chu Tước Sơn","tinhCach":"Thủ đoạn lạnh lùng, xem sinh linh làm mồi luyện; toan tính thâm sâu, bố cục nhiều tầng từ trong cấm địa; trọng nhân tài, sẵn lòng truyền thụ tuyệt học cho kẻ xứng đáng; hành sự khó lường, khi cười đắc ý khi âm trầm ngưng trọng","blurb":"Lão tổ đời thứ hai của Chu Tước tộc, toàn thân phát hồng quang, ẩn cư trong cấm địa phía sau Chu Tước Sơn. Thuở đầu nuôi Hồng Điệp làm mồi cho Kiền Phong, ra lệnh truy tìm Vương Lâm để đoạt Thiên Nghịch Châu cùng Tinh La Bàn, thậm chí sai Tiên vệ và Tiên đế nghênh chiến hắn; về sau nhận ra tài năng của Vương Lâm nên chuyển sang trợ giúp — giảng giải con đường Niết Không bước thứ ba, trao Cổ Hồn Cấm, truyền thụ Phần Giới Cổ Tán tuyệt học mạnh nhất của Chu Tước tộc, và ngầm bố cục để hắn lập uy danh trước Tư Mặc Tử. Sau này gặp lại Vương Lâm tại Đan Hải, bị kiếm ý chấn thương và được hắn đưa tho"},{"id":"ham-yen","name":"Hàm Yên","cn":"含烟","aliases":[],"gioiTinh":"nu","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"tu-vong","blurb":"Thê tử của Thanh Thủy. Vì muốn giữ lại nàng, Thanh Thủy từng hủy diệt cả sát lục giới. Tàn hồn xuất hiện khi Thanh Thủy phá không môn, được Vương Lâm dùng Cổ Tức Diệp và máu tiên nhân phong ấn lại.","vaiTro":"Thê tử Thanh Thủy, động lực sâu xa cho mọi hành động của hắn","tinhCach":"Ôn nhu, tình nghĩa sâu nặng với Thanh Thủy","tabs":{"diem":[{"text":"Là người duy nhất trong vô số hồn phách không quỳ lạy mà đứng mỉm cười nhìn Thanh Thủy khi không môn hiện ra.","chuong":"@c1467"},{"text":"Thanh Thủy vì muốn giữ nàng mà từng hủy diệt cả sát lục giới (diệt giới).","chuong":"@c1467"}],"kinhLich":[{"chuong":"@c1467","importance":"normal","mucCt":"vua","tieuDe":"Tàn hồn xuất hiện và được phong ấn","text":"Tàn hồn xuất hiện khi Thanh Thủy phá không môn, là hư ảnh duy nhất mỉm cười đứng nhìn thay vì quỳ lạy. Thanh Thủy ôm nàng khóc, tàn hồn sắp tiêu tán thì được Vương Lâm dùng Cổ Tức Diệp và máu tiên nhân phong ấn lại. Thanh Thủy cài thoa cổ xưa (di vật diệt giới) lên đầu nàng.","anchor":"Hắn vì muốn giữ lại thê tử không ngại huỷ diệt sát lục giới"}],"tuViMoc":[],"nhanMach":[{"ten":"Thanh Thủy","tag":"the-thiep","quanHe":"Phu quân","ghiChu":"Thanh Thủy vì giữ nàng mà hủy diệt sát lục giới, sẵn sàng bỏ tu vi bước thứ ba."},{"ten":"Vương Lâm","tag":"an-nhan","quanHe":"Ân nhân phong ấn tàn hồn","ghiChu":"Dùng Cổ Tức Diệp và máu tiên nhân phong ấn tàn hồn nàng trước khi tiêu tán."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1467"]},{"id":"dien-chu-thien-phat-dien","name":"Điện chủ Thiên Phạt Điện","cn":"秦九渊","aliases":["Tần Cửu Duyên","Điện chủ Thiên Phạt Điện","Lão giả áo đen"],"gioiTinh":"nam","canhGioiCaoNhat":"Không Huyền sơ kỳ","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1468","importance":"normal","mucCt":"vua","tieuDe":"Chiến đấu với Long Bàn Tử trong Thất Thải Giới","text":"Lão già mặc hắc bào, tu vi Không Huyền sơ kỳ chính thức, đang chiến đấu với Long Bàn Tử trong Thất Thải Giới Triệu Hà. Mấy vạn tu sĩ giới ngoại tụng chú hỗ trợ bằng hương hỏa lực hóa sinh linh quỷ dị.","anchor":"Tu vi của người này giống như ngũ tôn của Thái Cổ Tinh Thần, đã đạt tới Không Huyền sơ kỳ!"},{"chuong":"@c1469","importance":"normal","mucCt":"ky","tieuDe":"Bị liên thủ đánh trọng thương, mất đạo quả","text":"Nhận ra Vương Lâm là Phong Tôn, định đuổi giết nhưng bị Long Bàn Tử ngăn. Cười nhạo Vương Lâm không thể phá đạo quả do chưởng tôn bố trí. Nhận ra sát lục bổn nguyên của Thanh Thủy, muốn rút lui nhưng bị phong tỏa cửa ra. Bị Thanh Thủy và Long Bàn Tử liên thủ đánh trọng thương: hương hỏa giới vỡ nát, khuôn mặt năm vết rách sâu có ánh mặt trời lóe ra, lưng bị in dấu chưởng ấn sơn hà, thân thể héo rũ. Nhận ra Bạch Phàm Thuật và xác nhận đối thủ là Thanh Thủy. Đề nghị giúp mở đạo quả đổi lấy được rời đi, bị Vương Lâm từ chối. Kinh hãi chứng kiến Vương Lâm dễ dàng cứu Hồng Sam Tử và lấy đạo quả.","anchor":"Ta giúp các ngươi cứu Hồng Sam Tử, chúng ta cùng nhau rat ay có thể mở được đạo quả"},{"chuong":"@c1470","importance":"normal","mucCt":"vua","tieuDe":"Thất bại, bị Hồng Sam Tử giam cầm","text":"Là cao thủ bước thứ ba nhưng phải đối mặt bốn người hợp lực, hoàn toàn không còn sức chiến đấu. Thất bại hoàn toàn, bị Hồng Sam Tử giam cầm mang đi, sẽ bị luyện thành huyết thân.","anchor":"cuối cùng cũng thất bại, bị Hồng Sam Tử giam cầm mang đi"}],"tuViMoc":[{"chuong":"@c1468","canhGioi":"Không Huyền sơ kỳ","text":"Tu vi Không Huyền sơ kỳ chính thức, không phải hủy sinh cơ đổi lấy","importance":"major"}],"nhanMach":[{"ten":"Long Bàn Tử","tag":"doi-thu","quanHe":"Đối thủ chiến đấu","ghiChu":"Đang giao chiến trong Thất Thải Giới Triệu Hà"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Tu vi Không Huyền sơ kỳ chính thức, ngang ngũ tôn Thái Cổ Tinh Thần","chuong":"@c1468"}]},"nguon":["@c1468","@c1469","@c1470"],"vaiTro":"Điện chủ Thiên Phạt Điện của Trường Tôn hội, tu vi Không Huyền sơ kỳ chính thức","tinhCach":[{"text":"Chiến đấu trực diện, tu vi thực lực chính thức chứ không phải hủy sinh cơ đổi lấy"}],"blurb":"Điện chủ Thiên Phạt Điện thuộc Trường Tôn hội, lão già mặc hắc bào, tu vi Không Huyền sơ kỳ chính thức, đang chiến đấu với Long Bàn Tử trong Thất Thải Giới Triệu Hà.","theLuc":[{"ten":"Trường Tôn hội","trangThai":"gan-bo"}]},{"id":"vuong-trac","name":"Vương Trác","cn":"王拓","gioiTinh":"nam","trangThai":"khong-ro","tabs":{"kinhLich":[{"chuong":"@c1496","importance":"bridge","mucCt":"gon","text":"Được Từ Phi nhắc tên, là người mà hai nữ tu sĩ Hằng Nhạc Phái cần tụ họp cùng để tìm dị bảo phía đông.","anchor":"chúng ta phải tới tụ họp với đám Vương Trác"},{"chuong":"@c1500","importance":"bridge","mucCt":"gon","text":"Đang phi hành trong mưa cùng Từ Phi, Chu Nhị và lão già Hằng Nhạc Phái, tâm thần chấn động hoảng sợ khi cảm nhận khí tức từ chỉ lực Vương Lâm.","anchor":"mấy người này đồng thời chấn động tâm thần, thần sắc lộ vẻ hoảng sợ"},{"importance":"bridge","mucCt":"gon","chuong":"@c1518","text":"Toàn thân mặc hắc y đứng trên Hằng Nhạc Sơn, khi gió thổi qua thân ảnh tan nát trong mộng cảnh.","anchor":"Vương Trác toàn thân mặc hắc y. đứng trên Hằng Nhạc Sơn. giờ phút này gió thổi qua thân ảnh cũng tan nát"},{"chuong":"@c1533","importance":"bridge","mucCt":"gon","text":"Bị Huyễn Chân Kiếp hóa thành thân ảnh trong nhóm người quen thuộc vây tới Vương Lâm.","anchor":"có cha mẹ hắn, có tứ thúc của hắn, có Vương Trác"},{"chuong":"@c1540","importance":"major","mucCt":"gon","text":"Được Vương Lâm tìm thấy và thu hồi vận mệnh trong mặt trời thứ chín.","anchor":"Hắn tìm ấy Thập Tam, tìm thấy đầu to, tìm được Chu Dật"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Đậu trắc thí linh căn Hằng Nhạc Phái, được Đạo Hư thượng tiên thu làm đồ đệ","chuong":"@c0003"},{"text":"Sống sót sau vụ Đằng Hóa Nguyên tàn sát toàn bộ Vương gia, đã chuyển sang Huyền Đạo Tông tu tới Ngưng Khí tầng 11","chuong":"@c0087"},{"text":"Tu tới Kết Đan hậu kỳ, kết đạo lữ song tu cùng Đằng Tú Tú — con gái Đằng gia, kẻ thù giết cả họ hắn","chuong":"@c0210"},{"text":"Tái ngộ Vương Lâm, tự tay kết liễu vợ Đằng Tú Tú rồi tự sát, giao phó mọi thù hận cho Vương Lâm","chuong":"@c0217"},{"text":"Hồn phách được Vương Lâm đưa đầu thai vào Vương gia Triệu quốc, trở thành tổ phụ khai sáng một chi tộc mới","chuong":"@c0384"},{"text":"Bài vị được đặt ở vị trí cao nhất trong từ đường Vương gia, chứng tỏ đã giữ lời hứa bảo vệ hậu nhân trọn kiếp tái sinh","chuong":"@c0846"}]},"nguon":["@c1468","@c1496","@c1500","@c1515","@c1518","@c1533","@c1540"],"vaiTro":"Cố nhân của Vương Lâm — bi kịch rể Đằng gia, kiếp sau làm tổ phụ Vương gia Triệu quốc","tinhCach":"Kiêu căng, khinh miệt người tu vi kém, dựa thân phận đồ đệ Đạo Hư để sỉ nhục người thân; ôm thù hận sâu nặng với Đằng gia suốt trăm năm; quyết tuyệt tàn khốc khi cùng đường, dám tự tay kết liễu vợ rồi tự sát; trọng lời hứa, cả kiếp tái sinh vẫn giữ lời bảo vệ hậu nhân Vương gia","blurb":"Vương Trác là anh họ của Vương Lâm, thuở nhỏ nhờ linh căn được Đạo Hư thu làm đồ đệ tại Hằng Nhạc Phái, nhiều lần công khai châm biếm và sỉ nhục Vương Lâm cùng cả họ. Sau khi Hằng Nhạc Phái ly tán, hắn chuyển sang Huyền Đạo Tông, may mắn thoát nạn khi Đằng Hóa Nguyên tàn sát toàn bộ Vương gia, rồi tu tới Kết Đan hậu kỳ và kết đạo lữ song tu với Đằng Tú Tú trong khi vẫn nuôi mối thù bất cộng đái thiên với Đằng gia. Cuối cùng hắn tự tay kết liễu vợ rồi tự sát trước mặt Vương Lâm; hồn phách được Vương Lâm đưa đầu thai vào Vương gia Triệu quốc, trở thành tổ phụ trọn đời giữ lời bảo vệ hậu nhân, bà"},{"id":"thap-tam","name":"Thập Tam","cn":"十三","aliases":[],"gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"mucCt":"vua","text":"Ngồi một mình trong khách sạn Côn Hư Nhất Linh, khí tức lạnh như băng. Thầm gọi Sư tôn, kích động và không dám tin khi thấy một nam tử áo trắng bước vào khách sạn.","anchor":"thân mình hắn chấn động, nhìn một nam tử áo trắng đang mở cửa khách sạn đi vào, hai mắt lộ ra vẻ kích động và không dám tin","bridge":true,"khoang":"@c1470"},{"mucCt":"ky","text":"Đang ở khách sạn trên tu chân tinh buôn bán, quỳ lạy khi thấy sư tôn Vương Lâm bước vào, được đặt lại lên ghế. Cầm bầu rượu rót đầy chén cho sư tôn, lần đầu nghe chuyện cũ của sư tôn qua lời Chu Tử Hồng. Để lại linh thạch rồi theo Vương Lâm rời khách sạn. Trên đỉnh núi xin được theo hầu bên cạnh nhưng bị Vương Lâm từ chối, được dạy bảo phải tự đối mặt gió mưa, trở thành con chim bằng. Vương Lâm tuyên bố từ nay Thập Tam lấy danh nghĩa đồ đệ bắt đầu con đường tu đạo riêng, vỗ đỉnh đầu hắn.","anchor":"Thập Tam, ngươi là người đầu tiên ta nhận làm đệ tử, cũng là người đã đi theo ta trong thời gian dài nhất.","bridge":true,"khoang":"@c1471"},{"chuong":"@c1472","importance":"normal","mucCt":"ky","tieuDe":"Nhận hạt giống bổn nguyên, chia tay sư phụ","text":"Nhận hạt giống lôi hỏa bổn nguyên từ sư phụ Vương Lâm qua một chưởng gieo vào hồn phách, trong đầu ngưng tụ hạt giống màu vàng chứa cảm ngộ đại thành về lôi và hỏa cùng tiên lực huyết mạch. Bị lấy lại pho tượng Cổ Yêu. Được sư phụ dặn sống theo lương tâm, tìm nữ tử mình yêu thích. Cắn môi cầm nước mắt, quỳ giập đầu chín cái tiễn sư phụ.","anchor":"Thân thể Thập Tam chấn động, theo một chưởng của Vương Lâm hạ xuống, trong"},{"chuong":"@c1494","importance":"normal","mucCt":"vua","tieuDe":"Thề công khai danh phận đệ tử Vương Lâm","text":"Mấy ngày sau đến quỳ dập đầu trước pho tượng Vương Lâm trên Chu Tước Tinh, khóc, thề sẽ dưới con mắt vạn người trong thời khắc quan trọng nhất công khai danh phận đệ tử.","anchor":"Sư tôn. Thập Tam sẽ dưới con mắt của vạn người, trong thời khắc quan trọng nhất nói mình là đệ tử của người"},{"chuong":"@c1520","importance":"bridge","mucCt":"vua","text":"Cùng đám đầu to tham chiến tại Chu Tước Tinh, trưởng thành qua chiến trận, thương thế đầy người nhưng sát khí ngập trời.","anchor":"còn có Mười Ba, và đám đầu to"},{"chuong":"@c1523","importance":"normal","mucCt":"gon","text":"Kích động không thôi khi gặp lại sư tôn Vương Lâm xuất hiện từ vòng xoáy.","anchor":"Nhất là Thập Tam lại càng kích động không thôi."},{"chuong":"@c1540","importance":"normal","mucCt":"gon","text":"Được Vương Lâm tìm thấy và thu hồi vận mệnh trong mặt trời thứ chín.","anchor":"Hắn tìm ấy Thập Tam, tìm thấy đầu to, tìm được Chu Dật"},{"chuong":"@c1553","importance":"bridge","mucCt":"gon","text":"Có mặt trong đoàn tu sĩ giới nội xuất chinh theo Vương Lâm, ánh mắt quyết tâm.","anchor":"có đệ tử Thập Tam của hắn"}],"nhanMach":[{"ten":"Vương Lâm","tag":"su-mon","quanHe":"Sư tôn","ghiChu":"Gọi thầm Sư tôn, kích động khi thấy nam tử áo trắng bước vào"}],"tuViMoc":[],"diem":[{"text":"Chỉ tu luyện Luyện Hồn Yêu Thuật ba tháng đã đạt giai đoạn ba, chế thành hồn phiên bảy thước đầu tiên","chuong":"@c0505"},{"text":"Bị phế tu vi vẫn không cam lòng, mỗi đêm chịu đau luyện thể theo pháp Cự Ma Tộc, tự phát gần đạt yêu lực nhị tinh","chuong":"@c0508"},{"text":"Nhận truyền thừa Cự Linh Cửu Tu, kích động quỳ đập đầu tôn Vương Lâm làm Lão tổ, thề cả đời trung thành","chuong":"@c0530"},{"text":"Ngồi dưới tượng đá Vương Lâm suốt hơn hai nghìn ngày đêm không nhúc nhích, canh giữ động khẩu cho sư tôn","chuong":"@c1018"},{"text":"Là người sớm nhất rời Vũ Giới, mang theo pho tượng Vương Lâm dựa cảm ứng mơ hồ khổ tìm sư tôn khắp nơi","chuong":"@c1440"},{"text":"Chuyển thế thành cô nhi Vương Thạch, được Vương Lâm khôi phục ký ức, tiếp tục theo sư tôn vào Tiên giới thi triển Cực Hỏa Đạo","chuong":"@c1955"}]},"nguon":["@c1470","@c1471","@c1472","@c1494","@c1520","@c1523","@c1540","@c1553"],"vaiTro":"Đại đệ tử của Vương Lâm — thiên tài Luyện Hồn Yêu Thuật kiêm thủ lĩnh bộ lạc Luyện Hồn","tinhCach":"Trầm ổn kiên nghị, càng trải biến cố càng vững chí; bất khuất không cam lòng, phế tu vi vẫn tự luyện thể mỗi đêm; trung thành tận tụy tuyệt đối, nguyện theo sư tôn dù chuyển thế đầu thai; cảnh giác điềm tĩnh trong hiểm cảnh","blurb":"Kính Thập Tam là đại đệ tử của Vương Lâm, trời sinh ngộ tính với Luyện Hồn Yêu Thuật — chỉ ba tháng đã đạt giai đoạn ba. Sau khi bị phế tu vi, gã không cam lòng mà tự phát luyện thể theo pháp Cự Ma Tộc, quỳ bái Vương Lâm làm Lão tổ, nhận truyền thừa Cự Linh Cửu Tu rồi trưởng thành thành thủ lĩnh thần thông kinh người của bộ lạc Luyện Hồn, thân thể được rèn bằng máu Cự Ma Tộc và máu vương tộc Cổ Thần đến gần cảnh giới Tiên vệ Ngân Thi. Gã là người sớm nhất rời Vũ Giới mang theo pho tượng Vương Lâm khổ tìm sư tôn, cuối cùng nguyện theo sư phụ chuyển thế đầu thai, chuyển thế thành Vương Thạch rồi"},{"id":"truu-dong-duc","name":"Trứu Đông Đức","cn":"","aliases":[],"gioiTinh":"nam","vaiTro":"Văn sĩ trung niên tự nhận quen Phong Tôn từ thời Chu Tước Tinh","tinhCach":"Khoác lác, thích khoe mẽ","blurb":"Tu sĩ trung niên tự xưng quen biết Phong Tôn từ thời ở Chu Tước Tinh khi Phong Tôn còn là Kết Đan tu sĩ, bị người xung quanh chọc cười.","trangThai":"song","tabs":{"diem":[{"text":"Tự nhận quen Phong Tôn thời Kết Đan, khoác lác bị chế giễu","chuong":"@c1470"}],"kinhLich":[{"chuong":"@c1470","importance":"bridge","mucCt":"gon","text":"Tại khách sạn Côn Hư Nhất Linh tự khoe quen Phong Tôn, bị lão già bên cạnh chọc cười.","anchor":"Ta đã nói rồi, ta có quen biết với Phong Tôn"}],"nhanMach":[],"tuViMoc":[],"tuiDo":{}},"nguon":["@c1470"]},{"id":"chu-tu-hong","name":"Chu Tử Hồng","cn":"朱紫红","aliases":["Nữ tử áo tím họ Chu","Chu sư tỷ"],"gioiTinh":"nu","trangThai":"song","tabs":{"kinhLich":[{"mucCt":"vua","text":"Xuất hiện ở khách sạn Côn Hư Nhất Linh, được tu sĩ xung quanh đứng dậy cung kính vì đến từ Chu Tước Tinh. Kể chuyện từng gặp Mã Lương (Vương Lâm) thời Trúc Cơ ở chiến trường ngoại vực, cùng quay về Hỏa Phần Quốc. Tiết lộ Lý Mộ Uyển là bạn cùng phòng với nàng.","anchor":"Lúc đó, hắn có tên là Mã Lương…….Khi đó, hắn mới chỉ là một Trúc Cơ tu sĩ, rất lạnh lùng, có một chút vô tình","bridge":true,"khoang":"@c1470"},{"mucCt":"ky","text":"Trong khách sạn trên tu chân tinh buôn bán, hồi tưởng và kể cho các tu sĩ nghe quá khứ của Phong Tôn tại Chu Tước Tinh: giai đoạn Trúc Cơ giết hơn trăm tu sĩ, cứu Lý Mộ Uyển bị truy sát vào Tu Ma Hải, quay về Triệu Quốc diệt cả nhà họ Đằng báo thù máu chảy thành sông. Khi Vương Lâm quay đầu mỉm cười trước khi rời khách sạn, tâm thần chấn động, nhận ra thân ảnh chính là người trong ký ức nhưng không nói ra. Sau đó tiếp tục kể chuyện, khoé miệng lộ nụ cười.","anchor":"Nữ tử áo tím kia tâm thần chấn động, có chút không thể tin được","bridge":true,"khoang":"@c1471"},{"chuong":"@c1477","importance":"normal","mucCt":"gon","tieuDe":"Rời Chu Tước Tinh, bái nhập tông phái Triệu Hà","text":"Được Chu Vũ Thái nhắc: theo mẫu thân Phượng Tuý rời khỏi Chu Tước Tinh nhiều năm trước, bái nhập một tông phái ở Triệu Hà, đao lữ của nàng đã tử vong trong đại chiến.","anchor":"Nàng theo mẫu thân Phượng Tuý nhiều năm trước đã rời khỏi, nghe nói đã bái nhập vào một tông phái nào đó ở Triệu Hà"},{"mucCt":"vua","text":"Bị phát hiện nằm trong số tù binh giới nội trên tu chân tinh của Minh Linh tộc, giam trong bọt khí màu xám giữa tử khí nồng đậm, hai mắt nhắm nghiền, sắc mặt tái nhợt nhưng quần áo còn đầy đủ. Bị lực hút từ khe nứt mặt đất cuốn vào bên trong cùng ba trăm bọt khí khác.","anchor":"Bên trong đám tù binh này phần lớn đều là phụ nữ, bất ngờ lại có cả Chu Tử Hồng!","bridge":true,"khoang":"@c1554"},{"importance":"bridge","mucCt":"vua","chuong":"@c1555","tieuDe":"Bị rút sinh cơ, được Vương Lâm cứu","text":"Nằm trong số ba trăm nữ tu Triệu Hà bị tộc trưởng Minh Linh tộc rút sinh cơ, thần sắc vặn vẹo, hai mắt nhắm nghiền, nguyên thần bị kéo ra. Được Vương Lâm phá ngang thần thông, nguyên thần trở lại cơ thể.","anchor":"Thần sắc Chu Tử Hồng vặn vẹo, hai mắt nhắm nghiền, thân thể run rẩy"}],"nhanMach":[{"ten":"Vương Lâm","tag":"ban-be","quanHe":"Từng quen biết thời Mã Lương Trúc Cơ","ghiChu":"Cùng quay về Hỏa Phần Quốc từ chiến trường ngoại vực"},{"ten":"Lý Mộ Uyển","tag":"ban-be","quanHe":"Bạn cùng phòng","ghiChu":"Tiết lộ Lý Mộ Uyển từng gặp Mã Lương tại Hỏa Phần Quốc"}],"tuViMoc":[],"diem":[{"text":"Bị du hồn truy đuổi trong chiến trường Vực Ngoại, được Vương Lâm (thân Mã Lương) cứu mạng","chuong":"@c0105"},{"text":"Nhận ra Vương Lâm đoạt xá, bình tĩnh hỏi thẳng và dâng bản mệnh tinh huyết quy phục","chuong":"@c0106"},{"text":"Được Vương Lâm thả tự do, trả lại bản mệnh tinh huyết cho sư tổ Phượng Loan","chuong":"@c0113"},{"text":"Tu vi đạt Hóa Thần Hậu Kỳ tại Chiến Thần Điện, chuẩn bị xung kích Anh Biến","chuong":"@c0846"},{"text":"Theo mẫu thân Phượng Tuý rời Chu Tước Tinh, bái nhập tông phái Triệu Hà","chuong":"@c1477"},{"text":"Bị Minh Linh tộc bắt làm tù binh rút sinh cơ, được Vương Lâm giải cứu","chuong":"@c1555"}]},"nguon":["@c1470","@c1471","@c1477","@c1554","@c1555"],"vaiTro":"Nhân vật phụ — nữ đệ tử Chiến Thần Điện, nô tài rồi cố nhân của Vương Lâm","tinhCach":"Bình tĩnh trước nguy nan, dám hỏi thẳng sự thật; biết giữ bí mật về thân phận Vương Lâm; cầu tiến trong tu luyện","blurb":"Chu Tử Hồng là đệ tử Chiến Thần Điện, con gái của Phượng Loan (Phượng Tuý), từng bị du hồn truy đuổi trong chiến trường Vực Ngoại và được Vương Lâm trong thân phận Mã Lương cứu mạng. Sau khi nhận ra Vương Lâm đoạt xá, nàng bình tĩnh đối mặt và dâng bản mệnh tinh huyết quy phục, rồi được trả lại tự do. Về sau nàng tu luyện tới Hóa Thần Hậu Kỳ tại Chiến Thần Điện, sau đó theo mẫu thân rời Chu Tước Tinh bái nhập tông phái Triệu Hà, và bị Minh Linh tộc bắt làm tù binh rút sinh cơ trước khi được Vương Lâm giải cứu lần nữa."},{"id":"hua-co-nuong","name":"Hứa cô nương","cn":"","aliases":[],"gioiTinh":"nu","vaiTro":"Nữ tu áo hồng, sư muội của Chu Tử Hồng","tinhCach":"Tò mò, hiếu kỳ về Phong Tôn","blurb":"Nữ tử áo hồng dung mạo tuyệt trần, tóc ngang vai, là sư muội của Chu Tử Hồng, tò mò hỏi chuyện về Phong Tôn.","trangThai":"song","tabs":{"diem":[{"text":"Dung mạo tuyệt trần, tò mò hỏi thăm về Phong Tôn","chuong":"@c1470"}],"kinhLich":[{"chuong":"@c1470","importance":"bridge","mucCt":"gon","text":"Hỏi sư tỷ Chu Tử Hồng và Trứu Đông Đức về chuyện gặp Phong Tôn.","anchor":"Trứu đại ca đã gặp Phong Tôn ở chỗ nào?"}],"nhanMach":[{"ten":"Chu Tử Hồng","tag":"su-mon","quanHe":"Sư tỷ","ghiChu":"Gọi Chu sư tỷ"}],"tuViMoc":[],"tuiDo":{}},"nguon":["@c1470"]},{"id":"ly-mo-uyen","name":"Lý Mộ Uyển","cn":"李慕婉","aliases":["Uyển Nhi"],"gioiTinh":"nu","trangThai":"tu-vong","tabs":{"kinhLich":[{"chuong":"@c1470","importance":"bridge","mucCt":"gon","text":"Được Chu Tử Hồng nhắc tên, tiết lộ là bạn cùng phòng và từng gặp Mã Lương ở Hỏa Phần Quốc.","anchor":"Lý Mộ Uyển, còn là bạn cùng phòng với ta"},{"chuong":"@c1493","importance":"bridge","mucCt":"vua","text":"Xuất hiện trong hồi ức cuối cùng của Vương Lâm khi sắp chết: ngồi trước nhà gỗ trong sơn cốc mái tóc đen vấn cao, ôn nhu đánh đàn nhìn Vương Lâm. Vương Lâm xin lỗi nàng vì cuối cùng không có sức mạnh khiến nàng thức tỉnh.","anchor":"Uyển nhi, xin lỗi nàng.ta cuối cùng vẫn không có sức mạnh để khiến nàng thức tỉnh."},{"chuong":"@c1504","importance":"bridge","mucCt":"gon","text":"Được nhắc tới khi Vương Lâm gảy khúc đàn bi ai trên họa thuyền Tô thành — khúc đàn chính là khúc năm xưa Lý Mộ Uyển đàn.","anchor":"Tiếng đàn này là tiếng đàn năm xưa Lý Mộ Uyển đàn"},{"chuong":"@c1512","importance":"bridge","mucCt":"ky","text":"Hình ảnh nữ tử bạch y xuất hiện trong huyễn cảnh hải thị thận lâu trên mặt biển, từ mây đen đi ra, giơ ngọc thủ chỉ xuống khiến ngọn núi lửa đang bộc phát có dấu hiệu bị dập tắt, Vương Lâm nhận ra nàng ngay lập tức và rơi lệ.","anchor":"Nữ tử này từ trong mây đen đi ra, ngọc thủ giơ lên hướng về phía dưới điểm một chi"},{"chuong":"@c1514","importance":"bridge","mucCt":"vua","text":"Được nhắc nhiều lần trong chương như trung tâm nỗi đau nhân quả: bản thể tu sĩ Vương Lâm muốn cắt đứt nhân quả với nàng, khiến nàng không phải chờ đợi cô độc hai ngàn năm, nhưng đại nho Vương Lâm kịch liệt phản đối, tuyên bố không thể tiếp nhận việc này.","anchor":"ngươi muốn cắt đứt nhân quả với Lý Mộ Uyển thì loại chuyện này ta không thể tiếp nhận"},{"mucCt":"ky","text":"Lý Mộ Uyển ôm chặt Vương Lâm sợ hắn rời đi, nước mắt chảy dài. Nàng dìu Vương Lâm bay đi trước mắt hàng ngàn tu sĩ. Tại sơn cốc, nàng đề nghị không suy nghĩ mộng hay thật, cứ sống ở đây. Nàng dùng thần thông pháp thuật biến mình thành bà lão để cùng Vương Lâm già đi như phàm nhân. Năm thứ 35, nàng tóc bạc phơ mang vẻ quyến luyến không nỡ, dìu Vương Lâm rời sơn cốc bay về phía Triệu quốc.","anchor":"Đây là Lý Mộ Uyển dùng thần thông pháp thuật tạo thành","bridge":true,"khoang":"@c1516"},{"chuong":"@c1517","importance":"normal","mucCt":"vua","tieuDe":"Viếng mộ cha mẹ Vương Lâm, được giới thiệu là con dâu","text":"Đã hóa thành bà lão, đi cùng Vương Lâm trở về Triệu quốc. Quỳ cạnh Vương Lâm trước mộ cha mẹ hắn, được giới thiệu là con dâu rồi cùng vái. Tại Tô thành gảy đàn trên họa thuyền. Khi thanh niên tóc bạc (bản thể thật Vương Lâm) xuất hiện từ dòng xoáy trắng, thời gian mộng cảnh dừng lại, tay nàng ngừng đàn bất động. Thanh niên tóc bạc bước lên thuyền không nhìn bản thân lão niên mà nhìn nàng rất lâu.","anchor":"không nhìn “bản thân” kia mà lại nhìn Lý Mộ Uyển đã biến thành bà lão rất lâu, rất lâu!"},{"mucCt":"vua","text":"Nằm bất động trên họa thuyền bên Vương Lâm, được thanh niên tóc bạc hôn mi tâm. Khi Vương Lâm thốt lời sinh tử, thân thể nàng hóa tro bụi tiêu tan trong mộng cảnh. Vương Lâm hứa sẽ đánh thức nàng.","anchor":"Chờ ta, Uyển nhi, ta sẽ đánh thức nàng","bridge":true,"khoang":"@c1518"},{"chuong":"@c1527","importance":"bridge","mucCt":"gon","text":"Được nhắc như động lực trọng yếu thúc đẩy Vương Lâm dồn hết sức phá cửa — hắn muốn mạnh hơn để làm nàng sống lại.","anchor":"quyết tâm muốn trở nên hùng mạnh hơn để làm cho Lý Mộ Uyển sống lại"},{"chuong":"@c1533","importance":"bridge","mucCt":"vua","text":"Được Vương Lâm nhắc trong lời hỏi trời về việc bị cướp đi. Đồng thời bị Huyễn Chân Kiếp hóa thành thân ảnh hai mắt đẫm lệ nhưng mặt mang nụ cười bước tới gần hắn.","anchor":"Hỏi trời là ai cho ngươi tư cách cướp đi Lý Mộ Uyển"},{"chuong":"@c1540","importance":"normal","mucCt":"vua","tieuDe":"Vận mệnh bị kẻ bí ẩn đoạt trước","text":"Vương Lâm tìm kiếm vận mệnh nàng trong mặt trời thứ chín, phát hiện có dấu hiệu tồn tại nhưng đã bị kẻ nào đó sớm một bước đem đi. Khác hẳn trường hợp Thanh Thủy và Tư Đồ Nam hoàn toàn không có dấu vết.","anchor":"Mà Lý Mộ Uyển thì lại có dấu hiệu tồn tại, nhưng không biết kẻ nào đã sớm một bước đem đi."},{"chuong":"@c1541","importance":"normal","mucCt":"ky","tieuDe":"Vận mệnh bị đánh cắp, Vương Lâm phát thề thu hồi","text":"Vương Lâm phát hiện khí tức vận mệnh của nàng vốn có dấu vết trong mặt trời thứ chín nhưng đã bị ai đó lấy đi. Nàng chỉ là nữ tử bình thường, vận mệnh vốn không đáng chú ý nhưng lại bị đánh cắp. Vương Lâm nhận ra muốn nàng thức tỉnh và sống lại, bước đầu tiên là phải tìm lại vận mệnh bị đánh cắp và khiến nàng siêu thoát khỏi vận mệnh.","anchor":"Uyển Nhi chỉ là một nữ tử bình thường. Vận mệnh của nàng vốn không đáng để người ta chú ý"}],"nhanMach":[{"ten":"Vương Lâm","tag":"the-thiep","quanHe":"Người yêu / nhân duyên xuyên suốt giấc mộng","ghiChu":"Được Vương Lâm phá phong ấn mi tâm, tỉnh lại trong mộng, thề chờ chàng tỉnh mộng"}],"tuViMoc":[],"diem":[{"text":"Dùng Bách Thú Linh Lô và Ma Huyết đằng luyện thành công linh đan trong lúc động phủ bị mười tu sĩ Kết Đan kỳ công phá","chuong":"@c0127"},{"text":"Chia tay Vương Lâm sau bốn năm đồng hành tại Tu Ma Hải, để lại hơn 18.000 ngọc giản đan phương và bản mệnh tinh huyết kèm thần thức hộ thể","chuong":"@c0137"},{"text":"Ba lần Kết Anh thất bại, thọ nguyên cạn kiệt, thân xác hóa xương khô, kim đan nứt vỡ; nguyên anh đầu thai thành bé gái Chu Như qua bức tranh Sinh Tử Luân Hồi","chuong":"@c0313"},{"text":"Sau chín mươi năm trong thân Chu Như, thức tỉnh rồi tự đẩy nguyên anh ra, từ bỏ cơ hội tái sinh để bảo toàn sinh mệnh Chu Như","chuong":"@c0381"},{"text":"Tàn hồn được Vương Lâm tách khỏi thân Tống Trí suốt gần hai năm, hồn phách hoàn chỉnh trở lại","chuong":"@c1929"},{"text":"Được hồi sinh nhờ Vương Lâm nghịch chuyển năm tháng, mở mắt tỉnh lại và cùng hắn rời đi sống bình thường","chuong":"@c1975"}]},"nguon":["@c1470","@c1493","@c1494","@c1504","@c1512","@c1514","@c1515","@c1516","@c1517","@c1518","@c1527","@c1533","@c1540","@c1541","@c1573"],"vaiTro":"Nhân vật nữ chính — thê tử Vương Lâm, tu sĩ tài hoa luyện đan và trận pháp","tinhCach":"Tài hoa xuất chúng về luyện đan và trận pháp, sáng tạo linh hoạt trong chiến đấu; nặng tình sâu sắc với Vương Lâm, kiên trinh suốt trăm năm ly biệt; kiên cường chịu đựng trước thọ nguyên cạn kiệt và ba lần Kết Anh thất bại; giàu lòng trắc ẩn, tự từ bỏ cơ hội tái sinh để bảo toàn sinh mệnh Chu Như","blurb":"Lý Mộ Uyển là tu sĩ Kết Đan hậu kỳ, nổi bật với thiên phú luyện đan và trận pháp, từng bị Song Tu Môn truy sát vì Thiên Ly đan rồi được Vương Lâm cứu giúp, cùng hắn trải qua bốn năm đồng hành tại Tu Ma Hải trước khi chia tay. Hơn trăm năm sau, ba lần Kết Anh thất bại khiến thọ nguyên cạn kiệt, thân xác hóa xương khô; nguyên anh nhờ bức tranh Sinh Tử Luân Hồi đầu thai thành bé gái Chu Như, nhưng nàng tự đẩy nguyên anh ra để bảo toàn sinh mệnh Chu Như, rồi được Vương Lâm gìn giữ nguyên anh suốt gần bảy trăm năm. Tàn hồn nàng sau đó được phát hiện dung nhập trong thân Tống Trí, trải qua gần hai n"},{"id":"nguoi-dien","name":"Liên Đạo Phi","cn":null,"aliases":["A Ngốc","Vương gia","Đồng tử đầu to","Chủ nhân của Chưởng Tôn","Nam tử trung niên điên","chủ nhân (Chưởng Tôn nhắc)"],"gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"mucCt":"ky","text":"Tự xưng “bổn vương”, đi nghênh ngang trong thành trì phàm nhân trên tu chân tinh cấp bảy với Hứa Lập Quốc và Lưu Kim Bưu theo sau. Hành xử điên rồ, giẫm nát cành cây rồi gào thét. Bị hai người dụ dỗ bằng hứa dẫn gặp nữ tử, tự cắn tay cho máu chảy đổi thưởng, nói máu của mình rất quý giá và nhắc “năm đó” nhưng bị cắt ngang. Bị dẫn qua nhiều truyền tống trận liên tiếp, mất kiên nhẫn gào thét dọa mách sư phụ, khiến Hứa Lập Quốc và Lưu Kim Bưu hoảng sợ.","anchor":"Các ngươi khinh người quá, thật là quá đáng! Ta phải mách sư phụ của các ngươi!","bridge":true,"khoang":"@c1472"},{"mucCt":"ky","text":"Bị Hứa Lập Quốc và Lưu Kim Bưu dẫn qua truyền tống trận tới động phủ trong ngọn núi phía tây bắc tu chân tinh. Lưu Kim Bưu bóp vai xin thưởng rồi kể chi phí mười ba ngày (bảy mươi ba vạn linh thạch, chín trăm tám mươi lăm vạn lượng bạc) ép Người điên áy náy cắn ngón tay cho tám chín giọt máu tươi. Bị Hứa Lập Quốc dụ vào phòng gặp Pháp Hoa Tử (nam giới) mà tưởng là tiểu nương tử. Hứa Lập Quốc triệu hồi hơn mười tu sĩ đồng mưu diễn kịch giả bị thương, nữ tu dẫn đầu quát mắng đòi đổ đầy mười bình ngọc bằng máu tươi để chuộc mạng. Người điên hoảng sợ kêu mình không làm gì. Cuối cùng thân ảnh áo trắng (chủ nhân) xuất hiện bắt quả tang.","anchor":"Nhéo vài cái mà đòi phần thưởng? Không cho, máu tươi của bổn vương rất quý","bridge":true,"khoang":"@c1473"},{"mucCt":"ky","text":"Là người ít bị uy áp nhất, xông tới bên Vương Lâm khóc lớn kể lể mình bị khinh thường, chỉ hỏi tên nữ tử chưa làm gì. Sau sự kiện bị lừa gạt, tính cách thay đổi rõ rệt: trở nên cực kỳ keo kiệt với linh thạch và ngân lượng, không ngừng lẩm bẩm lòng người hiểm ác và không thể hoang phí. Bộ dạng nói liến thoắng khiến Vương Lâm mơ hồ liên tưởng tới một người từng gặp ở giới ngoại Thái Cổ Tinh Thần.","anchor":"Khất là đối với linh thạch và ngân lượng sau một vài ngày đã đạt tới một mức độ cực kỳ keo kiệt, gần như khiến người khác phải phát điên lên","bridge":true,"khoang":"@c1474"},{"mucCt":"ky","text":"Đi theo Vương Lâm trong tinh không, không ngừng gào thét đòi biến Hứa Lập Quốc và Lưu Kim Bưu thành lá cây để giẫm đạp. Bị Vương Lâm vạch trần rằng hắn sớm nhìn thấu âm mưu của hai người, máu hắn hứa chỉ là thứ vất đi — ngượng ngùng thừa nhận mình thông minh. Suốt đường đi dần cảm nhận trên người Vương Lâm cảm giác y hệt như lúc mới ra khỏi cơ thể U Minh Thú. Tới ngoài Chu Tước Tinh thấy ba đệ tử liền hưng phấn đòi hỏi tên, bị trừng mắt.","anchor":"Bổn vương là người thông minh như vậy, há có thể bị bọn họ lừa","bridge":true,"khoang":"@c1475"},{"mucCt":"vua","text":"Đi theo Vương Lâm tới Chu Tước Tinh, chê bức tượng Phong Tôn thô tháo, gào đòi thưởng duyên phận khi thấy bốn sư đồ. Trầm mặc hiếm thấy khi cảm nhận nỗi cô độc nồng đậm từ bóng lưng Vương Lâm, mơ hồ nhớ nhà. Hưng phấn theo Vương Lâm phá trận pháp vào Triệu Quốc.","anchor":"Hắn có thể từ bóng lưng của Vương Lâm nhận ra nỗi cô độc nồng đậm","bridge":true,"khoang":"@c1476"},{"chuong":"@c1477","importance":"bridge","mucCt":"gon","text":"Trong tiếng cười ha hả bay tới Triệu Quốc, bị ba đệ tử lão già truy kích, đi quanh Vương Lâm vài vòng mơ hồ nhìn thấy ba hư ảnh rồi buồn bực ngồi dựa tường ngủ.","anchor":"Cảnh tượng này dường như là một gia đình bốn người, vô cùng đầm ấm"},{"chuong":"@c1478","importance":"minor","tieuDe":"Líu lo bên Vương Lâm trong bảy ngày giữ hiếu","text":"Tỉnh dậy trong bảy ngày giữ hiếu, líu lo nói lung tung, đoạt bầu rượu uống say hát hò. Được Vương Lâm mang theo bay đến hố sâu Phù Văn tộc.","anchor":"vặn vẹo bẻ cổ bắt đầu lải nhải bên tai Vương Lâm","mucCt":"vua"},{"chuong":"@c1479","importance":"normal","mucCt":"vua","tieuDe":"Tách riêng trên Chu Tước Tinh tìm ba nương","text":"Từ chối đi vào hố sâu Phù Văn tộc, muốn ở lại Chu Tước Tinh chơi đùa. Nói sẽ đi tìm ba nương từ trước — những người không cho hắn biết tên tuổi, rồi đắc ý bay đi.","anchor":"Ba nương từ lúc trước không cho bổn vương biết tên tuổi họ"},{"mucCt":"vua","text":"Ở giới nội trên Chu Tước Tinh thực sự, ngồi giữa đám ăn mày cầm đùi gà. Chợt ngẩn ra nhìn bầu trời, tức giận vì Vương Lâm bỏ mặc, quyết đi tìm hắn.","anchor":"Con bà nó, không ngờ hắn lại bỏ mặc bổn vương ở nơi này","bridge":true,"khoang":"@c1491"},{"chuong":"@c1493","importance":"normal","mucCt":"ky","tieuDe":"Lao vào Thất Thải Thương cứu Vương Lâm, cả hai bị hắc động nuốt","text":"Đột ngột xuất hiện từ lam quang bên lỗ thủng, tay cầm đùi gà ăn dở, thân phát kim quang nồng đậm. Chưởng Tôn kinh hãi tột cùng gọi hắn là Chủ, hồn phi phách tán. Thấy Vương Lâm sắp chết dưới Thất Thải Thương, phát tiếng rống kinh thiên lao vào ánh sáng bảy màu ôm lấy Vương Lâm. Dù có tiên nhân bất diệt thể hoàn chỉnh vẫn bị tan vỡ liên tục nhiều lần bởi bảy lần bạo phát. Chưởng Tôn khẳng định tiên nhân bất diệt thể nhất định do hắn truyền cho Vương Lâm, với tính cách năm xưa hắn tuyệt không cứu người, nay hành xử như vậy là thực sự điên rồi. Cuối cùng ôm Vương Lâm hôn mê bị hắc động hút vào biến mất.","anchor":"Ngươi không được chết. Ngươi còn chưa cùng bổn vương đi chơi. Ngươi đã nói là mang bổn vương đi rất nhiều nơi chơi đùa."},{"chuong":"@c1494","importance":"normal","mucCt":"vua","tieuDe":"Hôn mê trong hư vô, bị Thất Thải Thương cản trở","text":"Nằm hôn mê bên Vương Lâm trong hư vô, thân thể tiên nhân bất diệt không có ngoại thương nhưng mi tâm có đám ánh sáng bảy màu do Thất Thải Thương gắn vào vết thương cũ. Vương Lâm nắm tay liên kết trước khi thi triển Mộng Đạo.","anchor":"Nó không thể gây thương tổn cho tiên nhân bất diệt thể của người điên nhưng lại gắn liền vào vết thương nặng của hắn năm đó"},{"mucCt":"ky","text":"Trong miếu hoang, người điên vô tình buột miệng xưng hô bổn vương rồi tự sửng sốt không hiểu vì sao. Hắn kể khi tỉnh lại bốn phía có kim quang và nhiều người muốn bắt, nói muốn có linh thạch rồi cũng không hiểu linh thạch là gì. Hắn khoe bí mật dấu tay trên cổ tay phải mà ban ngày không ai thấy, trong đêm tối cổ tay phát kim quang mờ hiện hình dấu tay. Hắn mơ hồ nhớ có người đã hứa chăm sóc và dẫn đi chơi nhưng đã bỏ đi mất. Sáng hôm sau được Vương Lâm nhận làm thư đồng.","anchor":"Ta không biết ta tên là gì.ta tỉnh lại thì đã ở trong núi thẳm rồi","bridge":true,"khoang":"@c1499"},{"chuong":"@c1522","importance":"bridge","mucCt":"gon","text":"Đang hôn mê, bị Vương Lâm thu lấy mang theo khi rời hư vô; được nhắc từng nói cố hương gọi là Tiên Cương đại lục.","anchor":"Người điên từng nói cố hương của hắn gọi là Tiên Cương đại lục"},{"chuong":"@c1531","importance":"normal","mucCt":"vua","tieuDe":"Bị Chưởng Tôn nhắc là người cứu Vương Lâm","text":"Được Chưởng Tôn nhắc là chủ nhân đã xuất hiện cứu Vương Lâm lần thứ hai, có khả năng dùng huyết mạch giúp Vương Lâm thi triển cung tên Lý Quảng mà không bị bài xích. Chưởng Tôn nói người này đã điên, từng trọng thương và bị Thiên Đạo nuốt mất tích, lo sợ nếu khôi phục trí nhớ sẽ trừng phạt mình.","anchor":"Chủ nhân điên rồi, với tính cách của hắn không ngờ lại tới cứu Vương Lâm"},{"chuong":"@c1545","importance":"major","mucCt":"vua","tieuDe":"Thân phận viễn cổ bị Vương Lâm nhận diện","text":"Đang ngủ say trong không gian trữ vật của Vương Lâm, khoé miệng nhếch lên cười khúc khích. Vương Lâm xác nhận giọng nói Bổn vương tự xưng trong ký ức đại chiến chính là giọng người điên, suy ra hắn năm xưa là một trong ba kẻ phát kim quang tấn công vào Thất Đạo Tông, kết quả mất thần trí trở nên điên dại.","anchor":"khoé miệng còn nhếch lên cười khúc khích"}],"nhanMach":[{"ten":"Pháp Hoa Tử","tag":"khac","quanHe":"Thanh niên đồng mưu đóng vai tiểu nương tử lừa Người điên"},{"ten":"Vương Lâm","tag":"an-nhan","quanHe":"Được nhận làm thư đồng","ghiChu":"Vương Lâm chia lương khô, trò chuyện suốt đêm rồi nhận làm thư đồng đi cùng vào kinh. @c1499"}],"tuViMoc":[],"diem":[{"text":"Lộ diện trong Thất Thải Giới, cho Vương Lâm uống máu mình để cứu mạng, nhiều lần phun máu dùng ấn ký trên tay phải hồi phục thân thể Vương Lâm","chuong":"@c1441"},{"text":"Truyền thụ Dịch Linh Ấn hoàn chỉnh cùng ba thần thông cho Vương Lâm, quỳ dập đầu bái Vương Lâm làm sư phụ và hé lộ bí mật Tiên Chi Cửu Tuyệt","chuong":"@c1450"},{"text":"Chân tướng viễn cổ được Vương Lâm xác nhận: vốn là kẻ ngỗ ngược trên Tiên Cương đại lục, thân phận và lai lịch liên quan tới tiên tộc thời thượng cổ","chuong":"@c1628"},{"text":"Lao vào Thất Thải Thương cứu Vương Lâm, thân phát kim quang nồng đậm, cả hai bị hắc động nuốt vào hư vô","chuong":"@c1493"},{"text":"Được ca ca mặc hoàng bào kéo ra từ vòng xoáy và dùng tiên lực cứu chữa trong hoàng cung khi đang hôn mê","chuong":"@c1713"},{"text":"Hôn mê trong địa cung, toàn thân bị chín sợi xích xuyên qua, về sau hoá thành núi trong không gian xếp chồng dưới hoàng cung Tổ Thành","chuong":"@c1883"}]},"nguon":["@c1472","@c1473","@c1474","@c1475","@c1476","@c1477","@c1478","@c1479","@c1491","@c1493","@c1494","@c1499","@c1522","@c1531","@c1545"],"canhGioiCaoNhat":"Không rõ","vaiTro":"Tu sĩ tiên tộc viễn cổ mang huyết mạch Tiên Cương — đệ tử của Vương Lâm","tinhCach":"Cô độc đến điên loạn, thường tự xưng bổn vương và nói lảm nhảm; Trọng nghĩa, nhiều lần dùng máu và thân mình cứu Vương Lâm; Tự phụ giữ thể diện nhưng dễ hoảng sợ trước nguy hiểm; Nặng tình với ca ca và ba nương","blurb":"Liên Đạo Phi là tu sĩ mang huyết mạch Tiên Cương, vốn là kẻ ngỗ ngược trên Tiên Cương đại lục từ thời viễn cổ, bị nhốt trong Thất Thải Giới bên trong U Minh Thú không rõ bao nhiêu năm, cô độc đến phát điên. Hắn cứu Vương Lâm bằng máu và tiên lực của mình, truyền Dịch Linh Ấn cùng ba thần thông, rồi quỳ bái Vương Lâm làm sư phụ và hé lộ bí mật Tiên Chi Cửu Tuyệt. Sau khi rời Thất Thải Giới, hắn nhiều lần bị cuốn vào biến cố quanh Vương Lâm, từng lao vào Thất Thải Thương cứu sư phụ, được ca ca cứu chữa trong hoàng cung, về sau hôn mê bị chín sợi xích xuyên thân trong địa cung và hoá thành núi dư"},{"id":"co-yeu-lao-to-tong","name":"Cổ Yêu","gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1472","importance":"bridge","mucCt":"gon","text":"Vẫn bị phong ấn trong không gian trữ vật của Vương Lâm; Vương Lâm nhớ đã hứa cho hắn một con đường sống.","anchor":"Năm đó hắn đã từng hứa cho hắn một con đường sống, việc này Vương Lâm không hề quên"},{"chuong":"@c1535","importance":"bridge","mucCt":"gon","text":"Bốn Cổ Yêu bát tinh từ cái khe thiên kiếp hiện ra, cùng Cổ Thần và Cổ Ma vây công Vương Lâm.","anchor":"bốn Cổ Yêu bát tinh thân thể như sương khói uốn lượn quỷ dị hiện ra"}],"diem":[{"text":"Lần đầu lộ diện, lập giao kèo với Vương Lâm và kể nguồn gốc chín tồn tại không hoàn chỉnh cùng chiến tranh cửu quận Yêu Lin","chuong":"@c0555"},{"text":"Giáng ý chí cường đại từ Thiên Yêu thành cứu Vương Lâm, mượn máu ngưng huyết ảnh đại chiến tán ma ba ngày","chuong":"@c0565"},{"text":"Đoạt cuốn tranh trong bình bạch ngọc, biến tiên khí thành yêu khí tại Tiên phủ","chuong":"@c0963"},{"text":"Liên thủ cùng Vương Lâm đối đầu Cổ Ma Tháp Già, hóa thất tinh Cổ Yêu thi triển Yêu Linh Biến và tự bạo phân thân cản địch","chuong":"@c0999"},{"text":"Phong ấn bị Cửu Thiên Ma Tôn nghiền nát mà thức tỉnh, sau đó bị Vương Lâm bắt sống và hiện nguyên hình lục tinh trăm trượng","chuong":"@c1406"},{"text":"Sống sót sau đại chiến Vân Hải tinh vực, cảm nhận khí tức cổ Mạch Thương Khung Huyết và mơ hồ muốn bái tế","chuong":"@c1612"}]},"nguon":["@c1472","@c1535"],"vaiTro":"Cường giả viễn cổ ẩn trong Yêu Cổ — lão tổ tông Thiên Yêu quận, đồng minh giao kèo của Vương Lâm","tinhCach":"Hành sự qua giao kèo và điều kiện ràng buộc lợi ích, tính toán chặt chẽ; sẵn sàng hao tổn bản thể và tự bạo phân thân để chiến đấu, không né tránh khi cần đối đầu; can thiệp gián tiếp qua trung gian thay vì trực tiếp lộ diện; mỉa mai sắc bén và tự phụ về lai lịch cổ tộc","blurb":"Cổ Yêu là một trong chín tồn tại không hoàn chỉnh từ giới ngoại đến, trú ngụ trong Yêu Cổ với tư cách lão tổ tông của Thiên Yêu quận, thường được gọi là Bối La. Ông lập giao kèo với Vương Lâm từ sớm, nhiều lần giáng ý chí hoặc hiện bản thể cứu viện và tham chiến — từ đại chiến tán ma đến liên thủ đánh Cổ Ma Tháp Già trong Tiên phủ — đồng thời trở thành biến số then chốt trong nhiều bước ngoặt của Vương Lâm. Về sau phong ấn bị Cửu Thiên Ma Tôn nghiền nát mà thức tỉnh, bị Vương Lâm bắt sống và ép giao nộp bí mật, hiện vẫn tồn tại dưới dạng cổ yêu bị phong ấn trong không gian trữ vật của Vương Lâ"},{"id":"phap-hoa-tu","name":"Pháp Hoa Tử","cn":"法华子","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"La Thiên","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Thanh niên áo đen tướng mạo anh tuấn, đồng mưu trong kế hoạch lừa đảo Người điên lấy máu tươi. Đóng vai tiểu nương tử ngồi trong phòng dụ Người điên.","vaiTro":"Đồng mưu trong kế hoạch lừa Người điên","tinhCach":"Trầm mặc; chịu đóng vai nữ để phục vụ âm mưu","tabs":{"diem":[{"text":"Thanh niên áo đen đóng vai tiểu nương tử trong phòng để dụ Người điên, sau đó lộ vẻ xấu hổ khi nhóm tu sĩ xông vào","chuong":"@c1473"},{"text":"Từng ở La Thiên Tinh Vực, tham gia đại quân La Thiên trong trận Vân Hải, đã nhìn thấy Phong Tôn từ xa","chuong":"@c1474"},{"text":"Là người đầu tiên nhận ra và gào lên xác nhận danh tính Phong Tôn trong động phủ","chuong":"@c1474"}],"kinhLich":[{"mucCt":"gon","text":"Ngồi khoanh chân trong phòng có màn hào quang, tự xưng Pháp Hoa Tử, đóng vai tiểu nương tử dụ Người điên vào. Sau khi nhóm tu sĩ xông vào lộ vẻ xấu hổ đứng sang một bên.","anchor":"Bần đạo là Pháp Hoa Tử","bridge":true,"khoang":"@c1473"},{"mucCt":"vua","text":"Nghe nhắc Chu Tước Tinh và Hỏa Tước Tộc, nhận ra Vương Lâm là Phong Tôn, gào lên xác nhận danh tính. Từng nhìn thấy Phong Tôn từ xa trong trận Vân Hải khi ở đại quân La Thiên, vừa nhận ngọc giản từ Vân Hải nên biết mơ hồ hình dáng. Ôm quyền bái kiến cùng toàn bộ tu sĩ. Sau khi Vương Lâm rời đi, hối hận vì bị Hứa Lập Quốc xúi giục mà làm chuyện đáng xấu hổ trước mặt Phong Tôn.","anchor":"Trận chiến đầu tiên ở Vân Hải năm đó vãn bối cũng ở trong đại quân của La Thiên, đã từng nhìn thấy Phong Tôn từ xa","bridge":true,"khoang":"@c1474"}],"tuViMoc":[],"nhanMach":[{"ten":"Hứa Lập Quốc","tag":"dong-minh","quanHe":"Đồng mưu sắp đặt kế hoạch lừa Người điên"},{"ten":"Lưu Kim Bưu","tag":"dong-minh","quanHe":"Đồng mưu lừa Người điên"},{"ten":"Người điên","tag":"khac","quanHe":"Mục tiêu bị lừa đảo"},{"ten":"Vương Lâm","tag":"khac","quanHe":"Sùng bái, bái kiến Phong Tôn","ghiChu":"Nhận diện Phong Tôn trong động phủ @c1474"},{"ten":"Hứa Lập Quốc","tag":"khac","quanHe":"Bị xúi giục","ghiChu":"Bị Hứa Lập Quốc xúi giục làm chuyện xấu hổ @c1474"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1473","@c1474"]},{"id":"nu-tu-dan-dau","name":"Nữ tu dẫn đầu","cn":"","aliases":[],"gioiTinh":"nu","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Nữ tử vẻ mặt lạnh như băng, dẫn đầu hơn mười tu sĩ đồng mưu xông vào phòng diễn kịch uy hiếp Người điên, đòi đổ đầy mười bình ngọc bằng máu tươi.","vaiTro":"Đồng mưu diễn vai hung ác uy hiếp Người điên","tinhCach":"Lạnh lùng; diễn vai hung ác đáng sợ","tabs":{"diem":[{"text":"Dẫn đầu nhóm tu sĩ xé rách màn ánh sáng xông vào, quát mắng Người điên đòi máu tươi đổ đầy mười bình ngọc","chuong":"@c1473"}],"kinhLich":[{"mucCt":"gon","text":"Dẫn đầu hơn mười tu sĩ qua truyền tống trận tới động phủ, xé rách màn ánh sáng xông vào phòng quát mắng Người điên, đòi đổ đầy mười bình ngọc bằng máu tươi để chuộc mạng Hứa Lập Quốc và Lưu Kim Bưu.","anchor":"Đừng có nói dối! Hãy lấy máu tươi của ngươi đổ đầy mười cái bình này","bridge":true,"khoang":"@c1473"}],"tuViMoc":[],"nhanMach":[{"ten":"Hứa Lập Quốc","tag":"dong-minh","quanHe":"Đồng mưu, được triệu hồi diễn kịch"},{"ten":"Người điên","tag":"khac","quanHe":"Mục tiêu uy hiếp lấy máu tươi"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1473"]},{"id":"nu-tu-trong-dong-phu","name":"Nữ tu trong động phủ","cn":"","aliases":[],"gioiTinh":"nu","canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Nữ tu sĩ trong động phủ, phun máu trước uy áp Vương Lâm, sùng kính bái kiến Phong Tôn, thề sẽ tính sổ với Hứa Lập Quốc.","vaiTro":"Nữ tu sĩ phụ trong động phủ","tinhCach":["Có khí phách, biết phân biệt mạnh yếu"],"tabs":{"diem":[{"text":"Cho rằng ngay cả sư tôn cũng chỉ như con kiến trước uy áp Vương Lâm","chuong":"@c1474"}],"kinhLich":[{"chuong":"@c1474","importance":"bridge","mucCt":"gon","text":"Phun máu trước uy áp Vương Lâm, sùng kính bái kiến Phong Tôn, sau đó nghiến răng thề tính sổ với Hứa Lập Quốc.","anchor":"Phong Tôn! Người là Phong Tôn!"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1474"]},{"id":"dao-duc-tu","name":"Đạo Đức Tử","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Triệu Hà","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","vaiTro":"Tu sĩ Minh Hồng Tinh thuộc Triệu Hà, dẫn đệ tử tới Chu Tước Tinh chầu thánh","tinhCach":"Cung kính với thánh địa Phong Tôn; cẩn thận dặn dò đệ tử không sinh sự","blurb":"Lão già từ Minh Hồng Tinh thuộc Triệu Hà, dẫn ba đệ tử tới Chu Tước Tinh chầu thánh. Coi nơi đây là cố hương của Phong Tôn, thánh địa của Côn Hư tinh vực.","tabs":{"diem":[{"text":"Dẫn đệ tử tới Chu Tước Tinh hành hương, cung kính gọi đây là cố hương Phong Tôn và thánh địa giới nội","chuong":"@c1475"}],"kinhLich":[{"mucCt":"vua","text":"Dẫn ba đệ tử tới Chu Tước Tinh, gọi đây là cố hương Phong Tôn và thánh địa của Côn Hư tinh vực cùng giới nội. Dặn đệ tử chớ sinh sự vì nơi đây có nhiều lão quái đại thần thông bảo vệ. Tuân thủ quy củ trận pháp, được mở cầu thang mây cho vào.","anchor":"Lão phu là Đạo Đức Tử của Minh Hồng Tinh - Triệu Hà, tới đây chầu thánh","bridge":true,"khoang":"@c1475"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Gặp ngoài Chu Tước Tinh, nhờ quản lý bạn đồng hành","ghiChu":"@c1475"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1475"]},{"id":"hai-hu-anh-canh-tran-phap","name":"Hai hư ảnh canh trận pháp Chu Tước Tinh","cn":"","aliases":[],"gioiTinh":"nam","canhGioiCaoNhat":"Không rõ","trangThai":"song","vaiTro":"Hư ảnh canh giữ trận pháp bảo vệ bên ngoài Chu Tước Tinh","tinhCach":"Nghiêm túc tuần tra; cảnh giác với người lạ","blurb":"Hai lão già dạng hư ảo canh giữ trận pháp bên ngoài Chu Tước Tinh, hỏi quy củ rồi mở cầu thang mây cho tu sĩ vào.","tabs":{"diem":[{"text":"Canh giữ trận pháp Chu Tước Tinh, thấy Vương Lâm quen mặt nhưng không nhận ra","chuong":"@c1475"}],"kinhLich":[{"chuong":"@c1475","importance":"bridge","mucCt":"gon","text":"Canh trận pháp Chu Tước Tinh, hỏi quy củ rồi mở cầu thang mây, cho Vương Lâm đi qua nhưng cảm thấy quen mặt mà không nhận ra.","anchor":"Ta sao vẫn cảm thấy người kia quen quen, giống như đã gặp ở đâu rồi thì phải"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1475"]},{"id":"lao-gia-trieu-thanh","name":"Lão già triều thánh","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Cửu đại tông môn Chu Tước Tinh","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ","trangThai":"song","blurb":"Lão tu sĩ dẫn ba đệ tử tới Chu Tước Tinh triều bái tượng Phong Tôn, am hiểu sự tích trận Vân Hải tinh vực. Đuổi theo Vương Lâm khi hắn phá trận pháp Triệu Quốc, cuối cùng nhận ra người quỳ trước mộ chính là Phong Tôn.","vaiTro":"Tu sĩ hành hương, người giải thích sự tích Phong Tôn cho đệ tử, nhân chứng nhận ra Vương Lâm chính là Phong Tôn.","tinhCach":[{"text":"Sùng kính Phong Tôn, nghiêm khắc với quy tắc, dũng cảm đuổi theo kẻ phá trận bất chấp tu vi không thấu"}],"tabs":{"diem":[{"text":"Nhận ra Vương Lâm chính là Phong Tôn khi thấy hắn quỳ khóc trước mộ cha mẹ, chấn động dừng lại","chuong":"@c1476"}],"kinhLich":[{"chuong":"@c1457","importance":"normal","mucCt":"vua","tieuDe":"Triệu hoán Sơn Hà Đồ chí bảo","text":"Dung hợp với tu chân tinh, đánh ấn quyết triệu hoán Sơn Hà Đồ — chí bảo chân chính của Vũ Tiên Giới. Hai dãy núi nổi lên như hai thanh trục mở ra bức tranh sơn thủy mười vạn trượng để chống Vương Lâm.","anchor":"Sơn Hà Đồ, bảo vệ Liên Minh ta!"},{"mucCt":"vua","text":"Dẫn ba đệ tử tới Chu Tước Tinh triều bái pho tượng Phong Tôn, giải thích nguồn gốc tượng và trận chiến đầu tiên ở Vân Hải tinh vực. Phẫn nộ đuổi theo Vương Lâm khi hắn phá trận pháp Triệu Quốc, thi triển Súc Địa Thành Thốn nhưng chậm hơn. Tới mộ cha mẹ Phong Tôn, thấy Vương Lâm quỳ khóc, nhận ra chỉ có một người có tư cách quỳ ở đó, chấn động dừng lại.","anchor":"Hắn biết trong thiên địa này chỉ có một người mới có tư cách quỳ ở chỗ đó","bridge":true,"khoang":"@c1476"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Người phá trận pháp Triệu Quốc mà lão đuổi theo, sau nhận ra chính là Phong Tôn","ghiChu":"@c1476"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1476","@c1457"]},{"id":"chu-vu-thai","name":"Chu Vũ Thái","cn":"朱武太","aliases":[],"gioiTinh":"nam","canhGioiCaoNhat":"Tịnh Niết sơ kỳ","trangThai":"song","tabs":{"kinhLich":[{"mucCt":"ky","text":"Xuất hiện từ đám mây đỏ, mặc hồng bào, dung nhan uy nghiêm, thân thể đã già toát ra mùi vị tang thương. Nhìn Vương Lâm quỳ mộ với vẻ hồi tưởng, nói Ngươi đã về rồi, rồi hướng mộ vái lạy. Dùng thân phận người đứng đầu Chu Tước Tinh xua hết tu sĩ rời đi. Lấy rượu Tằng gia cất từ hơn ngàn năm trước cùng Vương Lâm uống suốt đêm. Kể tin tức cố nhân: Vân Tước Tử đã hết tuổi thọ mà chết, Chu Tử Hồng theo mẫu thân Phượng Tuý rời đi bái nhập tông phái ở Triệu Hà, đao lữ nàng tử vong trong đại chiến, Vân Thiên Tông thành chín đại tông môn. Cho biết đã nhận Tằng Ngưu làm đệ tử. Tâm sự rằng hâm mộ Vương Lâm dám rời đi, còn mình chỉ thủ hộ nơi đây hơn ngàn năm, nhắc đệ tử ý cảnh Hỏa Thần đã chết, đã hứa bầu bạn tới khi chết và mai táng trên Chu Tước Tinh. Trong trạng thái hồn say khi trời sáng nói ra: Hồng Điệp có thể vẫn chưa chết.","anchor":"Đây là rượu của Tằng gia. Năm đó ta đã để lại không ít, chính là để cùng với ngươi say một trận.","bridge":true,"khoang":"@c1477"},{"chuong":"@c1478","importance":"normal","tieuDe":"Tiết lộ trận pháp Hồng Điệp, bộc lộ tình cảm với Liễu Mi","text":"Kể cho Vương Lâm về trận pháp Hồn Truyền Tống chứa tóc Hồng Điệp phát hiện tại vùng Tuyết Vực Quốc đã tiêu tan, đã na di về động phủ. Tiết lộ tu sĩ Tuyết Vực Quốc và Cự Ma tộc đều từ bên ngoài tới. Do dự hỏi Vương Lâm về Liễu Mi, nghe tin nàng chết thì sắc mặt tái nhợt, khổ sở. Sau đó uống rượu say đến tối, cười ha ha trong bi ai — lộ ra gần hai ngàn năm vẫn yêu Liễu Mi.","anchor":"Không ai biết năm đó hắn vẫn yêu Liễu Mi.","mucCt":"ky"},{"chuong":"@c1484","importance":"bridge","mucCt":"gon","text":"Vẫn yên lặng ngồi uống rượu trước pho tượng Chu Tước ở Chu Tước Tinh thật, không hay biết Vương Lâm bị tách ra vây sát.","anchor":"Chu Vũ Thái kia vẫn còn yên lặng ngồi uống rượu ở trước pho tượng Chu Tước"},{"chuong":"@c1494","importance":"minor","mucCt":"gon","text":"Vẫn ngồi trên pho tượng Chu Tước yên lặng uống rượu, không hay biết chuyện sát kiếp đã xảy ra.","anchor":"Chu Vũ Thái vẫn ngồi trên pho tượng Chu Tước như cũ, yên lặng uống rượu"},{"importance":"bridge","mucCt":"gon","chuong":"@c1518","text":"Đang đứng trước đệ tử thiếu niên dường như đang dạy bảo, khi gió thổi tới liền tiêu tán trong mộng cảnh.","anchor":"Chu Vũ Thái đang đứng trước người một thiếu niên. Thiếu niên kia là đệ tử của hắn"}],"tuViMoc":[],"nhanMach":[{"ten":"Liễu Mi","tag":"khac","quanHe":"Người yêu thầm lặng gần hai ngàn năm","ghiChu":"Nghe tin Liễu Mi chết thì khổ sở, uống rượu bi ai — @c1478"}],"tuiDo":{},"diem":[{"text":"Lần đầu ra mặt tại kinh đô để hỏi tội Vương Lâm vì đệ tử bị phá bản mạng la sát.","chuong":"@c0238"},{"text":"Nhận ra ý cảnh trong tượng gỗ, đấu trí gieo tâm chướng và xem Vương Lâm là đối thủ Hóa Thần lớn nhất.","chuong":"@c0239"},{"text":"Dùng chức quyền dìm chuyện Vương Lâm thu gỗ trên bình nguyên tuyết, lặng lẽ che chở hắn trước Tứ Phái.","chuong":"@c0247"},{"text":"Khống chế Thương Long đại trận khai chiến chống quân Tuyết Vực, sau đó trọng thương và mất huyết mạch Thương Long.","chuong":"@c0253"},{"text":"Được Vương Lâm trong thân phận Tằng Ngưu nhường lại chức Chu Tước, trở thành Chu Tước Tử.","chuong":"@c0439"},{"text":"Kích phát huyết mạch Thanh Long chống lại đồng tử đầu to khi Chu Tước Tinh bị thần thức Khuy Niết sơ kỳ trấn áp.","chuong":"@c0835"}]},"nguon":["@c1477","@c1478","@c1484","@c1494","@c1515","@c1518"],"vaiTro":"Cố nhân của Vương Lâm — đệ thập ngũ Chu Tước","tinhCach":"Mưu trí, giỏi đấu trí gieo tâm chướng; biết thừa nhận thua kém và tiến thoái đúng lúc; trọng ân tình cố nhân, ghi nhớ nghĩa nhường ngôi; có trách nhiệm trấn thủ, dám liều mình bảo vệ Chu Tước Tinh","blurb":"Chu Vũ Thái, còn gọi là tu sĩ tai to, Chu Võ Thái và đệ thập ngũ Chu Tước, ban đầu xuất hiện để hỏi tội Vương Lâm rồi xem hắn là đối thủ Hóa Thần lớn nhất. Qua nhiều lần tái ngộ, hắn từ đối đầu chuyển sang thừa nhận thua kém, âm thầm che chở Vương Lâm, được nhường chức Chu Tước Tử và trở thành người trấn thủ Chu Tước Tinh. Về sau hắn tiếp tục bảo vệ Chu Tước Tinh trong biến cố La Thiên, chiếu cố người liên quan tới Vương Lâm, rồi còn cùng các Chu Tước, Bạch Hổ, Huyền Vũ tham dự thế cục Đan Hải."},{"id":"van-tuoc-tu","name":"Vân Tước Tử","cn":"云雀子","aliases":[],"gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1477","importance":"normal","mucCt":"gon","tieuDe":"Hết tuổi thọ mà chết","text":"Được Chu Vũ Thái cho biết đã hết tuổi thọ mà chết, trước khi chết vẫn gọi tên Vương Lâm, Chu Vũ Thái đã mai táng cho hắn.","anchor":"Vân Tước Tử của Phù Văn Tộc đã hết tuổi thọ mà chết, ta đã mai táng cho hắn"},{"chuong":"@c1481","importance":"bridge","mucCt":"gon","text":"Được nhắc đến: ngay cả Vân Tước Tử cũng không biết chân tướng mũi tên.","anchor":"dần dần ngay cả Vân Tước Tử cũng không biết được chân tướng"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Lần đầu xuất hiện trong dáng vẻ lão nhân lôi thôi, chia gà nướng với Vương Lâm, nhìn ra tu vi của hắn sắp tới Hóa Thần và tiết lộ bí mật Vũ Đỉnh.","chuong":"@c0244"},{"text":"Thân phận thật được hé lộ là Nhị tổ Tiên Di Tộc, cũng là sư đệ năm xưa thua cuộc tranh danh hiệu Chu Tước Tử.","chuong":"@c0402"},{"text":"Tham gia biến cố Chu Tước Mộ, từng dùng thủ đoạn dụ Vương Lâm liên quan đến tinh dẫn và dùng Ảnh cấm vây phân thần Thác Sâm.","chuong":"@c0434"},{"text":"Sau giao chiến với Chu Tước trong Chu Tước Mộ, bị ném ra và trọng thương, khiến về sau già nua rõ rệt.","chuong":"@c0437"},{"text":"Tỉnh khỏi bế quan mấy trăm năm khi Chu Tước Tinh đối diện nguy cơ từ La Thiên, tụ tập Tiên Di Tộc.","chuong":"@c0834"},{"text":"Hết tuổi thọ mà chết; trước khi chết vẫn gọi tên Vương Lâm và được Chu Vũ Thái mai táng.","chuong":"@c1477"}]},"nguon":["@c1477","@c1481","@c1515"],"canhGioiCaoNhat":"Không rõ","vaiTro":"Nhị tổ Tiên Di Tộc — sư đệ Chu Tước Tử","tinhCach":"Bề ngoài lôi thôi cợt nhả nhưng am hiểu bí mật cao thâm; giảo hoạt dụ dỗ khi tranh đoạt lợi ích; trọng ân tình cố nhân","blurb":"Vân Tước Tử ban đầu xuất hiện như một lão nhân lôi thôi chia gà nướng với Vương Lâm, nhìn thấu tu vi và tiết lộ bí mật Vũ Đỉnh. Thân phận thật của ông về sau được xác nhận là Nhị tổ Tiên Di Tộc, sư đệ từng thua Chu Tước Tử trong cuộc tranh danh hiệu, rồi nhiều lần liên quan đến Chu Tước Mộ, Tiên Di Tộc và các biến cố của Chu Tước Tinh. Ông từng trọng thương, bế quan mấy trăm năm, dẫn Vương Lâm vào tầng sâu Tiên Di Tộc, và về sau được cho biết đã hết tuổi thọ mà chết, trước lúc mất vẫn gọi tên Vương Lâm."},{"id":"hong-diep","name":"Hồng Điệp","cn":"红蝶","aliases":[],"gioiTinh":"nu","trangThai":"song","tabs":{"kinhLich":[{"mucCt":"gon","text":"Chu Vũ Thái trong trạng thái hồn say khi trời vừa sáng tiết lộ: Hồng Điệp có thể vẫn chưa chết.","anchor":"Vương Lâm, Hồng Điệp có thể vẫn chưa chết!","bridge":true,"khoang":"@c1477"},{"chuong":"@c1478","importance":"normal","tieuDe":"Tiết lộ có thể chưa chết nhờ Hồn Truyền Tống Trận","text":"Được hồi tưởng và bàn luận: sư tôn năm xưa đã lập trận pháp truyền tống hồn phách dùng tóc đen của nàng. Vương Lâm kết luận phần hồn phách đã được truyền đi trước khi nàng mất mạng, có thể đã đoạt xá sống lại ở nơi nào đó trong tinh hải.","anchor":"Hồng Điệp kia giống hệt như tên nàng, chính là cánh bướm do ánh sáng chói lọi trên bầy trời hoá thành!","mucCt":"ky"},{"chuong":"@c1512","importance":"normal","mucCt":"ky","tieuDe":"Được Vương Lâm đặt tên Hồng Điệp","text":"Xuất hiện dưới dạng trẻ sơ sinh được nữ tử Tuyết Vực nhặt trong tuyết khi gần chết cóng, cha mẹ đều mất lúc sinh. Trong cơ thể có khí tức ngũ hành, thiên tư cực cao, nhưng mệnh số mang đại kiếp sinh tử. Bị nữ tử Tuyết Vực dùng thần thông hạn chế lớn lên, bảo trì trạng thái trẻ con. Mi tâm có một điểm đỏ. Khi được Vương Lâm ôm, kỳ lạ ngừng khóc và cười khanh khách. Được Vương Lâm nhìn con bướm trú mưa dưới lá mà đặt tên Hồng Điệp — cánh bướm trong mưa, mang theo hồng mang, khi bay lên mang theo ánh sáng cao ngạo cả đời. Vương Lâm vẽ trận pháp thâm áo để hóa giải kiếp nạn cho nàng.","anchor":"mi tâm còn có một điểm đỏ, giống như là linh hồn của đứa bé này vậy"},{"chuong":"@c1514","importance":"bridge","mucCt":"gon","text":"Được nhắc trong phần vạch trần nhân quả giả tạo: bản thể tu sĩ Vương Lâm đã nghe chuyện Hồng Điệp trước khi vào Mộng Đạo nên đưa vào mộng luân hồi để hoàn thành nhân quả tuần hoàn.","anchor":"Ngươi trước khi Mộng Đạo đã nghe chuyện Hồng Điệp, thế nên ngươi liền ở trong mộng luân hồi của mình đem chuyện này vào"},{"chuong":"@c1540","importance":"bridge","mucCt":"gon","text":"Được Vương Lâm tìm thấy và thu hồi vận mệnh trong mặt trời thứ chín.","anchor":"Hắn tìm ấy Thập Tam, tìm thấy đầu to, tìm được Chu Dật"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"an-nhan","quanHe":"Người đặt tên cho nàng, vẽ trận pháp hóa giải kiếp nạn","ghiChu":"@c1512"},{"ten":"Nữ tử Tuyết Vực quốc","tag":"an-nhan","quanHe":"Nhặt nàng trong tuyết khi gần chết cóng, dùng thần thông hạn chế nàng lớn lên để bảo vệ","ghiChu":"@c1512"}],"tuiDo":{},"diem":[{"text":"Sở hữu Thiên Tiên Ngũ Linh thể, tiềm năng Hóa Thần hậu kỳ đỉnh phong, từng cầm Vũ Tiên Thạch bay lên tiên giới rồi trở về với tu vi hao tổn","chuong":"@c0268"},{"text":"Giao chiến Vương Lâm nhiều lần, bị mất cánh tay phải bởi Cấm Khí Trường Thương và Tuế Nguyệt, từ chối dùng Đông Hải Chi Linh mọc lại tay để giữ ý chí","chuong":"@c0317"},{"text":"Đại chiến quyết tử tại Chu Tước quốc: triệu Băng Thần, hy sinh Anh Hài phát động Phân Thần Biến, lĩnh ngộ Tuyệt Tình ý cảnh nhưng bại trước Sinh Tử Luân Hồi của Vương Lâm","chuong":"@c0339"},{"text":"Bị Kiền Phong đoạt tuyệt tình ý cảnh cùng tứ linh, biến thành con rối trống rỗng mắt vô thần, bị đổi tên thành Tuyệt Tình","chuong":"@c0340"},{"text":"Chết dưới chiến phủ Vương Lâm — chọn không chống cự, không né tránh, mỉm cười kiêu hãnh, thân thể nứt vỡ","chuong":"@c0428"},{"text":"Hồn phách được Hồn Truyền Tống Trận bảo toàn, chuyển thế tái sinh tại Tuyết Vực; sau cùng phụ thân Thanh Thủy chuyển thế đầu thai tại tiên giới","chuong":"@c1696"}]},"nguon":["@c1477","@c1478","@c1483","@c1512","@c1514","@c1540","@c1515"],"canhGioiCaoNhat":"Phàm nhân (trẻ sơ sinh, bị hạn chế lớn lên)","vaiTro":"Thiên chi kiêu nữ Tuyết Vực — đối thủ định mệnh và nhân duyên chưa dứt của Vương Lâm","tinhCach":"Kiêu hãnh bất khuất, giữ tôn nghiêm đến tận lúc chết; hiếu chiến cố chấp, nhiều lần chủ động khiêu chiến dù biết bất lợi; tàn nhẫn quyết đoán, sẵn sàng hy sinh pháp bảo và Anh Hài để phát động tuyệt chiêu; cương liệt trọng khí tiết, từ chối phục hồi cánh tay cụt để giữ ý chí","blurb":"Hồng Điệp là nữ tu thiên tài của Tuyết Vực quốc, sở hữu Thiên Tiên Ngũ Linh thể với tiềm năng Hóa Thần hậu kỳ đỉnh phong, từng vượt tiên giới rồi trở về với tu vi hao tổn nghiêm trọng. Xuyên suốt nhiều lần giao tranh với Vương Lâm — từ đánh lén trên sa mạc, đấu pháp tại tế đàn đến đại chiến quyết tử tại Chu Tước quốc — nàng lĩnh ngộ Tuyệt Tình ý cảnh nhưng bại trước Sinh Tử Luân Hồi, rồi bị Kiền Phong đoạt ý cảnh cùng tứ linh, biến thành con rối trống rỗng và cuối cùng chết dưới chiến phủ của Vương Lâm trong tư thế không chống cự, mỉm cười kiêu hãnh. Về sau nhờ Hồn Truyền Tống Trận mà hồn phác"},{"id":"tang-nguu","name":"Tằng Ngưu","cn":"","aliases":[],"gioiTinh":"nam","vaiTro":"Đứa trẻ nhà Tằng gia, được Chu Vũ Thái nhận làm đệ tử","tinhCach":"Tư chất không tồi","blurb":"Con của gia đình Tằng gia tại Triệu Quốc, được Chu Vũ Thái nhận làm đệ tử sau khi Vương Lâm rời đi.","trangThai":"song","theLuc":[{"ten":"Chu Tước Tinh","trangThai":"gan-bo"}],"tabs":{"diem":[{"text":"Được Chu Vũ Thái nhận làm đệ tử, tư chất không tồi","chuong":"@c1477"}],"kinhLich":[{"chuong":"@c1477","importance":"normal","mucCt":"gon","tieuDe":"Được Chu Vũ Thái nhận làm đệ tử","text":"Chu Vũ Thái cho biết đã nhận đứa nhỏ Tằng gia làm đệ tử, nếu biết Vương Lâm trở về nhất định sẽ rất mừng.","anchor":"Đứa nhỏ của Tằng gia kia ta cũng đã nhận hắn làm đệ tử"}],"tuViMoc":[],"nhanMach":[{"ten":"Chu Vũ Thái","tag":"su-mon","quanHe":"Sư phụ"},{"ten":"Vương Lâm","tag":"an-nhan","quanHe":"Tiền bối quen biết gia đình"}],"tuiDo":{}},"nguon":["@c1477"]},{"id":"phuong-tuy","name":"Phượng Tuý","cn":"","aliases":[],"gioiTinh":"nu","vaiTro":"Mẫu thân Chu Tử Hồng","blurb":"Mẫu thân của Chu Tử Hồng, cùng con gái rời khỏi Chu Tước Tinh nhiều năm trước.","trangThai":"khong-ro","tabs":{"diem":[{"text":"Mẫu thân Chu Tử Hồng, cùng con gái rời Chu Tước Tinh","chuong":"@c1477"}],"kinhLich":[{"chuong":"@c1477","importance":"bridge","mucCt":"gon","text":"Được nhắc đã cùng Chu Tử Hồng rời khỏi Chu Tước Tinh nhiều năm trước.","anchor":"Nàng theo mẫu thân Phượng Tuý nhiều năm trước đã rời khỏi, nghe nói đã bái nhập vào một tông phái nào đó ở Triệu Hà"}],"tuViMoc":[],"nhanMach":[{"ten":"Chu Tử Hồng","tag":"cha-me","quanHe":"Con gái"}],"tuiDo":{}},"nguon":["@c1477"]},{"id":"lieu-mi","name":"Liễu Mi","cn":"柳眉","aliases":["Liễu sư muội"],"trangThai":"khong-ro","tabs":{"kinhLich":[{"text":"Chu Vũ Thái hỏi Vương Lâm về Liễu Mi, được trả lời nàng đã chết. Lộ ra Chu Vũ Thái gần hai ngàn năm vẫn yêu Liễu Mi.","anchor":"Gặp…nàng đã chết rồi.","mucCt":"vua","bridge":true,"khoang":"@c1478"},{"chuong":"@c1500","importance":"bridge","mucCt":"vua","text":"Đang ẩn trong cầu vồng trên bầu trời Triệu quốc cùng một nam tử. Khi mây đen tan nát, cầu vồng tiêu tan lộ ra hai người. Sắc mặt tái nhợt, ánh mắt mê mang trước uy lực khí tức Vương Lâm.","anchor":"Sắc mặt nàng tái nhợt, quay đầu lại, ánh mắt lộ vẻ mê mang"},{"mucCt":"ky","text":"Cưỡi cầu vồng cùng nhóm tu sĩ bay qua biên giới Triệu quốc, nhận ra Vương Lâm già nua, tự ý rời đồng môn bay xuống gặp. Nói đã gặp hắn mấy chục năm trước (lần 1), nay lần 2 vẫn cảm thấy quen thuộc đau lòng bí ẩn — không phải từ hai lần gặp này mà từ đâu đó xa hơn, nhìn vẻ già nua của hắn càng đau đớn buồn bã. Hỏi tên, biết là đại nho Triệu quốc Vương Lâm. Tặng hắn viên đan dược bảo trì tinh lực, nói gặp nhau là có duyên, rồi cưỡi mây mù bay đi xa.","anchor":"ta không biết vì sao khi nhìn thấy cụ lại luôn cảm thấy chúng ta đã gặp nhau ở nơi nào đó rồi. Không phải lần này, cũng không phải lần trước.","bridge":true,"khoang":"@c1510"},{"chuong":"@c1514","importance":"bridge","mucCt":"gon","text":"Được nhắc trong phần vạch trần nhân quả giả tạo: bản thể tu sĩ Vương Lâm sắp đặt trong mộng cho đại nho hai lần gặp Liễu Mi và Liễu Mi tặng đan dược để cắt đứt nhân quả.","anchor":"ngươi muốn cắt đứt nhân quả với Liễu Mi, vì thế mới cho ta hai lần gặp Liễu Mi, lại khiến Liễu Mi tặng ta đan dược"},{"chuong":"@c1516","importance":"bridge","mucCt":"vua","text":"Liễu Mi ở phía xa im lặng nhìn Vương Lâm và Lý Mộ Uyển, vẻ mê man trong mắt những năm gần đây biến thành căm giận không nói lên lời.","anchor":"vẻ mê man trong mắt trong những năm gần đây càng ngày càng dày, cho tới cuối cùng đã trở thành một thứ căm giận không nói lên lời"},{"importance":"bridge","mucCt":"gon","chuong":"@c1518","text":"Đứng trên đỉnh núi trong mộng cảnh, rơi nước mắt rồi theo gió tan đi khi Vương Lâm phá hủy mộng.","anchor":"Hắn thấy ở biên cương của Triệu quốc, Liễu Mi hai mắt lộ vẻ mê man, vừa mỉm cười vừa để lại đan dược"},{"chuong":"@c1533","importance":"bridge","mucCt":"vua","text":"Bị Huyễn Chân Kiếp hóa thành thân ảnh, trong lòng ôm một đứa trẻ bị hắc khí bao quanh, tiếng trẻ khóc xuyên thấu tâm thần Vương Lâm.","anchor":"Hắn nhìn thấy Liễu Mi, nhìn thấy ở trong lòng Liễu Mi có ôm một đứa trẻ bị hắc khí bao quanh"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Lão nhân phàm tục quen thuộc bí ẩn","ghiChu":"Hai lần gặp trong kiếp mộng đều cảm thấy đau lòng quen thuộc không rõ nguyên do, gợi liên hệ xuyên kiếp"}],"tuiDo":{},"diem":[{"text":"Phân thân lặng lẽ ném lệnh bài cho Vương Lâm không nói một lời rồi thở dài nhìn hắn rời đi, thể hiện tình cảm kín đáo từ thuở đầu","chuong":"@c0093"},{"text":"Được xác nhận là đệ tử chân truyền Chu Tước Tử, sư muội Kiền Phong, một trong bốn người được chọn kế thừa danh hiệu","chuong":"@c0374"},{"text":"Được Lão tổ Huyễn gia thu làm nghĩa nữ với danh Huyễn Mi, nhờ Hoán huyết đại pháp đạt Vấn Đỉnh hậu kỳ đại viên mãn","chuong":"@c0633"},{"text":"Bị Huyễn Vô Tình cắn nuốt ý cảnh, trở thành vật hy sinh trong xung đột giữa Huyễn gia và Vương Lâm","chuong":"@c0643"},{"text":"Xác định là Thánh nữ đời thứ bảy của Côn Hư chi cảnh với danh Mộc Băng Mi, gắn với bí mật Thiên Hồn","chuong":"@c0993"},{"text":"Vương Lâm thừa nhận Liễu Mi là người đi vào lòng hắn bằng đau đớn, hình bóng nàng trở thành vết thương không thể xóa trong đạo tâm","chuong":"@c1107"}]},"nguon":["@c1478","@c1500","@c1510","@c1514","@c1516","@c1518","@c1533","@c1515"],"gioiTinh":"nu","canhGioiCaoNhat":"Không rõ","vaiTro":"Thiên đạo bí ẩn — Thánh nữ Côn Hư, nghĩa nữ Huyễn gia, người khắc sâu trong đạo tâm Vương Lâm","tinhCach":"nặng lòng với Vương Lâm nhưng cam chịu không đòi hỏi, lặng lẽ bảo vệ từ xa; kiên định phụng lệnh sư tôn dù biết bị lợi dụng; hành sự quyết liệt khi cần, sẵn sàng luyện oán ảnh để hoàn thành mục đích; cao ngạo lạnh lùng bề ngoài nhưng nội tâm cô độc hiu quạnh","blurb":"Liễu Mi là một thiên đạo sở hữu hàng nghìn phân thân cảm ngộ thiên đạo khắp các nước, bản thể tu luyện trong Hàn Đàm cấm địa phía sau Chu Tước Sơn; nàng mang nhiều thân phận xuyên suốt truyện — đệ tử chân truyền Chu Tước Tử, sư muội Kiền Phong, Thánh nữ đời thứ bảy của Côn Hư chi cảnh với danh Mộc Băng Mi, và nghĩa nữ Lão tổ Huyễn gia với danh Huyễn Mi. Tình cảm đơn phương với Vương Lâm khiến nàng nhiều lần chủ động cảnh báo và bảo vệ hắn, nhưng cũng đưa nàng vào trung tâm xung đột giữa Huyễn gia và Vương Lâm tại La Thiên tinh vực; về sau hình bóng nàng trở thành vết thương không phai trong đạ"},{"id":"hoang-long-chan-nhan","name":"Hoàng Long chân nhân","cn":"黄龙真人","aliases":["Phân thân lão Chu Tước"],"trangThai":"song","tabs":{"kinhLich":[{"text":"Được nhắc: phân thân năm xưa muốn tiến vào tầng thứ 19 hố sâu Phù Văn tộc, nơi ẩn chứa nhiều bí mật.","anchor":"Nơi đó phân thân của Hoàng Long chân nhân vẫn muốn đi vào!","mucCt":"gon","bridge":true,"khoang":"@c1478"},{"chuong":"@c1479","importance":"bridge","mucCt":"gon","tieuDe":"","text":"Được Vương Lâm hồi tưởng: năm đó là phân thân lão Chu Tước, đầu tiên ngăn cản rồi đổi ý cho Vương Lâm vào tầng 18 cảm ngộ, nhưng không đủ lực vào tầng 19 vì phong ấn ngang Thiên Nhân đệ ngũ suy.","anchor":"Hoàng Long – Phân thân của lão Chu Tước xuất hiện, đầu tiên là ngăn cản mình bước vào tầng mười tam"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Chủ trì đại điện tuyên bố đợt tập huấn bốn năm, xuất một vạn linh đan và dùng pháp thuật dịch chuyển tập thể đệ tử","chuong":"@c0035"},{"text":"Thúc Tử Nhạc Tiên Kiếm hóa tử long uy hiếp Thiên Túc Ngô Công, thể hiện thực lực chưởng môn","chuong":"@c0040"},{"text":"Thẩm vấn riêng Vương Lâm về tiên pháp và tu vi thật sau khi chứng kiến năng lực bất thường của Vương Lâm","chuong":"@c0050"},{"text":"Mất Tử Nhạc Tiên Kiếm khi Huyền Đạo Tông chiếm Hằng Nhạc sơn, rút theo tàn quân về Tượng Xà sơn","chuong":"@c0054"},{"text":"Xuất hiện tại chiến trường Liên Minh Bắc Bộ, nhận định Tu Chân Liên Minh thực tế đã thua","chuong":"@c0876"},{"text":"Được xác nhận là phân thân của lão Chu Tước, từng đổi ý cho Vương Lâm vào tầng thứ 19 hố sâu Phù Văn tộc","chuong":"@c1479"}]},"nguon":["@c1478","@c1479"],"gioiTinh":"nam","vaiTro":"Chưởng môn Hằng Nhạc Phái — phân thân của lão Chu Tước","tinhCach":"Uy quyền khi chủ trì đại cục môn phái; cứng rắn, truy vấn kỹ lưỡng khi nghi ngờ; biết bảo toàn lực lượng và giữ thể diện khi lâm nguy; có tầm nhìn xa khi đánh giá cục diện","blurb":"Hoàng Long chân nhân là chưởng môn Hằng Nhạc Phái, sở hữu Tử Nhạc Tiên Kiếm chứa Long Hồn, từng chủ trì tập huấn đệ tử và đích thân đối ứng khi Huyền Đạo Tông đến sơn môn. Sau khi Hằng Nhạc sơn bị chiếm và mất kiếm, ông rút theo tàn quân môn phái, về sau xuất hiện trong hàng ngũ phòng thủ Chu Tước Tinh và tại chiến trường Liên Minh Bắc Bộ. Thân phận thực của ông là phân thân của lão Chu Tước, từng can dự vào việc cho Vương Lâm tiến vào tầng thứ 19 hố sâu Phù Văn tộc."},{"id":"dao-co-diep-mich","name":"Đạo Cổ Diệp Mịch","cn":"道古叶寂","aliases":["Đạo cổ","Diệp Mịch"],"gioiTinh":"nam","tabs":{"kinhLich":[{"chuong":"@c1479","importance":"normal","mucCt":"vua","tieuDe":"Mắt trái bị phát hiện tại tầng 19 hố sâu Phù Văn tộc","text":"Vương Lâm cảm nhận khí tức Đạo Cổ Diệp Mịch từ ký hiệu phong ấn tầng 19, xác nhận mắt trái bị Lý Quảng bắn rơi năm xưa đang bị Phù Văn tộc phong ấn tại đây.","anchor":"Luồng khí tức làm hắn thấy quen thuộc đúng là Đạo Cổ, chính là khí tức của Đạo Cổ Diệp Mịch"},{"chuong":"@c1545","importance":"normal","mucCt":"vua","tieuDe":"Tìm đến động phủ Thất Đạo Tông","text":"Có thanh danh hiển hách tại đại tôn cổ quốc. Tìm đến động phủ Thất Đạo Tông, chỉ trích Thất Thải Đạo Tôn vứt bỏ đạo lữ để đoạt bảo vật rồi lưu đầu mối dẫn hắn đến.","anchor":"Đạo Cổ Diệp Mịch thanh danh hiển hách"},{"chuong":"@c1578","importance":"normal","mucCt":"ky","tieuDe":"Lộ bí mật: không có con trai, chín giọt tâm huyết trong ba ngàn giọt máu","text":"Được Vương Lâm xác nhận: Đạo Cổ Diệp Mịch KHÔNG có con trai. Trước khi chết ba ngàn giọt máu hóa thành ba tộc cổ (Cổ Thần, Cổ Yêu, Cổ Ma), trong đó chín giọt là tâm huyết chứa khí tức cổ tộc cực nồng. Đầu lâu Đạo cổ (không mắt trái) được Vương Lâm triệu hồi trong trận chiến.","anchor":"Đạo Cổ Diệp Mịch không có con trai!"}],"tuViMoc":[],"nhanMach":[{"ten":"Thất Thải Thiên Tôn","tag":"doi-thu","quanHe":"Đối thủ, chỉ trích Thất Thải vứt bỏ đạo lữ đoạt bảo vật"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Để lại hệ thống truyền thừa thí luyện trong cổ mộ: mở đài mộ cấp năm sẽ mở cánh cửa luân hồi, trở thành người thí luyện truyền thừa","chuong":"@c1368"},{"text":"Dung hợp tam đạo: trong trận chiến hư ảo năm xưa tuần tự thi triển thần thuật, yêu thuật và ma thuật của Đạo Cổ","chuong":"@c1380"},{"text":"Mắt trái bị Lý Quảng bắn rơi, phong ấn tại tầng 19 hố sâu Phù Văn tộc","chuong":"@c1479"},{"text":"Có thanh danh hiển hách tại đại tôn cổ quốc; từng tìm đến động phủ Thất Đạo Tông chỉ trích Thất Thải Đạo Tôn","chuong":"@c1545"},{"text":"Trước khi chết, ba ngàn giọt máu hóa thành ba tộc, chín giọt trong đó là tâm huyết; không có con trai nối dõi","chuong":"@c1578"},{"text":"Bị Thất Thải Tiên Tôn dụ tới tông sơn Thất Đạo Tông rồi bị Lý Quảng chém giết; từng vượt kiếp Cổ Mạch Thương Khung Huyết tại cổ miếu cổ quốc","chuong":"@c1599"}]},"nguon":["@c1479","@c1545","@c1578"],"trangThai":"tu-vong","vaiTro":"Chủ nhân cổ mộ — đại năng thượng cổ nắm tam phủ Đạo Cổ, ngoài hàng ngũ tiên tôn","tinhCach":"Bí ẩn, mưu lược sâu xa (thiết kế hệ thống truyền thừa thí luyện nhiều cấp); uy nghiêm, có thanh danh hiển hách tại đại tôn cổ quốc; dung hợp đa đạo, không câu nệ ranh giới thần–yêu–ma","blurb":"Đạo Cổ Diệp Mịch là chủ nhân cổ mộ, một đại năng thượng cổ đạt cảnh giới Cửu tinh Cổ Thần / Cổ Yêu / Cổ Ma, tu vi đủ khiến các tiên tôn e dè dù không nằm trong hàng ngũ tiên tôn. Ông nắm giữ tam phủ Thiên Địa Nhân của Đạo Cổ, dung hợp cả thần thuật, yêu thuật và ma thuật, đồng thời để lại hệ thống truyền thừa thí luyện gồm đài mộ nhiều cấp và cánh cửa luân hồi. Trước khi chết, ông bị Thất Thải Tiên Tôn dụ tới tông sơn Thất Đạo Tông rồi bị Lý Quảng chém giết; ba ngàn giọt máu của ông hóa thành ba tộc, trong đó chín giọt là tâm huyết, và ông không có con trai nối dõi.","theLuc":[{"ten":"Đại tôn cổ quốc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ"},{"id":"ly-quang","name":"Lý Quảng","cn":"李广","aliases":[],"gioiTinh":"nam","tabs":{"kinhLich":[{"chuong":"@c1479","importance":"bridge","mucCt":"gon","tieuDe":"","text":"Được nhắc: năm xưa bắn mũi tên mang huyết mạch tiên nhân khiến mắt trái Đạo Cổ Diệp Mịch rơi rụng tiêu tán trong tinh không.","anchor":"trên mũi tên có máu huyết của Lý Quảng, do vậy mới mang khí tức của huyết mạch tiên nhân"},{"chuong":"@c1481","importance":"bridge","mucCt":"ky","text":"Được hồi tưởng: đưa tay trái kéo dây cung bắn mũi tên, bắn rơi mắt trái Đạo cổ Diệp Mịch trong vùng đất cổ mộ, mũi tên mang thần thông Đạo cổ vô biên bay ra khỏi cổ mộ xuyên thấu tinh không phá tan mấy tu chân tinh.","anchor":"Lý Quảng đưa tay trái kéo dây cung, trên đó có một mũi tên, trong tiếng vù vù ngợp trời, một mũi tên gào thét bay ra"},{"chuong":"@c1482","importance":"normal","mucCt":"gon","tieuDe":"Mũi tên năm xưa bị Vương Lâm thu phục","text":"Mũi tên mà Lý Quảng năm đó bắn rơi mắt trái Đạo cổ nay bị Vương Lâm thu phục làm bảo vật.","anchor":"Một mũi tên của Lý Quảng năm đó bắn rơi mắt trái của Đạo cổ"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Dùng cây cung chín đạo phong ấn bắn mũi tên chứa huyết mạch tiên nhân, ghim trúng mắt trái đầu lâu Đạo Cổ Diệp Mịch rồi hóa đá tử vong","chuong":"@c1380"},{"text":"Được Thất Thải Tiên Tôn thu nạp trợ giúp trong trận chém giết Đạo Cổ Diệp Mịch","chuong":"@c1599"},{"text":"Mũi tên năm xưa bắn rơi mắt trái Đạo Cổ bị Vương Lâm thu phục làm bảo vật","chuong":"@c1482"},{"text":"Nhận truyền thừa cây cung từ lão tổ Lý gia, cung này về sau rơi vào tay Vương Lâm","chuong":"@c1870"},{"text":"Hình ảnh giương cung oai hùng được Vương Lâm hồi tưởng nhiều lần, trở thành hình mẫu bất khuất","chuong":"@c1436"}]},"nguon":["@c1479","@c1481","@c1482","@c1483"],"canhGioiCaoNhat":"Không rõ","trangThai":"khong-ro","vaiTro":"Đạo sĩ áo đen bắn cung — người bắn rơi mắt trái Đạo Cổ Diệp Mịch","tinhCach":"Quyết đoán, dứt khoát trong chiến đấu; thiện xạ phi phàm; oai hùng, bất khuất trước cường địch","blurb":"Lý Quảng là đạo sĩ áo đen nổi danh với tài bắn cung, được Thất Thải Tiên Tôn thu nạp trợ giúp trong cuộc chém giết Đạo Cổ Diệp Mịch tại vùng đất cổ mộ. Ông dùng cây cung lớn mang chín đạo phong ấn bắn mũi tên chứa huyết mạch tiên nhân xuyên qua mọi trở ngại, ghim trúng mắt trái đầu lâu Diệp Mịch rồi hóa đá tử vong. Mũi tên và cây cung năm ấy về sau đều được Vương Lâm thu phục làm bảo vật, còn hình ảnh oai hùng khi giương cung củaông trở thành ký ức không phai trongâm trí Vương Lâm."},{"id":"diep-mich","name":"Đạo cổ Diệp Mịch","cn":"叶觅","aliases":["Diệp Mịch","Đạo cổ","Đạo Cổ Diệp Mịch"],"gioiTinh":"nam","canhGioiCaoNhat":"Không rõ","trangThai":"khong-ro","tabs":{"kinhLich":[{"chuong":"@c1481","importance":"bridge","mucCt":"ky","text":"Được hồi tưởng chi tiết qua ký ức truyền thừa: trong vùng đất cổ mộ từng hóa thân thể khổng lồ chém giết, bị Lý Quảng bắn rơi mắt trái bằng mũi tên, mắt trái chứa ký ức nửa đời và ký ức cố hương, tiếng gào thét đòi trả mắt trái vang trong đầu Vương Lâm.","anchor":"Lý Quảng kia đã bắn rơi mắt trái của ta, trong mắt trái kia có chứa ký ức nửa đời cùng với toàn bộ ký ức về cố hương của ta"},{"chuong":"@c1482","importance":"normal","mucCt":"gon","tieuDe":"Lầu các địa phủ được cân nhắc nhưng chưa dùng","text":"Vương Lâm lấy lầu các địa phủ của Đạo cổ Diệp Mịch ra cân nhắc dùng ba thần hồn bên trong gia tăng mũi tên, nhưng quyết không thả vì thực lực chưa đủ.","anchor":"Lầu các này chính là địa phủ của Đạo cổ Diệp Mịch mà Vương Lâm tìm được trong vùng đất Cổ Thần"},{"importance":"major","mucCt":"gon","chuong":"@c1576","tieuDe":"Khí tức Đạo cổ lộ diện từ chín quan tài","text":"Khí tức Đạo cổ biến đổi giữa Cổ Thần – Cổ Ma – Cổ Yêu bùng lên từ chín quan tài trên tấm bia đá khổng lồ của giới ngoại, được Vương Lâm nhận ra thuộc về Đạo cổ Diệp Mịch. Giới ngoại gọi đây là thân thể chia chín phần của Thái cổ hoàng thần. Vương Lâm phán đoán đây không phải mắt trái.","anchor":"Luồng khí tức này vô cùng quen thuộc. Nó thuộc về Đạo cổ Diệp Mịch"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Trong vùng đất cổ mộ từng hóa thân thể khổng lồ chém giết, khí tức biến đổi giữa Cổ Thần – Cổ Ma – Cổ Yêu, nhưng bị bắn rơi mắt trái khiến truyền thừa không hoàn chỉnh","chuong":"@c1481"},{"text":"Khí tức Đạo Cổ bùng phát từ chín quan tài trên tấm bia đá khổng lồ, biến đổi giữa ba dạng Cổ Thần – Cổ Ma – Cổ Yêu","chuong":"@c1576"},{"text":"Nguyên thần ẩn trong huyết ngưng tụ thành thực chất, mưu đoạt xá Vương Lâm nhưng thất bại và tiêu tán vĩnh viễn","chuong":"@c1672"},{"text":"Trái tim khổng lồ trăm trượng ở tầng cuối cổ mộ — di thể cuối cùng mang thần niệm thê lương oán hận — được truyền thừa cho Vương Lâm","chuong":"@c1680"},{"text":"Truyền thừa vẫn thiếu phần mắt trái chưa tìm được, khiến ký ức Vương Lâm nhận từ Diệp Mịch chưa trọn vẹn","chuong":"@c1729"},{"text":"Được Vương Lâm dùng làm mốc suy xét hệ thống lực lượng Cổ Tộc, thực lực được xem là tương đương Thiên Tôn","chuong":"@c1903"}]},"nguon":["@c1481","@c1482","@c1576"],"vaiTro":"Đạo Cổ — chủ nhân cổ mộ truyền thừa, nguồn gốc sức mạnh thể chất mà Vương Lâm thừa kế","blurb":"Diệp Mịch, được gọi là Đạo Cổ, là chủ nhân vùng đất cổ mộ và nguồn gốc toàn bộ truyền thừa thể chất mà Vương Lâm tiếp nhận. Năm xưa từng hóa thân thể khổng lồ chém giết trong cổ mộ, khí tức biến đổi giữa Cổ Thần – Cổ Ma – Cổ Yêu, nhưng bị bắn rơi mắt trái khiến truyền thừa không hoàn chỉnh; di thể gồm đầu lâu, hai cánh tay, trái tim cùng lầu các địa phủ chứa ba thần hồn lần lượt được Vương Lâm dung hợp. Nguyên thần ẩn trong huyết từng mưu đoạt xá Vương Lâm nhưng thất bại và tiêu tán vĩnh viễn; trái tim khổng lồ trăm trượng ở tầng sâu nhất cổ mộ mang thần niệm oán hận trở thành di sản truyền th","tinhCach":"kiên ngạnh bất khuất, dù thất bại vẫn lưu lại truyền thừa cho hậu nhân; mưu tính thâm viễn, ẩn giấu nguyên thần trong huyết mưu đoạt xá người thừa kế; oán niệm dai dẳng, thần niệm thê lương tồn tại đến tận di thể cuối cùng"},{"id":"huyet-than-tu","name":"Huyết Thần Tử","cn":"血神子","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1482","importance":"normal","mucCt":"vua","tieuDe":"Cổ Yêu bị phá phong ấn luyện hóa, hồn phách được lưu giữ","text":"Cổ Yêu trên người Huyết Thần Tử bị Vương Lâm phá phong ấn, đập tan yêu tinh dồn yêu lực vào pho tượng. Vương Lâm giữ lời hứa năm xưa, lưu hồn phách cổ Yêu phong ấn cất giữ, dự định rời đi sẽ thả.","anchor":"Theo lời hứa năm đó, Vương Lâm không g**t ch*t cổ Yêu của Huyết Thần Tử mà lưu lại hồn phách của hắn"}],"diem":[{"text":"Phá lời thề truy vào La Thiên Tinh vực truy sát Vương Lâm, bị phản chế bằng sinh tử Diêu Tích Tuyết và mất nửa Huyết Thân","chuong":"@c0717"},{"text":"Bỏ Huyết Thân, nguyên thần chạy trốn khỏi Thiên Kiếp sau khi bị Vương Lâm dẫn lôi kiếp truy kích","chuong":"@c0724"},{"text":"Bị Thanh Thủy ép sát, hiến tế Diêu Vân cho Cổ Yêu hút huyết nhục và nguyên thần để lấy Cổ Đăng nghịch chuyển cục diện","chuong":"@c0804"},{"text":"Giao chiến một đối một với Hắc Sát Ma Tôn trong đại chiến La Thiên – Liên Minh","chuong":"@c0863"},{"text":"Được Vương Lâm giải phóng khỏi Phong Tiên Ấn, buông bỏ thù hận và được trả tự do","chuong":"@c0975"},{"text":"Bị Vương Lâm dùng khí tức Đạo cổ dung hợp đầu lâu Đạo cổ xuyên thấu nguyên thần mà giết, kết thúc tuyến nhân vật","chuong":"@c1406"}]},"nguon":["@c1482"],"vaiTro":"Lão tổ trấn tộc Diêu gia — cường giả đại gia tộc truyền thừa Tiên giới tại La Thiên Đông Vực","tinhCach":"quyết đoán tàn nhẫn, không tiếc hiến tế hậu bối hay bảo bối để đạt mục đích; âm trầm thâm hiểm, luôn ẩn nhẫn quan sát trước khi ra tay; cương ngạnh, dám đối đầu cả Thanh Thủy và các Ma Tôn; cuối đời lộ sợ hãi tuyệt vọng khi đối diện Vương Lâm đã vượt tầm kiểm soát","blurb":"Huyết Thần Tử là Lão Tổ trấn tộc của Diêu gia tại La Thiên Đông Vực, thế lực cốt lõi khiến Diêu gia được liệt vào hàng đại gia tộc truyền thừa Tiên giới. Từ khi Diêu gia ban Thiên Khung Lệnh truy sát Vương Lâm, ông nhiều lần trực tiếp can thiệp — phá lời thề truy vào La Thiên Tinh vực, ép hậu bối làm khí hồn, hiến tế Diêu Vân cho Cổ Yêu, giao chiến Thanh Thủy rồi đối đầu Hắc Sát Ma Tôn và Vân Long Yêu Tôn trong đại chiến La Thiên – Liên Minh. Sau khi hồi phục thương thế và tái xuất, Huyết Thần Tử rốt cuộc bị Vương Lâm dùng khí tức Đạo cổ dung hợp đầu lâu Đạo cổ xuyên thấu nguyên thần mà giết c"},{"id":"nam-chieu-thuong-nhan","name":"Nam Chiếu Thượng Nhân","cn":"南诏上人","trangThai":"khong-ro","tabs":{"kinhLich":[{"chuong":"@c1482","importance":"normal","mucCt":"gon","tieuDe":"Hồn bị lôi ra gia tăng mũi tên","text":"Hồn bị phong ấn trong Thiên Hoàng Lô, bị Vương Lâm lôi ra dung hợp vào ký hiệu trên mũi tên Lý Quảng.","anchor":"hồn của Nam Chiếu và Thiên Triệu trực tiếp bay ra"}],"diem":[{"text":"Cùng Đông Địch Tử đồng chủ trì trận chiến nhập giới đầu tiên, ấn ký mi tâm hiện sương mù đen quay cuồng thể hiện độc công","chuong":"@c1422"},{"text":"Liên thủ lão tổ Hỏa Tước Tộc tấn công Vương Lâm, tay phải hóa đen chứa kịch độc xuyên phá hỏa điểu","chuong":"@c1425"},{"text":"Tung chưởng chứa linh lực Không Linh hút Vương Lâm vào hương hỏa giới của mình để giao chiến","chuong":"@c1426"},{"text":"Bị Huyết Sam phá thân thể, nguyên thần thoát ra, chuyển sang dùng thân dự phòng tiếp tục chiến đấu","chuong":"@c1427"},{"text":"Bị Vương Lâm tiêu diệt bằng Thiên Hoàng Lô, kết cục tu vong","chuong":"@c1432"},{"text":"Hồn bị phong ấn trong Thiên Hoàng Lô, bị Vương Lâm lôi ra dung hợp vào ký hiệu trên mũi tên Lý Quảng","chuong":"@c1482"}]},"nguon":["@c1482"],"vaiTro":"Cường giả bước thứ ba giới ngoại, nổi danh độc công, đồng chủ trì trận chiến nhập giới","tinhCach":"Âm trầm, thiện dụng kịch độc; chiến đấu kiên quyết, sẵn sàng dùng thân dự phòng để tiếp tục giao chiến; hung hãn truy kích, không ngại liên thủ vây sát đối thủ","blurb":"Nam Chiếu Thượng Nhân là tu sĩ bước thứ ba giới ngoại, ngoại hình thanh niên thanh tú nhưng mắt dài nhỏ như hai cái khe, sương mù dày đặc thường trực bao quanh thân. Hắn cùng Đông Địch Tử đồng chủ trì trận chiến nhập giới đầu tiên, sở hữu độc công bổn mạng cực kỳ lợi hại và nhiều lần giao chiến Vương Lâm trong hương hỏa giới. Sau khi bị phá thân phải dùng thân dự phòng tiếp chiến, cuối cùng bị Vương Lâm tiêu diệt bằng Thiên Hoàng Lô, hồn bị phong ấn và dung hợp vào mũi tên Lý Quảng."},{"id":"ma-luong","name":"Mã Lương","cn":"马梁","tabs":{"kinhLich":[],"diem":[{"text":"Đang đào bộ giáp từ xác người khổng lồ Cự Ma tộc thì bỏ ngang để đuổi theo hạt châu phát sáng bay qua","chuong":"@c0101"},{"text":"Bị Hứa Hạo và Cát Dương phục kích; dâng túi trữ vật cầu sống nhưng vẫn bị Cát Dương giết chết, thân xác sau đó bị Vương Lâm đoạt xá","chuong":"@c0103"},{"text":"Vương Lâm dùng thân phận Mã Lương được Phượng Loan lão tổ Nguyên Anh sơ kỳ (Chiến Thần Điện) chính thức thu làm ký danh đệ tử","chuong":"@c0119"}]},"nguon":["@c1483"],"vaiTro":"Nhân vật phụ — đệ tử Chiến Thần Điện, thân xác bị Vương Lâm đoạt xá","tinhCach":"Nhiều kinh nghiệm chiến trường, dày dạn sinh tồn; tham lợi, bỏ mục tiêu hiện tại để đuổi theo bảo vật; tham sống sợ chết, sẵn sàng dâng hết tài sản cầu sống","blurb":"Mã Lương là đệ tử Chiến Thần Điện xuất thân từ Hỏa Phần Quốc, có hơn 30 năm kinh nghiệm tại chiến trường ngoại vực. Khi đang đào bộ giáp từ xác Cự Ma tộc, hắn bỏ giáp đuổi theo hạt châu phát sáng bay qua nhưng bị Hứa Hạo và Cát Dương phục kích, dâng cả túi trữ vật cầu sống vẫn bị giết. Thân xác hắn sau đó trở thành vật chủ cho Vương Lâm đoạt xá, và nhờ thân phận này Vương Lâm được Phượng Loan lão tổ thu làm ký danh đệ tử Chiến Thần Điện."},{"id":"ngan-y-luyen-thi","name":"Ngân Y Luyện Thi","cn":"银衣炼尸","tabs":{"kinhLich":[{"chuong":"@c1545","importance":"normal","mucCt":"ky","tieuDe":"Thân phận nữ tử của tiên tôn được xác nhận","text":"Vương Lâm nhận ra nữ tử mặc quần áo bạc trong ký ức chính là ngân y nữ tử trong khe trữ vật, thân phận là một trong những nữ tử của Thất Thải Thiên Tôn. Nàng từng sợ hãi pho tượng bảy màu vô cùng. Vương Lâm cũng nhớ lời nàng nói cánh cửa không phải do nàng mở ra, liên hệ đó chính là cánh cửa đá mà người điên bước tới.","anchor":"Nữ tử này chính là ngân y nữ tử bên trong khe trữ vật của Vương Lâm"}],"nhanMach":[],"tuViMoc":[],"diem":[{"text":"Bị gọi ra trong cung điện phong kín, tỉnh lại rồi phản kháng dữ dội bằng lốc xoáy","chuong":"@c0931"},{"text":"Lần đầu tiên mở miệng nói chuyện với giọng đứt quãng, nhắc lại lời Hoa Phù cứu nguy trận pháp","chuong":"@c1046"},{"text":"Mơ hồ nhớ lại ký ức, tự thi triển và giải trừ Sinh Tử Cấm thành thạo hơn cả lão bà","chuong":"@c1125"},{"text":"Tự mở khe không gian trữ vật bước ra ngoài sự khống chế của Vương Lâm, bắt nuốt kim tuyến Lan Phi và cảnh báo hương hỏa là âm mưu","chuong":"@c1251"},{"text":"Thủy Đạo Tử nhìn thấy liền lập tức nhận ra thân phận, tâm thần chấn động","chuong":"@c1206"},{"text":"Vương Lâm xác nhận thân phận nàng là nữ tử của một vị tiên tôn","chuong":"@c1545"}]},"nguon":["@c1483","@c1545"],"trangThai":"khong-ro","gioiTinh":"nu","aliases":["ngân y nữ tử"],"vaiTro":"Luyện thi áo bạc của Vương Lâm — nữ tử của một vị tiên tôn","tinhCach":"ban đầu phản kháng dữ dội, về sau trung thành bám sát hộ vệ Vương Lâm; trầm mặc ít nói, giọng đứt quãng như mới học nói; chiến đấu quyết đoán sắc bén; có ý chí tự chủ tiềm ẩn, nhiều lần hành động ngoài khống chế","blurb":"Ngân Y Luyện Thi là nữ thi áo bạc tu vi Tịnh Niết sơ kỳ, bị Vương Lâm gọi ra trong cung điện phong kín và dần trở thành hộ vệ thủy chung theo sát hắn qua vô số biến cố. Nàng từng mơ hồ nhớ lại ký ức cũ, tự thi triển Sinh Tử Cấm, nhiều lần tự ý hành động ngoài sự khống chế của Vương Lâm, đồng thời được Thủy Đạo Tử nhận ra thân phận ngay khoảnh khắc nhìn thấy. Về sau Vương Lâm xác nhận nàng chính là nữ tử của một vị tiên tôn, mang lai lịch liên hệ tới những bí mật thượng cổ."},{"id":"tu-do-nam","name":"Tư Đồ Nam","cn":"司徒南","tabs":{"kinhLich":[{"chuong":"@c1520","importance":"normal","mucCt":"ky","tieuDe":"Đột phá bước thứ ba, tử chiến Chu Tước Tinh","text":"Ba mươi năm trước, được Thanh Lâm trợ giúp phá không môn, Tư Đồ Nam chính thức trở thành tu sĩ bước thứ ba. Không theo Thanh Lâm về La Thiên mà quay lại Chu Tước Tinh — cố hương huynh đệ, nơi Vương Lâm mất tích — quyết tử chiến. Mặc đại bào tím, tóc bạc trắng, xông vào chém giết giới ngoại. Cùng Long Bàn Tử đấu nam tử áo thanh y nhưng liên tiếp bại lui, sắc mặt đại biến. Khi Không Môn xuất hiện, khiếp sợ tưởng giới ngoại có thêm tu sĩ bước thứ ba.","anchor":"Tư Đồ Nam hắn không muốn ra đi một mình"},{"mucCt":"vua","text":"Mơ hồ nhận ra khí tức từ không môn giống huynh đệ của mình, cực kỳ kích động và kỳ vọng. Cùng Long Bàn Tử, Lỗ Phu Tử lao vào phản công giới ngoại nhưng bị sương mù tím (Thái Cổ Ngũ Tôn) quét trúng, phun máu sụp đổ. Trong lúc nguy cấp kích hoạt ngọc giản pháp bảo Thanh Lâm tặng (ngọc giản vỡ tan) để thoát thân, được Long Bàn Tử cuốn rút vào Chu Tước Tinh.","anchor":"Khí tức này.sao lại giống huynh đệ ta như vậy.","bridge":true,"khoang":"@c1521"},{"chuong":"@c1523","importance":"bridge","mucCt":"gon","text":"Run rẩy vui mừng lẫn sợ hãi, điên cuồng cười khẳng định huynh đệ chưa chết khi cảm nhận khí tức Vương Lâm.","anchor":"hắn chưa chết mà, hắn vẫn chưa chết"},{"chuong":"@c1524","importance":"bridge","mucCt":"vua","text":"Nắm chặt tay, thần sắc cực kỳ lo lắng cho Vương Lâm mở Không Môn. Nhớ lại bản thân mở Không Môn năm xưa có Thanh Lâm trợ giúp mà vẫn chịu đau khổ, biết cửa Vương Lâm dẫn động còn hùng mạnh hơn vô số lần.","anchor":"Bản thân hắn khi mở Không Môn có Thanh Lâm trợ giúp"},{"chuong":"@c1525","importance":"bridge","mucCt":"gon","text":"Cùng nhóm người giới nội khiếp sợ khi chứng kiến Không Môn thứ hai xuất hiện.","anchor":"Không chỉ có tu sĩ giới ngoại khiếp sợ mà còn có đám người Tư Đồ Nam của giới nội"},{"importance":"bridge","mucCt":"vua","chuong":"@c1529","text":"Cười lớn nhìn Vương Lâm trong vòng xoáy ở đằng xa, ánh mắt hưng phấn trước uy thế một tiễn quét sạch Côn Hư.","anchor":"Tư Đồ Nam cười ha hả, nhìn Vương Lâm trong vòng xoáy ở đằng xa"},{"mucCt":"vua","text":"Từ Chu Tước Tinh bay ra cùng mọi người muốn hội ngộ Vương Lâm, được Vương Lâm hẹn sau khi phá thiên kiếp sẽ uống rượu. Lo lắng nhìn Vương Lâm đứng giữa tinh không, muốn trợ giúp nhưng bị sức mạnh thiên kiếp đẩy lùi, không thể tới gần.","anchor":"Tư Đồ Nam nhìn Vương Lâm đang đứng giữa tinh không ở đằng xa, ánh mắt lộ ra vẻ lo lắng","bridge":true,"khoang":"@c1531"},{"chuong":"@c1532","importance":"bridge","mucCt":"gon","text":"Đứng ngoài vùng sương mù quan sát thiên kiếp của Vương Lâm, xung lực lôi đình quét ra khiến nhóm hắn lộ vẻ hoảng sợ.","anchor":"khiến cho đám người Tư Đồ Nam ở bên ngoài đám sương mù trong tiếng ầm ầm, ánh mắt lộ ra vẻ hoảng sợ."},{"chuong":"@c1533","importance":"bridge","mucCt":"gon","text":"Ở ngoài sương mù trăm vạn dặm, cùng mấy ngàn tu sĩ giới nội nghe được lời Vương Lâm chất vấn thiên kiếp.","anchor":"truyền vào trong tai đám người Tư Đồ Nam cùng với mấy ngàn tu sĩ giới nội kia"},{"mucCt":"vua","text":"Cảm thấy Vương Lâm gặp nguy, Tư Đồ Nam quay mạnh đầu lại, hai mắt tràn ngập vẻ điên cuồng, định lao vào sương mù. Bị Nam Vân Tử cản lại thì nổi sát khí đối đầu dù biết mình yếu hơn, sau đó đặt hạn nửa nén nhang, nếu bên trong vẫn yên tĩnh thì nhất định xông vào.","anchor":"Ta sẽ chờ nửa nén nhang, nếu sau nửa nén nhang mà vẫn yên tĩnh như vậy, ta nhất định phải xông vào","bridge":true,"khoang":"@c1534"},{"chuong":"@c1535","importance":"bridge","mucCt":"vua","text":"Ở ngoài sương mù cùng mấy ngàn tu sĩ giới nội, bị uy áp của Phong Mệnh Hoàn ép phải lùi lại.","anchor":"Mấy ngàn tu sĩ, bao gồm cả Tư Đồ Nam đều lập tức lùi lại phía sau"},{"mucCt":"vua","text":"Vương Lâm tìm kiếm vận mệnh hắn trong mặt trời thứ chín nhưng hoàn toàn không thấy. Vận mệnh dường như chưa từng xuất hiện bên trong, gợi ý không thuộc hệ thống vận mệnh của động phủ.","anchor":"Vận mệnh của Thanh Thủy và Tư Đồ Nam dường như chưa từng xuất hiện bên trong mặt trời thứ chín này.","bridge":true,"khoang":"@c1540"},{"chuong":"@c1541","importance":"bridge","mucCt":"vua","text":"Được Vương Lâm nhắc tới khi tìm kiếm trong mặt trời thứ chín: không tìm thấy khí tức vận mệnh, suy luận thiên tư kinh người và tu vi bạo tăng mỗi lần gặp có thể bởi vận mệnh không nằm trong mặt trời thứ chín.","anchor":"thiên tư của hắn kinh người, tu vi mỗi một lần gặp lại đều bạo tăng"},{"mucCt":"ky","text":"Chờ đợi Vương Lâm bên ngoài viễn cổ tiên vực cùng mấy ngàn tu sĩ. Phát hiện vẻ mê man của Vương Lâm khi trở về. Đồng ý uống say cùng Vương Lâm mà không hỏi lý do. Trong cuộc rượu trên đỉnh núi, nhắc lại quan điểm: thế gian không có trường sinh, chỉ vì sợ chết mà theo đuổi bất tử. Nhớ lại năm xưa Vương Lâm mới luyện khí đã nói không bỏ được cha mẹ, không muốn chặt đứt thất tình lục dục. Đoán đúng Vương Lâm sau khi giết tiên nhân sẽ lục soát trí nhớ. Khi nghe Vương Lâm tiết lộ giới nội giới ngoại chỉ là động phủ của viễn cổ tiên tôn, sửng sốt đứng phắt dậy ngẩng đầu nhìn bầu trời, ánh mắt lộ vẻ khiếp sợ, cuối cùng vô thức buông rơi bầu rượu.","anchor":"Tư Đồ Nam vô thức buông bầu rượu trong tay ra, xoảng một tiếng liền rơi xuống đất.","bridge":true,"khoang":"@c1551"},{"mucCt":"vua","text":"Nghe Vương Lâm tiết lộ bí mật thiên địa: giới nội giới ngoại chỉ là động phủ của Thất Thải Tiên Tôn. Rơi vào trầm mặc, thần sắc mờ mịt, vừa không thể tin vừa tin vì người nói là Vương Lâm — huynh đệ mà hắn nhìn lớn lên. Sợ hãi khi nghĩ mình chỉ là đồ chơi bị sắp đặt.","anchor":"Hắn hiểu rõ Vương Lâm, hắn gần như là nhìn Vương Lâm trưởng thành","bridge":true,"khoang":"@c1552"},{"chuong":"@c1553","importance":"bridge","mucCt":"gon","text":"Theo sát phía sau Vương Lâm khi xuất chinh ra khỏi Chu Tước Tinh vào tinh không.","anchor":"còn có huynh đệ Tư Đồ Nam của hắn"},{"importance":"bridge","mucCt":"vua","chuong":"@c1556","text":"Dẫn mấy ngàn tu sĩ tới Triệu Hà, chứng kiến tinh vực đã được Vương Lâm quét sạch tu sĩ giới ngoại, đại quân theo sau bước chân Vương Lâm tiến về phía trước.","anchor":"Khi Tư Đồ Nam và mấy ngàn tu sĩ tới Triệu Hà thì bọn họ nhìn thấy một Triệu Hà không còn bóng tu sĩ giới ngoại!"},{"chuong":"@c1566","importance":"bridge","mucCt":"gon","tieuDe":"","text":"Cùng mấy ngàn tu sĩ đến muộn không tham chiến, trở thành lực lượng bảo vệ cho tu sĩ giới nội chữa thương.","anchor":"Tư Đồ Nam và mấy ngàn tu sĩ cũng từ xa tiến lại"},{"chuong":"@c1571","importance":"bridge","mucCt":"gon","text":"Nằm trong số tu sĩ La Thiên Tinh Vực đứng dậy vái lạy anh hồn.","anchor":"Nam Vân Tử, Tư Đồ Nam, Hồng Sam Tử, tất cả tu sĩ đều không hề có ngoại lệ"}],"tuViMoc":[{"chuong":"@c1520","canhGioi":"Bước thứ ba","text":"Ba mươi năm trước được Thanh Lâm trợ giúp phá không môn, trở thành tu sĩ bước thứ ba.","importance":"major"}],"nhanMach":[],"diem":[{"text":"Tiết lộ thân phận cường giả lục cấp Chu Tước Quốc, bị truy sát thân hủy, tinh hoa Nguyên Anh ẩn vào Thiên Nghịch Châu theo sát Vương Lâm","chuong":"@c0047"},{"text":"Đoạt xá thành công thân đồng tử áo đỏ trong khối viêm băng, nuốt tứ tổ Tiên Di Tộc, bản lãnh đạt Vấn Đỉnh kỳ","chuong":"@c0411"},{"text":"Được Thanh Lâm trợ giúp phá Không Môn, chính thức trở thành tu sĩ bước thứ ba, tham chiến bảo vệ Chu Tước Tinh","chuong":"@c1520"},{"text":"Được xác nhận là phách thứ hai màu xanh của Thất Thải Tiên Tôn, phách ẩn chứa toàn bộ tu vi Không Kiếp","chuong":"@c1650"},{"text":"Được Vương Lâm gửi gắm trọng trách: nếu Vương Lâm chết, bố cáo thiên hạ sự thật và viết thành ngọc giản lưu truyền","chuong":"@c1588"},{"text":"Được Vương Lâm cứu thoát khỏi Đan Hải, chia tay huynh đệ trước biến cố lớn","chuong":"@c1752"}]},"nguon":["@c1483","@c1520","@c1521","@c1523","@c1524","@c1525","@c1529","@c1531","@c1532","@c1533","@c1534","@c1535","@c1540","@c1541","@c1551","@c1552","@c1553","@c1556","@c1566","@c1571"],"canhGioiCaoNhat":"Không rõ","trangThai":"song","gioiTinh":"nam","vaiTro":"Huynh trưởng Vương Lâm — cường giả Chu Tước, phách thứ hai của Thất Thải Tiên Tôn","tinhCach":"Kiêu ngạo ngang tàng, hành sự bá đạo không kiêng nể; tàn nhẫn quyết đoán nhưng trọng nghĩa tình với huynh đệ; nóng nảy bốc đồng, dễ kích động vì người thân; phong lưu phóng khoáng, thích tự do không chịu ràng buộc","blurb":"Tư Đồ Nam vốn là cường giả lục cấp đệ nhất của Chu Tước Quốc, bị kẻ địch từ thất cấp tu chân quốc truy sát đến thân hủy, chỉ còn tinh hoa Nguyên Anh ẩn trong Thiên Nghịch Châu, từ đó theo sát Vương Lâm hàng trăm năm, vừa chỉ điểm tu luyện vừa nhiều lần xả thân bảo vệ. Sau khi đoạt xá thành công và phục hồi thực lực, ông trải qua Vấn Đỉnh, Tịnh Niết rồi được Thanh Lâm trợ giúp phá Không Môn bước vào bước thứ ba, cùng Vương Lâm chinh chiến tinh không trong cuộc đại chiến giới nội giới ngoại. Về sau được xác nhận chính là phách thứ hai màu xanh của Thất Thải Tiên Tôn, ẩn chứa toàn bộ tu vi Không "},{"id":"dang-hoa-nguyen","name":"Đằng Hóa Nguyên","cn":"","tabs":{"kinhLich":[{"chuong":"@c1500","importance":"bridge","mucCt":"gon","text":"Tại Đằng gia Thành đang đả tọa, mở bừng mắt hoảng sợ hãi hùng khi cảm nhận khí tức từ chỉ lực Vương Lâm.","anchor":"Toàn thân hắn tràn ngập một cảm giác khiến hắn hãi hùng khiếp vía"}],"nhanMach":[],"tuViMoc":[],"diem":[{"text":"Phân thân sương vàng cảm ứng cháu nội Đằng Lệ bị luyện hóa, khởi đầu mối thù với Vương Lâm","chuong":"@c0072"},{"text":"Đích thân diệt toàn bộ Vương gia hơn trăm người để thực hiện lời nguyền báo thù","chuong":"@c0087"},{"text":"Phóng Nguyên Anh xuất xác, dùng trớ chú lưới máu giam Vương Lâm và lấy hồn phách phụ mẫu Vương Lâm phong vào Hồn Kỳ làm con tin","chuong":"@c0100"},{"text":"Bế quan hơn 400 năm đạt Nguyên Anh hậu kỳ, hoàn thành thề nguyện","chuong":"@c0210"},{"text":"Đối mặt Vương Lâm vây thành diệt tộc chín ngày, chứng kiến hạch tâm tộc nhân lần lượt bị giết","chuong":"@c0221"},{"text":"Giả ý xóa bỏ ân oán cầu tha mạng bất thành, bị Vương Lâm giết — mối thù ba đời kết thúc","chuong":"@c0222"}]},"nguon":["@c1483","@c1500","@c1515"],"gioiTinh":"nam","aliases":["lão tổ Đằng gia"],"trangThai":"song","vaiTro":"Phản diện dài hạn — lão tổ Nguyên Anh trấn giữ Đằng Gia, truy thù Vương Lâm qua ba đời","tinhCach":"Bảo hộ gia tộc bằng mọi giá, yêu quý hạch tâm tộc nhân hơn hết thảy; báo thù dai dẳng, quyết liệt, không từ thủ đoạn; tàn nhẫn diệt tuyệt huyết thân kẻ thù; đường cùng giả nhân nghĩa cầu sống","blurb":"Đằng Hóa Nguyên là lão tổ Nguyên Anh trấn giữ Đằng Gia thành — gia tộc tu chân đệ nhất Triệu quốc, ông nội của Đằng Lệ. Khi phân thân thần thức cài trong linh hồn cháu cảm ứng được lúc Đằng Lệ bị luyện hóa, hắn lần theo trớ chú truy sát Vương Lâm, diệt toàn bộ hơn trăm người Vương gia để thi hành lời nguyền, rồi bế quan hơn bốn trăm năm đạt Nguyên Anh hậu kỳ. Cuối cùng hắn vẫn không thoát khỏi cuộc vây thành diệt tộc của Vương Lâm — bị giết tại Đằng Gia thành, khép lại mối thù ba đời."},{"id":"lam-mong-dao-ton","name":"Lam Mộng Đạo Tôn","cn":"蓝梦道尊","aliases":["Lam Mộng"],"gioiTinh":"nam","theLuc":[{"ten":"Thái Cổ Tinh Thần","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không Huyền hậu kỳ viên mãn đỉnh phong","trangThai":"song","vaiTro":"Thái Cổ Ngũ Tôn — lãnh đạo Lam Ti Tộc, người sinh ra trong giới nội","tinhCach":"Thâm trầm u buồn, nặng tình cảm gia đình; điềm tĩnh thận trọng, coi trọng nhân quả; trọng nghĩa khí, sẵn sàng xả thân hộ người thân; phức tạp nội tâm, hay hối hận và trầm mặc","blurb":"Lam Mộng Đạo Tôn là một trong Thái Cổ Ngũ Tôn, tu vi Không Huyền đại viên mãn, lãnh đạo Lam Ti Tộc tại Lam Sơn và được tiết lộ là người sinh ra trong giới nội. Ông từng chiêu mộ Vương Lâm kế thừa đạo thống không thành nhưng vẫn truyền thần thông, nhiều lần can thiệp hộ Vương Lâm trong các biến cố lớn, từ cuộc đối đầu Thiên Nghịch đến đại chiến Chưởng Tôn. Dù từng vì ước định với Chưởng Tôn mà xuất thủ chặn Vương Lâm, về sau ông dứt khoát tuyên bố đứng về phía Vương Lâm, một mình đánh bại ba đạo tôn, và trở thành người mạnh nhất tọa trấn tân Tiên Giới cho đến khi bị Xích Hồn Giáo đánh trọng thư","tabs":{"diem":[{"text":"Lộ diện lần đầu, tự xưng danh tính là chủ nhân bàn tay khổng lồ tấn công Thất Thải giới","chuong":"@c1156"},{"text":"Chiêu mộ Vương Lâm kế thừa đạo thống thất bại, truyền ba thức thần thông gồm Phiên Thiên, Quang Ảnh Thuẫn và Dung biến đạo thuật","chuong":"@c1243"},{"text":"Xuất thủ chặn Vương Lâm theo ước định với Chưởng Tôn, ân đoạn nghĩa tuyệt","chuong":"@c1492"},{"text":"Tuyên bố đứng về phía Vương Lâm, tiết lộ bản thân là người sinh ra trong giới nội, kể bí mật ngũ phi","chuong":"@c1582"},{"text":"Một mình đánh bại Diệu Âm Đạo Tôn, Cửu Thiên và Đại Hoang Thượng Nhân trong ba ngày, tự xưng Thái Cổ Ngũ Tôn","chuong":"@c1583"},{"text":"Dùng tu vi cả đời phong ấn Chưởng Tôn ba nhịp thở, nói kết thúc nhân quả với Vương Lâm","chuong":"@c1679"}],"kinhLich":[{"chuong":"@c1484","importance":"normal","mucCt":"vua","tieuDe":"Hiện thân cảnh báo Vương Lâm về sát kiếp","text":"Lam quang ngưng tụ thành thân ảnh nam tử trung niên áo lam, hiện thân trước Vương Lâm trong vùng thiên địa vây khốn. Nói rõ vùng thiên địa do tất cả cao thủ Không Huyền Thái Cổ Tinh Thần liên thủ cùng Viễn Cổ Tiên Phi bố trí, tồn tại ba canh giờ. Khẳng định không tham gia giết Phong Tôn đời trước, niệm tình cũ mà báo tin, rồi hóa lam quang tiêu tan.","anchor":"Lão phu niệm tình cũ mà hiện thân báo cho ngươi biết"},{"importance":"major","mucCt":"gon","chuong":"@c1492","tieuDe":"Xuất thủ chặn Vương Lâm — ân đoạn nghĩa tuyệt","text":"Được Chưởng Tôn gọi thực hiện ước định lấy lại thân thể thê tử, thở dài rồi xuất thủ dùng lam quang ngập trời tạo tấm màn chặn lỗ thủng, bắn ngược Vương Lâm trở lại. Từ đây ân nghĩa với Vương Lâm nhất đao lưỡng đoạn.","anchor":"Hắn đã từng nói sẽ không ra tay nhưng giờ phút này cuối cùng vẫn phải xuất thủ rồi"},{"mucCt":"vua","text":"Được nhắc đến khi so sánh các cường giả đối mặt huyền kiếp. Tu vi Không Huyền hậu kỳ viên mãn đỉnh phong, chưa từng vượt huyền kiếp lần đầu. Không phải sợ chết mà còn một việc cuối cùng chưa hoàn thành, không thể đối mặt tiếc nuối sau thất bại.","anchor":"Hắn còn có một việc cuối cùng chưa hoàn thành do đó hắn không thể đối mặt với tiếc nuối sau khi thất bại.","bridge":true,"khoang":"@c1568"},{"mucCt":"vua","text":"Đang đánh đàn trong nhà gỗ trên đỉnh Lam Sơn khi Chưởng Tôn tới đề nghị: dẫn động một mũi tên của Vương Lâm đổi lấy trợ giúp bức hồn phách tiên phi thứ năm ra. Chưởng Tôn tin Lam Mộng sẽ không cự tuyệt.","anchor":"Ngươi nếu có thể dẫn động một mũi tên của hắn thì bổn tôn xin thề lấy huyết mạch tiên nhân của ta","bridge":true,"khoang":"@c1572"}],"tuViMoc":[{"chuong":"@c1568","canhGioi":"Không Huyền hậu kỳ viên mãn đỉnh phong","text":"Được tiết lộ tu vi đạt Không Huyền hậu kỳ viên mãn đỉnh phong, chưa từng vượt qua huyền kiếp lần đầu.","importance":"major"}],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Phong Tôn tái thế, niệm tình cũ với Phong Tôn mà hiện thân cảnh báo về sát kiếp"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1484","@c1492","@c1568","@c1572"]},{"id":"lao-gia-ao-xam","name":"Lão già áo xám","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thái Cổ Tinh Thần","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không Huyền","trangThai":"song","vaiTro":"Cao thủ Thái Cổ Tinh Thần, một trong ba kẻ vây sát Vương Lâm","tinhCach":"Tàn nhẫn quyết đoán; kinh ngạc trước sức mạnh bất thường của mục tiêu","blurb":"Một trong ba cao thủ Không Huyền của Thái Cổ Tinh Thần bị áp chế tu vi còn Không Linh Trung Kỳ, tấn công Vương Lâm trong thiên địa lam quang. Kinh ngạc và mơ hồ sợ hãi trước kim quang bí ẩn trong thần thông của Vương Lâm.","tabs":{"diem":[{"text":"Mơ hồ sợ hãi trước kim quang trong Hô Phong Thuật và Dịch Linh Ấn của Vương Lâm, dù bản thân là cao thủ Không Huyền","chuong":"@c1484"},{"text":"Mơ hồ sợ hãi trước kim quang trong thần thông Vương Lâm dù là cao thủ Không Huyền","chuong":"@c1484"},{"text":"Kinh ngạc và mơ hồ sợ hãi trước kim quang bí ẩn trong thần thông Vương Lâm dù bản thân là cao thủ Không Huyền","chuong":"@c1484"}],"kinhLich":[{"chuong":"@c1484","importance":"normal","mucCt":"vua","tieuDe":"Tấn công Vương Lâm trong sát kiếp Phong Tôn","text":"Xuất hiện đầu tiên tấn công Vương Lâm, phóng chỉ hóa rồng xám mang hương hỏa hồn tạp. Bị 13 hắc long gió kim quang của Hô Phong Thuật đối kháng. Cuối chương kinh ngạc trước kim quang trong Dịch Linh Ấn, mơ hồ cảm thấy sợ hãi.","anchor":"Kim quang này rốt cuộc là cái gì! Không ngờ lại khiến cho ta mơ hồ có một cảm giác run rẩy sợ hãi."},{"chuong":"@c1485","importance":"normal","mucCt":"vua","tieuDe":"Phối hợp vây sát Vương Lâm, bị tiên lôi đánh lui","text":"Dùng chai bùn đất thi triển Đại địa bổn nguyên Táng Linh phối hợp phá Dịch Linh Ấn, áp sát dùng ngón trỏ bùn đất chứa hồn phách hương hỏa điểm mi tâm Vương Lâm. Bị hư ảnh Cổ Thần đánh lui phun máu, sau đó bị tiên lôi của Vương Lâm đánh trúng, hoảng sợ hô xác nhận đó là tiên lực.","anchor":"Tiên lực! Đây là tiên lực!"},{"mucCt":"vua","text":"Kinh hãi gọi Vương Lâm là Phong Tôn. Dùng bùn đất hộ thân chống biển lửa Cổ tán nhưng bị trọng thương, bóp nát ngọc giản để hình chiếu tiêu tán thoát thân trước đợt lửa thứ hai. Bổn tôn tại lầu các cũng phun máu.","anchor":"Phong Tôn! Người này không hổ là Phong Tôn, với tu vi như vậy mà lại có thể thi triển loại thần thông hủy thiên diệt địa này","bridge":true,"khoang":"@c1486"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Mục tiêu vây sát, Phong Tôn tái thế"},{"ten":"Bà lão áo đen","tag":"dong-minh","quanHe":"Đồng đội liên thủ vây sát Vương Lâm"},{"ten":"Nam tử áo trắng","tag":"dong-minh","quanHe":"Đồng đội liên thủ vây sát Vương Lâm"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1484","@c1485","@c1486"]},{"id":"ba-lao-ao-den","name":"Bà lão áo đen","cn":"","aliases":["Bà lão mặc hắc y"],"gioiTinh":"nu","theLuc":[{"ten":"Thái Cổ Tinh Thần","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không Huyền","trangThai":"song","vaiTro":"Cao thủ Thái Cổ Tinh Thần, một trong ba kẻ vây sát Vương Lâm","tinhCach":"Âm hiểm, chuyên tập kích sau lưng","blurb":"Bà lão toàn thân áo đen, cánh tay phải khô héo, một trong ba cao thủ Thái Cổ Tinh Thần vây sát Vương Lâm. Tập kích sau lưng bằng một chỉ nhưng bị Vương Lâm đánh quyền đối kháng, đầu ngón trỏ vỡ nát.","tabs":{"diem":[{"text":"Tập kích sau lưng Vương Lâm nhưng bị đánh vỡ đầu ngón trỏ","chuong":"@c1484"},{"text":"Tập kích phía sau Vương Lâm bằng một chỉ, bị đánh quyền đối kháng vỡ đầu ngón trỏ","chuong":"@c1484"}],"kinhLich":[{"chuong":"@c1484","importance":"normal","mucCt":"gon","tieuDe":"Tập kích Vương Lâm trong sát kiếp Phong Tôn","text":"Xuất hiện phía sau tập kích Vương Lâm bằng một chỉ, bị Vương Lâm xoay người đánh quyền đối kháng, đầu ngón trỏ tay phải vỡ nát.","anchor":"đầu ngón trỏ tay phải vỡ thành từng mảnh tản ra"},{"chuong":"@c1485","importance":"normal","mucCt":"vua","tieuDe":"Phối hợp vây sát Vương Lâm, bị lửa tiên lực đánh lui","text":"Dùng chín móng tay hóa quỷ ảnh phi kiếm phối hợp phá Dịch Linh Ấn và đâm vào thân Vương Lâm, áp sát ấn năm ngón tay quỷ ảnh tử khí vào ngực hắn. Bị hư ảnh Cổ Thần đánh lui phun máu, sau đó bị lửa tiên lực của Vương Lâm bức lui phun máu, hoảng sợ khi nghe xác nhận tiên lực.","anchor":"Tiên.tiên lực!"},{"mucCt":"vua","text":"Nhận xét Phong Tôn đời trước đã cực kỳ khó giết, đời này cũng vậy. Hình chiếu bị biển lửa Cổ tán cắn nuốt sụp đổ, bổn tôn tại lầu các Thái Cổ Tinh Thần phun máu tươi. Sau đó yêu cầu giọng nói bí ẩn trong đại điện giải thích.","anchor":"Phong Tôn đời trước đã cực kỳ khó giết, không ngờ Phong Tôn đời này cũng như vậy","bridge":true,"khoang":"@c1486"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Mục tiêu vây sát"},{"ten":"Lão già áo xám","tag":"dong-minh","quanHe":"Đồng đội liên thủ vây sát Vương Lâm"},{"ten":"Nam tử áo trắng","tag":"dong-minh","quanHe":"Đồng đội liên thủ vây sát Vương Lâm"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1484","@c1485","@c1486"]},{"id":"nam-tu-ao-trang","name":"Nam tử áo trắng","cn":"","aliases":["Nam tử mặc bạch y"],"gioiTinh":"nam","theLuc":[{"ten":"Thái Cổ Tinh Thần","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không Huyền","trangThai":"song","vaiTro":"Cao thủ Thái Cổ Tinh Thần — chủ nhân hàn kiếm, một trong ba kẻ vây sát Vương Lâm","tinhCach":"Lạnh lùng vô tình, sát khí băng hàn; quyết đoán tốc chiến; thực lực chỉ dưới thái cổ ngũ tôn","blurb":"Nam tử áo trắng là cao thủ Thái Cổ Tinh Thần thực lực chỉ dưới ngũ tôn, tham gia vây sát Vương Lâm trong sát kiếp Phong Tôn. Hắn sử hàn kiếm đoản kiếm lam xuyên thấu Quang Ảnh Thuẫn và cắt đứt Dịch Linh Ấn, dùng huyết băng ấn ký phối hợp truy sát, nhưng cuối cùng chạy chậm nhất khi rút lui và bị mũi tên xuyên mi tâm tử vong.","tabs":{"diem":[{"text":"Phóng đoản kiếm lam kèm trụ băng xuyên thấu Quang Ảnh Thuẫn, cắt đứt Dịch Linh Ấn khiến Vương Lâm phun máu","chuong":"@c1484"},{"text":"Dùng máu vẽ ấn ký huyết băng phối hợp phá Dịch Linh Ấn, áp sát vỗ chưởng hàn khí vào thiên linh Vương Lâm","chuong":"@c1485"},{"text":"Thân phận được xác nhận chỉ dưới thái cổ ngũ tôn trong Thái Cổ Tinh Thần","chuong":"@c1486"},{"text":"Cùng Tiên Phi tấn công Vương Lâm nhưng dừng lại khi thấy cung Lý Quảng","chuong":"@c1489"},{"text":"Chạy chậm nhất trong bốn người, cố bóp nát ngọc giản nhưng không phản ứng, bị mũi tên xuyên mi tâm tử vong","chuong":"@c1490"}],"kinhLich":[{"chuong":"@c1484","importance":"normal","mucCt":"vua","tieuDe":"Tấn công Vương Lâm bằng hàn kiếm trong sát kiếp Phong Tôn","text":"Phóng đoản kiếm lam kèm trụ băng xuyên thấu Quang Ảnh Thuẫn, cắt đứt Dịch Linh Ấn khiến Vương Lâm phun máu. Hàn kiếm bị huyết kiếm của Vương Lâm đánh vỡ đôi. Ra lệnh tốc chiến tốc thắng, ba người cùng lao tới.","anchor":"Tốc chiến tốc thắng!"},{"chuong":"@c1485","importance":"normal","mucCt":"vua","tieuDe":"Phối hợp vây sát Vương Lâm, bị một quyền đánh lui","text":"Dùng máu vẽ ấn ký huyết băng phối hợp phá Dịch Linh Ấn, áp sát vỗ chưởng hàn khí vào thiên linh Vương Lâm. Bị hư ảnh Cổ Thần đánh lui phun máu, sau đó bị Vương Lâm từ dưới nước lao lên dùng một quyền cùng đầu lâu đạo cổ đánh lui mấy trăm trượng, phun máu.","anchor":"thân thể nam tử mặc bạch y lập tức bị một quyền này đánh cho lui lại mấy trăm trượng, phun một ngụm máu tươi"},{"mucCt":"ky","text":"Thân phận được xác nhận chỉ dưới thái cổ ngũ tôn trong Thái Cổ Tinh Thần. Lôi ký hiệu bông tuyết từ mi tâm ném vào biển lửa, thi triển Băng Phong Vạn Cổ lấy thọ nguyên làm đạo, đóng băng toàn bộ mặt nước, bầu trời và cả Cổ tán. Tuy nhiên bị Vương Lâm bơm sinh cơ phá vỡ toàn bộ tầng băng. Sau đó bị luồng lửa cuối cùng đóng thành phong ấn ngàn trượng, Vương Lâm tiến tới định giết.","anchor":"Lấy thọ nguyên của lão phu làm đạo, lấy hồn phách băng tuyết làm bầu trời, lấy hàn phong vô vi làm vật dẫn","bridge":true,"khoang":"@c1486"},{"chuong":"@c1487","importance":"bridge","mucCt":"gon","tieuDe":"","text":"Vẫn bị vây trong băng tầng, nữ tử tiên phi bước qua hắn khi tiến tới Vương Lâm.","anchor":"cất bước đi qua nam tử mặc bạch y đang bị vây trong băng tầng"},{"importance":"bridge","mucCt":"gon","chuong":"@c1488","tieuDe":"","text":"Vừa phá tan băng đi ra, sắc mặt tái nhợt, lập tức bị kim quang tiên nhân bất diệt thể chói mắt, biến sắc.","anchor":"sắc mặt tái nhợt vừa đi ra, liền lập tức bị kim quang này làm cho chói mắt"},{"importance":"bridge","mucCt":"gon","chuong":"@c1489","tieuDe":"Tấn công Vương Lâm rồi dừng lại trước cung Lý Quảng","text":"Từ trong khối băng đi ra mang sát khí băng hàn, cùng Tiên Phi tấn công Vương Lâm, nhưng dừng lại khi thấy cung Lý Quảng.","anchor":"nam tử áo trắng đang từ trong khối băng đi ra kia"},{"chuong":"@c1490","importance":"normal","tieuDe":"Bị mũi tên xuyên mi tâm, tử vong","text":"Chạy chậm nhất trong bốn người, cố bóp nát ngọc giản để rời đi nhưng không có phản ứng. Mũi tên xuyên mi tâm, đầu vỡ nát, thân thể tầng tầng tan rã.","anchor":"mũi tên kia đã bay tới, với một tốc độ không thể tưởng tượng được trực tiếp đâm vào mi tâm của nam tử áo trắng này","mucCt":"vua"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Mục tiêu vây sát"},{"ten":"Lão già áo xám","tag":"dong-minh","quanHe":"Đồng đội liên thủ vây sát Vương Lâm"},{"ten":"Bà lão áo đen","tag":"dong-minh","quanHe":"Đồng đội liên thủ vây sát Vương Lâm"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1484","@c1485","@c1486","@c1487","@c1488","@c1489","@c1490"]},{"id":"nu-tu-bi-an-ngu-tang","name":"Nữ tử bí ẩn (Ngũ Tạng Tiên Đạo)","cn":"","aliases":["Nữ tử hình dáng mơ hồ"],"gioiTinh":"nu","vaiTro":"Nhân vật bí ẩn — thi triển Ngũ Tạng Tiên Đạo tấn công Vương Lâm","tinhCach":"Lạnh lùng, mắt lộ hàn ý; tiếng nói êm ái","blurb":"Nữ tử hình dáng mơ hồ bước ra từ hư vô trên bầu trời khi Vương Lâm sắp giết nam tử bạch y. Thi triển Ngũ Tạng Tiên Đạo phá hủy nội tạng Vương Lâm từng cái một, ngay cả lực khôi phục của Cổ thân cũng bất lực trước đạo thuật này.","trangThai":"song","tabs":{"diem":[{"text":"Xuất hiện từ hư vô, can thiệp khi Vương Lâm tiến lại gần nam tử bạch y bị phong ấn","chuong":"@c1486"},{"text":"Thi triển Ngũ Tạng Tiên Đạo phá hủy nội tạng Vương Lâm, vượt qua cả sức khôi phục Cổ thân","chuong":"@c1486"}],"kinhLich":[{"chuong":"@c1486","importance":"major","mucCt":"ky","tieuDe":"Xuất hiện, thi triển Ngũ Tạng Tiên Đạo tấn công Vương Lâm","text":"Từ hư vô bước ra trên bầu trời khi Vương Lâm tiến lại gần nam tử bạch y bị phong ấn. Thi triển Ngũ Tạng Tiên Đạo: chiêu thứ nhất (ngón út) khiến hai quả thận Vương Lâm héo rũ hóa máu tiêu tan, lực khôi phục Cổ thân cũng bất lực. Chiêu thứ hai (ngón vô danh) nhắm vào phế, chiêu thứ ba (ngón giữa) nhắm vào tỳ. Vương Lâm phun máu lui ba bước nhưng sát khí đạt đỉnh điểm.","anchor":"Ngũ tạng tiên đạo. Thứ nhất là thận. Thận suy nhi thương"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối thủ","ghiChu":"Xuất hiện tấn công Vương Lâm bằng Ngũ Tạng Tiên Đạo khi hắn sắp giết nam tử bạch y"}],"tuiDo":{}},"nguon":["@c1486"]},{"id":"giong-noi-dai-dien","name":"Giọng nói già nua trong đại điện","cn":"","aliases":[],"gioiTinh":"khong-ro","vaiTro":"Nhân vật bí ẩn ẩn trong đại điện lầu các Thái Cổ Tinh Thần, tự nhận ràng buộc được Vương Lâm","tinhCach":"Bí ẩn; uy quyền; già nua","blurb":"Giọng nói già nua phát ra từ sâu trong đại điện lầu các Thái Cổ Tinh Thần, khẳng định Vương Lâm vẫn chịu ràng buộc bởi mình. Thân phận và mục đích hoàn toàn chưa rõ.","trangThai":"khong-ro","theLuc":[{"ten":"Thái Cổ Tinh Thần","trangThai":"gan-bo"}],"tabs":{"diem":[{"text":"Tự nhận có ràng buộc trên người Vương Lâm, tuyên bố chưa đến lúc","chuong":"@c1486"}],"kinhLich":[{"mucCt":"gon","text":"Từ sâu trong đại điện trả lời bà lão rằng chưa đến lúc và khẳng định Vương Lâm vẫn còn chịu ràng buộc.","anchor":"Không đến lúc đó.kẻ này vẫn còn chịu ràng buộc bởi ta","bridge":true,"khoang":"@c1486"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Ràng buộc","ghiChu":"Tự nhận có ràng buộc trên người Vương Lâm"}],"tuiDo":{}},"nguon":["@c1486"]},{"id":"nu-tu-tien-phi","name":"Nữ tử tiên phi","cn":"","aliases":["Tiên Phi Âm Nguyệt","Tiên Phi (Âm Nguyệt)"],"gioiTinh":"nu","canhGioiCaoNhat":"Không rõ","trangThai":"tu-vong","tabs":{"kinhLich":[{"chuong":"@c1487","importance":"normal","mucCt":"ky","tieuDe":"Hoàn tất Ngũ tạng, bị Âm Nguyệt hủy dung","text":"Hoàn tất Ngũ tạng kỳ thuật — phá hủy can tạng và tâm tạng Vương Lâm, chặt đứt sinh cơ. Yêu cầu Vương Lâm quỳ gối cầu xin nhưng bị cự tuyệt. Nhận ra kim quang tiên lực của Vương Lâm nhưng không nói. Bị Âm Nguyệt Hữu Tình hủy dung mạo, khe nứt từ mặt lan xuống cổ, trông như lệ quỷ. Nhận ra đây là thần thông Âm Nguyệt Tông, tiết lộ Bạch Phàm từng là phản đồ Âm Nguyệt Tông. Khóe miệng chảy máu lùi hơn mười trượng sau cú đấm Cổ lực của Vương Lâm. Biến ảo cổ cầm thi triển khúc Táng Hoàng Tuyền, tiếng đàn hóa sát khí oanh kích tâm thần Vương Lâm, tuyên bố chỉ tiên tôn mới từng nghe tiếng đàn này.","anchor":"Tiếng đàn của ta cũng chỉ có tiên tôn mới từng được nghe"},{"mucCt":"vua","text":"Tiếng đàn dung hợp với thuật bói toán phối hợp tấn công Vương Lâm. Khi thấy tiên nhân bất diệt thể, run tay dừng đàn. Sau đó cắn răng nhận định bất diệt thể chưa hoàn chỉnh, dựng đàn phóng chín thanh phi đao máu tấn công, bị Tàn Dạ và Lưu Nguyệt phá phần lớn, chỉ còn ba thanh đâm vào Vương Lâm.","anchor":"Tiên nhân bất diệt thể này của hắn vẫn chưa hoàn chỉnh, hiển nhiên là đã học trộm được ở đâu đó, giết","bridge":true,"khoang":"@c1488"},{"mucCt":"vua","text":"Toàn thân tràn ngập Âm Nguyệt, hai mắt lóe hàn quang lao tới tấn công Vương Lâm khi Hư Thần Thiên Tôn bị đẩy ra. Thấy cung Lý Quảng thì hoảng sợ vô cùng, vội vàng lùi lại, bóp ngọc giản muốn rời đi nhưng không có phản ứng.","anchor":"nữ tử toàn thân tràn ngập Âm Nguyệt kia hai mắt lộ ra vẻ hoảng sợ vô cùng, thân thể vội vàng lùi lại","bridge":true,"khoang":"@c1489"},{"chuong":"@c1490","importance":"normal","tieuDe":"Cây đàn Tiên Tôn bị phá, tử vong","text":"Triệu hào quang chống đỡ bị phá, phun máu hóa huyết nhân cũng bị xuyên thấu, lấy cây đàn do Tiên Tôn ban ra chắn nhưng đàn vỡ tan. Mũi tên xuyên mi tâm, thân thể tan rã.","anchor":"cây đàn này liền ầm ầm vỡ tan, biến thành vô số mảnh bị cuốn đi","mucCt":"ky"},{"chuong":"@c1491","importance":"normal","mucCt":"vua","tieuDe":"Bị Xích Hồn Tử nuốt, tử vong","text":"Là người duy nhất sống sót dưới một tiễn, mê man đứng giữa Vương Lâm và Chưởng Tôn. Bị Xích Hồn Tử cuốn lấy, toàn thân bị máu tươi tràn ngập, thân thể tan chảy biến mất — bị cắn nuốt.","anchor":"Bị thân thể hắn cuốn lấy, Tiên Phi kia kêu lên thảm thiết toàn thân bị máu tươi tràn ngập"}],"tuViMoc":[],"nhanMach":[{"ten":"Nữ tử tử y","tag":"ho-hang","quanHe":"Muội muội (nữ tử tử y gọi là tỷ tỷ)","ghiChu":"@c1487"},{"ten":"Bạch Phàm","tag":"khac","quanHe":"Biết Bạch Phàm từng là phản đồ Âm Nguyệt Tông","ghiChu":"@c1487"},{"ten":"Xích Hồn Tử","tag":"doi-thu","quanHe":"Bị Xích Hồn Tử nuốt ngay khi hắn được giải phóng","ghiChu":"Tiên Phi bị tan chảy biến mất."}],"tuiDo":{"phapBao":[{"ten":"Cổ cầm","trangThai":"dang-co","moTa":"Biến ảo ra cổ cầm để gảy khúc Táng Hoàng Tuyền","nguon":"@c1487"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Hoàn tất Ngũ tạng kỳ thuật, phá hủy can tạng và tâm tạng Vương Lâm, chặt đứt sinh cơ của hắn và yêu cầu hắn quỳ gối","chuong":"@c1487"},{"text":"Phối hợp tiếng đàn với thuật bói toán tấn công Vương Lâm, nhưng run tay dừng lại khi thấy tiên nhân bất diệt thể","chuong":"@c1488"},{"text":"Toàn thân tràn ngập lực lượng Âm Nguyệt, lao tới tấn công Vương Lâm khi Hư Thần Thiên Tôn bị đẩy ra","chuong":"@c1489"},{"text":"Cây đàn Tiên Tôn bị phá, phun máu hóa huyết nhân cũng bị xuyên thấu, tử vong lần đầu","chuong":"@c1490"},{"text":"Là người duy nhất sống sót dưới một tiễn, cuối cùng bị Xích Hồn Tử cuốn lấy và nuốt, tử vong hoàn toàn","chuong":"@c1491"}]},"nguon":["@c1487","@c1488","@c1489","@c1490","@c1491"],"vaiTro":"Tiên phi của Âm Nguyệt — địch thủ trực tiếp đối đầu Vương Lâm","tinhCach":"tàn nhẫn, quyết đoán khi hạ sát; kiêu ngạo, yêu cầu đối phương quỳ gối; có phần e sợ trước sức mạnh vượt ngoài nhận thức","blurb":"Tiên phi thuộc thế lực Âm Nguyệt, nắm giữ cây đàn do Tiên Tôn ban tặng và tinh thông Ngũ tạng kỳ thuật. Nàng phối hợp thuật bói toán cùng tiếng đàn để tấn công Vương Lâm, phá hủy can tạng và tâm tạng của hắn, song cuối cùng bị đánh bại — cây đàn Tiên Tôn tan vỡ, bản thân hóa huyết nhân bị xuyên thấu, và là người duy nhất sống sót dưới một tiễn trước khi bị Xích Hồn Tử nuốt, tử vong."},{"id":"nu-tu-tu-y","name":"Nữ tử tử y","cn":"","aliases":["Tiên Phi bói toán","Tiên Phi (thứ hai)","nữ tử thuật bói toán"],"gioiTinh":"nu","vaiTro":"Tiên phi thứ hai — nữ tử tử y thân hư ảo, sở hữu thuật bói thần tiên","tinhCach":"Bình thản khi xuất hiện, cao ngạo tự tin tuyệt đối vào thuật bói; mất bình tĩnh và tuyệt vọng khi đối mặt kẻ mạnh hơn","blurb":"Nữ tử mặc tử y, thân thể hư ảo không phải thực thể, xuất hiện vô thanh vô tức phía sau Vương Lâm. Sở hữu thuật bói thần tiên có thể dự ngôn sinh tử và tấn công bằng ba nhịp thở hủy diệt, nhưng bị áp chế khi đối đầu tiên nhân cấp, phải nhờ viên đá đen của Tiên Tôn mới thoát chết. Gọi nữ tử tiên phi kia là tỷ tỷ, sau đó tái xuất trận từ tinh trận và bị chính tiên phi đó đón đánh.","canhGioiCaoNhat":"Không rõ","trangThai":"song","theLuc":[{"ten":"Viễn Cổ Tiên Phi","trangThai":"gan-bo"}],"tabs":{"diem":[{"text":"Xuất hiện vô thanh vô tức sau lưng Vương Lâm, thân hư ảo khiến huyết kiếm xuyên qua vô hiệu, dự ngữ Vương Lâm tử vong","chuong":"@c1487"},{"text":"Thi triển thuật bói toán ba nhịp thở: thịt nát, tan xương, hồn phách tan — tấn công trực tiếp Vương Lâm","chuong":"@c1488"},{"text":"Mất vẻ cao ngạo, sắc mặt tái nhợt, bóp ngọc giản muốn rời đi nhưng không có phản ứng, bị áp chế","chuong":"@c1489"},{"text":"Tuyệt vọng chờ chết, được viên đá đen hình tròn trên sợi dây chuyền — bảo vật Tiên Tôn — cứu mạng","chuong":"@c1490"},{"text":"Tái xuất trận từ tinh trận, bị tiên phi thứ nhất đón đánh","chuong":"@c1559"}],"kinhLich":[{"chuong":"@c1487","importance":"normal","mucCt":"vua","tieuDe":"Xuất hiện, dự ngữ Vương Lâm tử vong","text":"Xuất hiện vô thanh vô tức phía sau Vương Lâm, thân thể hư ảo khiến huyết kiếm xuyên qua không hiệu quả. Gọi nữ tử tiên phi là tỷ tỷ. Tuyên bố bói cả thần tiên, dự ngữ dùng hồn làm vật dẫn, đoán Vương Lâm trong ba nhịp thở phải tử vong.","anchor":"Ta bói cả thần tiên, đoán được ngươi trong vòng ba nhịp thở phải tử vong"},{"mucCt":"vua","text":"Thi triển thuật bói toán ba nhịp thở tấn công Vương Lâm (thịt nát, tan xương, hồn phách tan). Khi thấy tiên nhân bất diệt thể, kinh hoàng hét lên nói vạn tiên khấu bái, hỏi Vương Lâm có quan hệ gì với Tiên Hoàng, nỗi sợ lớn hơn khi đối mặt Tiên Tôn. Bị Tàn Dạ và Lưu Nguyệt tấn công, phun máu lùi lại, mất hết ý chí chiến đấu.","anchor":"Tiên nhân bất diệt thể, vạn tiên khấu bái. Ngươi không phải là người ở nơi này","bridge":true,"khoang":"@c1488"},{"mucCt":"vua","text":"Sắc mặt tái nhợt, không còn vẻ cao ngạo như trước. Bóp ngọc giản muốn rời đi nhưng cũng không có phản ứng, bị mắc kẹt.","anchor":"sắc mặt cũng tái nhợt, không còn vẻ cao ngạo như trước nữa","bridge":true,"khoang":"@c1489"},{"chuong":"@c1490","importance":"normal","tieuDe":"Viên đá đen Tiên Tôn cứu mạng","text":"Tuyệt vọng nhắm mắt chờ chết khi thấy hai người kia bị giết. Sợi dây chuyền trên cổ có viên đá đen hình tròn phát ánh sáng bảy màu bao phủ toàn thân, mũi tên xuyên qua mi tâm mà không bị thương. Viên đá xuất hiện vết nứt. Sống sót nhờ vật bảo hộ của Tiên Tôn.","anchor":"nhưng lại không bị thương một chút nào, chỉ có hòn đá màu đen đang trôi lưng lửng kia trong tiếng rắc rắc đã xuất hiện một vết nứt","mucCt":"ky"},{"mucCt":"vua","text":"Xuất trận từ tinh trận, bị tiên phi (từng hủy ngũ tạng Vương Lâm) đón đánh.","anchor":"Nàng đến từ Triệu Hà, là người đứng đầu Triệu Hà","bridge":true,"khoang":"@c1559"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Mục tiêu tiêu diệt, dự ngữ ba nhịp thở tử vong","ghiChu":"@c1487"},{"ten":"Nữ tử tiên phi","tag":"ho-hang","quanHe":"Tỷ tỷ","ghiChu":"@c1487"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1487","@c1488","@c1489","@c1490","@c1559"]},{"id":"hu-than-thien-ton","name":"Hư Thần Thiên Tôn","cn":"虚神天尊","aliases":["Lão già trong sương mù tím"],"gioiTinh":"nam","theLuc":[{"ten":"Thái Cổ Ngũ Tôn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không Huyền (phân thân)","trangThai":"song","vaiTro":"Một trong Thái Cổ Ngũ Tôn — cường giả giới ngoại thèm khát thân thể bất diệt của Vương Lâm","tinhCach":"Tham lam, nhiều lần mưu đồ đoạt xá thân thể tiên nhân của Vương Lâm; tàn nhẫn, chuyên tập kích lúc đối phương suy yếu; cao ngạo khinh thường hậu bối nhưng dễ kinh sợ trước sức mạnh ngoài dự liệu; quyết đoán, đích thân ra tay khi thủ hạ bất lực","blurb":"Hư Thần Thiên Tôn là một trong Thái Cổ Ngũ Tôn từ giới ngoại, xuất hiện dưới dạng thân ảnh toàn thân sương mù màu tím, tu vi phân thân đạt Không Huyền sơ kỳ. Nhiều lần mưu đồ đoạt xá thân thể bất diệt của Vương Lâm nhưng liên tiếp thất bại — lần đầu bị cung cổ Lý Quảng tiêu diệt phân thân, lần sau đích thân phá trận Chu Tước Tinh rồi thi triển Vạn Hà Hư Thần Đạo để trấn áp, cuối cùng phân thân vẫn bị Vương Lâm xé nát, bản thể trọng thương bỏ chạy, về sau bị Vương Lâm bắt đưa đi đầu thai.","tabs":{"diem":[{"text":"Xuất hiện dưới dạng thân ảnh sương mù, tự xưng Thái Cổ Ngũ Tôn, đánh Vương Lâm rơi xuống Chu Tước Tinh","chuong":"@c1488"},{"text":"Đoạt xá thân thể bất diệt của Vương Lâm thất bại, phân thân bị mũi tên cung cổ Lý Quảng tiêu diệt","chuong":"@c1490"},{"text":"Đích thân phá trận pháp Chu Tước Tinh, quở trách thủ hạ bất lực, kinh hãi trước sáu đạo bổn nguyên","chuong":"@c1522"},{"text":"Thi triển Vạn Hà Hư Thần Đạo mở khe khổng lồ trấn áp Vương Lâm, phân thân bị chém đôi lộ bản thể","chuong":"@c1528"},{"text":"Phân thân bị Vương Lâm xé nát, bản thể trọng thương bỏ chạy, kinh sợ Cung Lý Quảng","chuong":"@c1529"},{"text":"Bị Vương Lâm tìm đến khi đang bế quan, tuyệt vọng cầu xin tha mạng, bị bắt đưa đi đầu thai","chuong":"@c1698"}],"kinhLich":[{"importance":"normal","mucCt":"ky","chuong":"@c1488","tieuDe":"Xuất hiện, đánh Vương Lâm rơi xuống Chu Tước Tinh","text":"Xuất hiện từ phía sau dưới dạng thân ảnh mơ hồ toàn thân sương mù, tự xưng là một trong Thái Cổ Ngũ Tôn. Đánh một chưởng vào hậu tâm Vương Lâm khi hắn vừa ngưng tụ thân thể, khiến Vương Lâm phun máu vàng bắn xuống Chu Tước Tinh. Hút ngụm máu vàng tiên nhân của Vương Lâm vào miệng, lộ vẻ tham lam, tuyên bố phải lấy bằng được thân thể bất diệt và huyết mạch tiên nhân, rồi hóa mây đuổi theo.","anchor":"Lão phu là một trong Thái Cổ Ngủ Tôn, Hư Thần Thiên Tôn"},{"importance":"normal","mucCt":"ky","chuong":"@c1489","tieuDe":"Đoạt xá tiên thể Vương Lâm thất bại — bị cung Lý Quảng uy hiếp","text":"Đuổi theo Vương Lâm xuống tầng 18 Phù Văn Tộc, lợi dụng thân thể bất diệt đang tan vỡ để hóa sương mù dung nhập đoạt xá tiên thể, gần như thành công khi chiếm phần lớn thân thể. Bị cơn lốc du hồn do Vương Lâm triệu hồi đẩy ra khỏi thân xác, đoạt xá thất bại. Định lao tới đoạt xá lần nữa nhưng thấy Vương Lâm rút cung Lý Quảng thì hoảng sợ lui lại, nhận ra đó là cung của Lý Quảng và mũi tên đã được tìm thấy. Tuyên bố không tham gia nữa, nắm ngọc giản muốn rời đi nhưng không có phản ứng. Trách Chưởng Tôn cố tình không xuất hiện để mình tự đối mặt cung Lý Quảng.","anchor":"Cây cung của Lý Quảng! Ngươi… không ngờ ngươi đã tìm thấy mũi tên kia rồi"},{"chuong":"@c1490","importance":"normal","tieuDe":"Bị mũi tên tiêu diệt, gào gọi Chưởng Tôn","text":"Chạy nhanh nhất ở xa nhất nhưng mũi tên vẫn đuổi kịp. Thân sương mù tan vỡ rồi ngưng tụ nhiều lần, cuối cùng mi tâm vỡ nát, tiêu tán. Trước khi chết gào thét rằng Chưởng Tôn phải giải thích việc này.","anchor":"Chưởng Tôn, lão phu đỡ cho ngươi một tiễn này, người phải giải thích với lão phu","mucCt":"vua"},{"chuong":"@c1516","importance":"normal","mucCt":"vua","tieuDe":"Trọng thương Thanh Thủy giả Vương Lâm","text":"Trong một lần đại chiến giới nội–giới ngoại, Hư Thần Thiên Tôn đánh trọng thương Thanh Thủy (đang hóa thân Vương Lâm tọa trấn), gần khiến Thanh Thủy tử vong. Từ đó tin Phong Tôn tử vong không thể ngăn cản.","anchor":"Thanh Thủy cũng bị Hư Thần Thiên Tôn khiến cho bị trọng thương"},{"chuong":"@c1521","importance":"normal","mucCt":"vua","tieuDe":"Xuất hiện tại chiến trường, đánh bại toàn bộ cao thủ giới nội","text":"Một trong Thái Cổ Ngũ Tôn. Xuất hiện từ sương mù màu tím, một đòn đánh Nam Vân Tử phun máu, quét thương Tư Đồ Nam, Long Bàn Tử, Lỗ Phu Tử, buộc toàn bộ tu sĩ giới nội rút về Chu Tước Tinh. Thần sắc không giận mà uy, lạnh lùng nhìn không môn, đồng tử co rụt.","anchor":"Từ trong đó có một lão già thần sắc không giận mà uy bước ra"},{"chuong":"@c1522","importance":"normal","mucCt":"vua","tieuDe":"Đích thân phá trận pháp Chu Tước Tinh","text":"Quở trách thủ hạ không hạ nổi Chu Tước Tinh suốt mấy tháng, đích thân bước tới. Kinh hãi trước sáu đạo bổn nguyên của không môn, đánh giá người bên trong nếu phá ra sẽ cực mạnh. Một vỗ tay hóa sương mù tím phá nát trận pháp Chu Tước Tinh, bước vào thấy tượng Phong Tôn và mấy ngàn tu sĩ giới nội. Đang định hủy diệt thì biến sắc vì người trong không môn phá môn ra.","anchor":"Hắn chính là Hư Thần Thiên Tôn trong Thái cổ ngũ tôn!"},{"chuong":"@c1523","importance":"normal","mucCt":"vua","tieuDe":"Lao tới đoạt xá Vương Lâm, bị chính khí đại nho bật lùi","text":"Tuyên bố năm xưa đoạt xá thân thể Vương Lâm không thành, nay hắn tự dẫn xác tới thì là vật của lão. Phân thân lao tới cực nhanh nhưng bị một câu quát của Vương Lâm khiến khí tức nhập linh hồn, nhớ lại nỗi sợ nhỏ bé như con kiến, lùi mấy trượng hoảng sợ hiếm thấy.","anchor":"Năm đó lão phu đoạt xá thân thể của ngươi không thành"},{"mucCt":"vua","text":"Hư Thần Thiên Tôn cười lạnh khinh thường, tin rằng tiểu bối dù có sáu đạo bổn nguyên cũng sẽ chết dưới Không Môn không cần lão ra tay. Sau đó sửng sốt khiếp sợ khi thấy lôi đình bổn nguyên Vương Lâm mạnh chưa từng gặp, kêu thất thanh khi cả lôi đình Vân Hải cũng bị dẫn động.","anchor":"Có thể khiến cho Hư Thần Thiên Tôn, một trong Thái cổ ngũ tôn khiếp sợ như vậy","bridge":true,"khoang":"@c1524"},{"mucCt":"ky","text":"Lần đầu tiên thật lòng gọi Vương Lâm là Phong Tôn, thể hiện sự công nhận. Giải thích thông lệ tu sĩ sau khi mở Không Môn phải nhanh chóng hấp thu sức mạnh để bước vào bước thứ ba. Thừa nhận phán đoán trước đây về Không Môn của Vương Lâm là sai. Nhận ra Vương Lâm định mở từng Không Môn theo từng bổn nguyên để thành bước thứ ba toàn năng mạnh hơn vô số lần. Sát khí trong ánh mắt càng nồng đậm hơn.","anchor":"Hắn muốn lấy mỗi đạo bổn nguyên để mở ra một Không Môn","bridge":true,"khoang":"@c1525"},{"mucCt":"vua","text":"Sắc mặt tái nhợt khi nhận ra Không Môn thứ sáu là Vạn Không Cốt Môn trong truyền thuyết. Dẫn lời Tiên Phi rằng người dẫn động được cửa này cực hiếm, nếu không gặp tai họa nhất định thành Đại Tôn.","anchor":"chẳng lẽ chính là Vạn Không Cốt Môn trong truyền thuyết","bridge":true,"khoang":"@c1526"},{"mucCt":"vua","text":"Nhận định thời điểm Vương Lâm dung hợp bổn nguyên là cơ hội cuối cùng để giết hắn, Hư Thần Thiên Tôn không còn che giấu sát khí, lao tới tấn công. Bị một chỉ đạo niệm của Vương Lâm làm tốc độ giảm mạnh, không thể tiếp cận.","anchor":"Hiện giờ hắn đang dung hợp bổn nguyên, chính là thời cơ tốt nhất để giết hắn","bridge":true,"khoang":"@c1527"},{"chuong":"@c1528","importance":"normal","mucCt":"ky","tieuDe":"Phân thân bị Vương Lâm chém đôi, lộ bản thể","text":"Thi triển Vạn Hà Hư Thần Đạo mở khe khổng lồ phóng vô số hồn phách hương hỏa và hàng vạn pho tượng trấn áp Vương Lâm, kết hợp vòng xoáy oan hồn và vòng xoáy Không Môn sụp đổ vây khốn. Hóa sương mù tím thành trường thương vung tới. Bị Vương Lâm phản công liên hoàn bằng Sinh Tử Ấn, Định, Lôi, Hỏa, Nhân Quả, Chân Giả Đạo rồi Sát lục chém đôi thân, hóa hai đám sương tím. Bản thể phân thân lộ ra là đám khí vô hình hư ảo, vội bay đi trốn thoát.","anchor":"Hư Thần Thiên Tôn có tên là Hư Thần bởi vì thân thể của hắn từ xưa đến nay thủy chung đều là hư ảo."},{"importance":"major","mucCt":"ky","chuong":"@c1529","tieuDe":"Phân thân bị diệt, bản thể trọng thương","text":"Phân thân bị Vương Lâm xé nát, bỏ chạy về hướng biên giới Côn Hư và Vân Hải, định rời giới nội. Kinh sợ Cung Lý Quảng và oán Chưởng Tôn năm xưa đưa cung ra, nhận định có cung tên này thì trong giới nội lẫn giới ngoại khó ai giết được Vương Lâm. Mũi tên phá tinh không lao tới xuyên qua thân thể phân thân, phân thân tan thành mây khói. Bản thể trong tinh vực sương mù Thái cổ Tinh Thần phun máu, lảo đảo lùi lại, nhìn về giới nội với kiêng kỵ nặng nề.","anchor":"Hắn phun ra một ngụm máu tươi, thân thể lảo đảo lùi lại"}],"tuViMoc":[{"chuong":"@c1522","canhGioi":"Không Huyền sơ kỳ (phân thân)","text":"Phân thân hiện tại tu vi đạt Không Huyền sơ kỳ.","importance":"major"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Mục tiêu đoạt thân thể bất diệt và huyết mạch tiên nhân","ghiChu":"Tập kích từ phía sau, hút máu tiên nhân, đuổi theo xuống Chu Tước Tinh"},{"ten":"Chưởng Tôn","tag":"dong-minh","quanHe":"Đồng minh trong Thái Cổ Ngũ Tôn","ghiChu":"Trách Chưởng Tôn cố tình không xuất hiện để mình đối mặt cung Lý Quảng"},{"ten":"Thanh Thủy","tag":"doi-thu","quanHe":"Đánh trọng thương Thanh Thủy (giả Vương Lâm)","ghiChu":"@c1516"},{"ten":"Nam Vân Tử","tag":"doi-thu","quanHe":"Đối thủ","ghiChu":"Một đòn đánh bại Nam Vân Tử tại chiến trường Chu Tước Tinh"},{"ten":"Chu Cẩn","tag":"khac","quanHe":"Thủ hạ đi theo","ghiChu":"@c1522"},{"ten":"Chưởng Tôn","tag":"khac","quanHe":"Được hắn nhắc khi đánh giá: ngay cả Chưởng Tôn cũng không thể có sáu đạo bổn nguyên","ghiChu":"@c1522"}],"tuiDo":{}},"nguon":["@c1488","@c1489","@c1490","@c1516","@c1521","@c1522","@c1523","@c1524","@c1525","@c1526","@c1527","@c1528","@c1529"]},{"id":"xich-hon-tu","name":"Xích Hồn Tử","cn":"赤魂子","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Không rõ (linh hồn cực mạnh)","trangThai":"song","blurb":"Xích Hồn Tử là linh hồn cực mạnh bị Đạo cổ Diệp Mịch phong ấn trong Hắc Tháp qua vô số năm. Được Vương Lâm dùng máu Đạo Cổ giải phóng trong sinh tử kiếp Chướng Tôn, hắn nuốt Tiên Phi rồi phá tan phong ấn Tĩnh Trung Lao Nguyệt mà thoát đi. Sau khi khôi phục tu vi đỉnh phong, hắn vây khốn Tiên giới và phá vỡ trận pháp bảo hộ, nhưng cuối cùng tâm thần sụp đổ và bị chính Vương Lâm hủy diệt hoàn toàn.","vaiTro":"Linh hồn cực mạnh bị phong ấn trong Hắc Tháp — cựu thù của Diệp Mịch, kẻ thù cuối cùng bị Vương Lâm hủy diệt","tinhCach":"Điên cuồng, mất kiểm soát sau vô số năm bị giam cầm; thù hận Diệp Mịch cực sâu; kiêu ngạo bất tuân; tâm thần bất ổn, không chấp nhận được thực tại","tabs":{"diem":[{"text":"Được Vương Lâm dùng máu Đạo Cổ giải phong ấn từ Hắc Tháp, gào thét điên cuồng hiện huyết ảnh và nuốt Tiên Phi","chuong":"@c1491"},{"text":"Cười điên cuồng phá tan phong ấn Tĩnh Trung Lao Nguyệt, thiên địa chấn động, tuyên bố ân oán triệt tiêu rồi thoát đi tự do","chuong":"@c1492"},{"text":"Lộ thân thế là hồn phách bị Diệp Mịch phong ấn năm xưa, khôi phục tu vi đỉnh phong và vây khốn Tiên giới","chuong":"@c1962"},{"text":"Phá vỡ trận pháp bảo hộ Tiên giới sau mấy ngày ăn mòn, mở lỗ thủng khổng lồ","chuong":"@c1964"},{"text":"Tâm thần sụp đổ hoàn toàn, viện dẫn quan hệ bạn cũ với La Minh nhưng bị Vương Lâm hủy diệt","chuong":"@c1966"}],"kinhLich":[{"chuong":"@c1491","importance":"major","mucCt":"vua","tieuDe":"Được giải phong ấn, nuốt Tiên Phi","text":"Được Vương Lâm dùng máu Đạo Cổ giải phong ấn từ Hắc Tháp sau vô số năm bị giam. Gào thét điên cuồng, huyết ảnh va vào Chưởng Tôn đẩy lùi hơn mười trượng. Không đánh Chưởng Tôn mà lao nuốt Tiên Phi, toàn thân nàng tan chảy biến mất. Sau đó phá thủng bầu trời lam quang bay ra ngoài.","anchor":"Diệp Mịch đáng chết, ngươi phong ấn Xích Hồn Tử ta đã vô số năm, hôm nay lão phu đã được tự do rồi"},{"importance":"normal","mucCt":"vua","chuong":"@c1492","tieuDe":"Phá phong ấn thoát tự do — ân oán triệt tiêu","text":"Cười điên cuồng phá tan phong ấn Tĩnh Trung Lao Nguyệt, tạo lỗ thủng lớn, thiên địa chấn động. Tuyên bố trên người Vương Lâm có khí tức Đạo cổ, đáng ra phải giết nhưng coi việc Vương Lâm thả hắn như triệt tiêu ân oán, rồi rời đi tự do.","anchor":"Tên nhóc con, trên người ngươi có khí tức của Đạo cổ, lão phu vốn phải giết ngươi"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"an-nhan","quanHe":"Người giải phong ấn cho Xích Hồn Tử","ghiChu":"Vương Lâm dùng máu Đạo Cổ mở Hắc Tháp giải phóng, yêu cầu giúp giết địch nhưng Xích Hồn Tử không tuân lệnh."},{"ten":"Đạo cổ Diệp Mịch","tag":"doi-thu","quanHe":"Người phong ấn Xích Hồn Tử trong Hắc Tháp","ghiChu":"Xích Hồn Tử thù hận sâu sắc."},{"ten":"Nữ tử tiên phi","tag":"khac","quanHe":"Bị Xích Hồn Tử nuốt ngay sau khi được tự do","ghiChu":"Tiên Phi bị cắn nuốt, thân thể tan chảy biến mất."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1491","@c1492"]},{"id":"vuong-binh","name":"Vương Bình","aliases":["Bình Nhi"],"gioiTinh":"nam","tabs":{"kinhLich":[{"chuong":"@c1493","importance":"bridge","mucCt":"vua","text":"Xuất hiện trong hồi ức cuối cùng của Vương Lâm: thiếu niên áo vải thô đứng sau phụ thân trên đỉnh núi gió lớn, nói sẽ ở cùng cha đời đời kiếp kiếp mãi mãi không chia lìa.","anchor":"Cha, Bình Nhi sẽ ở với người đời đời kiếp kiếp. Chúng ta sẽ mãi mãi không chia lìa."},{"chuong":"@c1540","importance":"bridge","mucCt":"gon","text":"Được Vương Lâm tìm thấy và thu hồi vận mệnh trong mặt trời thứ chín.","anchor":"Hắn tìm ấy Thập Tam, tìm thấy đầu to, tìm được Chu Dật"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Xuất hiện dưới dạng oán anh trong màn sương đen, bị Liễu Mi luyện hóa trăm năm, sau được Vương Lâm nhận làm huyết mạch ruột thịt","chuong":"@c0636"},{"text":"Nhiều lần xin phụ thân cho tu đạo nhưng đều bị từ chối, cuối cùng chấp nhận cầu đạo chí tôn của phàm nhân","chuong":"@c0650"},{"text":"Từ thủ lĩnh Thiên Hành phái trở thành quân chủ lập nên Thiên Hành đế quốc","chuong":"@c0652"},{"text":"Cuối đời bị Lôi Đạo Tử nhìn thấu thân phận oán anh, tự xâu chuỗi chân tướng rồi tan thành hồn tức","chuong":"@c0659"},{"text":"Tiếng khóc lúc còn là oán anh kéo Vương Lâm khỏi nguy cơ, cứu phụ thân trong khoảnh khắc then chốt","chuong":"@c1813"},{"text":"Được Vương Lâm sắp xếp Mộng Đạo thuật để gặp mẫu thân Mộc Băng Mi trong mộng cảnh luân hồi trọn vẹn","chuong":"@c1963"}]},"nguon":["@c1493","@c1540"],"vaiTro":"Con trai duy nhất của Vương Lâm — oán anh được ban một đời phàm nhân","tinhCach":"hiếu thuận và quyến luyến phụ thân; kiên trì khẩn cầu tu đạo dù nhiều lần bị cấm; trầm ổn trước hiểm nguy; biết tha thứ và buông bỏ lúc cuối đời","blurb":"Vương Bình vốn là oán anh trong màn sương đen trên Nhiễm Vân Tinh, bị Liễu Mi luyện hóa trăm năm, sau được Vương Lâm nhận làm huyết mạch ruột thịt và nuôi dưỡng như phàm nhân tại thôn Lạc Nguyệt. Hắn sống trọn một đời bên phụ thân — học điêu khắc, du ngoạn sơn xuyên, lập nên Thiên Hành đế quốc — rồi cuối đời bị Lôi Đạo Tử nhìn thấu thân phận oán anh và tan thành hồn tức. Sau đó Vương Bình vẫn tồn tại trong Thiên Nghịch Châu, trở thành nỗi day dứt lâu dài trong tâm thần và nhân quả của Vương Lâm, cho tới khi được phụ thân thu hồi vận mệnh và sắp xếp mộng cảnh luân hồi để gặp lại mẫu thân."},{"id":"chu-nhu","name":"Chu Như","cn":"朱茹","aliases":["Chu Nhị","Nữ tử áo tím","Chu Cẩn","Chu Như"],"gioiTinh":"nu","tabs":{"kinhLich":[{"chuong":"@c1494","importance":"normal","mucCt":"vua","tieuDe":"Khóc trước pho tượng Vương Lâm","text":"Cùng Lão Hồ (con hổ già nua) đến trước pho tượng Vương Lâm trên Chu Tước Tinh, khóc gọi thúc thúc, vuốt ve pho tượng.","anchor":"Thúc thúc.ta là Chu Như.ta là tiểu Chu Như"},{"mucCt":"ky","text":"Vén rèm thuyền lộ diện khi Từ Phi trêu chọc Vương Lâm bên bờ sông. Nhìn Vương Lâm liền ngẩn ra, nói đã gặp ở đâu rồi. Dùng thân pháp phi thường đỡ Vương Lâm lên thuyền khi hắn trượt chân. Nghe tên Vương Lâm càng thấy quen thuộc. Chủ động thi triển pháp thuật khiến Vương Lâm ngủ say vì muốn bàn chuyện tu tiên. Khẳng định nhất định đã từng gặp người này nhưng cuối cùng lắc đầu, đoán có lẽ gặp từ kiếp trước.","anchor":"Người này nhất định ta đã từng gặp qua, nhưng thế nào cũng không thể nhớ ra được","bridge":true,"khoang":"@c1496"},{"chuong":"@c1500","importance":"bridge","mucCt":"gon","text":"Đang phi hành cùng Vương Trác, Từ Phi và lão già Hằng Nhạc Phái trong mưa Triệu quốc, chấn động trước khí tức Vương Lâm.","anchor":"mấy người này đồng thời chấn động tâm thần, thần sắc lộ vẻ hoảng sợ"},{"chuong":"@c1508","importance":"bridge","mucCt":"vua","tieuDe":"Lướt thuyền ngang qua Vương Lâm trên sông Tô thành","text":"Xuất hiện trên họa thuyền cùng sư muội Từ Phi, hai thuyền lướt ngang nhau. Quay đầu liếc nhìn nhưng đã cách xa bị cầu đá che khuất, không nhận ra Vương Lâm, cũng không dùng thần thức kiểm tra.","anchor":"Nàng cũng không vì người khác nhìn mình một cái mà lại dùng thần thức kiểm tra"},{"mucCt":"vua","text":"Rời họa thuyền cùng Từ Phi, dung mạo biến đổi thành tầm thường. Muốn bái phỏng đại nho Tô Đạo nhưng biết ông đã mất, đại nho hiện tại là Vương Lâm. Nhận ra ông lão trên thuyền ban ngày chính là Vương Lâm, nhớ lại hình ảnh thiếu niên đỏ mặt năm xưa. Hóa cầu vồng bay lên bầu trời Tô thành, tỏa thần thức lùng khắp nhưng không tìm được bóng dáng hắn.","anchor":"trước mặt dường như hiện lên hình ảnh người thiếu niên đỏ mặt năm đó","bridge":true,"khoang":"@c1509"},{"chuong":"@c1533","importance":"bridge","mucCt":"vua","text":"Được Chân Giả Đạo của Vương Lâm biến thành thân ảnh ôm con gái hướng trời gào giận dữ, góp vào thiên kiếp đặc biệt phản kích trời.","anchor":"có Chu Như ôm con gái hướng lên không trung rống lên một tiếng giận dữ"},{"chuong":"@c1540","importance":"bridge","mucCt":"gon","text":"Được Vương Lâm tìm thấy và thu hồi vận mệnh trong mặt trời thứ chín.","anchor":"Hắn tìm ấy Thập Tam, tìm thấy đầu to, tìm được Chu Dật"}],"tuViMoc":[],"nhanMach":[{"ten":"Từ Phi","tag":"su-mon","quanHe":"Sư muội","ghiChu":"@c1496"},{"ten":"Vương Lâm","tag":"khac","quanHe":"Thư sinh phàm nhân gặp trên sông, cảm thấy quen mặt quen tên từ kiếp trước","ghiChu":"@c1496"},{"ten":"Vương Trác","tag":"dong-minh","quanHe":"Đồng môn Hằng Nhạc Phái, cần tụ họp cùng","ghiChu":"@c1496"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Nguyên Anh Lý Mộ Uyển đầu thai vào bào thai sơn thôn Hạnh Hoa Thôn, chuyển sinh thành Chu Như với tư chất bách mạch đều thông","chuong":"@c0314"},{"text":"Hồn phách bị Lý Mộ Uyển chấn ra khỏi nhục thân, được Vương Lâm triệu hồi sống sót, từ đó tồn tại với thân phận độc lập","chuong":"@c0381"},{"text":"Ký ức phong ấn được giải phóng tại đỉnh Chu Tước Sơn khi mở túi trữ vật Vương Lâm lưu lại","chuong":"@c0663"},{"text":"Tái ngộ Vương Lâm tại Côn Hư cảnh sau thời gian dài xa cách, đau lòng nhìn tóc bạc trắng của hắn","chuong":"@c1053"},{"text":"Được Vương Lâm thu hồi vận mệnh trong mặt trời thứ chín, thoát khỏi sự chi phối của thiên mệnh","chuong":"@c1540"},{"text":"Chuyển thế đầu thai thành thiếu nữ hơn mười tuổi tại sơn thôn Sơn Nhạc Châu, từ chối tu tiên, sống giản dị cùng cha mẹ","chuong":"@c1956"}]},"nguon":["@c1494","@c1496","@c1497","@c1500","@c1508","@c1509","@c1533","@c1540"],"trangThai":"khong-ro","vaiTro":"Chuyển sinh phàm nhân của Nguyên Anh Lý Mộ Uyển — nghĩa nữ được Vương Lâm bảo hộ suốt nhiều kiếp","tinhCach":"Quyến luyến sâu sắc, nhiều lần bất chấp tìm kiếm Vương Lâm và không nỡ rời xa; hồn nhiên bộc trực, hay hờn dỗi giận lẫy; dã tính phóng khoáng, gắn bó với hổ Tiểu Bạch như bạn đồng hành; chí tu luyện kiên định, lấy việc tìm lại thúc thúc làm mục đích","blurb":"Chu Như là thân xác phàm nhân do Nguyên Anh Lý Mộ Uyển chuyển sinh tại Hạnh Hoa Thôn, mang tư chất tuyệt hảo bách mạch đều thông, từ nhỏ được Vương Lâm âm thầm bảo hộ rồi nuôi dưỡng trong Tiên Ngọc Bảo Tháp. Sau khi hồn phách được tách khỏi Nguyên Anh Lý Mộ Uyển và ký ức bị xóa, nàng đoàn tụ phụ mẫu rồi tự mình tu luyện đến cảnh Anh Biến, suốt đời lấy việc tìm lại thúc thúc Vương Lâm làm tâm nguyện duy nhất. Trải qua nhiều lần tái ngộ và chia ly, Chu Như cuối cùng được thu hồi vận mệnh trong mặt trời thứ chín, ở bên Vương Lâm như cô con gái trước khi quyết định chuyển thế đầu thai, tái sinh th","theLuc":[{"ten":"Hằng Nhạc Phái","trangThai":"gan-bo"}]},{"id":"hua-moc","name":"Hứa Mộc","cn":"许木","aliases":[],"gioiTinh":"nam","tabs":{"kinhLich":[{"chuong":"@c1494","importance":"normal","mucCt":"ky","tieuDe":"Ân hận trước pho tượng Vương Lâm","text":"Đại hán khôi ngô cầm hai bầu rượu đến trước pho tượng, cười rồi khóc rống. Ân hận rằng nếu năm đó không chỉ dẫn Vương Lâm tu đạo, không lấy đi Thiên Nghịch, Vương Lâm vẫn còn là thiếu niên ngây thơ.","anchor":"Nếu năm đó ta không chỉ dẫn ngươi tu đạo.nếu năm đó chúng ta không gặp nhau.nếu năm đó ta lấy đi Thiên Nghịch của ngươi"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Đấu tỷ thí với Lữ Tung tại Thương Tùng Phong, trận bị dừng khi trung niên nam tử bí ẩn Huyền Đạo Tông bẻ gãy phi kiếm Lữ Tung","chuong":"@c0047"},{"text":"Từng lo việc cho Nhiễm gia bốn năm trước và bị cho là đã chết, được lão tổ Nhiễm gia nhắc tới","chuong":"@c0627"},{"text":"Tung tích bất minh, được xác nhận thân phận Chính Phẩm Lôi Tiên mới phong của La Thiên Tinh Vực","chuong":"@c0845"},{"text":"Bị Sát Vực Giới xác định tung tích và truy sát","chuong":"@c0847"},{"text":"Bị kế hoạch Đồ La nhắm tới, được nhắc trong lời tuyên bố của kẻ chiếm thân Tu sĩ sáu ngón","chuong":"@c0857"},{"text":"Ân hận đến trước pho tượng Vương Lâm, cười rồi khóc rống, hối tiếc chuyện chỉ dẫn năm xưa","chuong":"@c1494"}]},"nguon":["@c1494"],"vaiTro":"Đệ tử Hằng Nhạc Phái — Chính Phẩm Lôi Tiên mới phong của La Thiên Tinh Vực","tinhCach":"Trọng tình nghĩa, mang nỗi ân hận sâu sắc; có mối liên hệ phức tạp với nhiều thế lực","blurb":"Hứa Mộc xuất thân là đệ tử Hằng Nhạc Phái, từng đấu tỷ thí với Lữ Tung của Huyền Đạo Tông tại Thương Tùng Phong. Về sau, hắn dính líu tới sự vụ của Nhiễm gia, được phong Chính Phẩm Lôi Tiên tại La Thiên Tinh Vực nhưng tung tích bất minh, bị Sát Vực truy sát và kế hoạch Đồ La nhắm tới. Hắn từng đến trước pho tượng Vương Lâm, khóc rống vì ân hận chuyện năm xưa."},{"id":"moc-bang-mi","name":"Mộc Băng Mi","cn":"木冰眉","aliases":[],"gioiTinh":"nu","tabs":{"kinhLich":[{"chuong":"@c1494","importance":"normal","mucCt":"vua","tieuDe":"Lặng lẽ viếng pho tượng Vương Lâm","text":"Đứng dưới pho tượng ngây người nhìn mặt trời mọc lặn mấy lần, yên lặng rời đi, hai giọt nước mắt rơi.","anchor":"Nàng chính là Mộc Băng Mi"},{"chuong":"@c1540","importance":"normal","mucCt":"gon","text":"Được Vương Lâm tìm thấy và thu hồi vận mệnh trong mặt trời thứ chín.","anchor":"Hắn tìm ấy Thập Tam, tìm thấy đầu to, tìm được Chu Dật"},{"mucCt":"vua","text":"Xuất hiện bên trong trận pháp 990 tu chân tinh tại La Thiên, mặc bạch y tóc bó cao, khuôn mặt lộ vẻ mờ mịt. Đang cùng tu sĩ giới nội bị hơn mười vạn tu sĩ giới ngoại vây khốn.","anchor":"Mộc Băng Mi mái tóc bó cao, mặc bạch y, khuôn mặt xinh đẹp lộ vẻ mờ mịt","bridge":true,"khoang":"@c1556"},{"mucCt":"ky","text":"Mộc Băng Mi đứng trên tu chân tinh cùng mấy ngàn tu sĩ Thần Tông còn sót lại. Lão già bạch mi khuyên nàng lui vào tế đàn, mọi người ôm quyền xin nàng đi trước. Nàng kiên quyết ở lại, tuyên bố mình là tông chủ Thần Tông. Đạo Phi Hủ nhạo nàng là hồng nhan của Phong Tôn đã chết, muốn song tu với nàng. Nàng bình tĩnh đáp lại. Từng hai lần suýt tử vong trong cuộc chiến, một lần bị Đạo Phi Hủ đuổi giết và được Thanh Thủy cứu.","anchor":"Sau mấy năm trở thành tông chủ Thần Tông, Mộc Băng Mi lấy mị lực đặc biệt của mình","bridge":true,"khoang":"@c1559"},{"mucCt":"gon","text":"Tấm màn sáng bảo vệ tu chân tinh tan nát, Đạo Phi Hủ cuốn hết tu sĩ chỉ để lại nàng, từng bước đi tới với ý đồ xấu.","anchor":"Ánh mắt Mộc Băng Mi lộ vẻ tuyệt vọng","bridge":true,"khoang":"@c1560"},{"chuong":"@c1561","importance":"normal","mucCt":"vua","tieuDe":"Tin Vương Lâm còn sống, được hắn bảo vệ","text":"Đang tuyệt vọng bỗng thân thể run rẩy, mắt bừng sáng, mỉm cười vì tin Vương Lâm không chết. Cuối chương Vương Lâm xoay người bảo vệ nàng, tuyên bố nàng là mẫu thân Vương Bình.","anchor":"Nàng biết, nàng tin là hắn không chết!"},{"chuong":"@c1562","importance":"bridge","mucCt":"gon","text":"Bị Đạo Phi Hủ lao tới định bắt làm con tin nhưng lạnh lùng nhìn không thèm coi hắn vào đâu, được Vương Lâm xuất hiện chặn trước mặt bảo vệ.","anchor":"vẫn lạnh lùng nhìn Đạo Phi Hủ, đôi mắt xinh đẹp lộ vẻ không thèm coi hắn vào đâu cả"},{"chuong":"@c1563","importance":"bridge","mucCt":"gon","text":"Cùng đồng loạt bay lên từ tinh trận xông ra chém giết tu sĩ giới ngoại.","anchor":"có Mộc Băng Mi, Thần Tông, cùng với vô số tu sĩ giới nội"},{"chuong":"@c1565","importance":"bridge","mucCt":"gon","text":"Cùng toàn bộ tu sĩ giới nội ngồi xuống xuất nguyên thần dung nhập bánh xe đẩy vòng thứ hai.","anchor":"Cho dù là Mộc Băng Mi lúc này cũng làm như vậy"},{"mucCt":"ky","text":"Nhìn Vương Lâm rời đi, nhớ lại lời hắn nói nàng tuy không phải hồng nhan nhưng là mẫu thân của Vương Bình. Từ vẻ mê man chuyển sang kiên định, hóa phượng hoàng màu lam đuổi theo Vương Lâm.","anchor":"Mộc Băng Mi ngẩng khuôn mặt tuyệt mỹ, vẻ mê man trong ánh mắt tan đi, lộ ra sự kiên định","bridge":true,"khoang":"@c1566"},{"chuong":"@c1569","importance":"bridge","mucCt":"gon","text":"Cùng nữ tử áo hồng và Tây Tử Phượng dừng lại trong Vân Hải tinh vực chứng kiến Phong Giới Đại Trận sụp đổ, mặt mũi tái nhợt.","anchor":"Mộc Băng Mi, nữ tử áo hồng. Tây Tử Phượng lúc này hóa thành ba đạo cầu vồng ngưng tụ lại với nhau"},{"importance":"bridge","mucCt":"gon","chuong":"@c1570","text":"Gió lốc do Vương Lâm tạo ra khi cuốn tàn hồn từ Vân Hải tinh vực đảo qua chỗ ba người Mộc Băng Mi, cho thấy nàng vẫn đang ở Vân Hải.","anchor":"Cơn gió lốc gào thét đảo qua ba người Mộc Băng Mi"},{"chuong":"@c1571","importance":"bridge","mucCt":"gon","text":"Cùng hai người khác đứng trong Vân Hải tinh vực, lộ vẻ bi ai ôm quyền lạy anh hồn.","anchor":"ba người Mộc Băng Mi đang đứng đó"},{"chuong":"@c1573","importance":"normal","mucCt":"gon","tieuDe":"Tới nơi Vương Lâm bảo vệ, chờ đợi phiên mình","text":"Cùng Tây Tử Phượng và nữ tử áo hồng tới nơi Vương Lâm trấn thủ, ngồi khoanh chân bên ngoài tinh không chờ đợi. Ba nàng đã thỏa thuận mỗi người một năm.","anchor":"Mộc Băng Mi và nữ tử áo hồng ở xa xa trầm mặc, ngồi khoanh chân bên ngoài tinh không"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Tuyên bố mọi thần thông và nguyên lực thiên địa trong Côn Hư Tinh vực đều nằm trong tay nàng, thể hiện quyền uy tuyệt đối","chuong":"@c1011"},{"text":"Bị Thác Sâm đánh tan thân, nguyên thần trọng thương, dùng bí thuật Côn Hư thoát ra lưu lạc tới Vân Hải tinh vực","chuong":"@c1147"},{"text":"Xác nhận danh tính Liễu Mi — mẹ Vương Bình — và đạo tâm viên mãn, từ biệt Vương Lâm dưới ánh trăng","chuong":"@c1196"},{"text":"Được Vương Lâm phong làm tông chủ Thần Tông, chỉ huy bày binh bố trận tạo phòng tuyến giới nội trong đại chiến giới ngoại","chuong":"@c1440"},{"text":"Được hé lộ chính là phách thứ sáu (phách sinh từ tình) của Thất Thải Tiên Tôn","chuong":"@c1651"},{"text":"Tái ngộ Vương Lâm tại Tiên giới, đồng ý ước định Mộng Đạo trăm năm, cùng hắn rời Tiên giới","chuong":"@c1963"}]},"nguon":["@c1494","@c1540","@c1556","@c1559","@c1560","@c1561","@c1562","@c1563","@c1565","@c1566","@c1569","@c1570","@c1571","@c1573"],"trangThai":"song","canhGioiCaoNhat":"Không rõ","theLuc":[{"ten":"Thần Tông","trangThai":"gan-bo"}],"vaiTro":"Côn Hư Thánh Nữ — mẹ Vương Bình, tông chủ Thần Tông, phách thứ sáu của Thất Thải Tiên Tôn","tinhCach":"Lạnh lùng quyền uy nhưng nặng tình với con và Vương Lâm, âm thầm chịu đựng chia ly giấu nỗi đau sau vẻ ngoài băng lãnh; bất khuất trước cường địch, không chịu khuất phục dù trọng thương hay bị giam cầm; kiên định trong đại chiến, sẵn sàng xông trận dù tuyệt vọng","blurb":"Mộc Băng Mi là Côn Hư Thánh Nữ, mẹ của Vương Bình, từng nắm quyền điều khiển toàn bộ thần thông và nguyên lực thiên địa trong Côn Hư Tinh vực. Sau khi Côn Hư cảnh bị Thác Sâm hủy diệt, nàng trọng thương lưu lạc tới Vân Hải tinh vực lấy thân phận Liễu Mi tái ngộ Vương Lâm, rồi về Thần Tông chịu giam cầm nhiều năm trước khi được Vương Lâm phong làm tông chủ, chỉ huy phòng tuyến giới nội trong đại chiến giới ngoại. Về sau nàng được hé lộ chính là phách thứ sáu — phách sinh từ tình — của Thất Thải Tiên Tôn, và trong Tiên giới đã tái ngộ Vương Lâm, đồng ý ước định Mộng Đạo trăm năm, là một trong số"},{"id":"nu-tu-ao-hong-nhat","name":"Nữ tử y phục hồng nhạt","cn":"","aliases":[],"gioiTinh":"nu","vaiTro":"Nữ tử bí ẩn đến viếng pho tượng Vương Lâm, danh tính chưa rõ","tinhCach":"uể oải; nhớ nhung","blurb":"Nữ tử mặc y phục hồng nhạt, vẻ mặt uể oải, đến Chu Tước Tinh nhìn pho tượng Vương Lâm và nói rằng chàng không biết thiếp nhưng thiếp biết chàng. Danh tính chưa được xác định.","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"khong-ro","tabs":{"diem":[{"text":"Nữ tử bí ẩn có liên hệ một chiều với Vương Lâm, danh tính chưa hé lộ","chuong":"@c1494"}],"kinhLich":[{"chuong":"@c1494","importance":"minor","mucCt":"gon","text":"Đến Chu Tước Tinh nhìn pho tượng Vương Lâm, nói chàng không biết thiếp nhưng thiếp biết chàng, danh tính chưa rõ.","anchor":"Chàng không biết thiếp nhưng thiếp biết chàng"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Biết Vương Lâm nhưng Vương Lâm không biết nàng","ghiChu":"Đơn phương quen biết, danh tính chưa rõ"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1494"]},{"id":"tu-thuc","name":"Tứ thúc","gioiTinh":"nam","tabs":{"kinhLich":[{"chuong":"@c1495","importance":"bridge","mucCt":"gon","text":"Được Vương Lâm nhắc trong mộng cảnh phàm nhân: ba năm trước tứ thúc đến đưa hắn gia nhập Hằng Nhạc phái.","anchor":"Không ngờ ba năm trước đây tứ thúc đến, ta lại gia nhập Hằng Nhạc phái"},{"chuong":"@c1506","importance":"bridge","mucCt":"gon","text":"Phái người mang thư nhà của mẹ Vương Lâm tới cho VL tại Tô thành.","anchor":"lại được tứ thúc phái người mang tới"},{"chuong":"@c1533","importance":"bridge","mucCt":"gon","text":"Bị Huyễn Chân Kiếp hóa thành thân ảnh cùng cha mẹ, Vương Trác, Trương Hổ, Liễu Mi tiếp cận Vương Lâm.","anchor":"có cha mẹ hắn, có tứ thúc của hắn, có Vương Trác"}],"nhanMach":[],"tuViMoc":[],"diem":[{"text":"Đến thăm nhà Vương Lâm, tặng hai quyển sách và báo tin Hằng Nhạc Phái thu đệ tử, nhường danh ngạch đề cử cho cháu","chuong":"@c0001"},{"text":"Cho Vương Lâm nghỉ qua đêm tại nhà mình, sáng hôm sau dẫn hắn tới tòa nhà lớn của Vương gia","chuong":"@c0002"},{"text":"Phái người mang thư nhà của mẹ Vương Lâm tới cho Vương Lâm tại Tô thành","chuong":"@c1506"},{"text":"Bị Huyễn Chân Kiếp hóa thành thân ảnh cùng người thân để tiếp cận Vương Lâm","chuong":"@c1533"}]},"nguon":["@c1495","@c1506","@c1533"],"trangThai":"khong-ro","vaiTro":"Ân nhân của Vương Lâm — chú thứ tư trong Vương gia","tinhCach":"Trọng ân nghĩa, sẵn sàng nhường lợi lớn cho cháu; quan tâm chân thành, chu đáo trong việc dẫn dắt hậu bối","blurb":"Chú thứ tư của Vương Lâm trong gia tộc họ Vương, một phàm nhân sống trong căn nhà ngói giản dị. Ông mang danh ngạch đề cử của gia tộc đến nhường lại cho cháu trai, tặng sách và đích thân dẫn Vương Lâm tới tòa nhà lớn của Vương gia để bước vào con đường tu tiên tại Hằng Nhạc Phái. Về sau ông vẫn giữ mối liên hệ với Vương Lâm, từng phái người chuyển thư nhà tới tận Tô thành."},{"id":"co-gai-tren-thuyen","name":"Cô gái trên thuyền","aliases":[],"gioiTinh":"nu","theLuc":[],"trangThai":"song","blurb":"Cô gái xinh xắn xuất hiện trên đầu một chiếc thuyền gần bờ trong mộng cảnh phàm nhân của Vương Lâm, giọng trong trẻo, mắng hắn là thư sinh ngốc khi thấy hắn cười cảnh thuyền bị nước mưa bắn.","vaiTro":"Nhân vật phàm nhân trong mộng cảnh, chưa rõ danh tính","tinhCach":"Hoạt bát, bộc trực","tabs":{"diem":[{"text":"Xuất hiện cuối chương mộng cảnh phàm nhân, mắng Vương Lâm là thư sinh ngốc","chuong":"@c1495"}],"kinhLich":[{"mucCt":"gon","text":"Đứng trên đầu thuyền gần bờ trong cơn mưa, trừng mắt chỉ tay mắng Vương Lâm là thư sinh ngốc vì cười khi thuyền bị nước mưa bắn lên.","anchor":"Người thư sinh này chẳng lẽ ngốc rồi, thấy đội thuyền nhà ta bị nước mưa bắn lên như vậy lại cười ha hả","bridge":true,"khoang":"@c1495"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Gặp gỡ tình cờ bên sông trong mưa","ghiChu":"Mắng hắn là thư sinh ngốc"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1495"]},{"id":"tu-phi","name":"Từ Phi","cn":"","aliases":["Thiếu nữ áo xanh"],"gioiTinh":"nu","theLuc":[{"ten":"Hằng Nhạc Phái","trangThai":"gan-bo"}],"trangThai":"song","tabs":{"kinhLich":[{"mucCt":"vua","text":"Cầm ô đứng trên thuyền, trêu chọc Vương Lâm là tiểu tử ngốc khi thấy hắn trú mưa bên bờ sông. Cũng cảm thấy tên Vương Lâm quen nhưng không nhớ ra. Cuối cùng nhắc sư tỷ cần tới tụ họp với đám Vương Trác, tiết lộ chưởng môn phát hiện kim quang phía đông, nghi có dị bảo xuất hiện.","anchor":"Sư tỷ, thời gian không còn nhiều, chúng ta phải tới tụ họp với đám Vương Trác.","bridge":true,"khoang":"@c1496"},{"chuong":"@c1500","importance":"bridge","mucCt":"gon","text":"Đang phi hành cùng Vương Trác, Chu Nhị và lão già Hằng Nhạc Phái trong mưa Triệu quốc, chấn động trước khí tức Vương Lâm.","anchor":"mấy người này đồng thời chấn động tâm thần, thần sắc lộ vẻ hoảng sợ"},{"chuong":"@c1508","importance":"bridge","mucCt":"gon","tieuDe":"Cùng Chu Nhị trên họa thuyền ngang qua Vương Lâm","text":"Cùng sư tỷ Chu Nhị trên họa thuyền, phàn nàn tơ liễu phiền hà, nhận ra có lão đầu nhìn họ nhưng không để tâm.","anchor":"Sư tỷ, tơ liễu này đúng là phiền hà, rơi lên người rất khó chịu."},{"chuong":"@c1509","importance":"bridge","mucCt":"gon","text":"Cùng Chu Nhị rời họa thuyền tại Tô thành, hỏi về chỗ chơi, dường như hiểu tâm tư sư tỷ khi Chu Nhị bay đi tìm Vương Lâm.","anchor":"Từ Phi nhìn Chu Nhị giống như đã hiểu ra chút gì, nhẹ giọng nói"},{"importance":"bridge","mucCt":"gon","chuong":"@c1518","text":"Đang phi hành trên bầu trời cùng Vọng Nam, khi gió thổi tới thân thể hóa tro bụi bị cuốn đi trong mộng cảnh tan rã.","anchor":"Tử Phi, Vọng Nam. hai nữ tử này vốn đang phi hành trên bầu trời lúc này cùng với thời gian đọng lại, theo cơn gió thổi tới thân thể liền hóa thành một đám tro bụi bị cuốn đi"}],"nhanMach":[{"ten":"Chu Nhị","tag":"su-mon","quanHe":"Sư tỷ","ghiChu":"@c1496"},{"ten":"Vương Lâm","tag":"khac","quanHe":"Thư sinh phàm nhân gặp bên sông, cảm thấy tên quen","ghiChu":"@c1496"},{"ten":"Vương Trác","tag":"dong-minh","quanHe":"Đồng môn Hằng Nhạc Phái, cần tụ họp cùng","ghiChu":"@c1496"}],"tuViMoc":[],"diem":[{"text":"Cùng Lịch Hải và tiểu sư đệ đến khu vực núi trọc nơi Vương Lâm bế quan, lúc này đã đạt tầng 7 Ngưng Khí","chuong":"@c0062"},{"text":"Bị thần thức của Vương Lâm áp chế không dám động đậy; họ Từ của cô khiến Tư Đồ Nam bất ngờ","chuong":"@c0063"},{"text":"Cầm ô đứng trên thuyền, trêu chọc Vương Lâm là tiểu tử ngốc khi thấy hắn trú mưa bên bờ sông","chuong":"@c1496"},{"text":"Phi hành cùng Vương Trác, Chu Nhị và lão già Hằng Nhạc Phái, chấn động trước khí tức mạnh mẽ","chuong":"@c1500"},{"text":"Cùng sư tỷ Chu Nhị trên họa thuyền ngang qua Vương Lâm tại Tô thành","chuong":"@c1508"},{"text":"Trong mộng cảnh, phi hành cùng Vọng Nam trên bầu trời rồi thân thể hóa tro bụi cuốn đi trong gió","chuong":"@c1518"}]},"nguon":["@c1496","@c1497","@c1500","@c1508","@c1509","@c1515","@c1518"],"vaiTro":"Nhân vật phụ — đệ tử Huyền Đạo Tông, hậu nhân họ Từ","tinhCach":"có cảm tình thầm kín với 'Vương Trác' (Vương Lâm giả danh); nhút nhát khi đối diện cường giả; hồn nhiên hay trêu đùa","blurb":"Từ Phi là đệ tử Huyền Đạo Tông, tu vi Ngưng Khí kỳ tầng 7, mang họ Từ — điều khiến Tư Đồ Nam ẩn trong Nghịch Thiên Châu bất ngờ. Cô từng có cảm tình với 'Vương Trác' tức Vương Lâm giả danh, và xuất hiện nhiều lần xuyên suốt hành trình của Vương Lâm tại Triệu quốc, từ vùng núi trọc nơi hắn bế quan cho đến trên họa thuyền ở Tô thành. Trong mộng cảnh tái hiện, cô cùng Vọng Nam phi hành trên bầu trời rồi thân thể hóa tro bụi cuốn đi theo gió."},{"id":"nu-tu-ao-lam-cau-vong","name":"Nữ tử áo lam (tu sĩ cầu vồng)","cn":"","gioiTinh":"nu","vaiTro":"Tu sĩ nữ bay bằng cầu vồng, cảm thấy quen Vương Lâm","tinhCach":"Mê man, nhạy cảm với linh cảm","blurb":"Tu sĩ nữ bay bằng cầu vồng cùng sư huynh, dừng lại nhìn Vương Lâm đang ở thân phàm nhân, cảm thấy hình như đã gặp ở đâu rồi. Đang cùng sư huynh đi tụ họp sư môn tới nơi phát ra kim quang.","trangThai":"song","tabs":{"diem":[{"text":"Cảm nhận được sự quen thuộc với Vương Lâm dù hắn đang ở thân phàm nhân, dừng cầu vồng nhìn hắn mê man","chuong":"@c1497"},{"text":"Cảm thấy quen thuộc khi nhìn Vương Lâm dù hắn chỉ là phàm nhân","chuong":"@c1497"}],"kinhLich":[{"chuong":"@c1497","importance":"normal","tieuDe":"Gặp Vương Lâm phàm nhân, cảm thấy quen","text":"Bay bằng cầu vồng cùng sư huynh, dừng lại nhìn Vương Lâm bên sông, mê man nói hình như đã gặp ở đâu. Bị sư huynh nhận định đó chỉ là phàm nhân, thúc giục đi tụ họp sư môn tới nơi phát ra kim quang.","mucCt":"vua","anchor":"Thư sinh kia hình như ta đã gặp ở đâu rồi"}],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Phàm nhân nàng cảm thấy quen thuộc","ghiChu":"Nhìn thấy Vương Lâm bên sông, cảm giác đã gặp ở đâu"},{"ten":"Thanh niên anh tuấn (sư huynh)","tag":"su-mon","quanHe":"Sư huynh","ghiChu":"Cùng đi tụ họp sư môn"}],"tuViMoc":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1497"]},{"id":"thanh-nien-anh-tuan-su-huynh","name":"Thanh niên anh tuấn (sư huynh)","cn":"","gioiTinh":"nam","vaiTro":"Tu sĩ nam, sư huynh của nữ tử áo lam","tinhCach":"Thực tế, không quan tâm phàm nhân","blurb":"Tu sĩ nam anh tuấn bay bằng cầu vồng cùng sư muội (nữ tử áo lam), nhận định Vương Lâm chỉ là phàm nhân, thúc giục sư muội đi tụ họp sư môn tới nơi phát ra kim quang.","trangThai":"song","tabs":{"diem":[{"text":"Nhận định Vương Lâm chỉ là phàm nhân, thúc giục sư muội đi tụ họp sư môn","chuong":"@c1497"}],"kinhLich":[{"chuong":"@c1497","importance":"normal","tieuDe":"Cùng sư muội gặp Vương Lâm phàm nhân","text":"Bay cầu vồng cùng sư muội, nhận định Vương Lâm chỉ là phàm nhân, thúc giục đi tụ họp sư môn tới nơi phát ra kim quang.","mucCt":"gon","anchor":"Một phàm nhân thôi mà, chúng ta hãy mau đi tụ họp với sư môn"}],"nhanMach":[{"ten":"Nữ tử áo lam (tu sĩ cầu vồng)","tag":"su-mon","quanHe":"Sư muội","ghiChu":"Cùng đi tụ họp sư môn"}],"tuViMoc":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1497"]},{"id":"dai-phuc","name":"Đại Phúc","cn":"大福","aliases":["Nam tử trung niên điên trong miếu","A Ngốc"],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Phàm nhân","trangThai":"song","blurb":"Đại Phúc ban đầu là nam tử trung niên mất trí trong miếu thổ địa hoang, được Vương Lâm gặp giữa đêm mưa bão, sau đó trở thành thư đồng theo hầu Vương Lâm suốt hành trình ứng thí, du ngoạn và giảng học. Trải qua mấy mươi năm từ trẻ tới già nua, Đại Phúc vẫn trung thành chờ đợi Vương Lâm tại sơn thôn theo đúng lời hẹn, và cuối cùng là một trong hai sinh linh duy nhất không tiêu tan khi mộng cảnh tan vỡ.","vaiTro":"Thư đồng trung thành của Vương Lâm trong mộng cảnh, sinh linh duy nhất không tiêu tan","tinhCach":"Trung thành tuyệt đối, chờ đợi Vương Lâm suốt 35 năm không rời; keo kiệt tiết kiệm, luôn than phiền chi phí; chất phác hồn nhiên, hưng phấn vì ngân lượng hơn công danh","tabs":{"diem":[{"text":"Xuất hiện lần đầu trong miếu thổ địa hoang giữa đêm mưa bão, quần áo tả tơi, vừa khóc vừa cười, lẩm bẩm không biết mình là ai","chuong":"@c1498"},{"text":"Theo hầu Vương Lâm tới huyện thành ứng thí, hưng phấn vì ngân lượng thưởng tú tài chứ không phải công danh","chuong":"@c1503"},{"text":"Già nua trên họa thuyền, thường xuyên nhìn cổ tay phải rồi ngẩn ra cố nhớ lại điều gì đó","chuong":"@c1508"},{"text":"Chờ đợi Vương Lâm suốt 35 năm tại sơn thôn theo lời hẹn không quá 38 năm, đã già nua đầy nếp nhăn","chuong":"@c1517"},{"text":"Là một trong hai sinh linh duy nhất không tiêu tan khi mộng cảnh vỡ, được Vương Lâm cầm tay phải nắm giữ dấu ấn","chuong":"@c1518"}],"kinhLich":[{"mucCt":"vua","text":"Quần áo tả tơi chạy vào miếu thổ địa hoang giữa đêm mưa bão, cầm đùi gà bị gặm nửa đầy nước mưa, vừa khóc lóc thê lương vừa bật cười ha hả, lẩm bẩm hỏi mình là ai. Ngồi bên đống lửa cùng Vương Lâm trong miếu.","anchor":"Mặc kệ ta rồi, đều mặc kệ ta rồi.ta nghĩ mãi không ra.ta là ai","bridge":true,"khoang":"@c1498"},{"mucCt":"vua","text":"Đi cùng Vương Lâm tới huyện thành ứng thí, tìm nhà trọ khó khăn. Khi trả tiền phòng, đau lòng lẩm bẩm rằng trước đây hình như đã trải qua chuyện gì, biết ngân lượng vô cùng trọng yếu, gợi ý có ký ức tiền kiếp.","anchor":"ta trước đây hình như đã trải qua chuyện gì, biết rằng ngân lượng vô cùng trọng yếu","bridge":true,"khoang":"@c1500"},{"importance":"bridge","mucCt":"vua","chuong":"@c1501","tieuDe":"Chờ Vương Lâm thi tại huyện thành","text":"Khoe nằm mơ một chỉ khiến sấm chớp tiêu tán. Năm ngày Vương Lâm đọc sách, Đại Phúc đi dạo khắp huyện thành quen thêm người. Ngày thi đưa Vương Lâm tới trường thi, ở ngoài chờ ngủ khò dưới gốc cây, rồi cùng bị hắc phong bao phủ.","anchor":"Đại Phúc đúng là chịu khổ sở không nói lên lời"},{"importance":"bridge","mucCt":"gon","chuong":"@c1502","tieuDe":"Ngủ say dưới gốc đại thụ","text":"Vẫn ngáy vang dưới gốc đại thụ bên ngoài trường thi, hoàn toàn không hay biết Vương Lâm bị tiên nhân đưa đi.","anchor":"Đại Phúc vẫn ngáy vang như trước, vừa lẩm bầm vừa ngủ ngon lành"},{"mucCt":"vua","text":"Bị lay dậy ở huyện thành, hưng phấn vì ngân lượng thưởng tú tài chứ không vì công danh. Hai tháng đi đường cò kè mặc cả mua rượu, than khóc khi tiền gần hết, giấu bớt bạc. Tại Tô thành bị Vương Lâm sai đi mua Quế Hoa Tửu và thuê tiểu hoa thuyền.","anchor":"Bạc ơi, bạc à, bạc ơi là bạc!","bridge":true,"khoang":"@c1503"},{"mucCt":"vua","text":"Đại Phúc mặc trang phục thư đồng theo hầu Vương Lâm trên họa thuyền, liên tục than phiền chi phí thuê thuyền, mua rượu Quế Hoa tửu và thuê ba nữ tử, nói đã lôi hết tiền giấu ra và chỉ còn đủ bảy ngày. Khi nghe Vương Lâm gảy đàn bi ai, sửng sốt ngồi ngây quên cả tiếc tiền.","anchor":"Công tử, bạc lần này thực sự không nhiều lắm đâu","bridge":true,"khoang":"@c1504"},{"chuong":"@c1505","importance":"bridge","mucCt":"gon","text":"Theo Vương Lâm rời họa thuyền, bị giữ bên ngoài đình viện khi Vương Lâm vào phủ Tô Đạo.","anchor":"Đại Phúc bị giữ ở bên ngoài đình viện"},{"chuong":"@c1506","importance":"bridge","mucCt":"vua","text":"Đã lớn tuổi nhưng dáng vẻ vẫn như hai mươi năm trước, ba năm qua cũng tức giận vì bị xa lánh. Nghe VL tuyên bố giảng học mười năm liền hưng phấn đi sắp xếp truyền tin.","anchor":"hắn vừa đắc ý với chờ mong, vội vàng đi sắp xếp việc này"},{"chuong":"@c1507","importance":"bridge","mucCt":"gon","text":"Vội vàng mang Quế Hoa tửu cho Vương Lâm trong buổi giảng học tại Tô phủ, thần sắc đắc ý.","anchor":"Đại Phúc trong lúc này đang đắc ý cũng không còn đau lòng nữa"},{"chuong":"@c1508","importance":"bridge","mucCt":"vua","tieuDe":"Già nua trên họa thuyền, cùng Vương Lâm rời Tô thành","text":"Thân thể đã già nua, thói keo kiệt càng lợi hại. Thường xuyên nhìn cổ tay phải rồi ngẩn ra, cố nhớ lại điều gì đó nhưng không nhớ nổi. Đi cùng Vương Lâm trên họa thuyền suốt hai mươi tám năm, cùng lên xe ngựa rời Tô thành về Hằng Nhạc Sơn.","anchor":"Lão gia, ngươi rốt cục là chờ cái gì."},{"mucCt":"vua","text":"Cùng Vương Lâm đi xe ngựa về quê hương sơn thôn. Khi về tới cũng quỳ gọi cha mẹ, được phụ thân Vương Lâm nâng dậy trước và cảm ơn đã chiếu cố cho con trai mình.","anchor":"Ngươi đó, vẫn giống hệt như năm đó","bridge":true,"khoang":"@c1509"},{"chuong":"@c1510","importance":"normal","mucCt":"vua","tieuDe":"Từ biệt Vương Lâm, ở lại trông nhà","text":"Già nua chống gậy đứng phía sau Vương Lâm trước mộ cha mẹ. Cúi đầu nhìn cổ tay mình rồi lắc đầu, ngầm biết thời gian sống không còn bao lâu. Được Vương Lâm nhờ trông coi nhà cửa chờ hắn trở về, yên lặng lưu lại trong thôn.","anchor":"Đại Phúc vẫn còn có thể làm thư đồng"},{"chuong":"@c1516","importance":"bridge","mucCt":"gon","text":"Được Vương Lâm nhắc tên, yêu cầu Lý Mộ Uyển mang theo khi trở về Triệu quốc đi tới Tô thành.","anchor":"mang theo Đại Phúc, chúng ta đi tới Tô thành"},{"chuong":"@c1517","importance":"normal","mucCt":"vua","tieuDe":"Tái ngộ Vương Lâm sau 35 năm chờ đợi","text":"Đã già nua đầy nếp nhăn, chờ đợi Vương Lâm suốt 35 năm tại sơn thôn theo lời hẹn không quá 38 năm. Trên cổ tay phải còn dấu tay màu vàng do Vương Lâm để lại. Kinh ngạc nhếch miệng cười khi thấy Vương Lâm đứng ngoài sân trong gió tuyết. Đi cùng tới mộ cha mẹ Vương Lâm, rồi theo hắn tới Tô thành ngồi trên họa thuyền.","anchor":"Hắn đã nói là hắn khi còn sống thì không quá ba mươi tám năm sẽ trở về mà."},{"importance":"normal","mucCt":"gon","chuong":"@c1518","tieuDe":"Sinh linh duy nhất không tiêu tan trong mộng cảnh","text":"Là một trong hai sinh linh duy nhất không biến mất khi mộng cảnh vỡ. Vương Lâm cầm tay phải Đại Phúc, nắm dấu ấn trên cánh tay hắn trước khi nhắm mắt tỉnh mộng.","anchor":"Vương Lâm cầm lấy tay phải Đại Phúc, nắm lên dấu ấn trên cánh tay hắn"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Người gặp trong miếu hoang đêm mưa","ghiChu":"Vương Lâm thương xót cho hắn"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1498","@c1500","@c1501","@c1502","@c1503","@c1504","@c1505","@c1506","@c1507","@c1508","@c1509","@c1510","@c1516","@c1517","@c1518"]},{"id":"to-dao","name":"Tô Đạo","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Phàm nhân (đại nho)","trangThai":"song","blurb":"Tô Đạo là bậc đại nho nổi tiếng nhất Triệu quốc, người đặt tên cho Tô thành và từng khiến nơi đây suýt trở thành kinh đô. Ông thu Vương Lâm làm môn sinh cuối cùng, truyền dạy suốt mười năm về đạo nhân quả trước khi hết thọ qua đời trên đỉnh Tô sơn. Thực chất ông là hồn thứ ba của Thất Thải Tiên Tôn luân hồi thành phàm nhân tại Chu Tước Tinh, đồng thời cũng là nhân vật do bản thể tu sĩ Vương Lâm tạo ra trong Mộng Đạo.","vaiTro":"Bậc đại nho Triệu quốc — sư phụ cuối cùng của Vương Lâm trong Mộng Đạo, hồn thứ ba Thất Thải Tiên Tôn luân hồi","tinhCach":"Trọng tài hoa, sẵn lòng thu nạp kẻ xứng đáng dù đã muộn; điềm đạm luận đạo, lấy nhân quả làm gốc truyền dạy; ý chí kiên định nhưng dễ bị ngoại lực chi phối khi đối mặt áp chế vượt tầm","tabs":{"diem":[{"text":"Đại nho nổi tiếng nhất Triệu quốc, đặt tên cho Tô thành và khiến nơi đây suýt trở thành kinh đô","chuong":"@c1500"},{"text":"Thu Vương Lâm làm môn sinh cuối cùng, luận đạo nhân quả và truyền dạy suốt mười năm","chuong":"@c1505"},{"text":"Hết thọ qua đời trên đỉnh Tô sơn vào mùa đông tuyết phủ","chuong":"@c1506"},{"text":"Bị Chu Lập uy hiếp khiến phân tâm, mất tư cách học Vân Đạo Thiên Thuật","chuong":"@c1685"},{"text":"Được xác nhận là hồn thứ ba của Thất Thải Tiên Tôn luân hồi thành phàm nhân tại Chu Tước Tinh","chuong":"@c1651"}],"kinhLich":[{"chuong":"@c1500","importance":"bridge","mucCt":"gon","text":"Được nhắc tới là bậc đại nho Triệu quốc khiến Tô thành gần trở thành kinh đô.","anchor":"Hắn là bậc đại nho của Triệu quốc"},{"chuong":"@c1503","importance":"bridge","mucCt":"gon","text":"Được nhắc tên là đại nho nổi tiếng nhất Triệu quốc, người đặt tên cho Tô thành, thích Quế Hoa Tửu, được các học tử mơ tưởng bái nhập.","anchor":"Nếu có thể được Tô Đạo nhận, trở thành môn sinh của hắn thì vinh quang ấy không thể hình dung nổi"},{"mucCt":"ky","text":"Tô Đạo cùng đệ tử Tô Tam đứng trên cầu đá ở Tô thành khi họa thuyền Vương Lâm trôi qua bên dưới. Khen khúc đàn bi ai của Vương Lâm là bi hồn tuyệt vời, trong bi ai lộ tang thương vạn cổ, nói chuyến đi không vô ích. Hai lần hỏi Vương Lâm nhân quả là gì, nghe Vương Lâm đáp xong mỉm cười, quay lại hỏi đệ tử tên của chàng thiếu niên.","anchor":"Chàng thiếu niên, nói cho lão phu biết ngươi cảm thấy nhân quả là gì","bridge":true,"khoang":"@c1504"},{"chuong":"@c1505","importance":"major","mucCt":"ky","tieuDe":"Thu Vương Lâm, luận đạo nhân quả, mười năm truyền dạy","text":"Xem bài thi của Vương Lâm qua Tô Tam rồi tuyên bố đây là môn sinh cuối cùng muốn nhận. Mời Vương Lâm vào phủ, đàm luận suốt đêm dưới trăng, truyền dạy triết lý: phàm nhân hiểu đạo lý thiên địa thì tư tưởng lưu danh muôn đời, phá lồng giam thiên địa. Tiết lộ cả đời có nhiều tu sĩ tìm đến hỏi ý cảnh và cảnh giới Hóa Thần, tư tưởng cốt lõi là nhân quả — ngộ ra trước mộ vong thê khi 50 tuổi. Mười năm sau già yếu phải ngồi ghế có người dìu, luận với Vương Lâm rằng tơ liễu là nhân sinh nhân quả, hai đám tơ liễu cuốn nhau là ông cùng vong thê. Nhớ lại lần đầu gặp Vương Lâm trên cầu — thấy hắn như tơ liễu không gốc rễ mê mang, nói Vương Lâm là nhân quả cuối cùng và cảm giác đã gặp ở đâu đó.","anchor":"Cả đời lão phu môn đồ đông đảo, nhưng môn sinh chính thức chỉ có ba người"},{"chuong":"@c1506","importance":"normal","mucCt":"ky","tieuDe":"Hết thọ qua đời trên đỉnh Tô sơn","text":"Mười năm trôi qua, Tô Đạo hết thọ qua đời vào mùa đông ba năm trước khi tuyết phủ kín Tô thành. Trước khi chết, ông dặn Vương Lâm rằng cả đời không có con nối dõi, trong ba sư huynh chỉ VL có tư tưởng tương đương, rồi tặng phủ đệ cho VL. Ông yêu cầu VL đẩy xe lăn đưa tới đỉnh Tô sơn bên ngoài thành, nơi có nấm mộ cô độc của vợ ông. Tô Đạo áp mặt vào bia mộ, thì thầm rằng ông chôn bà ở đây để bà nhìn thấy nhà dưới chân núi, rồi mỉm cười nhắm mắt tắt thở. Nửa tháng sau VL chôn ông bên cạnh mộ vợ. Tô Đạo ở cùng VL mười bảy năm.","anchor":"Ta tới rồi nàng nói muốn nhìn thấy ta, ta liền chôn nàng ở nơi này"},{"chuong":"@c1508","importance":"bridge","mucCt":"gon","tieuDe":"Danh tiếng bị Vương Lâm thay thế","text":"Danh tiếng đại nho Triệu quốc bị Vương Lâm hoàn toàn thay thế sau sự kiện quát lui tiên tu.","anchor":"hoàn toàn thay thế được sư tôn Tô Đạo của hắn"},{"chuong":"@c1509","importance":"bridge","mucCt":"gon","text":"Được xác nhận đã qua đời hơn mười năm trước, vị trí đại nho Triệu quốc do môn sinh Vương Lâm kế thừa.","anchor":"Đại nho Tô Đạo hơn mười năm trước đã qua đời rồi"},{"chuong":"@c1511","importance":"bridge","mucCt":"gon","text":"Được nhắc tên khi so sánh: khí chất hiện tại của Vương Lâm vượt cả sư phụ Tô Đạo năm xưa.","anchor":"cho dù là sư phụ Tô Đạo của hắn năm đó cũng không có loại khí chất này"},{"chuong":"@c1514","importance":"bridge","mucCt":"gon","text":"Được nhắc là nhân vật do bản thể tu sĩ Vương Lâm tạo ra trong Mộng Đạo để đại nho gặp được người cho mình ngộ thiên địa.","anchor":"Vì vậy liền xuất hiện Tô Đạo"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Thiếu niên trên họa thuyền, Tô Đạo quan tâm hỏi nhân quả rồi hỏi tên","ghiChu":"@c1504"},{"ten":"Tô Tam","tag":"su-mon","quanHe":"Đệ tử, dẫn Tô Đạo tới xem Vương Lâm sau khi đọc bài thi bất phàm","ghiChu":"@c1504"},{"ten":"Vương Lâm","tag":"su-mon","quanHe":"Môn sinh cuối cùng (thứ ba)","ghiChu":"Thu nhận khi Vương Lâm 19 tuổi, Tô Đạo 83 tuổi"}],"tuiDo":{}},"nguon":["@c1500","@c1503","@c1504","@c1505","@c1506","@c1508","@c1509","@c1511","@c1514"]},{"id":"lao-gia-hang-nhac-phai","name":"Lão già Hằng Nhạc Phái","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Hằng Nhạc Phái","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Tu sĩ Hằng Nhạc Phái đi cùng nhóm Vương Trác, hoảng sợ thốt lên khi cảm nhận khí tức từ chỉ lực Vương Lâm.","vaiTro":"Tu sĩ Hằng Nhạc Phái, phản ứng trước khí tức Vương Lâm","tinhCach":"Không rõ","tabs":{"diem":[{"text":"Hoảng sợ vô cùng khi cảm nhận khí tức Vương Lâm, thốt lên nghi vấn về tu vi","chuong":"@c1500"}],"kinhLich":[{"chuong":"@c1500","importance":"bridge","mucCt":"gon","text":"Đang phi hành phía trước nhóm Vương Trác trong mưa, quay phắt đầu lại hoảng sợ khi cảm nhận khí tức Vương Lâm.","anchor":"Khí tức này.trời ạ, đây là tu vi gì chứ!"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{}},"nguon":["@c1500"]},{"id":"hoang-long-thuong-tien","name":"Hoàng Long","cn":"","aliases":["Hoàng Long Chân Nhân"],"gioiTinh":"nam","tabs":{"kinhLich":[{"chuong":"@c1500","importance":"normal","mucCt":"vua","tieuDe":"Tính toán khí tức Vương Lâm — máu từ móng tay túa ra","text":"Trên đỉnh Hằng Nhạc Sơn, mặc hoàng bào giơ tay tính toán. Tay rung, máu tươi từ móng tay túa ra, thốt lên kinh ngạc không dám tin — phản ứng mạnh nhất trong các tu sĩ Triệu quốc trước khí tức Vương Lâm.","anchor":"tay phải đang tính toán thì rung lên, máu tươi từ móng tay túa ra"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Vô số năm trước dẫn tổ tiên tộc nhân Âu Dương Hoa đến định cư sơn cốc nơi có trận pháp cổ, được tộc nhân tôn là Hoàng Long thượng tiên","chuong":"@c0495"},{"text":"Hiện thân tại chiến trường Liên Minh Bắc Bộ sau trận thăm dò, nhận định thực lực Tu Chân Liên Minh","chuong":"@c0876"},{"text":"Trên đỉnh Hằng Nhạc Sơn mặc hoàng bào giơ tay tính toán khí tức Vương Lâm, máu tươi từ móng tay túa ra, kinh hãi thốt lên","chuong":"@c1500"}]},"nguon":["@c1500","@c1515"],"trangThai":"song","vaiTro":"Nhân vật bí ẩn — thượng tiên cổ đại từng dẫn dắt tộc nhân, sau hiện thân tại chiến trường","tinhCach":"thâm mưu viễn lự, hành sự thận trọng qua việc đích thân thăm dò thực lực đối phương","blurb":"Hoàng Long thượng tiên là nam tử trung niên xuất hiện trong bức tranh cổ ố vàng nhà Âu Dương Hoa, vô số năm trước từng dẫn tổ tiên tộc nhân đến định cư tại sơn cốc có trận pháp cổ. Về sau hiện thân tại chiến trường Liên Minh Bắc Bộ để nhận định thực lực Tu Chân Liên Minh, và trên đỉnh Hằng Nhạc Sơn mặc hoàng bào giơ tay tính toán khí tức Vương Lâm khiến máu tươi từ móng tay túa ra, kinh hãi thốt lên."},{"id":"niem-thien","name":"Niệm Thiên","cn":"","aliases":["Sư huynh Độn Thiên"],"gioiTinh":"nam","theLuc":[{"ten":"Luyện Hồn Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Anh Biến","trangThai":"tu-vong","blurb":"Niệm Thiên là nam tu trung niên thuộc Luyện Hồn Tông trên Chu Tước Tinh, cả đời cống hiến cho việc tính toán con đường quật khởi của tông phái nhưng 37 lần đều thất bại, rơi vào tuyệt vọng sâu sắc. Sau khi gặp Vương Lâm, hắn hao tổn cự lượng thọ nguyên và sinh cơ để thực hiện chín lần tính toán cuối cùng tìm ra con đường thông thiên cho Luyện Hồn Tông, rồi thọ nguyên cạn kiệt, Nguyên Anh hóa thành chủ hồn đại phiên.","vaiTro":"Thành viên cốt cán Luyện Hồn Tông — sư huynh Độn Thiên trên Chu Tước Tinh","tinhCach":"Kiên trì bất chấp thất bại liên tiếp; u ám và hoài nghi về tiền đồ tông phái; sẵn sàng hy sinh thọ nguyên vì sứ mệnh","tabs":{"diem":[{"text":"Khoanh chân tu luyện giữa âm hồn tràn ngập tại Luyện Hồn Tông, đã trải qua 37 lần tính toán cả đời đều thất bại","chuong":"@c1500"},{"text":"Tuyệt vọng vì Luyện Hồn Tông không thể quật khởi, phát hiện dấu hiệu lạ phía xa và bắt quyết truy tìm","chuong":"@c1501"},{"text":"Hao phí rất nhiều thọ nguyên và sinh cơ, liên tục tính toán chín lần sau khi gặp Vương Lâm để tìm con đường thông thiên cho Luyện Hồn Tông","chuong":"@c1502"},{"text":"Thọ nguyên cạn kiệt, Nguyên Anh hóa thành chủ hồn đại phiên, thần thức khuếch tán khắp Luyện Hồn Tông","chuong":"@c1503"}],"kinhLich":[{"mucCt":"vua","text":"Tại Luyện Hồn Tông trên Chu Tước Tinh, khoanh chân ngồi giữa âm hồn tràn ngập, đã tính toán 37 lần cả đời đều thất bại. Than thở nghi ngờ Luyện Hồn Tông không còn hi vọng.","anchor":"lão phu cả đời này đã tính ba mươi bảy lần, lần nào cũng không thành công","bridge":true,"khoang":"@c1500"},{"mucCt":"ky","text":"Đang tuyệt vọng vì Luyện Hồn tông không thể quật khởi. Đột nhiên phát hiện dấu hiệu lạ ở phía xa, bắt quyết tính toán chín lần đều ra kết quả một, kinh ngạc tới mức có cảm giác hoang đường. Tiêu hao rất nhiều thọ nguyên, dùng thuật Na Di phóng về Triệu quốc. Mấy ngày tìm tới từng thư sinh khoa khảo ở huyện thành, hỏi mỗi người một câu rồi xóa trí nhớ, thất vọng bỏ đi. Cuối cùng dùng hắc phong bao phủ Vương Lâm và Đại Phúc, nói sẽ không làm tổn thương, chỉ cần hỏi một vấn đề.","anchor":"chín lần đều toàn bộ là một","bridge":true,"khoang":"@c1501"},{"importance":"normal","mucCt":"ky","chuong":"@c1502","tieuDe":"Chín lần tính toán, gặp Vương Lâm và nhận lời tiên tri","text":"Hao phí rất nhiều thọ nguyên và sinh cơ liên tục tính toán chín lần để tìm con đường thông thiên cho Luyện Hồn tông, chín lần đều chỉ về một thư sinh ở Triệu quốc. Tới huyện thành tìm kiếm mấy ngày, cuối cùng gặp Vương Lâm. Vung tay áo tạo hắc phong và âm hồn thị uy nhưng Vương Lâm hoàn toàn bình tĩnh, nhận ra đây là người thứ ba trong đời có khí tức đại nho. Đưa Vương Lâm tới Luyện Hồn tông đi khắp sơn môn. Nghe Vương Lâm nói lời tiên tri về thông thiên lộ, chấn động, ghi tạc trong lòng. Cả đời không nói với Độn Thiên, mãi đến mấy trăm năm sau khi đại hạn phủ lưu di ngôn mới nhớ lại lời nho sinh năm xưa.","anchor":"Cả đời này hắn không nói với Độn Thiên chuyện này, mà vào một ngày ở mấy trăm năm sau khi cảm thấy đại hạn phủ trong lúc lưu lại di ngôn mới nhớ tới lời nói của nho sinh mấy trăm năm trước"},{"chuong":"@c1503","importance":"major","mucCt":"vua","tieuDe":"Thọ nguyên hết, Nguyên Anh thành chủ hồn đại phiên","text":"Thọ nguyên cạn kiệt, nhớ lại lời nho sinh mấy trăm năm trước. Thần thức khuếch tán khắp Luyện Hồn tông, kinh hãi phát hiện trong đám người bái nhập có nho sinh hắn từng gặp mấy trăm năm trước. Nguyên Anh dấn thân vào Luyện Hồn Phiên trở thành chủ hồn đại phiên, mang theo sự mê mang không lời giải.","anchor":"Hắn khiếp sợ phát hiện ra người này không ngờ chính là nho sinh hắn đã hỏi chuyện từ mấy trăm năm trước"}],"tuViMoc":[],"nhanMach":[{"ten":"Độn Thiên","tag":"su-mon","quanHe":"Sư đệ","ghiChu":"Cùng thuộc Luyện Hồn Tông"},{"ten":"Vương Lâm","tag":"khac","quanHe":"Thư sinh mà chiêm bốc chỉ tới","ghiChu":"Dùng hắc phong bao phủ, nói chỉ muốn hỏi một câu"}],"tuiDo":{}},"nguon":["@c1500","@c1501","@c1502","@c1503"]},{"id":"don-thien","name":"Độn Thiên","cn":"遁天","aliases":[],"gioiTinh":"nam","tabs":{"kinhLich":[{"chuong":"@c1500","importance":"bridge","mucCt":"gon","text":"Được nhắc tới qua sư huynh tại Luyện Hồn Tông, xác nhận thuộc tông phái này.","anchor":"chính là sư huynh của Độn Thiên"},{"mucCt":"vua","text":"Xuất hiện từ sương mù trên chủ phong Luyện Hồn tông, giọng mang vẻ tang thương, hỏi sư huynh Niệm Thiên về Vương Lâm. Được Niệm Thiên bảo đang dung hợp phiên linh chớ phân tâm, mau bế quan, chỉ nhìn thoáng Vương Lâm rồi rời đi. Bị Vương Lâm tiên tri: mấy trăm năm sau ngày hắn tọa hóa tử vong sẽ có người tới là thông thiên lộ cho Luyện Hồn tông.","anchor":"mấy trăm năm sau ngày ngươi tọa hóa tử vong thì sẽ có một người tới nơi này","bridge":true,"khoang":"@c1502"},{"chuong":"@c1540","importance":"bridge","mucCt":"gon","text":"Được Vương Lâm tìm thấy và thu hồi vận mệnh trong mặt trời thứ chín.","anchor":"Hắn tìm ấy Thập Tam, tìm thấy đầu to, tìm được Chu Dật"}],"tuViMoc":[],"nhanMach":[{"ten":"Niệm Thiên","tag":"su-mon","quanHe":"Sư huynh","ghiChu":"Cùng thuộc Luyện Hồn Tông"}],"tuiDo":{},"diem":[{"text":"Hiện thân từ vòng sáng đỏ, xua chín vị Hóa Thần và tặng Vương Lâm ba phần đại lễ, chính thức nhận làm người kế thừa Luyện Hồn Tông","chuong":"@c0363"},{"text":"Dẫn Vương Lâm cướp tiên ngọc ba tháng khắp bốn tu chân quốc, gom đủ tài nguyên cho Vương Lâm đột phá Anh Biến","chuong":"@c0389"},{"text":"Hộ pháp cho Vương Lâm tiến hành Anh Biến, bố trí lồng khí đen ngăn hương khí bảo vệ quá trình đột phá","chuong":"@c0393"},{"text":"Đối mặt Chu Tước Tử đích thân ép đoạt Thập Ức Tôn Hồn Phiên, thiêu đốt thọ nguyên quyết chiến để bảo vệ trọng bảo tông môn","chuong":"@c0394"},{"text":"Mãn nguyện tọa hóa, tự hủy thần trí và hồn phách hóa tử kim khí dung nhập vào Thập Ức Tôn Hồn Phiên","chuong":"@c0397"},{"text":"Vận mệnh được Vương Lâm tìm thấy và thu hồi trong mặt trời thứ chín, hoàn tất lời hứa kế thừa","chuong":"@c1540"}]},"nguon":["@c1500","@c1502","@c1515","@c1540"],"trangThai":"song","vaiTro":"Thủy tổ Luyện Hồn Tông — ân sư truyền thừa và bồi dưỡng Vương Lâm","tinhCach":"Nhẫn nại chờ đợi người kế thừa qua thời gian bế quan dài đằng đẵng; hào phóng trao đại lễ và toàn bộ tài nguyên tông môn; quyết liệt tự thiêu thọ nguyên để bảo vệ trọng bảo; tính toán an bài hậu sự tông môn chu đáo","blurb":"Độn Thiên là Thủy tổ kiêm tông chủ đương nhiệm Luyện Hồn Tông, tu vi Anh Biến hậu kỳ, bế quan trong vòng sáng đỏ như máu tại tông môn với thọ nguyên chưa tới hai năm trước khi hiện thân chọn Vương Lâm làm người kế thừa. Lão xua chín vị Hóa Thần, tặng ba phần đại lễ, dẫn Vương Lâm cướp tiên ngọc khắp bốn tu chân quốc để bồi dưỡng đột phá Anh Biến, đồng thời giao phó bí mật Thập Ức Tôn Hồn Phiên. Khi Chu Tước Tử đích thân đến ép đoạt hồn phiên, Độn Thiên thiêu đốt thọ nguyên, mãn nguyện tọa hóa, tự hủy thần trí và hồn phách hóa tử kim khí dung nhập vào Thập Ức Tôn Hồn Phiên, hoàn thành sứ mệnh h"},{"id":"to-tam","name":"Tô Tam","cn":"","aliases":["Giám quan già"],"gioiTinh":"nam","vaiTro":"Giám quan già tại trường thi huyện thành Triệu quốc, người duy nhất đánh giá cao bài thi nhân quả của Vương Lâm","tinhCach":"Tỉ mỉ; có nhãn quan khác biệt, không theo số đông","blurb":"Vị giám quan duy nhất đứng lại đọc kỹ bài thi của Vương Lâm sau khi các giám quan khác cười nhạo bỏ đi. Đánh giá Vương Lâm sẽ thành đại nho một đời, khoanh tròn tên hắn.","trangThai":"song","theLuc":[],"tabs":{"diem":[{"text":"Nhãn quan sắc bén, nhận ra tài năng đặc biệt của Vương Lâm khi mọi người cười nhạo","chuong":"@c1501"},{"text":"Chính là lão già trường thi từng nhìn bài thi Vương Lâm cho tới cuối cùng, nhận ra bất phàm","chuong":"@c1504"}],"kinhLich":[{"mucCt":"vua","text":"Là giám quan duy nhất đứng lại đọc kỹ bài luận nhân quả của Vương Lâm. Kinh ngạc nhận định Vương Lâm sẽ thành đại nho một đời, dùng bút khoanh tròn tên hắn.","anchor":"Người này có lẽ không thể thành lương tài cho triều đình nhưng sẽ thành đại nho một đời","bridge":true,"khoang":"@c1501"},{"mucCt":"vua","text":"Tô Tam đứng sau Tô Đạo trên cầu đá Tô thành. Vì khi đọc bài thi của Vương Lâm ở trường thi thấy bất phàm, nên tới bái kiến sư phụ Tô Đạo rồi dẫn Tô Đạo tới nhìn Vương Lâm trên họa thuyền.","anchor":"cảm thấy người này bất phàm, thế nên mới tới bái kiến tiên sinh","bridge":true,"khoang":"@c1504"},{"chuong":"@c1505","importance":"normal","mucCt":"gon","tieuDe":"Mang bài thi Vương Lâm tới Tô Đạo","text":"Mang bài thi của Vương Lâm tới cho Tô Đạo xem, dẫn đến việc đại nho quyết định thu nhận Vương Lâm.","anchor":"Hắn tên là Vương Lâm!"},{"chuong":"@c1506","importance":"bridge","mucCt":"gon","text":"Một trong ba môn sinh cũ của Tô Đạo, bị bệnh nặng nên không lên tiếng nghi ngờ Vương Lâm như hai sư huynh kia.","anchor":"trừ Tô Tam năm đó bị bệnh nặng ra thì hai người còn lại đều lên tiếng nghi ngờ"}],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Thí sinh được ông đánh giá cao","ghiChu":"Khoanh tròn tên trong kỳ thi huyện thành"},{"ten":"Tô Đạo","tag":"su-mon","quanHe":"Sư phụ, Tô Tam xưng đệ tử, dẫn Tô Đạo tới xem Vương Lâm","ghiChu":"@c1504"}],"tuViMoc":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1501","@c1504","@c1505","@c1506"],"canhGioiCaoNhat":"Phàm nhân"},{"id":"dong-van","name":"Đổng Vân","cn":"董云","aliases":[],"gioiTinh":"nam","vaiTro":"Văn sĩ trung niên, tú tài thành triều thần, hỏi Vương Lâm về xuân hạ thu đông","tinhCach":"Hiếu học; dễ bị chấn động tinh thần","blurb":"Văn sĩ trung niên từ tú tài lên triều thần, tới Tô phủ hỏi Vương Lâm về ý nghĩa xuân hạ thu đông. Bị câu trả lời chấn động tâm thần, phải nhờ nô bộc dìu ra.","theLuc":[],"canhGioiCaoNhat":"Phàm nhân","trangThai":"song","tabs":{"diem":[{"text":"Hỏi Vương Lâm về xuân hạ thu đông, bị câu trả lời về sinh lão bệnh tử chấn động tâm thần","chuong":"@c1507"}],"kinhLich":[{"mucCt":"vua","text":"Tới Tô phủ hỏi Vương Lâm về ý nghĩa xuân hạ thu đông. Vương Lâm đáp đó là sinh lão bệnh tử, khiến Đổng Vân ngây ra tại chỗ, tâm thần chấn động, phải nhờ nô bộc dìu ra ngoài.","anchor":"Văn sĩ trung niên ngây ra ở đó. hồi lâu sau ánh mắt lộ vẻ mê man","bridge":true,"khoang":"@c1507"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"an-nhan","quanHe":"Người giảng học tại Tô phủ, đáp câu hỏi khiến Đổng Vân chấn động","ghiChu":"@c1507"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1507"]},{"id":"to-nhat","name":"Tô Nhất","cn":"苏一","aliases":[],"gioiTinh":"nam","vaiTro":"Đệ nhất môn sinh của Tô Đạo, văn thần đương triều Triệu quốc","tinhCach":"Âm trầm; cứng rắn; không phục Vương Lâm","blurb":"Đệ nhất môn sinh của Tô Đạo, nay là văn thần đương triều Triệu quốc. Chất vấn Vương Lâm có thực sự coi tiên nhân như kiến hôi được không, kích hoạt sự kiện tu sĩ tấn công.","theLuc":[{"ten":"Triệu quốc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Phàm nhân","trangThai":"song","tabs":{"diem":[{"text":"Đệ nhất môn sinh Tô Đạo, nay là văn thần đương triều, chất vấn Vương Lâm dẫn đến xung đột tu sĩ","chuong":"@c1507"}],"kinhLich":[{"chuong":"@c1507","importance":"normal","mucCt":"vua","tieuDe":"Chất vấn Vương Lâm tại Tô phủ","text":"Với tư cách đệ nhất môn sinh Tô Đạo và văn thần đương triều, sắc mặt âm trầm chất vấn Vương Lâm có thực sự làm được việc nhìn tiên nhân cũng chẳng khác kiến hôi hay không. Câu hỏi trực tiếp kích hoạt sự kiện tu sĩ đạo bào tấn công Vương Lâm.","anchor":"Hắn đúng là đệ nhất môn sinh của Tô Đạo. đã trở thành một văn thần đương triều - Tô Nhất"},{"chuong":"@c1508","importance":"bridge","mucCt":"gon","tieuDe":"Bái kiến Vương Lâm làm đại nho","text":"Sắc mặt tái nhợt run rẩy quỳ xuống, gắng gượng đứng dậy dẫn đầu văn sinh bái kiến Vương Lâm là đại nho Triệu quốc.","anchor":"Tô Nhất bái kiến đại nho của Triệu quốc ta."}],"tuViMoc":[],"nhanMach":[{"ten":"Tô Đạo","tag":"su-mon","quanHe":"Sư phụ, đệ nhất môn sinh của Tô Đạo","ghiChu":"@c1507"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Người giảng học tại phủ sư phụ mình, Tô Nhất chất vấn không phục","ghiChu":"@c1507"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1507","@c1508"]},{"id":"nam-tu-hoa-phuc-trieu-quoc","name":"Nam tử trung niên hoa phục (Triệu quốc)","cn":"","aliases":[],"gioiTinh":"nam","vaiTro":"Nhân vật bí ẩn thân phận cao quý quan sát Vương Lâm từ tửu lâu, có tu sĩ hầu cận","tinhCach":"Thần sắc không giận mà uy; âm trầm","blurb":"Nam tử trung niên mặc hoa phục, ngồi trong tửu lâu đối diện Tô phủ quan sát Vương Lâm giảng học, có thị vệ và hai thanh niên đạo bào (tu sĩ) hầu cận. Khi Vương Lâm bộc phát uy áp thì sắc mặt tái nhợt kinh hãi.","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"song","tabs":{"diem":[{"text":"Thân phận cao quý bí ẩn, có tu sĩ hầu cận, dường như thấy bóng dáng Tô Đạo trong Vương Lâm","chuong":"@c1507"}],"kinhLich":[{"mucCt":"vua","text":"Ngồi trong tửu lâu đối diện Tô phủ quan sát Vương Lâm, dường như thấy bóng dáng Tô Đạo năm đó. Khi Vương Lâm bộc phát uy áp lôi đình, sắc mặt tái nhợt kinh hãi.","anchor":"Chỉ thấy người này hóa thành một đạo cầu vồng trực tiếp phá tan thiên địa","bridge":true,"khoang":"@c1507"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Quan sát Vương Lâm giảng học, bị uy áp chấn nhiếp","ghiChu":"@c1507"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1507"]},{"id":"thanh-nien-dao-bao-tan-cong","name":"Thanh niên đạo bào tấn công","cn":"","aliases":[],"gioiTinh":"nam","vaiTro":"Tu sĩ hầu cận nam tử hoa phục, tấn công Vương Lâm tại Tô phủ","tinhCach":"Ngạo mạn; khinh phàm nhân","blurb":"Thanh niên mặc đạo bào, một trong hai tu sĩ hầu cận nam tử trung niên hoa phục tại tửu lâu. Hóa cầu vồng phá không, cầm kiếm lao tới phán Vương Lâm tội chết vì bất kính tiên nhân, bị uy áp lôi đình của Vương Lâm chặn lại.","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"song","tabs":{"diem":[{"text":"Tấn công Vương Lâm vì bất kính tiên nhân, bị uy áp lôi đình chấn nhiếp","chuong":"@c1507"}],"kinhLich":[{"mucCt":"vua","text":"Khi Vương Lâm nói có thể coi tiên nhân như kiến hôi, hóa cầu vồng phá không cầm kiếm lao tới, tuyên bố phán Vương Lâm tội chết. Bị luồng uy áp lôi đình mênh mông của Vương Lâm chặn đứng.","anchor":"con kiến hôi không hiểu biết, bất kính với tiên nhân, phán ngươi tội chết","bridge":true,"khoang":"@c1507"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Phán tội chết Vương Lâm, bị uy áp chấn nhiếp","ghiChu":"@c1507"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1507"]},{"id":"thanh-nien-dao-bao-thu-hai","name":"Thanh niên đạo bào thứ hai","cn":"","aliases":[],"gioiTinh":"nam","vaiTro":"Tu sĩ hầu cận nam tử hoa phục, chứng kiến uy áp Vương Lâm","tinhCach":"","blurb":"Thanh niên đạo bào còn lại đứng cạnh nam tử hoa phục trong tửu lâu. Khi Vương Lâm bộc phát uy áp thì mở bừng mắt lộ vẻ sợ hãi khôn cùng.","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"song","tabs":{"diem":[{"text":"Chứng kiến uy áp Vương Lâm, sợ hãi khôn cùng","chuong":"@c1507"}],"kinhLich":[{"chuong":"@c1507","importance":"bridge","mucCt":"gon","text":"Chứng kiến Vương Lâm bộc phát uy áp lôi đình, mở bừng mắt lộ vẻ sợ hãi khôn cùng.","anchor":"ánh mắt hiện lên sự sợ hãi khôn cùng"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1507"]},{"id":"thanh-nien-truc-co-so-ky","name":"Thanh niên Trúc Cơ sơ kỳ","cn":"","aliases":[],"gioiTinh":"nam","trangThai":"song","vaiTro":"Tu sĩ Trúc Cơ sơ kỳ bị Vương Lâm quát lui ở Tô thành","tinhCach":"Kiêu ngạo với phàm nhân; hoảng loạn khi gặp uy áp mạnh","blurb":"Tu sĩ cầm phi kiếm ở Tô thành, bị Vương Lâm một tiếng quát khiến phun máu, phi kiếm rơi xuống đất, tâm thần sụp đổ.","tabs":{"diem":[{"text":"Bị phàm nhân Vương Lâm quát một tiếng khiến phun máu, phi kiếm rơi","chuong":"@c1508"}],"kinhLich":[{"mucCt":"gon","text":"Bị Vương Lâm quát một tiếng phát ra uy áp chính khí, phun máu, phi kiếm rơi xuống đất, hoảng loạn vọt lui.","anchor":"phi kiếm rơi xuống đất, thân thể vội vàng vọt về phía sau","bridge":true,"khoang":"@c1508"}],"tuViMoc":[{"chuong":"@c1508","canhGioi":"Trúc Cơ sơ kỳ","text":"Tu vi Trúc Cơ sơ kỳ khi xuất hiện.","importance":"minor"}],"nhanMach":[],"tuiDo":{}},"canhGioiCaoNhat":"Trúc Cơ sơ kỳ","theLuc":[],"nguon":["@c1508"]},{"id":"thanh-nien-truc-co-trung-ky","name":"Thanh niên Trúc Cơ trung kỳ","cn":"","aliases":[],"gioiTinh":"nam","trangThai":"song","vaiTro":"Tu sĩ Trúc Cơ trung kỳ, đồng môn của thanh niên Trúc Cơ sơ kỳ, bị Vương Lâm uy áp chấn động","tinhCach":"Biết tiến thoái, cung kính khi nhận ra đối phương không thể đắc tội","blurb":"Tu sĩ Trúc Cơ trung kỳ, chỉ liếc nhìn Vương Lâm đã bị chấn động phun máu. Nhận ra không thể đắc tội, cung kính xin rời Tô thành vĩnh viễn rồi dìu đồng môn hóa cầu vồng bay đi.","tabs":{"diem":[{"text":"Chỉ liếc mắt nhìn Vương Lâm đã bị khí tức chấn động phun máu, nhận ra không thể đắc tội phàm nhân này","chuong":"@c1508"}],"kinhLich":[{"chuong":"@c1508","importance":"normal","mucCt":"vua","tieuDe":"Bị Vương Lâm uy áp chấn thương, xin rời Tô thành","text":"Từ tửu lâu bước tới đặt tay lên lưng đồng môn, chỉ liếc mắt nhìn Vương Lâm đã bị khí tức chấn động phun máu. Nhận ra không thể đắc tội, cung kính xin rời đi, thề vĩnh viễn không bước vào Tô thành, dìu đồng môn hóa cầu vồng bay đi.","anchor":"mong đại nho đừng để ý. Chúng ta xin rời đi, vĩnh viễn không bước vào Tô thành nửa bước"}],"tuViMoc":[{"chuong":"@c1508","canhGioi":"Trúc Cơ trung kỳ","text":"Tu vi Trúc Cơ trung kỳ khi xuất hiện.","importance":"minor"}],"nhanMach":[],"tuiDo":{}},"canhGioiCaoNhat":"Trúc Cơ trung kỳ","theLuc":[],"nguon":["@c1508"]},{"id":"phu-than-vuong-lam","name":"Phụ thân Vương Lâm","gioiTinh":"nam","aliases":[],"theLuc":[],"canhGioiCaoNhat":"Phàm nhân","trangThai":"tu-vong","blurb":"Phụ thân phàm nhân của Vương Lâm, sống ở sơn thôn Hằng Nhạc Sơn. Cả đời tự hào vì con trở thành đại nho Triệu quốc, dù không biết chữ vẫn nhờ người chỉnh sửa lời con thành sách.","vaiTro":"Phụ thân phàm nhân của Vương Lâm, nhân vật cảm xúc trọng tâm trong kiếp Toái Niết","tinhCach":"Tự hào về con; hiền hậu chất phác; sợ hãi tử vong nhưng được an ủi liền buông bỏ","tabs":{"diem":[{"text":"Cả đời tự hào nhất là con trai trở thành đại nho Triệu quốc, dù bản thân không biết chữ vẫn nhờ người chỉnh sửa lời con thành sách","chuong":"@c1509"},{"text":"Lâm chung trong vòng tay con trai, từ sợ hãi tử vong dần buông bỏ khi được Vương Lâm ôm và an ủi","chuong":"@c1509"}],"kinhLich":[{"chuong":"@c1509","importance":"normal","mucCt":"vua","tieuDe":"Đón con hồi hương rồi lâm chung","text":"Thân thể già yếu phải chống gậy, đón Vương Lâm về quê, đắc ý tổ chức tiệc rượu lớn, nhắc con chưa cưới thê tử. Năm năm sau lâm chung, nhắc lại đã nhờ người chỉnh sửa lời con thành sách, nhớ câu thiên địa luân hồi sinh lão bệnh tử. Trong nụ cười tự hào có sự sợ hãi tử vong. Được Vương Lâm ôm an ủi, dần hết sợ, nhắm mắt ra đi trong lòng con.","anchor":"Thiết Trụ, cả đời này cha vì con mà không quên được"},{"chuong":"@c1510","importance":"bridge","mucCt":"gon","text":"Được hồi tưởng qua hình ảnh nâng con lên cao, dìu con tập đi, nghiêm khắc nhưng yêu thương, đã mất trước mẫu thân.","anchor":"vẻ mặt bà khi ngủ lộ ra nụ cười hạnh phúc, giống như là trong mộng gặp được phụ thân hắn, hai người gặp lại liền không quay về nữa"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"cha-me","quanHe":"Phụ tử","ghiChu":"Con trai, đại nho Triệu quốc, niềm tự hào cả đời"},{"ten":"Đại Phúc","tag":"khac","quanHe":"Bạn đồng hành của con trai","ghiChu":"Cảm ơn đã chiếu cố cho Vương Lâm"},{"ten":"Mẫu thân Vương Lâm","tag":"the-thiep","quanHe":"Phu thê","ghiChu":"Vợ, dìu đỡ ông lúc già yếu"}],"tuiDo":{}},"nguon":["@c1509","@c1510"]},{"id":"mau-than-vuong-lam","name":"Mẫu thân Vương Lâm","gioiTinh":"nu","aliases":[],"theLuc":[],"canhGioiCaoNhat":"Phàm nhân","trangThai":"tu-vong","blurb":"Mẫu thân phàm nhân của Vương Lâm, sống ở sơn thôn Hằng Nhạc Sơn. Mái tóc bạc, nhiều nếp nhăn, hiền từ đón con hồi hương.","vaiTro":"Mẫu thân phàm nhân của Vương Lâm","tinhCach":"Hiền từ; lấy con trai làm niềm kiêu hãnh","tabs":{"diem":[{"text":"Hiền từ nhìn con trai, dìu đỡ phụ thân già yếu, lấy Vương Lâm làm niềm kiêu hãnh","chuong":"@c1509"}],"kinhLich":[{"chuong":"@c1509","importance":"bridge","mucCt":"gon","text":"Đón Vương Lâm hồi hương, mái tóc bạc nhiều nếp nhăn, hiền từ dìu đỡ phụ thân.","anchor":"Cha, mẹ, Thiết Trụ đã về"},{"chuong":"@c1510","importance":"normal","mucCt":"gon","text":"Qua đời trong giấc ngủ với nụ cười hạnh phúc sau khi chồng mất.","anchor":"vẻ mặt bà khi ngủ lộ ra nụ cười hạnh phúc, giống như là trong mộng gặp được phụ thân hắn, hai người gặp lại liền không quay về nữa"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"cha-me","quanHe":"Mẫu tử","ghiChu":"Con trai"},{"ten":"Phụ thân Vương Lâm","tag":"the-thiep","quanHe":"Phu thê","ghiChu":"Chồng"}],"tuiDo":{}},"nguon":["@c1509","@c1510"]},{"id":"lao-ho-luyen-khi-cac","tabs":{"kinhLich":[],"tuViMoc":[],"nhanMach":[],"tuiDo":{}},"nguon":["@c1494"]},{"id":"nu-tu-ao-tim","tabs":{"kinhLich":[{"chuong":"@c1497","importance":"normal","tieuDe":"Đắp áo cho Vương Lâm rồi rời đi","text":"Do dự trước khi rời thuyền, quay lại lấy áo khoác dày từ túi trữ vật đắp lên người Vương Lâm đang ngủ, thì thầm rồi than nhẹ xoay người rời khỏi.","mucCt":"vua","anchor":"Đúng là từ kiếp trước…"},{"mucCt":"vua","text":"Người thứ tư đuổi theo Vương Lâm sau đại chiến. Mang khí tức bậc toàn năng bước thứ ba, đạo cầu vồng màu tím gào thét bay tới Vân Hải tinh vực.","anchor":"Nữ tử này chính là nữ tử mặc áo tím, bậc toàn năng Không Huyền tới từ Triệu Hà","bridge":true,"khoang":"@c1566"}],"nhanMach":[{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Người nàng đuổi theo sau đại chiến"}],"tuViMoc":[{"chuong":"@c1566","canhGioi":"Toàn năng bước thứ ba (Không Huyền)","text":"Được xác nhận là bậc toàn năng Không Huyền khi đuổi theo Vương Lâm.","importance":"major"}],"diem":[{"text":"Không mở miệng nói từ khi muội muội tử trận ba mươi năm trước, hành động trong đại chiến khiến mọi người tôn trọng","chuong":"@c1566"}]},"nguon":["@c1497","@c1566"],"canhGioiCaoNhat":"Toàn năng bước thứ ba (Không Huyền)","trangThai":"song","vaiTro":"Bậc toàn năng Không Huyền từ Triệu Hà, lai lịch thần bí, đuổi theo Vương Lâm","tinhCach":"Trầm mặc; kiên nghị; không mở miệng nói từ khi muội muội tử trận","blurb":"Nữ tử áo tím bậc toàn năng Không Huyền tới từ Triệu Hà. Lai lịch thần bí, ba mươi năm trước muội muội tử trận, từ đó không mở miệng nói. Hành động trong đại chiến khiến mọi người tôn trọng.","gioiTinh":"nu","theLuc":[{"ten":"Triệu Hà","trangThai":"gan-bo"}]},{"id":"nu-tu-tuyet-vuc-quoc","name":"Nữ tử Tuyết Vực quốc","cn":"","aliases":["Nữ tử Tuyết Vực (lạnh như băng)"],"gioiTinh":"nu","theLuc":[{"ten":"Tuyết Vực quốc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","vaiTro":"Nữ tu sĩ từ Tuyết Vực quốc tìm đại nho Vương Lâm hỏi chuyện","tinhCach":"Lạnh lùng; mang hàn ý cực mạnh","blurb":"Nữ tử trung niên dung nhan xinh đẹp tới từ Tuyết Vực quốc, toàn thân tỏa hàn ý vô tận khiến nước mưa đóng băng. Ôm một đứa trẻ bọc chăn bông, tìm đại nho Vương Lâm để hỏi chuyện.","tabs":{"diem":[{"text":"Toàn thân tỏa hàn ý vô tận, nước mưa bốn phía đóng băng, cả bầu trời phía sau đều đóng băng","chuong":"@c1511"},{"text":"Ôm đứa trẻ bọc chăn bông, tự xưng tới từ Tuyết Vực quốc tìm Vương Lâm","chuong":"@c1511"}],"kinhLich":[{"mucCt":"vua","text":"Bước tới trong mưa, hàn ý khiến nước mưa và cả bầu trời phía sau đều đóng băng. Ôm đứa trẻ bọc chăn bông, tự xưng tới từ Tuyết Vực quốc, tìm đại nho Vương Lâm hỏi một chuyện.","anchor":"Ta tới từ Tuyết Vực quốc, tìm ngươi hỏi một chuyện","bridge":true,"khoang":"@c1511"},{"chuong":"@c1512","importance":"normal","mucCt":"vua","tieuDe":"Đem Hồng Điệp tới nhờ Vương Lâm chỉ điểm","text":"Tu sĩ từ Tuyết Vực xa xôi, dáng vẻ lạnh lùng như băng, am hiểu bói toán. Nhặt được Hồng Điệp trong tuyết khi bé gần chết cóng, phát hiện thiên tư cực cao (khí tức ngũ hành) và mệnh số mang đại kiếp sinh tử. Dùng thần thông hạn chế đứa bé lớn lên, tìm tới đại nho Vương Lâm nhờ chỉ điểm cách hóa giải. Nhận trận pháp Vương Lâm vẽ, vái sâu rồi ôm đứa bé đi vào mưa.","anchor":"Tu vi của lão thân có hạn. Chỉ có thể lấy thần thông hạn chế nó lớn lên"}],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Tìm tới đại nho Vương Lâm để hỏi chuyện","ghiChu":"@c1511"},{"ten":"Vương Lâm","tag":"an-nhan","quanHe":"Tìm tới nhờ chỉ điểm hóa giải kiếp nạn cho Hồng Điệp, được Vương Lâm vẽ trận pháp","ghiChu":"@c1512"},{"ten":"Hồng Điệp","tag":"khac","quanHe":"Nhặt được trong tuyết, nuôi dưỡng và bảo vệ","ghiChu":"@c1512"}],"tuiDo":{}},"nguon":["@c1511","@c1512"]},{"id":"dai-han-tho-ren","name":"Đại hán thợ rèn","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Phàm nhân","trangThai":"song","vaiTro":"Chủ tiệm rèn ở đô thành, mời Vương Lâm uống rượu","tinhCach":"Đôn hậu; hiếu khách","blurb":"Nam tử trung niên thân thể cường tráng, chủ tiệm rèn ở đô thành trong tuyết. Tổ phụ trước làm nghề bán rượu, đời hắn mới chuyển sang thợ rèn. Mời Vương Lâm uống rượu ấm và tặng bầu rượu khi tiễn biệt.","tabs":{"diem":[{"text":"Tổ phụ trước làm nghề bán rượu, đời hắn mới mở tiệm rèn — chi tiết trùng hợp với giấc mộng của Vương Lâm","chuong":"@c1511"}],"kinhLich":[{"mucCt":"gon","text":"Mời Vương Lâm vào tiệm uống rượu ấm, kể chuyện tổ phụ làm nghề bán rượu, tặng bầu rượu giữ ấm khi tiễn biệt.","anchor":"Vương Lâm ngồi ở đó, uống rượu Tằng gia, hơi không phân biệt được đây có phải là mộng hay không","bridge":true,"khoang":"@c1511"}],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Khách ghé tiệm rèn, mời uống rượu và tặng bầu rượu","ghiChu":"@c1511"}],"tuiDo":{}},"nguon":["@c1511"]},{"id":"tu-nuong","name":"Tú Nương","cn":"","aliases":[],"gioiTinh":"nu","theLuc":[],"canhGioiCaoNhat":"Phàm nhân","trangThai":"song","vaiTro":"Vợ đại hán thợ rèn","tinhCach":"Hiền huệ","blurb":"Vợ đại hán thợ rèn, nữ tử trung niên thần sắc hiền huệ, mang rượu ấm cho Vương Lâm.","tabs":{"diem":[{"text":"Thần sắc hiền huệ, mang rượu ấm cho Vương Lâm và hỏi hắn có phải tìm người thân","chuong":"@c1511"}],"kinhLich":[{"chuong":"@c1511","importance":"bridge","mucCt":"gon","text":"Mang rượu ấm cho Vương Lâm, hỏi hắn có phải tìm người thân.","anchor":"Vương Lâm ngồi ở đó, uống rượu Tằng gia, hơi không phân biệt được đây có phải là mộng hay không"}],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Khách ghé tiệm rèn của gia đình","ghiChu":"@c1511"}],"tuiDo":{}},"nguon":["@c1511"]},{"id":"be-trai-tiem-ren","name":"Bé trai tiệm rèn","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Phàm nhân","trangThai":"song","vaiTro":"Con trai đại hán thợ rèn và Tú Nương","tinhCach":"Tò mò","blurb":"Bé trai khoảng tám tuổi, con trai đại hán thợ rèn và Tú Nương. Khuôn mặt đỏ bừng, mặc áo bông dày, tò mò nhìn Vương Lâm. Vương Lâm thoáng nghĩ giống Đại Ngưu trong mộng nhưng nhận ra không phải.","tabs":{"diem":[{"text":"Vương Lâm nhìn thấy giống Đại Ngưu trong mộng nhưng nhận ra không phải","chuong":"@c1511"}],"kinhLich":[{"chuong":"@c1511","importance":"bridge","mucCt":"gon","text":"Tò mò nhìn Vương Lâm khi hắn ghé tiệm rèn.","anchor":"Đứa bé kia không phải là Đại Ngưu trong mộng của hắn"}],"nhanMach":[],"tuiDo":{}},"nguon":["@c1511"]},{"id":"dai-nguu","name":"Đại Ngưu","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"trangThai":"khong-ro","tabs":{"kinhLich":[{"chuong":"@c1511","importance":"bridge","mucCt":"gon","text":"Được Vương Lâm nhớ tới khi nhìn bé trai tiệm rèn, nhận ra không phải Đại Ngưu trong mộng.","anchor":"Đứa bé kia không phải là Đại Ngưu trong mộng của hắn"}],"diem":[{"text":"Thiếu niên 12 tuổi kết thân với Vương Lâm, ngày nào cũng mang rượu trái cây sang xem điêu khắc","chuong":"@c0229"},{"text":"Cha qua đời — Vương Lâm cảm ngộ thiên đạo luân hồi từ sự kiện này","chuong":"@c0240"},{"text":"Bị cưỡng bức đưa đi phương Nam dọn tuyết trong chiến loạn tu sĩ","chuong":"@c0245"},{"text":"Được Vương Lâm cứu thoát, đưa vợ chồng vượt biên giới sang nước láng giềng an toàn","chuong":"@c0249"},{"text":"Định cư nước láng giềng, mở cửa hàng rèn, vợ sinh con gái được Vương Lâm từ xa bảo hộ","chuong":"@c0258"},{"text":"Sống thọ 137 tuổi, trước khi chết vẫn nhớ mong vị tiên nhân Vương Lâm","chuong":"@c1041"}]},"nguon":["@c1511"],"vaiTro":"Hàng xóm phàm nhân — bạn cố tri của Vương Lâm suốt giai đoạn hóa phàm ngộ đạo","tinhCach":"Thân thiện, chủ động kết giao từ thuở thiếu niên; trọng tình nghĩa, giữ liên hệ thăm hỏi qua nhiều năm; chịu thương chịu khó, kế thừa nghề rèn gánh vác gia đình","blurb":"Con trai thợ rèn sống đối diện nhà Vương Lâm trong hơn ba mươi năm hóa phàm tại Tứ Phái, từ cậu thiếu niên 12 tuổi ngày ngày mang rượu trái cây sang xem khắc gỗ cho đến khi trưởng thành lấy vợ sinh con, chịu tang cha rồi kế thừa lò rèn gia truyền. Bị cưỡng bức đưa đi dọn tuyết trong chiến loạn tu sĩ, được Vương Lâm cứu thoát và đưa vợ chồng vượt biên sang nước láng giềng định cư, mở cửa hàng rèn mới. Sống thọ 137 tuổi, đến lúc lâm chung vẫn nhớ mong vị tiên nhân họ Vương năm xưa."},{"id":"nu-tu-ao-trang-nui-lua","name":"Nữ tử áo trắng (vùng núi lửa)","cn":"","aliases":[],"gioiTinh":"nu","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"song","vaiTro":"Nữ tử bí ẩn xuất hiện tại vùng núi lửa, khiến Vương Lâm chấn động","tinhCach":"Bí ẩn; xuất hiện giữa khói lửa núi lửa một cách tự nhiên","blurb":"Nữ tử tóc dài phủ vai, bề ngoài rất đẹp, xuất hiện giữa đám khói đen núi lửa đang bộc phát trên đại lục xa lạ. Nàng cầm bình ngọc thu thập vật phẩm tại chỗ núi lửa phun, ánh mắt khi xoay người nhìn Vương Lâm khiến hắn chấn động sâu sắc.","tabs":{"diem":[{"text":"Xuất hiện giữa núi lửa bộc phát, cầm bình ngọc thu thập vật phẩm, bề ngoài rất đẹp","chuong":"@c1513"},{"text":"Ánh mắt khiến Vương Lâm run lên như đã đợi mấy ngàn năm","chuong":"@c1513"}],"kinhLich":[{"chuong":"@c1513","importance":"normal","mucCt":"vua","tieuDe":"Xuất hiện tại vùng núi lửa","text":"Trong đám khói đen núi lửa bộc phát, nàng xuất hiện như bóng trắng, tay cầm bình ngọc thu thập thứ gì đó tại chỗ núi lửa phun. Khi xoay người nhận thấy Vương Lâm ở phía xa, ánh mắt của nàng khiến hắn chấn động.","anchor":"Hắn thấy trong đám khói đen có một bóng trắng đi ra"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Người đối diện ánh mắt","ghiChu":"Vương Lâm gặp nàng tại vùng núi lửa, chỉ một ánh mắt đã chấn động"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1513"]},{"id":"thuyen-vien-trung-nien","name":"Thuyền viên trung niên","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Phàm nhân","trangThai":"khong-ro","vaiTro":"Thuyền viên trên thương thuyền, người cất tiếng hát đầu tiên trong bão","tinhCach":"Kiên cường; dám cất tiếng hát giữa tuyệt vọng","blurb":"Thuyền viên trung niên trên thương thuyền vượt biển Chu Tước Tinh, trong cơn bão nộ hải đã cười thảm rồi cất tiếng hát truyền thống đầu tiên, khơi dậy tinh thần bất khuất cho cả thuyền.","tabs":{"diem":[{"text":"Cất tiếng hát nghịch hành đầu tiên giữa bão biển, khơi dậy tinh thần bất khuất cho thuyền viên","chuong":"@c1513"}],"kinhLich":[{"mucCt":"gon","text":"Giữa bão biển nộ hải, cười thảm rồi nắm chặt dây thừng, cất tiếng hát truyền thống đầu tiên khơi dậy tinh thần bất khuất.","anchor":"Một thuyền viên trung niên cười thảm một tiếng, nắm chặt lấy dây thừng","bridge":true,"khoang":"@c1513"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1513"]},{"id":"vong-nam","name":"Vọng Nam","gioiTinh":"nu","trangThai":"khong-ro","blurb":"Nữ tử đang phi hành cùng Từ Phi trên bầu trời Chu Tước Tinh trong mộng cảnh, hóa tro bụi khi Vương Lâm phá hủy mộng.","vaiTro":"Nhân vật phụ trong mộng cảnh Chu Tước Tinh","tinhCach":"Không rõ","tabs":{"diem":[{"text":"Phi hành cùng Từ Phi trong mộng cảnh, hóa tro bụi khi mộng vỡ","chuong":"@c1518"}],"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1518","text":"Đang phi hành cùng Từ Phi trên bầu trời, hóa tro bụi khi Vương Lâm phá hủy mộng cảnh.","anchor":"Tử Phi, Vọng Nam. hai nữ tử này vốn đang phi hành trên bầu trời lúc này cùng với thời gian đọng lại, theo cơn gió thổi tới thân thể liền hóa thành một đám tro bụi bị cuốn đi"}],"tuViMoc":[],"nhanMach":[{"ten":"Từ Phi","tag":"ban-be","quanHe":"Đồng hành","ghiChu":"Cùng phi hành trên bầu trời trong mộng cảnh"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1518"]},{"id":"lao-to-dang-gia","name":"Lão tổ Đằng gia","gioiTinh":"nam","trangThai":"khong-ro","blurb":"Lão tổ gia tộc họ Đằng tại Triệu quốc trong mộng cảnh Chu Tước Tinh, tiêu tán cùng mọi tu sĩ khi Vương Lâm phá mộng.","vaiTro":"Nhân vật phụ trong mộng cảnh, tu sĩ Triệu quốc","tinhCach":"Không rõ","tabs":{"diem":[{"text":"Tu sĩ Triệu quốc tiêu tán khi Vương Lâm phá hủy mộng cảnh","chuong":"@c1518"}],"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1518","text":"Được nhắc tên trong số tu sĩ Triệu quốc tiêu tán khi mộng cảnh vỡ.","anchor":"Cái gì là sinh tử.tay trái của ta là sinh, tay phải là tử"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1518"]},{"id":"dong-tu-dau-to","name":"Đồng tử đầu to","gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1520","importance":"bridge","mucCt":"vua","text":"Cùng Thập Tam tham chiến tại Chu Tước Tinh, tu vi chưa đủ nhưng trưởng thành nhanh qua chiến đấu, thương tích đầy người.","anchor":"Tu vi của bọn họ dù không đủ nhưng trong mấy trận chiến này đều trưởng thành nhanh chóng"},{"chuong":"@c1540","importance":"bridge","mucCt":"gon","text":"Được Vương Lâm tìm thấy và thu hồi vận mệnh trong mặt trời thứ chín.","anchor":"Hắn tìm ấy Thập Tam, tìm thấy đầu to, tìm được Chu Dật"},{"chuong":"@c1553","importance":"bridge","mucCt":"gon","text":"Có mặt với tư cách phó tướng trong đoàn tu sĩ giới nội xuất chinh theo Vương Lâm.","anchor":"có phó tướng đầu to của hắn"}],"nhanMach":[],"tuViMoc":[],"diem":[{"text":"Dẫn quân La Thiên xâm phạm Chu Tước Tinh, bị Vương Lâm đánh bại rồi phong ấn nguyên thần thu phục","chuong":"@c0838"},{"text":"Mang quá khứ bị gia tộc đuổi đi trong đêm mưa, mẫu thân phiền chán đánh đập, tạo nên tính cách cô độc trầm mặc","chuong":"@c0856"},{"text":"Định tự bạo nguyên thần khi bị sáu phân thân Khuy Niết sơ kỳ của Vu Phi dồn ép đến tuyệt vọng","chuong":"@c0853"},{"text":"Nhục thân cũ sụp đổ tại Yêu Linh chi địa, được trợ giúp ngưng tụ thân thể mới tại Chu Tước Thánh Tông","chuong":"@c1016"},{"text":"Được Vương Lâm trả hồn huyết và giải phong ấn, hoàn toàn tự do nhưng vẫn chọn ở lại","chuong":"@c1621"},{"text":"Chuyển thế thành tu sĩ đầu cực to, được Vương Lâm tìm tới khôi phục ký ức kiếp trước","chuong":"@c1959"}]},"nguon":["@c1520","@c1540","@c1553"],"vaiTro":"Thiên Cương tiên La Thiên — thuộc hạ trung thành của Vương Lâm","tinhCach":"ngoài mặt cười ngây ngô nhưng nội tâm thận trọng, quan sát tinh tế; trung thành tuyệt đối với Vương Lâm, sẵn sàng tự bạo nguyên thần khi nguy cấp; cô độc trầm mặc do quá khứ bị gia tộc ruồng bỏ; am hiểu cấm chế và phá trận","blurb":"Đồng tử đầu to là tu sĩ Khuy Niết thuộc La Thiên Bắc Vực, một trong số ít Thiên Cương tiên có thể khắc tên lên Phong Tiên thạch. Từ kẻ dẫn quân xâm phạm Chu Tước Tinh, hắn bị Vương Lâm đánh bại và phong ấn nguyên thần thu phục, về sau nhiều lần hộ pháp, trợ chiến và theo hầu qua vô số tử địa. Dù nhục thân cũ sụp đổ rồi được tái tạo, dù được trả hồn huyết và giải phong ấn hoàn toàn tự do, hắn vẫn chọn ở lại bên Vương Lâm, và sau khi chuyển thế vẫn được Vương Lâm tìm tới khôi phục ký ức kiếp trước."},{"id":"thanh-long-thanh-hoang","name":"Thanh Long Thánh Hoàng","gioiTinh":"nam","canhGioiCaoNhat":"Thiên nhân ngũ suy (chưa bước thứ ba)","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1520","importance":"normal","mucCt":"ky","tieuDe":"Tái xuất cùng Tứ Thánh Tông, tử chiến Chu Tước Tinh","text":"Thanh Long Thánh Hoàng chưa chết, vài thập niên trước tái xuất hiện cùng Tứ Thánh Tông trở thành lực lượng giới nội Côn Hư. Tu vi đạt thiên nhân ngũ suy (chưa bước thứ ba). Dẫn trưởng lão Tứ Thánh Tông tử chiến với giới ngoại tại Chu Tước Tinh.","anchor":"tu vi đã cực cao, những năm gần đây dù chưa đạt tới bước thứ ba nhưng cũng đã đạt tới thiên nhân ngũ suy"},{"chuong":"@c1523","importance":"bridge","mucCt":"gon","text":"Thần sắc mệt mỏi nhưng thân thể chấn động kích động khi khí tức Phong Tôn xuất hiện.","anchor":"Thanh Long Thánh Hoàng thần sắc mệt mỏi kia lúc này toàn bộ đều thân thể chấn động"},{"mucCt":"vua","text":"Được xác nhận là người của Tứ Thánh Tông. Giơ tay túm hư không, bốn bảo vật truyền thừa Tứ Thánh Tông hiện ra bên thân, dự định dùng chúng giúp Vương Lâm mở Không Môn ở thời điểm mấu chốt.","anchor":"lập tức bốn bảo vật truyền thừa của Tứ Thánh Tông hiện ra bên cạnh thân thể hắn","bridge":true,"khoang":"@c1524"}],"tuViMoc":[{"chuong":"@c1520","canhGioi":"Thiên nhân ngũ suy","text":"Tu vi đạt thiên nhân ngũ suy, chưa đạt bước thứ ba.","importance":"minor"}],"nhanMach":[],"diem":[{"text":"Bị Tiên Đế Thanh Lâm phong ấn trong lòng núi tại Vũ chi Tiên giới, được đoàn Vương Lâm giải cứu thoát ra","chuong":"@c1044"},{"text":"Chỉnh hợp Tứ Thánh Tông thành một tông duy nhất, xưng thánh tôn","chuong":"@c1054"},{"text":"Bế quan trấn áp nội hoạ do máu thiên đạo, xuất quan hạ lệnh thu phục Côn Hư","chuong":"@c141"},{"text":"Một mình tiến vào tinh vực Thi Âm Tông, đánh bại tông chủ Đệ Nhất Vương","chuong":"@c147"},{"text":"Tái xuất cùng Tứ Thánh Tông tham chiến tại Chu Tước Tinh, tu vi đạt thiên nhân ngũ suy","chuong":"@c1520"},{"text":"Máu thiên đạo bị Thiên Vận Tử cướp mất","chuong":"@c1626"}]},"nguon":["@c1520","@c1523","@c1524"],"cn":"青龙圣皇","vaiTro":"Thánh Hoàng hùng mạnh nhất Tứ Thánh Tông, sau chỉnh hợp bốn tông xưng thánh tôn","tinhCach":"Năm xưa hào sảng phóng khoáng, nay âm trầm tâm cơ sâu do ảnh hưởng máu thiên đạo; giỏi bày mưu giăng bẫy, quyết đoán cứng rắn trong việc chỉnh hợp và thu phục các thế lực","blurb":"Thanh Long Thánh Hoàng là Thánh Hoàng hùng mạnh nhất của Tứ Thánh Tông, vừa nhậm chức liền đi điều tra nguyên nhân Tiên giới sụp đổ, bị Tiên Đế Thanh Lâm phong ấn trong lòng núi tại Vũ chi Tiên giới, chỉ kịp để lại thần niệm cầu cứu trong Thanh quang thuẫn. Sau khi được giải cứu, ông trở về chỉnh hợp Tứ Thánh Tông thành một tông duy nhất và xưng thánh tôn, tính tình đổi khác do ảnh hưởng máu thiên đạo, bế quan trấn áp nội hoạ rồi ra tay thu phục các thế lực, một mình đánh bại Thi Âm Tông. Vài thập niên sau tái xuất cùng Tứ Thánh Tông tham chiến tại Chu Tước Tinh, hiện tu vi đạt thiên nhân ngũ "},{"id":"nam-tu-ao-thanh-y","name":"Nam tử mặc thanh y (giới ngoại)","aliases":["Nam tử áo thanh y","Thanh niên thanh y (giới ngoại)"],"gioiTinh":"nam","canhGioiCaoNhat":"Không Huyền sơ kỳ (bước thứ ba)","trangThai":"song","theLuc":[{"ten":"Đại quân giới ngoại","trangThai":"gan-bo"}],"tabs":{"diem":[{"text":"Tu sĩ bước thứ ba phe giới ngoại, cảm ngộ băng bổn nguyên, tu vi Không Huyền sơ kỳ, từng xuất hiện trong đại kiếp năm xưa của Vương Lâm.","chuong":"@c1520"}],"kinhLich":[{"mucCt":"ky","text":"Một mình đấu Long Bàn Tử và Tư Đồ Nam khiến hai người liên tiếp bại lui. Phất tay đóng băng ngàn trượng. Nhạo báng rằng Phong Tôn đã bị giới ngoại lừa giết. Khi Không Môn xuất hiện, nheo mắt tuyên bố sẽ giết ngay kẻ vừa đột phá bước thứ ba.","anchor":"Nếu Vương Lâm ở nơi này chắc chắn sẽ nhận ra kẻ này là một người xuất hiện trong đại kiếp của hắn năm đó","bridge":true,"khoang":"@c1520"},{"mucCt":"ky","text":"Đứng vững trong uy áp, lần lượt nhận ra Lôi bổn nguyên, Hỏa bổn nguyên, Nhân Quả đại đạo. Thần sắc đại biến khi ba đạo bổn nguyên xuất hiện. Tới bốn đạo thì tái nhợt, nhận định bốn đạo bổn nguyên phá không môn ngang Không Linh trung kỳ. Năm đạo bổn nguyên khiến hắn hoảng sợ chưa từng có, lui hơn mười trượng, nhận định đủ đánh Không Linh hậu kỳ. Hắn tính nếu người này thuộc giới nội phải lập tức giết, hậu hoạn vô cùng.","anchor":"Năm đạo bổn nguyên. Không ngờ lại có tới năm đạo bổn nguyên.","bridge":true,"khoang":"@c1521"},{"chuong":"@c1522","importance":"bridge","mucCt":"gon","text":"Đi cùng Chu Cẩn và Hư Thần Thiên Tôn, kinh hãi thốt lên khi phát hiện không môn có sáu đạo bổn nguyên.","anchor":"Sáu.sáu đạo bổn nguyên! Trong thiên địa này không ngờ lại có người có được sáu đạo bổn nguyên!"},{"chuong":"@c1525","importance":"bridge","mucCt":"vua","text":"Nhìn ra việc Vương Lâm không hấp thu sức mạnh Không Môn, kinh hoảng và lộ vẻ kính trọng trước hành động của kẻ địch.","anchor":"Mặc dù hai bên là kẻ địch của nhau, nhưng hắn cũng lộ ra một vẻ kính trọng"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Từng xuất hiện trong đại kiếp năm xưa của Vương Lâm"},{"ten":"Long Bàn Tử","tag":"doi-thu","quanHe":"Đấu khiến Long Bàn Tử bại lui"},{"ten":"Tư Đồ Nam","tag":"doi-thu","quanHe":"Đấu khiến Tư Đồ Nam bại lui"}]},"vaiTro":"Tu sĩ bước thứ ba phe giới ngoại, cảm ngộ băng bổn nguyên","blurb":"Nam tử mặc thanh y lãnh khốc, tu sĩ bước thứ ba phe giới ngoại cảm ngộ băng bổn nguyên, tu vi Không Huyền sơ kỳ. Từng xuất hiện trong đại kiếp năm xưa của Vương Lâm.","tinhCach":"Lãnh khốc; ngạo mạn; tàn nhẫn","nguon":["@c1520","@c1521","@c1522","@c1525"]},{"id":"dai-han-phung-thien-lang-toc","name":"Chu Cẩn","cn":"朱谨","aliases":["Chu Cẩn","#chu-duc-chu-can"],"gioiTinh":"nam","canhGioiCaoNhat":"Bước thứ ba","trangThai":"song","theLuc":[{"ten":"Phụng Thiên Lang tộc","trangThai":"gan-bo"},{"ten":"Đại quân giới ngoại","trangThai":"gan-bo"}],"tabs":{"kinhLich":[{"chuong":"@c1520","importance":"normal","mucCt":"ky","tieuDe":"Phản bội giới nội, theo giới ngoại tạo gió tanh mưa máu","text":"Nguyên nô bộc của Vương Lâm, sau khi Vương Lâm mất tích liền phản bội, mang Phụng Thiên Lang tộc gây tang tóc giới nội để rửa nhục bị thu làm nô bộc. Lúc này là một trong ba tu sĩ bước thứ ba phe giới ngoại, huyết lang khổng lồ hiện thân nhưng không hạ được Lỗ Phu Tử. Nghe hai chữ Phong Tôn thì lộ vẻ khuất nhục, ra tay tàn độc hơn. Khi Không Môn xuất hiện, Chu Cẩn mẫn cảm nhất vì mang ấn ký nô bộc của Vương Lâm, nhận ra khí tức quen thuộc, gần hồn phi phách tán.","anchor":"Người này sau khi Vương Lâm mất tích liền phản bội, lúc này mang theo Phụng Thiên Lang tộc tạo thành gió tanh mưa máu trong giới nội"},{"chuong":"@c1521","importance":"bridge","mucCt":"gon","text":"Kinh hãi trước uy áp không môn vượt xa không môn hắn năm đó, sụp đổ hoảng sợ khi đạo bổn nguyên thứ tư xuất hiện.","anchor":"Uy áp không môn cường đại như vậy, đây.đây rốt cục là mấy đạo bổn nguyên!"},{"chuong":"@c1522","importance":"bridge","mucCt":"gon","text":"Theo sau Hư Thần Thiên Tôn tiến về Chu Tước Tinh, run rẩy sợ hãi trước không môn, rồi lại kinh hãi khi phát hiện sáu đạo bổn nguyên.","anchor":"Chỉ là trong lòng Chu cẩn vẫn run rẩy"},{"chuong":"@c1523","importance":"bridge","mucCt":"vua","text":"Đang định dẫn mấy vạn tu sĩ giới ngoại xông vào Chu Tước Tinh thì cảm khí tức Vương Lâm, đổ mồ hôi như mưa lùi về sau, sắc mặt trắng bệch tuyệt vọng.","anchor":"Chu cẩn kia mồ hôi đổ xuống như mưa"},{"mucCt":"vua","text":"Chu Cẩn như phát điên lui về sau, tuyệt vọng trước sức mạnh lôi đình Vương Lâm. Hy vọng duy nhất là Vương Lâm mở không được Không Môn — nếu thất bại thì đó là lúc Vương Lâm tử vong, cũng là con đường sống duy nhất của Chu Cẩn.","anchor":"một khi thất bại, thì đó chính là lúc hắn tử vong","bridge":true,"khoang":"@c1524"},{"mucCt":"vua","text":"Chứng kiến Vương Lâm phá Không Môn thì tuyệt vọng, muốn rời đi nhưng bị áp lực phong tỏa tinh không khóa lại. Bị một cái liếc mắt của Vương Lâm khiến tâm thần chấn động ầm vang và phun máu.","anchor":"Một cái liếc mắt này khiến trong đầu Chu cẩn ầm vang lên","bridge":true,"khoang":"@c1525"},{"mucCt":"vua","text":"Dù bị cảnh tượng Vương Lâm phá cửa dọa sợ, vẫn liều mạng xông lên cùng huyết lang mấy vạn trượng. Bị một chỉ đạo niệm của Vương Lâm khiến thân thể run lên, không thể bước tới thêm.","anchor":"thân thể Chu Cẩn kia đột nhiên run lên, không thể bước tới thêm được chút nào nữa","bridge":true,"khoang":"@c1527"},{"mucCt":"vua","text":"Là tu sĩ giới ngoại duy nhất tại khu vực gần Chu Tước Tinh không bị gợn sóng giết. Đứng run rẩy, mặt xám như tro, nhìn Vương Lâm trong vòng xoáy Không Môn hấp thụ sức mạnh và nhận ra Vương Lâm đã mạnh vượt xa tưởng tượng.","anchor":"Cách đó không xa, Chu Cẩn là tu sĩ giới ngoại duy nhất ở nơi đây không bị gợn sóng kia g**t ch*t","bridge":true,"khoang":"@c1529"}],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Nguyên nô bộc của Vương Lâm, mang ấn ký nô bộc, phản bội sau khi Vương Lâm mất tích"},{"ten":"Lỗ Phu Tử","tag":"doi-thu","quanHe":"Đang giằng co chiến đấu tại Chu Tước Tinh"}],"tuViMoc":[],"diem":[{"text":"Phục kích Vương Lâm từ khe nứt hư không, bị móng tay Đại Hoang thượng nhân xuyên thấu trúng độc","chuong":"@c1343"},{"text":"Bị Vương Lâm cùng Linh Động áp chế hoàn toàn, luyện hóa trong Thiên Hoàng Lô","chuong":"@c1373"},{"text":"Thoát Thiên Hoàng Lô nhưng đạo tâm tan nát, quỳ phục trước Vương Lâm","chuong":"@c1379"},{"text":"Thi triển Quần Lang Bái Nguyệt — hồng nguyệt đỏ máu xé bầu trời, phá bàn tính truy kích kẻ địch","chuong":"@c1417"},{"text":"Phản bội giới nội sau khi Vương Lâm mất tích, mang Phụng Thiên lang tộc gây tang tóc cho giới nội","chuong":"@c1520"},{"text":"Tuyệt vọng trước sức mạnh Vương Lâm tái xuất, là tu sĩ giới ngoại duy nhất gần Chu Tước Tinh sống sót","chuong":"@c1529"}]},"nguon":["@c1520","@c1521","@c1522","@c1523","@c1524","@c1525","@c1527","@c1529"],"vaiTro":"Đại hán Phụng Thiên lang tộc — tu sĩ bước thứ ba, nguyên nô bộc của Vương Lâm","tinhCach":"Hung hãn cuồng bạo khi giao chiến; tham lam, muốn chiếm đoạt Cổ Tức Diệp; tuân lệnh nhưng phản bội khi mất ràng buộc; khiếp nhược trước cường giả áp chế","blurb":"Chu Cẩn là tu sĩ Không Niết sơ kỳ bước thứ ba thuộc Phụng Thiên lang tộc, thân cao ba trượng, mi tâm mang ấn ký đầu sói xanh. Nhận lệnh Chưởng Tôn phục kích Vương Lâm nhưng liên tiếp thất bại, bị luyện hóa trong Thiên Hoàng Lô và trở thành nô bộc. Sau khi Vương Lâm mất tích, hắn phản bội giới nội mang lang tộc gây tang tóc, song khi Vương Lâm tái xuất liền tuyệt vọng khiếp sợ và bị áp chế hoàn toàn."},{"id":"oa-oa","name":"Oa Oa","cn":"","aliases":["Nữ đồng Tiên Cương"],"gioiTinh":"nu","trangThai":"song","theLuc":[],"vaiTro":"Nữ đồng bí ẩn trên Tiên Cương đại lục, liên quan Song Tử Đại Thiên Tôn","tinhCach":"Hồn nhiên nhưng ngang ngược; tinh nhanh, quan sát lực mạnh; chiến lực phi phàm dù hình dạng trẻ con;ọng tình nghĩa, sẵn sàng bảo vệ người thân","blurb":"Oa Oa là nữ đồng khoảng bảy tám tuổi mặc y phục lam trên Tiên Cương đại lục, tướng mạo xinh đẹp, có thể dừng giữa không trung và nhìn thấu thần thức xuyên hư vô. Cô bé có mối liên hệ với Song Tử Đại Thiên Tôn, sở hữu chiến lực vượt xa ngoại hình, từng đá một cước suýt phế tu vi Tham Lang. Về sau tái ngộ Vương Lâm tại Tử Dương Tông, tự nhận từng cứu hắn và khẳng định sẽ bảo vệ hắn trước các Đại Thiên Tôn.","tabs":{"diem":[{"text":"Dừng giữa không trung trên Tiên Cương, nhìn thấu thần thức Vương Lâm xuyên dòng xoáy hư vô","chuong":"@c1522"},{"text":"Đá một cước suýt phế tu vi Tham Lang, phá vây khốn dễ dàng","chuong":"@c1609"},{"text":"Nhận ra Vương Lâm qua khe nứt, cùng Hàm Hàm phong bế vết nứt và giấu Tham Lang","chuong":"@c1610"},{"text":"Xông vào Tử Dương Tông nhận ra Vương Lâm, gọi nam tử trung niên là Tiểu Cô Nhai","chuong":"@c1856"},{"text":"Tự nhận từng cứu Vương Lâm, rủ Hàm Hàm đánh các Đại Thiên Tôn","chuong":"@c1865"},{"text":"Tâm trạng sa sút tiễn Vương Lâm rời đi, cùng Hàm Hàm khẳng định sẽ bảo vệ hắn","chuong":"@c1867"}],"kinhLich":[{"mucCt":"vua","text":"Dừng giữa không trung trên Tiên Cương đại lục, hình như trông thấy thần thức Vương Lâm xuyên dòng xoáy hư vô. Truyền âm tới hắn, tự giới thiệu tên là Oa Oa và cho biết nơi đây là Tiên Cương đại lục.","anchor":"ta tên là Oa Oa, ngươi tên là gì?","bridge":true,"khoang":"@c1522"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Người mà thần thức xuyên hư vô tới Tiên Cương, Oa Oa truyền âm tự giới thiệu","ghiChu":"@c1522"}],"tuiDo":{}},"nguon":["@c1522"]},{"id":"chien-khong-liet","name":"Chiến Không Liệt","aliases":["Chiến lão quỷ"],"gioiTinh":"nam","tabs":{"kinhLich":[{"chuong":"@c1522","importance":"bridge","mucCt":"gon","text":"Được Vương Lâm nhắc trong chuỗi suy luận bí mật kinh thiên, liên quan lời nói năm đó ở Vân Hải tinh vực.","anchor":"Nội phủ trong chuyện này tồn tại một sợi dây, xỏ xuyên qua những người này"},{"chuong":"@c1559","importance":"bridge","mucCt":"vua","text":"Đứng cùng Tây Tử Phượng và Thân Công Hổ ở hướng tây, chuẩn bị tự bạo khi màn sáng sụp đổ.","anchor":"Bên cạnh nàng còn có chiến Không Liệt và Thân Công Hổ"},{"chuong":"@c1568","importance":"normal","mucCt":"vua","tieuDe":"Tiết lộ tiên duyên bí ẩn và huyền kiếp thứ tám","text":"Được tiết lộ là người duy nhất trong lịch sử động phủ dựa vào thân phận tu sĩ trong động phủ mà vượt tới huyền kiếp thứ tám. Năm đó đột kiếp thứ năm thất bại lẽ ra phải chết, nhưng nhận được một tiên duyên lớn lao khiến tu vi tăng mạnh, liên tục vượt tới kiếp thứ tám, chỉ còn một kiếp nữa là thành Tôn.","anchor":"Nhưng Chưởng Tôn không biết vì sao Chiến lão quỷ lại đạt được một tiên duyên lớn lao!"},{"chuong":"@c1571","importance":"normal","mucCt":"ky","tieuDe":"Vái lạy anh hồn, lực lượng bí ẩn trong thân ngăn cản","text":"Chiến Không Liệt trong Côn Hư tinh vực nhìn hồn ảnh bay qua, nhận ra đồng đạo cũ Lữ Tài, Lý Đông, Thường Dịch — những người năm xưa cùng hắn phát thề hủy diệt Phong Giới Đại Trận. Hắn cảm khái rằng mình đã trở thành kẻ dẫn động chiến tranh mà năm xưa oán hận. Hắn tiết lộ đã biết một bí mật kinh người trong tiên duyên. Khi hắn vái lạy, một luồng lực lượng bí ẩn từ bên trong cơ thể bộc phát ngăn cản, nhưng hắn cắn răng cưỡng ép hoàn thành vái lạy, tuyên bố lực lượng đó có thể giúp hắn nhưng không được ngăn hắn vái. Tu vi hắn được xác nhận có lẽ là cao nhất trong thế giới động phủ.","anchor":"Ta có thể giúp ngươi nhưng ngươi không thể ngăn ta vái lạy những hồn phách mà ta áy náy"}],"nhanMach":[{"ten":"Lữ Tài","tag":"ban-be","quanHe":"Đồng đạo cũ, cùng phát thề hủy diệt Phong Giới Đại Trận","ghiChu":"Đã tử trận, tàn hồn xuất hiện trong đám anh hồn"},{"ten":"Lý Đông","tag":"ban-be","quanHe":"Đồng đạo cũ","ghiChu":"Đã tử trận"},{"ten":"Thường Dịch","tag":"ban-be","quanHe":"Đồng đạo cũ","ghiChu":"Đã tử trận"}],"tuViMoc":[{"chuong":"@c1568","canhGioi":"Không Kiếp (tám lần huyền kiếp)","text":"Được tiết lộ đã vượt qua tám lần huyền kiếp, dừng trước kiếp thứ chín, là người duy nhất trong lịch sử động phủ đạt mức này. Đột kiếp thứ năm thất bại nhưng nhận tiên duyên lớn lao, tu vi tăng mạnh vượt liên tiếp tới kiếp tám.","importance":"major"}],"diem":[{"text":"Gặp Vương Lâm tại Lôi Trì, suy đoán hắn là tiền bối ẩn tu rồi cung kính bái kiến","chuong":"@c0733"},{"text":"Được Vương Lâm chỉ ra chiến ý Chiến gia thiếu niềm tin bất khuất, chấn động ngộ đạo","chuong":"@c0809"},{"text":"Tu vi đạt Tịnh Niết viên mãn, chỉ huy gần trăm tu sĩ kéo tu chân tinh chuẩn bị chiến tranh Ngoại Vực","chuong":"@c1388"},{"text":"Sẵn sàng tự bạo cùng Tây Tử Phượng và Thân Công Hổ khi màn sáng sụp đổ","chuong":"@c1559"},{"text":"Được tiết lộ là người duy nhất trong lịch sử động phủ vượt tám lần huyền kiếp bằng thân phận tu sĩ bên trong","chuong":"@c1568"},{"text":"Bị Vương Lâm suy luận chính là hồn thứ hai của Thất Thải Thiên Tôn, hồn chứa ý cảnh và bổn nguyên lực","chuong":"@c1600"}]},"nguon":["@c1522","@c1559","@c1568","@c1571","@c1573"],"trangThai":"song","canhGioiCaoNhat":"Không Kiếp (vượt tám lần huyền kiếp, dừng trước kiếp thứ chín)","cn":"战空烈","vaiTro":"Tu sĩ Chiến gia — hồn thứ hai Thất Thải Thiên Tôn, truy tùy trung thành của Vương Lâm","tinhCach":"thận trọng biết thời thế, suy đoán sắc bén trước cường giả; cung kính cầu đạo, sùng kính Vương Lâm sau khi chứng kiến uy lực; mang chiến ý bất khuất cố hữu của Chiến gia; trung thành kiên định, sẵn sàng tự bạo vì đại cục","blurb":"Chiến Không Liệt là tu sĩ Chiến gia xuất thân từ Lôi Tiên Giới, ban đầu ở cảnh Dương Thực viên mãn, về sau đạt tới Tịnh Niết viên mãn và vượt qua tám lần huyền kiếp — là người duy nhất trong lịch sử động phủ dựa vào thân phận tu sĩ bên trong mà đạt tới mốc này. Hắn gặp Vương Lâm tại Lôi Trì, từ nghi ngờ chuyển sang cung kính bái kiến, được Vương Lâm chỉ điểm về niềm tin bất khuất của chiến ý Chiến gia, rồi theo Vương Lâm suốt hành trình từ tranh đoạt phong hào đến chiến tranh Ngoại Vực. Về sau bị Vương Lâm suy luận chính là hồn thứ hai của Thất Thải Thiên Tôn — hồn chứa ý cảnh và bổn nguyên lự"},{"id":"nam-tu-ao-xanh","name":"Nam tử áo xanh","gioiTinh":"nam","trangThai":"tu-vong","tabs":{"kinhLich":[{"chuong":"@c1523","importance":"bridge","mucCt":"vua","text":"Chấn động không tin Vương Lâm còn sống, hai chân run rẩy đạo tâm bất ổn trước chính khí đại nho, nhớ lại thuở còn là nho sinh gặp tiên sinh.","anchor":"Hắn trước khi tu đạo đã từng là một nho sinh"},{"chuong":"@c1524","importance":"bridge","mucCt":"gon","text":"Lui về sau không cản trở Vương Lâm mở Không Môn, sắc mặt trắng bệch da đầu tê dại trước lôi đình tràn ngập.","anchor":"Tu vi của hắn mặc dù đã đạt tới Không Huyền Sơ Kỳ"},{"mucCt":"vua","text":"Hoảng sợ lui về sau khi thấy Vương Lâm phá liên tiếp Không Môn. Nhận ra Vương Lâm minh ngộ nhân quả, sinh tử, chân giả — những bổn nguyên hư ảo cực khó tu, kêu người này không thể trêu chọc được.","anchor":"Nhân quả, sinh tử, chân giả! Không ngờ hắn có thể minh ngộ được những bổn nguyên đại đạo này","bridge":true,"khoang":"@c1526"},{"mucCt":"vua","text":"Thấy Hư Thần Thiên Tôn ra tay liền cắn răng lao tới cùng hàn băng, nhưng bị một chỉ đạo niệm kiềm chế không thể tiến. Bị Định Thân Thuật trói lại rồi bị Vương Lâm thi triển Nhân Quả Ấn rút ra bổn nguyên dưới dạng sương mù hư ảo.","anchor":"Thứ được rút ra này, không ngờ chính là bổn nguyên của nam tử áo xanh kia","bridge":true,"khoang":"@c1527"},{"mucCt":"vua","text":"Bị Vương Lâm thi triển Nhân Quả Ấn rút hơn phân nửa bổn nguyên, phun máu lùi mấy ngàn trượng, gào thầm không phục rồi bỏ chạy. Sau đó dừng chân, quay trở lại chiến trường nhìn Vương Lâm bị Hư Thần Thiên Tôn vây khốn.","anchor":"Lão phu có tu vi Không Huyền, lão phu không phục!","bridge":true,"khoang":"@c1528"},{"importance":"normal","mucCt":"ky","chuong":"@c1529","tieuDe":"Tử vong dưới mũi tên Cung Lý Quảng","text":"Bị mũi tên Cung Lý Quảng bức từ khe không gian hiện thân. Dùng bổn nguyên lực, mở hương hỏa giới, lấy toàn bộ hồn phách hương hỏa dung nhập máu tươi hóa tầng băng tự vệ, đồng thời phá vỡ tộc ấn để chống lại. Vẫn bị mũi tên xuyên qua, thân thể tan nát, nguyên thần tử vong. Trở thành tu sĩ Không Huyền đầu tiên chết trong cuộc chiến này.","anchor":"Đây là tu sĩ Không Huyền đầu tiên tử vong trong cuộc chỉến này"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Bị Vương Lâm dùng Nhân Quả Ấn rút bổn nguyên","ghiChu":"Bỏ chạy rồi quay lại chiến trường"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Dùng ba mảnh ngọc giản màu xanh hấp thu lôi quang phòng hộ trong lôi trì, bị Lôi Linh đánh vỡ pháp bảo buộc phải rời đi","chuong":"@c0818"},{"text":"Chấn động không tin Vương Lâm còn sống, hai chân run rẩy đạo tâm bất ổn trước chính khí đại nho","chuong":"@c1523"},{"text":"Cắn răng lao tới khi thấy Hư Thần Thiên Tôn ra tay, nhưng bị một chỉ đạo niệm kiềm chế","chuong":"@c1527"},{"text":"Bị Vương Lâm thi triển Nhân Quả Ấn rút hơn phân nửa bổn nguyên, phun máu lùi mấy ngàn trượng","chuong":"@c1528"},{"text":"Tử vong dưới mũi tên Cung Lý Quảng, bị bức hiện thân từ khe không gian","chuong":"@c1529"}]},"nguon":["@c1523","@c1524","@c1526","@c1527","@c1528","@c1529"],"canhGioiCaoNhat":"Không Huyền Sơ Kỳ","vaiTro":"Tu sĩ dự thí lôi trì — biểu ca của Tây Tử Phượng","tinhCach":"thận trọng phòng hộ khi lâm nguy; đạo tâm bất ổn dễ bị chấn động trước cường giả; liều mạng lao tới khi đồng bạn gặp nạn","blurb":"Biểu ca của Tây Tử Phượng, từng dự thí trong lôi trì bằng ba mảnh ngọc giản màu xanh hấp thu lôi quang để phòng hộ. Về sau hắn đối đầu Vương Lâm, bị Nhân Quả Ấn rút hơn phân nửa bổn nguyên, cuối cùng tử vong dưới mũi tên Cung Lý Quảng."},{"id":"lo-van-tu","name":"Lô Vân Tử","gioiTinh":"nam","trangThai":"khong-ro","blurb":"Nhân vật bí ẩn chỉ một ngón tay khiến vòng xoáy tinh không chuyển động, dẫn ra đồng thời Không Môn thứ ba đến thứ năm cho Vương Lâm phá.","vaiTro":"Người dẫn động vòng xoáy tinh không, hỗ trợ Vương Lâm phá Không Môn","tinhCach":"Bí ẩn; chỉ ra tay nhẹ nhàng một ngón tay mà tác động cực lớn","tabs":{"diem":[{"text":"Chỉ một ngón tay khiến vòng xoáy tinh không dẫn ra đồng thời ba Không Môn, hỗ trợ Vương Lâm đột phá liên tiếp.","chuong":"@c1526"}],"kinhLich":[{"chuong":"@c1526","importance":"normal","mucCt":"gon","tieuDe":"Dẫn ra ba Không Môn cho Vương Lâm","text":"Chỉ một ngón tay khiến vòng xoáy tinh không chuyển động, dẫn ra đồng thời Không Môn thứ ba, thứ tư, thứ năm.","anchor":"theo một chỉ của Lô Vân Tử"}]},"nguon":["@c1526"]},{"id":"thien-van-tu","name":"Thiên Vận Tử","gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1531","importance":"normal","mucCt":"vua","tieuDe":"Tái xuất tại Triệu Hà và tuyên bố đại kế bắt đầu","text":"Tái hiện ở Triệu Hà tinh vực dưới hình tượng lão già áo trắng tóc trắng mi tâm có huyết điểm, ngồi trên đá vụn mở mắt tính toán. Xác nhận Vương Lâm đã đạt bước thứ ba, tuyên bố đại kế sắp đặt mấy vạn năm đã bắt đầu và gọi Vương Lâm là đồ nhi.","anchor":"Hắn chính là kẻ đã mất tích nhiều năm, Thiên Vận Tử"},{"chuong":"@c1540","importance":"normal","mucCt":"vua","tieuDe":"Vận mệnh biến mất khỏi hệ thống động phủ","text":"Vương Lâm cố tìm vận mệnh Thiên Vận Tử đã mất tích nhưng không thấy dấu hiệu nào, vận mệnh giống như đã biến mất.","anchor":"Thậm chí hắn từng cố gắng tìm kiếm Thiên Vận Tử đã mất tích nhưng cuối cùng vận mệnh của ba người này giống như đã biến mất"},{"chuong":"@c1541","importance":"bridge","mucCt":"vua","text":"Được Vương Lâm suy ngẫm: dù đã đạt Không Linh trung kỳ vẫn kiêng kỵ Thiên Vận Tử, cho rằng bí mật của người này rất nhiều, ẩn giấu rất sâu.","anchor":"bí mật của người này rất nhiều, ẩn dấu rất sâu, khiến cho người ta sợ hãi"},{"mucCt":"vua","text":"Thiên Vận Tử ẩn trong đám thiên thạch lơ lửng bên trong Triệu Hà tinh vực, Vương Lâm quét thần thức cũng không phát hiện. Hắn tự nhận là người thứ nhất trừ hai kẻ kia thức tỉnh trí nhớ, xác nhận có ít nhất ba cá thể đã thức tỉnh. Dù bản chất thế nào, hắn thừa nhận mình từng là tu sĩ giới nội, than nhẹ rồi vung tay áo ôm quyền hướng tinh không vái lạy.","anchor":"Ta hẳn là người thứ nhất trừ hai kẻ kia thức tỉnh trí nhớ","bridge":true,"khoang":"@c1571"}],"nhanMach":[],"tuViMoc":[],"diem":[{"text":"Lần đầu xuất hiện cưỡi tảng đá khổng lồ như sao băng ngang Chu Tước tinh, cứu Vương Lâm khỏi lạc vào cảm ngộ thiên đạo luân hồi, thể hiện tu vi vượt Hóa Thần","chuong":"@c0241"},{"text":"Nhận Vương Lâm làm đệ tử chân chính trong đại thọ vạn năm, mở tâm thần thành thế giới bảy màu chứa 3600 phân thân cho Vương Lâm tự chọn cấm pháp thần thông","chuong":"@c0474"},{"text":"Chủ động hiến phân hồn để đoạt cấm chế bổn nguyên của Vương Lâm, tiết lộ Luân Hồi Toàn Thể Thuật — âm mưu hai ngàn năm bố cục nhằm chiếm cứ thân xác đệ tử","chuong":"@c1624"},{"text":"Bị phơi bày chân tướng: không phải tam hồn thất phách Thất Thải Tiên Tôn mà là thực thể nguyên thủy đã nuốt phách Thất Thải, bổn tôn là nửa nghịch la bàn — một bộ phận của Thiên Đạo","chuong":"@c1628"},{"text":"Hoàn thành thức tỉnh thứ chín mươi chín, thi triển Luân Hồi nhất thể thuật chiếm cứ phân thân Vương Lâm, nhưng bị Vương Lâm đoạt nửa la bàn bổn tôn và đánh bại","chuong":"@c1629"},{"text":"Bị vạch trần là khí linh La Bàn Định Giới, phản kháng lần cuối dưới dạng hạc đen rồi bị Vương Lâm bóp nát tiêu diệt hoàn toàn","chuong":"@c1975"}]},"nguon":["@c1531","@c1540","@c1541","@c1571"],"cn":"天运子","vaiTro":"Chưởng môn Thiên Vận Tông — bộ phận Thiên Đạo, bổn tôn là nửa nghịch la bàn / khí linh La Bàn Định Giới","tinhCach":"Giỏi tính toán thiên cơ và bố cục dài hạn qua hàng ngàn năm; điềm tĩnh uy nghi khi chủ trì tông môn, giảng đạo; tự tin quyết liệt trước cường địch; che giấu dã tâm thôn phệ dưới thân phận sư tôn","blurb":"Thiên Vận Tử là chưởng môn Thiên Vận Tông, thành viên Liên Minh Trưởng Lão Đoàn, từng nhận Vương Lâm làm đệ tử chân chính nhưng âm thầm bố cục qua lạc ấn, phân hồn và Luân Hồi Toàn Thể Thuật suốt hai ngàn năm. Chân tướng về sau phơi bày: hắn không phải tàn hồn Thất Thải Tiên Tôn mà là thực thể nguyên thủy đã nuốt phách Thất Thải — bổn tôn là nửa nghịch la bàn, một bộ phận của Thiên Đạo, đồng thời là khí linh La Bàn Định Giới. Sau lần thức tỉnh thứ chín mươi chín và ý đồ chiếm cứ phân thân Vương Lâm, hắn bị Vương Lâm đoạt bổn tôn rồi tiêu diệt hoàn toàn."},{"id":"truong-ho","name":"Trương Hổ","cn":"张虎","aliases":["Trương Hố"],"gioiTinh":"nam","trangThai":"khong-ro","tabs":{"kinhLich":[{"chuong":"@c1533","importance":"bridge","mucCt":"gon","text":"Bị Huyễn Chân Kiếp hóa thành thân ảnh trong đám người quen thuộc của Vương Lâm.","anchor":"có Vương Trác, có Trương Hố, có Liễu Mi"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Ký danh đệ tử áo xám tại Hằng Nhạc Phái, đói hai ngày, được Vương Lâm chia thức ăn và trở thành bạn cùng phòng","chuong":"@c0010"},{"text":"Làm lao dịch đốn củi ba năm, hằng ngày để lại khoai lang cho Vương Lâm dù bản thân kiệt sức","chuong":"@c0011"},{"text":"Giết Lưu sư huynh rồi đột ngột biến mất khỏi Hằng Nhạc Phái, vụ án bỏ ngỏ","chuong":"@c0026"},{"text":"Tái xuất sau mười năm với danh Đại đương gia, Ngưng Khí tầng 2 đỉnh phong, dẫn đầu nhóm hắc y nhưng bị Bạch Triển dùng độc tiêu khống chế","chuong":"@c0066"},{"text":"Sau khi Bạch Triển chết, nhổ độc tiêu thoát khỏi khống chế và cùng Vương Lâm vào Đằng Gia thành","chuong":"@c0069"},{"text":"Được xác nhận đã qua đời từ lâu; gia phả hậu nhân bốn trăm năm sau vẫn ghi hắn là tổ tiên từng bái nhập Hằng Nhạc","chuong":"@c0846"}]},"nguon":["@c1533"],"vaiTro":"Bạn cũ của Vương Lâm — Đại đương gia nhóm cướp, ký danh đệ tử Hằng Nhạc Phái","tinhCach":"Nghĩa khí, sẵn sàng sẻ chia đồ ăn với đồng môn khi đói khổ; bộc trực, hành động quyết liệt dám giết người rồi bỏ phái; trọng tình cố nhân, giữ lập trường ngay cả khi bị khống chế bằng độc","blurb":"Trương Hổ là bạn cùng phòng đầu tiên của Vương Lâm khi cả hai còn là ký danh đệ tử lao dịch gầy yếu tại Hằng Nhạc Phái; hai người chia nhau khoai lang qua ngày đói. Sau khi giết Lưu sư huynh và biến mất khỏi phái, hắn tái xuất mười năm sau với danh Đại đương gia, đạt Ngưng Khí kỳ tầng 2 đỉnh phong nhưng bị sư phụ tà đạo Bạch Triển dùng độc khống chế; được giải thoát sau khi Bạch Triển chết, hắn cùng Vương Lâm vào Đằng Gia thành. Hậu nhân bốn trăm năm sau xác nhận Trương Hổ đã qua đời từ lâu, gia phả vẫn ghi hắn là tổ tiên từng bái nhập Hằng Nhạc."},{"id":"thac-sam","name":"Thác Sâm","cn":"托森","gioiTinh":"nam","trangThai":"khong-ro","tabs":{"kinhLich":[{"chuong":"@c1533","importance":"bridge","mucCt":"vua","text":"Được Chân Giả Đạo biến thành hình ảnh cuồng ngạo quát mắng bầu trời, góp vào phản kích Huyễn Chân Kiếp.","anchor":"còn có Thác Sâm cuồng ngạo đến cực điểm, tức giận quát mắng bầu trời"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Lộ diện là kẻ đứng đầu huyết hải bị phong ấn mấy vạn năm trong Cổ Thần Chi Địa, thực chất là ma vật do oán niệm Cổ Thần Đồ Ti ngưng tụ","chuong":"@c0163"},{"text":"Trao bảo vật cho Vương Lâm nhờ phá phong ấn, thừa kế lực lượng truyền thừa bát tinh Cổ Thần Đồ Ti","chuong":"@c0430"},{"text":"Phá phong ấn, hóa huyết hải thành huyết long vạn trượng xông vào hư vô, thi triển tuế nguyệt quy tắc tàn sát hàng loạt tu sĩ","chuong":"@c1060"},{"text":"Thức tỉnh sau trăm năm, phá trận pháp bay khỏi Chu Tước Tinh, quét ngang Liên Minh tinh vực truy tìm Vương Lâm","chuong":"@c1147"},{"text":"Trong trận chiến định mệnh tại cổ mộ, lần đầu bỏ xưng bổn thần, quỳ gối nhận truyền thừa Đồ Ti từ Vương Lâm và nói hai chữ đa tạ","chuong":"@c1386"},{"text":"Hóa thành đứa trẻ ngủ say trên tu chân tinh ở giới ngoại tinh hải, đang dung hợp ký ức Đồ Ti tu luyện thần thông","chuong":"@c1969"}]},"nguon":["@c1533"],"vaiTro":"Phản diện trọng yếu — Cổ Ma Đồ Ti, ma vật chủ huyết hải bị phong ấn trong Cổ Thần Chi Địa","tinhCach":"Xảo trá, dùng bảo vật làm mồi nhử dụ dỗ Vương Lâm phá phong ấn; tàn nhẫn, khinh miệt chúng sinh như kiến và tàn sát hàng loạt tu sĩ không chớp mắt; cuồng ngạo đỉnh thiên, coi mọi thế lực đều không đáng kể; chấp niệm sâu nặng, liên tục khắc tên Vương Lâm và thề truy sát","blurb":"Thác Sâm là nam tử tóc đỏ như máu, kẻ đứng đầu huyết hải, thực chất là ma vật do oán niệm của Cổ Thần Đồ Ti chết ngưng tụ — tức Cổ Ma Đồ Ti — bị phong ấn mấy vạn năm trên thạch chùy giữa Cổ Thần Chi Địa. Hắn dùng bảo vật dụ dỗ Vương Lâm phá phong ấn, thừa kế lực lượng truyền thừa bát tinh Cổ Thần Đồ Ti, triệu hoán Diệt Thần Mâu và thi triển tuế nguyệt quy tắc tàn sát hàng loạt tu sĩ, phá phong ấn bay khỏi Chu Tước Tinh quét ngang Liên Minh tinh vực, truy tìm Vương Lâm xuyên suốt nhiều tinh vực. Cuối cùng trong cổ mộ, sau trận chiến định mệnh với Vương Lâm, Thác Sâm lần đầu bỏ xưng bổn thần, qu"},{"id":"su-gia-thien-kiep","name":"Sứ giả thiên kiếp","aliases":["thân ảnh mơ hồ trong tế đàn"],"gioiTinh":"khong-ro","trangThai":"tu-vong","vaiTro":"Sứ giả được thiên kiếp phái ra từ tế đàn, từng khiến Vương Lâm chật vật khi vấn đỉnh năm xưa","tinhCach":"Không lộ tính cách, chỉ là thực thể chiến đấu của thiên kiếp","blurb":"Thân ảnh mơ hồ trong tế đàn thiên kiếp, từng là đối thủ đáng gờm khi Vương Lâm vấn đỉnh năm xưa. Lần tái xuất này bị Sinh Tử Ấn đánh tan chỉ bằng một đòn.","theLuc":[],"tabs":{"diem":[{"text":"Từng khiến Vương Lâm chật vật thời vấn đỉnh, nay không chịu nổi một đòn Sinh Tử Ấn, cho thấy bước tiến vượt bậc của Vương Lâm","chuong":"@c1533"}],"kinhLich":[{"mucCt":"vua","text":"Từ tế đàn sụp đổ lao ra đánh Vương Lâm bằng một chưởng màu vàng. Bị Vương Lâm dùng sinh khí đối chưởng rồi đặt tử khí vào ngực, sinh tử giao hòa thành đại ấn khiến thân thể tan vỡ.","anchor":"Sứ giả của thiên kiếp khiến cho Vương Lâm phải chật vật năm đó","bridge":true,"khoang":"@c1533"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối tượng giáng kiếp nạn, bị Vương Lâm đánh tan"}],"tuiDo":{}},"nguon":["@c1533"]},{"id":"tan-linh-thuong-nhan","name":"Tán Linh thượng nhân","gioiTinh":"nam","trangThai":"khong-ro","vaiTro":"Thủ lĩnh Tán Linh Tông — cường giả bí ẩn phản kháng sấm sét bất diệt trong bảy trăm vạn thiên địa","tinhCach":"Hiền lành bề ngoài nhưng tự tin cao độ; bình thản, quan sát sắc bén trước cường giả; kiên định phản kháng, sẵn sàng hy sinh vì tộc nhân","blurb":"Thanh niên đầu trọc láng bóng, vẻ mặt hiền lành, tồn tại hơn vạn năm trong bảy trăm vạn thiên địa, tu vi đạt tới Thiên Nhân Tứ Suy — điều gần như bất khả trong thế giới bị phong tỏa bởi sấm sét bất diệt. Sau khi phá phong hộ tu chân tinh lần đầu nhìn thấy tinh không và phát hiện chân tướng thế giới, y lập Tán Linh Tông chiêu mộ tộc nhân phản kháng, mở Tuyệt Thiên trận đối đầu sấm sét bất diệt, dẫn tộc nhân thoát khỏi thiên địa đang sụp đổ vào Thái Cổ Tinh Thần và thề trung thành với Vương Lâm. Về sau gặp lại Vương Lâm ở giới ngoại.","theLuc":[],"tabs":{"diem":[{"text":"Hiện thân sau khi Vương Lâm rời đi, xin mang thi thể tu sĩ Âm Hư, bộc lộ thân phận dị thường","chuong":"@c1264"},{"text":"Bị Vương Lâm phát hiện và phóng tia chớp hồng sắc xuyên mi tâm kích bản thể, lộ diện xưng danh Tán Linh, tiết lộ chân tướng bảy trăm vạn thiên địa","chuong":"@c1267"},{"text":"Tu vi đạt Thiên Nhân Tứ Suy sau vài ngàn năm điên cuồng tu luyện, lập Tán Linh Tông chiêu mộ tộc nhân phản kháng sấm sét bất diệt","chuong":"@c1268"},{"text":"Mở Tuyệt Thiên trận, dùng thân thể tộc nhân bị phong ấn làm mảng lưới ánh sáng chịu sấm sét bất diệt, trọng thương phun máu","chuong":"@c1271"},{"text":"Dẫn tộc nhân thoát khỏi bảy trăm vạn thiên địa đang sụp đổ vào Thái Cổ Tinh Thần, tuyên thệ trung thành với Vương Lâm","chuong":"@c1273"},{"text":"Gặp lại Vương Lâm cùng bằng hữu ở giới ngoại","chuong":"@c1966"}],"kinhLich":[{"chuong":"@c1533","importance":"bridge","mucCt":"gon","text":"Được Chân Giả Đạo của Vương Lâm hóa thành thân ảnh, mắt cháy vẻ điên cuồng sau khi nhận ra tận cùng của trời, góp vào phản kích thiên kiếp.","anchor":"Còn có Tán Linh thượng nhân, sau khi hắn nhận ra được tận cùng của trời"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{}},"nguon":["@c1533"]},{"id":"co-than-bat-tinh-thien-kiep","name":"Cổ Thần bát tinh mất thần trí trong thiên kiếp","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[],"canhGioiCaoNhat":"Cổ Thần bát tinh","trangThai":"khong-ro","blurb":"Cổ Thần đầu tiên bước ra từ cái khe thiên kiếp, có tám tinh điểm trên mi tâm nhưng tinh điểm ảm đạm như bị phong ấn, hai mắt trống rỗng không còn thần trí, là kẻ đầu tiên áp sát Vương Lâm.","vaiTro":"Cổ Tộc bát tinh bị thiên kiếp khống chế, vây công Vương Lâm","tinhCach":"Không còn thần trí, hành động như bị khống chế","tabs":{"diem":[{"text":"Tám tinh điểm trên mi tâm ảm đạm như bị phong ấn, hai mắt trống rỗng không có thần trí.","chuong":"@c1535"}],"kinhLich":[{"chuong":"@c1535","importance":"normal","mucCt":"vua","tieuDe":"Xuất hiện từ thiên kiếp áp sát Vương Lâm","text":"Từ cái khe thiên kiếp bước ra, có tám tinh điểm trên mi tâm xoay tròn nhưng ảm đạm, hai mắt trống rỗng, là Cổ Thần đầu tiên áp sát bên cạnh Vương Lâm đang nhắm mắt.","anchor":"Trên mi tâm của Cổ Thần này có tám tinh điểm nhanh chóng xoay tròn"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối tượng vây công trong thiên kiếp","ghiChu":""}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1535"]},{"id":"ba-co-than-bat-tinh-thien-kiep","name":"Ba Cổ Thần bát tinh còn lại trong thiên kiếp","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[],"canhGioiCaoNhat":"Cổ Thần bát tinh","trangThai":"khong-ro","blurb":"Ba Cổ Thần thân thể ngàn trượng, da thô ráp nhiều vết sẹo, dữ tợn lao tới Vương Lâm cùng lúc xuất hiện từ cái khe thiên kiếp.","vaiTro":"Cổ Tộc bát tinh bị thiên kiếp triệu ra vây công Vương Lâm","tinhCach":"Dữ tợn, không còn thần trí","tabs":{"diem":[{"text":"Thân thể ngàn trượng, da thô ráp nhiều vết sẹo, từ cái khe thiên kiếp đồng loạt bước ra.","chuong":"@c1535"}],"kinhLich":[{"chuong":"@c1535","importance":"normal","mucCt":"vua","tieuDe":"Xuất hiện từ thiên kiếp lao về phía Vương Lâm","text":"Sau Cổ Thần đầu tiên, ba Cổ Thần thân thể ngàn trượng, da thô ráp nhiều vết sẹo đồng thời bước ra từ cái khe và dữ tợn lao tới Vương Lâm.","anchor":"ba Cổ Thần khác thân thể tới ngàn trượng đồng thời bước ra"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối tượng vây công trong thiên kiếp","ghiChu":""}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1535"]},{"id":"bon-co-ma-bat-tinh-thien-kiep","name":"Bốn Cổ Ma bát tinh trong thiên kiếp","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[{"ten":"Cổ Ma","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Bát tinh Cổ Ma","trangThai":"tu-vong","blurb":"Bốn Cổ Ma hóa ra từ ma khí đen như mực trong cái khe thiên kiếp, tám ma tinh, tàn nhẫn khát máu, cười nanh ác lao về phía Vương Lâm.","vaiTro":"Cổ Tộc bát tinh bị thiên kiếp triệu ra vây công Vương Lâm","tinhCach":"Tàn nhẫn, khát máu, cười nanh ác","tabs":{"diem":[{"text":"Hóa từ ma khí đen như mực, tám ma tinh, tàn nhẫn khát máu.","chuong":"@c1535"},{"text":"Ma khí nồng đậm, dùng chiến phủ và thần thông Cổ Ma tấn công.","chuong":"@c1536"}],"kinhLich":[{"chuong":"@c1535","importance":"normal","mucCt":"vua","tieuDe":"Xuất hiện từ thiên kiếp vây Vương Lâm","text":"Ma khí đen như mực từ cái khe tràn ra hóa thành bốn Cổ Ma tám ma tinh, cười nanh ác theo sau Cổ Thần phóng tới vây Vương Lâm.","anchor":"Ma khí này đen như mực, tràn ra liền hóa thành bốn Cổ Ma"},{"mucCt":"vua","text":"Lao tới bằng ma khí ngập trời, dùng thần thông và pháp khí Cổ Ma tấn công Vương Lâm. Bị hắn lần lượt đánh nát, ma khí nồng đậm bị rút ra và hấp thu vào mắt trái.","anchor":"Bọn chúng nhằm về phía Vương Lâm, ma khí ngập trời","bridge":true,"khoang":"@c1536"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối tượng vây công trong thiên kiếp","ghiChu":""}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1535","@c1536"]},{"id":"bat-tinh-co-than-vet-seo-nguc","name":"Bát tinh Cổ Thần có vết sẹo ngực","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Cổ Thần tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Bát tinh Cổ Thần","trangThai":"tu-vong","blurb":"Bát tinh Cổ Thần mang vết sẹo khổng lồ trên ngực, phía sau hiện hư ảnh Cổ Thần cửu tinh mặc giáp. Bị xóa trí nhớ thành con rối trong thiên kiếp, cuối cùng được Vương Lâm dùng Dịch Linh Ấn giải thoát.","vaiTro":"Cổ Thần bị xóa trí nhớ trong thiên kiếp, bị Vương Lâm giải thoát","tinhCach":"Mất trí nhớ, chỉ còn bản năng chiến đấu","tabs":{"diem":[{"text":"Phía sau hiện hư ảnh Cổ Thần cửu tinh mặc giáp có chín tinh điểm, mang khí tức sát lục.","chuong":"@c1536"}],"kinhLich":[{"mucCt":"vua","text":"Lao tới tấn công Vương Lâm bằng một quyền toàn lực, sau lưng hiện hư ảnh Cổ Thần cửu tinh. Bị Vương Lâm gạt quyền rồi vỗ lui vạn trượng, sau cùng bị Dịch Linh Ấn đánh tan cùng ba Cổ Thần khác, khuôn mặt trước chết lộ vẻ được giải thoát.","anchor":"Trên ngực cổ Thần này có một vết sẹo khổng lồ","bridge":true,"khoang":"@c1536"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Đồng tộc Cổ Thần, bị Vương Lâm giải thoát khỏi kiếp con rối","ghiChu":"@c1536"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1536"]},{"id":"ba-bat-tinh-co-than-con-lai","name":"Ba bát tinh Cổ Thần còn lại","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Cổ Thần tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Bát tinh Cổ Thần","trangThai":"tu-vong","blurb":"Ba bát tinh Cổ Thần bị xóa trí nhớ trong thiên kiếp, vây công Vương Lâm từ ba hướng nhưng bị áp chế bởi thất tinh vương tộc, cuối cùng được Dịch Linh Ấn giải thoát.","vaiTro":"Cổ Thần bị biến thành con rối trong thiên kiếp","tinhCach":"Mất trí nhớ, chỉ còn bản năng chiến đấu","tabs":{"diem":[{"text":"Bị xóa trí nhớ thành con rối trong thiên kiếp, trước khi chết lộ vẻ được giải thoát.","chuong":"@c1536"}],"kinhLich":[{"mucCt":"vua","text":"Từ ba hướng lao tới vây công Vương Lâm, bị hắn dùng thất tinh vương tộc Cổ Thần áp chế và đánh lui. Cuối cùng bị Dịch Linh Ấn diệt, khuôn mặt trước chết lộ vẻ được giải thoát.","anchor":"Trong lúc này, ba cổ Thần khác từ ba hướng lao thẳng tới Vương Lâm","bridge":true,"khoang":"@c1536"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Đồng tộc Cổ Thần, bị Vương Lâm giải thoát","ghiChu":"@c1536"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1536"]},{"id":"co-than-cuu-tinh-hu-anh","name":"Cổ Thần cửu tinh hư ảo mặc áo giáp","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Cổ Thần tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Cửu tinh Cổ Thần","trangThai":"khong-ro","blurb":"Hư ảnh Cổ Thần mặc áo giáp xuất hiện phía sau bát tinh Cổ Thần có vết sẹo, mang chín tinh điểm trên mi tâm và khí tức sát lục. Tượng trưng cho truyền thừa hoặc thuần phục, chưa rõ thân phận thật.","vaiTro":"Hư ảnh bí ẩn phía sau bát tinh Cổ Thần trong thiên kiếp","tinhCach":"Chưa rõ","tabs":{"diem":[{"text":"Hư ảnh có chín tinh điểm và khí tức sát lục, là dấu hiệu truyền thừa hoặc thuần phục một Cổ Thần cửu tinh.","chuong":"@c1536"}],"kinhLich":[{"mucCt":"vua","text":"Hiện ra dưới dạng hư ảnh phía sau bát tinh Cổ Thần có vết sẹo ngực, mang khí tức sát lục và chín tinh điểm trên mi tâm. Vương Lâm nhận ra đây là dấu hiệu truyền thừa hoặc thuần phục.","anchor":"Trên mi tâm của hư ảnh không ngờ lại có tới. Chín tinh điểm!","bridge":true,"khoang":"@c1536"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1536"]},{"id":"bon-co-yeu-thien-kiep","name":"Bốn Cổ Yêu trong thiên kiếp","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[{"ten":"Cổ Yêu","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Bát tinh Cổ Yêu","trangThai":"tu-vong","blurb":"Bốn Cổ Yêu trong thiên kiếp, áp sát Vương Lâm sau khi Cổ Ma bị diệt. Bị Dịch Linh Ấn đánh tan, yêu khí bị hút vào mắt trái Vương Lâm.","vaiTro":"Đối thủ trong thiên kiếp","tinhCach":"Bản năng chiến đấu","tabs":{"diem":[{"text":"Bị Dịch Linh Ấn xuyên thấu, tan thành mây khói.","chuong":"@c1536"}],"kinhLich":[{"chuong":"@c1536","importance":"normal","mucCt":"vua","tieuDe":"Áp sát Vương Lâm và bị Dịch Linh Ấn diệt","text":"Áp sát Vương Lâm sau khi Cổ Ma bị diệt, nhưng khi hắn mở mắt thi triển Dịch Linh Ấn thì cả bốn bị chưởng ấn xuyên thấu, tan thành mây khói, yêu khí bị hút vào mắt trái.","anchor":"bốn cổ Yêu thân thể đồng thời run rẩy"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Bị Vương Lâm diệt trong thiên kiếp","ghiChu":"@c1536"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1536"]},{"id":"thanh-nien-toc-bac-ao-trang-vien-co","name":"Thanh niên tóc bạc áo trắng giống hệt Vương Lâm","cn":"","aliases":["Thanh niên tóc bạc trong Bổn Ngã kiếp","Thanh niên tóc bạc","bản ngã kiếp của Vương Lâm"],"gioiTinh":"nam","trangThai":"tu-vong","blurb":"Thanh niên xuất hiện trong thế giới bên trong khe thiên kiếp, đứng trên pho tượng Cổ Yêu. Hình dáng, thần sắc và khí tức đều giống Vương Lâm đến mức không thể phân biệt, thân phận chưa rõ.","vaiTro":"Nhân vật bí ẩn giống hệt Vương Lâm trong Viễn Cổ Tiên Vực","tinhCach":"Chưa rõ","tabs":{"diem":[{"text":"Giống Vương Lâm về hình dáng, thần sắc và khí tức đến mức không thể phân biệt.","chuong":"@c1536"}],"kinhLich":[{"mucCt":"vua","text":"Xuất hiện trên pho tượng Cổ Yêu trong thế giới bên trong khe thiên kiếp, hình dáng, thần sắc và khí tức đều giống Vương Lâm như đúc. Vương Lâm chất vấn đối phương là ai.","anchor":"người này dù là hình dáng, thần sắc, khí tức, hết thảy đều giống hắn như đúc","bridge":true,"khoang":"@c1536"},{"chuong":"@c1537","importance":"normal","mucCt":"ky","tieuDe":"Chặn Vương Lâm tại Bổn Ngã kiếp","text":"Tự xưng là chính Vương Lâm, chặn đường hắn vào đại lục và gọi đây là Bổn Ngã kiếp. Tuyên bố muốn biết thiên kiếp và bổn nguyên thiên kiếp thì phải đánh bại hắn. Giao thủ bổn nguyên ngang bằng Vương Lâm, cả hai cùng phun máu. Chủ động thi triển Sinh Tử Ấn, Chân Giả Đạo và Định thần thuật giống hệt Vương Lâm, mọi đối kháng đều ngang nhau. Lùi về dẫm lên pho tượng cổ Yêu khiến tượng nứt vỡ sụp đổ.","anchor":"Thần thông của ngươi chính là thần thông của ta! Ta chính là ngươi!"},{"importance":"normal","mucCt":"ky","chuong":"@c1538","tieuDe":"Bị Vương Lâm tiêu diệt","text":"Giao chiến với Vương Lâm bằng hơn mười loại thần thông hoàn toàn giống nhau, dùng thân thể Cổ Thần, tu vi Không Linh trung kỳ và pháp bảo y hệt, tự tin tuyên bố Vương Lâm không thể giết mình. Bị Vương Lâm dùng Đạo lừa gạt qua mặt khi nhắm mắt theo Chân Giả Đạo, lần đầu có động tác khác Vương Lâm và không kịp né. Bị Nhân Quả Ấn rút bổn nguyên và Sinh Tử Ấn đánh vào mi tâm, trọng thương phun máu, lần đầu sinh ra sợ hãi. Nhận ra thủ đoạn Vương Lâm dùng chính là Đạo lừa gạt của Lưu Kim Bưu. Cố lùi về tấm màn ngăn nhưng bị liên lụy khi Vương Lâm tự đánh nát đùi phải, chịu thương thế giống hệt và chậm lại, cuối cùng thân thể tứ phân ngũ liệt tan nát.","anchor":"Vô dụng. Ta chính là ngươi, ngươi không giết nổi ta"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Giống hệt Vương Lâm, thân phận chưa rõ","ghiChu":"@c1536"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Tự xưng là chính Vương Lâm, đối thủ trong Bổn Ngã kiếp","ghiChu":"Có toàn bộ thần thông và bổn nguyên giống Vương Lâm"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1536","@c1537","@c1538"],"canhGioiCaoNhat":"Không Linh trung kỳ"},{"id":"nam-tu-bay-mau","name":"Nam tử trung niên bảy màu","cn":"","aliases":["Bổn tôn bảy màu"],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Không rõ (đại tôn Tiên Cương đại lục)","trangThai":"khong-ro","blurb":"Nhân vật bí ẩn mặc đạo bào bảy màu, tự xưng bổn tôn, là chủ nhân tạo ra động phủ mà giới nội giới ngoại hình thành từ đó. Tuyên bố sẽ cướp thiên đạo, chế tạo sấm sét thiên kiếp để trừng phạt nghịch tu.","vaiTro":"Đại tôn Tiên Cương đại lục, chủ nhân sáng tạo giới nội giới ngoại","tinhCach":"Cao ngạo; uy áp tuyệt đối; tự tin vô hạn vào sức mạnh bản thân","tabs":{"diem":[{"text":"Tự xưng bổn tôn, tuyên bố động phủ bốn tôn tự thành một giới, vạn vật do hắn tạo ra","chuong":"@c1539"},{"text":"Chế tạo sấm sét thiên kiếp để trừng phạt tu sĩ nghịch thiên trong động phủ","chuong":"@c1539"},{"text":"Giống hệt pho tượng trong khe trữ vật, tương tự người hóa thân bảy màu Thất Thải giới nhưng mạnh hơn gấp bội","chuong":"@c1539"}],"kinhLich":[{"importance":"normal","mucCt":"vua","chuong":"@c1539","tieuDe":"Tạo thiên kiếp cho động phủ","text":"Xuất hiện trong ký ức bên trong tia sét thiên kiếp. Tuyên bố động phủ bốn tôn tự thành một giới, vạn vật do hắn tạo ra nhưng chưa có thiên đạo. Nói sẽ cướp thiên đạo, rồi vung tay triệu tập sấm sét, ngưng tụ thành sấm sét thiên kiếp để trừng phạt chúng sinh nghịch thiên.","anchor":"Bổn tôn sẽ cướp được thiên đạo!"},{"chuong":"@c1540","importance":"bridge","mucCt":"gon","text":"Được nhắc tên: người sáng tạo thiên địa (động phủ). Hỏa diễm do hắn ngưng tụ thành thiên kiếp thứ hai. Vương Lâm tuyên bố ngay cả hắn cũng không thể thay đổi vận mệnh Vương Lâm nữa.","anchor":"chẳng qua chỉ là tu sĩ được sinh ra trong động phủ mà thôi!"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Vương Lâm chứng kiến ký ức của hắn qua tia sét thiên kiếp","ghiChu":""}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1539","@c1540"]},{"id":"chu-dat","name":"Chu Dật","gioiTinh":"nam","tabs":{"kinhLich":[{"chuong":"@c1540","importance":"bridge","mucCt":"gon","text":"Được Vương Lâm tìm thấy và thu hồi vận mệnh trong mặt trời thứ chín.","anchor":"Hắn tìm ấy Thập Tam, tìm thấy đầu to, tìm được Chu Dật"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Thiêu đốt Nguyên Thần đột phá Vấn Đỉnh kỳ ngay trước lúc chết, giao phó Vũ Chi Tiên Kiếm và di nguyện cho Vương Lâm","chuong":"@c0293"},{"text":"Nguyên Thần nhập kiếm, hóa thành Kiếm Tiêu Chi Hồn trong Vũ Chi Tiên Kiếm","chuong":"@c0294"},{"text":"Bị phong ấn trăm năm trong Luyện Tiên Hóa Ma đại trận, linh thể hao tổn chỉ còn sót lại, vẫn cứu Vương Lâm","chuong":"@c0594"},{"text":"Hóa kiếm quang đánh thẳng Hư Không Tử, dẫn phát thương thế cũ của đối phương, linh thể hao tổn nghiêm trọng","chuong":"@c0991"},{"text":"Nhìn Thanh Sương phủ nhận và quên lãng mình, vẫn ngồi bên cạnh không rời mắt — bi kịch si tình ngàn năm","chuong":"@c1046"},{"text":"Cuối cùng đạt viên mãn hạnh phúc bên Thanh Sương sau nhiều năm khổ luyện và chờ đợi","chuong":"@c1961"}]},"nguon":["@c1540"],"vaiTro":"Phụ — si tình kiếm tu, Kiếm Tiêu Chi Hồn của Vũ Chi Tiên Kiếm, ân nhân bảo hộ Vương Lâm","tinhCach":"Si tình bền bỉ, ngàn năm không đổi dù người xưa đã quên lãng; trọng nghĩa xả thân, sẵn sàng thiêu đốt Nguyên Thần vì người; kiên nghị chịu phong ấn trăm năm không oán hận; trầm mặc bi ai trước bi kịch tình duyên không trọn nhưng vẫn thủ hộ lặng lẽ","blurb":"Chu Dật vốn là đệ tử tư chất xuất sắc của Ngũ Hành Tông xuất thân Chu Tước tinh, về sau trở thành đại trưởng lão Thi Âm Tông, cả đời mang theo nữ thi tiên nhân Đình Nhi và ôm mối si tình ngàn năm với Thanh Sương. Vì cứu Đình Nhi, y thiêu đốt Nguyên Thần đột phá Vấn Đỉnh kỳ ngay trước lúc thân thể cháy tàn, giao phó Vũ Chi Tiên Kiếm cùng di nguyện cho Vương Lâm rồi Nguyên Thần nhập kiếm hóa thành Kiếm Tiêu Chi Hồn. Từ đó, Chu Dật dĩ thân phận kiếm linh nhiều lần trợ chiến bảo hộ Vương Lâm qua vô số kiếp nạn, chịu phong ấn trăm năm không oán, đánh thương Hư Không Tử để hộ chủ, lặng lẽ theo sau T"},{"id":"thanh-suong","name":"Thanh Sương","gioiTinh":"nu","tabs":{"kinhLich":[{"chuong":"@c1540","importance":"bridge","mucCt":"gon","text":"Được Vương Lâm tìm thấy và thu hồi vận mệnh trong mặt trời thứ chín.","anchor":"Hắn tìm ấy Thập Tam, tìm thấy đầu to, tìm được Chu Dật"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Từng bày kế áp chế đối thủ khi động phủ mở ra và là người duy nhất có thể tiến vào động phủ thứ năm — cấm địa bế quan tuyệt mật của Thanh Lâm","chuong":"@c0952"},{"text":"Thân thể bị Cổ Ma Tháp Già chi phối và tranh đoạt sau khi đứng dậy trong tầng chín của tiên tháp","chuong":"@c0996"},{"text":"Hồn phách tụ lại trong thức hải Thanh Lâm, dung nhập thể Vương Lâm và thức tỉnh tại Tân Vũ Giới, hóa băng sơn","chuong":"@c1046"},{"text":"Được Vương Lâm thu hồi vận mệnh trong mặt trời thứ chín","chuong":"@c1540"},{"text":"Thần sắc lạnh lùng bước theo Thanh Lâm vào con đường chuyển thế, quay đầu nhìn Chu Dật trước khi biến mất","chuong":"@c1696"},{"text":"Không chọn tu tiên, chuyển thế nhiều lần như phàm nhân, cuối cùng ở bên Chu Dật hạnh phúc","chuong":"@c1961"}]},"nguon":["@c1540"],"vaiTro":"Tiên quân Vũ Tiên Giới — con gái Tiên Đế Thanh Lâm","tinhCach":"mưu lược, từng bày kế áp chế đối thủ và bố trí cấm địa bế quan tuyệt mật; nặng tình nhưng ẩn nhẫn, nén đau đớn trước Chu Dật; lạnh lùng, ít để lộ cảm xúc","blurb":"Thanh Sương là Tiên quân của Vũ Tiên Giới, con gái Tiên Đế Thanh Lâm — vị Tiên Đế chí tôn từng bước vào bước tu đạo thứ ba. Di thể nàng được Chu Dật gửi gắm cho Vương Lâm mang theo với hy vọng phục sinh, trải qua nhiều biến cố bị Cổ Ma Tháp Già chi phối trước khi hồn phách tụ lại trong thức hải Thanh Lâm, dung nhập thể Vương Lâm và thức tỉnh tại Tân Vũ Giới. Sau khi được thu hồi vận mệnh trong mặt trời thứ chín, nàng trở lại tiên giới với ký ức chưa hoàn toàn phục hồi, rồi bước theo Thanh Lâm vào con đường chuyển thế, không chọn tu tiên mà sống như phàm nhân qua nhiều kiếp, cuối cùng ở bên Chu"},{"id":"tay-tu-phuong","name":"Tây Tử Phượng","aliases":["Tây Phượng Tử"],"gioiTinh":"nu","tabs":{"kinhLich":[{"chuong":"@c1540","importance":"bridge","mucCt":"gon","text":"Được Vương Lâm tìm thấy và thu hồi vận mệnh trong mặt trời thứ chín.","anchor":"Hắn tìm ấy Thập Tam, tìm thấy đầu to, tìm được Chu Dật"},{"chuong":"@c1559","importance":"bridge","mucCt":"vua","text":"Đứng trong tinh trận hướng tây cùng tu sĩ La Thiên, bên cạnh Chiến Không Liệt và Thân Công Hổ, đối mặt mấy vạn tu sĩ giới ngoại.","anchor":"Bên cạnh nàng còn có chiến Không Liệt và Thân Công Hổ"},{"chuong":"@c1566","importance":"bridge","mucCt":"gon","tieuDe":"","text":"Bay lên từ một tu chân tinh đuổi theo Vương Lâm, là người thứ ba rời đi sau Mộc Băng Mi và nữ tử áo hồng.","anchor":"Bên trong đạo cầu vồng này là một nữ tử, nàng tên là Tây Tử Phượng"},{"chuong":"@c1569","importance":"bridge","mucCt":"gon","text":"Cùng Mộc Băng Mi và nữ tử áo hồng chứng kiến Phong Giới Đại Trận sụp đổ trong Vân Hải tinh vực, mặt mũi tái nhợt.","anchor":"Mộc Băng Mi, nữ tử áo hồng. Tây Tử Phượng lúc này hóa thành ba đạo cầu vồng ngưng tụ lại với nhau"},{"chuong":"@c1573","importance":"major","mucCt":"ky","tieuDe":"Xin Vương Lâm cho một năm ở bên cạnh","text":"Cùng Mộc Băng Mi và nữ tử áo hồng tới nơi Vương Lâm bảo vệ trong Vô Danh Chuyển Luân trận. Là người đầu tiên tiến tới, tuyên bố không muốn làm đệ tử, chỉ xin một năm ở bên hắn. Bị cự tuyệt ban đầu, nàng run rẩy van xin, cuối cùng được Vương Lâm đồng ý. Ngồi bên cạnh hắn, hâm rượu cho hắn. Nhớ lại Vương Lâm là người đầu tiên và cuối cùng nàng thích, từ hơn ngàn năm trước. Ba nàng đã thỏa thuận mỗi người một năm bên Vương Lâm.","anchor":"Ta chỉ cần một năm. Vương Lâm, cho ta thời gian một năm có được không."},{"importance":"bridge","mucCt":"vua","chuong":"@c1574","text":"Đứng bên Vương Lâm trên Thiên Hoàng Lô, tâm thần chấn động khi thấy lực lượng giới ngoại dàn trận, được Vương Lâm nhu hòa bảo hâm rượu mà bình tĩnh lại.","anchor":"nhìn cảnh tượng này mà tâm thần chấn động"},{"importance":"bridge","mucCt":"gon","chuong":"@c1577","tieuDe":"","text":"Ở trong Vô Danh Chuyển Luân trận, sắc mặt tái nhợt nhìn Vương Lâm giao chiến nhưng im lặng không muốn hắn phân tâm, cúi đầu tiếp tục hâm rượu.","anchor":"Nàng cúi đầu tiếp tục hâm rượu cho Vương Lâm"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Gặp Vương Lâm lần đầu giữa Lôi Tiên Giới sụp đổ, cung kính cảm tạ hắn hai lần cứu mạng","chuong":"@c0750"},{"text":"Đau lòng rơi lệ khi nhận ra Vương Lâm tranh phong tiên vì Lý Mộ Uyển","chuong":"@c0826"},{"text":"Tái xuất sau tám trăm năm với gia tộc bị diệt vong, dung nhan tự hủy thành sẹo để giữ khí tiết","chuong":"@c1395"},{"text":"Được Vương Lâm chữa lành thương thế, khôi phục dung mạo, truyền công bạo tăng tới Tinh Tịnh Niết và chính thức bái sư tôn","chuong":"@c1398"},{"text":"Nhận huyết kiếm bản mệnh từ Vương Lâm, mang theo sứ mệnh rửa nhục tám trăm năm","chuong":"@c1399"},{"text":"Xin Vương Lâm cho ở bên cạnh một năm trong đại chiến giới ngoại, lặng lẽ ấm rượu chờ hắn giữa trận tiền","chuong":"@c1573"}]},"nguon":["@c1540","@c1559","@c1566","@c1569","@c1573","@c1574","@c1577"],"trangThai":"song","cn":"西子凤","canhGioiCaoNhat":"Không rõ","vaiTro":"Nữ tu sĩ trọng tình, từng được Vương Lâm nhiều lần cứu giúp và sau bái hắn làm sư tôn","tinhCach":"biết cảm ân, cung kính tạ ơn và trung thành với ân nhân; trọng tình cảm, nhiều lần rung động trước Vương Lâm nhưng âm thầm chịu đựng; kiên cường chịu nhục, tự hủy dung nhan để giữ khí tiết; dễ tự ti trước khoảng cách thân phận","blurb":"Tây Tử Phượng là nữ tu sĩ lần đầu gặp Vương Lâm trong biến cố Lôi Tiên Giới sụp đổ, được hắn hai lần cứu mạng rồi mang theo tình cảm thầm kín qua cuộc tranh phong tiên tại Lôi Tiên Điện, nơi nàng chứng kiến hắn tranh đoạt vì Lý Mộ Uyển mà đau lòng rơi lệ. Tám trăm năm sau, nàng tái xuất với gia tộc đã bị diệt, dung nhan tự hủy thành vết sẹo, được Vương Lâm chữa lành thương thế, khôi phục dung mạo, truyền công cho tu vi bạo tăng tới Tinh Tịnh Niết, rồi chính thức bái hắn làm sư tôn và nhận huyết kiếm bản mệnh để rửa nhục. Trong đại chiến giới ngoại, nàng xin được ở bên cạnh Vương Lâm một năm, l"},{"id":"ly-thien-mai","name":"Lý Thiến Mai","gioiTinh":"nu","tabs":{"kinhLich":[{"chuong":"@c1540","importance":"normal","mucCt":"gon","text":"Được Vương Lâm tìm thấy và thu hồi vận mệnh trong mặt trời thứ chín.","anchor":"Hắn tìm ấy Thập Tam, tìm thấy đầu to, tìm được Chu Dật"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Luận đạo cùng Vương Lâm tại Bồng Lai, đặt ba câu hỏi về thiên, đạo, ý — khởi đầu mối tri kỷ xuyên suốt","chuong":"@c1096"},{"text":"Bất chấp tông lệnh và cảnh cáo đào ngũ, rời chiến trường Yêu Tông sau trăm năm chém giết mãnh thú để tìm Vương Lâm","chuong":"@c1163"},{"text":"Bị sư tôn Phá Thiên Tông vây khốn, phá trận pháp rời tông, bị đoạn tuyệt sư đồ vĩnh viễn","chuong":"@c1200"},{"text":"Suốt mười năm hy sinh máu tươi, tinh huyết chăm sóc tượng đá Vương Lâm tại đại lục hoang dã đến kiệt quệ mất trí nhớ","chuong":"@c1214"},{"text":"Nguyện chuyển thế đầu thai chờ Vương Lâm trong luân hồi, là người cuối cùng rời đi với nụ cười","chuong":"@c1697"},{"text":"Sau khi đầu thai, cố ý ẩn mình không tản ấn ký, lặng lẽ chúc phúc Vương Lâm từ xa","chuong":"@c1969"}]},"nguon":["@c1540"],"vaiTro":"Nữ tu sĩ Phá Thiên Tông — thiên chi kiêu nữ Vân Hải tinh vực, tri kỷ của Vương Lâm","tinhCach":"ham hỏi đạo, trọng bản tâm; nặng tình và giữ hẹn; kiên định trước sư mệnh, tông lệnh; sẵn sàng hy sinh vì người mình chọn","blurb":"Lý Thiến Mai, bí danh Lý Oánh Chi, là thiên chi kiêu nữ Vân Hải tinh vực xuất thân Phá Thiên Tông, năm tuổi nhập đạo, hơn 1200 năm tu luyện đạt Toái Niết hậu kỳ. Nàng kết giao với Vương Lâm qua luận đạo tại Bồng Lai, trải trăm năm chém giết mãnh thú tại chiến trường Yêu Tông rồi bất chấp tông lệnh vượt tinh vực tìm hắn, bị đoạn tuyệt sư đồ và hy sinh máu tươi, tinh huyết chăm sóc tượng đá Vương Lâm suốt mười năm đến kiệt quệ mất trí nhớ. Sau khi dần khôi phục ký ức và được Vương Lâm tiếp nhận, nàng quyết định chuyển thế đầu thai, nguyện chờ hắn trong luân hồi; tính đến chương gần nhất, Vương L"},{"id":"lao-thanh-hoang","name":"Lão Thánh Hoàng","gioiTinh":"nam","tabs":{"kinhLich":[{"chuong":"@c1540","importance":"bridge","mucCt":"gon","text":"Được Vương Lâm tìm thấy và thu hồi vận mệnh trong mặt trời thứ chín.","anchor":"Hắn tìm ấy Thập Tam, tìm thấy đầu to, tìm được Chu Dật"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[]},"nguon":["@c1540"]},{"id":"chu-tuoc-doi-dau","name":"Chu Tước đời đầu","gioiTinh":"nam","tabs":{"kinhLich":[{"chuong":"@c1540","importance":"bridge","mucCt":"gon","text":"Được nhắc lại: từng nói chỉ có thể đưa vài người rời khỏi động phủ về quê hương Tiên Cương đại lục.","anchor":"Khó trách Chu Tước đời đầu tiên lại nói, hắn chỉ có thể đưa mấy người rời khỏi nơi này, đi tới quê hương hắn."}],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Là người hiếm hoi có cách ngăn cản nghiệp hỏa thiêu đốt thân thể, được Lão Chu Tước nhắc lại","chuong":"@c1317"},{"text":"Năm xưa lừa viêm long ra khỏi viêm vực khi còn nhỏ để liên tục lấy máu","chuong":"@c1321"},{"text":"Hư hỏa biến dị của Vương Lâm là loại biến hóa mà ngay cả lão tổ đời đầu cũng chưa từng đạt tới","chuong":"@c1323"},{"text":"Chỉ học trộm được Phần Giới cổ Tán, không nắm trọn vẹn","chuong":"@c1449"},{"text":"Từng nói chỉ có thể đưa vài người rời khỏi động phủ về quê hương Tiên Cương đại lục","chuong":"@c1540"}]},"nguon":["@c1540"],"vaiTro":"Lão tổ đời đầu của Chu Tước tộc — người sáng lập nền tảng nghiên cứu nghiệp hỏa","tinhCach":"mưu lược sâu xa, dám hành sự tàn nhẫn để đạt mục đích; am hiểu sâu về hỏa đạo và nghiệp hỏa","blurb":"Lão tổ khai tộc của Chu Tước tộc, là một trong số hiếm hoi nắm được cách ngăn nghiệp hỏa thiêu đốt thân thể. Năm xưa từng lừa viêm long ra khỏi viêm vực lúc còn nhỏ để liên tục lấy máu, đồng thời chỉ học trộm được Phần Giới cổ Tán chứ không nắm trọn vẹn. Lời truyền lại của người này đặt nghiệp hỏa nhập hồn cao hơn con đường mượn bất diệt hồn hỏa, và hư hỏa biến dị của Vương Lâm là loại biến hóa mà ngay cả lão tổ đời đầu cũng chưa từng đạt tới."},{"id":"lao-gia-kho-gay-si-tien","name":"Lão già khô gầy (sĩ tiên)","aliases":["Sinh vật bí ẩn trong pho tượng Cổ Thần sát cửu tinh","Lão già tiên nhân gầy gò (hộ vệ tiên tôn)","Lão già gầy gò (sĩ tiên Thất Đạo Tông)"],"gioiTinh":"nam","trangThai":"khong-ro","theLuc":[{"ten":"Thất Đạo Tông","trangThai":"gan-bo"}],"blurb":"Sĩ tiên xuất thân từ Thất Đạo Tông trên Tiên Cương đại lục, vì lý do không rõ mà ẩn trong pho tượng Cổ Thần sát cửu tinh, dùng thân thể pho tượng làm phôi thể chữa thương. Bị Vương Lâm phá hủy phôi thể, phẫn nộ giao chiến nhưng bị cường hành xâm nhập thức hải, cuối cùng phong ấn trong thức hải bị phá, thân thể nổ tung mà chết; ký ức tàn dư tiết lộ thân phận sĩ tiên Thất Đạo Tông.","vaiTro":"Sĩ tiên Thất Đạo Tông — sinh vật bí ẩn ẩn trong pho tượng Cổ Thần, bị Vương Lâm chế phục","tinhCach":"Ngạo mạn, tự thị uy nghiêm vô thượng; hung hãn khi bị kinh động; tàn nhẫn đe dọa diệt tộc đối phương","tabs":{"diem":[{"text":"Bị kinh động khi Vương Lâm phá hủy pho tượng Cổ Thần sát cửu tinh, đe dọa sẽ giết Vương Lâm và diệt cả bộ tộc","chuong":"@c1541"},{"text":"Phôi thể ký sinh trong pho tượng Cổ Thần bát tinh bị hủy, phẫn nộ thức tỉnh lao ra tấn công Vương Lâm","chuong":"@c1542"},{"text":"Bị Vương Lâm dùng thần thức cường hành xâm nhập thức hải, thất khiếu chảy máu; tự xưng sĩ tiên dưới trướng tiên tôn","chuong":"@c1543"},{"text":"Bị phá phong ấn thức hải, thân thể nổ tung chết; ký ức tàn dư tản ra","chuong":"@c1544"},{"text":"Ký ức tiết lộ thân phận: lớn lên trên Tiên Cương đại lục, xin vào Thất Đạo Tông trở thành sĩ tiên","chuong":"@c1545"}],"kinhLich":[{"mucCt":"vua","text":"Bị kinh động khi Vương Lâm phá hủy pho tượng Cổ Thần sát cửu tinh, đe dọa sẽ giết Vương Lâm và diệt cả bộ tộc, tuyên bố sẽ biến Vương Lâm thành phôi thể thay thế. Bị Vương Lâm túm cánh tay khô héo giật ra khỏi dòng xoáy ném xuống đất.","anchor":"huỷ diệt thân thể chữa thương của ta, đã phạm phải tử tội","bridge":true,"khoang":"@c1541"},{"mucCt":"ky","text":"Thức tỉnh khi phôi thể ký sinh trong pho tượng Cổ Thần bát tinh bị Vương Lâm hủy diệt, phẫn nộ lao ra tấn công. Tự xưng bổn tiên, là một trong trăm hộ vệ của tiên tôn, coi tu sĩ hạ giới là kiến hôi. Bị Vương Lâm dùng một trảo khóa chặt trong hư không, bị đánh nát tay trái. Hồi ức lại chuyện năm xưa trong trận đại chiến bị trọng thương, chọn ký sinh vào pho tượng Cổ Thần bát tinh để chữa thương. Nhận ra Vương Lâm là nghịch tu bước thứ ba, kinh hãi vì thiên kiếp lẽ ra ngăn chặn điều này. Cố thi triển thủ đoạn bảo mạng (cắn lưỡi phun máu tỏa kim quang) nhưng bị Vương Lâm dùng Định Không Thuật định thân hoàn toàn, cuối cùng bị đọc ký ức.","anchor":"Đối với người như vậy hắn thân là một trong trăm hộ vệ của tiên tôn có thể tuỳ ý xử trí","bridge":true,"khoang":"@c1542"},{"mucCt":"vua","text":"Bị Vương Lâm dùng thần thức cường hành xâm nhập thức hải, thất khiếu chảy máu, tự xưng sĩ tiên dưới trướng tiên tôn có huyết mạch tiên nhân, đe dọa Vương Lâm phạm tội giết tiên. Thức hải chứa phong ấn tiên tôn (sương mù + nam tử bảy màu) bảo vệ trí nhớ.","anchor":"Ta là sĩ tiên dưới trướng tiên tôn đại nhân. Ta có huyết mạch tiên nhân.","bridge":true,"khoang":"@c1543"},{"chuong":"@c1544","importance":"normal","mucCt":"gon","tieuDe":"Bị phá phong ấn thức hải, thân thể nổ tung chết","text":"Bị Vương Lâm phá phong ấn trong thức hải. Thức hải sụp đổ, thân thể nổ tung thành máu thịt tiêu tán. Ký ức cả đời ngưng tụ thành tinh thể bị Vương Lâm đoạt.","anchor":"thân thể trong tiếng ầm ầm liền sụp đổ, bị lực lượng đến từ bên trong thức hải đánh tan"},{"chuong":"@c1545","importance":"normal","mucCt":"gon","tieuDe":"Ký ức tiết lộ: sĩ tiên Thất Đạo Tông","text":"Tinh thể ký ức tiết lộ hắn lớn lên trên Tiên Cương đại lục, xin vào Thất Đạo Tông trở thành sĩ tiên của Thất Thải Thiên Tôn chỉ dưới tứ đại chiến tướng, chứng kiến đêm hai mặt trời xuất hiện thì thất khiếu chảy máu hôn mê, tu vi tụt bậc.","anchor":"cuối cùng trở thành sĩ tiên của Thất Thải Thiên Tôn"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Bị Vương Lâm chế phục, Vương Lâm muốn lấy trí nhớ","gap":"@c1541"},{"ten":"Thất Thải Thiên Tôn","tag":"su-mon","quanHe":"Chủ nhân, hắn là sĩ tiên dưới quyền tiên tôn"}],"tuiDo":{}},"nguon":["@c1541","@c1542","@c1543","@c1544","@c1545"]},{"id":"chu-tuoc-thanh-hoang","name":"Chu Tước Thánh Hoàng","cn":"朱雀圣皇","aliases":["Chu Tước chiến tướng","Chu Tước đời thứ nhất (phân thân)"],"gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1543","importance":"normal","mucCt":"vua","tieuDe":"Bàn luận trong pho tượng, tiết lộ kế hoạch","text":"Từ bên trong pho tượng, phản bác Bạch Hổ rằng Vương Lâm đã độ thiên kiếp thứ ba và rút vận mệnh từ mặt trời thứ chín. Tiết lộ Vương Lâm vốn không nằm trong kế hoạch nhưng là người đầu tiên có thể đến được nơi bốn pho tượng. Thầm than, nhận định Vương Lâm không thể phá phong ấn tiên tôn.","anchor":"Hắn vống không phải là người trong kế hoạch của ta. Nhưng hắn lại là người đầu tiên có thể đến được nơi này"},{"chuong":"@c1549","importance":"normal","mucCt":"vua","tieuDe":"Xuất hiện cầu hòa, xưng Vương Lâm là tiên hữu","text":"Không tham gia ba chiến tướng liên thủ tấn công Vương Lâm. Sau khi cung Lý Quảng trấn áp, từ dòng xoáy mi tâm pho tượng bước ra, vẻ xấu hổ, ôm quyền xưng Vương Lâm là tiên hữu, xin nể mặt cùng nói chuyện — cầu hòa.","anchor":"Vương Lâm tiên hữu, chớ nên tức giận. Xin hãy nể mặt lão phu mà cùng nói chuyện đi."}],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Phát lệnh cứu Vương Lâm từ sâu trong tinh vực lửa khi Chu Tước Chi Biến xảy ra","chuong":"@c0967"},{"text":"Dùng nguyên thần giáng lâm bảo hộ Vương Lâm trước thế cục liên quan Tứ Thánh Tông","chuong":"@c1012"},{"text":"Cận kề tử vong vẫn cường hành truyền nguyên lực, hỗ trợ Vương Lâm tu luyện Cửu Huyền Biến","chuong":"@c1017"},{"text":"Trao cho Vương Lâm ba vật phẩm truyền thừa, xác lập hắn là tân Chu Tước Thánh Hoàng","chuong":"@c1020"},{"text":"Để lại trăn trối bằng thần niệm đặc biệt rồi qua đời trong tử khí","chuong":"@c1039"},{"text":"Được xác nhận đã dục hỏa trọng sinh và thức tỉnh Chu Tước lần thứ ba","chuong":"@c1141"}]},"nguon":["@c1543","@c1549","@c1550"],"canhGioiCaoNhat":"Không rõ","vaiTro":"Lão tổ Chu Tước mạch — người truyền vị Thánh Hoàng cho Vương Lâm","tinhCach":"Tận tâm dìu dắt hậu bối; coi trọng truyền thừa Chu Tước; kiên định bảo hộ truyền nhân; linh hoạt cầu hòa khi cần","blurb":"Chu Tước Thánh Hoàng là lão tổ của Chu Tước mạch trong Tứ Thánh Tông, từng ra tay bảo hộ Vương Lâm, truyền nguyên lực và trao lại ba vật phẩm truyền thừa khi hắn trở thành tân Thánh Hoàng. Cận kề tử vong, ông để lại trăn trối rồi qua đời; về sau được xác nhận đã dục hỏa trọng sinh, thức tỉnh Chu Tước lần thứ ba và tiếp tục xuất hiện trong các biến cố liên quan Vương Lâm."},{"id":"bach-ho-thanh-hoang","name":"Bạch Hổ Thánh Hoàng","cn":"白虎圣皇","aliases":["Bạch Hổ chiến tướng","Bạch Hổ lão giả","lão già áo bào trắng","lão già tóc bạc"],"gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"mucCt":"vua","text":"Trào phúng hậu duệ Chu Tước (Vương Lâm) không biết lượng sức khi muốn tìm kiếm trí nhớ sĩ tiên. Thừa nhận bản thân không làm được điều Vương Lâm đã làm. Khẳng định phong ấn trí nhớ tiên nhân chỉ môn nhân hạch tâm Thất Đạo tông mới có, Vương Lâm phá phong ấn tiên tôn là đi tìm đường chết.","anchor":"phong ấn trong trí nhớ của tiên nhân chúng ta chỉ có những môn nhân hạch tâm của Thất Đạo tông chúng ta mới có","bridge":true,"khoang":"@c1543"},{"mucCt":"vua","text":"Khiếp sợ kêu lên không thể tin phong ấn của tiên tôn bị Vương Lâm phá vỡ. Hiện thân từ dòng xoáy pho tượng, khẳng định ba tấc phong ấn đủ huỷ diệt hết thảy, dù Tứ Thánh Hoàng thời đỉnh cao đồng loạt ra tay cũng không phá nổi.","anchor":"Ba tấc phong ấn đó đủ để huỷ diệt hết thảy lực lượng và vật chất, căn bản là không có khả năng thương tổn tới nó","bridge":true,"khoang":"@c1544"},{"mucCt":"vua","text":"Bước ra từ vòng xoáy pho tượng, tự xưng Bạch Hổ, mắng Vương Lâm đại nghịch bất đạo, nói sẽ thay Chu Tước giáo huấn. Hiện hư ảnh mãnh hổ trắng khổng lồ lao tới tấn công nhưng bị Vương Lâm một quyền đẩy lùi. Muốn bước ra lần nữa nhưng dưới ánh mắt uy áp của Vương Lâm theo bản năng lùi lại. Chấn động khi phát hiện Vương Lâm đã phá được phong ấn đọc ký ức tiên nhân, dâng lên sợ hãi.","anchor":"Lão phu Bạch Hổ, sẽ thay mặt Chu Tước giáo huấn ngươi!","bridge":true,"khoang":"@c1546"},{"chuong":"@c1547","importance":"normal","mucCt":"ky","tieuDe":"Đại bại trước hai hư bổn nguyên của Vương Lâm","text":"Đang trong giai đoạn chữa thương mấu chốt, tu vi chỉ phát huy được Không Huyền sơ kỳ. Thi triển thức thứ nhất trong ba thức thần thông bổn nguyên hung tinh Bạch Hổ — Hổ Khiếu Sơn Hà — triệu hoán hư ảnh Bạch Hổ cao tận trời gầm thét chấn động thiên không đại địa, uy lực đủ cuốn tan tinh không. Tiếp đó dùng khai thiên đao vàng dài mười trượng chém liên tục hàng ngàn lần vào Vương Lâm nhưng đao xuyên qua thân thể như hư ảnh, không gây thương tổn. Kinh hãi nhận ra Vương Lâm sở hữu Chân Giả bổn nguyên, hồi tưởng tiên tôn từng hạ bảy đạo pháp tắc phong kín hư bổn nguyên, vì trọng thương rút ra nên Vương Lâm mới lĩnh ngộ được. Bị Vương Lâm dùng Nhân Quả bổn nguyên vỗ chưởng lôi bạch quang từ cơ thể ra rồi bóp nát, phun máu hai lần. Cuối cùng phải dung hợp với hư ảnh Bạch Hổ hóa thành Bạch Hổ khổng lồ vừa rít gào vừa lùi.","anchor":"tiên tôn đã hạ bảy đạo pháp tắc phong kín hư bổn nguyên không cho sinh ra"},{"mucCt":"ky","text":"Bị đầu lâu Đạo cổ đánh tan hư ảnh Bạch Hổ, phun máu tươi bị đánh găm vào pho tượng đang chữa thương khiến pho tượng nứt nẻ. Không chịu khuất phục, tự xưng truyền thừa Bạch Hổ, thi triển đại thuật thần thông Kỵ Hổ Nan Hạ ngưng bạch quang thành Bạch Hổ khổng lồ dưới chân Vương Lâm, phong ấn thiên địa, biến thành dòng xoáy trắng trói đối thủ trên lưng hổ. Phóng hổ linh bản mệnh mưu nuốt thiên linh Vương Lâm để trấn thần hồn dưới sáu mươi bảy đạo thiên sơn tiên cương đại lục. Hổ linh bị khí thế đại nho của Vương Lâm trấn áp, run rẩy cúi đầu quy phục. Xác nhận là tiên nhân chân chính từ tiên cương đại lục, một trong tứ đại chiến tướng của Thất Thải Tiên Tôn, huyết mạch chứa tiên lực vượt xa Vương Lâm nhưng thương thế năm xưa chưa khôi phục hoàn toàn.","anchor":"Hắn là tiên nhân, là tiên nhân chân chính!","bridge":true,"khoang":"@c1548"},{"chuong":"@c1549","importance":"normal","mucCt":"ky","tieuDe":"Bạch Hổ bỏ đi, liên thủ thất bại, bị cung Lý Quảng trấn áp","text":"Hổ linh dung hợp lại thành Bạch Hổ, Bạch Hổ bỏ đi không thèm để ý hắn, hóa bạch quang tiêu tán vào viễn cổ tiên vực. Hoảng sợ nhưng vẫn cầm khai thiên đao phối hợp Thanh Long, Huyền Vũ đánh lén Vương Lâm. Bị sáu chưởng ấn liên hoàn phá tan khai thiên đao, trọng thương. Điên cuồng gầm thét đòi Thanh Long, Huyền Vũ giúp mở phong ấn tu vi ở mi tâm để khôi phục sức mạnh. Thấy cung Lý Quảng liền im bặt, không còn dám đòi mở phong ấn.","anchor":"Ta muốn giết hắn. Hắn có tư cách gì mà bức lui tiên nhân ta. Hắn chỉ là một con kiến hôi nơi hạ giới!"}],"tuViMoc":[{"chuong":"@c1546","canhGioi":"Không Huyền Sơ Kỳ","text":"Tu vi được xác nhận là Không Huyền Sơ Kỳ khi xuất chiến đối đầu Vương Lâm.","importance":"major"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Bị Vương Lâm một quyền đẩy lùi, dưới uy áp theo bản năng lùi lại","ghiChu":"@c1546"},{"ten":"Thất Thải Thiên Tôn","tag":"cap-tren","quanHe":"Chiến tướng dưới trướng Thất Thải Tiên Tôn","ghiChu":"@c1546"},{"ten":"Chu Tước","tag":"dong-minh","quanHe":"Đồng liêu, cùng là chiến tướng dưới trướng Thất Thải Tiên Tôn, nói sẽ thay Chu Tước giáo huấn Vương Lâm","ghiChu":"@c1546"}],"tuiDo":{},"diem":[{"text":"Trong đại chiến liên tục giết nhiều trưởng lão chủ chốt của Tu Chân Liên Minh và vô số cường giả","chuong":"@c0976"},{"text":"Chết trận trong cuộc chiến Tứ Thánh Tông với Tu Chân Liên Minh, thi thể bị đoạt","chuong":"@c1027"},{"text":"Hiện thân từ pho tượng viễn cổ, tự xưng Bạch Hổ, mắng Vương Lâm đại nghịch bất đạo và đòi thay Chu Tước giáo huấn","chuong":"@c1546"},{"text":"Đại bại trước Vương Lâm do đang chữa thương, tu vi chỉ phát huy được Không Huyền Sơ Kỳ","chuong":"@c1547"},{"text":"Bị đầu lâu Đạo cổ đánh tan hư ảnh, phun máu bị găm vào pho tượng","chuong":"@c1548"},{"text":"Hổ linh dung hợp lại thành Bạch Hổ, bỏ đi không thèm để ý, hóa bạch quang tiêu tán vào viễn cổ tiên giới","chuong":"@c1549"}]},"nguon":["@c1543","@c1544","@c1546","@c1547","@c1548","@c1549","@c1550"],"theLuc":[{"ten":"Thất Đạo Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","vaiTro":"Thánh Hoàng của Bạch Hổ Thánh Tông — cường giả tử chiến trong đại chiến với Liên Minh","tinhCach":"Dũng mãnh tử chiến, giết nhiều cường địch đến hơi thở cuối; kiên cường bất khuất, thi thể vẫn đứng chặn đại quân; cao ngạo tự tôn, mắng kẻ khác đại nghịch bất đạo và đòi thay mặt giáo huấn","blurb":"Bạch Hổ Thánh Hoàng là Thánh Hoàng của Bạch Hổ Thánh Tông, một trong Tứ Thánh Tông. Trong đại chiến giữa Tứ Thánh Tông với Tu Chân Liên Minh và Côn Hư Cảnh, ông liên tục giết nhiều trưởng lão chủ chốt cùng vô số cường giả trước khi chết trận, thi thể vẫn đứng chặn đại quân và về sau bị đoạt. Hư ảnh của ông tồn tại bên trong pho tượng viễn cổ, từng xuất thế đối đầu Vương Lâm nhưng do đang chữa thương chỉ phát huy được tu vi Không Huyền Sơ Kỳ, cuối cùng đại bại và bỏ đi."},{"id":"thanh-hoang-thu-ba","name":"Thánh Hoàng thứ ba (chưa rõ tên)","cn":"","aliases":[],"gioiTinh":"nam","vaiTro":"Một trong bốn Thánh Hoàng ngồi trong pho tượng tam tộc cổ tại trung tâm giới","tinhCach":"Thận trọng; quan tâm kế hoạch đại cục","blurb":"Thánh Hoàng thứ ba trong bốn pho tượng tam tộc cổ tại trung tâm Viễn cổ tiên vực. Hỏi Chu Tước về ảnh hưởng nếu Vương Lâm chết dưới phong ấn tiên tôn.","theLuc":[{"ten":"Thất Đạo Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","tabs":{"diem":[{"text":"Một trong bốn Thánh Hoàng tồn tại bên trong pho tượng tam tộc cổ, quan tâm kế hoạch của Chu Tước","chuong":"@c1543"}],"kinhLich":[{"chuong":"@c1543","importance":"normal","mucCt":"gon","tieuDe":"Hỏi Chu Tước về kế hoạch","text":"Hỏi nếu Vương Lâm chết dưới phong ấn tiên tôn thì ảnh hưởng kế hoạch Chu Tước thế nào.","anchor":"Nếu hắn chết dưới phong ấn của tiên tôn, đối với kế hoạch của ngươi có ảnh hưởng gì lớn không?"},{"chuong":"@c1544","importance":"normal","mucCt":"vua","tieuDe":"Đánh giá Vương Lâm bất phàm, quyết thay đổi kế hoạch","text":"Hiện thân từ dòng xoáy pho tượng thứ ba. Đánh giá Vương Lâm bất phàm, có thể vang danh thiên hạ ở Tiên Cương đại lục. Quyết định phải thay đổi kế hoạch đối với Vương Lâm.","anchor":"Người này bất phàm….Người này khiến ta phải thay đổi kế hoạch"}],"tuViMoc":[],"nhanMach":[{"ten":"Chu Tước Thánh Hoàng","tag":"dong-minh","quanHe":"Đồng liệt trong bốn pho tượng Thánh Hoàng","ghiChu":""}],"tuiDo":{}},"nguon":["@c1543","@c1544"]},{"id":"thanh-hoang-thu-tu","name":"Thánh Hoàng thứ tư (chưa rõ tên)","cn":"","aliases":[],"gioiTinh":"nam","vaiTro":"Một trong bốn Thánh Hoàng ngồi trong pho tượng tam tộc cổ tại trung tâm giới","tinhCach":"Điềm tĩnh; có kiến thức rộng về tu sĩ nghịch tu","blurb":"Thánh Hoàng thứ tư trong bốn pho tượng tam tộc cổ. Đánh giá Vương Lâm là tu sĩ nghịch tu bước thứ ba đầu tiên hắn gặp, nhưng nhận định phong ấn tiên tôn bốn người liên thủ cũng không phá nổi.","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"song","tabs":{"diem":[{"text":"Thánh Hoàng thứ tư, nhận xét Vương Lâm là tu sĩ nghịch tu bước thứ ba đầu tiên từng gặp, kết luận phong ấn tiên tôn không thể phá","chuong":"@c1543"}],"kinhLich":[{"chuong":"@c1543","importance":"normal","mucCt":"vua","tieuDe":"Đánh giá Vương Lâm nghịch tu bước thứ ba","text":"Đánh giá Vương Lâm là tu sĩ nghịch tu bước thứ ba đầu tiên hắn gặp trong đời, nếu là người Tiên Cương đại lục sẽ thành danh. Nhận định phong ấn tiên tôn bốn người liên thủ cũng không phá nổi, Vương Lâm không tới nửa nén hương sẽ tử vong.","anchor":"Người này bất phàm, là tu sĩ nghịch tu bước thứ ba đầu tiên ta gặp trong đời"}],"tuViMoc":[],"nhanMach":[{"ten":"Chu Tước Thánh Hoàng","tag":"dong-minh","quanHe":"Đồng liệt trong bốn pho tượng Thánh Hoàng","ghiChu":""}],"tuiDo":{}},"nguon":["@c1543"]},{"id":"that-thai-thien-ton","name":"Thất Thải Thiên Tôn","cn":"七彩天尊","aliases":["Thất Thải Tiên Tôn","Thất Thải Đạo Tôn","Viễn Cổ Tiên Tôn","Thất Thải Đạo Nhân","kẻ bảy màu","viễn cổ tiên hoàng"],"gioiTinh":"nam","theLuc":[{"ten":"Thất Đạo Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Thiên Tôn (viễn cổ tiên hoàng)","trangThai":"khong-ro","blurb":"Viễn cổ tiên hoàng tu vi Không Kiếp trung kỳ, cùng đạo lữ khai tông lập phái Thất Đạo Tông trên Tiên Cương đại lục, uy vọng cực cao suốt vô số ngàn năm. Sau đại chiến viễn cổ, kim thân tan nát, hóa thành ba chủ hồn bảy phách tản mác, mỗi hồn mang một phần đạo thuật thần thông. Tàn hồn của y vẫn tỏa uy áp kinh khiếp vượt thiên uy, chìm trong ảo giác ký ức đại chiến năm xưa.","vaiTro":"Tông chủ Thất Đạo Tông — viễn cổ tiên hoàng trên Tiên Cương đại lục","tinhCach":"Uy nghiêm thâm trầm, uy áp vượt thiên uy; sẵn sàng hy sinh đạo lữ vì bảo vật (theo lời Diệp Mịch); chấp niệm cực thâm, tự nguyện đắm chìm trong ảo giác ký ức","tabs":{"diem":[{"text":"Cùng đạo lữ khai tông lập phái Thất Đạo Tông trên Tiên Cương đại lục, trải vô số ngàn năm uy vọng cực cao","chuong":"@c1545"},{"text":"Tu vi xác nhận Không Kiếp trung kỳ, đủ tư cách đại tôn khai tông lập phái","chuong":"@c1568"},{"text":"Kim thân tan nát sau đại chiến, hóa thành ba chủ hồn bảy phách, mỗi hồn chứa đạo thuật thần thông riêng","chuong":"@c1600"},{"text":"Tàn hồn tự nguyện đắm chìm trong ảo giác, khoanh chân ngồi trên thi thể mãnh thú trong không gian kỳ dị của thuyền cổ","chuong":"@c1604"},{"text":"Trong ảo giác tái hiện ký ức đại chiến, tỏa uy áp kinh khiếp hơn thiên uy, xung quanh đầy thi thể mãnh thú","chuong":"@c1606"}],"kinhLich":[{"chuong":"@c1545","importance":"major","mucCt":"ky","tieuDe":"Khai tông Thất Đạo Tông và đại chiến viễn cổ","text":"Cùng đạo lữ khai tông lập phái Thất Đạo Tông trên Tiên Cương đại lục, trải vô số ngàn năm, uy vọng cực cao. Đêm hai mặt trời xuất hiện trên trời kèm uy áp kinh hoàng, hắn cùng đạo lữ bay về phía hai mặt trời, mấy tháng sau một mình trở về, thần sắc âm u nhưng mắt bừng sáng, đạo lữ không về cùng. Sau đó mang đệ tử, tiên phi, bách vệ, tứ đại chiến tướng vào động phủ phong kín bằng vô số phong ấn. Đạo Cổ Diệp Mịch tìm đến chỉ trích hắn vứt bỏ đạo lữ để đoạt bảo vật rồi lưu đầu mối, hắn đáp chính mình mời Diệp Mịch đến. Đại chiến nổ ra trong động phủ với ba kẻ phát kim quang, bách vệ và chiến tướng vây công nhưng tử vong thảm trọng. Kết quả: hắn bị trọng thương, viễn cổ tiên vực thành đống đổ nát, Thất Đạo Tông gần diệt.","anchor":"hắn ở trên đại lục này được gọi là Thất Thải Tiên Tôn"},{"chuong":"@c1546","importance":"bridge","mucCt":"gon","text":"Được nhắc qua: Vương Lâm thắc mắc nếu Thất Thải Tiên Tôn đang trọng thương bế quan thì Thất Thải Đạo Nhân ở Thất Thải Giới tại Triệu Hà là ai.","anchor":"Nếu Thất Thải Tiên Tôn trọng thương bế quan, thì Thất Thải Đạo Nhân mà ta nhìn thấy trong Thất Thải Giới tại Triệu Hà là ai"},{"chuong":"@c1568","importance":"bridge","mucCt":"gon","text":"Được nhắc là đại tôn Không Kiếp trung kỳ, đủ khai tông lập phái thành lập Thất Đạo Tông.","anchor":"Thất Thải Tiên Tôn cũng là đại tôn Không Kiếp nhưng tu vi của hắn không phải là Không Kiếp đại viên mãn mà là Không Kiếp trung kỳ!"}],"tuViMoc":[{"chuong":"@c1568","canhGioi":"Không Kiếp trung kỳ","text":"Được xác nhận tu vi là Không Kiếp trung kỳ, đại tôn Không Kiếp nhưng không phải đại viên mãn.","importance":"major"}],"nhanMach":[{"ten":"Đạo Cổ Diệp Mịch","tag":"doi-thu","quanHe":"Kẻ thù tìm đến chỉ trích và tấn công","ghiChu":"Diệp Mịch tố Thất Thải vứt bỏ đạo lữ đoạt bảo vật"},{"ten":"Lão già khô gầy (sĩ tiên)","tag":"khac","quanHe":"Sĩ tiên trung thành, chỉ dưới tứ đại chiến tướng"},{"ten":"Người điên","tag":"doi-thu","quanHe":"Một trong ba kẻ phát kim quang tấn công động phủ, tự xưng Bổn vương bảo hắn quỳ lạy"},{"ten":"Chu Tước","tag":"khac","quanHe":"Tứ đại chiến tướng dưới quyền"},{"ten":"Huyền Vũ","tag":"khac","quanHe":"Tứ đại chiến tướng dưới quyền"},{"ten":"Thanh Long","tag":"khac","quanHe":"Tứ đại chiến tướng dưới quyền"},{"ten":"Bạch Hổ","tag":"khac","quanHe":"Tứ đại chiến tướng dưới quyền"},{"ten":"Đạo lữ (chưa rõ tên)","tag":"the-thiep","quanHe":"Đạo lữ, cùng khai tông lập phái","ghiChu":"Đêm hai mặt trời biến mất, không trở về"},{"ten":"Lão già gầy gò (sĩ tiên)","tag":"cap-tren","quanHe":"Sĩ tiên dưới quyền, chỉ thấp hơn tứ đại chiến tướng"},{"ten":"Chu Tước","tag":"cap-tren","quanHe":"Chiến tướng dưới quyền","ghiChu":"Một trong tứ đại chiến tướng của Thất Đạo Tông."},{"ten":"Huyền Vũ","tag":"cap-tren","quanHe":"Chiến tướng dưới quyền","ghiChu":"Một trong tứ đại chiến tướng."},{"ten":"Thanh Long","tag":"cap-tren","quanHe":"Chiến tướng dưới quyền","ghiChu":"Một trong tứ đại chiến tướng."},{"ten":"Bạch Hổ","tag":"cap-tren","quanHe":"Chiến tướng dưới quyền","ghiChu":"Một trong tứ đại chiến tướng."}],"tuiDo":{}},"nguon":["@c1545","@c1546","@c1568"]},{"id":"cap-song-sinh-gioi-ngoai","name":"Cặp tu sĩ song sinh giới ngoại","gioiTinh":"nam","trangThai":"tu-vong","canhGioiCaoNhat":"Thiên Nhân Nhị Suy","theLuc":[{"ten":"Lang tộc","trangThai":"gan-bo"}],"blurb":"Hai huynh đệ song sinh nổi danh ở Thái Cổ Tinh Thần, tu vi thiên nhân nhị suy, hợp kích có thể chống ngang thiên nhân tam suy. Tính cách tàn bạo, giết nhiều tu sĩ giới nội. Bị Vương Lâm truy sát và diệt cả hai tại Côn Hư tinh vực.","vaiTro":"Tu sĩ giới ngoại song sinh bị Vương Lâm diệt","tinhCach":"Tàn bạo; tình huynh đệ sâu nặng","tabs":{"diem":[{"text":"Hai huynh đệ song sinh mồ côi được dã lang nuôi lớn, từ nhỏ như chỉ có một trái tim chung, hợp kích mạnh ngang thiên nhân tam suy.","chuong":"@c1553"}],"kinhLich":[{"mucCt":"vua","text":"Cảm nhận uy áp của Vương Lâm, hoảng loạn bỏ chạy. Người anh bị chém đầu, người em gào thê lương lao vào Vương Lâm thay vì trốn nhưng cũng bị giết.","anchor":"được dã lang nuôi lớn, từ nhỏ đã như chỉ có một trái tim chung","bridge":true,"khoang":"@c1553"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Kẻ truy sát và giết cả hai"}],"tuiDo":{}},"nguon":["@c1553"]},{"id":"toc-truong-minh-linh-toc","name":"Tộc trưởng Minh Linh tộc","cn":"","aliases":["nam tử đầu trọc tử y"],"gioiTinh":"nam","theLuc":[{"ten":"Minh Linh tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Thiên nhân ngũ suy","trangThai":"tu-vong","vaiTro":"Tộc trưởng Minh Linh tộc, bị Vương Lâm giết","tinhCach":"Tàn nhẫn, tham lam; dám thôn phệ tu sĩ sống để mưu cầu quật khởi cho bộ tộc; hèn nhát khi đối mặt kẻ mạnh hơn","blurb":"Tộc trưởng Minh Linh tộc, tu vi thiên nhân ngũ suy. Lợi dụng giới nội không có giám sát của Trường Tôn hội để thôn phệ nữ tu Triệu Hà, bị Vương Lâm diệt sát.","tabs":{"diem":[{"text":"Tu vi thiên nhân ngũ suy, đầu trọc lốc mặc tử y, có hồn phách thê lương nhô trên đầu","chuong":"@c1555"},{"text":"Lợi dụng giới nội thôn phệ nữ tu bằng thuật Minh phệ cực lạc, bị Vương Lâm nát thân phong ấn nguyên thần vào đầu lâu","chuong":"@c1555"}],"kinhLich":[{"mucCt":"vua","text":"Đang thi triển Minh phệ cực lạc thôn phệ ba trăm nguyên thần nữ tu Triệu Hà thì bị Vương Lâm hừ lạnh đánh tan song chưởng. Nhận ra khí tức quen thuộc trên người Vương Lâm, hoảng sợ ra lệnh tộc nhân rời đi. Bị Vương Lâm một trảo nát thân thể, phong ấn nguyên thần linh hồn vào đầu lâu.","anchor":"Tu vi hắn đã đạt tới thiên nhân ngũ suy","bridge":true,"khoang":"@c1555"}],"tuViMoc":[{"chuong":"@c1555","canhGioi":"Thiên nhân ngũ suy","text":"Tu vi đạt tới thiên nhân ngũ suy.","importance":"minor"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Kẻ giết mình","ghiChu":"Bị Vương Lâm nát thân, phong ấn nguyên thần vào đầu lâu (@c1555)"}],"tuiDo":{}},"nguon":["@c1555"]},{"id":"nam-tu-trung-nien-gioi-ngoai","name":"Nam tử trung niên mặc đạo bào","cn":"","aliases":["tu sĩ giới ngoại Bước thứ ba"],"gioiTinh":"nam","canhGioiCaoNhat":"Bước thứ ba","trangThai":"tu-vong","vaiTro":"Tu sĩ giới ngoại Bước thứ ba, bị Vương Lâm chém đầu","tinhCach":"Thận trọng, ẩn thân quan sát; nhận biết danh hiệu Phong Tôn nhưng không kịp đào thoát","blurb":"Tu sĩ giới ngoại tu vi Bước thứ ba, ẩn thân quan sát trên tu chân tinh. Nhận ra Vương Lâm là Phong Tôn tưởng đã chết, bị bức hiện thân và bị chém đầu.","tabs":{"diem":[{"text":"Nhận ra Vương Lâm là Phong Tôn Vương Lâm tưởng đã chết, kinh ngạc kêu lên trước khi bị diệt","chuong":"@c1555"}],"kinhLich":[{"mucCt":"vua","text":"Ẩn thân quan sát trên tu chân tinh, bị Vương Lâm phóng cơn lốc tử vong bức hiện thân. Triệu hồi tấm khiên mai rùa trăm trượng chống đỡ nhưng bị nhân quả đánh vỡ. Mở hương hỏa giới trên mi tâm muốn phản kháng nhưng bị Định Thần thuật khống chế, bị đánh tan tâm thần rồi chém đầu.","anchor":"Phong Tôn Vương Lâm, ngươi không ngờ lại không chết!","bridge":true,"khoang":"@c1555"}],"tuViMoc":[{"chuong":"@c1555","canhGioi":"Bước thứ ba","text":"Tu vi đạt Bước thứ ba.","importance":"minor"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Kẻ giết mình","ghiChu":"Bị Vương Lâm chém đầu trên tu chân tinh (@c1555)"}],"tuiDo":{}},"nguon":["@c1555"]},{"id":"nu-tu-thanh-y-nu-hoa-tim","name":"Nữ tử thanh y trong nụ hoa tím","gioiTinh":"nữ","aliases":[],"theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Nữ tử xinh đẹp mặc thanh y, ngồi đả tọa bên trong nụ hoa tím khổng lồ tại trung tâm phế tích Phá Thiên Tông trong Vân Hải tinh vực. Có mối liên hệ đặc biệt với biển cây cỏ tím bao phủ phế tích.","vaiTro":"Nhân vật bí ẩn tại phế tích Phá Thiên Tông","tinhCach":"Chưa rõ","tabs":{"diem":[{"text":"Ngồi trong nụ hoa tím mười trượng tại phế tích Phá Thiên Tông, khi thần thức Vương Lâm quét qua thì biển cây cỏ tím đồng loạt chuyển động theo nàng","chuong":"@c1556"}],"kinhLich":[{"importance":"normal","mucCt":"vua","chuong":"@c1556","tieuDe":"Xuất hiện tại phế tích Phá Thiên Tông","text":"Ngồi đả tọa bên trong nụ hoa tím khổng lồ tại trung tâm phế tích Phá Thiên Tông. Khi thần thức Vương Lâm quét qua, mở bừng đôi mắt lộ vẻ khiếp sợ, biển cây cỏ tím trên tu chân tinh đồng loạt chuyển động.","anchor":"nữ tử bên trong nụ hoa mở bừng đôi mắt"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{}},"nguon":["@c1556"]},{"id":"lao-gia-hong-bao-an-ky-doi","name":"Lão già hồng bào (ấn ký dơi đen)","gioiTinh":"nam","aliases":[],"theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Tu sĩ giới ngoại mặc hồng bào, mi tâm mang ấn ký hình dơi đen. Ngồi trên đỉnh đầu pho tượng dơi khổng lồ tại đại lục trôi nổi gần chiến trường giáp giới ngoại trong Vân Hải tinh vực.","vaiTro":"Tu sĩ giới ngoại cấp cao tại Vân Hải","tinhCach":"Chưa rõ","tabs":{"diem":[{"text":"Mi tâm có ấn ký hình dơi đen, chỉ huy xây miếu thờ tượng dơi khổng lồ tại Vân Hải","chuong":"@c1556"}],"kinhLich":[{"importance":"normal","mucCt":"vua","chuong":"@c1556","tieuDe":"Kinh hãi trước thần thức Vương Lâm","text":"Đang ngồi trên đỉnh đầu pho tượng dơi khổng lồ tại đại lục trôi nổi, vô số tu sĩ giới ngoại đang xây miếu. Khi thần thức Vương Lâm quét qua, hoảng sợ đứng phắt dậy, thần sắc trắng bệch.","anchor":"lão già này hoảng sợ mở bừng đôi mắt, đứng phắt dậy nhìn bầu trời, thần sắc trở nên trắng bệch"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{}},"nguon":["@c1556"]},{"id":"nu-tu-ao-hong-la-thien","name":"Nữ tử áo hồng (La Thiên)","gioiTinh":"nữ","aliases":[],"theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Nữ tử mặc áo hồng, thần sắc lạnh lùng, ánh mắt dần dâng lên vẻ tuyệt vọng, đang bị vây khốn bên trong trận pháp tại La Thiên.","vaiTro":"Tu sĩ giới nội bị vây tại La Thiên","tinhCach":"Lạnh lùng","tabs":{"diem":[{"text":"Bị vây trong trận pháp La Thiên, thần sắc lạnh lùng nhưng ánh mắt dần dâng vẻ tuyệt vọng","chuong":"@c1556"}],"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1556","text":"Bị vây khốn bên trong trận pháp 990 tu chân tinh tại La Thiên cùng tu sĩ giới nội.","anchor":"có một nữ tử mặc áo hồng, thần sắc lạnh lùng"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{}},"nguon":["@c1556"]},{"id":"nguoi-ngoi-te-dan-la-thien","name":"Người ngồi trong tế đàn (La Thiên)","gioiTinh":"nam","aliases":[],"theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"khong-ro","blurb":"Nhân vật bí ẩn ngồi bên trong tế đàn hình tròn ở trung tâm trận pháp 990 tu chân tinh tại La Thiên, sương mù bao quanh, chỉ mơ hồ nhìn thấy bóng dáng.","vaiTro":"Nhân vật bí ẩn trung tâm trận pháp La Thiên","tinhCach":"Chưa rõ","tabs":{"diem":[{"text":"Ngồi trong tế đàn sương mù ở trung tâm trận pháp bảo vệ tu sĩ giới nội tại La Thiên, danh tính chưa rõ","chuong":"@c1556"}],"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1556","text":"Ngồi bên trong tế đàn hình tròn ở trung tâm trận pháp 990 tu chân tinh tại La Thiên, sương mù bao quanh.","anchor":"Trên một tu chân tinh khác, những thân ảnh quen thuộc với Vương Lâm đều ở chỗ này"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{}},"nguon":["@c1556"]},{"id":"nu-tu-si-buoc-ba-van-hai","name":"Nữ tử tu sĩ bước thứ ba giới ngoại (Vân Hải)","cn":"","aliases":[],"gioiTinh":"nu","theLuc":[{"ten":"Tu sĩ giới ngoại","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Bước thứ ba","trangThai":"tu-vong","vaiTro":"Tu sĩ giới ngoại bước thứ ba đóng trên tu chân tinh, bị Vương Lâm giết","tinhCach":"Thận trọng, không dám chủ động ra tay cũng không dám bỏ chạy","blurb":"Nữ tu sĩ giới ngoại bước thứ ba đóng trên một tu chân tinh mọc đầy cây cỏ tại Vân Hải tinh vực. Phát hiện thần thức Vương Lâm nhưng không dám ra tay trước, dựa vào tu chân tinh nghênh chiến. Thi triển thần thông biến cả tu chân tinh thành hình đầu nữ tử khổng lồ nhưng bị Vương Lâm một kiếm bổ đôi.","tabs":{"diem":[{"text":"Thi triển thần thông quỷ dị biến cả tu chân tinh thành đầu nữ tử khổng lồ, nhưng bị Vương Lâm đánh giá thần thông không tồi mà tu vi quá yếu, một kiếm chém chết","chuong":"@c1557"}],"kinhLich":[{"chuong":"@c1557","importance":"normal","mucCt":"vua","tieuDe":"Nghênh chiến Vương Lâm, bị một kiếm bổ đôi","text":"Dựa vào tu chân tinh đã nắm giữ hoàn toàn để nghênh chiến Vương Lâm, thi triển thần thông biến cả tu chân tinh thành hình đầu nữ tử khổng lồ. Bị Vương Lâm đánh giá thần thông không tồi nhưng tu vi quá yếu, bị một kiếm bổ đôi tu chân tinh lẫn bổn tôn, đầu lâu bị thu.","anchor":"Thần thông không tồi, nhưng tu vi quá yếu!"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Kẻ giết mình","ghiChu":"Bị Vương Lâm một kiếm bổ đôi chết @c1557"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1557"]},{"id":"lao-gia-tren-pho-tuong-dai-luc","name":"Lão già trên pho tượng (đại lục chạy trốn)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Tu sĩ giới ngoại","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"tu-vong","vaiTro":"Nhân vật trên đại lục giới ngoại đang cố chạy trốn vào Thái Cổ Tinh Thần","tinhCach":"Chưa rõ","blurb":"Lão già ngồi trên pho tượng của đại lục tu sĩ giới ngoại đang cố chạy trốn qua lỗ hổng vào Thái Cổ Tinh Thần. Sắc mặt đại biến khi thấy bánh xe sinh tử của Vương Lâm xuất hiện.","tabs":{"diem":[{"text":"Sắc mặt đại biến khi thấy bánh xe sinh tử của Vương Lâm chậm rãi chuyển động","chuong":"@c1557"}],"kinhLich":[{"chuong":"@c1557","importance":"bridge","mucCt":"gon","text":"Đang trên đại lục cố chạy trốn vào Thái Cổ Tinh Thần thì bị bánh xe sinh tử của Vương Lâm chặn đánh, sắc mặt đại biến.","anchor":"Lão già trên pho tượng sắc mặt đại biến"},{"mucCt":"vua","text":"Gắng gượng chống lại bánh xe sinh tử bằng hắc phong hóa miệng khổng lồ nuốt bánh xe nhưng thất bại, bị đánh bật ra rơi xuống đống đổ nát. Cuối cùng bị Vương Lâm vung tay khiến thân thể nổ tung, nguyên thần bị phong ấn trong đầu lâu.","anchor":"Thân thể lão già kia lập tức nổ tung, huyết nhục văng khắp nơi","bridge":true,"khoang":"@c1558"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Kẻ chặn đánh đại lục","ghiChu":"@c1557"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1557","@c1558"]},{"id":"hu-khong-tu","name":"Hư Không Tử","cn":"虛空子","aliases":["Hư Thần Thiên Tôn"],"gioiTinh":"nam","trangThai":"tu-vong","tabs":{"kinhLich":[{"chuong":"@c1558","importance":"bridge","mucCt":"gon","text":"Được xác nhận đã chết, không có mặt tại trận chiến La Thiên.","anchor":"Hư Thần Thiên Tôn đã chết ra thì toàn bộ đều ở đây"}],"diem":[{"text":"Xuất hiện trước hố đen Đông Hải Triều Tịch trong hình tượng lão giả áo choàng vàng, tu vi được nhận ra ở cảnh giới Toái Niết","chuong":"@c0938"},{"text":"Nhiều lần sinh sát khí với Vương Lâm trong động phủ Tiên Đế, thi triển thần thông bão cát và tách phân thân nguyên thần nhưng đều bị Vương Lâm phá giải, liên tiếp trọng thương","chuong":"@c0984"},{"text":"Tu vi rơi từ Toái Niết xuống Tịnh Niết đỉnh, tự bạo thân thể dẫn Thiên Nhân đệ nhất suy khiến nguyên thần huyễn hóa, rơi vào trạng thái điên cuồng mất kiểm soát","chuong":"@c0999"},{"text":"Bị lực Tàn Dạ giết chết trong tình trạng suy kiệt vì Thiên Nhân nhất suy, kết thúc sinh mệnh tại động phủ Tiên Đế","chuong":"@c1003"},{"text":"Hồn phách bị giam vào tầng mười tám Thập Bát Địa Ngục Phong Tiên Ấn, sau đó nhiều lần bị Vương Lâm triệu ra làm chiến hồn bằng thuật Tát Đậu Thành Binh","chuong":"@c1005"},{"text":"Được xác nhận đã bỏ mình sau trận chiến động phủ Tiên Đế, tin tức lan truyền khắp Liên Minh Tinh","chuong":"@c1015"}]},"nguon":["@c1558"],"vaiTro":"Đại trưởng lão Tu Chân Liên Minh — cường giả Toái Niết tử trận tại động phủ Tiên Đế","tinhCach":"Thâm trầm mưu lược, kín đáo giấu sát khí và liên tục tính toán trừ khử mối nguy tiềm tàng; kiêu ngạo cậy mạnh nhưng phán đoán sai lầm liên tiếp trước Vương Lâm; cuồng sát mất kiểm soát khi tâm thần bị Thiên Nhân đệ nhất suy huyễn hóa chi phối","blurb":"Hư Không Tử là đại trưởng lão áo choàng vàng của Tu Chân Liên Minh, tu vi Toái Niết, theo nhóm cường giả tiến vào hố đen Đông Hải Triều Tịch rồi thâm nhập động phủ Tiên Đế. Trong động phủ, ông nhiều lần nảy sinh sát khí truy sát Vương Lâm nhưng đều thất bại, liên tiếp bị trọng thương khiến tu vi rơi từ Toái Niết xuống Tịnh Niết đỉnh, sau đó tự bạo thân thể dẫn Thiên Nhân đệ nhất suy khiến nguyên thần huyễn hóa và rơi vào trạng thái điên cuồng không thể tự chủ. Cuối cùng ông bị lực Tàn Dạ giết chết trong lúc suy kiệt, hồn phách bị giam vào tầng mười tám Thập Bát Địa Ngục Phong Tiên Ấn và nhiều "},{"id":"van-lac","name":"Vân Lạc đại ti","aliases":["Phân thân Vân Lạc đại ti"],"gioiTinh":"nu","trangThai":"song","tabs":{"kinhLich":[{"mucCt":"vua","text":"Phân thân Vân Lạc đại ti có mặt trong đám tu sĩ giới ngoại bao vây La Thiên, thần sắc sầu lo nhìn tinh trận giới nội. Bổn tôn Vân Lạc đại ti đã tử vong, đây là phân thân còn sót lại.","anchor":"Nàng chính là phân thân của Vân Lạc đại ti mà bổn tôn đã tử vong","bridge":true,"khoang":"@c1558"},{"mucCt":"ky","text":"Vân Lạc đại ti nén sầu lo, hồi tưởng cảnh năm xưa khi tính toán tương lai thấy bóng Cổ Thần hủy diệt Thái Cổ Tinh Thần của giới ngoại. Nàng chỉ tay ra lệnh đại quân tám hướng công kích khu vực phòng thủ cuối cùng giới nội. Sầu lo trong lòng càng ngày càng đậm, tự hỏi tương lai đã tính là thật hay giả.","anchor":"Sầu lo trong lòng Vân Lạc đại ti theo thời gian trôi qua càng ngày càng đậm","bridge":true,"khoang":"@c1559"},{"mucCt":"vua","text":"Ở phía xa thân thể run rẩy không thể khống chế. Nhìn bóng lưng Vương Lâm, nhận ra đây chính là người mà nàng khi tính toán đã nhìn thấy — Người hủy diệt thiên địa.","anchor":"Bóng lưng này chính là của người mà nàng khi tính toán đã nhìn thấy - Người hủy diệt thiên địa!","bridge":true,"khoang":"@c1561"},{"chuong":"@c1566","importance":"normal","mucCt":"vua","tieuDe":"Bóp nát ngọc giản thoát mạng khỏi bánh xe vận mệnh","text":"Khi Vương Lâm đánh tan chưởng Chưởng Tôn, lập tức bóp nát ngọc giản bảo mạng do sư tôn trước khi chết tế luyện, na di về tế đàn tộc trong Thái Cổ Tinh Thần. Là người duy nhất trong tu sĩ giới ngoại sống sót dưới bánh xe vận mệnh ngoài một tiên phi xé khe không gian chạy thoát.","anchor":"Vân Lạc đại ti liền không chút do dự bóp nát ngọc giản bảo vệ tính mạng mà sư tôn năm đó lưu lại"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Người nàng kiêng kỵ nhất","ghiChu":"Kiêng kỵ sâu sắc từ năm đó"}],"tuViMoc":[],"diem":[{"text":"Dùng Thuật Thiên Đại Tinh Thần thôi diễn quả cầu nước hiển hiện hình bóng Vương Lâm, suy tính ra khí tức và tung tích của hắn để hỗ trợ Tư Mặc Tử truy sát","chuong":"@c1281"},{"text":"Bị lực lượng bí ẩn phản phệ khi thôi diễn bí ẩn cây hương trên Đại Đế tinh, tay phải rách nát nôn máu, trong cảnh hư ảo thấy dự tượng hạo kiếp Thái Cổ Tinh Thần","chuong":"@c1322"},{"text":"Chỉ huy đại quân giới ngoại bày bẫy liên hoàn truy sát Vương Lâm, điều khiển toàn quân phân bốn hướng và tiên tri tiên cơ để phục kích Hồng Sam Tử","chuong":"@c1429"},{"text":"Phân thân trên chiến trường bị Khai Thiên Phủ chém nát huyết thuẫn bát giác rồi xuyên thấu, thân thể hóa tan, bổn tôn bị diệt nhưng hồn phách thoát đi","chuong":"@c1433"},{"text":"Nhận ra Vương Lâm chính là bóng hình đáng sợ từng thấy trong thôi diễn, thân thể run rẩy không thể khống chế","chuong":"@c1561"},{"text":"Bóp nát ngọc giản bảo mạng do sư tôn trước khi chết tế luyện để thoát khỏi bánh xe vận mệnh của Vương Lâm","chuong":"@c1566"}]},"nguon":["@c1558","@c1559","@c1561","@c1566"],"canhGioiCaoNhat":"Không rõ (bậc cao giới ngoại)","cn":"云落","vaiTro":"Đại Tư của Trường Tôn Hội — chuyên gia thôi diễn tinh thần, chỉ huy quân sự giới ngoại","tinhCach":"Tinh thông thuật toán thôi diễn, suy tính tung tích và bí ẩn với độ chính xác cao; hành sự âm trầm kín kẽ, thường giấu tay bắt ấn quyết ngay giữa đám đông; kiên trì truy xét và chỉ huy quyết đoán dù liên tục bị phản phệ trọng thương; dễ hoảng loạn khiếp sợ khi biến cố vượt ngoài dự liệu hoặc đối diệ","blurb":"Vân Lạc là Đại Tư của Trường Tôn Hội, sở hữu Thuật Thiên Đại Tinh Thần có thể thôi diễn hình ảnh, ký ức và tung tích mục tiêu. Nàng tính ra hình dáng cùng khí tức của Vương Lâm để hỗ trợ Tư Mặc Tử truy sát, đồng hành tới Đại Đế tinh bái kiến đại đế, và tại đó nhiều lần âm thầm thôi diễn bí ẩn liên quan tới hạo kiếp Thái Cổ Tinh Thần nhưng liên tục bị lực lượng bí ẩn cắt đứt phép tính và phản phệ trọng thương. Sau khi bế quan hồi phục, nàng tái xuất với vai trò chỉ huy đại quân giới ngoại tấn công Vương Lâm, bày bẫy liên hoàn nhưng phân thân bị Khai Thiên Phủ chém nát; về sau phân thân của nàng"},{"id":"ba-lao-gioi-ngoai","name":"Bà lão (giới ngoại, đại kiếp sinh tử)","gioiTinh":"nu","trangThai":"song","theLuc":[{"ten":"Giới ngoại","trangThai":"gan-bo"}],"blurb":"Một trong năm bậc toàn năng Không Huyền phe giới ngoại, từng tham gia trận đánh sinh tử năm đó với Vương Lâm. Có mặt tại La Thiên bao vây tinh trận giới nội.","vaiTro":"Bậc toàn năng Không Huyền giới ngoại, đối thủ cũ của Vương Lâm","tinhCach":"Chưa rõ","tabs":{"diem":[{"text":"Bậc toàn năng cấp Không Huyền, từng tham gia đại kiếp sinh tử với Vương Lâm","chuong":"@c1558"}],"kinhLich":[{"mucCt":"gon","text":"Là một trong năm bậc toàn năng Không Huyền giới ngoại có mặt tại La Thiên, ngăn cản giới nội đồng quy vu tận.","anchor":"bà lão và lão già áo đen trong trận chiến sinh tử năm đó với hắn","bridge":true,"khoang":"@c1558"},{"chuong":"@c1559","importance":"bridge","mucCt":"gon","text":"Cười lạnh đón Hồng Sam Tử khi hắn rời tế đàn ra ngoài.","anchor":"Bà lão bước thứ ba của giới ngoại cười lạnh đón hắn"},{"chuong":"@c1561","importance":"bridge","mucCt":"gon","text":"Sắc mặt tái nhợt, sợ hãi vô tận trước uy lực mũi tên Vương Lâm.","anchor":"Một mũi tên đó đã dọa cho bà ta chết khiếp!"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối thủ trong đại kiếp sinh tử năm đó"}],"tuiDo":{}},"nguon":["@c1558","@c1559","@c1561"]},{"id":"lao-gia-ao-den-gioi-ngoai","name":"Lão già áo đen (giới ngoại, đại kiếp sinh tử)","gioiTinh":"nam","trangThai":"song","theLuc":[{"ten":"Giới ngoại","trangThai":"gan-bo"}],"blurb":"Một trong năm bậc toàn năng Không Huyền phe giới ngoại, từng tham gia trận chiến sinh tử với Vương Lâm. Có mặt tại La Thiên bao vây tinh trận giới nội.","vaiTro":"Bậc toàn năng Không Huyền giới ngoại, đối thủ cũ của Vương Lâm","tinhCach":"Chưa rõ","tabs":{"diem":[{"text":"Bậc toàn năng cấp Không Huyền, từng tham gia đại kiếp sinh tử với Vương Lâm","chuong":"@c1558"}],"kinhLich":[{"mucCt":"gon","text":"Là một trong năm bậc toàn năng Không Huyền giới ngoại có mặt tại La Thiên, ngăn cản giới nội đồng quy vu tận.","anchor":"bà lão và lão già áo đen trong trận chiến sinh tử năm đó với hắn","bridge":true,"khoang":"@c1558"},{"chuong":"@c1561","importance":"bridge","mucCt":"gon","text":"Thần sắc hoảng hốt khi nhìn uy lực mũi tên Vương Lâm như nhìn thấy tử thần.","anchor":"Một mũi tên đó đã dọa cho bà ta chết khiếp!"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối thủ trong đại kiếp sinh tử năm đó"}],"tuiDo":{}},"nguon":["@c1558","@c1561"]},{"id":"quy-phu-ao-tim-gioi-ngoai","name":"Quý phụ áo tím (giới ngoại)","gioiTinh":"nu","trangThai":"song","theLuc":[{"ten":"Giới ngoại","trangThai":"gan-bo"}],"blurb":"Một trong năm bậc toàn năng Không Huyền phe giới ngoại có mặt tại La Thiên. Mặc áo tím, trông như một quý phụ.","vaiTro":"Bậc toàn năng Không Huyền giới ngoại","tinhCach":"Chưa rõ","tabs":{"diem":[{"text":"Bậc toàn năng cấp Không Huyền giới ngoại, có mặt tại La Thiên bao vây giới nội","chuong":"@c1558"}],"kinhLich":[{"chuong":"@c1558","importance":"normal","mucCt":"gon","tieuDe":"Có mặt tại La Thiên bao vây giới nội","text":"Là một trong năm bậc toàn năng Không Huyền giới ngoại ngồi bốn phía phiêu phù, ngăn cản giới nội đồng quy vu tận.","anchor":"còn có một người mặc áo tím trông như một quý phụ"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{}},"nguon":["@c1558"]},{"id":"dao-phi-hu","name":"Đạo Phi Hủ","aliases":["Thanh niên mắt dâm tà"],"gioiTinh":"nam","canhGioiCaoNhat":"Toàn năng dưới Không Huyền","trangThai":"tu-vong","theLuc":[{"ten":"Phi tộc","trangThai":"gan-bo"},{"ten":"Giới ngoại","trangThai":"gan-bo"}],"vaiTro":"Tộc trưởng Phi tộc giới ngoại, một trong bảy bậc toàn năng dưới Không Huyền","tinhCach":"Tàn nhẫn dâm tà; thích cả nữ nhân lẫn nam tử tuấn kiệt; ngạo mạn khinh người","blurb":"Tộc trưởng Phi tộc của giới ngoại, một trong bảy bậc toàn năng dưới Không Huyền. Am hiểu thuật song tu, tính cách tàn nhẫn dâm tà, từng đuổi giết Mộc Băng Mi.","tabs":{"diem":[{"text":"Một trong bảy bậc toàn năng dưới Không Huyền của giới ngoại, tộc trưởng Phi tộc.","chuong":"@c1559"},{"text":"Am hiểu thuật song tu, tính cách tàn nhẫn dâm tà, thích cả nam lẫn nữ.","chuong":"@c1559"}],"kinhLich":[{"mucCt":"ky","text":"Đứng ngoài màn sáng tu chân tinh Thần Tông, dùng oan hồn nữ tử tạo thần thông công kích. Nhạo Mộc Băng Mi là hồng nhan của Phong Tôn đã chết, tuyên bố muốn song tu với nàng. Từng đuổi giết Mộc Băng Mi nhưng bị Thanh Thủy cản.","anchor":"Thanh niên này chính là một trong bảy bậc toàn năng dưới không Huyền","bridge":true,"khoang":"@c1559"},{"mucCt":"gon","text":"Phá màn sáng tu chân tinh Mộc Băng Mi, vung tay áo cuốn hết tu sĩ chỉ để lại nàng, từng bước đi tới tuyên bố sẽ chiếm đoạt hồng nhan của Phong Tôn.","anchor":"Hồng nhan của Phong Tôn nhất định sẽ khiến bổn công tử rất thoải mái","bridge":true,"khoang":"@c1560"},{"mucCt":"vua","text":"Ở trên tu chân tinh cách Mộc Băng Mi không tới mười trượng, cảm nhận khí tức kinh hãi, da đầu tê dại. Cuối chương bị Vương Lâm nhìn thẳng, sững người trước lời đe dọa.","anchor":"Đạo Phi Hủ đang ở trên một tu chân tinh, còn cách Mộc Băng Mi ngoài mười trượng, đang bị dọa sững người ra đó","bridge":true,"khoang":"@c1561"},{"chuong":"@c1562","importance":"normal","mucCt":"ky","tieuDe":"Tử vong dưới tay Vương Lâm","text":"Kinh hãi trước uy lực Vương Lâm giết Chưởng Tôn bằng một tiễn, hối hận vì đã trêu chọc Mộc Băng Mi và có ý tục tĩu với Phong Tôn. Tuyệt vọng lao về phía Mộc Băng Mi định bắt nàng làm con tin nhưng bị Vương Lâm chặn đứng. Bị phá nát tứ chi, vỗ mi tâm khiến thân thể nổ tung, nguyên thần bị bóp nát — hoàn toàn tử vong.","anchor":"một bậc toàn năng bước thứ ba Không Niết đã hoàn toàn tử vong"}],"tuViMoc":[],"nhanMach":[{"ten":"Mộc Băng Mi","tag":"doi-thu","quanHe":"Đối tượng muốn ép song tu, từng đuổi giết"},{"ten":"Thanh Thủy","tag":"doi-thu","quanHe":"Thanh Thủy từng cứu Mộc Băng Mi khỏi tay hắn"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1559","@c1560","@c1561","@c1562"],"cn":"道非朽"},{"id":"nu-tu-ao-hong-con-hu","name":"Nữ tử áo hồng","aliases":["Phấn y nữ tử"],"gioiTinh":"nữ","canhGioiCaoNhat":"Không rõ","trangThai":"song","theLuc":[{"ten":"Tu Chân Liên Minh","trangThai":"gan-bo"},{"ten":"Côn Hư","trangThai":"gan-bo"}],"vaiTro":"Nữ tử ẩn danh dẫn đầu tàn binh Tu Chân Liên Minh từ Côn Hư, nghi là nữ nhi Thanh Thủy","tinhCach":"Can đảm quyết tử cùng đồng đạo dù tu vi không cao; mang tâm sự giấu kín với Thanh Thủy; từng quen biết Vương Lâm từ trước","blurb":"Nữ tử áo hồng dẫn gần ba nghìn tu sĩ Tu Chân Liên Minh còn sót lại từ Côn Hư đứng trên tu chân tinh đã bị phá. Dù tu vi không cao, nàng quyết cùng sống chết với giới nội, bước về phía trước đỡ Thanh Thủy bị thương. Sau khi Vương Lâm xuất hiện giết hai bậc toàn năng và cứu chữa Thanh Thủy, nàng xác nhận đã sớm quen biết hắn, đồng thời hỏi Thanh Thủy vì sao cứu nàng nhưng không nhận được câu trả lời.","tabs":{"diem":[{"text":"Dẫn gần ba nghìn tu sĩ Tu Chân Liên Minh từ Côn Hư đứng trên tu chân tinh, uể oải chấp nhận kết cục","chuong":"@c1559"},{"text":"Tu vi không cao nhưng quyết cùng giới nội sống chết, bước về phía trước đỡ Thanh Thủy","chuong":"@c1560"},{"text":"Dìu Thanh Thủy, ngước mắt ngời sáng nhìn về phía mũi tên Vương Lâm","chuong":"@c1561"},{"text":"Chứng kiến Vương Lâm giết hai bậc toàn năng và cứu chữa Thanh Thủy","chuong":"@c1562"},{"text":"Xác nhận đã sớm quen biết Vương Lâm; hỏi Thanh Thủy vì sao cứu nàng nhưng không được trả lời","chuong":"@c1566"}],"kinhLich":[{"mucCt":"ky","text":"Đứng trên tu chân tinh cùng gần ba nghìn tu sĩ Tu Chân Liên Minh từ Côn Hư. Uể oải chấp nhận kết cục, thì thầm rằng còn chưa nói cho hắn biết mình là ai. Màn sáng tu chân tinh bị đại hán dùng phong lôi phá tan, đại hán kéo mấy vạn tu sĩ lao tới.","anchor":"ta còn chưa nói cho hắn biết ta là ai","bridge":true,"khoang":"@c1559"},{"mucCt":"vua","text":"Đứng trên tu chân tinh bị phá, tu vi không cao nhưng quyết cùng giới nội sống chết, bước về phía trước. Đỡ Thanh Thủy khi hắn ngã xuống sau trận chiến, hỏi hắn tại sao liều mạng bảo vệ nàng.","anchor":"Tu vi nàng không cao nhưng nàng là người giới nội","bridge":true,"khoang":"@c1560"},{"chuong":"@c1561","importance":"bridge","mucCt":"gon","text":"Đang dìu Thanh Thủy, ngước mắt nhìn ngời sáng về phía mũi tên Vương Lâm.","anchor":"tâm thần lại cảm nhận được một luồng khí tức quen thuộc tới cực điểm"},{"chuong":"@c1562","importance":"bridge","mucCt":"gon","text":"Đứng bên cạnh Thanh Thủy, kinh ngạc chứng kiến Vương Lâm giết hai bậc toàn năng rồi cứu chữa Thanh Thủy, bị Vương Lâm liếc qua trước khi rời đi.","anchor":"Vương Lâm nhìn lướt quá nữ tử áo hồng đang kinh ngạc bên cạnh Thanh Thủy"},{"mucCt":"vua","text":"Nhìn theo Vương Lâm rời đi, xác nhận đã sớm quen biết hắn. Hỏi Thanh Thủy vì sao cứu nàng nhưng không được trả lời. Cúi chào rồi rời đi đuổi theo Vương Lâm.","anchor":"khi nhận ra đối phương là nữ nhi của mình hắn đã nói rồi","bridge":true,"khoang":"@c1566"}],"tuViMoc":[],"nhanMach":[{"ten":"Thanh Thủy","tag":"khac","quanHe":"Thanh Thủy nhìn về phía nàng với ánh mắt nhu hòa, gợi ý là cha con"},{"ten":"Thanh Thủy","tag":"cha-me","quanHe":"Phụ thân (nàng mang khí tức hồn phách nữ nhi của Thanh Thủy)","ghiChu":"Bí mật không ai biết kể cả Vương Lâm"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1559","@c1560","@c1561","@c1562","@c1566"]},{"id":"lao-gia-ao-den","name":"Lão giả áo đen","gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1559","importance":"bridge","mucCt":"vua","text":"Giao chiến với Thanh Lâm, thụt lui trăm trượng nhưng bắt quyết phản công bằng hắc vụ.","anchor":"Lão già mặc áo đen đã từng vây sát Vương Lâm bước tới"},{"mucCt":"vua","text":"Thừa lúc Vương Lâm bị thương mà đánh lén bằng kiếm khí. Bị Nhân Quả trận phá kiếm khí, bị Sinh Tử Ấn đánh phun máu, bị Nhân Quả Ấn kéo bổn nguyên ra bóp nát một phần, bị Thất Thải Đinh đâm ngực, cuối cùng bị Thiên Hoàng Lô thôn phệ trấn áp vạn vạn năm.","anchor":"Tiên phi khó giết, nhưng giết một kẻ Không Huyền sơ kỳ thì không khó!","bridge":true,"khoang":"@c1564"}],"diem":[{"text":"Một ngón tay xuyên sọ giết chết thượng cổ tu sĩ áo đỏ tóc râu đỏ trong hư vô","chuong":"@c1059"},{"text":"Thi triển thần thông Súc Thốn Thành Không, co rút cả thế giới thành một thiên địa thu nhỏ","chuong":"@c1062"},{"text":"Rút kiếm gãy phun máu kích hoạt, chống Thác Sâm xuyên thấu vòng xoáy để cứu Viêm Lôi Tử","chuong":"@c1066"},{"text":"Dẫn đầu sáu trưởng lão Vô Cực Tông vây công Vương Lâm, định bắt giao cho Thần Tông","chuong":"@c1218"},{"text":"Đánh lén Vương Lâm lúc bị thương bằng kiếm khí, bị Nhân Quả trận phá giải và Sinh Tử Ấn đánh phun máu","chuong":"@c1564"},{"text":"Phân thân bước thứ ba lao tới cửa Thiên Nghịch bị ánh sáng thiêu đốt tiêu tán","chuong":"@c1151"}]},"nguon":["@c1559","@c1564"],"vaiTro":"Đại năng bí ẩn của Liên Minh — tu vi Không Niết, trưởng lão Vô Cực Tông","tinhCach":"Thâm trầm bình tĩnh, quan sát kỹ trước khi ra tay; dứt khoát tàn nhẫn khi động thủ; mưu tính sâu xa, biết toan tính lợi hại; không ngại đánh lén khi có cơ hội","blurb":"Lão giả áo đen là đại năng bí ẩn cư tại tây bộ Liên Minh tinh vực, tu vi đạt tới Không Niết, nắm giữ thần thông Súc Thốn Thành Không có thể co rút cả thiên địa và bước một bước vượt vô số khoảng cách. Lão từng một ngón tay giết chết thượng cổ tu sĩ, rút kiếm gãy chống Thác Sâm cứu Viêm Lôi Tử, sau đó lộ diện với thân phận trưởng lão Vô Cực Tông dẫn đầu vây công Vương Lâm. Về sau lão nhiều lần giao chiến với các cường giả khác, từng đánh lén Vương Lâm lúc bị thương nhưng bị Sinh Tử Ấn đánh phun máu, trong khi phân thân của lão bị ánh sáng thiêu đốt tiêu tán trước cửa Thiên Nghịch."},{"id":"dai-han-toan-nang-gioi-ngoai","name":"Đại hán hung tàn (bậc toàn năng giới ngoại)","gioiTinh":"nam","canhGioiCaoNhat":"Toàn năng dưới Không Huyền","trangThai":"tu-vong","theLuc":[{"ten":"Giới ngoại","trangThai":"gan-bo"}],"vaiTro":"Một trong bảy bậc toàn năng giới ngoại dưới Không Huyền","tinhCach":"Hung tàn; cười điên cuồng","blurb":"Một trong bảy bậc toàn năng giới ngoại, thân thể khôi ngô như ngọn hung sơn, dùng phong lôi cuồn cuộn phá tan màn sáng tu chân tinh nữ tử áo hồng.","tabs":{"diem":[{"text":"Một trong bảy bậc toàn năng dưới Không Huyền, sức mạnh phong lôi một công kích bằng mấy vạn tu sĩ.","chuong":"@c1559"}],"kinhLich":[{"mucCt":"gon","text":"Dùng phong lôi cuồn cuộn phá tan màn sáng tu chân tinh nữ tử áo hồng, kéo mấy vạn tu sĩ lao tới trong tiếng cười điên cuồng.","anchor":"Người này cũng là một trong bảy bậc toàn năng","bridge":true,"khoang":"@c1559"},{"mucCt":"vua","text":"Triệu hồi Lôi Long màu đen dài vạn trượng tấn công tu chân tinh, nhưng bị Thanh Thủy xé nát Lôi Long và chém vết thương từ mi tâm tới ngực suýt chết. Sau khi Thanh Thủy sụp đổ, hồi phục và lao tới tấn công hai phụ tử.","anchor":"Tu vi Không Niết cơ hồ không người nào là đối thủ của Thanh Thủy","bridge":true,"khoang":"@c1560"},{"chuong":"@c1561","importance":"bridge","mucCt":"gon","text":"Đang tiến tới gần Thanh Thủy thì quay phắt đầu lại kinh sợ khi cảm nhận khí tức mũi tên Vương Lâm.","anchor":"Nàng mặc dù không phải là hồng nhan của ta nhưng lại là mẫu thân của con trai Vương Bình của ta"},{"chuong":"@c1562","importance":"normal","mucCt":"ky","tieuDe":"Bị Vương Lâm hủy diệt hoàn toàn","text":"Bỏ chạy sau khi chứng kiến Đạo Phi Hủ bị giết, thi triển cơn lốc máu kết hợp lôi cầu đỏ nhưng hoàn toàn vô dụng trước lôi bổn nguyên đại thành viên mãn của Vương Lâm. Bị Vương Lâm điểm vào cổ, hút sạch máu huyết, sinh cơ, xương cốt, nguyên thần — toàn bộ tiêu tan thành quả cầu sương mù. Trừng phạt vì tội đánh thương Thanh Thủy.","anchor":"tận mắt nhìn thấy một bậc toàn năng bước thứ ba Không Niết thân thể dưới lực hút trên ngón tay của Vương Lâm toàn bộ tiêu tan"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1559","@c1560","@c1561","@c1562"],"aliases":["Đại hán phong lôi"]},{"id":"tien-phi-that-dao-tong","name":"Tiên phi (phi tử tông chủ Thất Đạo Tông)","aliases":["Tiên phi từng hủy ngũ tạng Vương Lâm"],"gioiTinh":"nữ","canhGioiCaoNhat":"Không Huyền trung kỳ","trangThai":"tu-vong","theLuc":[{"ten":"Giới ngoại","trangThai":"gan-bo"}],"vaiTro":"Bậc toàn năng Không Huyền giới ngoại, từng hủy ngũ tạng Vương Lâm","blurb":"Một trong mấy bậc toàn năng Không Huyền giới ngoại, từng hủy ngũ tạng Vương Lâm. Cười duyên đón đánh nữ tử tử y từ Triệu Hà.","tabs":{"diem":[{"text":"Từng hủy ngũ tạng Vương Lâm, là bậc toàn năng Không Huyền giới ngoại.","chuong":"@c1559"}],"kinhLich":[{"chuong":"@c1559","importance":"bridge","mucCt":"gon","text":"Cười duyên đón đánh nữ tử tử y từ Triệu Hà khi nàng xuất trận.","anchor":"tiên phi năm đó hủy ngũ tạng của Vương Lâm thân thể liền mờ ảo hiện ra"},{"chuong":"@c1563","importance":"normal","mucCt":"ky","tieuDe":"Bị Vương Lâm áp đảo và hé lộ thân phận","text":"Thi triển cổ cầm phóng sóng âm và ngũ tạng thuật (tâm, can, tỳ, phế, thận) nhằm vào Vương Lâm nhưng bị ngạnh kháng bằng thân thể Cổ Thần. Bị quyền thuật dung hợp Đạo cổ và tam tộc cổ đánh phun máu đẩy lùi. Cầu xin hòa giải bị phớt lờ, hoảng sợ bỏ chạy khi thấy Xạ Thần xa. Bị Định khống chế tạm thời, bị tiên thuật Âm Nguyệt Hữu Tình xé tan dung nhan tuyệt mỹ. Phản kích tuyệt vọng nhưng bị Dịch Linh Ấn đẩy lùi phun máu. Bị Vương Lâm hé lộ thân phận phi tử tông chủ Thất Đạo Tông, tu sĩ Tiên Cương đại lục, kịch chấn sững lại. Cuối chương bị Vương Lâm rút huyết kiếm chém xuống, kết quả chưa rõ.","anchor":"Ngươi là phi tử của tông chủ Thất Đạo Tông -Tu sĩ Tiên Cương đại lục, ngươi tưởng Vương mỗ không biết sao!"},{"chuong":"@c1564","importance":"normal","mucCt":"gon","tieuDe":"Bị Vương Lâm hạ sát, hình thần câu diệt","text":"Bị Dịch Linh Ấn và huyết kiếm phối hợp đánh trúng, hình thần câu diệt. Trước khi chết vẫn thi triển thần thông huyết mạch tiên nhân gây thương tích cho Vương Lâm.","anchor":"thân thể run lên lập tức tan nát, hình thần câu diệt!"},{"chuong":"@c1565","importance":"normal","mucCt":"vua","tieuDe":"Dùng thần thông tổn mệnh thoát thân","text":"Tu sĩ Không Huyền giới ngoại duy nhất sống sót trong toàn bộ hơn mười vạn tu sĩ giới ngoại. Dùng thần thông tổn mệnh của Tiên Cương đại lục mở khe không gian, sắc mặt tái nhợt nhanh chóng bước vào trốn thoát.","anchor":"chỉ còn mỗi tiên phi duy nhất còn lại, ở trong lực lượng dung hợp nguyên thần của tất cả tu sĩ giới nội đã sớm dựa vào thần thông tổn mệnh của Tiên Cương đại lục mà mở ra một cái khe"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1559","@c1563","@c1564","@c1565"]},{"id":"lao-gia-ao-lam-toan-nang","name":"Lão già áo lam (toàn năng giới ngoại)","gioiTinh":"nam","canhGioiCaoNhat":"Toàn năng (giới ngoại)","trangThai":"song","theLuc":[{"ten":"Giới ngoại","trangThai":"gan-bo"}],"vaiTro":"Bậc toàn năng giới ngoại, vung tay hủy diệt tu chân tinh","blurb":"Bậc toàn năng giới ngoại, vung tay hủy diệt một tu chân tinh và mấy ngàn tu sĩ giới nội.","tabs":{"diem":[{"text":"Vung tay hủy diệt một tu chân tinh, giết mấy ngàn tu sĩ giới nội.","chuong":"@c1559"}],"kinhLich":[{"chuong":"@c1559","importance":"bridge","mucCt":"gon","text":"Vung tay hủy diệt một tu chân tinh, giết mấy ngàn tu sĩ giới nội.","anchor":"dưới một cái vung tay của một lão già áo lam liền lập tức tử vong"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1559"]},{"id":"lao-gia-bach-mi-than-tong","name":"Lão già bạch mi (Thần Tông)","gioiTinh":"nam","canhGioiCaoNhat":"Không rõ","trangThai":"song","theLuc":[{"ten":"Thần Tông","trangThai":"gan-bo"}],"vaiTro":"Tu sĩ Thần Tông bên cạnh Mộc Băng Mi","blurb":"Tu sĩ Thần Tông bạch mi, khuyên tông chủ Mộc Băng Mi vào tế đàn, tin rằng Phong Tôn chưa chết.","tabs":{"diem":[{"text":"Tin rằng Phong Tôn chưa chết, khuyên tông chủ lui vào tế đàn.","chuong":"@c1559"}],"kinhLich":[{"chuong":"@c1559","importance":"bridge","mucCt":"gon","text":"Khuyên Mộc Băng Mi lui vào tế đàn trung tâm, tuyên bố không tin Phong Tôn đã chết.","anchor":"Lão phu không tin Phong Tôn đã chết"}],"tuViMoc":[],"nhanMach":[{"ten":"Mộc Băng Mi","tag":"cap-tren","quanHe":"Tông chủ Thần Tông, hắn khuyên nàng lui"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1559"]},{"id":"trieu-ha","name":"Triệu Hà","gioiTinh":"nu","tabs":{"kinhLich":[{"chuong":"@c1563","importance":"bridge","mucCt":"gon","text":"Cùng xông ra từ tinh trận tham gia quyết chiến với tu sĩ giới ngoại.","anchor":"còn có nữ tử Triệu Hà"},{"chuong":"@c1564","importance":"bridge","mucCt":"gon","text":"Như la sát giao chiến với mấy tu sĩ Không Niết giới ngoại, sau đó nhận lệnh Vương Lâm liên thủ chặn hai Không Huyền cuối cùng.","anchor":"nữ tu Triệu Hà giống như la sát đang cùng với mấy tu sĩ Không Niết ầm ầm chiến đấu"},{"chuong":"@c1565","importance":"bridge","mucCt":"gon","text":"Nữ tử Triệu Hà xuất nguyên thần cùng Hồng Sam Tử, Thanh Lâm, Thanh Thủy đẩy bánh xe vòng ba.","anchor":"Hồng Sam Tử và nữ tử của Triệu Hà kia cũng đồng thời nhắm hai mắt"}],"nhanMach":[],"tuViMoc":[],"diem":[{"text":"Cùng La Thiên và mấy ngàn tu sĩ Vân Hải truy kích chém giết tu sĩ giới ngoại trong giới nội, giết đến đỏ cả mắt","chuong":"@c1435"},{"text":"Phối hợp cùng Tử Mộng và các cao thủ giới nội tấn công bàn tay khổng lồ","chuong":"@c1438"},{"text":"Xông ra từ tinh trận tham gia quyết chiến với tu sĩ giới ngoại","chuong":"@c1563"},{"text":"Như la sát giao chiến với tu sĩ Không Niết giới ngoại, nhận lệnh Vương Lâm liên thủ chặn hai Không Niết","chuong":"@c1564"},{"text":"Xuất nguyên thần cùng Hồng Sam Tử, Thanh Lâm, Thanh Thủy đẩy bánh xe vòng ba","chuong":"@c1565"}]},"nguon":["@c1563","@c1564","@c1565"],"cn":"赵霞","vaiTro":"Nữ tu sĩ giới nội Vân Hải — chiến tướng tham gia nhiều trận quyết chiến với giới ngoại","tinhCach":"Hung hãn trong chiến đấu, giết đến đỏ cả mắt; quyết liệt diệt trừ ngoại địch; dũng mãnh như la sát","blurb":"Triệu Hà là nữ tu sĩ thuộc giới nội Vân Hải, tham chiến xuyên suốt cuộc đại chiến với giới ngoại. Cô từng cùng La Thiên truy kích chém giết hàng ngàn tu sĩ giới ngoại, phối hợp tấn công bàn tay khổng lồ cùng Tử Mộng, và sau đó giao chiến như la sát với tu sĩ Không Niết giới ngoại trước khi xuất nguyên thần đẩy bánh xe vòng ba."},{"id":"tien-phi-ao-lam","name":"Tiên phi áo lam","gioiTinh":"nu","theLuc":[{"ten":"Giới ngoại","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Tiên phi","trangThai":"song","vaiTro":"Tiên phi giới ngoại, bị Vương Lâm trấn áp trong Thiên Hoàng Lô","tinhCach":"Hung hãn; quyết đoán bỏ đối thủ cũ để vây công kẻ nguy hiểm hơn","blurb":"Nữ tử mặc áo lam, một trong các tiên phi giới ngoại tham gia đại chiến tại Chu Tước Tinh. Đang giao chiến với Thanh Lâm thì bỏ sang vây công Vương Lâm, bị Thiên Hoàng Lô thôn phệ trấn áp vạn vạn năm.","tabs":{"diem":[{"text":"Tiên phi giới ngoại dùng dải lụa lam làm vũ khí, bỏ Thanh Lâm lao sang vây công Vương Lâm nhưng bị Thiên Hoàng Lô trấn áp.","chuong":"@c1564"}],"kinhLich":[{"chuong":"@c1564","importance":"normal","mucCt":"vua","tieuDe":"Bị Thiên Hoàng Lô trấn áp vạn vạn năm","text":"Bỏ giao chiến với Thanh Lâm, lao tới vây công Vương Lâm bằng dải lụa màu lam. Bị Thiên Hoàng Lô thôn phệ, trấn áp vạn vạn năm cùng lão già áo đen.","anchor":"Một dải lụa màu lam từ bên trong đám mây lóe lên cuốn về phía Vương Lâm"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối thủ","ghiChu":"Bị Vương Lâm dùng Thiên Hoàng Lô trấn áp vạn vạn năm."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1564"]},{"id":"ba-lao-ao-luc","name":"Bà lão áo lục","gioiTinh":"nu","theLuc":[{"ten":"Giới ngoại","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không Huyền","trangThai":"tu-vong","vaiTro":"Tu sĩ Không Huyền giới ngoại, tham gia đại chiến tại Chu Tước Tinh","tinhCach":"Chưa rõ","blurb":"Bà lão mặc áo lục, tu vi Không Huyền thuộc giới ngoại, đang giao chiến trong đại chiến tại Chu Tước Tinh.","tabs":{"diem":[{"text":"Tu sĩ Không Huyền giới ngoại, một trong hai Không Huyền cuối cùng còn lại trên chiến trường.","chuong":"@c1564"}],"kinhLich":[{"chuong":"@c1564","importance":"bridge","mucCt":"gon","text":"Đang giao chiến trong trận đại chiến tại Chu Tước Tinh, là một trong hai Không Huyền cuối cùng chưa bị hạ.","anchor":"Bà lão áo lục tu vi Không Huyền của giới ngoại lúc này cũng đang giao chiến"},{"mucCt":"vua","text":"Một trong hai tu sĩ Không Huyền giới ngoại đang giao chiến với Thanh Lâm cùng đồng đạo, khi bánh xe quay hoảng sợ bỏ chạy vào tinh không. Ở vòng thứ tư bị lực lượng quét ngang, thân thể tan thành mây khói, hình thần câu diệt.","anchor":"Bà lão áo lục năm đó vây sát Vương Lâm dưới cái quét ngang này thân thể run lên, trực tiếp tan thành mây khói, hình thần câu diệt","bridge":true,"khoang":"@c1565"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1564","@c1565"]},{"id":"tu-ha","name":"Tử Hà","cn":"紫霞","aliases":["Tiên phi thứ tám","Bát Phi"],"gioiTinh":"nu","theLuc":[{"ten":"Thất Đạo Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Nữ tu Triệu Hà tinh vực, tiên phi thứ tám của Thất Thải Tiên Tôn, là người duy nhất trong tám tiên phi vẫn trung thành với tiên tôn. Mặc áo tím, tướng mạo xinh đẹp lạnh lùng.","vaiTro":"Tiên phi thứ tám của Thất Thải Tiên Tôn, trung thành thu thập các tiên phi khác","tinhCach":"Lạnh lùng; thái độ ra lệnh kẻ trên; trung thành cuồng nhiệt với tiên tôn; có mục đích riêng ẩn giấu","tabs":{"diem":[{"text":"Tiên phi duy nhất trong tám người vẫn trung thành với Thất Thải Tiên Tôn, chủ động thu thập các tiên phi khác.","chuong":"@c1567"},{"text":"Bị Vương Lâm nhận định còn có mục đích riêng ngoài việc thức tỉnh tiên tôn.","chuong":"@c1567"}],"kinhLich":[{"chuong":"@c1567","importance":"normal","mucCt":"ky","tieuDe":"Lộ diện gặp Vương Lâm, bị đuổi đi","text":"Tới gặp Vương Lâm trước lỗ hổng Phong Giới Đại Trận, tự xưng tiên phi thứ tám của Thất Thải Tiên Tôn. Yêu cầu Vương Lâm giao tiên phi thứ năm đang bị phong ấn và bắt hết tiên phi còn lại. Bị cự tuyệt, chuyển sang dụ dỗ bằng cơ duyên Thất Đạo Tông và đại lục trên Tiên Cương nhưng thất bại. Bị Vương Lâm phát sát khí đuổi đi, kinh hoảng rời khỏi.","anchor":"Ta là Tử Hà của Triệu Hà tinh vực"}],"tuViMoc":[],"nhanMach":[{"ten":"Thất Thải Thiên Tôn","tag":"su-mon","quanHe":"Tiên tôn — tiên phi thứ tám","ghiChu":"Trung thành cuồng nhiệt, muốn thức tỉnh tiên tôn"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Bị Vương Lâm cự tuyệt và đuổi đi","ghiChu":"Coi Vương Lâm là người dưới trướng tiên tôn vì mang danh Phong Tôn"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1567"]},{"id":"phan-y-nu-tu","name":"Nữ tử áo hồng","aliases":["Phấn y nữ tử","Hoa Phi","Nữ tử áo hồng"],"gioiTinh":"nu","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1569","importance":"bridge","mucCt":"gon","text":"Cùng Mộc Băng Mi và Tây Tử Phượng chứng kiến Phong Giới Đại Trận tan rã trong Vân Hải tinh vực.","anchor":"Mộc Băng Mi, nữ tử áo hồng. Tây Tử Phượng lúc này hóa thành ba đạo cầu vồng ngưng tụ lại với nhau"},{"chuong":"@c1573","importance":"normal","mucCt":"gon","tieuDe":"Tới nơi Vương Lâm, chờ phiên năm thứ ba","text":"Cùng Tây Tử Phượng và Mộc Băng Mi tới nơi Vương Lâm bảo vệ, ngồi khoanh chân bên ngoài tinh không chờ đợi. Đã thỏa thuận mỗi người một năm.","anchor":"Mộc Băng Mi và nữ tử áo hồng ở xa xa trầm mặc, ngồi khoanh chân bên ngoài tinh không"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Bị hỏa long nuốt khi chưa kịp vào đại điện, nhưng sống sót nhiều tháng nhờ ấn ký bông tuyết và pháp bảo hộ thân của Đại sư tỷ","chuong":"@c0992"},{"text":"Phủ nhận mình là Côn Hư Thánh nữ, xác nhận Thánh nữ là Đại sư tỷ của nàng","chuong":"@c0993"},{"text":"Ấn ký bông tuyết trên trán tự kích hoạt bảo vệ nàng khi Bối La định bắt, trong lúc tầng sáu sụp đổ","chuong":"@c0999"},{"text":"Liều thân dùng pháp bảo bông tuyết kéo Thiên Cầm thoát khỏi hắc long, bản thân phun máu chịu thương","chuong":"@c1000"},{"text":"Dải lụa do Viễn Cổ Tiên Tôn ban tặng bị hủy, thân thể nổ tung, chỉ nguyên thần miễn cưỡng sống sót","chuong":"@c1382"},{"text":"Cùng Mộc Băng Mi và Tây Tử Phượng tới nơi Vương Lâm bảo vệ, ngồi chờ đợi trong tinh không","chuong":"@c1573"}]},"nguon":["@c1569","@c1573"],"canhGioiCaoNhat":"Không rõ","vaiTro":"Sư muội của Côn Hư Thánh nữ — nữ tu áo phấn sống sót qua nhiều tử địa","tinhCach":"kiên cường, sống sót nhiều tháng trong bụng hỏa long nhờ ấn ký và pháp bảo hộ thân; vị tha, liều thân phun máu cứu Thiên Cầm thoát khỏi hắc long; gắn bó sư môn, luôn mang theo pháp bảo và ấn ký do Đại sư tỷ ban tặng","blurb":"Nữ tu mặc áo phấn hồng, sư muội của Côn Hư Thánh nữ (Đại sư tỷ). Nàng bị hỏa long nuốt khi chưa kịp vào đại điện nhưng sống sót nhiều tháng nhờ ấn ký bông tuyết và pháp bảo hộ thân của sư tỷ, sau đó nhiều lần liều mình cứu người trong các biến cố sụp tầng và hắc long. Dải lụa do Viễn Cổ Tiên Tôn ban tặng bị hủy khiến thân thể nổ tung, chỉ nguyên thần miễn cưỡng còn sống; về sau nàng cùng Mộc Băng Mi và Tây Tử Phượng tới nơi Vương Lâm bảo vệ, ngồi chờ đợi trong tinh không."},{"id":"thanh-nien-bi-an","name":"Thanh niên bí ẩn","gioiTinh":"nam","aliases":[],"theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Nhân vật bí ẩn thân thể mơ hồ không ai nhìn rõ diện mạo, thoát ra từ viễn cổ tiên vực và ẩn mình trong tinh không, khinh miệt tu sĩ giới nội, gọi giới nội là động phủ của Thất Đạo Tông. Hắn âm thầm theo dõi Vương Lâm xuyên suốt từ Triệu Hà tinh vực tới Ngũ Hành tinh, nhận ra Đạo cổ bất diệt thể của Vương Lâm, rồi giáng lâm chấn nhiếp toàn trường để bảo vệ thanh danh Đạo Cổ nhất mạch, đồng thời đặt ra tiêu chí khảo sát và tuyển chọn Vương Lâm.","vaiTro":"Nhân vật bí ẩn từ viễn cổ tiên vực, liên hệ Đạo Cổ nhất mạch, theo dõi và khảo sát Vương Lâm","tinhCach":"Cao ngạo khinh thế, coi tu sĩ giới nội là sinh vật thấp kém; hành sự độc lập, ẩn mình quan sát không ai hay biết; trọng thị Đạo Cổ nhất mạch, nổi giận khi nghe sỉ nhục; thâm trầm mưu tính, chủ động đặt tiêu chí tuyển chọn Vương Lâm","tabs":{"diem":[{"text":"Ẩn mình trong Triệu Hà tinh vực, thân thể mơ hồ không thể nhìn rõ, ngay cả Thiên Vận Tử cũng không phát hiện","chuong":"@c1571"},{"text":"Quan sát Vương Lâm từ bên ngoài Ngũ Hành tinh, nhận định Đạo cổ bất diệt thể cùng loại với tiên nhân bất diệt thể","chuong":"@c1645"},{"text":"Giáng lâm Ngũ Hành tinh, uy áp kinh thiên chấn nhiếp toàn trường, chất vấn ai dám sỉ nhục Đạo Cổ nhất mạch","chuong":"@c1646"},{"text":"Thị uy với uy áp cửu dương, đoạt giáp và đặt tiêu chí tuyển chọn Vương Lâm","chuong":"@c1647"},{"text":"Lần đầu đại biến sắc mặt khi nhận ra Không Diệt khí từ thanh kiếm hư ảo bên người Vương Lâm","chuong":"@c1654"},{"text":"Thong dong tiến vào đại môn, tuyên bố khảo sát đối với Vương Lâm","chuong":"@c1657"}],"kinhLich":[{"mucCt":"ky","text":"Ẩn trong Triệu Hà tinh vực, thân thể mơ hồ không thể nhìn rõ, Thiên Vận Tử cũng không phát hiện. Khinh miệt việc tế bái, gọi anh hồn là chim trong lồng. Nhắc tới Mã sư bá — nơi Mã sư bá chỉ dẫn hắn không tìm thấy, quyết định bỏ qua. Nói sư bá cũng sắp thức tỉnh. Gọi nơi này là động phủ của Thất Đạo Tông. Chính là kẻ năm xưa thoát ra từ cái khe của viễn cổ tiên vực trong thiên kiếp của Vương Lâm.","anchor":"Động phủ của Thất Đạo Tông này càng ngày càng thú vị","bridge":true,"khoang":"@c1571"}],"tuViMoc":[],"nhanMach":[{"ten":"Mã sư bá","tag":"su-mon","quanHe":"Sư bá, người chỉ dẫn hắn tìm kiếm thứ gì đó","ghiChu":"Thanh niên nói sư bá sắp thức tỉnh"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1571"]},{"id":"lu-tai","name":"Lữ Tài","gioiTinh":"nam","aliases":[],"theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"tu-vong","blurb":"Đồng đạo cũ của Chiến Không Liệt, năm xưa cùng phát thề hủy diệt Phong Giới Đại Trận. Đã chết trận từ lâu, tàn hồn xuất hiện trong đám anh hồn được Vương Lâm tế bái.","vaiTro":"Đồng đạo cũ của Chiến Không Liệt, tu sĩ tử trận","tinhCach":"Không rõ","tabs":{"diem":[],"kinhLich":[{"chuong":"@c1571","importance":"bridge","mucCt":"gon","text":"Tàn hồn xuất hiện trong đám anh hồn, được Chiến Không Liệt nhận ra là đồng đạo cũ từng cùng phát thề hủy diệt Phong Giới Đại Trận.","anchor":"Ta có thể giúp ngươi nhưng ngươi không thể ngăn ta vái lạy những hồn phách mà ta áy náy"}],"tuViMoc":[],"nhanMach":[{"ten":"Chiến Không Liệt","tag":"ban-be","quanHe":"Đồng đạo, cùng phát thề hủy diệt Phong Giới Đại Trận"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1571"]},{"id":"ly-dong","name":"Lý Đông","gioiTinh":"nam","aliases":[],"theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"tu-vong","blurb":"Đồng đạo cũ của Chiến Không Liệt, đã chết trận từ lâu, tàn hồn xuất hiện trong đám anh hồn.","vaiTro":"Đồng đạo cũ của Chiến Không Liệt, tu sĩ tử trận","tinhCach":"Không rõ","tabs":{"diem":[],"kinhLich":[{"chuong":"@c1571","importance":"bridge","mucCt":"gon","text":"Tàn hồn xuất hiện trong đám anh hồn, được Chiến Không Liệt nhận ra.","anchor":"Ta có thể giúp ngươi nhưng ngươi không thể ngăn ta vái lạy những hồn phách mà ta áy náy"}],"tuViMoc":[],"nhanMach":[{"ten":"Chiến Không Liệt","tag":"ban-be","quanHe":"Đồng đạo"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1571"]},{"id":"thuong-dich","name":"Thường Dịch","gioiTinh":"nam","aliases":[],"theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"tu-vong","blurb":"Đồng đạo cũ của Chiến Không Liệt, đã chết trận từ lâu, tàn hồn xuất hiện trong đám anh hồn.","vaiTro":"Đồng đạo cũ của Chiến Không Liệt, tu sĩ tử trận","tinhCach":"Không rõ","tabs":{"diem":[],"kinhLich":[{"chuong":"@c1571","importance":"bridge","mucCt":"gon","text":"Tàn hồn xuất hiện trong đám anh hồn, được Chiến Không Liệt nhận ra.","anchor":"Ta có thể giúp ngươi nhưng ngươi không thể ngăn ta vái lạy những hồn phách mà ta áy náy"}],"tuViMoc":[],"nhanMach":[{"ten":"Chiến Không Liệt","tag":"ban-be","quanHe":"Đồng đạo"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1571"]},{"id":"ma-su-ba","name":"Mã sư bá","gioiTinh":"khong-ro","aliases":[],"theLuc":[{"ten":"Thất Đạo Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"khong-ro","blurb":"Nhân vật được thanh niên bí ẩn nhắc tới với danh xưng sư bá. Thanh niên nói nơi Mã sư bá chỉ dẫn hắn không tìm thấy, và sư bá cũng sắp thức tỉnh. Chưa xuất hiện trực tiếp.","vaiTro":"Nhân vật bí ẩn bậc sư bá, liên hệ với Thất Đạo Tông","tinhCach":"Không rõ","tabs":{"diem":[],"kinhLich":[{"chuong":"@c1571","importance":"bridge","mucCt":"gon","text":"Được thanh niên bí ẩn nhắc tới: nơi sư bá chỉ dẫn thanh niên không tìm thấy, sư bá cũng sắp thức tỉnh.","anchor":"Nơi Mã sư bá nói ta không tìm thấy, vậy thì không cần tìm nữa. Sư bá cũng sắp thức tỉnh rồi"}],"tuViMoc":[],"nhanMach":[{"ten":"Thanh niên bí ẩn","tag":"su-mon","quanHe":"Sư điệt (thanh niên gọi hắn là sư bá)"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1571"]},{"id":"tien-phi-thu-bay","name":"Tiên phi thứ bảy","cn":"","aliases":[],"gioiTinh":"nu","theLuc":[{"ten":"Thái Cổ Tinh Thần","trangThai":"gan-bo"}],"canhGioiCaoNhat":"","trangThai":"song","blurb":"Một trong các tiên phi, bế quan khôi phục thương thế trong khe sâu thuộc Thái Cổ Tinh Thần, được Chưởng Tôn triệu ra tay theo ước định trước đây.","vaiTro":"Đồng minh của Chưởng Tôn, có ước định phải ra tay khi được triệu","tinhCach":[{"text":"Bình tĩnh, tuân thủ ước định"}],"tabs":{"diem":[],"kinhLich":[{"chuong":"@c1572","importance":"normal","mucCt":"gon","tieuDe":"Đồng ý ra tay theo ước định với Chưởng Tôn","text":"Chưởng Tôn tới khe sâu trong Thái Cổ Tinh Thần đe nếu không ra tay thì ước định vô hiệu, tiên phi thứ bảy bình tĩnh đồng ý.","anchor":"Tiên phi thứ bảy, ngươi bế quan đến nay thương thế đã sớm khôi phục"}],"tuViMoc":[],"nhanMach":[{"ten":"Chưởng Tôn","tag":"dong-minh","quanHe":"Có ước định, Chưởng Tôn triệu ra tay","ghiChu":"@c1572"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1572"]},{"id":"dai-hoang-thuong-nhan","name":"Đại Hoang Thượng Nhân","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"","trangThai":"khong-ro","blurb":"Đại Hoang thượng nhân là cường giả cảnh Không Huyền, lão giả mặc da thú trú trên một tu chân tinh khô héo. Không có phân thân sẵn và không dám suy yếu tu vi bản thể, hắn đoạt xá tu sĩ khác để phân hồn tiến vào cổ mộ, gây ra hàng loạt cuộc tranh đoạt tàn khốc — giải ấn Tam Tiên biến biển hương hỏa thành biển độc, đoạt xá thành công Diệu Âm Đạo Tôn, phân hồn bị hủy diệt khi tham lam lao tới đài mộ cấp chín. Bổn tôn bị nhốt lại trong cổ mộ sau khi Địa Phù bị Vương Lâm thu đoạt, về sau được Chưởng Tôn cứu ra nhưng bại trận thảm hại, bị đoán định sống không quá mười năm.","vaiTro":"Cường giả Không Huyền — kẻ đoạt xá tàn độc trong cổ mộ","tinhCach":"Tàn nhẫn bất chấp, sẵn sàng hy sinh người khác để đạt mục đích; mưu mô thâm trầm, tính toán nhiều bước nhưng hay bị phản đòn; tham lam không kiềm chế, lao vào nguy hiểm vì lợi ích trước mắt","tabs":{"diem":[{"text":"Không có phân thân, bắt tu sĩ bên ngoài sương mù để đoạt xá nhằm đưa phân hồn vào cổ mộ","chuong":"@c1345"},{"text":"Giải ấn Tam Tiên, biến biển hương hỏa thành biển độc; bổn tôn ở tinh cầu hoang dã phun máu khiến toàn tinh cầu chết","chuong":"@c1365"},{"text":"Đoạt xá thành công Diệu Âm Đạo Tôn, hóa hắc khí chui vào thất khiếu chiếm cứ thân xác","chuong":"@c1366"},{"text":"Phân hồn bị hủy diệt khi tham lam lao tới đài mộ cấp chín, bị cánh tay khổng lồ tiêu diệt","chuong":"@c1377"},{"text":"Bổn tôn bị nhốt trong cổ mộ sau khi Địa Phù bị Vương Lâm thu đoạt","chuong":"@c1386"},{"text":"Được Chưởng Tôn cứu khỏi cổ mộ nhưng bại trận nặng nhất, bị đoán định sống không quá mười năm","chuong":"@c1583"}],"kinhLich":[{"mucCt":"gon","text":"Chưởng Tôn nhắc tới Đại Hoang Thượng Nhân đang bị nhốt trong cổ mộ cùng Diệu Âm Đạo Tôn và Cửu Thiên Ma Tôn.","anchor":"Diệu âm đ*o tôn, Cửu Thiên ma tôn, còn có cả Đại Hoang Thượng Nhân, hai người bọn họ bị nhốt bên trong vùng đất cổ mộ","bridge":true,"khoang":"@c1572"}],"tuViMoc":[],"nhanMach":[{"ten":"Chưởng Tôn","tag":"khac","quanHe":"Chưởng Tôn coi là quân cờ có thể lợi dụng","ghiChu":"@c1572"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1572"]},{"id":"su-ton-cua-chuong-ton","name":"Sư tôn của Chưởng Tôn","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[],"canhGioiCaoNhat":"","trangThai":"khong-ro","blurb":"Chưa lộ danh tính, ở nơi sáu đại lục lơ lửng sâu trong Thái Cổ Tinh Thần có trận pháp chỉ huyết mạch tiên nhân mới vào, Chưởng Tôn cung kính xưng đệ tử cầu kiến.","vaiTro":"Sư tôn của Chưởng Tôn, nhân vật bí ẩn cực kỳ cao cấp","tinhCach":[],"tabs":{"diem":[],"kinhLich":[{"chuong":"@c1572","importance":"normal","mucCt":"gon","tieuDe":"Chưởng Tôn cầu kiến","text":"Chưởng Tôn tới sáu đại lục lơ lửng sâu trong Thái Cổ Tinh Thần, cung kính vái cầu kiến sư tôn.","anchor":"Đệ tử cầu kiến sư tôn!"}],"tuViMoc":[],"nhanMach":[{"ten":"Chưởng Tôn","tag":"su-mon","quanHe":"Đệ tử","ghiChu":"@c1572"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1572"]},{"id":"tien-phi-thu-nam","name":"Tiên phi thứ năm","cn":"","aliases":[],"gioiTinh":"nu","theLuc":[],"canhGioiCaoNhat":"","trangThai":"khong-ro","blurb":"Tiên phi thứ năm sở hữu nhục thân vốn là thê tử của Vương Lâm, linh hồn tiên phi đang cùng tồn tại bên trong thân xác này. Thân phận của nàng được Chưởng Tôn tiết lộ và sử dụng làm con bài trong cuộc giao dịch với Lam Mộng Đạo Tôn.","vaiTro":"Tiên phi thứ năm — nhục thân là thê tử Vương Lâm, con bài giao dịch của Chưởng Tôn","tinhCach":[],"tabs":{"diem":[{"text":"Bị Chưởng Tôn tiết lộ thân phận và dùng làm con bài giao dịch với Lam Mộng Đạo Tôn","chuong":"@c1572"},{"text":"Nhục thân là thê tử Vương Lâm, linh hồn tiên phi đang cùng tồn tại trong thân xác","chuong":"@c1572"}],"kinhLich":[{"chuong":"@c1572","importance":"major","mucCt":"vua","tieuDe":"Chưởng Tôn tiết lộ thân phận, dùng làm con bài giao dịch","text":"Chưởng Tôn tiết lộ tiên phi thứ năm có nhục thân là thê tử Vương Lâm, linh hồn đang cùng tồn tại với tiên phi. Dùng việc bức hồn phách tiên phi thứ năm ra làm điều kiện giao dịch với Lam Mộng Đạo Tôn.","anchor":"còn có tiên phi thứ năm có nhục thân thê tử của hắn, linh hồn đang cùng tồn tại với tiên phi"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"the-thiep","quanHe":"Nhục thân là thê tử Vương Lâm","ghiChu":"@c1572"},{"ten":"Lam Mộng Đạo Tôn","tag":"khac","quanHe":"Lam Mộng muốn bức hồn phách tiên phi ra","ghiChu":"@c1572"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1572"]},{"id":"dao-nhan-bay-mau","name":"Đạo nhân bảy màu","cn":"","aliases":["Sư tôn của Chưởng Tôn","Thất Thải Tiên Tôn"],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Không rõ (cấp Chiến lão quỷ)","trangThai":"song","blurb":"Đạo nhân bảy màu là hồn thứ nhất của Thất Thải Tiên Tôn, cường giả ẩn cư tại chín đại lục trôi nổi trong Thái Cổ Tinh Thần, nắm giữ toàn bộ đạo thuật thần thông cả đời của Thất Thải Tiên Tôn. Với tư cách sư tôn của Chưởng Tôn, lão bày bố huyết trận, mang tổ tiên viễn cổ mãnh thú từ Tiên giới, tập hợp Cửu huyền huyết mạch và truy tìm hồn thứ ba xuyên suốt Côn Hư, La Thiên cùng nhiều tàn giới nhằm thôn phệ rồi vượt qua Chiến lão quỷ. Sau khi bị Vương Lâm bắn xuyên ngực trọng thương, lão dần suy yếu và cuối cùng hồn bị Chiến lão quỷ phóng ra làm lớp phòng hộ rồi bị Đạo Cổ Vô Tiên hóa đá, cưỡng ép","vaiTro":"Phản diện ẩn cấp cao — hồn thứ nhất của Thất Thải Tiên Tôn, sư tôn của Chưởng Tôn","tinhCach":"Thâm trầm mưu lược, sắp đặt kế hoạch xuyên suốt nhiều đời; tự tin tuyệt đối vào thần thông và quyền năng bản thân; coi mọi người như quân cờ phục vụ mưu đồ thôn phệ; hung tàn quyết đoán nhưng hoảng sợ bỏ chạy trước khí tức đại thiên tôn","tabs":{"diem":[{"text":"Lộ diện tại chín đại lục trong Thái Cổ Tinh Thần, bàn mưu đồ thôn phệ hồn thứ ba cùng Chưởng Tôn","chuong":"@c1573"},{"text":"Được xác nhận là hồn thứ nhất của Thất Thải Thiên Tôn, nắm toàn bộ đạo thuật thần thông cả đời","chuong":"@c1600"},{"text":"Bị khí tức đại thiên tôn dọa đến mức phun máu, điên cuồng bỏ chạy khỏi khe Vân","chuong":"@c1610"},{"text":"Tập hợp đủ Cửu huyền huyết mạch tại Côn Hư, chuẩn bị huyễn hóa luân hồi truy tìm hồn thứ ba","chuong":"@c1633"},{"text":"Bị Vương Lâm bắn xuyên ngực trọng thương, bộc phát toàn bộ tu vi thi triển chín mặt trời rồi bỏ chạy","chuong":"@c1670"},{"text":"Hồn bị Chiến lão quỷ phóng ra làm lớp phòng hộ, bị Đạo Cổ Vô Tiên hóa đá và cưỡng ép dung hợp","chuong":"@c1683"}],"kinhLich":[{"chuong":"@c1573","importance":"major","mucCt":"ky","tieuDe":"Lộ diện tại chín đại lục, bàn mưu đồ thôn phệ người thứ ba","text":"Thân ảnh huyễn hóa xuất hiện từ cầu vồng bảy màu trên chín đại lục trong Thái Cổ Tinh Thần. Chưởng Tôn bái kiến, bẩm báo thất bại và cây cung Lý Quảng rơi vào tay Vương Lâm. Đạo nhân bảy màu nói sẽ giúp mở vùng đất cổ mộ, nhận định trò chơi sắp kết thúc. Bàn về “người thứ ba” ẩn thế luân hồi vô số lần, nói Vương Lâm “không giống” nhưng “cũng không phải là không có khả năng”. Tuyên bố sau khi thôn phệ người thứ ba thì Chiến lão quỷ cũng không phải đối thủ, và chủ nhân của Chưởng Tôn sẽ là thuốc bổ. Hóa ánh sáng bảy màu tiêu tán.","anchor":"Đợi sau khi ta thôn phệ người thứ ba xong thì Chiến lão quỷ cũng không phải là đối thủ của ta"},{"importance":"bridge","mucCt":"gon","chuong":"@c1575","tieuDe":"","text":"Được nhắc đến là nguồn gốc thần thông trường thương bảy màu và người đã mang tổ tiên viễn cổ mãnh thú từ Tiên Cương đại lục tới thế giới động phủ.","anchor":"cũng chỉ có người điên với thân phận của hắn trên Tiên Cương đại lục và lực lượng mạnh mẽ như vậy mới có thể đạt được loại thần thông này"},{"importance":"bridge","mucCt":"gon","chuong":"@c1577","tieuDe":"","text":"Được Chưởng Tôn nhắc tới khi tiết lộ lai lịch nam tử trung niên trong chín quan tài — cùng Chưởng Tôn tạo nên chí bảo này qua năm tháng vô tận.","anchor":"được hắn và đạo nhân bảy màu tạo nên cuối cùng ngưng tụ thành"}],"tuViMoc":[],"nhanMach":[{"ten":"Chưởng Tôn","tag":"su-mon","quanHe":"Đệ tử (bái sư theo giao kèo)","ghiChu":"Chưởng Tôn bái sư để đổi lời hứa về chủ nhân bí ẩn"},{"ten":"Chiến Không Liệt","tag":"doi-thu","quanHe":"Đối thủ cùng cấp","ghiChu":"Coi Chiến lão quỷ là đối thủ, tự tin sau khi thôn phệ người thứ ba sẽ vượt qua"},{"ten":"Vương Lâm","tag":"khac","quanHe":"Đối tượng quan sát","ghiChu":"Nhận định Vương Lâm không giống người thứ ba nhưng không loại trừ"}],"tuiDo":{}},"nguon":["@c1573","@c1575","@c1577"]},{"id":"lao-gia-toc-bac-gioi-ngoai","name":"Lão già tóc bạc (giới ngoại)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Giới ngoại","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Toàn năng bước thứ ba","trangThai":"song","blurb":"Đứng đầu năm bậc toàn năng bước thứ ba — lực lượng dự phòng cuối cùng của giới ngoại. Chỉ huy hai đòn tổng công kích vào Vô Danh Chuyển Luân trận nhưng đều thất bại.","vaiTro":"Thủ lĩnh chiến trường năm toàn năng giới ngoại, chỉ huy đòn tổng tử chiến","tinhCach":"Kiên quyết, bất khuất, sẵn sàng hy sinh tất cả","tabs":{"diem":[{"text":"Đứng đầu hàng chữ nhất năm toàn năng, nhận lực lượng dung hợp thi triển viễn cổ thuật tạo đại kiếm vạn trượng","chuong":"@c1574"},{"text":"Không chịu lùi sau thất bại, kêu gọi mười vạn tu sĩ hiến tế toàn bộ thọ nguyên để triệu hồi ánh sáng viễn cổ","chuong":"@c1574"}],"kinhLich":[{"importance":"normal","mucCt":"ky","chuong":"@c1574","tieuDe":"Chỉ huy hai đòn tổng công kích giới ngoại thất bại","text":"Ở vị trí đầu tiên trong hàng chữ nhất năm toàn năng bước thứ ba, nhận lực lượng dung hợp của bốn người phía sau, thi triển viễn cổ thuật hóa đại kiếm vạn trượng dung nhập mười vạn nguyên thần chém xuống Vô Danh Chuyển Luân trận nhưng bị phản lực đánh bật, thổ huyết. Không chịu lùi, bắt quyết kêu gọi mười vạn tu sĩ hiến tế toàn bộ thọ nguyên đổi lấy một kích viễn cổ, triệu hồi ánh sáng viễn cổ kim quang từ Tiên Cương đại lục qua hắc động. Đòn này bị Vương Lâm dùng Phần Giới Cổ Tán và trường thương bảy màu phá giải.","anchor":"Lấy tu vi của ta, lấy huyết mạch của ta, dẫn đại thuật viễn cổ, khai thiên chỉ đạo, một đạo không diệt"}],"tuViMoc":[{"chuong":"@c1574","canhGioi":"Toàn năng bước thứ ba","text":"Được xác nhận là toàn năng bước thứ ba, đứng đầu năm vị toàn năng cuối cùng của giới ngoại.","importance":"minor"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối thủ trận chiến","ghiChu":"Chỉ huy tổng công kích Vô Danh Chuyển Luân trận của Vương Lâm nhưng thất bại"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1574"]},{"id":"u-minh-thu","name":"U Minh thú","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Linh thú khổng lồ vốn ngủ trong cấm địa sương mù La Thiên, bị Vương Lâm hoàn thành ba tầng phong ấn thu phục làm bổn mệnh thú, sinh mệnh từ đó gắn liền chủ nhân. Sở hữu U Minh Hồn Khẩu uy lực đủ nuốt cả tinh không, từng nuốt trọn cuồng phong chuông vàng cứu nguy Vân Hải, huyễn hóa hư ảnh khổng lồ thôn phệ mãnh thú viễn cổ, và phóng sương mù thiên đạo nuốt gần hết tiên nhân. Dẫu uy mãnh vô song, nó lại run rẩy sợ hãi mỗi khi bị người khác nhìn chằm chằm, bộc lộ bản tính vừa dữ tợn vừa ngờ nghệch.","vaiTro":"Bổn mệnh thú của Vương Lâm — linh thú cổ quái sở hữu U Minh Hồn Khẩu","tinhCach":"Hung hãn dữ tợn khi chiến đấu, uy lực kinh người; nhút nhát cổ quái, run rẩy sợ hãi khi bị đám đông chú ý, nép vào Vương Lâm như hài tử nép cha mẹ; tham ăn, nuốt cuồng phong rồi nhấm nháp thưởng thức","tabs":{"diem":[{"text":"Bị Vương Lâm hoàn thành ba tầng phong ấn (phong ngoài, hồn phong bằng bảy tinh điểm Cổ Thần, phong ấn máu thịt), thu phục làm bổn mệnh thú","chuong":"@c1412"},{"text":"Mở U Minh Hồn Khẩu khổng lồ nuốt trọn cuồng phong chuông vàng, cứu nguy Vân Hải","chuong":"@c1419"},{"text":"Bộc lộ bản tính cổ quái — vọt về nép vào Vương Lâm như hài tử nép cha mẹ khi bị tu sĩ nhìn chằm chằm","chuong":"@c1420"},{"text":"Tái xuất huyễn hóa hư ảnh khổng lồ thôn phệ mãnh thú viễn cổ, bao trùm Vô Danh Chuyển Luân trận","chuong":"@c1576"},{"text":"Phóng sương mù thiên đạo tràn ngập tinh không, lực hút kinh thiên nuốt gần hết tiên nhân","chuong":"@c1633"},{"text":"Được xác nhận là một bộ phận của Vương Lâm, sinh mệnh và sức sống tương thông với chủ nhân","chuong":"@c1631"}],"kinhLich":[{"importance":"normal","mucCt":"ky","chuong":"@c1576","tieuDe":"Tái xuất thôn phệ mãnh thú viễn cổ","text":"Xuất hiện lần đầu sau rất lâu trong Vô Danh Chuyển Luân trận, huyễn hóa hư ảnh khổng lồ bao trùm cả trận pháp. Uy áp tự nhiên khiến hơn mười hồn phách mãnh thú viễn cổ run rẩy lùi lại do sợ hãi từ ký ức tổ tiên, đồng thời mấy vạn tu sĩ giới ngoại và năm bậc toàn năng đều kinh hãi. Bản tính nhát gan bộc phát khi bị hình dạng dữ tợn của mãnh thú cùng tiếng hét tu sĩ dọa cho sợ tới mức mắt trắng dã gần bất tỉnh. Dưới mệnh lệnh mạnh của Vương Lâm qua tâm thần tương liên, gầm lấy can đảm rồi mở miệng hút nuốt trọn hơn mười hồn phách mãnh thú viễn cổ. Sau đó chép miệng vẻ tủi thân, hóa tia sáng dung nhập vào mi tâm Vương Lâm.","anchor":"u Minh thú nhát gan tới cực điểm đã rất lâu không xuất hiện"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Chủ nhân","ghiChu":"Ẩn trong mi tâm Vương Lâm, nghe lệnh qua tâm thần tương liên"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1576"]},{"id":"nam-tu-trung-nien-chin-quan-tai","name":"Nam tử trung niên (chín quan tài)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Trường Tôn hội","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Thực thể được ngưng tụ từ chín phần thân thể phong ấn trong chín quan tài, do Chưởng Tôn và đạo nhân bảy màu của Trường Tôn hội tạo nên. Thân hình ngàn trượng mọc đầy lông đỏ, mi tâm mang hai tinh điểm Cổ Thần, khí tức Đạo cổ Diệp Mịch tinh thuần tới cực điểm, từng giao tranh ngang tài với Vương Lâm.","vaiTro":"Chí bảo chiến đấu của Trường Tôn hội — thực thể cổ tộc ngưng tụ từ chín quan tài","tinhCach":"Không có ý thức rõ ràng, hành xử theo bản năng chiến đấu; uy nghiêm lạnh lùng","tabs":{"diem":[{"text":"Chín quan tài nổ tung, chín phần thân thể dung hợp thành thân hình ngàn trượng mọc đầy lông đỏ, khiêu chiến Vương Lâm","chuong":"@c1577"},{"text":"Giao tranh cận chiến ngang tài với Vương Lâm bằng thân thể cổ tộc, thi triển Cổ Thần nhất chỉ","chuong":"@c1578"}],"kinhLich":[{"importance":"major","mucCt":"ky","chuong":"@c1577","tieuDe":"Hợp nhất từ chín quan tài, khiêu chiến Vương Lâm","text":"Chín quan tài lần lượt nổ tung, chín phần thân thể dung hợp thành thân hình ngàn trượng mọc đầy lông đỏ, tướng mạo tầm thường nhưng uy nghiêm. Mi tâm hai tinh điểm Cổ Thần, mắt trái ba yêu tinh, mắt phải ba ma tinh. Dùng Cổ tộc Chiến Ấn — ấn ký chí cao vô thượng trong tam tộc cổ — khiêu chiến Vương Lâm, ép đấu sanh tử. Hai bên đấu quyền bằng thân thể, va chạm chấn động giới nội giới ngoại.","anchor":"Hai tinh điểm này là hai tinh điểm cổ Thần"},{"mucCt":"ky","text":"Giao tranh cận chiến ngang tài với Vương Lâm bằng thân thể cổ tộc. Thi triển Cổ Thần nhất chỉ (hư ảnh Cổ Thần tám tinh điểm) bị Vương Lâm song quyền phá tan, ngực bị đánh lõm nhưng phản kích bằng cước pháp đá Vương Lâm bắn lùi mấy ngàn trượng. Liên hoàn triệu hư ảnh tam tộc cổ: Cổ Yêu thôn thiên, Cổ Ma phệ địa, Cổ Thần nổi giận, rồi triệu hư ảnh Đạo Cổ Diệp Mịch, tự xưng con trai Đạo cổ đòi thu hồi truyền thừa. Bị Vương Lâm nếm máu vạch trần: KHÔNG phải con trai Diệp Mịch mà do đám Chưởng Tôn giới ngoại ngưng tụ tám giọt tâm huyết tam tộc cổ tạo thành.","anchor":"Ta là con trai của Đạo cổ, ngươi được truyền thừa của phụ thân ta, hôm nay ta muốn thu hồi truyền thừa!","bridge":true,"khoang":"@c1578"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối thủ Cổ tộc Chiến Ấn","ghiChu":"Giao chiến sanh tử bằng Chiến Ấn @c1577"},{"ten":"Chưởng Tôn","tag":"khac","quanHe":"Người tạo ra hắn","ghiChu":"Cùng đạo nhân bảy màu tạo nên hắn qua năm tháng vô tận @c1577"},{"ten":"Đạo nhân bảy màu","tag":"khac","quanHe":"Người tạo ra hắn","ghiChu":"Cùng Chưởng Tôn tạo nên hắn @c1577"},{"ten":"Nữ Cổ Thần Đông Lâm tinh","tag":"ho-hang","quanHe":"Hậu duệ huyết mạch (nàng gọi là phụ tổ)","ghiChu":"Nàng cảm nhận khí tức huyết mạch phụ tổ từ hắn @c1577"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[{"ten":"Cổ tộc Chiến Ấn","trangThai":"dang-co","moTa":"Ấn ký chí cao vô thượng tam tộc cổ, dùng khiêu chiến Vương Lâm","nguon":"@c1577"}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1577","@c1578"]},{"id":"nu-co-than-dong-lam-tinh","name":"Nữ Cổ Thần Đông Lâm tinh","cn":"","aliases":[],"gioiTinh":"nu","theLuc":[{"ten":"Gia tộc viễn cổ Đông Lâm tinh","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ (bảy tinh điểm Cổ Thần)","trangThai":"song","blurb":"Nữ tử xinh đẹp trên tế đàn đỉnh núi Đông Lâm tinh, thuộc gia tộc viễn cổ tu chân duy nhất La Thiên Tinh Vực. Mi tâm có bảy tinh điểm Cổ Thần, có thể dung hợp thành ấn ký hình giọt máu màu đỏ yêu dị.","vaiTro":"Hậu duệ Cổ Thần tại Đông Lâm tinh, cảm ứng được khí tức huyết mạch phụ tổ","tinhCach":"Trầm tĩnh; có linh cảm mạnh với huyết mạch tổ tiên","tabs":{"diem":[{"text":"Bảy tinh điểm Cổ Thần trên mi tâm, có thể dung hợp thành ấn ký hình giọt máu đỏ yêu dị.","chuong":"@c1577"},{"text":"Thuộc gia tộc viễn cổ tu chân duy nhất La Thiên, sống trên thế giới bị đóng băng hoàn toàn.","chuong":"@c1577"}],"kinhLich":[{"importance":"normal","mucCt":"vua","chuong":"@c1577","tieuDe":"Cảm ứng khí tức huyết mạch phụ tổ","text":"Đang tu luyện trên tế đàn đỉnh núi Đông Lâm tinh thì đột nhiên mở mắt, cảm nhận được khí tức huyết mạch của phụ tổ. Điểm lên mi tâm, bảy tinh điểm Cổ Thần dung hợp thành ấn ký hình giọt máu màu đỏ yêu dị.","anchor":"Ta cảm nhận được khí tức huyết mạch của phụ tổ"}],"tuViMoc":[],"nhanMach":[{"ten":"Nam tử trung niên (chín quan tài)","tag":"ho-hang","quanHe":"Phụ tổ (tổ tiên huyết mạch)","ghiChu":"Cảm ứng khí tức huyết mạch từ xa @c1577"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1577"]}]};
